import SwiftUI

/// Search-overlay state machine. Lives on `AppState`, drives the
/// `SearchOverlay` view's mode (idle/searching/results/error) and
/// the VoiceOver announcements that go with each transition.
enum SearchState: Equatable {
    /// No query in flight and no results to show. The initial state
    /// when the overlay first opens.
    case idle
    /// A query is in flight. UI shows a "Searching…" placeholder
    /// (announced through the polite live region).
    case searching
    /// Latest search returned `rows` with a pre-rendered audio
    /// summary string (`"Search returned N results"`).
    case results(rows: [QueryHit], summary: String)
    /// SQLite or FFI error — surfaced through the same panel slot
    /// as results so the user notices.
    case error(String)
}

/// Outcome of a single link-activation call. Mirrors the branches in
/// `AppState.openLink(_:)` so tests can assert routing without
/// observing AppKit side effects.
enum LinkActivationOutcome: Equatable {
    case openedInternal(String)
    case unresolved(String)
    case openedExternal(String)
    case externalOpenFailed(String)
}

/// User-facing filter for the vault-wide Tasks Review view (#114).
/// Maps to the FFI `TaskFilter` via `toFFIFilter` — the UI side
/// carries the human-named cases (`.all`, `.dueToday`, …) and the
/// adapter converts them into the date-window + completed-flag
/// shape the SQLite query expects.
///
/// **Timezone note.** The backend parser stores `📅 2026-06-01` as
/// midnight UTC of that calendar date. Our `.dueToday` / `.overdue`
/// / `.thisWeek` windows compare against UTC midnight too, so the
/// filter boundary moves with UTC, not with the user's local
/// timezone. A user in PST will see "today" tasks change at
/// 5 PM local (UTC midnight). That's the cost of the parser's
/// timezone-naive shape and is documented as a V1 limitation; a
/// follow-up could thread a `TimeZone` through the parser and
/// filter together.
enum TaskReviewFilter: Hashable, CaseIterable, Identifiable {
    /// Every task in the vault, completed or open. The literal
    /// "show me everything" view.
    case all
    /// Open tasks with a due date that falls on today (UTC).
    case dueToday
    /// Open tasks whose due date is in the past (UTC) — `due_ms <
    /// startOfTodayUtc`. Tasks with no due date are excluded.
    case overdue
    /// Open tasks due in the next 7 days (UTC), inclusive of today,
    /// exclusive of the 8th day. Matches the `[from, to)` shape of
    /// the FFI's `dueFromMs` / `dueToMs` pair.
    case thisWeek

    var id: Self { self }

    /// Picker chip label. Plain English, no abbreviations — chips
    /// are read by VoiceOver verbatim.
    var displayName: String {
        switch self {
        case .all: return "All"
        case .dueToday: return "Due today"
        case .overdue: return "Overdue"
        case .thisWeek: return "This week"
        }
    }

    /// Resolve to the FFI `TaskFilter` against a reference "now"
    /// (parameterised so tests can pin the clock without mocking
    /// `Date()`). UTC throughout — see the timezone note above.
    func toFFIFilter(now: Date = Date()) -> TaskFilter {
        let cal = Self.utcCalendar
        let startOfTodayUtc = cal.startOfDay(for: now)
        switch self {
        case .all:
            return TaskFilter(
                completed: nil,
                dueFromMs: nil,
                dueToMs: nil,
                priorityAtLeast: nil
            )
        case .dueToday:
            let startOfTomorrow = cal.date(byAdding: .day, value: 1, to: startOfTodayUtc)!
            return TaskFilter(
                completed: false,
                dueFromMs: Int64(startOfTodayUtc.timeIntervalSince1970 * 1000),
                dueToMs: Int64(startOfTomorrow.timeIntervalSince1970 * 1000),
                priorityAtLeast: nil
            )
        case .overdue:
            return TaskFilter(
                completed: false,
                // Unix epoch start as the lower bound — any due
                // date qualifies as long as it's before today.
                dueFromMs: 0,
                dueToMs: Int64(startOfTodayUtc.timeIntervalSince1970 * 1000),
                priorityAtLeast: nil
            )
        case .thisWeek:
            let endOfWindow = cal.date(byAdding: .day, value: 7, to: startOfTodayUtc)!
            return TaskFilter(
                completed: false,
                dueFromMs: Int64(startOfTodayUtc.timeIntervalSince1970 * 1000),
                dueToMs: Int64(endOfWindow.timeIntervalSince1970 * 1000),
                priorityAtLeast: nil
            )
        }
    }

    /// UTC `Calendar` for `startOfDay` etc. so the filter's
    /// behaviour is locale-independent. Built once per call site
    /// rather than statically because `Calendar` isn't `Sendable`
    /// across actors in Swift 6 strict-concurrency mode.
    private static var utcCalendar: Calendar {
        var cal = Calendar(identifier: .gregorian)
        cal.timeZone = TimeZone(identifier: "UTC")!
        return cal
    }
}

/// Per-incident snapshot for the conflict-resolution alert.
///
/// Populated by `saveCurrentNote` when the backend returns
/// `WriteConflict`. Carries everything the resolution actions need:
/// the bytes the user tried to save (so "Keep mine" can re-issue the
/// save), the on-disk hash the alert reports, and the original
/// `expectedContentHash` (kept for telemetry — testers can confirm
/// the conflict was caught because the file moved, not because the
/// editor's hash tracking was wrong).
struct SaveConflict: Equatable {
    let path: String
    let attemptedContents: String
    let currentContentHash: String
    let expectedContentHash: String
    let currentMtimeMs: Int64
}

/// Per-incident snapshot for the editor's embed-preview popover
/// (#188). Carries enough state for the popover to render the
/// resolved embed without re-querying the backend — the resolution
/// has already been cached by `loadCurrentNoteEmbedResolutions`.
///
/// `sourceLine` is the 1-based line number of the embed's source
/// `![[…]]` reference in the editor buffer. Surfaced in the
/// popover header so users have textual spatial bearing without
/// AppKit geometry plumbing (audit #209). Nil when the caller
/// can't compute it (synthetic callers in tests).
struct EmbedPreview: Equatable {
    let target: String
    let resolution: EmbedResolution
    let sourceLine: Int?
}

/// What edit the user was trying to make when a property-edit
/// `WriteConflict` fired. Carries enough state for the resolve
/// helpers to re-issue the original edit verbatim.
enum PropertyEditAction: Equatable {
    case set(PropertyValue)
    case delete
    /// U3-4 (#468): replace the WHOLE frontmatter source (the widget's
    /// show-source Apply). Rides the same edit/conflict machinery as the
    /// per-key actions — one conflict alert flow, one resolution surface.
    case setSource(String)
}

/// Per-incident snapshot for the property-edit conflict alert.
/// Modeled on `SaveConflict` (whole-file save) but scoped to a
/// single key edit so "Keep mine" re-issues the property action
/// rather than the whole-file save.
struct PropertyEditConflict: Equatable {
    let path: String
    let key: String
    let action: PropertyEditAction
    let currentContentHash: String
    let expectedContentHash: String
    let currentMtimeMs: Int64
}

/// Captured identity for a mounted Markdown authoring surface. AppKit can
/// deliver text/edit callbacks after SwiftUI has already replaced the view;
/// path equality alone is insufficient because another tab or vault can mount
/// the same relative path. Every view-owned callback carries this token and is
/// accepted only while the exact session + mount generation still owns it.
struct NoteAuthoringOwner: Hashable {
    fileprivate let generation: UInt64
    fileprivate let sessionID: ObjectIdentifier
    let path: String

    static func == (lhs: Self, rhs: Self) -> Bool {
        lhs.generation == rhs.generation
            && lhs.sessionID == rhs.sessionID
            && BaseExactIdentity.matches(lhs.path, rhs.path)
    }

    func hash(into hasher: inout Hasher) {
        hasher.combine(generation)
        hasher.combine(sessionID)
        BaseExactIdentity.hash(path, into: &hasher)
    }
}

/// Destination the user asked to navigate to while the editor was
/// dirty. Held in `AppState.pendingNavigation` until the user
/// responds to the "Save changes?" alert.
enum PendingNavigation: Equatable {
    case closeVault
    case selectFile(String?)

    static func == (lhs: Self, rhs: Self) -> Bool {
        switch (lhs, rhs) {
        case (.closeVault, .closeVault):
            return true
        case (.selectFile(let lhsPath), .selectFile(let rhsPath)):
            return BaseExactIdentity.matches(lhsPath, rhsPath)
        default:
            return false
        }
    }
}

/// State machine driving the create-from-template flow (Milestone H).
///
/// `idle` is the resting state. `needsPrompts` is set after
/// `selectTemplate` against a template that declared at least one
/// `{{prompt:Label}}` marker — the prompt sheet renders one
/// `TextField` per entry, in declaration order, and `Submit`
/// transitions to `needsName(...)` carrying the user's responses.
/// `needsName` is set for prompt-less templates (skipping straight
/// from picker → name sheet) and for any template after its prompts
/// resolve. Submitting the name sheet returns the flow to `idle`
/// via `submitTemplateNoteName`; any sheet's Cancel button calls
/// `cancelTemplateFlow` to do the same.
enum PendingTemplateFlow: Equatable {
    case idle
    case needsPrompts(TemplateSummary, [TemplatePrompt])
    case needsName(TemplateSummary, [String: String])
}

/// Side-effect-free state consumed by every Sidebar surface when projecting
/// the shared Template action. Busy remains the shared structural-mutation
/// state so it uses the same reason as every other structural action.
enum TemplateAvailability: Equatable {
    case loading
    case available
    case empty
    case failed
}

struct TemplateCreationDestinationOwner: Equatable {
    let sessionIdentity: ObjectIdentifier
    let generation: UInt64
    let path: String
}

enum NativeDocumentRetargetOwner: Sendable, Equatable {
    case registry(key: String)
    case basesDock
}

/// Value-only work captured while a batch report lands. Document objects stay
/// on MainActor; the executor receives only path/source identities, generation
/// tokens, and detached native handles.
enum NativeDocumentRetargetPlan: @unchecked Sendable {
    case canvas(
        path: String,
        generation: UInt64,
        replacedHandle: UInt64?,
        prepare: Bool
    )
    case base(
        owner: NativeDocumentRetargetOwner,
        source: BaseDocumentSource,
        generation: UInt64,
        replacedHandle: UInt64?,
        request: BasePreparedLoadRequest,
        prepare: Bool
    )

    var shouldPrepare: Bool {
        switch self {
        case .canvas(_, _, _, let prepare),
            .base(_, _, _, _, _, let prepare):
            return prepare
        }
    }
}

enum NativeDocumentRetargetResult: @unchecked Sendable {
    case canvas(path: String, generation: UInt64, prepared: CanvasPreparedLoad)
    case base(
        owner: NativeDocumentRetargetOwner,
        source: BaseDocumentSource,
        generation: UInt64,
        prepared: BasePreparedLoad
    )
}

/// A byte-preserving, user-readable snapshot of an uncommitted property row.
/// Values are intentionally rendered as plain text: this is a recovery
/// artifact, not an attempt to reconstruct or commit typed frontmatter.
struct MissingPropertyRecoveryDraft: Identifiable, Equatable {
    let key: String
    let value: String

    var id: String {
        BaseExactIdentity.key(
            prefix: "missing-property-recovery", components: [key])
    }
}

/// Durable in-memory recovery payload for a dirty Markdown note whose file is
/// proven absent after an outcome-unknown Trash operation. The active editor,
/// properties-source editor, and row editors all unmount in the missing-file
/// state, so AppState must own the last recoverable copy until the user
/// explicitly discards it or closes the vault.
struct MissingNoteRecoveryDraft: Equatable {
    let path: String
    let body: String
    let frontmatterSource: String
    let propertiesSourceDraft: String?
    let propertyDrafts: [MissingPropertyRecoveryDraft]
    let retainedPropertyUpdates: [MissingPropertyRecoveryDraft]

    var copyText: String {
        var sections: [String] = [
            "Path: \(path)",
            "Markdown body:\n\(body)",
        ]
        if !frontmatterSource.isEmpty {
            sections.append("Saved frontmatter source:\n\(frontmatterSource)")
        }
        if let propertiesSourceDraft {
            sections.append("Uncommitted properties source:\n\(propertiesSourceDraft)")
        }
        for draft in propertyDrafts {
            sections.append("Uncommitted property \(draft.key):\n\(draft.value)")
        }
        for update in retainedPropertyUpdates {
            sections.append(
                "Saved property update awaiting verification \(update.key):\n\(update.value)")
        }
        return sections.joined(separator: "\n\n")
    }
}

enum BatchTrashPhysicalPresence: Sendable, Equatable {
    case present
    case absent
    case indeterminate
}

enum BatchTrashPathCapability: Equatable {
    case writable
    case readOnly(String)
    case invalid(String)
}

private enum BatchTrashAdmissionPath {
    case normalized(String)
    case invalid(String)
}

private struct BatchTrashPresenceProbe: Sendable {
    let path: String
    let isDirectory: Bool
}

private struct BatchTrashPresenceResult: Sendable {
    let path: String
    let isDirectory: Bool
    let presence: BatchTrashPhysicalPresence
}

/// FIFO two-permit gate shared by every path that prepares a replacement
/// Canvas/Base/embed native handle. Waiting is asynchronous so overlapping
/// refreshes do not occupy cooperative executor threads while permits are busy.
actor NativeDocumentPreparationLimiter {
    private let limit: Int
    private var availablePermits: Int
    private var waiters: [CheckedContinuation<Void, Never>] = []

    init(limit: Int = 2) {
        precondition(limit > 0)
        self.limit = limit
        availablePermits = limit
    }

    func acquire() async {
        if availablePermits > 0 {
            availablePermits -= 1
            return
        }
        await withCheckedContinuation { continuation in
            waiters.append(continuation)
        }
    }

    func release() {
        if !waiters.isEmpty {
            waiters.removeFirst().resume()
            return
        }
        precondition(availablePermits < limit)
        availablePermits += 1
    }
}

/// Cursor park deferred because the dirty-note navigation gate retained the
/// current editor. It may land only after this exact vault/path has loaded.
private struct DeferredTemplateCursorLanding {
    let sessionID: ObjectIdentifier
    let path: String
    let fileByteOffset: Int
}

enum BaseQueryBuilderPreviewExecutionPhase: Sendable, Equatable {
    case opened
    case executed
    case closed
}

/// Nil-default preview lifecycle observation surface. The recorded thread bit
/// is captured immediately before each synchronous native call; tests can also
/// suspend the observer after `opened` to hold a real handle across generations.
struct BaseQueryBuilderPreviewExecutionEvent: Sendable, Equatable {
    let phase: BaseQueryBuilderPreviewExecutionPhase
    let generation: Int
    let handle: UInt64
    let ranOnMainThread: Bool
}

enum BaseQueryBuilderPreviewExecutionOutcome: Sendable {
    case success(BasesResultSet)
    case failure(String)
    case cancelled
}

private struct SidebarActionValidationError: LocalizedError {
    let reason: String

    var errorDescription: String? { reason }
}

/// Top-level app state.
///
/// Owns the currently-open `VaultSession` (or none, on the welcome
/// screen) and the most-recent error surfaced from opening one. The
/// session is held until `closeVault()` is called or another vault is
/// opened. uniffi gives us back a reference-counted `VaultSession`, so
/// storing it on the main-thread state object is enough — the Rust
/// side keeps the SQLite connection alive as long as we hold a
/// reference.
@MainActor
final class AppState: ObservableObject {
    /// Invalidated synchronously whenever the mounted note identity changes.
    /// Kept separate from path/session so same-path tab remounts are distinct.
    private var noteAuthoringGeneration: UInt64 = 0

    private func invalidateNoteAuthoringOwnership() {
        noteAuthoringGeneration &+= 1
    }

    func noteAuthoringOwner(for path: String? = nil) -> NoteAuthoringOwner? {
        guard let session = currentSession, let loadedFilePath else { return nil }
        if let path, !BaseExactIdentity.matches(path, loadedFilePath) { return nil }
        return NoteAuthoringOwner(
            generation: noteAuthoringGeneration,
            sessionID: ObjectIdentifier(session),
            path: loadedFilePath)
    }

    func ownsNoteAuthoring(_ owner: NoteAuthoringOwner) -> Bool {
        guard let session = currentSession else { return false }
        return noteAuthoringGeneration == owner.generation
            && ObjectIdentifier(session) == owner.sessionID
            && BaseExactIdentity.matches(loadedFilePath, owner.path)
    }
    @Published private(set) var currentSession: VaultSession?
    @Published private(set) var currentVaultURL: URL?
    @Published private(set) var recentVaults: [RecentVault] = []
    @Published var lastError: String?
    /// Set when an attempt to open a recent-vaults entry fails because
    /// the path no longer exists. WelcomeView reads this to drive the
    /// "missing vault, remove from recent?" confirmation alert.
    @Published var missingRecentVault: RecentVault?
    /// Markdown files in the currently-open vault, sorted by relative
    /// path (case-insensitive). Populated by `loadFiles()` after the
    /// scanner finishes; empty while no vault is open or while the
    /// initial scan is still running.
    @Published private(set) var files: [FileSummary] = []
    /// True while the initial scan + file load is in progress for the
    /// current vault. Sidebar uses this to show a progress indicator.
    @Published private(set) var isScanning: Bool = false
    /// Latest progress event from the scanner. Updated unconditionally
    /// for every `Started`/`FileIndexed`/`Finished` so the sidebar's
    /// progress bar can stay current; cleared back to `nil` on
    /// terminal events (Finished/Cancelled/Failed) so the bar hides.
    @Published private(set) var scanProgress: ScanProgress?
    /// Surfaced when scanning or listing fails. Independent of
    /// `lastError` (which guards the open path).
    @Published var scanError: String?
    /// Path of the file currently selected in the sidebar, if any.
    /// `NoteContentView` reads the corresponding bytes via
    /// `currentNoteText`; AppState watches this property and kicks
    /// off the load whenever it changes.
    @Published var selectedFilePath: String?
    /// Monotone user-navigation edge for file opens originating outside the
    /// tree selection model (search, graph, links, templates, and commands).
    /// The tree consumes this independently of `selectedFilePath` so choosing
    /// an already-open result still protects newer user agency from a deferred
    /// structural landing.
    @Published private(set) var sidebarSelectionIntentRevision: UInt64 = 0

    // MARK: File-management command state (U2-5, #463)

    /// The most recent structural mutation the tree sidebar must react to
    /// (create/rename/move/delete). `FileTreeSidebar` observes this and drives
    /// its view-owned `FileTreeViewModel` — `treeInvalidation` for the affected
    /// levels, then `postMutationFocus` (U2-6) to move the selection. AppState
    /// owns the mutation funnel but not the tree VM (which is a `@StateObject`
    /// in the view, per U2-4), so this published seam is how the two connect —
    /// the same shape `selectedFilePath` uses to drive the tree.
    ///
    /// A monotonically-bumped `token` guarantees `.onChange` fires even when two
    /// mutations produce an equal event payload (e.g. two creates into root).
    @Published private(set) var treeMutation: TreeMutation?
    /// A targeted enriched-summary replacement emitted after a non-structural
    /// committed write. The view-owned tree applies it in place without
    /// refetching a potentially 5k-item sibling level.
    private(set) var sidebarFileSummaryUpdate: SidebarFileSummaryUpdate?
    /// Event channel rather than `@Published`: a metadata-only save must not
    /// invalidate every view observing the environment object. The sidebar
    /// receives the batch and updates only its keyed row observables.
    let sidebarFileSummaryUpdates = PassthroughSubject<[FileSummary], Never>()

    /// Surfaced when a structural mutation's link-rewrite pass left one or more
    /// files un-rewritten (`StructuralReport.failed`): the move/rename itself
    /// stood, but some notes' links to it couldn't be updated (an external edit
    /// raced us, malformed frontmatter, …). Drives a SPECIFIC alert listing the
    /// skipped files — never a silent drop (spec §U2-5 "surface … in a specific
    /// alert listing skipped files").
    @Published var structuralFailureReport: StructuralFailureReport?

    /// The tab currently in inline-rename mode in the tree, if any (U2-5). The
    /// tree row swaps its label for a `TextField` while this matches the row's
    /// node. Nil = no rename in progress. Set by the rename command, cleared on
    /// commit/cancel.
    @Published private(set) var renamingNode: RenamingNode?

    /// Drives the Move-to-folder sheet (U2-5). Non-nil = the sheet is up,
    /// carrying the node being moved. Cleared on commit/cancel.
    @Published private(set) var pendingMove: PendingMove?

    /// Drives the BATCH Move-to-folder sheet (#852): a multi-selection's items
    /// awaiting a destination. The same `MoveToFolderSheet` renders it (a batch
    /// initializer); commit routes every item through `batchMove`. Separate from
    /// `pendingMove` so the single-node path (U2-5) is untouched. Cleared on
    /// commit/cancel.
    @Published private(set) var pendingBatchMove: BatchMove?

    /// The complete native report for the latest batch structural operation.
    /// No report vector is flattened or discarded; MainSplitView derives its
    /// single attention presentation and copied details from this value.
    struct BatchStructuralResult: Identifiable, Equatable {
        enum MoveMode: Equatable {
            case forward(destination: String)
            case undo
            case redo
        }

        enum Operation: Equatable {
            case move(MoveMode)
            case trash
        }

        enum Payload: Equatable {
            case move(BatchMoveReport, mode: MoveMode)
            case trash(BatchTrashReport)
            case importBatch(ImportBatchFailureReport)
            case infrastructure(operation: Operation, message: String)
        }

        let id: UUID
        let payload: Payload
        let requiresAttention: Bool

        init(id: UUID = UUID(), payload: Payload, requiresAttention: Bool) {
            self.id = id
            self.payload = payload
            self.requiresAttention = requiresAttention
        }
    }

    struct ImportBatchFailureDetail: Equatable {
        enum Scope: Equatable {
            case provider(Int)
            case batch(stage: String)
        }

        enum Kind: Equatable {
            /// The source item did not reach its requested destination.
            case terminalFailure
            /// The item landed, but ancillary reconciliation needs attention.
            case warning
        }

        let scope: Scope
        let treeOrder: Int
        let item: String
        let reason: String
        let kind: Kind
        /// Stable identity of one failed source item. Multiple diagnostic rows
        /// for that item share this key; recursive provider entries use distinct
        /// keys. Providerless batch diagnostics intentionally carry nil.
        let terminalItemKey: String?
        /// Destination path whose create outcome can be resolved only by the
        /// mandatory authoritative scan. Nil for ordinary failures/warnings.
        let reconciliationCandidatePath: String?

        init(
            providerIndex: Int,
            treeOrder: Int,
            item: String,
            reason: String,
            kind: Kind = .terminalFailure,
            terminalItemKey: String? = nil,
            reconciliationCandidatePath: String? = nil
        ) {
            scope = .provider(providerIndex)
            self.treeOrder = treeOrder
            self.item = item
            self.reason = reason
            self.kind = kind
            self.terminalItemKey = kind == .terminalFailure
                ? (terminalItemKey ?? "provider:\(providerIndex)")
                : nil
            self.reconciliationCandidatePath = reconciliationCandidatePath
        }

        init(
            batchStage: String,
            treeOrder: Int,
            item: String,
            reason: String,
            kind: Kind = .warning
        ) {
            scope = .batch(stage: batchStage)
            self.treeOrder = treeOrder
            self.item = item
            self.reason = reason
            self.kind = kind
            terminalItemKey = nil
            reconciliationCandidatePath = nil
        }

        var sourceLabel: String {
            switch scope {
            case .provider(let index): return "Provider \(index + 1)"
            case .batch(let stage): return stage
            }
        }
    }

    /// The UI retains only Task 3's one bounded first-N presentation. The
    /// complete, admission-bounded ledger remains available to Copy Details so
    /// no path or reason becomes unrecoverable after the alert is dismissed.
    struct ImportBatchFailureReport: Equatable {
        static let presentationLimit = 5
        let allDetails: [ImportBatchFailureDetail]
        let details: [ImportBatchFailureDetail]
        let omittedCount: Int
        let terminalFailureCount: Int
        let warningCount: Int

        init(_ failures: [ImportBatchFailureDetail]) {
            let ordered = failures.enumerated().sorted { lhs, rhs in
                let left = lhs.element
                let right = rhs.element
                switch (left.scope, right.scope) {
                case (.provider(let leftIndex), .provider(let rightIndex)):
                    if leftIndex != rightIndex { return leftIndex < rightIndex }
                    if left.treeOrder != right.treeOrder {
                        return left.treeOrder < right.treeOrder
                    }
                case (.provider, .batch):
                    return true
                case (.batch, .provider):
                    return false
                case (.batch, .batch):
                    if left.treeOrder != right.treeOrder {
                        return left.treeOrder < right.treeOrder
                    }
                }
                return lhs.offset < rhs.offset
            }
            let orderedDetails = ordered.map(\.element)
            allDetails = orderedDetails
            details = Array(orderedDetails.prefix(Self.presentationLimit))
            omittedCount = allDetails.count - details.count
            // Diagnostic rows and failed source items are different ledgers.
            // Deduplicate native facts by provider occurrence, retain distinct
            // recursive external entries, and never infer an item from a
            // providerless batch diagnostic.
            terminalFailureCount = Set(allDetails.compactMap { detail in
                detail.kind == .terminalFailure ? detail.terminalItemKey : nil
            }).count
            warningCount = allDetails.count { $0.kind == .warning }
        }

        var totalDetailCount: Int { allDetails.count }
    }

    /// Pure copy and deterministic detail formatting shared by Move and Trash
    /// batch presentations. Preview generation is bounded to twenty entries;
    /// the complete report is expanded only when the user chooses Copy Details.
    struct BatchStructuralCopy {
        static let previewLimit = 20
        static let inlinePreviewLimit = 3

        struct Attention: Equatable {
            let title: String
            /// Bounded diagnostic preview retained for non-UI consumers.
            let message: String
            /// Alert-sized copy: summary, at most three detail lines, then the
            /// exact omitted count. This is the only copy rendered inline.
            let inlineMessage: String
            /// True whenever the complete report has at least one ledger line,
            /// even when every line fits in the inline preview.
            let hasDetails: Bool
            let hasOmittedDetails: Bool
            /// Deterministic operation-count seam for the O(20) preview gate.
            let previewWorkCount: Int
        }

        struct PreviewAccumulator {
            private(set) var lines: [String] = []
            private(set) var workCount = 0

            var remaining: Int { max(0, previewLimit - lines.count) }

            mutating func append(_ line: @autoclosure () -> String) {
                guard remaining > 0 else { return }
                workCount += 1
                lines.append(line())
            }

            mutating func append<Element>(
                contentsOf values: [Element],
                render: (Element) -> String
            ) {
                for value in values.prefix(remaining) {
                    workCount += 1
                    lines.append(render(value))
                }
            }
        }

        static func failureStageLabel(_ stage: BatchFailureStage) -> String {
            switch stage {
            case .preflight: return "Preflight"
            case .move: return "Move"
            case .index: return "Index"
            case .linkRewrite: return "Link update"
            case .linkRewriteRestore: return "Link restoration"
            case .journal: return "History recording"
            case .rollback: return "Restoration"
            case .trash: return "Trash"
            case .reconciliation: return "Reconciliation"
            case .recoveryBarrier: return "Recovery safety"
            }
        }

        static func failureLine(_ failure: BatchItemFailure) -> String {
            let identity = failure.item?.path ?? "Request"
            return "\(identity) — \(failureStageLabel(failure.stage)): \(failure.message)"
        }

        static func skipReasonLabel(_ reason: BatchSkipReason) -> String {
            switch reason {
            case .duplicate: return "Duplicate selection"
            case .coveredBySelectedFolder: return "Covered by selected folder"
            case .alreadyInDestination: return "Already in destination"
            }
        }

        /// UniFFI flattens this Rust enum into `(kind, detail)`. Preserve the
        /// raw value for future variants while giving every current kind useful
        /// copy even when its authoritative detail string is empty.
        static func rewriteFailureReason(_ failure: RewriteFailureKind) -> String {
            switch failure.kind {
            case "write_conflict":
                return failure.detail.isEmpty
                    ? "Write conflict" : "Write conflict: \(failure.detail)"
            case "malformed_frontmatter":
                return failure.detail.isEmpty
                    ? "Malformed frontmatter"
                    : "Malformed frontmatter: \(failure.detail)"
            case "cancelled":
                return failure.detail.isEmpty
                    ? "Cancelled" : "Cancelled: \(failure.detail)"
            case "other":
                return failure.detail.isEmpty
                    ? "Other error" : "Other: \(failure.detail)"
            default:
                return failure.detail.isEmpty
                    ? failure.kind : "\(failure.kind): \(failure.detail)"
            }
        }

        static func attention(for result: BatchStructuralResult) -> Attention {
            switch result.payload {
            case .trash(let report):
                return BatchTrashCopy.attention(for: report)
            case .move(let report, let mode):
                let preview = movePreviewEntries(report)
                let summary = moveSummary(report, mode: mode)
                let detailCount = moveDetailEntryCount(report)
                return Attention(
                    title: moveAttentionTitle(report.state),
                    message: previewMessage(
                        summary: summary,
                        entries: preview.lines,
                        totalEntryCount: detailCount),
                    inlineMessage: previewMessage(
                        summary: summary,
                        entries: preview.lines,
                        totalEntryCount: detailCount,
                        visibleEntryLimit: inlinePreviewLimit),
                    hasDetails: detailCount > 0,
                    hasOmittedDetails: detailCount > inlinePreviewLimit,
                    previewWorkCount: preview.workCount)
            case .importBatch(let report):
                let failureSummary = report.terminalFailureCount == 1
                    ? "1 item could not be imported."
                    : "\(report.terminalFailureCount) items could not be imported."
                let warningSummary = report.warningCount == 1
                    ? "1 import warning needs attention."
                    : "\(report.warningCount) import warnings need attention."
                let summary: String
                if report.terminalFailureCount == 0 {
                    summary = "Import completed. " + warningSummary
                } else if report.warningCount == 0 {
                    summary = failureSummary
                } else {
                    summary = failureSummary + " " + warningSummary
                }
                let entries = report.details.map {
                    "\($0.sourceLabel) — \($0.item): \($0.reason)"
                }
                let message = previewMessage(
                    summary: summary,
                    entries: entries,
                    totalEntryCount: report.totalDetailCount,
                    visibleEntryLimit: ImportBatchFailureReport.presentationLimit)
                return Attention(
                    title: report.terminalFailureCount > 0
                        ? "Some Items Were Not Imported"
                        : "Import Completed with Warnings",
                    message: message,
                    inlineMessage: message,
                    hasDetails: report.totalDetailCount > 0,
                    hasOmittedDetails: report.omittedCount > 0,
                    previewWorkCount: report.details.count)
            case .infrastructure(let operation, let message):
                let verb = operationLabel(operation)
                let copy =
                    "\(verb) could not finish safely.\nRequest — Infrastructure: \(message)"
                return Attention(
                    title: "\(verb) Did Not Finish Safely",
                    message: copy,
                    inlineMessage: copy,
                    hasDetails: true,
                    hasOmittedDetails: false,
                    previewWorkCount: 0)
            }
        }

        static func shouldOfferTrashReconciliation(
            for result: BatchStructuralResult,
            hasQuarantinedTrashItems: Bool
        ) -> Bool {
            guard hasQuarantinedTrashItems,
                case .trash(let report) = result.payload
            else { return false }
            return !report.unknown.isEmpty
        }

        static func copiedDetails(for result: BatchStructuralResult) -> String {
            switch result.payload {
            case .trash(let report):
                return BatchTrashCopy.copiedDetails(for: report)
            case .move(let report, let mode):
                var lines = [
                    "Move",
                    "State: \(moveStateLabel(report.state))",
                    "Mode: \(moveModeLabel(mode))",
                    "Summary: \(moveSummary(report, mode: mode))",
                ]
                if let opID = report.opId {
                    lines.append("Operation ID: \(opID)")
                }
                lines.append(contentsOf: moveDetailEntries(report))
                lines.append(
                    "Reconciliation required: \(report.requiresRescan ? "Yes" : "No")")
                return lines.joined(separator: "\n")
            case .importBatch(let report):
                let state = report.terminalFailureCount > 0
                    ? "Completed with failures"
                    : "Completed with warnings"
                var lines = ["Import", "State: \(state)"]
                lines.append(contentsOf: report.allDetails.map {
                    "\($0.sourceLabel) — \($0.item): \($0.reason)"
                })
                return lines.joined(separator: "\n")
            case .infrastructure(let operation, let message):
                let verb = operationLabel(operation)
                return [
                    verb,
                    "State: Infrastructure failure",
                    "Request — Infrastructure: \(message)",
                    "Reconciliation required: Yes",
                ].joined(separator: "\n")
            }
        }

        static func previewMessage(
            summary: String,
            entries: [String],
            totalEntryCount: Int,
            visibleEntryLimit: Int = previewLimit
        ) -> String {
            var lines = [summary]
            let visibleEntries = entries.prefix(visibleEntryLimit)
            lines.append(contentsOf: visibleEntries)
            let omitted = totalEntryCount - visibleEntries.count
            if omitted > 0 {
                lines.append("…and \(omitted) more")
            }
            return lines.joined(separator: "\n")
        }

        private static func operationLabel(
            _ operation: BatchStructuralResult.Operation
        ) -> String {
            switch operation {
            case .move: return "Move"
            case .trash: return "Trash"
            }
        }

        private static func moveModeLabel(
            _ mode: BatchStructuralResult.MoveMode
        ) -> String {
            switch mode {
            case .forward(let destination):
                return "Forward to \(destination.isEmpty ? "vault root" : destination)"
            case .undo: return "Undo"
            case .redo: return "Redo"
            }
        }

        private static func moveStateLabel(_ state: BatchMoveState) -> String {
            switch state {
            case .rejected: return "Rejected"
            case .noOp: return "No operation"
            case .succeeded: return "Succeeded"
            case .rolledBack: return "Restored"
            case .rollbackIncomplete: return "Restoration incomplete"
            }
        }

        private static func moveAttentionTitle(_ state: BatchMoveState) -> String {
            switch state {
            case .rejected: return "Move Could Not Start"
            case .noOp: return "Nothing Moved"
            case .succeeded: return "Move Completed with Details"
            case .rolledBack: return "Move Was Restored"
            case .rollbackIncomplete: return "Move Restoration Needs Attention"
            }
        }

        private static func moveSummary(
            _ report: BatchMoveReport,
            mode: BatchStructuralResult.MoveMode
        ) -> String {
            switch report.state {
            case .rejected:
                return "Move could not start. No items were moved."
            case .noOp:
                return "Nothing moved."
            case .succeeded:
                switch mode {
                case .forward(let destination):
                    let where_ = destination.isEmpty
                        ? "vault root" : (destination as NSString).lastPathComponent
                    return "Moved \(itemCountText(report.standing.count)) to \(where_)."
                case .undo:
                    return "Undid move of \(itemCountText(report.standing.count))."
                case .redo:
                    return "Redid move of \(itemCountText(report.standing.count))."
                }
            case .rolledBack:
                return "Move stopped. Slate restored every item to its original location."
            case .rollbackIncomplete:
                return "Move stopped. Slate restored "
                    + "\(itemCountText(report.rolledBack.count)). "
                    + "\(itemCountText(report.standing.count)) "
                    + "\(report.standing.count == 1 ? "remains in its" : "remain in their") "
                    + "new location."
            }
        }

        private static func itemCountText(_ count: Int) -> String {
            "\(count) \(count == 1 ? "item" : "items")"
        }

        private static func moveDetailEntryCount(_ report: BatchMoveReport) -> Int {
            (report.failure == nil ? 0 : 1)
                + report.rollbackFailures.count
                + report.envelope.preflightFailures.count
                + report.rewriteFailures.count
                + report.envelope.skipped.count
                + report.standing.count
                + report.rolledBack.count
                + report.rewritten.count
                + report.envelope.planned.count
        }

        private static func movePreviewEntries(
            _ report: BatchMoveReport
        ) -> PreviewAccumulator {
            var preview = PreviewAccumulator()
            if let failure = report.failure {
                preview.append(failureLine(failure))
            }
            preview.append(contentsOf: report.rollbackFailures, render: failureLine)
            preview.append(
                contentsOf: report.envelope.preflightFailures, render: failureLine)
            preview.append(contentsOf: report.rewriteFailures) { failure in
                "Link update failed — \(failure.path): "
                    + rewriteFailureReason(failure.kind)
            }
            preview.append(contentsOf: report.envelope.skipped) { skipped in
                    "Skipped — \(skipped.item.path): "
                        + "\(skipReasonLabel(skipped.reason)) — \(skipped.detail)"
            }
            preview.append(contentsOf: report.standing) { change in
                "Standing — \(change.oldPath) → \(change.newPath)"
            }
            preview.append(contentsOf: report.rolledBack) { change in
                "Restored — \(change.newPath) → \(change.oldPath)"
            }
            preview.append(contentsOf: report.rewritten) { outcome in
                "Link updated — \(outcome.path)"
            }
            preview.append(contentsOf: report.envelope.planned) { item in
                "Planned — \(item.path)"
            }
            return preview
        }

        private static func moveDetailEntries(_ report: BatchMoveReport) -> [String] {
            var lines: [String] = []
            if let failure = report.failure { lines.append(failureLine(failure)) }
            lines.append(contentsOf: report.rollbackFailures.map(failureLine))
            lines.append(contentsOf: report.envelope.preflightFailures.map(failureLine))
            lines.append(contentsOf: report.rewriteFailures.map {
                "Link update failed — \($0.path): "
                    + rewriteFailureReason($0.kind)
            })
            lines.append(contentsOf: report.envelope.skipped.map {
                "Skipped — \($0.item.path): \(skipReasonLabel($0.reason)) — \($0.detail)"
            })
            lines.append(contentsOf: report.standing.map {
                "Standing — \($0.oldPath) → \($0.newPath)"
            })
            lines.append(contentsOf: report.rolledBack.map {
                "Restored — \($0.newPath) → \($0.oldPath)"
            })
            lines.append(contentsOf: report.rewritten.map {
                "Link updated — \($0.path)"
            })
            lines.append(contentsOf: report.envelope.planned.map {
                "Planned — \($0.path)"
            })
            return lines
        }
    }

    /// Pure, report-driven copy for the batch system-Trash boundary. Keeping
    /// every state in one exhaustive switch prevents a partial/failed result
    /// from claiming that zero items moved when core returned exact successes.
    struct BatchTrashCopy {
        static let actionLabel = "Move to Trash"
        static let destructiveWarning = "Slate can't undo this action."
        static let actionHint =
            "Move the selected items and folder contents to the system Trash. "
            + destructiveWarning
        static let cancelLabel = "Cancel"
        static let cancelHint = "Keep the selected items. Nothing is moved to Trash."
        static let doneLabel = "Done"
        static let checkAgainLabel = "Check Again"
        static let checkAgainHint =
            "Refresh the vault and check whether the affected items are still present."
        static let copyDetailsLabel = "Copy Details"
        static let copyDetailsHint =
            "Copies the complete batch report, closes this report, and returns to the files sidebar."

        static func singleFolderConfirmationTitle(name: String) -> String {
            "Move “\(name)” to Trash?"
        }

        static func singleFolderConfirmationMessage(
            name: String,
            itemCount: Int
        ) -> String {
            "Move “\(name)” and its \(countText(itemCount)) to the system Trash. "
                + destructiveWarning
        }

        static func singleFolderCancelHint(name: String) -> String {
            "Keep “\(name)” and everything inside it. Nothing is moved to Trash."
        }

        static func singleFolderActionHint(name: String) -> String {
            "Move “\(name)” and everything inside it to the system Trash. "
                + destructiveWarning
        }

        static func confirmationTitle(itemCount: Int) -> String {
            "Move \(countText(itemCount)) to Trash?"
        }

        static func confirmationMessage(
            itemCount: Int,
            nonEmptyFolderCount: Int
        ) -> String {
            let folderClause: String
            if nonEmptyFolderCount > 0 {
                folderClause = ", including \(countText(nonEmptyFolderCount, noun: "folder")) "
                    + "with contents,"
            } else {
                folderClause = ""
            }
            return "Move \(countText(itemCount))\(folderClause) to the system Trash. "
                + destructiveWarning
        }

        static func countText(_ count: Int) -> String {
            "\(count) \(count == 1 ? "item" : "items")"
        }

        private static func countText(_ count: Int, noun: String) -> String {
            "\(count) \(count == 1 ? noun : noun + "s")"
        }

        static func ledgerCount(_ report: BatchTrashReport) -> Int {
            max(
                report.envelope.planned.count,
                report.trashed.count + report.untrashed.count + report.unknown.count)
        }

        static func announcement(for report: BatchTrashReport) -> String {
            switch report.state {
            case .rejected:
                if !report.unknown.isEmpty {
                    return "Couldn’t start moving the selected items to Trash. "
                        + unknownOutcomeSentence(report.unknown.count)
                        + rescanSentence(report)
                }
                return "Couldn’t start moving the selected items to Trash."
            case .noOp:
                if !report.unknown.isEmpty {
                    return unknownOutcomeSentence(report.unknown.count)
                        + rescanSentence(report)
                }
                return "Nothing was moved to Trash."
            case .succeeded:
                guard !report.trashed.isEmpty else {
                    if !report.unknown.isEmpty {
                        return unknownOutcomeSentence(report.unknown.count)
                            + rescanSentence(report)
                    }
                    return "Trash result could not be reconciled safely."
                }
                var message = "Moved \(countText(report.trashed.count)) to Trash."
                if !report.unknown.isEmpty {
                    message += " " + unknownOutcomeSentence(report.unknown.count)
                        + rescanSentence(report)
                }
                return message
            case .partial:
                let total = ledgerCount(report)
                let stayed = report.untrashed.count
                var sentences = [
                    "Moved \(report.trashed.count) of \(countText(total)) to Trash."
                ]
                if stayed > 0 {
                    sentences.append(
                        "\(countText(stayed)) \(stayed == 1 ? "was" : "were") not moved.")
                }
                if !report.unknown.isEmpty {
                    sentences.append(unknownOutcomeSentence(report.unknown.count))
                    if report.requiresRescan { sentences.append("Rescan required.") }
                }
                return sentences.joined(separator: " ")
            case .failed:
                let total = ledgerCount(report)
                if !report.unknown.isEmpty {
                    var sentences: [String] = []
                    if !report.trashed.isEmpty {
                        sentences.append(
                            "Moved \(report.trashed.count) of \(countText(total)) to Trash.")
                    }
                    let stayed = report.untrashed.count
                    if stayed > 0 {
                        sentences.append(
                            "\(countText(stayed)) \(stayed == 1 ? "was" : "were") not moved.")
                    }
                    sentences.append(unknownOutcomeSentence(report.unknown.count))
                    if report.requiresRescan { sentences.append("Rescan required.") }
                    return sentences.joined(separator: " ")
                }
                guard !report.trashed.isEmpty else {
                    return "Couldn’t move \(countText(total)) to Trash."
                }
                return "Moved \(report.trashed.count) of \(countText(total)) to Trash, "
                    + "but the operation did not finish safely."
            }
        }

        static func attention(
            for report: BatchTrashReport
        ) -> BatchStructuralCopy.Attention {
            let preview = previewEntries(report)
            let total = detailEntryCount(report)
            var message = [announcement(for: report)]
            message.append(contentsOf: preview.lines)
            let omitted = total - preview.lines.count
            if omitted > 0 {
                message.append("…and \(omitted) more")
            }
            return BatchStructuralCopy.Attention(
                title: attentionTitle(report),
                message: message.joined(separator: "\n"),
                inlineMessage: BatchStructuralCopy.previewMessage(
                    summary: announcement(for: report),
                    entries: preview.lines,
                    totalEntryCount: total,
                    visibleEntryLimit: BatchStructuralCopy.inlinePreviewLimit),
                hasDetails: total > 0,
                hasOmittedDetails: total > BatchStructuralCopy.inlinePreviewLimit,
                previewWorkCount: preview.workCount)
        }

        static func copiedDetails(for report: BatchTrashReport) -> String {
            var lines = [
                "Trash",
                "State: \(stateLabel(report.state))",
                "Summary: \(announcement(for: report))",
            ]
            if let opID = report.opId {
                lines.append("Operation ID: \(opID)")
            }
            lines.append(contentsOf: detailEntries(report))
            lines.append(
                "Reconciliation required: \(report.requiresRescan ? "Yes" : "No")")
            return lines.joined(separator: "\n")
        }

        private static func stateLabel(_ state: BatchTrashState) -> String {
            switch state {
            case .rejected: return "Rejected"
            case .noOp: return "No operation"
            case .succeeded: return "Succeeded"
            case .partial: return "Partial"
            case .failed: return "Failed"
            }
        }

        private static func attentionTitle(_ report: BatchTrashReport) -> String {
            if !report.unknown.isEmpty { return "Trash Outcome Needs Review" }
            switch report.state {
            case .rejected: return "Trash Could Not Start"
            case .noOp: return "Nothing Moved to Trash"
            case .succeeded: return "Trash Completed with Details"
            case .partial: return "Some Items Were Not Moved"
            case .failed: return "Trash Did Not Finish Safely"
            }
        }

        private static func detailEntryCount(_ report: BatchTrashReport) -> Int {
            report.bookkeepingFailures.count
                + (report.untrashed.count * 2)
                + (report.unknown.count * 2)
                + report.envelope.preflightFailures.count
                + report.envelope.skipped.count
                + report.trashed.count
                + report.envelope.planned.count
        }

        private static func previewEntries(
            _ report: BatchTrashReport
        ) -> BatchStructuralCopy.PreviewAccumulator {
            var preview = BatchStructuralCopy.PreviewAccumulator()
            preview.append(
                contentsOf: report.bookkeepingFailures,
                render: BatchStructuralCopy.failureLine)
            for remainder in report.unknown {
                guard preview.remaining > 0 else { break }
                preview.append("Outcome unknown — \(remainder.item.path)")
                preview.append(BatchStructuralCopy.failureLine(remainder.failure))
            }
            for remainder in report.untrashed {
                guard preview.remaining > 0 else { break }
                preview.append("Not moved — \(remainder.item.path)")
                preview.append(BatchStructuralCopy.failureLine(remainder.failure))
            }
            preview.append(
                contentsOf: report.envelope.preflightFailures,
                render: BatchStructuralCopy.failureLine)
            preview.append(contentsOf: report.envelope.skipped) { skipped in
                    "Skipped — \(skipped.item.path): "
                        + "\(BatchStructuralCopy.skipReasonLabel(skipped.reason)) — "
                        + skipped.detail
            }
            preview.append(contentsOf: report.trashed) { item in
                "Moved to system Trash — \(item.path)"
            }
            preview.append(contentsOf: report.envelope.planned) { item in
                "Planned — \(item.path)"
            }
            return preview
        }

        private static func detailEntries(_ report: BatchTrashReport) -> [String] {
            var lines = report.bookkeepingFailures.map(BatchStructuralCopy.failureLine)
            for remainder in report.unknown {
                lines.append("Outcome unknown — \(remainder.item.path)")
                lines.append(BatchStructuralCopy.failureLine(remainder.failure))
            }
            for remainder in report.untrashed {
                lines.append("Not moved — \(remainder.item.path)")
                lines.append(BatchStructuralCopy.failureLine(remainder.failure))
            }
            lines.append(
                contentsOf: report.envelope.preflightFailures.map(
                    BatchStructuralCopy.failureLine))
            lines.append(contentsOf: report.envelope.skipped.map {
                "Skipped — \($0.item.path): "
                    + "\(BatchStructuralCopy.skipReasonLabel($0.reason)) — \($0.detail)"
            })
            lines.append(contentsOf: report.trashed.map {
                "Moved to system Trash — \($0.path)"
            })
            lines.append(contentsOf: report.envelope.planned.map {
                "Planned — \($0.path)"
            })
            return lines
        }

        private static func unknownOutcomeSentence(_ count: Int) -> String {
            "Couldn’t verify whether \(countText(count)) moved to Trash."
        }

        private static func rescanSentence(_ report: BatchTrashReport) -> String {
            report.requiresRescan ? " Rescan required." : ""
        }
    }

    @Published private(set) var batchStructuralResult: BatchStructuralResult?

    /// One presentation owner shared by the sidebar's 10+ file Open gate and
    /// MainSplitView's batch-attention result. A second alert is retained in a
    /// typed deferred slot and can only advance after the active UUID resolves.
    enum BatchAlertPresentation: Equatable, Identifiable {
        case open(SidebarOpenSelectionRequest)
        case result(BatchStructuralResult)

        var id: UUID {
            switch self {
            case .open(let request): return request.id
            case .result(let result): return result.id
            }
        }
    }

    @Published private(set) var activeBatchAlertPresentation: BatchAlertPresentation?
    @Published private(set) var deferredBatchAlertPresentation: BatchAlertPresentation?

    @discardableResult
    func enqueueOpenSelection(_ request: SidebarOpenSelectionRequest) -> Bool {
        guard isCurrentOpenSelection(request) else { return false }
        enqueueBatchAlert(.open(request))
        return true
    }

    /// Continue one staged multi-open inside AppState. The exact frozen intent,
    /// current catalog availability, navigation gate, and every filesystem item
    /// are revalidated before the alert clears or any tab opens.
    @discardableResult
    func confirmOpenSelection(id: UUID) -> SidebarOpenConfirmationOutcome {
        guard case .open(let request)? = activeBatchAlertPresentation,
            request.id == id
        else { return .ignored }

        let offloadsFilesystemValidation =
            Self.sidebarActionValidationRequiresOffload(
                request.intent.snapshot.items)
        let definition: SidebarActionDefinition
        do {
            definition = try validateSidebarActionIntent(
                request.intent,
                validateFilesystem: !offloadsFilesystemValidation)
            guard definition.id == SlateCommandID.sidebarOpen else {
                throw SidebarActionValidationError(
                    reason: Self.sidebarSelectionChangedReason)
            }
            if let preflight = sidebarActionDispatchOverrides.openPreflight {
                guard preflight(request.batch) else {
                    throw SidebarActionValidationError(
                        reason: "\(definition.label) could not start.")
                }
            } else if let reason = propertyEditNavigationDisabledReason {
                throw SidebarActionValidationError(reason: reason)
            }
        } catch let error as SidebarActionValidationError {
            return rejectOpenSelectionConfirmation(error.reason)
        } catch {
            return rejectOpenSelectionConfirmation(error.localizedDescription)
        }

        if offloadsFilesystemValidation {
            activeBatchAlertPresentation = nil
            promoteDeferredBatchAlert()
            beginSidebarActionValidation(
                request.intent,
                definition: definition
            ) { state in
                if let preflight = state.sidebarActionDispatchOverrides.openPreflight {
                    guard preflight(request.batch) else {
                        throw SidebarActionValidationError(
                            reason: "\(definition.label) could not start.")
                    }
                } else if let reason = state.propertyEditNavigationDisabledReason {
                    throw SidebarActionValidationError(reason: reason)
                }

                let executionPaths = request.batch.executionPaths
                for (index, path) in executionPaths.enumerated() {
                    if index > 0, index.isMultiple(of: 32) {
                        await Task.yield()
                        guard let session = state.currentSession,
                            ObjectIdentifier(session) == request.sessionIdentity
                        else { return }
                        if let reason = state.propertyEditNavigationDisabledReason {
                            throw SidebarActionValidationError(reason: reason)
                        }
                    }
                    if let openPath = state.sidebarActionDispatchOverrides.openPath {
                        guard openPath(path, .newTab) else {
                            throw SidebarActionValidationError(
                                reason: "Open could not start.")
                        }
                    } else {
                        state.openFile(path, target: .newTab)
                    }
                }
            }
            return .validationPending
        }

        let executionPaths = request.batch.executionPaths
        for path in executionPaths {
            if let openPath = sidebarActionDispatchOverrides.openPath {
                guard openPath(path, .newTab) else {
                    return rejectOpenSelectionConfirmation("Open could not start.")
                }
            } else {
                openFile(path, target: .newTab)
            }
        }

        activeBatchAlertPresentation = nil
        promoteDeferredBatchAlert()
        return .opened(executionPaths)
    }

    private func rejectOpenSelectionConfirmation(
        _ reason: String
    ) -> SidebarOpenConfirmationOutcome {
        activeBatchAlertPresentation = nil
        promoteDeferredBatchAlert()
        announcer.post(reason, priority: .medium)
        return .rejected(reason)
    }

    @discardableResult
    func cancelOpenSelection(id: UUID) -> Bool {
        guard case .open(let request)? = activeBatchAlertPresentation,
            request.id == id
        else { return false }
        activeBatchAlertPresentation = nil
        promoteDeferredBatchAlert()
        return true
    }

    @discardableResult
    func dismissBatchStructuralResult(id: UUID) -> Bool {
        guard case .result(let result)? = activeBatchAlertPresentation,
            result.id == id
        else { return false }
        if batchStructuralResult?.id == id {
            batchStructuralResult = nil
        }
        activeBatchAlertPresentation = nil
        promoteDeferredBatchAlert()
        return true
    }

    @discardableResult
    func copyBatchStructuralDetails(id: UUID) -> Bool {
        guard case .result(let result)? = activeBatchAlertPresentation,
            result.id == id
        else {
            return false
        }
        let details = BatchStructuralCopy.copiedDetails(for: result)
        return batchStructuralDetailsCopier(details)
    }

    /// Injectable only so the copy+dismiss interaction is deterministic in
    /// behavior tests; production owns the one system-pasteboard write here.
    var batchStructuralDetailsCopier: (String) -> Bool = { details in
        NSPasteboard.general.clearContents()
        return NSPasteboard.general.setString(details, forType: .string)
    }

    /// Copy Details is one UUID-owned action: copy the complete report, then
    /// dismiss exactly that result and promote its deferred alert (if any).
    @discardableResult
    func copyAndDismissBatchStructuralDetails(id: UUID) -> Bool {
        guard copyBatchStructuralDetails(id: id) else { return false }
        return dismissBatchStructuralResult(id: id)
    }

    private func setBatchStructuralResult(_ result: BatchStructuralResult) {
        batchStructuralResult = result
        guard result.requiresAttention else {
            if case .result? = deferredBatchAlertPresentation {
                deferredBatchAlertPresentation = nil
            }
            return
        }
        enqueueBatchAlert(.result(result))
    }

    private func enqueueBatchAlert(_ presentation: BatchAlertPresentation) {
        guard activeBatchAlertPresentation != nil else {
            activeBatchAlertPresentation = presentation
            return
        }
        deferredBatchAlertPresentation = presentation
    }

    private func promoteDeferredBatchAlert() {
        guard activeBatchAlertPresentation == nil else { return }
        guard let deferred = deferredBatchAlertPresentation else { return }
        deferredBatchAlertPresentation = nil
        guard isCurrentBatchAlert(deferred) else {
            promoteDeferredBatchAlert()
            return
        }
        activeBatchAlertPresentation = deferred
    }

    private func isCurrentBatchAlert(_ presentation: BatchAlertPresentation) -> Bool {
        switch presentation {
        case .open(let request):
            return isCurrentOpenSelection(request)
        case .result(let result):
            return batchStructuralResult?.id == result.id
        }
    }

    private func isCurrentOpenSelection(
        _ request: SidebarOpenSelectionRequest
    ) -> Bool {
        guard let session = currentSession else { return false }
        return request.sessionIdentity == ObjectIdentifier(session)
    }

    private func resetBatchAlertPresentations() {
        activeBatchAlertPresentation = nil
        deferredBatchAlertPresentation = nil
        batchStructuralResult = nil
    }

    typealias BatchMoveRunner =
        @Sendable (VaultSession, BatchMoveRequest) async throws -> BatchMoveReport
    typealias BatchTrashRunner =
        @Sendable (VaultSession, BatchTrashRequest) async throws -> BatchTrashReport
    typealias BatchDeleteConfirmationProbeRunner =
        @Sendable (URL, [String]) async -> Int
    typealias BatchTrashPresenceProbeRunner =
        @Sendable (URL, Bool) -> BatchTrashPhysicalPresence
    typealias BatchUndoMoveRunner =
        @Sendable (VaultSession, Int64) async throws -> BatchMoveReport
    typealias StructuralBatchRefreshRunner =
        @MainActor @Sendable (AppState) async -> Void
    typealias ImportRefreshRunner =
        @MainActor @Sendable (AppState, VaultSession) async throws -> Void
    typealias StructuralRenameRunner =
        @Sendable (VaultSession, String, Bool, String) async throws -> StructuralReport
    typealias TemplateListRunner = @Sendable (VaultSession, CancelToken) -> Result<
        [TemplateSummary], VaultError
    >

    var batchMoveRunner: BatchMoveRunner = { session, request in
        try await Task.detached(priority: .userInitiated) {
            try session.batchMove(request: request)
        }.value
    }
    var batchTrashRunner: BatchTrashRunner = { session, request in
        try await Task.detached(priority: .userInitiated) {
            try session.batchTrash(request: request)
        }.value
    }
    var batchTrashPresenceProbeRunner: BatchTrashPresenceProbeRunner = {
        url, expectedIsDirectory in
        AppState.batchTrashPhysicalPresence(
            at: url, expectedIsDirectory: expectedIsDirectory)
    }
    var batchDeleteConfirmationProbeRunner: BatchDeleteConfirmationProbeRunner = {
        vaultURL, folderPaths in
        await Task.detached(priority: .userInitiated) {
            folderPaths.reduce(into: 0) { count, path in
                let url = vaultURL.appendingPathComponent(path, isDirectory: true)
                if AppState.batchDeleteFolderRequiresConfirmation(at: url) {
                    count += 1
                }
            }
        }.value
    }
    var batchUndoMoveRunner: BatchUndoMoveRunner = { session, opID in
        try await Task.detached(priority: .userInitiated) {
            try session.undoBatchMove(opId: opID)
        }.value
    }
    var structuralBatchRefreshRunner: StructuralBatchRefreshRunner = { state in
        await state.loadFiles()
    }
    /// Clean import landings need only the indexed file inventory. This seam is
    /// intentionally separate from every pre-existing structural operation,
    /// whose uncertainty contract continues to use a full scan.
    var importInventoryRefreshRunner: ImportRefreshRunner = { state, session in
        try await state.reloadImportInventoryOnly(for: session)
    }
    /// All copy/move/list uncertainty coalesces into this one scan, always after
    /// native work. The import owner remains live so FileTree suppresses the
    /// generic scan-finish invalidation and accepts only the aggregate landing.
    var importScanRefreshRunner: ImportRefreshRunner = { state, session in
        try await state.reloadImportInventoryWithAuthoritativeScan(for: session)
    }
    var importDestinationCreators:
        @Sendable (VaultSession) -> SidebarImportDestinationCreators = {
            .production(session: $0)
        }
    var importSourceWalkerHooks = SidebarImportSourceWalkerHooks()
    /// Deterministic race seam for the accepted two-phase New Folder → Move
    /// carve-out. Tests park after the folder create releases its owner and
    /// before the dependent move tries to claim the gate. Nil in production.
    var createFolderMoveContinuationGateForTesting: (() async -> Void)?
    /// Deterministic race seam after Duplicate installs its exact dynamic
    /// destination reservation and before the exclusive native create. Nil in
    /// production; ownership is revalidated after any test suspension.
    var duplicateCandidateReservationGateForTesting:
        (@MainActor @Sendable (String) async -> Void)?
    var structuralRenameRunner: StructuralRenameRunner = {
        session, path, isDirectory, newName in
        try await Task.detached(priority: .userInitiated) {
            isDirectory
                ? try session.renameFolder(path: path, newName: newName)
                : try session.renameFile(path: path, newName: newName)
        }.value
    }

    /// Session-tagged, visible-order sidebar selection. This is published by
    /// the semantic selection model synchronously at the mutation edge; action
    /// surfaces never infer a batch from the native List's single focus row.
    @Published private(set) var sidebarSelectionSnapshot: SidebarSelectionSnapshot?

    /// Full lstat admission is cheap for ordinary selections but can exceed an
    /// interaction frame for thousands of rows. At this boundary, the frozen
    /// walk moves off the main actor before any action funnel can run.
    static let sidebarActionValidationComponentBudget = 1_000
    static let sidebarActionValidationPendingReason =
        "Wait for Slate to finish checking the selected items."
    static let sidebarWikilinkCopyPendingReason =
        "Wait for Slate to finish creating the wikilink."

    private static func sidebarActionValidationRequiresOffload(
        _ items: [SidebarSelectionItem]
    ) -> Bool {
        var componentWork = 0
        for item in items {
            componentWork += item.path.split(
                separator: "/",
                omittingEmptySubsequences: false
            ).count
            if componentWork >= sidebarActionValidationComponentBudget {
                return true
            }
        }
        return false
    }

    @Published private(set) var isValidatingSidebarAction = false
    @Published private(set) var sidebarActionBackgroundFailure: String?
    private var sidebarActionValidationToken = 0
    private(set) var pendingSidebarActionValidationTaskForTesting: Task<Void, Never>?
    private(set) var sidebarActionValidationRanOnMainThreadForTesting: Bool?
    var sidebarActionValidationItemProbeForTesting: (@Sendable (Int) -> Void)?

    @Published private(set) var isCopyingSidebarWikilink = false
    private var sidebarWikilinkCopyToken = 0
    private(set) var pendingSidebarWikilinkCopyTaskForTesting: Task<Void, Never>?

    var sidebarActionBackgroundProgressReason: String? {
        if isValidatingSidebarAction {
            return Self.sidebarActionValidationPendingReason
        }
        if isCopyingSidebarWikilink {
            return Self.sidebarWikilinkCopyPendingReason
        }
        return nil
    }

    /// Narrow, optional leaf seams for dispatcher tests. Nil always means the
    /// production path below, which calls the existing AppState funnel or the
    /// one unavoidable external boundary directly.
    struct SidebarActionDispatchOverrides {
        var openPreflight: ((SidebarOpenSelectionBatch) -> Bool)?
        var openPath: ((String, OpenTarget) -> Bool)?
        var createNote: ((String) -> Bool)?
        var createFolder: ((String) -> Bool)?
        var openTemplatePicker: ((String) -> Bool)?
        var rename: ((TreeSelection) -> Bool)?
        var moveSingle: ((TreeSelection) -> Bool)?
        var moveBatch: (([TreeSelection], String?) -> Bool)?
        var duplicate: ((String) -> Bool)?
        var reveal: ((URL, String) -> Bool)?
        var wikilink: (@Sendable (VaultSession, String) throws -> String?)?
        var trashSingle: ((TreeSelection) -> Bool)?
        var trashBatch: (([TreeSelection], String?) -> Bool)?
    }

    var sidebarActionDispatchOverrides = SidebarActionDispatchOverrides()

    /// Deterministic structural-reason seam. Nil preserves the live structural
    /// writer gate; tests can inject one exact current reason without starting
    /// unrelated asynchronous work.
    var sidebarActionStructuralDisabledReasonOverride: String?

    /// Task 4 installs template loading/failed availability here. Keeping the
    /// resolver AppState-owned lets render projection and activation query the
    /// same current state without filesystem I/O.
    var sidebarActionAvailabilityReasonProvider: (String) -> String? = { _ in nil }

    nonisolated static let sidebarSelectionChangedReason =
        "The sidebar selection changed. Select the items again and retry."
    static let sidebarSelectionStaleReason =
        "That Sidebar action belongs to a vault that is no longer open."
    static let sidebarCopyFailureReason = "Could not copy to the clipboard."
    static let sidebarWikilinkFailureReason =
        "Could not create a wikilink for this file."

    /// Accept a tree-owned snapshot only while the exact captured native
    /// session is current. A late publisher from a replaced tree is ignored;
    /// it is never re-stamped with the replacement session identity.
    @discardableResult
    func publishSidebarSelectionSnapshot(_ snapshot: SidebarSelectionSnapshot) -> Bool {
        guard let session = currentSession,
            ObjectIdentifier(session) == snapshot.sessionIdentity
        else { return false }
        sidebarSelectionSnapshot = snapshot
        let focusedItem = snapshot.focusedPath.flatMap { focusedPath in
            snapshot.items.first(where: { $0.path == focusedPath })
        }
        treeSelectedNode = focusedItem.map {
            TreeSelection(path: $0.path, isDirectory: $0.isDirectory)
        }
        return true
    }

    /// Revalidate a frozen invocation against the owning session and the live
    /// filesystem before any multi-item action performs its first side effect.
    /// Every path component is checked with lstat semantics, so both live and
    /// dangling symlinks fail closed and an intermediate link cannot escape the
    /// vault root.
    @discardableResult
    func validateSidebarActionIntent(
        _ intent: SidebarActionCatalog.InvocationIntent,
        validateFilesystem: Bool = true,
        ignoringOwnedSidebarValidation: Bool = false
    ) throws -> SidebarActionDefinition {
        guard let session = currentSession, let vaultURL = currentVaultURL,
            ObjectIdentifier(session) == intent.snapshot.sessionIdentity
        else {
            throw SidebarActionValidationError(reason: Self.sidebarSelectionStaleReason)
        }
        var currentActionDisabledReasons = sidebarActionDisabledReasons
        if isValidatingSidebarAction, !ignoringOwnedSidebarValidation {
            currentActionDisabledReasons[SlateCommandID.sidebarOpen] =
                Self.sidebarActionValidationPendingReason
        }
        guard let evaluation = SidebarActionCatalog.evaluation(
            for: intent.actionID,
            snapshot: intent.snapshot,
            structuralMutationDisabledReason:
                sidebarActionStructuralDisabledReasonOverride
                ?? (ignoringOwnedSidebarValidation
                    ? sidebarValidationIndependentStructuralMutationDisabledReason
                    : structuralMutationDisabledReason),
            actionDisabledReasons: currentActionDisabledReasons)
        else {
            throw SidebarActionValidationError(reason: Self.sidebarSelectionChangedReason)
        }
        guard let acceptedIntent = evaluation.intent,
            acceptedIntent == intent
        else {
            throw SidebarActionValidationError(
                reason: evaluation.disabledReason ?? Self.sidebarSelectionChangedReason)
        }

        if validateFilesystem {
            try Self.validateSidebarSelectionItems(
                intent.snapshot.items,
                vaultURL: vaultURL)
        }
        return evaluation.definition
    }

    /// Capture the current sidebar state exactly once, then route through the
    /// same frozen-intent executor used by every other action surface.
    func dispatchSidebarAction(id: String) throws -> SidebarActionDispatchResult {
        guard let evaluation = sidebarActionProjection(surface: .commandPalette)
            .first(where: { $0.id == id })
        else {
            throw sidebarActionFailure(Self.sidebarSelectionChangedReason)
        }
        guard let frozenIntent = evaluation.intent else {
            throw sidebarActionFailure(
                evaluation.disabledReason ?? Self.sidebarSelectionChangedReason)
        }
        return try dispatchSidebarAction(frozenIntent)
    }

    /// The one sidebar action executor. Validation finishes for the complete
    /// frozen selection before this switch reaches any AppState funnel or
    /// external boundary. Synchronous failures are returned to the caller;
    /// Task 3 owns Copy side effects and announcements.
    func dispatchSidebarAction(
        _ intent: SidebarActionInvocationIntent,
        filesystemAlreadyValidated: Bool = false
    ) throws -> SidebarActionDispatchResult {
        let itemCount = intent.snapshot.items.count
        let stagesOpenConfirmation =
            intent.actionID == SlateCommandID.sidebarOpen && itemCount >= 10
        let offloadsLargeStructuralValidation =
            !filesystemAlreadyValidated
            && Self.sidebarActionValidationRequiresOffload(
                intent.snapshot.items)
            && (intent.actionID == SlateCommandID.moveTo
                || intent.actionID == SlateCommandID.deleteEntry)
        let definition: SidebarActionDefinition
        do {
            definition = try validateSidebarActionIntent(
                intent,
                validateFilesystem:
                    filesystemAlreadyValidated
                    || stagesOpenConfirmation
                    || offloadsLargeStructuralValidation
                    ? false : true)
        } catch let error as SidebarActionValidationError {
            throw sidebarActionFailure(error.reason)
        } catch {
            throw sidebarActionFailure(error.localizedDescription)
        }

        // A newly admitted invocation is the user's retry path. Clear an older
        // detached-validation warning only after this intent itself passes live
        // session/catalog admission, so a stale click cannot erase recovery.
        sidebarActionBackgroundFailure = nil

        if offloadsLargeStructuralValidation {
            return startSidebarActionValidation(
                intent,
                definition: definition)
        }

        let rejected = "\(definition.label) could not start."
        switch intent.actionID {
        case SlateCommandID.sidebarOpen:
            let batch = SidebarOpenSelectionBatch(
                paths: intent.snapshot.items.map(\.path),
                focusedPath: intent.snapshot.focusedPath)
            if let preflight = sidebarActionDispatchOverrides.openPreflight {
                guard preflight(batch) else { throw sidebarActionFailure(rejected) }
            } else if let reason = propertyEditNavigationDisabledReason {
                throw sidebarActionFailure(reason)
            }

            if batch.paths.count >= 10 {
                let request = SidebarOpenSelectionRequest(intent: intent)
                guard enqueueOpenSelection(request) else {
                    throw sidebarActionFailure(rejected)
                }
                return .openConfirmation(request)
            }

            let executionPaths = batch.executionPaths
            let openTarget: OpenTarget = executionPaths.count == 1
                ? .currentTab : .newTab
            for path in executionPaths {
                if let openPath = sidebarActionDispatchOverrides.openPath {
                    guard openPath(path, openTarget) else {
                        throw sidebarActionFailure(rejected)
                    }
                } else {
                    openFile(path, target: openTarget)
                }
            }
            return .opened(executionPaths)

        case SlateCommandID.newNote:
            let parent = try canonicalSidebarCreationParent(
                for: intent.snapshot, rejection: rejected)
            let admitted: Bool
            if let createNote = sidebarActionDispatchOverrides.createNote {
                admitted = createNote(parent)
            } else if let task = requestCreateNote(in: parent) {
                pendingStructuralTaskForTesting = task
                admitted = true
            } else {
                admitted = false
            }
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.newFolder:
            let parent = try canonicalSidebarCreationParent(
                for: intent.snapshot, rejection: rejected)
            let admitted = sidebarActionDispatchOverrides.createFolder?(parent)
                ?? requestCreateFolder(in: parent)
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.newFromTemplate:
            if isCommandPaletteOpen,
                templateShortcutWindowOwnsActionLauncher(
                    templateShortcutKeyWindowProvider())
            {
                // The Command Palette is an action-launcher sheet, not a
                // blocking authoring dialog. Retire it before staging the
                // template sheet so the two presentations never overlap.
                isCommandPaletteOpen = false
            }
            let parent = try canonicalSidebarCreationParent(
                for: intent.snapshot, rejection: rejected)
            let admitted = sidebarActionDispatchOverrides.openTemplatePicker?(parent)
                ?? (openTemplatePicker(in: parent) != nil)
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.importFilesAndFolders:
            guard let capturedSession = currentSession else {
                throw sidebarActionFailure(rejected)
            }
            let frozenParent = try canonicalSidebarCreationParent(
                for: intent.snapshot, rejection: rejected)
            let frozenRevision = intent.snapshot.selectionRevision

            // `runModal` spins a nested AppKit event loop. Retire the action
            // launcher first, then revalidate every frozen owner fact after
            // the panel returns before claiming structural ownership.
            if isCommandPaletteOpen { isCommandPaletteOpen = false }
            guard let selectedURLs = importSourcePicker() else {
                return .completed(actionID: intent.actionID)
            }
            guard !selectedURLs.isEmpty else {
                return .completed(actionID: intent.actionID)
            }
            guard selectedURLs.count
                <= SidebarImportProviderIntake.maximumProviderCount
            else {
                sidebarActionBackgroundFailure = Self.importProviderLimitReason
                throw sidebarActionFailure(Self.importProviderLimitReason)
            }
            guard currentSession === capturedSession,
                sidebarSelectionSnapshot?.selectionRevision == frozenRevision
            else {
                throw sidebarActionFailure(Self.sidebarSelectionChangedReason)
            }
            do {
                _ = try validateSidebarActionIntent(intent)
            } catch let error as SidebarActionValidationError {
                throw sidebarActionFailure(error.reason)
            } catch {
                throw sidebarActionFailure(error.localizedDescription)
            }
            let liveParent = try canonicalSidebarCreationParent(
                for: intent.snapshot, rejection: rejected)
            guard liveParent == frozenParent else {
                throw sidebarActionFailure(Self.sidebarSelectionChangedReason)
            }
            let providers = selectedURLs.map { url in
                let provider = NSItemProvider()
                provider.registerDataRepresentation(
                    forTypeIdentifier: FileTreeSidebar.fileURLUTType,
                    visibility: .all
                ) { completion in
                    completion(url.dataRepresentation, nil)
                    return nil
                }
                return provider
            }
            guard let owner = beginImportBatch(
                providers: providers,
                destinationFolder: frozenParent,
                selectionRevision: frozenRevision)
            else { throw sidebarActionFailure(rejected) }
            _ = startImportBatch(owner)
            return .completed(actionID: intent.actionID)

        case SlateCommandID.renameEntry:
            let item = intent.snapshot.items[0]
            let selection = TreeSelection(
                path: item.path, isDirectory: item.isDirectory)
            let admitted = sidebarActionDispatchOverrides.rename?(selection)
                ?? requestRename(
                    path: selection.path, isDirectory: selection.isDirectory)
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.moveTo:
            let selections = intent.snapshot.items.map {
                TreeSelection(path: $0.path, isDirectory: $0.isDirectory)
            }
            let admitted: Bool
            if selections.count == 1, let selection = selections.first {
                admitted = sidebarActionDispatchOverrides.moveSingle?(selection)
                    ?? requestPendingMove(
                        path: selection.path, isDirectory: selection.isDirectory)
            } else {
                admitted = sidebarActionDispatchOverrides.moveBatch?(
                    selections, intent.snapshot.focusedPath)
                    ?? requestBatchMove(
                        selections,
                        preferredFocusPath: intent.snapshot.focusedPath)
            }
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.duplicateEntry:
            let path = intent.snapshot.items[0].path
            let admitted: Bool
            if let duplicate = sidebarActionDispatchOverrides.duplicate {
                admitted = duplicate(path)
            } else if let task = requestDuplicateEntry(path: path) {
                pendingStructuralTaskForTesting = task
                admitted = true
            } else {
                admitted = false
            }
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.revealInFinder:
            guard let vaultURL = currentVaultURL else {
                throw sidebarActionFailure(rejected)
            }
            let path = intent.snapshot.items[0].path
            let admitted: Bool
            if let reveal = sidebarActionDispatchOverrides.reveal {
                admitted = reveal(vaultURL, path)
            } else {
                NSWorkspace.shared.activateFileViewerSelecting([
                    vaultURL.appendingPathComponent(path)
                ])
                admitted = true
            }
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.copyPath:
            invalidateSidebarWikilinkCopy()
            return try completeSidebarCopy(
                intent.snapshot.items[0].path,
                actionID: intent.actionID)

        case SlateCommandID.sidebarCopyWikilink:
            guard let session = currentSession else {
                throw sidebarActionFailure(rejected)
            }
            return startSidebarWikilinkCopy(intent, session: session)

        case SlateCommandID.deleteEntry:
            let selections = intent.snapshot.items.map {
                TreeSelection(path: $0.path, isDirectory: $0.isDirectory)
            }
            let admitted: Bool
            if selections.count == 1, let selection = selections.first {
                admitted = sidebarActionDispatchOverrides.trashSingle?(selection)
                    ?? requestDeleteEntry(
                        path: selection.path, isDirectory: selection.isDirectory)
            } else {
                admitted = sidebarActionDispatchOverrides.trashBatch?(
                    selections, intent.snapshot.focusedPath)
                    ?? requestBatchDelete(
                        selections,
                        preferredFocusPath: intent.snapshot.focusedPath)
            }
            guard admitted else { throw sidebarActionFailure(rejected) }
            return .completed(actionID: intent.actionID)

        case SlateCommandID.sidebarSortNameAsc,
            SlateCommandID.sidebarSortNameDesc,
            SlateCommandID.sidebarSortCreatedDesc,
            SlateCommandID.sidebarSortCreatedAsc,
            SlateCommandID.sidebarSortModifiedDesc,
            SlateCommandID.sidebarSortModifiedAsc,
            SlateCommandID.sidebarToggleDateGrouping,
            SlateCommandID.sidebarUseVaultDefaultSort,
            SlateCommandID.sidebarPinNote,
            SlateCommandID.sidebarUnpinNote,
            SlateCommandID.sidebarUnpinAll:
            try dispatchSidebarOrganizationAction(intent, rejected: rejected)
            return .completed(actionID: intent.actionID)

        default:
            throw sidebarActionFailure(Self.sidebarSelectionChangedReason)
        }
    }

    private func startSidebarActionValidation(
        _ intent: SidebarActionInvocationIntent,
        definition: SidebarActionDefinition
    ) -> SidebarActionDispatchResult {
        beginSidebarActionValidation(
            intent,
            definition: definition
        ) { state in
            _ = try state.dispatchSidebarAction(
                intent,
                filesystemAlreadyValidated: true)
        }
        return .validationPending(actionID: intent.actionID)
    }

    /// Run the complete frozen filesystem walk without occupying the main
    /// actor. Landing first rechecks exact session ownership and the live
    /// catalog reason, then releases the validation gate and enters the action
    /// continuation in the same MainActor turn—there is no admission gap.
    @discardableResult
    private func beginSidebarActionValidation(
        _ intent: SidebarActionInvocationIntent,
        definition: SidebarActionDefinition,
        onValidated: @escaping @MainActor (AppState) async throws -> Void
    ) -> Task<Void, Never> {
        precondition(
            !isValidatingSidebarAction,
            "a second sidebar validator must be rejected by live admission")
        sidebarActionValidationToken &+= 1
        let token = sidebarActionValidationToken
        isValidatingSidebarAction = true
        sidebarActionBackgroundFailure = nil
        sidebarActionValidationRanOnMainThreadForTesting = nil

        let items = intent.snapshot.items
        let vaultURL = currentVaultURL
        let sessionIdentity = intent.snapshot.sessionIdentity
        let itemProbe = sidebarActionValidationItemProbeForTesting
        let task = Task { @MainActor [weak self] in
            guard let vaultURL else { return }
            let detachedValidation = Task.detached(priority: .userInitiated) {
                () -> (reason: String?, ranOnMainThread: Bool, cancelled: Bool) in
                let ranOnMainThread = pthread_main_np() != 0
                do {
                    try Self.validateSidebarSelectionItems(
                        items,
                        vaultURL: vaultURL,
                        checkCancellation: true,
                        itemProbe: itemProbe)
                    return (
                        reason: nil,
                        ranOnMainThread: ranOnMainThread,
                        cancelled: false)
                } catch is CancellationError {
                    return (
                        reason: nil,
                        ranOnMainThread: ranOnMainThread,
                        cancelled: true)
                } catch {
                    return (
                        reason: error.localizedDescription,
                        ranOnMainThread: ranOnMainThread,
                        cancelled: false)
                }
            }
            let validation = await withTaskCancellationHandler {
                await detachedValidation.value
            } onCancel: {
                detachedValidation.cancel()
            }

            guard let self, self.sidebarActionValidationToken == token else { return }
            self.sidebarActionValidationRanOnMainThreadForTesting =
                validation.ranOnMainThread
            if validation.cancelled {
                self.finishSidebarActionValidation(token: token)
                return
            }
            guard let session = self.currentSession,
                ObjectIdentifier(session) == sessionIdentity
            else {
                self.finishSidebarActionValidation(token: token)
                return
            }
            if let reason = validation.reason {
                self.finishSidebarActionValidation(token: token)
                self.surfaceSidebarActionBackgroundFailure(reason)
                return
            }

            do {
                _ = try self.validateSidebarActionIntent(
                    intent,
                    validateFilesystem: false,
                    ignoringOwnedSidebarValidation: true)
                self.finishSidebarActionValidation(token: token)
                try await onValidated(self)
            } catch {
                self.finishSidebarActionValidation(token: token)
                self.surfaceSidebarActionBackgroundFailure(
                    error.sidebarActionAnnouncement)
            }
        }
        pendingSidebarActionValidationTaskForTesting = task

        let actionName = definition.label.replacingOccurrences(of: "…", with: "")
        announcer.post(
            "Checking \(items.count.formatted()) selected items before \(actionName).",
            priority: .medium)
        return task
    }

    private func finishSidebarActionValidation(token: Int) {
        guard sidebarActionValidationToken == token else { return }
        isValidatingSidebarAction = false
        pendingSidebarActionValidationTaskForTesting = nil
    }

    private func cancelSidebarActionValidation() {
        sidebarActionValidationToken &+= 1
        pendingSidebarActionValidationTaskForTesting?.cancel()
        pendingSidebarActionValidationTaskForTesting = nil
        isValidatingSidebarAction = false
        sidebarActionBackgroundFailure = nil
        sidebarActionValidationRanOnMainThreadForTesting = nil
    }

    private func surfaceSidebarActionBackgroundFailure(_ reason: String) {
        sidebarActionBackgroundFailure = reason
        announcer.post(reason, priority: .medium)
    }

    func dismissSidebarActionBackgroundFailure() {
        sidebarActionBackgroundFailure = nil
    }

    private enum SidebarWikilinkFormatOutcome: Sendable {
        case formatted(String)
        case failed
    }

    private func startSidebarWikilinkCopy(
        _ intent: SidebarActionInvocationIntent,
        session: VaultSession
    ) -> SidebarActionDispatchResult {
        precondition(
            !isCopyingSidebarWikilink,
            "a second wikilink copy must be rejected by live admission")
        sidebarWikilinkCopyToken &+= 1
        let token = sidebarWikilinkCopyToken
        let sessionIdentity = intent.snapshot.sessionIdentity
        let path = intent.snapshot.items[0].path
        let formatter = sidebarActionDispatchOverrides.wikilink
        isCopyingSidebarWikilink = true

        let task = Task { @MainActor [weak self] in
            let outcome = await Task.detached(priority: .userInitiated) {
                do {
                    let value: String?
                    if let formatter {
                        value = try formatter(session, path)
                    } else {
                        value = try session.wikilinkForPath(path: path)
                    }
                    guard let value else {
                        return SidebarWikilinkFormatOutcome.failed
                    }
                    return SidebarWikilinkFormatOutcome.formatted(value)
                } catch {
                    return SidebarWikilinkFormatOutcome.failed
                }
            }.value

            guard let self, self.sidebarWikilinkCopyToken == token else { return }
            guard let currentSession = self.currentSession,
                ObjectIdentifier(currentSession) == sessionIdentity
            else {
                self.finishSidebarWikilinkCopy(token: token)
                return
            }

            self.finishSidebarWikilinkCopy(token: token)
            do {
                _ = try self.validateSidebarActionIntent(intent)
                guard case .formatted(let value) = outcome else {
                    self.surfaceSidebarActionBackgroundFailure(
                        Self.sidebarWikilinkFailureReason)
                    return
                }
                _ = try self.completeSidebarCopy(
                    value,
                    actionID: intent.actionID)
            } catch {
                self.surfaceSidebarActionBackgroundFailure(
                    error.sidebarActionAnnouncement)
            }
        }
        pendingSidebarWikilinkCopyTaskForTesting = task
        return .copyPending(actionID: intent.actionID)
    }

    private func finishSidebarWikilinkCopy(token: Int) {
        guard sidebarWikilinkCopyToken == token else { return }
        isCopyingSidebarWikilink = false
        pendingSidebarWikilinkCopyTaskForTesting = nil
    }

    private func invalidateSidebarWikilinkCopy() {
        sidebarWikilinkCopyToken &+= 1
        pendingSidebarWikilinkCopyTaskForTesting?.cancel()
        pendingSidebarWikilinkCopyTaskForTesting = nil
        isCopyingSidebarWikilink = false
    }

    private func completeSidebarCopy(
        _ value: String,
        actionID: String
    ) throws -> SidebarActionDispatchResult {
        sidebarPasteboard.clearContents()
        guard sidebarPasteboard.setString(value) else {
            throw sidebarActionFailure(Self.sidebarCopyFailureReason)
        }
        announcer.post("Copied.", priority: .medium)
        return .completed(actionID: actionID)
    }

    private func canonicalSidebarCreationParent(
        for snapshot: SidebarSelectionSnapshot,
        rejection: String
    ) throws -> String {
        guard snapshot.items.count <= 1 else {
            throw sidebarActionFailure(rejection)
        }
        guard let item = snapshot.items.first else {
            guard snapshot.focusedPath == nil, snapshot.creationParent.isEmpty else {
                throw sidebarActionFailure(rejection)
            }
            return ""
        }
        guard snapshot.focusedPath == item.path else {
            throw sidebarActionFailure(rejection)
        }
        let expected = item.isDirectory
            ? item.path
            : (TreeMutation.parentPath(of: item.path) ?? "")
        guard snapshot.creationParent == expected else {
            throw sidebarActionFailure(rejection)
        }
        return expected
    }

    private func sidebarActionFailure(_ reason: String) -> CommandError {
        .ActionFailed(message: reason)
    }

    var sidebarActionDisabledReasons: [String: String] {
        var reasons = Dictionary(
            uniqueKeysWithValues: SidebarActionCatalog.actions.compactMap { action in
            sidebarActionAvailabilityReasonProvider(action.id).map { (action.id, $0) }
            })
        if reasons[SlateCommandID.newFromTemplate] == nil,
            let reason = templateAvailabilityDisabledReason
        {
            reasons[SlateCommandID.newFromTemplate] = reason
        }
        if templateCreationDestinationOwner != nil {
            reasons[SlateCommandID.newFromTemplate] = Self.templateFlowBusyReason
        }
        if let reason = templateShortcutModalDisabledReason {
            reasons[SlateCommandID.newFromTemplate] = reason
        }
        if isCopyingSidebarWikilink {
            reasons[SlateCommandID.sidebarCopyWikilink] =
                Self.sidebarWikilinkCopyPendingReason
        }
        // FL-06 organization availability follows the published selection's
        // single target (nil covers both empty and multi selections; multi is
        // already capability-disabled upstream of these reasons).
        let organizationTarget = sidebarSelectionSnapshot.flatMap { snapshot in
            snapshot.items.count == 1 ? snapshot.items.first : nil
        }
        reasons.merge(
            sidebarOrganizationActionReasons(target: organizationTarget)
        ) { existing, _ in existing }
        return reasons
    }

    /// One synchronous, side-effect-free projection feeds every Sidebar
    /// action surface. The catalog owns capability and ordering; AppState adds
    /// only current state that the pure catalog cannot own.
    func sidebarActionProjection(
        surface: SidebarActionSurface
    ) -> [SidebarActionEvaluation] {
        let capturedSnapshot = sidebarSelectionSnapshot
        var actionDisabledReasons = sidebarActionDisabledReasons
        if let propertyEditNavigationDisabledReason {
            actionDisabledReasons[SlateCommandID.sidebarOpen] =
                propertyEditNavigationDisabledReason
        }
        if isValidatingSidebarAction {
            actionDisabledReasons[SlateCommandID.sidebarOpen] =
                Self.sidebarActionValidationPendingReason
        }
        return SidebarActionCatalog.project(
            surface: surface,
            snapshot: capturedSnapshot,
            structuralMutationDisabledReason:
                sidebarActionStructuralDisabledReasonOverride
                ?? structuralMutationDisabledReason,
            actionDisabledReasons: actionDisabledReasons)
    }

    /// Real key-equivalent routing for catalog-owned Sidebar shortcuts. The
    /// evaluation is captured once: enabled work dispatches that exact frozen
    /// intent, while disabled work announces the shared reason exactly once
    /// without presenting a sheet or starting a mutation.
    @discardableResult
    func invokeSidebarKeyboardAction(_ id: String) -> Bool {
        clearTemplateShortcutDialogNotice()
        guard let evaluation = sidebarActionProjection(surface: .keyboard)
            .first(where: { $0.id == id })
        else { return false }
        guard let intent = evaluation.intent else {
            if let reason = evaluation.disabledReason {
                lastMutationAnnouncement = reason
                announcer.post(reason, priority: .medium)
            }
            return true
        }
        do {
            _ = try dispatchSidebarAction(intent)
        } catch {
            let message = error.sidebarActionAnnouncement
            lastMutationAnnouncement = message
            announcer.post(message, priority: .medium)
        }
        return true
    }

    /// Consume Shift-Command-N while a non-template dialog owns the app.
    /// Starting another sheet would hide the template flow beneath the active
    /// dialog, so give one visible and spoken explanation without dispatching.
    @discardableResult
    func rejectTemplateShortcutForActiveDialog() -> Bool {
        rejectTemplateShortcut(reason: Self.templateDialogBusyReason)
    }

    /// Other Slate windows are not modal dialogs, so their recovery text must
    /// direct the user back to the primary vault window rather than asking
    /// them to cancel a dialog that does not exist.
    @discardableResult
    func rejectTemplateShortcutForOtherWindow() -> Bool {
        rejectTemplateShortcut(reason: Self.templateOtherWindowReason)
    }

    private func rejectTemplateShortcut(reason: String) -> Bool {
        templateShortcutDialogNotice = reason
        announceTemplate(reason)
        return true
    }

    func clearTemplateShortcutDialogNotice() {
        templateShortcutDialogNotice = nil
    }

    /// The RootView monitor supplies the one window allowed to start a new
    /// template flow. Keeping this admission rule in AppState means every
    /// catalog surface, including a stale File-menu intent, revalidates it.
    func setTemplateShortcutHostWindow(_ window: NSWindow?) {
        guard templateShortcutHostWindow !== window else { return }
        templateShortcutHostWindow = window
        if window != nil {
            templateShortcutHostWindowWasRegistered = true
        }
    }

    /// The Command Palette registers its exact sheet window as the only
    /// non-host window allowed to originate a template action.
    func setTemplateShortcutActionLauncherWindow(_ window: NSWindow?) {
        guard templateShortcutActionLauncherWindow !== window else { return }
        templateShortcutActionLauncherWindow = window
        templateShortcutWindowAdmissionDidChange()
    }

    func templateShortcutWindowOwnsActionLauncher(_ window: NSWindow?) -> Bool {
        guard let window, let actionLauncher = templateShortcutActionLauncherWindow
        else { return false }
        return window === actionLauncher
    }

    /// Window focus is AppKit state rather than an `@Published` model value.
    /// Bump a private observation token when AppKit changes the key window so
    /// SwiftUI refreshes menu enablement before the next pointer invocation.
    func templateShortcutWindowAdmissionDidChange() {
        templateShortcutWindowAdmissionVersion &+= 1
    }

    nonisolated private static func validateSidebarSelectionItems(
        _ items: [SidebarSelectionItem],
        vaultURL: URL,
        checkCancellation: Bool = false,
        itemProbe: (@Sendable (Int) -> Void)? = nil
    ) throws {
        for (index, item) in items.enumerated() {
            if checkCancellation {
                try Task.checkCancellation()
            }
            itemProbe?(index)
            if checkCancellation {
                try Task.checkCancellation()
            }
            try validateSidebarSelectionItem(
                item,
                vaultURL: vaultURL,
                checkCancellation: checkCancellation)
        }
    }

    nonisolated private static func validateSidebarSelectionItem(
        _ item: SidebarSelectionItem,
        vaultURL: URL,
        checkCancellation: Bool = false
    ) throws {
        guard !item.path.hasPrefix("/") else {
            throw SidebarActionValidationError(reason: Self.sidebarSelectionChangedReason)
        }
        var normalizedComponents: [Substring] = []
        for component in item.path.split(
            separator: "/",
            omittingEmptySubsequences: true
        ) {
            if checkCancellation {
                try Task.checkCancellation()
            }
            if component == "." { continue }
            guard component != ".." else {
                throw SidebarActionValidationError(
                    reason: Self.sidebarSelectionChangedReason)
            }
            normalizedComponents.append(component)
        }
        let normalized = normalizedComponents.joined(separator: "/")
        guard !normalized.isEmpty, normalized == item.path else {
            throw SidebarActionValidationError(reason: Self.sidebarSelectionChangedReason)
        }

        let components = normalized.split(separator: "/", omittingEmptySubsequences: false)
        var candidate = vaultURL
        for (index, component) in components.enumerated() {
            if checkCancellation {
                try Task.checkCancellation()
            }
            candidate.appendPathComponent(String(component), isDirectory: false)
            guard let attributes = try? FileManager.default.attributesOfItem(
                atPath: candidate.path),
                let type = attributes[.type] as? FileAttributeType,
                type != .typeSymbolicLink
            else {
                throw SidebarActionValidationError(reason: Self.sidebarSelectionChangedReason)
            }
            let isLast = index == components.index(before: components.endIndex)
            if !isLast, type != .typeDirectory {
                throw SidebarActionValidationError(reason: Self.sidebarSelectionChangedReason)
            }
            if isLast {
                let typeMatches = item.isDirectory
                    ? type == .typeDirectory
                    : type == .typeRegular
                guard typeMatches else {
                    throw SidebarActionValidationError(
                        reason: Self.sidebarSelectionChangedReason)
                }
            }
        }
    }

    /// The tree's currently-selected node (file OR folder), mirrored from
    /// `FileTreeSidebar` so the file-management COMMANDS (which run from the
    /// palette / menu with no row context) know what to act on. A file
    /// selection also lives in `selectedFilePath`; folders have no other home,
    /// so this is the single source the commands read. Nil = nothing selected
    /// (commands that need a target no-op or fall back to the vault root).
    @Published var treeSelectedNode: TreeSelection?

    /// A tree selection the file-management commands act on (U2-5).
    struct TreeSelection: Equatable {
        let path: String
        let isDirectory: Bool
    }

    /// The folder a new note/folder should be created in, given the current
    /// tree selection: the selected folder itself, a selected file's parent
    /// folder, or the vault root ("") when nothing is selected. Command-facing.
    var creationParentPath: String {
        guard let node = treeSelectedNode else { return "" }
        if node.isDirectory { return node.path }
        return TreeMutation.parentPath(of: node.path) ?? ""
    }

    /// The workspace shell (Milestone U1): split tree → tab groups → tabs.
    /// AppState's single-note fields hold the ACTIVE tab's document; parked
    /// tabs live in `workspace.documents` (U1-2 snapshot/restore — see the
    /// architecture amendment in u1_spec.md).
    let workspace = WorkspaceState()

    /// A tab-close request blocked on that tab's unsaved changes (U1-2).
    /// Drives the Save / Discard / Cancel alert in `MainSplitView`; the
    /// resolve trio below routes the outcome.
    @Published var pendingTabClose: TabID?

    /// Set when the pending-close alert chose "Save": the close completes
    /// when the in-flight save lands cleanly, and aborts on conflict/error
    /// (the tab must stay open while the user resolves).
    var pendingTabCloseAfterSave: TabID?

    /// Vault-close and vault-switch recovery supersede a narrower tab-close
    /// prompt. Keep exactly one alert owner so cancelling the newer request
    /// cannot resurrect an obsolete tab-close dialog.
    private func supersedePendingTabCloseForVaultTransition() {
        pendingTabClose = nil
        pendingTabCloseAfterSave = nil
    }

    /// Open canvas documents keyed by vault-relative path (Milestone T,
    /// #369) — one per path (t2), shared by every pane/tab showing that
    /// canvas. Not @Published: views observe each document directly.
    var canvasDocuments: [String: CanvasDocument] = [:]
    /// Nil-default deterministic observation seam for the New Canvas native
    /// boundary. Production never installs one; tests record call-site threads.
    var canvasNewFileNativeExecutionObserverForTesting:
        CanvasNewFileNativeExecutionObserver?
    /// Nil in production. Focused safety tests use this to prove a rejected
    /// prompt/keyboard action stopped before the native `canvas_apply` call.
    var canvasApplyObserverForTesting: ((CanvasAction) -> Void)?
    /// Injectable background preparation seam. Production opens and decodes
    /// the complete immutable snapshot before activation; tests can force a
    /// deterministic prepared failure without reaching native state.
    var canvasNewFilePreloadRunner: CanvasNewFilePreloadRunner = {
        session, path, observer in
        CanvasPreparedLoader.prepare(
            session: session,
            path: path,
            observer: observer)
    }

    /// Open base documents keyed by vault-relative path (Milestone N,
    /// #702) or saved-query source — one per source, shared by every
    /// pane/tab showing that base.
    /// Not @Published: views observe each document directly.
    var baseDocuments: [String: BaseDocument] = [:]
    /// Nil-default native-thread probe shared by Base retarget cleanup and
    /// preparation. Later Base writer/read refreshes use the same event stream.
    var baseRetargetNativeExecutionObserverForTesting:
        BaseRetargetNativeExecutionObserver?
    var baseRetargetPreloadRunner: BaseRetargetPreloadRunner = {
        session, request, observer in
        BasePreparedLoader.prepare(
            session: session,
            request: request,
            observer: observer)
    }
    let nativeDocumentPreparationLimiter = NativeDocumentPreparationLimiter()
    /// Cumulative scheduler tail, retained for lifecycle and deterministic
    /// tests. Each new call awaits the prior tail plus its own concurrently
    /// admitted work, while generation/session guards dispose stale prepared
    /// handles exactly once.
    var nativeDocumentRetargetTask: Task<Void, Never>?

    /// Latest-wins query-list refresh. Native listing is detached; only this
    /// generation may publish into the current vault's Queries panel.
    var baseQueriesRefreshGeneration: UInt64 = 0
    var baseQueriesRefreshTask: Task<Void, Never>?

    /// Serialized Builder updates. A later edit waits for any admitted native
    /// write, then supersedes its UI landing in the same vault.
    var savedQueryUpdateGeneration: UInt64 = 0
    var savedQueryUpdateTask: Task<Void, Never>?

    /// Latest all-consumer post-write refresh, retained for ordering-sensitive
    /// writers and deterministic lifecycle tests.
    var visibleBasesRefreshGeneration: UInt64 = 0
    var visibleBasesRefreshTask: Task<[String], Never>?

    /// Right-pane Queries leaf snapshot (#709): saved queries, `.base`
    /// files, dashboards, and app-level saved-query pins.
    @Published var baseQueries = BaseQueriesState()
    var savedQueryCommandIDs: Set<String> = []

    /// Dashboard tab documents (#710), keyed by dashboard id.
    var dashboardDocuments: [String: DashboardDocument] = [:]

    /// Right-pane docked Bases surface (#710): target plus the currently
    /// followed active note context.
    @Published var basesDock = BasesDockState()
    var basesDockDocument: BaseDocument?
    var basesDockDashboardDocument: DashboardDocument?
    var basesDockRefreshTask: Task<Void, Never>?

    /// Open embedded Bases keyed by source + host note (#706). Reusing the
    /// handle keeps duplicate embeds on one native cache while each rendered
    /// embed owns independent quick-filter/sort/view UI state.
    var baseEmbedHandles: [BaseEmbedCacheKey: BaseEmbedHandle] = [:]

    /// Per-tab Bases renderer override (#703). This is transient UI
    /// preference, deliberately outside `.base` persistence.
    @Published var baseRendererOverrides: [TabID: BaseRendererMode] = [:]

    /// #704: bumped to move keyboard focus into the active Bases quick
    /// filter field. The filter text itself lives on `BaseDocument` and is
    /// never persisted to the `.base` file.
    @Published var baseQuickFilterFocusToken = 0

    /// Last Bases action announcement, exposed for XCTest because the global
    /// accessibility announcer is a no-op without a running NSApp.
    @Published var lastBaseActionAnnouncement: String?

    /// Deduplicated membership announcements produced by the most recent
    /// successful in-app write refresh. This is also the deterministic XCTest
    /// surface for the no-spam gate; ordinary Bases action announcements stay
    /// in `lastBaseActionAnnouncement`.
    @Published var lastBaseRefreshAnnouncements: [String] = []

    /// N3-07 race-test seam — always nil in production. Tests park a completed
    /// write immediately before the session/active-note publish guards, switch
    /// notes or vaults, then release it to prove global Bases refresh ownership.
    var basesPostWritePublishGate: (() async -> Void)?

    /// Currently selected Bases row/column for registry commands whose
    /// invocation originates outside the grid's AppKit row-action callback.
    @Published var activeBaseSelectionPath: String?
    @Published var activeBaseSelectedRow: BasesRow?
    @Published var activeBaseSelectedColumn: BasesColumn?
    @Published var baseEditPropertyRequestToken = 0

    /// The one canvas announcement funnel (#518, DoD §H). Every canvas
    /// surface phrases through it; verbosity persists via
    /// `PreferencesStore` (`setCanvasVerbosity`).
    lazy var canvasAnnouncer = CanvasAnnouncer(
        verbosity: preferencesStore.loadCanvasPrefs().verbosity)

    /// The one graph announcement funnel (Milestone P; mirrors
    /// `canvasAnnouncer`). Connections leaf, graph table, and diagram
    /// surfaces phrase through it — no graph code posts directly
    /// (enforced by `GraphAnnouncerTests`). Verbosity persistence
    /// moves into `.slate/graph.json` with P2-4; `.standard` until then.
    lazy var graphAnnouncer = GraphAnnouncer()

    // MARK: Connections leaf (Milestone P, P1-1 #554)

    /// Local-graph depth for the Connections leaf (1…3). Persisted
    /// per-vault; migrates into `.slate/graph.json` with P2-4.
    @Published var connectionsDepth: Int = 1
    /// The note the Connections leaf is rooted on. `nil` = follow
    /// `selectedFilePath`; non-nil after a "Show connections" re-root
    /// (breadcrumb back-stack in `connectionsBackStack`).
    @Published var connectionsRootPath: String?
    /// The neighborhood payload (structure + metrics + pre-rendered
    /// `audioSummary`) for the current root+depth.
    @Published var connectionsNeighborhood: GraphNeighborhood?
    /// Depth-1 snippet source (spec §P1-1: rows show snippets from the
    /// existing `Backlink`/`OutgoingLink` data at depth 1).
    @Published var connectionsBundle: NoteLoadBundle?
    /// The path the currently-published neighborhood/bundle describes.
    /// The panel renders rows only when this matches the effective
    /// path, so a note switch never shows B's header over A's rows
    /// (review round 1 finding 9).
    @Published var connectionsLoadedPath: String?
    @Published var connectionsLoading: Bool = false
    @Published var connectionsError: String?
    /// Last graph generation the leaf refreshed against — the P0-3
    /// refresh discriminator (only reload when it moves).
    var connectionsSeenGraphGeneration: UInt64 = 0
    /// Newest-wins guard (the O-5 seq pattern).
    var connectionsLoadSeq: UInt64 = 0
    /// Re-root breadcrumb: `⌘[` pops back one step. Each entry records
    /// BOTH the prior root mode (`root`: a path, or `nil` = "was
    /// following the selection") AND the note that was in view
    /// (`effective`), so back restores the exact prior view —
    /// including the originally-selected note when returning to
    /// follow-mode (review round 3 finding 1).
    var connectionsBackStack: [(root: String?, effective: String)] = []
    /// Race-test seam (post-compute, pre-guard); nil in production.
    var connectionsPublishGate: (() async -> Void)?

    /// The note the Connections leaf currently describes: an explicit
    /// re-root wins, else the selected note.
    var connectionsEffectivePath: String? {
        connectionsRootPath ?? selectedFilePath
    }

    // MARK: Graph tab, Table mode (Milestone P, P1-2 #555)

    /// The whole-graph snapshot backing the Graph tab's Table mode,
    /// fetched once per generation and sorted/filtered client-side.
    @Published var graphTableSnapshot: GraphSnapshot?
    /// Backend filter (a snapshot re-fetch on change): Attachments /
    /// Unresolved (= ghosts) / Orphans-only toggles — exactly
    /// `GraphFilter` semantics (spec §P1-2). Defaults: attachments off,
    /// ghosts on.
    @Published var graphTableFilter = GraphFilter(
        includeAttachments: false, includeGhosts: true, orphansOnly: false)
    /// Client-side label substring filter (case/diacritic-insensitive),
    /// applied to the fetched rows without a re-fetch.
    @Published var graphTableTextFilter: String = ""
    /// Client-side KIND filter (P1-3 #556): non-nil shows only rows of
    /// that kind — the "unresolved links" preset sets `.ghost` (which
    /// `GraphFilter` can't express, having no "notes off" flag). Set only
    /// by presets; cleared by any manual filter-bar toggle so it never
    /// becomes hidden state the user can't see or undo.
    @Published var graphTableKindFilter: GraphNodeKind?
    /// A preset (orphans / unresolved / most-linked) awaiting its
    /// post-load announcement — set by `openGraphPreset`, consumed once
    /// the fresh snapshot publishes so the count/hub is spoken from real
    /// data, not the stale pre-fetch snapshot (P1-3 #556).
    var graphTablePendingPreset: GraphPreset?
    @Published var graphTableLoading: Bool = false
    @Published var graphTableError: String?
    var graphTableLoadSeq: UInt64 = 0
    var graphTableSeenGraphGeneration: UInt64 = 0
    /// Race-test seam (post-compute, pre-guard); nil in production.
    var graphTablePublishGate: (() async -> Void)?
    /// True when the active tab is the graph tab (gates the
    /// generation-driven table refresh's announcements).
    var graphTabActive: Bool {
        workspace.activeTab?.item == .graph
    }

    /// True when a `.graph` tab is the active tab of ANY split group —
    /// i.e. currently rendered somewhere, not merely open in a
    /// background position. Gates the generation-driven refresh so it
    /// stops once every graph tab is closed (a stale `graphTableSnapshot`
    /// is never cleared on close, so keying on it alone leaked a
    /// forever-refresh with no on-screen consumer — review round 1
    /// finding 10) while still keeping a graph visible in a non-focused
    /// pane current.
    var anyGraphTabVisible: Bool {
        workspace.model.groupsInOrder.contains { $0.activeTab?.item == .graph }
    }

    // MARK: Graph tab, Diagram mode (Milestone P, P2-3 #559)

    /// The live visual-diagram model — nil until the Graph tab enters
    /// Diagram mode, torn down on graph-tab close / vault change. Owns the
    /// running `LayoutSession` and the id→metadata join for accessible
    /// labels and actions.
    @Published var graphDiagramModel: GraphDiagramModel?
    /// Monotonic build sequence: an in-flight diagram build is stale once
    /// this advances (tab close, vault change, rebuild).
    var graphDiagramBuildSeq: UInt64 = 0
    /// Serializes generation-refreshes: each waits for the prior to adopt
    /// before probing, so two file-change-driven refreshes can't race
    /// (the second would otherwise get `nil` from an already-advanced
    /// layout while the first is rejected, stranding the model on the old
    /// generation). Adoption additionally requires a strictly newer
    /// generation (monotonic).
    var graphDiagramRefreshTask: Task<Void, Never>?
    @Published var graphDiagramLoading = false
    @Published var graphDiagramError: String?

    /// Persisted graph-tab config (P2-4 #560): the LIVE holder for the
    /// inspector's Groups / Display / Forces; filters, mode, and depth
    /// are synced from their existing live state at the load/save
    /// boundaries. Written to `.slate/graph.json` (debounced) via
    /// `graphConfigSaveTask`.
    @Published var graphConfig = GraphConfig.default
    /// Pending debounced saves keyed BY VAULT — genuine per-vault
    /// bookkeeping (P2-4 review finding 3). A same-vault edit cancels only
    /// that vault's pending task (coalescing); a save for a DIFFERENT vault
    /// keeps its own entry and runs to completion, so a fast vault switch
    /// can't drop vault A's final write and no stale same-vault task lingers.
    var graphConfigSaveTasks: [URL: Task<Void, Never>] = [:]
    /// A per-vault monotonic token so a completing save clears its dict
    /// entry ONLY if a newer same-vault save hasn't already replaced it
    /// (avoids a mid-write task dropping its successor's entry).
    var graphConfigSaveGen: [URL: Int] = [:]
    /// The vault `graphConfig` was last loaded for — so the config loads
    /// ONCE per vault (a per-activate reload would revert a debounced,
    /// not-yet-written filter/force edit when the user tab-switches).
    var graphConfigVaultURL: URL?
    /// False when this vault's `graph.json` is unreadable / unparseable /
    /// a NEWER version — the file is then treated as read-only so a save
    /// can never clobber whatever a newer Slate (or a human) put there
    /// (P2-4 review finding 2). Reset true on each successful load.
    var graphConfigWritable = true
    /// Set when a forces edit re-heats the layout; the renderer announces a
    /// single "settled" state once the layout converges, then clears it
    /// (P2-4 review finding 8 — the settled-state announcement).
    var graphForcesSettlePending = false
    /// The graph tab's SHARED selected-node key (Milestone P, P2-5 #561 —
    /// the `GraphViewState` selection channel). The ONE cross-projection-
    /// stable identity (`GraphNodeKey`: `"p:<path>"` / `"g:<label>"`, never
    /// a generation-volatile `UInt64`). The Table binds its row selection to
    /// this; the Diagram mirrors it to/from `GraphDiagramModel.selection`;
    /// Connections re-rooting writes it — so a selection in any projection
    /// reflects in the others within one runloop tick, and a Table↔Diagram
    /// mode switch lands on the same node. Filters and groups (the other
    /// GraphViewState fields) were already unified in P2-4 (`graphTableFilter`
    /// + `graphConfig.groups`); this closes the selection axis.
    @Published var graphSelectedNodeKey: String?

    /// The ⌃⌘I "Where am I?" readback (t0 §1.4): non-nil presents the
    /// focusable transient panel in the canvas container; Esc/Close
    /// dismisses (panel-local, not a t0 M5 ladder rung).
    @Published var canvasWhereAmIReadback: String?

    /// Per-canvas mode controllers (t0 §2, #364) keyed by path —
    /// created lazily; #521/#523 enter modes through them.
    var canvasModeControllers: [String: CanvasModeController] = [:]

    /// The pending canvas input prompt (#368): non-nil presents the
    /// matching sheet in the canvas container (M6 visible controls).
    @Published var canvasPrompt: CanvasPrompt?
    /// User-authored prompt text lives with the prompt owner instead of the
    /// ephemeral sheet. A quarantine or other failed commit therefore cannot
    /// destroy the only copy when SwiftUI re-renders the sheet.
    @Published var canvasPromptDraft: String = ""

    /// The pending card-picker request (#522/#523): non-nil presents
    /// the reusable proximity-sorted picker in the container.
    @Published var canvasCardPicker: CanvasCardPickerRequest?

    /// #368: the open text-card edit session. The draft is owned beside the
    /// request instead of by the ephemeral sheet so a quarantine-triggered
    /// remount (and even a later missing-file state) cannot discard it.
    @Published var canvasCardEditor: CanvasCardEditorRequest? {
        didSet {
            guard oldValue?.id != canvasCardEditor?.id else { return }
            canvasCardEditorDraft = canvasCardEditor?.initialText ?? ""
        }
    }
    @Published var canvasCardEditorDraft: String = ""

    /// #373: bumped to move keyboard focus into the canvas filter
    /// field (⌘F while a canvas has focus).
    @Published var canvasFilterFocusToken = 0

    /// Transient move/resize geometry (#521, the t4 pipeline
    /// exception): held UI-side while a spatial mode is active,
    /// committed as ONE canvas_apply on Return, dropped on Esc.
    var canvasTransient: CanvasTransientState?

    /// Re-entrancy latch: `activateTab` runs the tab funnel itself and then
    /// mirrors `selectedFilePath` for the sidebar highlight; the
    /// `$selectedFilePath` sink must not run the selection funnel again on
    /// that assignment. Synchronous sink ⇒ a plain flag suffices.
    var isActivatingTab = false

    /// One shared app-to-tree edge for explicit navigation that may otherwise
    /// produce no `selectedFilePath` change (same-file intent), or whose path
    /// change is mirrored neutrally by FileTreeSidebar. Internal restoration,
    /// mutation retargeting, and vault teardown never call this seam.
    func recordExplicitSidebarNavigationIntent() {
        sidebarSelectionIntentRevision &+= 1
    }

    /// The single tab-switch funnel (U1-2): snapshot the outgoing tab,
    /// select `id`, restore its parked buffer (or disk-load on first
    /// activation), re-fire the collection loads, and mirror the sidebar
    /// selection. Identity-keyed, so two tabs holding the SAME path switch
    /// correctly (a path-keyed funnel cannot distinguish them).
    func activateTab(
        _ id: TabID,
        advancesSidebarSelectionRevision: Bool = false
    ) {
        guard let tab = workspace.model.tab(id) else { return }
        if id != workspace.model.activeGroup.activeTabID,
            let reason = propertyEditNavigationDisabledReason
        {
            postMutationAnnouncement(reason)
            return
        }
        if advancesSidebarSelectionRevision {
            recordExplicitSidebarNavigationIntent()
        }
        clearBaseQuickFilterIfLeavingActiveTab(for: id)
        if case .base(let path) = tab.item {
            activateBaseTab(id, path: path)
            return
        }
        if case .savedQuery(let savedQueryID, let name) = tab.item {
            activateSavedQueryTab(id, savedQueryID: savedQueryID, name: name)
            return
        }
        if case .dashboard(let dashboardID, let name) = tab.item {
            activateDashboardTab(id, dashboardID: dashboardID, name: name)
            return
        }
        if case .canvas(let path) = tab.item {
            activateCanvasTab(id, path: path)
            return
        }
        if case .graph = tab.item {
            activateGraphTab(id)
            return
        }
        guard case .markdown(let path) = tab.item else { return }
        if id == workspace.model.activeGroup.activeTabID,
            BaseExactIdentity.matches(loadedFilePath, path)
        {
            return
        }
        // U4-4 (#473): any tab activation lands keyboard focus in the editor
        // content, so the focus region is now `.editor` — a subsequent
        // ⌘⌥arrow anchors on this group, not a stale terminal region left
        // over from before the switch. Clears `lastFocusedGroup`; the terminal
        // return-path already restored+cleared it before reaching here.
        workspace.markEditorRegionActive()
        // Codoki #492 (High): a save-then-close scope must not outlive its
        // tab context. If the user switches away while that save is in
        // flight, the success branch correctly skips the close (active-tab
        // guard) — but leaving the marker set would close the tab on a
        // LATER unrelated save. Clear it on any switch away.
        if let pending = pendingTabCloseAfterSave, pending != id {
            pendingTabCloseAfterSave = nil
        }
        isActivatingTab = true
        defer { isActivatingTab = false }
        parkPropertiesSourceDraftForTransition()
        workspace.snapshotActiveTab(
            text: currentNoteText, baseline: savedBaselineText,
            contentHash: currentNoteContentHash,
            hasUnsavedChanges: hasUnsavedChanges,
            saveError: saveError, saveConflict: currentSaveConflict,
            loadedFilePath: loadedFilePath,
            fmSource: currentNoteFMSource,
            bodyByteOffset: bodyByteOffset, bodyLineOffset: bodyLineOffset)
        cancelNoteScopedWork()
        clearActiveNoteFields()
        workspace.select(id)
        clearTransitionSensitiveCollections()
        restoreParkedOrLoadFromDisk(path: path)
        // Sidebar highlight mirrors the active tab. The sink is latched;
        // `removeDuplicates` additionally swallows same-path switches.
        if !BaseExactIdentity.matches(selectedFilePath, path) {
            selectedFilePath = path
        }
        if noteLoadError == nil {
            fireCollectionLoads(path: path)
        }
        scheduleBasesDockFollowActiveRefresh()
    }

    // MARK: - Tab lifecycle (U1-2, #454)

    /// ⌘T — Duplicate Tab (#863 returned the chord to the tab family;
    /// Quick Open moved to ⌘O, Obsidian's actual default). Duplicates
    /// the active tab's item — Slate's "new tab" verb, since a tab
    /// always hosts an item (u1_spec §U1-2); with no active tab it is
    /// a no-op.
    func newTab() {
        if let reason = propertyEditNavigationDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        guard let item = workspace.activeTab?.item else { return }
        // The graph is a workspace-global singleton: Duplicate Tab must
        // not spawn a second graph (round 2 finding 6). It's already the
        // active tab, so this is a no-op beyond the spoken confirmation.
        if case .graph = item {
            graphAnnouncer.announce(.status("The graph is already open."))
            return
        }
        // Snapshot the outgoing buffer, then open the duplicate. The
        // selection sink does NOT fire (same path selected), so park and
        // restore in place.
        workspace.snapshotActiveTab(
            text: currentNoteText, baseline: savedBaselineText,
            contentHash: currentNoteContentHash,
            hasUnsavedChanges: hasUnsavedChanges,
            saveError: saveError, saveConflict: currentSaveConflict,
            loadedFilePath: loadedFilePath,
            fmSource: currentNoteFMSource,
            bodyByteOffset: bodyByteOffset, bodyLineOffset: bodyLineOffset)
        workspace.openTab(item, allowDuplicate: true)
        announceActiveTab(prefix: "Opened new tab.")
    }

    /// ⌘W and the tab-strip close buttons. Gates on the tab's dirty state —
    /// active tab reads the live fields; parked tabs read their document.
    private func performCloseTabFromExplicitRequest(_ id: TabID) {
        if id == workspace.model.activeGroup.activeTabID {
            recordExplicitSidebarNavigationIntent()
        }
        performCloseTab(id)
    }

    func requestCloseTab(_ id: TabID? = nil) {
        guard let target = id ?? workspace.model.activeGroup.activeTabID else { return }
        guard workspace.model.tab(target) != nil else { return }
        let isActive = target == workspace.model.activeGroup.activeTabID
        // Canvas/base tabs are never dirty in the note-buffer sense:
        // canvas mutations write through, and the first Bases surface is
        // read-only (#702), so the close gate is bypassed by design.
        if case .canvas = workspace.model.tab(target)?.item {
            performCloseTabFromExplicitRequest(target)
            return
        }
        if case .base = workspace.model.tab(target)?.item {
            performCloseTabFromExplicitRequest(target)
            return
        }
        if case .savedQuery = workspace.model.tab(target)?.item {
            performCloseTabFromExplicitRequest(target)
            return
        }
        if case .dashboard = workspace.model.tab(target)?.item {
            performCloseTabFromExplicitRequest(target)
            return
        }
        // The Graph tab has no editable buffer, so it is never dirty —
        // closing it must never present the note save gate.
        if case .graph = workspace.model.tab(target)?.item {
            performCloseTabFromExplicitRequest(target)
            return
        }
        if let tab = workspace.model.tab(target),
            case .markdown(let path) = tab.item,
            hasAuthoredPropertyPublicationRecovery(for: path),
            !hasOtherMarkdownTab(for: path, excluding: target)
        {
            postMutationAnnouncement(
                "Resolve the saved property update awaiting verification in \(filename(of: path)) before closing its final tab. Copy the retained update, reapply it, or use the current version.")
            pendingTabClose = nil
            return
        }
        if let tab = workspace.model.tab(target),
            case .markdown(let path) = tab.item,
            propertyEditBlocksFinalTabClose(path: path, excluding: target)
        {
            postMutationAnnouncement(Self.propertyEditInProgressReason)
            pendingTabClose = nil
            return
        }
        if isActive, isEditingProperty,
            let tab = workspace.model.tab(target),
            case .markdown(let path) = tab.item,
            BaseExactIdentity.matches(path, loadedFilePath)
        {
            postMutationAnnouncement(Self.propertyEditInProgressReason)
            pendingTabClose = nil
            return
        }
        // Once a save owns this exact active note, a second close must not
        // present a destructive Discard action that cannot revoke native I/O.
        // A plain Save followed by close queues the close on that save; an
        // existing Save-and-close continuation is idempotent.
        if isActive, isSaving,
            let tab = workspace.model.tab(target),
            case .markdown(let path) = tab.item,
            BaseExactIdentity.matches(path, loadedFilePath)
        {
            if pendingTabCloseAfterSave == nil {
                recordExplicitSidebarNavigationIntent()
                pendingTabCloseAfterSave = target
            }
            pendingTabClose = nil
            return
        }
        let rawBodyDirty =
            isActive
            ? hasUnsavedChanges
            : (workspace.document(for: target)?.hasUnsavedChanges ?? false)
        let bodyDirty: Bool
        if let tab = workspace.model.tab(target), case .markdown(let path) = tab.item,
            hasOtherMarkdownTab(for: path, excluding: target)
        {
            bodyDirty = false
        } else {
            bodyDirty = rawBodyDirty
        }
        let recoveryDirty: Bool
        if let tab = workspace.model.tab(target), case .markdown(let path) = tab.item {
            // Recovery is path-owned rather than tab-owned. Closing one clean
            // duplicate is safe while another tab retains that exact path; the
            // final owner receives the destructive-resolution prompt.
            recoveryDirty = hasDirtyNoteRecovery(for: path)
                && !hasOtherMarkdownTab(for: path, excluding: target)
        } else {
            recoveryDirty = false
        }
        let dirty = bodyDirty || recoveryDirty
        if dirty {
            if isActive {
                recordExplicitSidebarNavigationIntent()
            }
            pendingTabClose = target
        } else {
            performCloseTabFromExplicitRequest(target)
        }
    }

    /// Alert "Save": activate the tab if parked (snapshot/restore through
    /// the identity funnel), then save through the standard path; the close
    /// completes in `performSave`'s success branch.
    var pendingTabCloseSaveDisabledReason: String? {
        guard let target = pendingTabClose,
            let tab = workspace.model.tab(target),
            case .markdown(let path) = tab.item
        else { return nil }
        return dirtyCloseSaveDisabledReason(for: path)
    }

    var pendingTabCloseDiscardDisabledReason: String? {
        guard pendingTabClose != nil else { return nil }
        return inFlightDraftDiscardDisabledReason
    }

    private func dirtyCloseSaveDisabledReason(for path: String) -> String? {
        noteSaveDisabledReason(for: path)
    }

    func resolveTabCloseSave() {
        guard let target = pendingTabClose else { return }
        if let reason = pendingTabCloseSaveDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        if target != workspace.model.activeGroup.activeTabID {
            activateTab(target, advancesSidebarSelectionRevision: true)
        }
        // Transactional close-after-save: a quarantine race, an already
        // running save, or an unavailable editor must leave the alert and its
        // dirty draft intact. Arm the continuation only after the standard
        // save path has returned a concrete task.
        guard saveCurrentNote() != nil else { return }
        pendingTabCloseAfterSave = target
        pendingTabClose = nil
    }

    /// Alert "Discard": drop the tab's buffer and close it.
    func resolveTabCloseDiscard() {
        guard let target = pendingTabClose else { return }
        if let reason = inFlightDraftDiscardDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        let discardedRecoveryPath: String? = {
            guard let tab = workspace.model.tab(target),
                case .markdown(let path) = tab.item,
                hasDirtyNoteRecovery(for: path),
                !hasOtherMarkdownTab(for: path, excluding: target)
            else { return nil }
            return path
        }()
        pendingTabClose = nil
        if let discardedRecoveryPath {
            if missingNoteRecoveryDraft(for: discardedRecoveryPath) != nil {
                discardMissingNoteRecoveryDraft(
                    path: discardedRecoveryPath,
                    announce: false)
            } else {
                discardRecoverablePropertyDrafts(for: discardedRecoveryPath)
            }
        }
        if target == workspace.model.activeGroup.activeTabID {
            // Neutralize the dirty state so the close path's teardown
            // doesn't trip the navigation gate.
            hasUnsavedChanges = false
        }
        performCloseTab(target)
    }

    func resolveTabCloseCancel() {
        pendingTabClose = nil
    }

    /// The close itself: mutate the model, then activate the surviving
    /// focused tab through the identity funnel (restores its buffer even
    /// when it shares a path with the closed tab).
    func performCloseTab(_ id: TabID) {
        let closingActive = id == workspace.model.activeGroup.activeTabID
        let closedTab = workspace.model.tab(id)
        let closedTitle = closedTab.map { filename(of: workspace.tabPath($0)) }
        let closedItem = closedTab?.item
        if case .markdown(let path) = closedItem,
            hasAuthoredPropertyPublicationRecovery(for: path),
            !hasOtherMarkdownTab(for: path, excluding: id)
        {
            postMutationAnnouncement(
                "Resolve the saved property update awaiting verification in \(filename(of: path)) before closing its final tab. Copy the retained update, reapply it, or use the current version.")
            pendingTabClose = nil
            return
        }
        if case .markdown(let path) = closedItem,
            propertyEditBlocksFinalTabClose(path: path, excluding: id)
        {
            postMutationAnnouncement(Self.propertyEditInProgressReason)
            pendingTabClose = nil
            return
        }
        if case .markdown(let path) = closedItem,
            hasPropertyPublicationUncertainty(for: path),
            !hasOtherMarkdownTab(for: path, excluding: id),
            !hasDirtyNoteRecovery(for: path)
        {
            clearCloseSafeBulkPropertyPublicationVerification(for: path)
        }
        if closingActive {
            // The buffer being closed must not leak into the successor's
            // snapshot: tear the active fields down BEFORE the model close
            // (afterwards the model's active tab is already the successor,
            // and a snapshot would park the closed buffer under its id).
            // A dirty buffer only reaches here through the Discard
            // resolution or clean state — requestCloseTab gates the rest.
            cancelNoteScopedWork()
            clearActiveNoteFields()
        }
        editorCaretReturn[id] = nil
        let outcome = workspace.close(id)
        releaseCanvasDocumentIfUnreferenced(closedItem)
        releaseBaseDocumentIfUnreferenced(closedItem)
        releaseDashboardDocumentIfUnreferenced(closedItem)
        releaseGraphStateIfUnreferenced(closedItem)
        if closingActive {
            if let successor = outcome.focusedTab {
                activateTab(successor)
            } else if selectedFilePath != nil {
                selectedFilePath = nil
            }
        }
        if let closedTitle {
            let successor = workspace.activeTab.map {
                filename(of: workspace.tabPath($0))
            }
            postAccessibilityAnnouncement(
                successor.map { "Closed \(closedTitle). \($0) is active." }
                    ?? "Closed \(closedTitle).",
                priority: .medium)
        }
    }

    // MARK: - Reopen Closed Tab (#863)

    /// Menu-enablement mirror of `workspace.closedTabs.isEmpty` (#863).
    /// The File ▸ Reopen Closed Tab item reads THIS property. Predates
    /// the #868 workspace→appState objectWillChange bridge (which alone
    /// would now re-render the menu on stack changes); kept because the
    /// mirror is the tested, named Bool surface the menu reads — no
    /// reason to re-derive emptiness at the call site. Wired in `init`
    /// from `workspace.$closedTabs`.
    @Published private(set) var canReopenClosedTab = false

    /// ⇧⌘T — Reopen Closed Tab (#863, the macOS/Obsidian convention).
    /// Pops the per-vault-session closed-tab stack and reopens the
    /// record through the STANDARD open funnel (`openFile` /
    /// `openSavedQuery` / `openDashboard` with `.newTab`), so the U1-2
    /// dedup rule applies unchanged: an item already open in the target
    /// group activates the existing tab and the popped record is simply
    /// consumed. A file that no longer exists on disk is announced and
    /// skipped, and the next record is tried (Reopen never resurrects a
    /// dead document). Pane placement: the reopen lands in the group
    /// the tab was closed from when that pane still exists, else the
    /// active group.
    /// The on-disk path for file-backed tab items; nil for id-backed
    /// kinds (saved query / dashboard), whose loaders own missing-state.
    static func fileBackedPath(of item: EditorItem) -> String? {
        switch item {
        case .markdown(let p), .canvas(let p), .base(let p): return p
        case .savedQuery, .dashboard, .graph: return nil
        }
    }

    func reopenClosedTab() {
        guard isVaultOpen else { return }
        if let reason = propertyEditNavigationDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        while let record = workspace.popClosedTab() {
            // Dead-record skip runs BEFORE any pane-focus movement: a
            // pure skip must be a focus/park no-op. The first draft
            // parked + focused first, so skipping a deleted file left
            // the previous pane's buffer rendered under the destination
            // tab's title (red-team probe, executable repro).
            if case let fileBacked = record.item,
                let path = Self.fileBackedPath(of: fileBacked),
                let vaultURL = currentVaultURL,
                !FileManager.default.fileExists(
                    atPath: vaultURL.appendingPathComponent(path).path)
            {
                postAccessibilityAnnouncement(
                    "\(filename(of: path)) no longer exists.",
                    priority: .medium)
                continue
            }
            if workspace.model.group(record.groupID) != nil,
                workspace.model.activeGroupID != record.groupID {
                // Park the outgoing buffer BEFORE moving group focus —
                // after `focusGroup` the model's active tab is the
                // destination pane's, and the snapshot guard would
                // (correctly) refuse to park the old fields under it.
                parkOutgoingNoteBuffer()
                workspace.focusGroup(record.groupID)
            }
            switch record.item {
            case .markdown(let path), .canvas(let path), .base(let path):
                openFile(path, target: .newTab)
                postAccessibilityAnnouncement(
                    "Reopened \(filename(of: path)).", priority: .medium)
            case .savedQuery(let id, let name):
                openSavedQuery(id: id, name: name, target: .newTab)
                postAccessibilityAnnouncement(
                    "Reopened \(name).", priority: .medium)
            case .dashboard(let id, let name):
                openDashboard(id: id, name: name, target: .newTab)
                postAccessibilityAnnouncement(
                    "Reopened \(name).", priority: .medium)
            case .graph:
                openGraphTab()
                postAccessibilityAnnouncement("Reopened Graph.", priority: .medium)
            }
            return
        }
    }

    /// ⌘⇧] / ⌘⇧[ / ⌘1…⌘9. The model is a value type: compute the target on
    /// a COPY (zero logic duplication), then run the identity funnel.
    func selectNextTab() { activateComputedTab { $0.selectNextTab() } }
    func selectPreviousTab() { activateComputedTab { $0.selectPreviousTab() } }
    func selectTab(ordinal: Int) { activateComputedTab { $0.selectTab(ordinal: ordinal) } }
    func selectTab(id: TabID) {
        activateTab(id, advancesSidebarSelectionRevision: true)
    }

    /// ⌃⌘← / ⌃⌘→ keyboard reorder (the non-drag equivalent to dragging).
    func moveActiveTabLeft() {
        workspace.moveActiveTab(by: -1)
        announceActiveTab(prefix: "Moved tab left.")
    }
    func moveActiveTabRight() {
        workspace.moveActiveTab(by: 1)
        announceActiveTab(prefix: "Moved tab right.")
    }

    private func activateComputedTab(_ compute: (inout WorkspaceModel) -> Void) {
        var preview = workspace.model
        compute(&preview)
        guard let target = preview.activeGroup.activeTabID,
            target != workspace.model.activeGroup.activeTabID
        else { return }
        activateTab(target, advancesSidebarSelectionRevision: true)
    }

    // MARK: - Frontmatter parts (U3-3, #467/#469)

    /// The exact bytes between the note's frontmatter delimiters ("" when
    /// the note has none) — `read_note_parts.fm_source`. The editor buffer
    /// (`currentNoteText`) is the BODY; every composed save reassembles
    /// through the ONE Rust composer (`compose_note` inside
    /// `save_composed`), never a Swift mirror. Refreshed by load, property
    /// edits, and the U3-4 source editor.
    @Published private(set) var currentNoteFMSource: String = ""

    /// Whole-file → body deltas, straight from `read_note_parts` (computed
    /// Rust-side as `whole − body` at the split point — byte-exact by
    /// construction, NEVER re-derived from any compose rule in Swift: two
    /// composers diverge, the U3-5 law). Backend offsets (headings, task
    /// lines, backlink lines, template cursors) are whole-file; the body
    /// buffer is not — these are the one conversion authority.
    private(set) var bodyByteOffset: Int = 0
    private(set) var bodyLineOffset: Int = 0

    /// Whole-file heading offsets → body space (clamped at 0 — the scanner
    /// only emits body headings, so clamping is defensive, not semantic).
    static func rebasedToBody(_ headings: [Heading], prefixBytes: Int) -> [Heading] {
        guard prefixBytes > 0 else { return headings }
        return headings.map { h in
            var rebased = h
            rebased.byteOffset = UInt32(max(0, Int(h.byteOffset) - prefixBytes))
            return rebased
        }
    }

    /// Whole-file 1-based line → body 1-based line (floor 1) and back.
    func bodyLine(fromFileLine line: Int) -> Int {
        max(1, line - bodyLineOffset)
    }

    func fileLine(fromBodyLine line: Int) -> Int {
        line + bodyLineOffset
    }

    /// Whole-file byte offset → body byte offset (floor 0).
    func bodyByte(fromFileByte byte: Int) -> Int {
        max(0, byte - bodyByteOffset)
    }

    /// Refresh fmSource + offsets (+hash) after an operation rewrote the
    /// file's frontmatter out-of-buffer (property edit, U3-4 source
    /// commit). One `read_note_parts` call; the BODY buffer is never
    /// touched — an fm-only rewrite leaves the on-disk body identical to
    /// `savedBaselineText`, and a dirty buffer keeps its edits. Same-path
    /// parked duplicates mirror the fresh fm so their eventual composed
    /// saves can't resurrect stale frontmatter.
    private enum NotePartsRefreshOutcome {
        case published
        case propertiesOnly
        case changedAgain(currentContentHash: String)
        case stale
        case failed(String)
    }

    private struct NotePartsRefreshSnapshot: Sendable {
        let parts: NotePartsBundle
        let properties: [Property]
        let bodyBaselinesMatch: Bool
    }

    /// Publish a frontmatter-only write as one validated unit. A fresh hash is
    /// never paired with stale FM bytes, nor with a body that differs from the
    /// editor's saved baseline. `allowPropertiesOnlyOnBodyMismatch` is the
    /// property-conflict Reload path: rows may truthfully show authoritative
    /// disk values while the old expected hash remains in place so a later
    /// body save still conflicts instead of overwriting an external body edit.
    private func refreshNoteParts(
        session: VaultSession,
        path: String,
        expectedContentHash: String? = nil,
        allowPropertiesOnlyOnBodyMismatch: Bool = false
    ) async -> NotePartsRefreshOutcome {
        // Strings are copy-on-write values, so capturing the current saved
        // baselines is O(number of open duplicates) on MainActor. The
        // potentially 50 MiB byte comparisons happen with the disk read and
        // frontmatter parse in the detached worker below.
        let activeBaselineRequired = BaseExactIdentity.matches(loadedFilePath, path)
        let activeBaseline = activeBaselineRequired ? savedBaselineText : nil
        let activeBaselineRevision = noteBodyBaselineRevision
        let parkedBaselines = workspace.loadedBaselineSnapshots(forPath: path)
        let parkedBaselineRevision = workspace.loadedBaselineRevision
        let outcome: Result<NotePartsRefreshSnapshot, VaultError> = await Task.detached(
            priority: .userInitiated
        ) {
            do {
                let parts = try session.readNoteParts(path: path)
                let activeBaselineMatches = !activeBaselineRequired
                    || activeBaseline.map {
                        BaseExactIdentity.matches($0, parts.body)
                    } == true
                let parkedBaselinesMatch = parkedBaselines.allSatisfy {
                    BaseExactIdentity.matches($0, parts.body)
                }
                return .success(
                    NotePartsRefreshSnapshot(
                        parts: parts,
                        properties: parseFrontmatterProperties(
                            fmSource: parts.fmSource),
                        bodyBaselinesMatch:
                            activeBaselineMatches && parkedBaselinesMatch))
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }.value
        guard currentSession === session else { return .stale }
        guard noteBodyBaselineRevision == activeBaselineRevision,
            workspace.loadedBaselineRevision == parkedBaselineRevision
        else {
            return .failed(
                "The editor baseline changed before Slate could publish the property update.")
        }
        let snapshot: NotePartsRefreshSnapshot
        switch outcome {
        case .success(let value):
            snapshot = value
        case .failure(let error):
            return .failed(humanReadable(error))
        }
        let parts = snapshot.parts
        if let expectedContentHash,
            parts.contentHash != expectedContentHash
        {
            return .changedAgain(currentContentHash: parts.contentHash)
        }

        guard snapshot.bodyBaselinesMatch else {
            guard allowPropertiesOnlyOnBodyMismatch,
                BaseExactIdentity.matches(loadedFilePath, path)
            else {
                return .failed(
                    "The note body changed externally before Slate could publish the property update.")
            }
            // Source Reload still needs to show the authoritative YAML. Keep
            // the OLD expected hash deliberately: the FM/body pair is not a
            // safe body-save baseline, so the next composed save must conflict
            // until the user explicitly resolves the external body edit.
            currentNoteFMSource = parts.fmSource
            bodyByteOffset = Int(parts.bodyByteOffset)
            bodyLineOffset = Int(parts.bodyLineOffset)
            workspace.mirrorFrontmatterWithoutAdvancingHash(
                path: path,
                fmSource: parts.fmSource,
                bodyByteOffset: Int(parts.bodyByteOffset),
                bodyLineOffset: Int(parts.bodyLineOffset))
            currentNoteProperties = snapshot.properties
            return .propertiesOnly
        }

        workspace.mirrorFrontmatter(
            path: path, fmSource: parts.fmSource,
            bodyByteOffset: Int(parts.bodyByteOffset),
            bodyLineOffset: Int(parts.bodyLineOffset),
            contentHash: parts.contentHash)
        if BaseExactIdentity.matches(loadedFilePath, path) {
            currentNoteFMSource = parts.fmSource
            bodyByteOffset = Int(parts.bodyByteOffset)
            bodyLineOffset = Int(parts.bodyLineOffset)
            currentNoteContentHash = parts.contentHash
            currentNoteProperties = snapshot.properties
        }
        return .published
    }

    // MARK: - View mode (U3-2, #466)

    /// Live caret location in RAW UTF-16, reported continuously by the
    /// editor coordinator (`onCaretUTF16Change`) — a plain Int handoff.
    /// NEVER `@Published` (selection churn is per-keystroke and must not
    /// invalidate views), and never converted here: the UTF-8 conversion
    /// runs ONCE at switch-to-reading time — a per-keystroke rope build
    /// over the whole document is the O(n) class #404 eliminated.
    private var liveEditorCaretUTF16: Int = 0

    /// Caret (UTF-8 byte offset) to restore per tab when its editor
    /// remounts after reading mode (U3-2 spec: "caret preserved from last
    /// editing session of this tab, else {0,0}"). Sparse; cleared on
    /// delivery and on tab close.
    private var editorCaretReturn: [TabID: Int] = [:]

    func noteEditorCaretDidMove(toUTF16 location: Int) {
        liveEditorCaretUTF16 = location
    }

    /// The ACTIVE tab's view mode — what `NoteContentView` renders.
    var activeViewMode: NoteViewMode { workspace.activeViewMode }

    /// #868 menu-title seam: TRUE when the active tab shows reading
    /// mode. A computed read of workspace state — no mirror needed,
    /// because the init-time workspace→appState objectWillChange
    /// bridge re-renders the menu on every mode flip. No tab reads
    /// as false ("Enter Reading Mode", matching `activeViewMode`'s
    /// `.editing` default for an empty workspace).
    var activeTabIsReading: Bool { activeViewMode == .reading }

    /// ⌘⇧E / toolbar toggle: flip the active tab between editing and
    /// reading. No-ops without a renderable note (no tab, load error, or
    /// nothing loaded) — the button and command are enabled in the same
    /// states, but the palette can always invoke.
    func toggleViewMode() {
        guard let tabID = workspace.model.activeGroup.activeTabID,
            loadedFilePath != nil, noteLoadError == nil
        else { return }
        let target: NoteViewMode =
            workspace.viewMode(for: tabID) == .editing ? .reading : .editing
        setViewMode(target, for: tabID)
    }

    /// Mode-flip funnel (toggle button, ⌘⇧E, ReadingView's empty-state
    /// "Switch to Editing"). Captures/restores the editor caret for the
    /// ACTIVE tab, announces, and persists the layout (mode is per-tab
    /// state in workspace.json).
    func setViewMode(_ target: NoteViewMode, for tabID: TabID? = nil) {
        guard let tabID = tabID ?? workspace.model.activeGroup.activeTabID
        else { return }
        guard workspace.viewMode(for: tabID) != target else { return }
        let isActiveTab = tabID == workspace.model.activeGroup.activeTabID
        if isActiveTab, target == .reading {
            // Park the caret before the editor unmounts (converted to a
            // byte offset HERE, once, against the live buffer — human
            // cadence, not keystroke cadence). The buffer stays in
            // AppState's fields — reading renders from it.
            editorCaretReturn[tabID] = EditorTextConversions.byteOffsetForUTF16Location(
                liveEditorCaretUTF16, in: currentNoteText ?? "")
        }
        workspace.setViewMode(target, for: tabID)
        if isActiveTab, target == .editing {
            // Remount: the coordinator's one-shot handler parks the caret,
            // scrolls it visible, and makes the editor first responder
            // (the #421 F-H1 discipline) — focus lands in the new surface.
            cursorByteOffsetRequest.send(
                editorCaretReturn.removeValue(forKey: tabID) ?? 0)
        }
        saveWorkspaceLayout()
        if isActiveTab {
            let announcement = target == .reading ? "Reading mode." : "Editing mode."
            lastViewModeAnnouncement = announcement
            postAccessibilityAnnouncement(announcement)
        }
    }

    /// Last mode-flip announcement (U3-2). Test seam — the announcement
    /// helper is a no-op under XCTest (no NSApp), so the exact string must
    /// be observable here (same pattern as `lastMutationAnnouncement`).
    private(set) var lastViewModeAnnouncement: String?

    // MARK: - Undo/Redo menu observability (#867)

    /// Re-render pulse for the Edit ▸ Undo/Redo titles. The state those
    /// titles derive from lives OUTSIDE appState's published surface —
    /// responder-chain `NSUndoManager`s and `CanvasDocument`'s session
    /// stacks — so this tick republishes "the undo world changed" into
    /// the object the `.commands` builder observes. Bumped (debounced)
    /// by the NSUndoManager-notification pipeline wired in `init` and
    /// by the canvas mutation funnel (`noteUndoStacksChanged`). The
    /// VALUE is meaningless; only the publish matters — the titles
    /// below are computed live at menu render.
    @Published private(set) var undoMenuTick = 0

    /// Feed for the init pipeline above — merged with the NSUndoManager
    /// notifications ahead of the shared debounce.
    private let undoMenuSubject = PassthroughSubject<Void, Never>()

    /// Canvas funnel entry (#867): the canvas undo/redo stacks mutated
    /// (`canvasApply` / `canvasUndo` / `canvasRedo`) — request an
    /// undo-menu re-render pulse. Coalesced by the init pipeline's
    /// debounce, so callers fire per-mutation without menu churn.
    func noteUndoStacksChanged() {
        undoMenuSubject.send()
    }

    /// The undo manager the responder chain would hand ⌘Z to: the key
    /// window's first responder's (NSTextView supplies its own), else
    /// the key window's on-demand manager. Nil under XCTest (no NSApp —
    /// same guard discipline as `postAccessibilityAnnouncement`) or
    /// with no key window at render time.
    var responderChainUndoManager: UndoManager? {
        guard let window = NSApp?.keyWindow else { return nil }
        return window.firstResponder?.undoManager ?? window.undoManager
    }

    /// Edit ▸ Undo title (#867): a canvas-focused tab uses the canvas
    /// stack's recorded verb (the t3 layer-2 names — "create card",
    /// "delete \"X\""); everywhere else NSUndoManager composes its own
    /// localized full title ("Undo Typing") — descriptive labels per
    /// undo-and-redo.md, the-menu-bar.md ("Undo | Append action name").
    var undoMenuItemTitle: String {
        if undoTargetsCanvas {
            return Self.canvasUndoRedoMenuTitle(
                base: "Undo", actionName: activeCanvasDocument?.undoStack.last?.name)
        }
        // #871: the structural (file-op) domain — same composer as canvas,
        // the action name describing the pending op read from the stack top
        // ("Undo Move of Notes.md", "Undo Rename to Draft.md"). An empty
        // stack composes to the bare "Undo".
        if undoTargetsStructural {
            return Self.canvasUndoRedoMenuTitle(
                base: "Undo",
                actionName: structuralUndoStack.last.map(Self.structuralUndoActionName))
        }
        return Self.responderUndoMenuTitle(responderChainUndoManager)
    }

    /// ⇧⌘Z symmetric to `undoMenuItemTitle`.
    var redoMenuItemTitle: String {
        if undoTargetsCanvas {
            return Self.canvasUndoRedoMenuTitle(
                base: "Redo", actionName: activeCanvasDocument?.redoStack.last?.name)
        }
        if undoTargetsStructural {
            return Self.canvasUndoRedoMenuTitle(
                base: "Redo",
                actionName: structuralRedoStack.last.map(Self.structuralUndoActionName))
        }
        return Self.responderRedoMenuTitle(responderChainUndoManager)
    }

    /// Enablement (#867): the responder path mirrors the system Edit
    /// menu — plain, disabled "Undo" when the resolved manager
    /// positively reports `canUndo == false`. An UNRESOLVABLE manager
    /// (no key window at render time — e.g. the app inactive) stays
    /// ENABLED with the plain title: ⌘Z then no-ops harmlessly through
    /// `sendAction`, which beats a stale-disabled item deadening the
    /// chord (first-responder moves don't publish, so a nil read must
    /// never latch the item off). The canvas path stays ALWAYS enabled:
    /// empty-stack ⌘Z announces "Nothing to undo." (t0 §1.3) — a
    /// deliberate VoiceOver affordance a disabled item would silence.
    var undoMenuItemEnabled: Bool {
        if undoTargetsCanvas { return activeCanvasMutationDisabledReason == nil }
        if canvasCardEditor != nil,
            activeCanvasCardEditorDisabledReason != nil
        {
            return false
        }
        if activeNoteAuthoringDisabledReason != nil { return false }
        // #871: the structural domain stays ALWAYS enabled while the tree
        // owns the chord — an empty-stack ⌘Z announces "Nothing to undo."
        // (`structuralUndo()`), the same deliberate VoiceOver affordance the
        // canvas path keeps that a disabled item would silence.
        if undoTargetsStructural { return true }
        guard let manager = responderChainUndoManager else { return true }
        return manager.canUndo
    }

    /// ⇧⌘Z symmetric to `undoMenuItemEnabled`.
    var redoMenuItemEnabled: Bool {
        if undoTargetsCanvas { return activeCanvasMutationDisabledReason == nil }
        if canvasCardEditor != nil,
            activeCanvasCardEditorDisabledReason != nil
        {
            return false
        }
        if activeNoteAuthoringDisabledReason != nil { return false }
        if undoTargetsStructural { return true }
        guard let manager = responderChainUndoManager else { return true }
        return manager.canRedo
    }

    /// Pure title composer (#867), extracted for direct testing:
    /// "Undo" + a canvas action name — "delete \"My Card\"" becomes
    /// "Undo Delete \"My Card\"". Only the LEADING character is
    /// uppercased: the t3 action names embed user-typed card titles
    /// that must pass through verbatim, so full Title Case is off the
    /// table. Nil/empty (empty stack) falls back to the bare verb.
    static func canvasUndoRedoMenuTitle(base: String, actionName: String?) -> String {
        guard let name = actionName, !name.isEmpty else { return base }
        return "\(base) \(name.prefix(1).uppercased())\(name.dropFirst())"
    }

    /// Pure title composer (#867) for the responder path: NSUndoManager
    /// composes and localizes the full title itself ("Undo Typing" via
    /// `undoMenuItemTitle`). With nothing to undo the item reads plain
    /// "Undo", matching its disabled state (system behavior).
    static func responderUndoMenuTitle(_ manager: UndoManager?) -> String {
        guard let manager, manager.canUndo else { return "Undo" }
        return manager.undoMenuItemTitle
    }

    /// Redo twin of `responderUndoMenuTitle`.
    static func responderRedoMenuTitle(_ manager: UndoManager?) -> String {
        guard let manager, manager.canRedo else { return "Redo" }
        return manager.redoMenuItemTitle
    }

    /// The THIRD undo domain (#871): ⌘Z drives the structural (file move /
    /// rename) undo stack when the FILE TREE owns focus.
    ///
    /// Precedence — MUST match the SlateMacApp `.undoRedo` routing and the
    /// title/enablement getters above: canvas FIRST (#372/#867
    /// route-by-active-tab, byte-for-byte unchanged), then structural, then
    /// the responder chain. This property is explicitly FALSE whenever
    /// `undoTargetsCanvas` is true, so the two domains are PROVABLY mutually
    /// exclusive and the render-time title can never bake a different domain
    /// than the press-time action resolves (the documented #867 desync).
    ///
    /// Gated on PUBLISHED state ONLY — `workspace.focusRegion`, which the
    /// #868 `workspace.objectWillChange → appState.objectWillChange` bridge
    /// forwards so `.commands` re-renders when focus crosses into/out of the
    /// tree. NEVER an `NSApp.keyWindow.firstResponder` read for the routing
    /// decision (constraint #871.2): that value is unpublished, so a title
    /// computed from it at render time would desync from the action.
    var undoTargetsStructural: Bool {
        guard !undoTargetsCanvas else { return false }
        // #871 red-team: EXCLUDE the inline tree-rename field. `RenameField`
        // is a TextField descendant of the List that carries
        // `.focused($fileTreeFocused)`, which has focus-WITHIN semantics — so
        // `workspace.focusRegion` stays `.tree` while the user is typing a new
        // name. Without this guard, ⌘Z to fix a typo mid-rename would route to
        // `structuralUndo()` — reversing an UNRELATED prior move/rename on disk
        // AND shadowing the field editor's own text undo (a regression: the
        // pre-#871 `else` branch forwarded `undo:` to that editor). Mirrors the
        // `!isRenaming` guard `treeKeyInterceptionActive` already uses for the
        // List's key interceptors. `renamingNode` is @Published, so the Edit
        // menu re-renders (and the routing flips back) the moment a rename
        // begins or ends — the published-state-only rule is preserved.
        return workspace.focusRegion == .tree && renamingNode == nil
    }

    // MARK: - Workspace persistence (U1-6, #458)

    /// Debounced layout save: any model mutation schedules a write 500ms
    /// out (coalescing bursts); vault close and app termination save
    /// immediately. Set up from init.
    func wireWorkspacePersistence() {
        workspace.$model
            .dropFirst()
            .debounce(for: .milliseconds(500), scheduler: DispatchQueue.main)
            .sink { [weak self] _ in
                self?.saveWorkspaceLayout()
            }
            .store(in: &subscriptions)
        // U4-1 (#470): the active right-pane leaf persists too. Same debounced
        // path as `$model` — a leaf switch coalesces with any concurrent layout
        // churn into one write.
        workspace.$activeLeaf
            .dropFirst()
            .debounce(for: .milliseconds(500), scheduler: DispatchQueue.main)
            .sink { [weak self] _ in
                self?.saveWorkspaceLayout()
            }
            .store(in: &subscriptions)
        // #873: the file tree's expanded-folder set persists too. Same
        // debounced path — an expand/collapse burst coalesces into one
        // write, and any concurrent layout churn shares it.
        $treeExpandedDirPaths
            .dropFirst()
            .removeDuplicates()
            .debounce(for: .milliseconds(500), scheduler: DispatchQueue.main)
            .sink { [weak self] _ in
                self?.saveWorkspaceLayout()
            }
            .store(in: &subscriptions)
        NotificationCenter.default.addObserver(
            forName: NSApplication.willTerminateNotification, object: nil,
            queue: .main
        ) { [weak self] _ in
            MainActor.assumeIsolated {
                self?.saveWorkspaceLayout()
            }
        }
    }

    /// The file tree's expanded-folder PATHS in recency order (#873):
    /// the sidebar mirrors its view-model's path ledger here on every
    /// expansion change AND explicitly after mutation reconciliation
    /// (id-stable renames change no id set — Codex round 6), a
    /// post-update mutation point (#448 discipline);
    /// `wireWorkspacePersistence` saves it on the shared debounced
    /// path, and `restoreWorkspaceLayout` refills it so the sidebar's
    /// `bind(to:)` rehydrates instead of resetting to [].
    @Published var treeExpandedDirPaths: [String] = []

    func saveWorkspaceLayout() {
        guard let vaultURL = currentVaultURL else { return }
        let store = WorkspaceStore(vaultRoot: vaultURL)
        do {
            try store.save(
                WorkspaceStore.snapshot(
                    of: workspace.model, activeLeaf: workspace.activeLeaf.rawValue,
                    viewModes: workspace.viewModes,
                    propertiesCollapsed: workspace.propertiesCollapsed,
                    canvasSurfaces: workspace.canvasSurfaces,
                    expandedDirPaths: treeExpandedDirPaths))
        } catch {
            // Layout persistence must never interrupt the user; the next
            // clean save wins.
            fputs("Slate: workspace.json save failed: \(error)\n", stderr)
        }
    }

    func restoreWorkspaceLayout() {
        guard let vaultURL = currentVaultURL else { return }
        let store = WorkspaceStore(vaultRoot: vaultURL)
        guard let snapshot = store.load() else { return }
        // Restore the active leaf independently of the tab model: an unknown or
        // absent token (or a leaf not yet registered) falls back to `.outline`
        // (Leaf.init(persisted:)). Assigning before the empty-model guard means
        // the remembered panel survives even a vault reopened with no tabs.
        workspace.activeLeaf = Leaf(persisted: snapshot.activeLeaf)
        // #873: likewise the expanded-folder set — assigned before the model
        // guard so expansion survives a vault reopened with no restorable
        // tabs. The sidebar's bind(to:) consumes this when it rehydrates.
        treeExpandedDirPaths = WorkspaceStore.expandedDirPaths(from: snapshot)
        guard let restored = WorkspaceStore.model(from: snapshot),
            !restored.isEmpty
        else { return }
        workspace.adopt(
            restored, viewModes: WorkspaceStore.viewModes(from: snapshot),
            propertiesCollapsed: WorkspaceStore.propertiesCollapsed(from: snapshot),
            canvasSurfaces: WorkspaceStore.canvasSurfaces(from: snapshot))
        if let tab = workspace.model.activeGroup.activeTabID {
            activateTab(tab)
        }
    }

    // MARK: - Open-in targets (U1-5, #457)

    /// Where a navigation opens its document.
    enum OpenTarget: Equatable {
        /// Replace the active tab's item (the pre-tabs behavior; the dirty
        /// gate applies exactly as before).
        case currentTab
        /// A new tab in the focused group (⌘-click); reuses an existing tab
        /// for the same path in that group rather than duplicating.
        case newTab
        /// A new split pane showing the document (falls back to `.newTab`
        /// at the 6-pane capacity, announced by the split path).
        case newSplit(SplitBranch.Axis)
    }

    /// The single navigation entry point (U1-5). Every open path — sidebar
    /// row, backlink/outgoing-link/embed activation, search result, palette
    /// command — routes here with an explicit target.
    func openFile(
        _ path: String,
        target: OpenTarget,
        advancesSidebarSelectionRevision: Bool = true
    ) {
        if let reason = propertyEditNavigationDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        if advancesSidebarSelectionRevision {
            recordExplicitSidebarNavigationIntent()
        }
        // Record the open into the vault's file-recents (#495) at this
        // single funnel — every user-visible open routes here, launch
        // restores (activateTab) do not. Recorded once per call, before
        // the target branch, so all three targets bump recency equally.
        recordFileOpen(path: path)
        // Milestone T (#369): .canvas paths take the canvas arm of the
        // funnel — the note loader must never read a canvas as text.
        if path.lowercased().hasSuffix(".canvas") {
            openCanvasFile(
                path,
                target: target,
                advancesSidebarSelectionRevision: false)
            return
        }
        // Milestone N (#702): .base paths take the Bases arm of the
        // funnel — the note loader must never read a base as text.
        if path.lowercased().hasSuffix(".base") {
            openBaseFile(
                path,
                target: target,
                advancesSidebarSelectionRevision: false)
            return
        }
        clearActiveBaseQuickFilter()
        switch target {
        case .currentTab:
            if !BaseExactIdentity.matches(selectedFilePath, path) {
                selectedFilePath = path
            }
        case .newTab:
            if let existing = workspace.activeGroupTab(forPath: path) {
                activateTab(existing.id)
                return
            }
            // Park the outgoing buffer while the fields still describe it,
            // then create + activate the tab; `activateTab` loads the new
            // path (its snapshot guard blocks a double-park: the fields no
            // longer match the new active tab).
            parkPropertiesSourceDraftForTransition()
            workspace.snapshotActiveTab(
                text: currentNoteText, baseline: savedBaselineText,
                contentHash: currentNoteContentHash,
                hasUnsavedChanges: hasUnsavedChanges,
                saveError: saveError, saveConflict: currentSaveConflict,
                loadedFilePath: loadedFilePath,
                fmSource: currentNoteFMSource,
                bodyByteOffset: bodyByteOffset, bodyLineOffset: bodyLineOffset)
            let id = workspace.openTab(.markdown(path: path))
            activateTab(id)
        case .newSplit(let axis):
            let paneCount = workspace.model.groupsInOrder.count
            splitActivePane(axis: axis)
            if workspace.model.groupsInOrder.count == paneCount {
                // Split rejected (capacity / empty) — the document still
                // deserves to open somewhere visible.
                openFile(
                    path,
                    target: .newTab,
                    advancesSidebarSelectionRevision: false)
                return
            }
            // The new pane holds a duplicate of the previous document;
            // retarget it (same funnel as a sidebar click in that pane).
            if !BaseExactIdentity.matches(selectedFilePath, path) {
                selectedFilePath = path
            }
        }
    }

    /// Pointer sugar: ⌘-click on any navigation affordance opens in a new
    /// tab. Reads the CURRENT AppKit event, so it must be called
    /// synchronously from the click's action.
    func openTargetFromCurrentEvent() -> OpenTarget {
        if NSApp?.currentEvent?.modifierFlags.contains(.command) == true {
            return .newTab
        }
        return .currentTab
    }

    // MARK: - Split panes (U1-3, #455)

    /// ⌘\ / ⌘⌥\. Duplicate-active-item split; focus lands in the new pane
    /// (the duplicate shares the active document's file, so the active
    /// fields remain valid — no funnel hop needed; the model split already
    /// moved group focus).
    func splitActivePane(axis: SplitBranch.Axis) {
        if let reason = propertyEditNavigationDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        // A split duplicates the active item into the new pane; for the
        // graph that would violate the workspace-global singleton (round
        // 2 finding 6). Refuse and say why — the graph opens in one pane;
        // to see it beside a note, split from the note instead. (An
        // `openFile(.newSplit)` for a real file falls back to a new tab
        // via its own capacity check.)
        if case .graph = workspace.activeTab?.item {
            postAccessibilityAnnouncement(
                "The graph opens in a single pane. Split from a note instead.",
                priority: .medium)
            return
        }
        // Park the outgoing pane's buffer FIRST: after the split the
        // original tab is unfocused and renders from its parked document —
        // without this it would show the never-visited placeholder.
        workspace.snapshotActiveTab(
            text: currentNoteText, baseline: savedBaselineText,
            contentHash: currentNoteContentHash,
            hasUnsavedChanges: hasUnsavedChanges,
            saveError: saveError, saveConflict: currentSaveConflict,
            loadedFilePath: loadedFilePath,
            fmSource: currentNoteFMSource,
            bodyByteOffset: bodyByteOffset, bodyLineOffset: bodyLineOffset)
        guard let newGroup = workspace.split(workspace.model.activeGroupID, axis: axis)
        else {
            let reason =
                workspace.isAtPaneCapacity
                ? "Pane limit reached — a seventh pane could not stay visible."
                : "Nothing to split — open a note first."
            postAccessibilityAnnouncement(reason, priority: .medium)
            return
        }
        // A split focuses the new EDITOR pane — if focus had been parked in a
        // terminal region (⌘\ while in the tree/leaf), re-seat the region so a
        // subsequent ⌘⌥arrow anchors on this new group (U4-4, #473).
        workspace.markEditorRegionActive()
        announcePaneFocus(newGroup, prefix: "Split. ")
    }

    /// ⌘⌥arrows. Spatial focus move across the three terminal regions
    /// (U4-4, #473): the file tree (westernmost), the editor split groups,
    /// and the right-pane leaf (easternmost). Interior editor↔editor moves
    /// are the model's geometry (`focusNeighbor`), unchanged; this method
    /// wraps that at the two horizontal edges so ⌘⌥← off the leftmost group
    /// enters the tree and ⌘⌥→ off the rightmost group enters the leaf, with
    /// the reverse move returning to the exact group left behind
    /// (`lastFocusedGroup`). Focus is never lost — I7 extended across the
    /// region boundary.
    func focusPane(_ direction: WorkspaceModel.Direction) {
        // Resolve the decision purely (the same resolver the terminal-region
        // census drives), then apply its one effect. The interior neighbor is
        // probed non-mutating so `.none`/terminal outcomes leave the model
        // untouched.
        let neighbor = workspace.peekNeighbor(direction)
        switch workspace.resolveFocusRouting(direction, interiorNeighbor: neighbor) {
        case .editorGroup(let target):
            if let reason = propertyEditNavigationDisabledReason {
                postMutationAnnouncement(reason)
                return
            }
            workspace.focusGroup(target)
            enterEditorGroup(target)
        case .returnToEditor:
            if let reason = propertyEditNavigationDisabledReason {
                postMutationAnnouncement(reason)
                return
            }
            let landed = workspace.focusEditorRegion()
            enterEditorGroup(landed)
        case .enterTree:
            workspace.focusTreeRegion()
            postAccessibilityAnnouncement(
                Self.filesRegionAnnouncement, priority: .medium)
        case .enterLeaf:
            focusLeafRegionRevealingPane()
            postAccessibilityAnnouncement(
                Self.leafRegionAnnouncement(workspace.activeLeaf), priority: .medium)
        case .none:
            return
        }
    }

    /// Focus an editor group after a move landed on it: activate its tab
    /// through the identity funnel (document swap) and announce. Shared by the
    /// interior move and the return-from-terminal paths so both keep the same
    /// funnel + announcement discipline (U1-3 invariant — never bypass
    /// `activateTab`).
    private func enterEditorGroup(_ groupID: GroupID) {
        if let tab = workspace.model.group(groupID)?.activeTabID {
            selectTab(id: tab)
        }
        announcePaneFocus(groupID)
    }

    /// ⌘⌥= / ⌘⌥-.
    func growFocusedPane() { adjustFocusedPane(by: WorkspaceModel.resizeStep) }
    func shrinkFocusedPane() { adjustFocusedPane(by: -WorkspaceModel.resizeStep) }

    private func adjustFocusedPane(by delta: Double) {
        guard workspace.hasSplits else {
            postAccessibilityAnnouncement("No split panes to resize.", priority: .medium)
            return
        }
        workspace.adjustFocusedPaneWeight(by: delta)
        if let fraction = workspace.focusedPaneFraction {
            postAccessibilityAnnouncement(
                "Pane resized, \(Int((fraction * 100).rounded())) percent.",
                priority: .medium)
        }
    }

    /// Palette-only "Close Pane": close the focused pane's tabs one at a
    /// time through the standard close gates. A dirty tab halts the sweep
    /// with its Save/Discard/Cancel alert; re-invoking after resolution
    /// continues. Closing the last tab collapses the pane (the model rule),
    /// which is also the shortcut-free keyboard path.
    func closeActivePane() {
        guard workspace.hasSplits else { return }
        let group = workspace.model.activeGroup
        for tab in group.tabs.reversed() {
            requestCloseTab(tab.id)
            // A surviving tab means the standard close funnel either staged a
            // recovery prompt or rejected the close because its writer owns
            // native I/O. Stop the pane sweep without bypassing that owner.
            if workspace.model.tab(tab.id) != nil { return }
            if workspace.model.group(group.id) == nil { return }
        }
    }

    private func announcePaneFocus(_ groupID: GroupID, prefix: String = "") {
        guard let group = workspace.model.group(groupID),
            let ordinal = workspace.model.ordinal(of: groupID)
        else { return }
        let total = workspace.model.groupsInOrder.count
        let title = group.activeTab.map { filename(of: workspace.tabPath($0)) } ?? "empty"
        postAccessibilityAnnouncement(
            Self.editorPaneAnnouncement(ordinal: ordinal, total: total, title: title, prefix: prefix),
            priority: .medium)
    }

    // MARK: - Focus-routing announcement strings (U4-4, #473) — pure & testable
    //
    // Verbatim per u4_spec §U4-4. Factored out as pure builders so the
    // announcement tests assert the exact string a VoiceOver user hears
    // (the free `postAccessibilityAnnouncement` has no test spy — the string
    // is the contract). The "Editor pane N of M, <title>." form is REUSED
    // from U1-3 unchanged.

    /// "Editor pane N of M, <title>." (U1-3 format, reused). `prefix` carries
    /// the "Split. " lead on a fresh split; empty for a plain focus move.
    static func editorPaneAnnouncement(
        ordinal: Int, total: Int, title: String, prefix: String = ""
    ) -> String {
        "\(prefix)Editor pane \(ordinal) of \(total), \(title)."
    }

    /// "<leaf title> panel." — spoken when ⌘⌥→ enters the leaf region.
    /// Matches the leaf-switch phrasing (`RightPaneView.activate`) so entering
    /// the leaf and switching leaves read identically.
    static func leafRegionAnnouncement(_ leaf: Leaf) -> String {
        "\(leaf.title) panel."
    }

    /// "Files." — spoken when ⌘⌥← enters the file-tree region.
    static let filesRegionAnnouncement = "Files."

    private func announceActiveTab(prefix: String) {
        guard let tab = workspace.activeTab else { return }
        let group = workspace.model.activeGroup
        let index = (group.tabs.firstIndex { $0.id == tab.id }).map { $0 + 1 } ?? 0
        postAccessibilityAnnouncement(
            "\(prefix) \(filename(of: workspace.tabPath(tab))), tab \(index) of \(group.tabs.count).",
            priority: .medium)
    }

    /// UTF-8 text of the currently-selected note. Nil while no note
    /// is selected or while loading is in flight. Writable so the
    /// editor's two-way `Binding<String>` can update the buffer
    /// directly via `updateEditorText(_:)`.
    @Published var currentNoteText: String?
    /// The last-saved (or freshly-loaded) version of the current
    /// note. `hasUnsavedChanges` is derived from
    /// `currentNoteText != savedBaselineText`. Stored separately so
    /// the editor can compare without losing the live buffer.
    @Published private(set) var savedBaselineText: String? {
        didSet { noteBodyBaselineRevision &+= 1 }
    }
    /// Cheap ownership stamp for detached whole-body validation. A property
    /// publication may capture String values and compare their bytes off the
    /// main actor, but it must not publish against a newer editor baseline.
    private var noteBodyBaselineRevision: UInt64 = 0
    /// blake3 hex digest of the file's content at the moment we
    /// loaded it (or last saved it). Used as
    /// `expectedContentHash` in `saveCurrentNote` so an external
    /// writer is caught via `WriteConflict`.
    @Published private(set) var currentNoteContentHash: String?
    /// Path of the note whose text+hash we last successfully loaded.
    /// Distinct from `selectedFilePath`: the latter reflects the
    /// user's UI intent (and the file-list selection), while
    /// `loadedFilePath` is what's actually in `currentNoteText`. The
    /// two diverge while a dirty save-changes prompt is open.
    @Published private(set) var loadedFilePath: String?
    /// True when the editor buffer differs from the on-disk
    /// baseline. Drives the toolbar indicator, Cmd+S enablement,
    /// and the save-or-discard prompts triggered by navigation
    /// while dirty.
    @Published private(set) var hasUnsavedChanges: Bool = false
    /// Populated when `saveCurrentNote` returns `WriteConflict`.
    /// Drives the "Keep mine / Reload from disk / Cancel" alert in
    /// `MainSplitView`.
    @Published var currentSaveConflict: SaveConflict?
    /// Set when the user requests navigation (close-vault, switch
    /// file) while `hasUnsavedChanges == true`. Drives the
    /// "Save changes?" prompt. Nil otherwise.
    @Published var pendingNavigation: PendingNavigation?
    private(set) var pendingNavigationSaveTask: Task<Void, Never>?
    private var pendingNavigationSaveGeneration: UInt64 = 0

    private func cancelPendingNavigationSave() {
        pendingNavigationSaveGeneration &+= 1
        pendingNavigationSaveTask?.cancel()
        pendingNavigationSaveTask = nil
    }

    private func ownsPendingNavigationSave(
        _ generation: UInt64,
        session: VaultSession,
        pending: PendingNavigation,
        noteOwner: NoteAuthoringOwner
    ) -> Bool {
        pendingNavigationSaveGeneration == generation
            && !Task.isCancelled
            && currentSession === session
            && pendingNavigation == pending
            && ownsNoteAuthoring(noteOwner)
    }
    /// Surfaced when `saveCurrentNote` fails with anything other
    /// than `WriteConflict` (which goes through `currentSaveConflict`
    /// instead). Independent of `noteLoadError` so a load alert
    /// doesn't shadow a save alert.
    @Published var saveError: String?
    /// True while a save is in flight. Disables Cmd+S to keep the
    /// user from queuing overlapping saves.
    @Published private(set) var isSaving: Bool = false
    /// Handle on the in-flight save task. Exposed (internal) so
    /// tests can `await state.saveTask?.value`.
    private(set) var saveTask: Task<Void, Never>?
    /// Owner generation for the native save + every post-write publication.
    /// Cancellation alone cannot stop an already-dispatched detached FFI call;
    /// the generation makes every stale continuation inert in a replacement
    /// vault or newer save lifecycle.
    private var saveGeneration: UInt64 = 0

    private func beginSaveOwnership() -> UInt64 {
        saveGeneration &+= 1
        isSaving = true
        return saveGeneration
    }

    private func ownsSave(_ generation: UInt64, session: VaultSession) -> Bool {
        saveGeneration == generation && currentSession === session
    }

    private func finishSaveOwnership(_ generation: UInt64) {
        guard saveGeneration == generation else { return }
        isSaving = false
    }

    private func cancelSaveOwnership() {
        saveGeneration &+= 1
        saveTask?.cancel()
        saveTask = nil
        isSaving = false
    }
    /// Parsed Markdown headings of the currently-selected note, in
    /// document order. Empty while no note is selected (or when the
    /// note has no `#` headings).
    @Published private(set) var currentNoteHeadings: [Heading] = []
    /// True while the selected note's content is being read from disk.
    @Published private(set) var isLoadingNote: Bool = false
    /// Surfaced when reading the selected note fails. Independent of
    /// `lastError` (open path) and `scanError` (indexing path) so the
    /// UI alerts don't cross-fire.
    @Published var noteLoadError: String?

    /// Last outcome from `openLink` / `openBacklink`. Exposed for
    /// tests so they can verify activation routing without observing
    /// AppKit side effects (NSWorkspace open, accessibility
    /// announcements). UI doesn't read this.
    private(set) var lastActivatedLinkOutcome: LinkActivationOutcome?

    /// Last line scrolled to via `openSearchResult`. Same role as
    /// `lastActivatedLinkOutcome` — verifiable in tests without
    /// observing AppKit side effects.
    private(set) var lastActivatedSearchResultLine: Int?
    private(set) var lastActivatedSearchResultPath: String?

    /// Frontmatter properties of the currently-selected note, in
    /// document order. Empty while no note is selected, while the
    /// fetch is still in flight, or when the note has no frontmatter.
    /// Loaded by `loadCurrentLinks(path:)` (which already runs a
    /// `get_file_metadata` under the SQLite mutex) so we don't pay
    /// for two trips through the lock per selection.
    @Published private(set) var currentNoteProperties: [Property] = []

    /// Conflict from `setProperty` / `deleteProperty`. Drives the
    /// "Property edit blocked" alert in `MainSplitView`. Modeled on
    /// `currentSaveConflict` but scoped to a single key edit rather
    /// than a whole-file save so the resolve actions can re-issue
    /// the original property edit verbatim.
    @Published var currentPropertyEditConflict: PropertyEditConflict?

    /// Surfaced when `setProperty` / `deleteProperty` fails with
    /// something other than `WriteConflict` — invalid value, malformed
    /// frontmatter, etc. Separate from `saveError` so a property
    /// failure can't shadow an editor save alert and vice versa.
    @Published var propertyEditError: String?

    /// True while a property set / delete / rename is in flight.
    /// Used by the row editors + sheets to disable commit buttons.
    @Published private(set) var isEditingProperty: Bool = false

    /// Handle on the in-flight property edit task. Exposed (internal)
    /// so tests can `await state.propertyEditTask?.value`.
    private(set) var propertyEditTask: Task<Void, Never>?
    private var propertyEditGeneration: UInt64 = 0
    /// Vault-relative note path owned by the current property-edit generation.
    /// Navigation may move that note off screen after native success, so
    /// `loadedFilePath` is not sufficient to protect its final tab while
    /// authoritative publication is still pending.
    private var propertyEditOwnerPath: String?
    /// The exact property-edit generation whose native write has committed.
    /// Same-vault navigation may resume in this post-write publication phase:
    /// any verification failure is retained in the path-owned recovery
    /// registry. Before native success, navigation stays blocked because a
    /// rejected Delete/Add may have no independent draft to preserve.
    private var propertyEditNativeWriteSucceededGeneration: UInt64?

    private func beginPropertyEditOwnership(path: String) -> UInt64 {
        propertyEditGeneration &+= 1
        propertyEditNativeWriteSucceededGeneration = nil
        propertyEditOwnerPath = path
        isEditingProperty = true
        return propertyEditGeneration
    }

    private func ownsPropertyEdit(
        _ generation: UInt64,
        session: VaultSession
    ) -> Bool {
        propertyEditGeneration == generation && currentSession === session
    }

    private func finishPropertyEditOwnership(_ generation: UInt64) {
        guard propertyEditGeneration == generation else { return }
        propertyEditNativeWriteSucceededGeneration = nil
        propertyEditOwnerPath = nil
        isEditingProperty = false
    }

    private func cancelPropertyEditOwnership() {
        propertyEditGeneration &+= 1
        propertyEditNativeWriteSucceededGeneration = nil
        propertyEditOwnerPath = nil
        propertyEditTask?.cancel()
        propertyEditTask = nil
        isEditingProperty = false
    }

    /// Navigation is unsafe only until the current generation has a committed
    /// native write. Writers, discard, close, and vault replacement continue
    /// to use the stronger full-duration `isEditingProperty` gate.
    var propertyEditNavigationDisabledReason: String? {
        guard isEditingProperty,
            propertyEditNativeWriteSucceededGeneration != propertyEditGeneration
        else { return nil }
        return Self.propertyEditInProgressReason
    }

    /// Closing a duplicate is safe because the exact path remains mounted.
    /// The final owner must survive the full property-edit lifetime, including
    /// the post-native-write interval in which same-vault navigation is safe.
    private func propertyEditBlocksFinalTabClose(
        path: String,
        excluding tabID: TabID
    ) -> Bool {
        isEditingProperty
            && BaseExactIdentity.matches(propertyEditOwnerPath, path)
            && !hasOtherMarkdownTab(for: path, excluding: tabID)
    }

    /// True when the Add-Property sheet is presented. Driven by
    /// `PropertiesPanel`'s header button.
    @Published var isAddPropertySheetOpen: Bool = false
    /// Stable owner for a mounted Add Property sheet. `loadedFilePath` can
    /// become nil if a Check Again proves the note absent; retaining the owner
    /// keeps the sheet read-only and prevents its draft from targeting a later
    /// note that happens to become active.
    @Published private(set) var addPropertySheetOwnerPath: String?
    private(set) var addPropertySheetOwner: NoteAuthoringOwner?

    /// True when the Bulk-Rename sheet is presented. Driven by
    /// `PropertiesPanel`'s header button + Cmd+Shift+R shortcut.
    @Published var isBulkRenameSheetOpen: Bool = false

    /// True when the command palette is presented (Milestone Q
    /// #313). Opened by `⌘⇧P` from the `SlateMacApp` menu, routed
    /// through `requestCommandPalette()` which only flips this when a
    /// vault is open (the menu item stays enabled on the welcome screen
    /// so the chord gives feedback instead of being a silent no-op).
    /// Closed by `Esc` (intercepted by the palette's keyDown monitor)
    /// or the cancel-action button. The palette registry, fuzzy filter,
    /// sections, and recents arrive in #314–#316.
    ///
    /// Reset to `false` by `closeVault()` so a vault close with
    /// the palette open doesn't leave the bool stuck (and re-
    /// trigger the sheet on the next vault open).
    @Published var isCommandPaletteOpen: Bool = false

    /// Persistent validation/native-save feedback for the active builder. It
    /// stays visible beside the Base path until the user edits that path,
    /// retries, succeeds, or starts a different builder flow.
    @Published var baseQueryBuilderSaveError: String?

    /// Active Bases query-builder draft (Milestone N4-1, #707).
    /// Non-nil presents `BaseQueryBuilderSheet`; the draft is in-memory
    /// only until N4-2 adds preview/save.
    @Published var activeBaseQueryBuilder: BaseQueryBuilderModel? {
        didSet {
            if oldValue !== activeBaseQueryBuilder {
                baseQueryBuilderSaveError = nil
            }
            guard let previous = oldValue else { return }
            if let current = activeBaseQueryBuilder, previous === current { return }
            baseQueryBuilderPreviewGeneration += 1
            baseQueryBuilderPreviewTask?.cancel()
            baseQueryBuilderPreviewTask = nil
            baseQueryBuilderPreviewCancelToken?.cancel()
            baseQueryBuilderPreviewCancelToken = nil
        }
    }
    var baseQueryBuilderPreviewTask: Task<Void, Never>?
    var baseQueryBuilderPreviewCancelToken: CancelToken?
    /// Monotonic freshness identity for builder preview publication. Every
    /// schedule and builder/vault teardown invalidates all earlier work.
    var baseQueryBuilderPreviewGeneration = 0
    /// N4-02 deterministic execution seam. Always nil in production; tests
    /// record native-call executor context and can park a real opened handle.
    var baseQueryBuilderPreviewExecutionObserver:
        (@Sendable (BaseQueryBuilderPreviewExecutionEvent) async -> Void)?

    /// Drives the quick switcher sheet (U1-5 follow-up #495). ⌘O opens
    /// it (via `openQuickSwitcher()`, vault-gated; chord moved ⌘T→⌘O by
    /// #863); Esc / opening a file closes it. Reset in `closeVault()`
    /// for the same stuck-bool reason as `isCommandPaletteOpen` —
    /// enforced by `CloseVaultSheetParityTests`.
    @Published var isQuickSwitcherOpen: Bool = false

    /// Latest `RenameReport` from `previewPropertyRename` (dry-run)
    /// or `applyPropertyRename` (applied). The bulk-rename sheet
    /// renders this in its accessible data grid.
    @Published private(set) var pendingRenameReport: RenameReport?

    /// True while a rename preview / apply call is in flight.
    @Published private(set) var isRenameInFlight: Bool = false

    /// Surfaced when `previewPropertyRename` / `applyPropertyRename`
    /// fails outright (not the per-file `RenameFailed` rows — those
    /// land in `pendingRenameReport.failed`).
    @Published var renameError: String?

    /// Handle on the in-flight rename task. Exposed for tests + so
    /// the sheet's Esc handler can cancel via the token.
    private(set) var renameTask: Task<Void, Never>?

    /// Cancellation token for the in-flight rename. Recreated per
    /// call so a stale `cancel()` from a previous sheet open doesn't
    /// kill a fresh request.
    private var renameCancelToken: CancelToken?

    /// Deterministic race-test seam. Always nil in production. Apply awaits
    /// this after its synchronous admission but before the second admission
    /// immediately adjacent to the native vault-wide writer.
    var renameApplySecondAdmissionGate: (() async -> Void)?
    /// Deterministic test seam after the native apply has committed but before
    /// open-note publication verifies the returned content hashes. Always nil
    /// in production.
    var renamePostWritePublishGate: (() async -> Void)?
    /// Companion deterministic seam: tests can install an outcome-unknown
    /// ledger entry in the exact gate-to-native window without starting a
    /// structural operation that the stronger shared ownership must reject.
    /// Always nil in production.
    var renameApplySecondAdmissionUnknownItemsForTesting:
        (() -> [StructuralBatchItem])?

    /// Inbound links to the currently-selected note. Updated whenever
    /// `selectedFilePath` changes. Empty while no note is selected or
    /// while the query is still in flight.
    @Published private(set) var currentBacklinks: [Backlink] = []
    /// Outgoing links from the currently-selected note — resolved,
    /// unresolved, and external in document order. Same lifecycle as
    /// `currentBacklinks`.
    @Published private(set) var currentOutgoingLinks: [OutgoingLink] = []
    /// Which note `currentOutgoingLinks` belongs to (Codex round 2).
    /// The array is intentionally RETAINED across note transitions
    /// (#90 panel anti-flicker), so the reading surface needs this
    /// ownership marker to refuse classifying/activating against a
    /// previous note's records mid-transition. Stamped only by the
    /// query landing (both arms), cleared with the array.
    @Published private(set) var currentOutgoingLinksPath: String?
    /// True while a backlinks/outgoing fetch is in flight. The panels
    /// use this to decide whether to show a `ProgressView`.
    @Published private(set) var isLoadingLinks: Bool = false
    /// Surfaced when the link queries fail (rare — would mean SQLite
    /// itself errored). Independent of `noteLoadError` so the panels'
    /// alert state doesn't cross-fire with the content pane's.
    @Published var linksLoadError: String?

    // MARK: Embeds (#187 — Milestone J UI)

    /// Resolved `EmbedResolution` for each `![[…]]` reference in the
    /// currently-loaded note, keyed by the raw target string
    /// (including any `#heading` / `^block` suffix). Populated by
    /// `loadCurrentNoteEmbedResolutions(path:)` after a selection
    /// change (chained on the back of `linksLoadTask`).
    ///
    /// Refresh shape: the cache is cleared on note-to-note
    /// transitions and re-populated when the next chained load
    /// resolves — same lifecycle as `currentBacklinks` /
    /// `currentOutgoingLinks` (and like them, NOT refreshed inline
    /// post-save; a save triggers a selection re-resolve via the
    /// scanner). Audit #205 corrected an earlier doc claim of
    /// "refreshed after a save" that didn't reflect the code path.
    ///
    /// Empty while no note is selected, while the resolutions are
    /// loading, or when the note has no embeds.
    @Published private(set) var currentNoteEmbedResolutions: [String: EmbedResolution] = [:]
    /// True while the embed-resolution batch is in flight.
    @Published private(set) var isLoadingEmbeds: Bool = false
    /// Surfaced when one of the per-embed resolves throws. Per-embed
    /// failures land in the resolution itself as
    /// `EmbedResolution::Unresolved` — this string only fires when
    /// the whole batch can't run (e.g. SQLite mutex held by the
    /// scanner errored). Independent of `linksLoadError`.
    @Published var embedsLoadError: String?
    /// Handle on the in-flight embed-resolution task so tests can
    /// `await state.embedsLoadTask?.value` for a settled state.
    private(set) var embedsLoadTask: Task<Void, Never>?

    /// Discriminated state for the editor's Cmd+E embed-preview
    /// popover. The editor's keyDown handler computes the embed
    /// at cursor and calls `requestEmbedPreview(target:)`; the
    /// popover dismisses via `dismissEmbedPreview()`. Nil when
    /// no popover is active.
    @Published var pendingEmbedPreview: EmbedPreview?

    // MARK: Content pipelines (#223 — Milestone K)

    /// Math blocks parsed + rendered (LaTeX → MathML → MathCAT
    /// speech + braille) for the currently-loaded note. Loaded by
    /// `loadCurrentNoteMathBlocks(path:)` after a selection change,
    /// chained in parallel off `linksLoadTask` alongside code +
    /// diagram. Cleared on selection change.
    @Published private(set) var currentNoteMathBlocks: [MathBlock] = []
    @Published private(set) var isLoadingMathBlocks: Bool = false
    @Published var mathBlocksLoadError: String?
    private(set) var mathBlocksLoadTask: Task<Void, Never>?

    /// Code blocks parsed + highlighted (tree-sitter) for the
    /// currently-loaded note. Same lifecycle as `currentNoteMathBlocks`.
    @Published private(set) var currentNoteCodeBlocks: [CodeBlock] = []
    @Published private(set) var isLoadingCodeBlocks: Bool = false
    @Published var codeBlocksLoadError: String?
    private(set) var codeBlocksLoadTask: Task<Void, Never>?

    /// Mermaid diagram blocks parsed + rendered (SVG + structured
    /// description) for the currently-loaded note. Same lifecycle
    /// as `currentNoteMathBlocks`.
    @Published private(set) var currentNoteDiagramBlocks: [DiagramBlock] = []
    @Published private(set) var isLoadingDiagramBlocks: Bool = false
    @Published var diagramBlocksLoadError: String?
    private(set) var diagramBlocksLoadTask: Task<Void, Never>?

    /// Citations rendered for the currently-loaded note. Each entry
    /// is a `RenderedCitation` carrying both `visual_text` (sighted)
    /// and `speech_text` (AT) — the renderer (#277) built both from
    /// structured data so the AT form never spells punctuation.
    /// Same lifecycle as `currentNoteMathBlocks`: cleared on
    /// selection change, repopulated by `loadCurrentNoteCitations`.
    @Published private(set) var currentNoteCitations: [RenderedCitation] = []

    /// Parallel array of the structured `CitationReference`s the
    /// rendered list came from. The `RenderedCitation` FFI shape
    /// doesn't surface the per-site `citations` array, so any
    /// caller that needs all keys at a multi-citation site (the
    /// summary sheet's unique-source count, the rotor's positional
    /// index, etc.) reads from here instead.
    @Published private(set) var currentNoteCitationRefs: [CitationReference] = []
    @Published private(set) var isLoadingCitations: Bool = false
    @Published var citationsLoadError: String?
    private(set) var citationsLoadTask: Task<Void, Never>?

    /// The style id that `loadCurrentNoteCitations` renders against.
    /// Derived from `.slate/prefs.json`'s `default_style` (or empty
    /// if no bibliography is configured). The style-switching command
    /// in #281 mutates this; the `didSet` re-triggers a render.
    @Published var activeStyleId: String = "" {
        didSet {
            guard activeStyleId != oldValue, let path = selectedFilePath else { return }
            citationsLoadTask?.cancel()
            citationsLoadTask = Task { [weak self] in
                await self?.loadCurrentNoteCitations(path: path)
            }
        }
    }

    /// Citation the user wants to expand (row activation in
    /// `CitationsPanel`, or an inline citation click in Reading mode).
    /// A `CitationsPanel` row presents the `CitationPopover` anchored to
    /// itself (#878); Reading mode has no SwiftUI anchor for an inline
    /// glyph, so it falls back to the detached presentation in
    /// `MainSplitView` gated on `expandedCitationRowAnchored` below.
    @Published var expandedCitation: RenderedCitation? {
        didSet {
            // #878 red-team: many paths clear this EXTERNALLY (⌘J jump-to-
            // bib, note-switch `clearTransitionSensitiveCollections`, vault
            // close) without going through `CitationsPanel.dismissExpansion`,
            // which is the only site that would reset the anchor. A stale
            // `true` here would let the panel row popover AND the detached
            // fallback both present on the next Reading-mode click. Reset the
            // discriminator whenever the expansion clears so the two gates
            // stay mutually exclusive.
            if expandedCitation == nil { expandedCitationRowAnchored = false }
        }
    }

    /// Discriminates the two `expandedCitation` triggers (#878). A
    /// `CitationsPanel` row sets this `true` so it owns the anchored
    /// `.popover` and `MainSplitView`'s detached fallback stays closed;
    /// Reading mode leaves it `false` so the fallback presents (an inline
    /// text glyph has no anchor a popover can point at). Rides
    /// `expandedCitation`'s publish — the two always change together, and
    /// its `didSet` above resets this on any external clear.
    var expandedCitationRowAnchored: Bool = false

    // MARK: - Bibliography (Milestone L, #280)

    /// Full merged bibliography for the open vault. Populated by
    /// `loadBibliographyEntries` after `setBibliographySources` runs
    /// and on session open. Empty when no bibliography is configured.
    @Published private(set) var bibliographyEntries: [BibEntry] = []
    @Published private(set) var isLoadingBibliography: Bool = false
    @Published var bibliographyLoadError: String?

    /// Vault-wide unresolved citation list: `(file_path, key)` pairs
    /// whose key has no matching `bibliography_entries` row. Bound
    /// by the BibliographyPanel's Unresolved segment.
    @Published private(set) var unresolvedCitations: [UnresolvedCitation] = []

    /// Search query bound to the BibliographyPanel's search field.
    /// The panel observes this and filters the entries list — kept on
    /// AppState (not local @State) so the panel survives sidebar tab
    /// switches without losing the query.
    @Published var bibliographySearchText: String = ""

    /// Bibliography entry the user wants to expand from the
    /// BibliographyPanel (vs. the per-note `expandedCitation` set by
    /// CitationsPanel). Presents the `CitationPopover` anchored to the
    /// triggering entry row (#878) — we wrap the entry in a synthetic
    /// `RenderedCitation` so the popover renders without a separate code
    /// path. Purely BibliographyPanel-driven (no Reading-mode path), so
    /// there is no detached fallback.
    @Published var expandedBibEntry: BibEntry?

    /// Vault-relative paths of every file that cites the
    /// currently-being-inspected key (right-click → Show files citing).
    /// Empty until the user requests this; cleared on tab switch /
    /// vault close.
    @Published var filesCitingResult: [String]?

    /// Bibliography prefs in memory — the Settings panel's binding
    /// surface (#281). On vault open we read the disk copy via
    /// `loadBibliographyPrefsFromDisk`; on every mutation the
    /// caller writes back via `applyBibliographyPrefs` (which both
    /// persists to disk AND calls `setBibliographySources` so the
    /// session re-loads).
    @Published var bibliographyPrefs: BibliographyPrefs = .empty

    /// CSL styles configured in `prefs.json` — populated by
    /// `refreshAvailableCslStyles`. Bound by the Settings tab's
    /// style picker and by the View → Citation Style menu in #282.
    @Published var availableCslStyles: [CslStyleInfo] = []

    /// Settings UI surface — when non-nil, an inline error is shown
    /// (e.g. "library.bib not found").
    @Published var bibliographySettingsError: String?

    /// Device-local Files-sidebar presentation. The lazy tree consumes one
    /// immutable snapshot per render; rows never scan `files` or observe the
    /// rest of AppState. Every Settings mutation persists immediately.
    @Published var sidebarPreferences: SidebarPreferences = SidebarPreferences() {
        didSet {
            guard oldValue != sidebarPreferences else { return }
            preferencesStore.saveSidebarPreferences(sidebarPreferences)
        }
    }

    /// AppState owns the current vault's generic sidebar preference store even
    /// though FL-02 intentionally authors no vault-local fields yet. A typed
    /// notice is published for the inline sidebar banner; unsafe input is kept
    /// read-only by the store and therefore can never be silently replaced.
    private(set) var sidebarVaultPrefsStore: SidebarVaultPrefsStore?
    /// Stable identity (device, inode) of the vault root captured when the
    /// store was installed. Pathname equality alone cannot gate queued
    /// writes: a same-path replacement vault must never receive them
    /// (round-18 finding 1).
    private(set) var sidebarVaultRootIdentity: SidebarVaultRootIdentity?
    /// Test seam: builds the per-vault store (e.g. with an injected failing
    /// directory synchronizer) instead of the production initializer.
    var sidebarVaultPrefsStoreFactoryForTesting: ((URL) -> SidebarVaultPrefsStore)?
    @Published private(set) var sidebarVaultPrefsNotice: SidebarVaultPrefsNotice?
    @Published private(set) var isRetryingSidebarVaultPreferences = false
    private var sidebarVaultPrefsRetryTask: Task<Void, Never>?
    private var sidebarVaultPrefsRetryGeneration = 0

    // MARK: - Sidebar organization (FL-06, #658/#659)

    /// One published value carries the vault's authored organization: the
    /// sort/grouping preferences (vault default + per-folder overrides) and
    /// per-folder pins. The tree derives every level order from this.
    struct SidebarOrganizationState: Equatable {
        var prefs = SidebarOrganizationPrefs()
        var pins = SidebarPins()
    }

    @Published private(set) var sidebarOrganization = SidebarOrganizationState()
    private var sidebarPinPruneLedger = SidebarPinPruneLedger()
    /// Serializes `.slate/sidebar.json` writes: each persist awaits its
    /// predecessor, so two quick commands cannot interleave read-modify-write
    /// cycles even though each cycle also holds the cross-process lock.
    private var sidebarOrganizationPersistChain: Task<Void, Never>?
    /// Writer chains that survive vault teardown (round-16), keyed by the
    /// vault root's PHYSICAL identity — device and inode, not URL spelling
    /// — so every alias of one vault (symlink, differently spelled path)
    /// shares one ordered chain (round-24). A persist detached before a
    /// close/reopen still holds the vault's serialization slot, so the
    /// reopened session's writers — and its post-open refresh — queue
    /// behind it instead of interleaving.
    @MainActor private static var sidebarStoreWriterChains:
        [SidebarVaultRootIdentity: Task<Void, Never>] = [:]
    /// Tail token per vault identity for chain-drain detection.
    @MainActor private static var sidebarStoreWriterChainTokens:
        [SidebarVaultRootIdentity: UUID] = [:]
    /// Structural transform IDs already committed to each vault. This ledger
    /// — not the live journal, which a same-vault reopen resets — is the
    /// at-most-once authority for a task's captured immutable backlog, so a
    /// queued rename survives close/reopen and still commits exactly once
    /// (round-20 finding 1). Cleared when a vault's chain fully drains.
    @MainActor private static var sidebarCommittedTransformIDs:
        [SidebarVaultRootIdentity: Set<UUID>] = [:]
    /// One write whose disk attempt failed AFTER its session was torn
    /// down (round-29): the user was already told the change happened,
    /// so the exact operation and its uncommitted structural backlog are
    /// retained here, keyed by physical vault identity, and the next
    /// same-vault open drains them through the normal funnel before its
    /// state settles. Conflicts and replaced-vault refusals are final
    /// and never retained.
    private struct SidebarUnflushedWrite {
        let apply: @Sendable (inout [String: Any]) throws -> Void
        let backlog: [SidebarStructuralTransform]
    }
    @MainActor private static var sidebarUnflushedWriteRetries:
        [SidebarVaultRootIdentity: [SidebarUnflushedWrite]] = [:]
    /// Round-32: capacity gates NEW acknowledgements up front (mutate
    /// refuses before any optimistic reflect); parking never evicts an
    /// already-acknowledged intent. Var for cap-boundary tests.
    static var sidebarUnflushedWriteRetriesCap = 64

    /// Round-32: static mirror of `isMutatingStructure` for the
    /// termination fence (didSet-maintained; production has exactly one
    /// AppState).
    @MainActor fileprivate(set) static var
        structuralMutationInFlightForTermination = false

    /// Rounds 31–32: termination fence. True while any identity's writer
    /// chain still holds queued work OR a structural operation (rename /
    /// move) is in flight — those commit on a worker and only then
    /// publish their sidebar transform, so quitting between the two
    /// would strand pins at the old path. Quit waits so an announced
    /// change can't die mid-flight with the process.
    @MainActor static var hasPendingSidebarWorkAtTermination: Bool {
        !sidebarStoreWriterChains.isEmpty
            || structuralMutationInFlightForTermination
    }

    /// Rounds 31–32: await quiescence with an unconditionally REAL
    /// five-second bound. Deadline-based polling never awaits an
    /// unbounded chain value (a writer wedged on the store's blocking
    /// flock must not turn Quit into a hang) — chains retire their own
    /// registry entries, so an empty registry IS settlement. Parked
    /// retained writes whose vault is closed are not recoverable at
    /// quit; durable cross-launch recovery is tracked in #944.
    @MainActor
    static func settleSidebarWriterChainsForTermination() async {
        let clock = ContinuousClock()
        let deadline = clock.now.advanced(by: .seconds(5))
        while clock.now < deadline, hasPendingSidebarWorkAtTermination {
            try? await Task.sleep(for: .milliseconds(50))
        }
    }

    /// Ownership generation for queued persists. Bumped on every vault
    /// teardown/switch; a queued task whose captured generation no longer
    /// matches skips its disk I/O and publishes nothing.
    private(set) var sidebarOrganizationWriteGeneration = 0
    /// Token of the most recently enqueued persist. Only the chain's tail
    /// may reconcile published state from disk: a mid-chain failure defers
    /// to the queued successors (which still apply their exact mutations)
    /// and stashes its message here for the tail to surface (round-3
    /// finding 3).
    private var sidebarOrganizationPersistTailToken: UUID?
    private var sidebarOrganizationPendingPersistFailure: String?
    /// Announcement-verification records awaiting the chain tail: container →
    /// the effective choice the optimistic announcement described. The tail
    /// verifies every record against decoded final disk truth; a later action
    /// on the same container supersedes the earlier record (round-11
    /// finding 2).
    private var sidebarOrganizationPendingAnnouncementVerifications:
        [String: SidebarOrganizationChoice] = [:]
    private(set) var sidebarOrganizationPersistTaskForTesting: Task<Void, Never>?
    /// Structural path transforms that arrived while `.slate/sidebar.json`
    /// was read-only. Retry replays them under the store lock before it
    /// republishes, so a rename made during the outage cannot orphan the
    /// file's pins/overrides (round-4 finding 2). Bounded; overflow is
    /// reported honestly instead of replaying an incomplete journal.
    private(set) var sidebarStructuralTransformJournal: [SidebarStructuralTransform] = []
    /// Test-only observability: how many committed persists replayed each
    /// structural transform (at-most-once semantics, round-9 finding 1).
    private(set) var sidebarStructuralReplayCountsForTesting: [UUID: Int] = [:]
    private var sidebarStructuralTransformJournalOverflowed = false
    /// One-shot test seam: runs on the main actor after a retry replay pass
    /// captures its journal prefix and before the pass completes, so tests
    /// can deterministically interleave a structural append (round-5
    /// finding 1's race).
    var sidebarStructuralJournalReplayInterleaveHookForTesting: (() -> Void)?
    /// Round-26: true while structural transforms remain unsaved after a
    /// tail persist failure that left the file READABLE (no typed notice) —
    /// the sidebar shows the journal-recovery banner whose Retry drains
    /// them. Cleared when the journal commits, on Retry publish, and on
    /// vault teardown.
    @Published private(set) var sidebarOrganizationJournalRecoveryPending = false
    private static let sidebarStructuralTransformJournalCap = 1000

    private func resetSidebarOrganizationState() {
        sidebarOrganizationWriteGeneration &+= 1
        sidebarOrganizationPersistChain = nil
        sidebarOrganizationPersistTailToken = nil
        sidebarOrganizationPendingPersistFailure = nil
        sidebarOrganizationPendingAnnouncementVerifications = [:]
        sidebarOrganizationPersistTaskForTesting = nil
        sidebarStructuralTransformJournal = []
        sidebarStructuralTransformJournalOverflowed = false
        sidebarPinPruneInFlight = []
        sidebarPinPruneLedger.reset()
        if sidebarOrganizationJournalRecoveryPending {
            sidebarOrganizationJournalRecoveryPending = false
        }
        if sidebarOrganization != SidebarOrganizationState() {
            sidebarOrganization = SidebarOrganizationState()
        }
    }

    /// Publish disk truth (state + any newly detected unsafe-file notice)
    /// and announce one persist failure. Runs only at the chain tail with
    /// ownership already validated by the caller.
    private func reconcileSidebarOrganizationFromDisk(
        _ recovered: SidebarVaultPrefsReadResult, failure: String
    ) {
        // Round-12 finding 3: the reconcile supersedes every optimistic
        // announcement still awaiting verification — a later unrelated
        // commit must not replay a stale sort correction.
        sidebarOrganizationPendingAnnouncementVerifications = [:]
        var notice = recovered.notice
        if notice == nil,
            !SidebarOrganizationSchema.knownSectionShapesAreValid(
                root: recovered.root)
        {
            notice = .malformed
        }
        let organization: SidebarOrganizationState
        if notice == nil {
            let decoded = SidebarOrganizationSchema.decode(root: recovered.root)
            organization = SidebarOrganizationState(
                prefs: decoded.prefs, pins: decoded.pins)
        } else {
            organization = SidebarOrganizationState()
        }
        if organization != sidebarOrganization {
            sidebarOrganization = organization
        }
        if sidebarVaultPrefsNotice != notice {
            sidebarVaultPrefsNotice = notice
        }
        // Round-26: transforms still pending after a failure with a
        // READABLE file have no notice-gated Retry — surface the dedicated
        // journal-recovery banner instead (cleared when the journal drains).
        sidebarOrganizationJournalRecoveryPending =
            notice == nil
            && (!sidebarStructuralTransformJournal.isEmpty
                || sidebarVaultRootIdentity.map({
                    Self.sidebarUnflushedWriteRetries[$0]?.isEmpty == false
                }) == true)
        lastMutationAnnouncement = failure
        announcer.post(failure, priority: .medium)
    }

    /// Round-23: the one announcement for any write or reconcile path that
    /// refuses to touch a same-path replacement vault.
    private func announceSidebarWriteDiscardedForReplacedVault() {
        let message =
            "The vault at this location changed, so a queued "
            + "sidebar settings write was discarded."
        lastMutationAnnouncement = message
        announcer.post(message, priority: .medium)
    }

    /// Availability the pure catalog cannot own: read-only preference files
    /// disable the whole organization set with the notice's reason, and the
    /// pin/override verbs reflect the target's current state so contextual
    /// surfaces show exactly the applicable direction.
    func sidebarOrganizationActionReasons(
        target: SidebarSelectionItem?
    ) -> [String: String] {
        var reasons: [String: String] = [:]
        if let notice = sidebarVaultPrefsNotice {
            let blocked =
                "Sidebar organization can't change while its settings file is "
                + "read-only. \(notice.localizedDescription)"
            for id in SlateCommandID.sidebarOrganizationCommands {
                reasons[id] = blocked
            }
            return reasons
        }

        if let target, !target.isDirectory {
            let folder = SidebarPins.folder(of: target.path)
            if sidebarOrganization.pins.isPinned(target.path, inFolder: folder) {
                reasons[SlateCommandID.sidebarPinNote] = "This note is already pinned."
            } else {
                reasons[SlateCommandID.sidebarUnpinNote] = "This note isn't pinned."
            }
        }

        if let target, target.isDirectory,
            sidebarOrganization.pins.paths(forFolder: target.path).isEmpty
        {
            reasons[SlateCommandID.sidebarUnpinAll] = "No pinned notes in this folder."
        }

        let container: String
        if let target {
            container = target.isDirectory
                ? target.path : SidebarPins.folder(of: target.path)
        } else {
            container = ""
        }
        if container.isEmpty {
            reasons[SlateCommandID.sidebarUseVaultDefaultSort] =
                "The vault default applies here."
        } else if sidebarOrganization.prefs.folderOverrides[container]?.sort == nil {
            // Availability tracks the SORT override specifically; a grouping-
            // only override leaves nothing for this command to clear.
            reasons[SlateCommandID.sidebarUseVaultDefaultSort] =
                "This folder uses the vault default."
        }

        // Grouping forces the matching date sort descending (fl3 §FL3-1.3
        // "mixed sort+group combinations are not offered"): while the target
        // container groups by date, only the two newest-first date sorts can
        // take effect, so the rest disable with one deterministic reason —
        // a menu choice must never write a hidden, inert preference
        // (red-team finding 2).
        let effective = sidebarOrganization.prefs.effectiveChoice(
            forFolder: container)
        if effective.grouping == .dateBuckets {
            let inert = Self.sidebarGroupedSortInertReason
            reasons[SlateCommandID.sidebarSortNameAsc] = inert
            reasons[SlateCommandID.sidebarSortNameDesc] = inert
            reasons[SlateCommandID.sidebarSortCreatedAsc] = inert
            reasons[SlateCommandID.sidebarSortModifiedAsc] = inert
        }
        return reasons
    }

    /// The published selection's organization container: a selected folder is
    /// its own container, a selected file targets its parent, anything else
    /// targets the vault default. Drives the menu-bar/toolbar radio state.
    var sidebarOrganizationMenuTargetChoice: SidebarOrganizationChoice {
        let target = sidebarSelectionSnapshot.flatMap { snapshot in
            snapshot.items.count == 1 ? snapshot.items.first : nil
        }
        let container: String
        if let target {
            container = target.isDirectory
                ? target.path : SidebarPins.folder(of: target.path)
        } else {
            container = ""
        }
        return sidebarOrganization.prefs
            .effectiveChoice(forFolder: container).normalized
    }

    /// The one FL-06 mutation funnel: reflect the change into the published
    /// state synchronously (the tree re-sorts immediately), announce it, and
    /// persist through the store's locked read-modify-write on a serialized
    /// background chain. A failed write reconciles the published state — and
    /// any newly detected unsafe-file notice — from disk truth and reports
    /// honestly; it never leaves silent divergence.
    ///
    /// Ownership: every queued persist carries the write generation captured
    /// at enqueue. Vault teardown bumps the generation, so a stale task
    /// revalidates on the main actor and skips its disk I/O entirely — a
    /// write queued under an old session can neither touch the file after
    /// reopen nor roll the UI back (red-team finding 1).
    /// Thrown from inside the locked update when the file's known sections
    /// no longer use shapes this build understands — a cooperating writer
    /// may have replaced them after our open-time validation, and the write
    /// must fail instead of clobbering that data (round-6 finding 2).
    private struct SidebarOrganizationShapeError: LocalizedError {
        var errorDescription: String? {
            ".slate/sidebar.json uses an unrecognized layout for a sidebar "
                + "section, so it was left untouched."
        }
    }

    /// Thrown from inside the locked update when the file's CURRENT state
    /// makes the requested change semantically inert (round-7 finding 2):
    /// the write is refused, published state reconciles to the merged disk
    /// truth, and the reason is announced as-is (it is a user-facing rule,
    /// not a save failure).
    /// The vault root no longer resolves to the identity this write was
    /// enqueued for; the write is dropped without touching the newcomer.
    private struct SidebarOrganizationVaultReplacedError: LocalizedError {
        var errorDescription: String? {
            "The vault at this location changed, so a queued sidebar "
                + "settings write was discarded."
        }
    }

    private struct SidebarOrganizationConflictError: LocalizedError {
        let reason: String
        var errorDescription: String? { reason }
    }

    static let sidebarPinCapacityReason =
        "Pinned-note limit reached (\(SidebarOrganizationSchema.maxPinsPerFolder) "
        + "per folder, \(SidebarOrganizationSchema.maxTotalPins) per vault). "
        + "Unpin something to pin more."

    static let sidebarGroupedSortInertReason =
        "Date grouping sorts newest first. Turn off Group by Date to use this order."

    private func mutateSidebarOrganization(
        announce announcement: String?,
        apply: @escaping @Sendable (inout [String: Any]) throws -> Void,
        reflect: (inout SidebarOrganizationState) -> Void,
        acknowledge: (() -> Void)? = nil,
        onSettled: (() -> Void)? = nil,
        isBacklogDrain: Bool = false,
        isRetainedDrain: Bool = false,
        prepare: (() -> Void)? = nil,
        verifyAnnouncement: (container: String, announced: SidebarOrganizationChoice)? = nil
    ) throws {
        if let notice = sidebarVaultPrefsNotice {
            throw sidebarActionFailure(
                "Sidebar organization can't change while its settings file is "
                    + "read-only. \(notice.localizedDescription)")
        }
        guard let store = sidebarVaultPrefsStore else {
            throw sidebarActionFailure("Open a vault to use Sidebar actions.")
        }
        // Round-24: chains, tokens, and the committed ledger are keyed by the
        // admitted PHYSICAL identity (device, inode) — every path spelling of
        // one vault shares one ordered chain. Without a captured identity no
        // write can be ordered or disk-verified: refuse up front, before any
        // optimistic reflect or announcement.
        guard let enqueueIdentity = sidebarVaultRootIdentity else {
            throw sidebarActionFailure(
                "Sidebar settings can't change right now — this vault's "
                    + "on-disk location could not be verified when it opened.")
        }
        // Round-32, refined round-33: capacity gates NEW user-acknowledged
        // work only — every dispatch command announces, and it is that
        // acknowledgement the cap must not let us break. Internal persists
        // (journal drains for structural transforms that ALREADY committed
        // on the filesystem, retained-drain runs, prune maintenance) carry
        // no announcement and must never be refused: refusing a committed
        // rename's drain would strand its pins at the old path for the
        // stale prune. Internal work that later fails simply parks
        // (append-only, past the cap if need be).
        if announcement != nil,
            let parked = Self.sidebarUnflushedWriteRetries[enqueueIdentity],
            parked.count >= Self.sidebarUnflushedWriteRetriesCap
        {
            throw sidebarActionFailure(
                "Sidebar changes can't be saved right now — earlier changes "
                    + "are still waiting to retry. Use Retry in the sidebar, "
                    + "then try again.")
        }

        var next = sidebarOrganization
        reflect(&next)
        if next != sidebarOrganization {
            sidebarOrganization = next
        }
        if let announcement {
            lastMutationAnnouncement = announcement
            announcer.post(announcement, priority: .medium)
        }

        let previous = Self.sidebarStoreWriterChains[enqueueIdentity]
        let session = currentSession
        let generation = sidebarOrganizationWriteGeneration
        let vaultRootURL = store.vaultRoot
        let token = UUID()
        sidebarOrganizationPersistTailToken = token
        if let verifyAnnouncement {
            sidebarOrganizationPendingAnnouncementVerifications[
                verifyAnnouncement.container] = verifyAnnouncement.announced
        }
        // Round-8 finding 1: EVERY persist first drains the pending
        // structural backlog under the lock, so a transform stranded by an
        // earlier readable-write failure (lock/temp/fsync) commits with the
        // next write of any kind instead of waiting for a notice-gated Retry.
        // The snapshot is re-filtered against the LIVE journal after the
        // predecessor completes (round-9 finding 1) — see below.
        let backlog = sidebarStructuralTransformJournal
        let task = Task { [weak self] in
            await previous?.value
            // Round-1, refined rounds 17–21: a queued exact-op write is the
            // user's committed intent and always finishes against its
            // CAPTURED store — including after the vault closed without
            // reopening. Safety lives in the identity checks bound to the
            // actual disk: the fresh pre-stat below and the store's own
            // descriptor-bound fstat refuse a replaced or deleted vault.
            // Publishes, acknowledgements, and announcements additionally
            // require the original generation/session ownership.
            // The chain-registry entry belongs to this task even when its
            // AppState is gone — retire it unconditionally, or the quit
            // fence would wait on a stale completed task forever
            // (round-31).
            defer {
                if Self.sidebarStoreWriterChainTokens[enqueueIdentity]
                    == token
                {
                    Self.sidebarStoreWriterChains[enqueueIdentity] = nil
                    Self.sidebarStoreWriterChainTokens[enqueueIdentity] = nil
                    Self.sidebarCommittedTransformIDs[enqueueIdentity] = nil
                }
            }
            guard let self else { return }
            // Round-9 finding 1 (at-most-once), rebased on the per-file
            // committed ledger (round-20 finding 1): the captured backlog is
            // immutable, and only ids NOT yet committed to this file replay.
            // Unlike the live journal — which a same-vault reopen resets —
            // the ledger survives, so a queued structural rename lands
            // exactly once across close/reopen. (An applied-but-unsynced
            // pass legitimately re-replays; every transform is a no-op
            // against its own committed effect.)
            let committed =
                Self.sidebarCommittedTransformIDs[enqueueIdentity] ?? []
            let effectiveBacklog = backlog.filter {
                !committed.contains($0.id)
            }
            let effectiveBacklogIDs = Set(effectiveBacklog.map(\.id))
            // Round-30 (review #1): an earlier same-identity write is
            // parked for ordered replay — any non-drain write reaching its
            // disk attempt now would commit AHEAD of it and invert the
            // user's order. Park this write behind the registry instead;
            // the drain settles everything in enqueue order. A live
            // session immediately schedules that drain.
            if !isRetainedDrain,
                Self.sidebarUnflushedWriteRetries[enqueueIdentity]?.isEmpty
                    == false
            {
                Self.sidebarUnflushedWriteRetries[enqueueIdentity, default: []]
                    .append(
                        SidebarUnflushedWrite(
                            apply: apply, backlog: effectiveBacklog))
                let ownedNow =
                    self.sidebarOrganizationWriteGeneration == generation
                    && self.currentSession === session
                if ownedNow {
                    self.scheduleSidebarRetainedWriteDrain()
                }
                onSettled?()
                return
            }
            prepare?()
            enum PersistOutcome {
                case success([String: Any])
                /// The atomic rename landed (content committed) but the
                /// directory fsync failed — treat as success plus a
                /// durability warning (round-10 finding 1).
                case replacedButUnsynced([String: Any], reason: String)
                case failure(Error)
            }
            let outcome: PersistOutcome =
                await Task.detached(priority: .utility) {
                    // Fresh on-disk revalidation immediately before the
                    // locked write: the path must still resolve to the SAME
                    // vault root the write was enqueued for (round-18
                    // finding 1 — a same-path replacement never receives
                    // queued writes).
                    guard
                        AppState.vaultRootIdentity(of: vaultRootURL)
                            == enqueueIdentity
                    else {
                        return .failure(
                            SidebarOrganizationVaultReplacedError())
                    }
                    var finalRoot: [String: Any] = [:]
                    do {
                        try store.update(
                            expectedRootIdentity: enqueueIdentity
                        ) { root in
                            // Revalidate under the lock: shapes may have
                            // changed since open-time validation (round-6
                            // finding 2).
                            guard
                                SidebarOrganizationSchema
                                    .knownSectionShapesAreValid(root: root)
                            else {
                                throw SidebarOrganizationShapeError()
                            }
                            for transform in effectiveBacklog {
                                transform.applyRaw(to: &root)
                            }
                            try apply(&root)
                            // Round-35: the write must never produce a file
                            // its own admission would reject — validate the
                            // RESULT before serialization. A capacity-
                            // crossing operation is refused as a typed
                            // user-facing rule, leaving the valid file
                            // unchanged. (Backlog transforms rename or
                            // delete; they cannot grow counts, and real
                            // filesystem paths sit far under the length
                            // ceiling — a post-state violation is the
                            // requested mutation's doing.)
                            guard
                                SidebarOrganizationSchema
                                    .knownSectionShapesAreValid(root: root)
                            else {
                                throw SidebarOrganizationConflictError(
                                    reason: AppState
                                        .sidebarPinCapacityReason)
                            }
                            finalRoot = root
                        }
                        return .success(finalRoot)
                    } catch SidebarVaultPrefsStoreError.replacedButUnsynced(
                        let reason)
                    {
                        // The mutation ran and the atomic rename landed:
                        // `finalRoot` holds the file's committed content.
                        return .replacedButUnsynced(finalRoot, reason: reason)
                    } catch {
                        // Reconcile candidate: what the file actually holds.
                        return .failure(error)
                    }
                }.value
            let ownedForPublish =
                self.sidebarOrganizationWriteGeneration == generation
                && self.currentSession === session

            let isTail = self.sidebarOrganizationPersistTailToken == token

            @MainActor
            func handleCommit(_ finalRoot: [String: Any], durabilityWarning: String?) {
                if !effectiveBacklogIDs.isEmpty {
                    Self.sidebarCommittedTransformIDs[enqueueIdentity, default: []]
                        .formUnion(effectiveBacklogIDs)
                    self.sidebarStructuralTransformJournal.removeAll {
                        effectiveBacklogIDs.contains($0.id)
                    }
                    for id in effectiveBacklogIDs {
                        self.sidebarStructuralReplayCountsForTesting[id, default: 0]
                            += 1
                    }
                }
                if self.sidebarStructuralTransformJournal.isEmpty,
                    Self.sidebarUnflushedWriteRetries[enqueueIdentity]?.isEmpty
                        != false
                {
                    self.sidebarOrganizationJournalRecoveryPending = false
                }
                acknowledge?()
                if let durabilityWarning {
                    self.lastMutationAnnouncement = durabilityWarning
                    self.announcer.post(durabilityWarning, priority: .medium)
                }
                guard isTail else { return }
                // The tail publishes decoded post-write disk truth: a locked
                // read-modify-write can merge ANOTHER writer's changes, and
                // the live tree and accessibility state must see that merge,
                // not just this window's optimistic reflect (round-4
                // finding 1). Queued optimistic successors are preserved
                // because only the tail publishes.
                let decoded = SidebarOrganizationSchema.decode(root: finalRoot)
                let organization = SidebarOrganizationState(
                    prefs: decoded.prefs, pins: decoded.pins)
                if organization != self.sidebarOrganization {
                    self.sidebarOrganization = organization
                }
                // Round-10 finding 2 + round-11 finding 2: the tail verifies
                // EVERY pending record — including ones enqueued by earlier
                // non-tail writes in this chain — against final disk truth,
                // announcing each container whose merged effective choice
                // differs from what its optimistic announcement described.
                let pendingVerifications =
                    self.sidebarOrganizationPendingAnnouncementVerifications
                self.sidebarOrganizationPendingAnnouncementVerifications = [:]
                for (container, announced) in pendingVerifications {
                    let merged = organization.prefs
                        .effectiveChoice(forFolder: container).normalized
                    if merged != announced.normalized {
                        let correction = merged.sortAnnouncement
                        self.lastMutationAnnouncement = correction
                        self.announcer.post(correction, priority: .medium)
                    }
                }
                if let pending = self.sidebarOrganizationPendingPersistFailure {
                    // An earlier queued write failed mid-chain; surface that
                    // failure exactly once now that state matches the file.
                    self.sidebarOrganizationPendingPersistFailure = nil
                    self.lastMutationAnnouncement = pending
                    self.announcer.post(pending, priority: .medium)
                }
            }

            defer {
                onSettled?()
            }
            switch outcome {
            case .failure(let error):
                guard ownedForPublish else {
                    // Round-29: nobody is left to report to, and teardown
                    // already reset the optimistic state — but the change
                    // was announced when it was enqueued. Retain the exact
                    // operation for the next same-vault open instead of
                    // treating a failed write as completed. Conflicts and
                    // replaced-vault refusals are final: never retried.
                    let isFinalRefusal =
                        error is SidebarOrganizationConflictError
                        || error is SidebarOrganizationVaultReplacedError
                        || (error as? SidebarVaultPrefsStoreError)
                            .map({
                                if case .vaultReplaced = $0 { return true }
                                return false
                            }) == true
                    if !isFinalRefusal {
                        // Round-32: append-only — capacity is enforced at
                        // acknowledgement time, never by eviction here.
                        Self.sidebarUnflushedWriteRetries[
                            enqueueIdentity, default: []
                        ].append(
                            SidebarUnflushedWrite(
                                apply: apply, backlog: effectiveBacklog))
                    }
                    return
                }
                // Round-22: a vault-replaced refusal must not reconcile from
                // the NEWCOMER's file — the disk at this path is no longer
                // ours to read. Announce and keep current published state.
                if error is SidebarOrganizationVaultReplacedError
                    || (error as? SidebarVaultPrefsStoreError)
                        .map({
                            if case .vaultReplaced = $0 { return true }
                            return false
                        }) == true
                {
                    self.announceSidebarWriteDiscardedForReplacedVault()
                    return
                }
                let failure: String
                if let conflict = error as? SidebarOrganizationConflictError {
                    failure = conflict.reason
                } else {
                    failure =
                        "Sidebar organization could not be saved. "
                        + error.localizedDescription
                }
                guard isTail else {
                    // A queued successor still holds an optimistic mutation
                    // the user was told about; let the tail publish disk
                    // truth once every queued write has run, instead of
                    // rolling that successor back mid-chain (round-3
                    // finding 3).
                    self.sidebarOrganizationPendingPersistFailure = failure
                    return
                }
                // Round-23: disk truth must still BE this vault's disk.
                // The reconcile read is bound to the enqueue identity; a
                // mismatch is the replaced-vault case — keep current state
                // and announce the discard.
                let reconcileIdentity = enqueueIdentity
                let recovered = await Task.detached(priority: .utility) {
                    store.read(expectedRootIdentity: reconcileIdentity)
                }.value
                guard self.sidebarOrganizationWriteGeneration == generation,
                    self.currentSession === session
                else { return }
                self.sidebarOrganizationPendingPersistFailure = nil
                guard let recovered else {
                    self.announceSidebarWriteDiscardedForReplacedVault()
                    return
                }
                // A write can fail because the file BECAME unsafe (synced-in
                // corruption, oversize, a newer version). The reconcile
                // publishes that notice so the banner appears and the whole
                // organization set disables with its reason.
                self.reconcileSidebarOrganizationFromDisk(
                    recovered, failure: failure)
                // Round-8 finding 1: a failure that leaves the file READABLE
                // publishes no notice, so the notice-gated Retry never runs.
                // Schedule one automatic drain for the surviving backlog;
                // any later persist drains it again regardless.
                if !isBacklogDrain,
                    self.sidebarVaultPrefsNotice == nil,
                    !self.sidebarStructuralTransformJournal.isEmpty
                {
                    try? self.mutateSidebarOrganization(
                        announce: nil,
                        apply: { _ in },
                        reflect: { _ in },
                        isBacklogDrain: true)
                }
            case .success(let finalRoot):
                if !effectiveBacklogIDs.isEmpty {
                    Self.sidebarCommittedTransformIDs[enqueueIdentity, default: []]
                        .formUnion(effectiveBacklogIDs)
                }
                guard ownedForPublish else { return }
                handleCommit(finalRoot, durabilityWarning: nil)
            case .replacedButUnsynced(let finalRoot, let reason):
                if !effectiveBacklogIDs.isEmpty {
                    Self.sidebarCommittedTransformIDs[enqueueIdentity, default: []]
                        .formUnion(effectiveBacklogIDs)
                }
                guard ownedForPublish else { return }
                // Content committed; report only durability (round-10
                // finding 1) — never leave the transform pending, or a later
                // drain could wrongly transform paths another process
                // recreated in between.
                handleCommit(
                    finalRoot,
                    durabilityWarning:
                        "Sidebar settings were saved, but the change may not "
                        + "survive a sudden power loss: \(reason)")
            }
        }
        sidebarOrganizationPersistChain = task
        Self.sidebarStoreWriterChains[enqueueIdentity] = task
        Self.sidebarStoreWriterChainTokens[enqueueIdentity] = token
        sidebarOrganizationPersistTaskForTesting = task
    }

    /// Written once on the main actor before the drain's detached update
    /// is created; read only inside that update (task creation is the
    /// happens-before edge).
    private final class SidebarRetainedDrainSnapshot: @unchecked Sendable {
        var entries: [SidebarUnflushedWrite] = []
    }

    /// Round-30: settle the identity-keyed retained writes in enqueue
    /// order through the normal funnel. The snapshot is taken at RUN time
    /// via `prepare` — after every predecessor in the chain has settled —
    /// so a failure landing after this drain was scheduled is still
    /// consumed. Inside the one locked update a per-entry FINAL refusal
    /// (conflict) drops only that entry; any other throw aborts the whole
    /// update and keeps the suffix parked. The registry shrinks only on
    /// commit (acknowledge), so nothing is lost to a transient failure.
    private func scheduleSidebarRetainedWriteDrain() {
        guard sidebarVaultPrefsNotice == nil,
            let drainIdentity = sidebarVaultRootIdentity
        else { return }
        let snapshot = SidebarRetainedDrainSnapshot()
        try? mutateSidebarOrganization(
            announce: nil,
            apply: { root in
                for entry in snapshot.entries {
                    for transform in entry.backlog {
                        transform.applyRaw(to: &root)
                    }
                    do {
                        try entry.apply(&root)
                    } catch is SidebarOrganizationConflictError {
                        // Final refusal: dropped on commit; later entries
                        // still settle.
                    }
                }
            },
            reflect: { _ in },
            acknowledge: {
                let count = snapshot.entries.count
                guard count > 0 else { return }
                if var entries = Self.sidebarUnflushedWriteRetries[
                    drainIdentity]
                {
                    entries.removeFirst(min(count, entries.count))
                    Self.sidebarUnflushedWriteRetries[drainIdentity] =
                        entries.isEmpty ? nil : entries
                }
            },
            isBacklogDrain: true,
            isRetainedDrain: true,
            prepare: {
                snapshot.entries =
                    Self.sidebarUnflushedWriteRetries[drainIdentity] ?? []
            })
    }

    /// Round-23 test seam: simulate an open whose root-identity capture
    /// failed (fstat raced a deletion) so fail-closed paths are testable.
    func overrideSidebarVaultRootIdentityForTesting(
        _ identity: SidebarVaultRootIdentity?
    ) {
        sidebarVaultRootIdentity = identity
    }

    /// Test seam: enqueue one raw write through the production persist chain
    /// — ownership guards, tail bookkeeping, and failure reconcile included —
    /// so chain-ordering behavior is testable without a second funnel.
    func enqueueSidebarOrganizationWriteForTesting(
        _ apply: @escaping @Sendable (inout [String: Any]) throws -> Void
    ) {
        try? mutateSidebarOrganization(announce: nil, apply: apply) { _ in }
    }

    /// Dispatch seam for the eleven FL-06 organization commands. Container
    /// resolution reuses the creation-parent contract: a selected folder is
    /// its own container, a selected file targets its parent, and an empty
    /// selection targets the vault default.
    func dispatchSidebarOrganizationAction(
        _ intent: SidebarActionInvocationIntent,
        rejected: String
    ) throws {
        switch intent.actionID {
        case SlateCommandID.sidebarSortNameAsc:
            try setSidebarSort(.init(field: .name, direction: .asc), intent: intent, rejected: rejected)
        case SlateCommandID.sidebarSortNameDesc:
            try setSidebarSort(.init(field: .name, direction: .desc), intent: intent, rejected: rejected)
        case SlateCommandID.sidebarSortCreatedDesc:
            try setSidebarSort(.init(field: .created, direction: .desc), intent: intent, rejected: rejected)
        case SlateCommandID.sidebarSortCreatedAsc:
            try setSidebarSort(.init(field: .created, direction: .asc), intent: intent, rejected: rejected)
        case SlateCommandID.sidebarSortModifiedDesc:
            try setSidebarSort(.init(field: .modified, direction: .desc), intent: intent, rejected: rejected)
        case SlateCommandID.sidebarSortModifiedAsc:
            try setSidebarSort(.init(field: .modified, direction: .asc), intent: intent, rejected: rejected)

        case SlateCommandID.sidebarToggleDateGrouping:
            let container = try canonicalSidebarCreationParent(
                for: intent.snapshot, rejection: rejected)
            let effective = sidebarOrganization.prefs.effectiveChoice(
                forFolder: container)
            let next: SidebarGroupingOption =
                effective.grouping == .dateBuckets ? .none : .dateBuckets
            var announced = effective
            announced.grouping = next
            // Single-axis write: only the grouping key changes, so an
            // interleaved writer's sort — or a raw sort object this build
            // cannot decode — is never restored from a stale snapshot
            // (round-3 finding 5).
            if container.isEmpty {
                try mutateSidebarOrganization(
                    announce: announced.sortAnnouncement,
                    apply: { root in
                        SidebarOrganizationSchema.setVaultGrouping(&root, next)
                    },
                    reflect: { state in
                        state.prefs.vaultChoice.grouping = next
                    },
                    verifyAnnouncement: (container: "", announced: announced))
            } else {
                // Choosing the vault's CURRENT value returns the folder to
                // inheritance instead of pinning an explicit copy (round-6
                // finding 3) — and that comparison happens under the store
                // lock against the on-disk vault grouping, so a concurrent
                // vault change cannot turn the toggle into a wrong-way
                // no-op (round-7 finding 3). The intended `next` value is
                // carried in; only the clear-vs-set decision is re-derived.
                try mutateSidebarOrganization(
                    announce: announced.sortAnnouncement,
                    apply: { root in
                    let vaultGrouping = SidebarOrganizationSchema.decode(root: root)
                        .prefs.vaultChoice.grouping
                    if next == vaultGrouping {
                        SidebarOrganizationSchema.clearFolderGroupingOverride(
                            &root, folder: container)
                    } else {
                        SidebarOrganizationSchema.setFolderGrouping(
                            &root, folder: container, next)
                    }
                }, reflect: { state in
                    if next == state.prefs.vaultChoice.grouping {
                        guard var override = state.prefs.folderOverrides[container]
                        else { return }
                        override.grouping = nil
                        state.prefs.folderOverrides[container] =
                            override.isEmpty ? nil : override
                    } else {
                        var override = state.prefs.folderOverrides[container]
                            ?? SidebarOrganizationOverride(sort: nil, grouping: nil)
                        override.grouping = next
                        state.prefs.folderOverrides[container] = override
                    }
                },
                    verifyAnnouncement: (container: container, announced: announced))
            }

        case SlateCommandID.sidebarUseVaultDefaultSort:
            let container = try canonicalSidebarCreationParent(
                for: intent.snapshot, rejection: rejected)
            guard !container.isEmpty else {
                throw sidebarActionFailure("The vault default applies here.")
            }
            // The command's label promises SORT only: a grouping override
            // must survive it (round-2 finding 2).
            guard sidebarOrganization.prefs.folderOverrides[container]?.sort != nil
            else {
                throw sidebarActionFailure("This folder uses the vault default.")
            }
            var announced = sidebarOrganization.prefs.effectiveChoice(
                forFolder: container)
            announced.sort = sidebarOrganization.prefs.vaultChoice.sort
            try mutateSidebarOrganization(
                announce: announced.sortAnnouncement,
                apply: { root in
                SidebarOrganizationSchema.clearFolderSortOverride(
                    &root, folder: container)
            }, reflect: { state in
                guard var override = state.prefs.folderOverrides[container] else {
                    return
                }
                override.sort = nil
                state.prefs.folderOverrides[container] =
                    override.isEmpty ? nil : override
            },
                verifyAnnouncement: (container: container, announced: announced))

        case SlateCommandID.sidebarPinNote:
            let target = try singleFileTarget(of: intent, rejected: rejected)
            let folder = SidebarPins.folder(of: target)
            guard
                !sidebarOrganization.pins.isPinned(target, inFolder: folder)
            else {
                throw sidebarActionFailure("This note is already pinned.")
            }
            // Round-35: refuse a capacity-crossing pin up front with the
            // published counts; the locked write's post-mutation shape
            // guard is the race-safe backstop.
            guard
                sidebarOrganization.pins.paths(forFolder: folder).count
                    < SidebarOrganizationSchema.maxPinsPerFolder
            else {
                throw sidebarActionFailure(Self.sidebarPinCapacityReason)
            }
            // Exact op against the decoded on-disk pins: a concurrent
            // writer's pin in the same folder survives (round-3 finding 4).
            try mutateSidebarOrganization(announce: "Pinned.") { root in
                var stored = SidebarOrganizationSchema.decode(root: root).pins
                stored.pin(target, inFolder: folder)
                SidebarOrganizationSchema.setPins(
                    &root, folder: folder, paths: stored.paths(forFolder: folder))
            } reflect: { state in
                state.pins.pin(target, inFolder: folder)
            }

        case SlateCommandID.sidebarUnpinNote:
            let target = try singleFileTarget(of: intent, rejected: rejected)
            let folder = SidebarPins.folder(of: target)
            guard sidebarOrganization.pins.isPinned(target, inFolder: folder)
            else {
                throw sidebarActionFailure("This note isn't pinned.")
            }
            try mutateSidebarOrganization(announce: "Unpinned.") { root in
                var stored = SidebarOrganizationSchema.decode(root: root).pins
                stored.unpin(target, inFolder: folder)
                SidebarOrganizationSchema.setPins(
                    &root, folder: folder, paths: stored.paths(forFolder: folder))
            } reflect: { state in
                state.pins.unpin(target, inFolder: folder)
            }

        case SlateCommandID.sidebarUnpinAll:
            guard intent.snapshot.items.count == 1,
                let item = intent.snapshot.items.first, item.isDirectory
            else {
                throw sidebarActionFailure(rejected)
            }
            let folder = item.path
            let count = sidebarOrganization.pins.paths(forFolder: folder).count
            guard count > 0 else {
                throw sidebarActionFailure("No pinned notes in this folder.")
            }
            let noun = count == 1 ? "note" : "notes"
            try mutateSidebarOrganization(
                announce: "Unpinned \(count) \(noun)."
            ) { root in
                SidebarOrganizationSchema.setPins(&root, folder: folder, paths: [])
            } reflect: { state in
                state.pins.unpinAll(inFolder: folder)
            }

        default:
            throw sidebarActionFailure(Self.sidebarSelectionChangedReason)
        }
    }

    private func singleFileTarget(
        of intent: SidebarActionInvocationIntent, rejected: String
    ) throws -> String {
        guard intent.snapshot.items.count == 1,
            let item = intent.snapshot.items.first, !item.isDirectory
        else {
            throw sidebarActionFailure(rejected)
        }
        return item.path
    }

    private func setSidebarSort(
        _ option: SidebarSortOption,
        intent: SidebarActionInvocationIntent,
        rejected: String
    ) throws {
        let container = try canonicalSidebarCreationParent(
            for: intent.snapshot, rejection: rejected)
        // Dispatch-side twin of the availability rule: a grouped container
        // accepts only the newest-first date sorts. Everything else would be
        // an inert hidden write (red-team finding 2).
        let effectiveBefore = sidebarOrganization.prefs.effectiveChoice(
            forFolder: container)
        if effectiveBefore.grouping == .dateBuckets,
            option.direction == .asc || option.field == .name
        {
            throw sidebarActionFailure(Self.sidebarGroupedSortInertReason)
        }
        // Single-axis writes: only the sort object changes (merged in place,
        // unknown members preserved); a concurrent grouping change is never
        // restored from a stale snapshot (round-3 finding 5).
        if container.isEmpty {
            var announced = sidebarOrganization.prefs.vaultChoice
            announced.sort = option
            try mutateSidebarOrganization(
                announce: announced.sortAnnouncement,
                apply: { root in
                // Authoritative recheck under the lock: a concurrent writer
                // may have enabled grouping since the pre-dispatch guard
                // read this process's published state (round-7 finding 2).
                let grouping = SidebarOrganizationSchema.decode(root: root)
                    .prefs.effectiveChoice(forFolder: "").grouping
                if grouping == .dateBuckets,
                    option.direction == .asc || option.field == .name
                {
                    throw SidebarOrganizationConflictError(
                        reason: Self.sidebarGroupedSortInertReason)
                }
                SidebarOrganizationSchema.setVaultSort(&root, option)
            },
                reflect: { state in
                    state.prefs.vaultChoice.sort = option
                },
                verifyAnnouncement: (container: "", announced: announced))
        } else {
            var announced = sidebarOrganization.prefs.effectiveChoice(
                forFolder: container)
            announced.sort = option
            try mutateSidebarOrganization(
                announce: announced.sortAnnouncement,
                apply: { root in
                let grouping = SidebarOrganizationSchema.decode(root: root)
                    .prefs.effectiveChoice(forFolder: container).grouping
                if grouping == .dateBuckets,
                    option.direction == .asc || option.field == .name
                {
                    throw SidebarOrganizationConflictError(
                        reason: Self.sidebarGroupedSortInertReason)
                }
                SidebarOrganizationSchema.setFolderSort(
                    &root, folder: container, option)
            },
                reflect: { state in
                    var override = state.prefs.folderOverrides[container]
                        ?? SidebarOrganizationOverride(sort: nil, grouping: nil)
                    override.sort = option
                    state.prefs.folderOverrides[container] = override
                },
                verifyAnnouncement: (container: container, announced: announced))
        }
    }

    /// Keep pins AND path-keyed folder overrides consistent with every
    /// structural mutation (fl3 spec §FL3-2.3 + round-2 finding 3): renames
    /// retarget in place, moves out of the folder and deletions drop, and
    /// folder transforms carry their whole subtree — for pins by rewriting
    /// members, for overrides by rekeying the stored entries with their
    /// unknown inner keys intact. Persistence replays the same pure mutation
    /// against the decoded on-disk state inside the locked update, so a
    /// concurrent writer's unrelated changes are never clobbered by a stale
    /// snapshot (round-2 finding 1). Silent — the structural mutation's own
    /// announcement already spoke.
    func applySidebarPinsMutation(_ kind: TreeMutation.Kind) {
        // Normalize the kind into one transform value so the in-memory
        // application, the locked disk replay, and the read-only journal all
        // consume the identical operation.
        var transform = SidebarStructuralTransform()
        switch kind {
        case let .rename(oldPath, newPath),
            let .move(oldPath, newPath, _, _):
            // The node kind is unknown here; pins/overrides transforms are
            // disjoint on file vs folder paths, so both are applied.
            transform.renames.append(
                .init(oldPath: oldPath, newPath: newPath, isDirectory: nil))
        case let .delete(path, _, wasDirectory):
            if wasDirectory {
                transform.deletedFolders.append(path)
            } else {
                transform.deletedFiles.append(path)
            }
        case let .batchMove(standing, _), let .importBatch(_, standing, _):
            for change in standing {
                transform.renames.append(
                    .init(
                        oldPath: change.oldPath,
                        newPath: change.newPath,
                        isDirectory: change.isDirectory))
            }
        case let .batchTrash(trashed):
            transform.deletedFiles.append(
                contentsOf: trashed.filter { !$0.isDirectory }.map(\.path))
            transform.deletedFolders.append(
                contentsOf: trashed.filter(\.isDirectory).map(\.path))
        case .createFolder, .createNote, .batchReconcile:
            return
        }
        guard !transform.isEmpty else { return }
        guard sidebarVaultPrefsStore != nil else { return }

        // Every structural transform is journaled as PENDING first and only
        // acknowledged (removed) after its locked replay commits. The vault
        // mutation already happened on disk, so a replay that fails — even
        // one whose failure is what first DETECTS silent corruption — must
        // survive for Retry rather than vanish with the rollback (round-6
        // finding 1; round-4 finding 2).
        guard
            sidebarStructuralTransformJournal.count
                < Self.sidebarStructuralTransformJournalCap
        else {
            sidebarStructuralTransformJournalOverflowed = true
            return
        }
        sidebarStructuralTransformJournal.append(transform)

        // While the file is already known read-only, Retry owns the replay.
        guard sidebarVaultPrefsNotice == nil else { return }

        // The locked raw replay always runs for a path transform: the file
        // can hold entries this build cannot decode (an unknown-only
        // override) or that another writer added after load, so in-memory
        // change flags must not gate the disk-side rekey (round-3 finding 1).
        // The transform itself was journaled above, and every persist drains
        // the journal backlog under the lock (round-8 finding 1), so the
        // payload here is empty — the drain both replays and, on commit,
        // acknowledges it.
        let frozen = transform
        try? mutateSidebarOrganization(
            announce: nil,
            apply: { _ in }
        ) { state in
            frozen.apply(to: &state.pins)
            frozen.apply(to: &state.prefs)
        }
    }

    /// Drop authored pin entries that no longer resolve to a real row —
    /// invoked lazily from level presentation, at most once per folder per
    /// session, and never against a read-only preference file. The disk
    /// replay filters the decoded folder list, so a concurrent writer's
    /// additions to other folders (or fresh non-stale pins in this one)
    /// survive.
    func pruneStaleSidebarPins(forFolder folder: String, stale: [String]) {
        guard !stale.isEmpty,
            sidebarVaultPrefsNotice == nil,
            sidebarPinPruneLedger.shouldPrune(folder: folder),
            !sidebarPinPruneInFlight.contains(folder),
            let vaultRoot = currentVaultURL
        else { return }
        // Round-13 finding 2: one in-flight prune per folder — repeated
        // stale reports while a prune is pending coalesce into the next
        // report after it settles.
        sidebarPinPruneInFlight.insert(folder)
        // Round-12 finding 1: no filesystem work on the main actor, and a
        // bounded, deduplicated candidate set — an adversarially repetitive
        // authored list cannot freeze the sidebar. Surplus candidates simply
        // wait for a later session's prune.
        var seen: Set<String> = []
        let candidates = Array(
            stale.filter { seen.insert($0).inserted }
                .prefix(Self.sidebarStalePruneCandidateCap))
        guard !candidates.isEmpty else { return }
        guard Self.sidebarVaultRelativePathIsAdmissible(folder) || folder.isEmpty
        else { return }
        let staleSet = Set(candidates)

        // All validation and mutation happen under the store lock, off the
        // main actor (round-11 finding 3's fresh exact-path rule): prune only
        // candidates that are STILL a definite ENOENT at mutation time. The
        // removal count reports back so the once-per-session slot is consumed
        // only by a committed mutation that actually removed a pin (round-12
        // finding 2). Published memory converges via the tail's decoded
        // final-root publish; no optimistic reflect is needed.
        final class RemovalCountBox: @unchecked Sendable {
            private let lock = NSLock()
            private var count = 0
            func record(_ value: Int) {
                lock.lock()
                count = value
                lock.unlock()
            }
            var value: Int {
                lock.lock()
                defer { lock.unlock() }
                return count
            }
        }
        let removals = RemovalCountBox()
        let pruneIdentity = sidebarVaultRootIdentity
        try? mutateSidebarOrganization(
            announce: nil,
            apply: { root in
                let storedPins = SidebarOrganizationSchema.decode(root: root).pins
                let storedPaths = storedPins.paths(forFolder: folder)
                let definitelyMissing = Self.sidebarDefinitelyMissingPaths(
                    vaultRoot: vaultRoot,
                    expectedIdentity: pruneIdentity,
                    candidates: storedPaths.filter { staleSet.contains($0) })
                let storedRemaining = storedPaths.filter { path in
                    !definitelyMissing.contains(path)
                }
                removals.record(storedPaths.count - storedRemaining.count)
                guard storedRemaining.count != storedPaths.count else { return }
                SidebarOrganizationSchema.setPins(
                    &root, folder: folder, paths: storedRemaining)
            },
            reflect: { _ in },
            acknowledge: { [weak self] in
                guard let self, removals.value > 0 else { return }
                self.sidebarPinPruneLedger.markPruned(folder: folder)
            },
            onSettled: { [weak self] in
                self?.sidebarPinPruneInFlight.remove(folder)
            })
    }

    private var sidebarPinPruneInFlight: Set<String> = []
    private static let sidebarStalePruneCandidateCap = 128

    typealias SidebarVaultRootIdentity = SidebarVaultPrefsStore.RootIdentity

    /// The vault root's stable (device, inode) identity; nil when it cannot
    /// be determined (in which case queued writes are dropped, never risked).
    nonisolated static func vaultRootIdentity(
        of vaultRoot: URL
    ) -> SidebarVaultRootIdentity? {
        var info = stat()
        guard vaultRoot.path.withCString({ stat($0, &info) }) == 0 else {
            return nil
        }
        return SidebarVaultRootIdentity(
            device: UInt64(info.st_dev), inode: UInt64(info.st_ino))
    }

    /// A vault-relative path safe to join to the vault root: nonempty,
    /// relative, forward-slash separated, with no empty, `.`, or `..`
    /// components (the organizer/index canonical form).
    nonisolated static func sidebarVaultRelativePathIsAdmissible(
        _ path: String
    ) -> Bool {
        guard !path.isEmpty, !path.hasPrefix("/") else { return false }
        return path.split(separator: "/", omittingEmptySubsequences: false)
            .allSatisfy { component in
                !component.isEmpty && component != "." && component != ".."
            }
    }

    /// The subset of candidates that are DEFINITELY absent: their parent
    /// directory is readable (or itself definitively gone) and contains no
    /// byte-exact entry for the final path component. A plain `stat` is not
    /// exact on the default case-insensitive APFS volume, follows symlinks,
    /// and accepts directories (round-14 finding 2) — an entry of any type
    /// with the exact name retains the pin (uncertainty never prunes), and
    /// so does an unreadable parent.
    nonisolated static func sidebarDefinitelyMissingPaths(
        vaultRoot: URL,
        expectedIdentity: SidebarVaultRootIdentity?,
        candidates: [String]
    ) -> Set<String> {
        guard !candidates.isEmpty else { return [] }
        var byParent: [String: [String]] = [:]
        var missing: Set<String> = []
        for candidate in candidates {
            // Round-16: admission BEFORE any filesystem access. An authored
            // pin that is absolute or traverses (`..`) can never be a real
            // vault-relative entry — it is definitively invalid and prunes
            // WITHOUT ever touching a path outside the vault.
            guard sidebarVaultRelativePathIsAdmissible(candidate) else {
                missing.insert(candidate)
                continue
            }
            byParent[SidebarPins.folder(of: candidate), default: []]
                .append(candidate)
        }
        guard !byParent.isEmpty else { return missing }

        // Round-17: descriptor-walk each parent with O_NOFOLLOW so a
        // component swapped to a symlink after stale detection can neither
        // escape the vault nor prove absence — symlinked/unreadable
        // components are uncertainty and retain their pins. The vault root
        // itself resolves once (a user may legitimately open a vault via a
        // symlink); every component below it refuses links.
        let rootFD = open(vaultRoot.path, O_RDONLY | O_DIRECTORY | O_CLOEXEC)
        guard rootFD >= 0 else { return missing }
        defer { close(rootFD) }

        // Round-22: this open re-resolves the path independently of the
        // store's pinned descriptors — verify it still IS the vault the
        // prune was admitted for. A same-path replacement (or any stat
        // failure) is uncertainty: nothing prunes on a newcomer's evidence.
        if let expectedIdentity {
            var info = stat()
            guard fstat(rootFD, &info) == 0,
                UInt64(info.st_dev) == expectedIdentity.device,
                UInt64(info.st_ino) == expectedIdentity.inode
            else { return missing }
        } else {
            return missing
        }

        for (parent, children) in byParent {
            var parentFD = dup(rootFD)
            guard parentFD >= 0 else { continue }
            var walkOutcome: WalkOutcome = .opened
            if !parent.isEmpty {
                for component in parent.split(separator: "/") {
                    let nextFD = String(component).withCString { name in
                        openat(
                            parentFD, name,
                            O_RDONLY | O_DIRECTORY | O_NOFOLLOW | O_CLOEXEC)
                    }
                    if nextFD >= 0 {
                        close(parentFD)
                        parentFD = nextFD
                        continue
                    }
                    walkOutcome = errno == ENOENT ? .definitelyMissing : .uncertain
                    break
                }
            }
            switch walkOutcome {
            case .definitelyMissing:
                // The parent chain itself is definitively gone: so are its
                // entries.
                close(parentFD)
                missing.formUnion(children)
            case .uncertain:
                // A symlinked, replaced, or unreadable component: retain.
                close(parentFD)
            case .opened:
                // nil from the enumerator means "error mid-listing": an
                // incomplete name set must retain, never prune (round-18
                // finding 2).
                guard
                    let exactNames = sidebarExactDirectoryNames(parentFD)
                else {
                    continue
                }
                for candidate in children {
                    let name = (candidate as NSString).lastPathComponent
                    if !exactNames.contains(name) {
                        missing.insert(candidate)
                    }
                }
            }
        }
        return missing
    }

    private enum WalkOutcome {
        case opened
        case definitelyMissing
        case uncertain
    }

    /// Test seam: replaces the readdir enumeration (return nil = failure).
    /// The production path distinguishes end-of-directory from an error via
    /// errno, per POSIX readdir semantics.
    nonisolated(unsafe) static var sidebarDirectoryEnumeratorForTesting:
        (@Sendable (Int32) -> Set<String>?)?

    /// Byte-exact entry names of the directory the descriptor pins, or nil
    /// when enumeration failed partway (round-18 finding 2: an incomplete
    /// listing must read as uncertainty, not absence). Consumes the fd.
    private nonisolated static func sidebarExactDirectoryNames(
        _ parentFD: Int32
    ) -> Set<String>? {
        if let enumerator = sidebarDirectoryEnumeratorForTesting {
            close(parentFD)
            return enumerator(parentFD)
        }
        guard let dir = fdopendir(parentFD) else {
            close(parentFD)
            return nil
        }
        defer { closedir(dir) }  // closes parentFD too
        var names: Set<String> = []
        errno = 0
        while let entry = readdir(dir) {
            let name = withUnsafeBytes(of: entry.pointee.d_name) {
                buffer -> String in
                let pointer = buffer.baseAddress!
                    .assumingMemoryBound(to: CChar.self)
                return String(cString: pointer)
            }
            names.insert(name)
            errno = 0
        }
        guard errno == 0 else { return nil }
        return names
    }

    /// Injectable targeted lookup for deterministic coalescing tests. The
    /// production closure uses the exact-path Rust projection and runs only
    /// from a detached task.
    var sidebarFileSummaryFetcher: @Sendable (VaultSession, String) -> FileSummary? = {
        session, path in
        try? session.getFileSummary(path: path)
    }
    var sidebarMetadataPendingPaths: Set<String> = []
    var sidebarMetadataRefreshGeneration = 0
    private(set) var sidebarMetadataRefreshTaskForTesting: Task<Void, Never>?
    private var sidebarFileSummaryUpdateCounter = 0

    /// Drives the Citation Summary sheet (Cmd+Shift+J / #282). `true`
    /// while the sheet is presented; the sheet body reads from
    /// `currentNoteCitations` to compute counts.
    @Published var isCitationSummaryOpen: Bool = false

    /// Set by the Jump-to-Bibliography command (#282 / Cmd+J) from a
    /// focused citation. When non-nil, the BibliographyPanel switches
    /// to the Entries segment and filters to this key. Cleared after
    /// the panel handles it.
    @Published var pendingBibliographyKeyFocus: String?

    /// Per-user math rendering preferences. UI panels bind to this;
    /// the `didSet` re-triggers the math-block load for the current
    /// path so settings changes propagate to the rendered output.
    ///
    /// **Note**: `MathPrefs` is a Swift-side mirror of the Rust
    /// `slate_core::math::MathPrefs` — the FFI doesn't surface the
    /// struct directly (only its enum components, which the FFI
    /// mirrors as `MathSpeechStyle`, `MathVerbosity`, `BrailleCode`).
    /// The session's `get_math_blocks` reads prefs from
    /// `SessionConfig.math_prefs` captured at session-open time;
    /// hot-swapping requires a session-side setter that the
    /// Settings PR (#224) lands. For #223 the UI state path is
    /// wired but the rendered output still uses session defaults
    /// until #224 is in.
    @Published var mathPrefs: MathPrefs = MathPrefs() {
        didSet {
            // Audit #257 L1: SwiftUI bindings (a Picker writing
            // back through `$mathPrefs.speechStyle`) can re-fire
            // the setter with the same value on view rebuilds.
            // Skip the loader spin-up if nothing actually changed.
            guard oldValue != mathPrefs else { return }
            preferencesStore.saveMathPrefs(mathPrefs)
            // Audit #259: push the new prefs into the open session
            // so subsequent `get_math_blocks` calls render with
            // them. Without this the Picker update was UI-only —
            // the backend kept the prefs captured at session-open
            // time. `setMathPrefs` throws VaultError; the only
            // realistic failure is a poisoned mutex, which is
            // unrecoverable — log and continue, the next loader
            // call will still use the cached prefs.
            if let session = currentSession {
                do {
                    try session.setMathPrefs(prefs: mathPrefs)
                } catch {
                    fputs(
                        "Slate: session.setMathPrefs failed: \(error)\n",
                        stderr
                    )
                }
            }
            // Audit #261 H1 (WCAG 4.1.3): when the user changes a
            // Picker in Settings, SwiftUI silently re-renders the
            // live preview's accessibilityLabel — VoiceOver won't
            // re-announce it unless focus is on that element. Post
            // an AT announcement describing what changed so users
            // hear confirmation regardless of focus location.
            announceMathPrefsDiff(from: oldValue, to: mathPrefs)
            guard let path = selectedFilePath else { return }
            mathBlocksLoadTask?.cancel()
            // Red-team M2: also cancel an in-flight
            // refresh-after-save task whose payload would otherwise
            // land AFTER the prefs-driven reload and clobber the
            // new-prefs result with the old-prefs blocks.
            mathBlocksRefreshTask?.cancel()
            mathBlocksRefreshTask = nil
            mathBlocksLoadTask = Task { [weak self] in
                await self?.loadCurrentNoteMathBlocks(path: path)
            }
        }
    }

    /// Compose a brief diff announcement for `mathPrefs` changes.
    /// Only one of the three fields can change per Picker selection
    /// (UI surface uses three separate Pickers), so the announcement
    /// reads like "Speech style: MathSpeak" — short, focused,
    /// announces what the user just did. (Audit #261 H1.)
    private func announceMathPrefsDiff(from old: MathPrefs, to new: MathPrefs) {
        if old.speechStyle != new.speechStyle {
            postAccessibilityAnnouncement(
                "Math speech style: \(new.speechStyle.displayName).",
                priority: .medium
            )
        } else if old.verbosity != new.verbosity {
            postAccessibilityAnnouncement(
                "Math verbosity: \(new.verbosity.displayName).",
                priority: .medium
            )
        } else if old.brailleCode != new.brailleCode {
            postAccessibilityAnnouncement(
                "Math braille code: \(new.brailleCode.displayName).",
                priority: .medium
            )
        }
    }

    /// Code pipeline preferences. Controls the AT preamble's
    /// verbosity on rendered code blocks. Settings panel #224
    /// drives this. The CodeBlockView UI binding to this is V1.x
    /// follow-up — today the view uses the same default
    /// (`preambleOnly`) the type carries.
    @Published var codePrefs: CodePrefs = CodePrefs() {
        didSet {
            guard oldValue != codePrefs else { return }
            preferencesStore.saveCodePrefs(codePrefs)
            if oldValue.verbosity != codePrefs.verbosity {
                postAccessibilityAnnouncement(
                    "Code preamble verbosity: \(codePrefs.verbosity.displayName).",
                    priority: .medium
                )
            }
        }
    }

    // MARK: Editor text zoom (#848)

    /// The discrete zoom ladder for in-app editor text zoom. 1.0 is
    /// the body-text-style base size (which itself tracks the system
    /// Text Size — the two COMPOSE: zoom multiplies on top, it never
    /// replaces the accessibility floor). Discrete rungs, not a free
    /// multiplier, so ⌘=/⌘− feel stepped like every macOS zoom and
    /// the announced percentages are stable round numbers.
    static let editorTextScaleSteps: [Double] = [0.9, 1.0, 1.1, 1.25, 1.4, 1.6]

    /// The persisted in-app editor text zoom factor (#848), applied by
    /// the monospaced EDITOR/CODE surfaces via
    /// `Tokens.Typography.monospacedBodyNSFont(scale:)` — the NSTextView
    /// note editor, the code-blocks panel, and the properties-source
    /// YAML editor. Deliberately NOT the reading surface: reading-mode
    /// prose is Dynamic-Type-backed and tracks the system Text Size;
    /// zooming it too would double-scale (see the Zoom In menu item's
    /// boundary note in `SlateMacApp`). `@Published` so the hosting
    /// views re-render (and their `updateNSView` re-derives the font)
    /// on change. Loaded from `PreferencesStore` in `init`; every
    /// mutation routes through `setEditorTextScale`.
    @Published private(set) var editorTextScale: Double = 1.0

    /// ⌘= with no canvas tab active (focus-routed in `SlateMacApp`).
    func editorZoomIn() { stepEditorTextScale(+1) }

    /// ⌘− with no canvas tab active.
    func editorZoomOut() { stepEditorTextScale(-1) }

    /// ⌘0 with no canvas tab active — reset to the base size.
    func editorActualSize() { setEditorTextScale(1.0) }

    /// Nearest ladder rung to an arbitrary (possibly hand-edited)
    /// stored value. Applied at LOAD so the runtime value is always
    /// on-ladder; static + pure for the boundary tests.
    static func nearestEditorTextRung(to value: Double) -> Double {
        editorTextScaleSteps.min {
            abs($0 - value) < abs($1 - value)
        } ?? 1.0
    }

    private func stepEditorTextScale(_ delta: Int) {
        let steps = Self.editorTextScaleSteps
        // DIRECTIONAL rung selection, not nearest-then-offset: from an
        // off-ladder value, nearest-snap could move AGAINST the pressed
        // direction (Codex counterexample: stored 0.5 + Zoom Out
        // snapped up to 0.9). Zoom In → first rung strictly above;
        // Zoom Out → last rung strictly below; pinned at the ends
        // (announcement still fires — never-silent policy).
        let target: Double
        if delta > 0 {
            target = steps.first(where: { $0 > editorTextScale + 0.0001 })
                ?? steps[steps.count - 1]
        } else {
            target = steps.last(where: { $0 < editorTextScale - 0.0001 })
                ?? steps[0]
        }
        setEditorTextScale(target)
    }

    private func setEditorTextScale(_ scale: Double) {
        if editorTextScale != scale {
            editorTextScale = scale
            preferencesStore.saveEditorTextScale(scale)
        }
        // Announce even when pinned at a ladder end (or already at
        // 100%): the keypress must never be silent feedback-wise —
        // the user hears the (unchanged) size instead of nothing.
        postAccessibilityAnnouncement(
            "Editor text size \(Int((editorTextScale * 100).rounded())) percent.",
            priority: .medium)
    }

    // MARK: Editor spell check (#855)

    /// Opt-in live spell checking for the note editor (#855). Default
    /// OFF (see `PreferencesStore.editorSpellCheckKey` — Markdown
    /// source squiggles everywhere). `@Published` so the Edit-menu
    /// checkmark re-renders and `NoteContentView`'s host re-runs
    /// `NoteEditorView.updateNSView` with the new value (the
    /// `editorTextScale` live-application pattern). Loaded from
    /// `PreferencesStore` in `init`; every mutation routes through
    /// `toggleEditorSpellCheck`.
    @Published private(set) var editorSpellCheckEnabled: Bool = false

    /// Edit ▸ Check Spelling While Typing / the palette command.
    /// Persists + announces — the toggle is never silent feedback-wise
    /// (the `setEditorTextScale` policy).
    func toggleEditorSpellCheck() {
        editorSpellCheckEnabled.toggle()
        preferencesStore.saveEditorSpellCheck(editorSpellCheckEnabled)
        postAccessibilityAnnouncement(
            editorSpellCheckEnabled
                ? "Check spelling while typing on."
                : "Check spelling while typing off.",
            priority: .medium)
    }

