    /// SwiftUI binding target; the picker sets this back to `false`
    /// from its close button + Esc keybinding.
    @Published var isTemplatePickerOpen: Bool = false
    /// State machine for the create-from-template flow. `.idle` when
    /// no flow is active; `.needsPrompts` while the prompt sheet is
    /// up; `.needsName` while the new-note name sheet is up. Driven
    /// by `selectTemplate` / `submitTemplatePrompts` /
    /// `submitTemplateNoteName` / `cancelTemplateFlow`.
    @Published var pendingTemplateFlow: PendingTemplateFlow = .idle
    /// Inline validation error surfaced by the new-note name sheet
    /// (empty / `.` / `..` / absolute paths, render/save failures).
    /// `nil` when the field is in a valid state.
    @Published var templateNoteNameError: String?
    /// Exact destination text restored when an admitted render/write fails and
    /// the name sheet is re-presented. Nil for a fresh flow.
    @Published private(set) var templateRetryNoteName: String?
    /// Canonical creation parent frozen by the shared Sidebar action intent.
    /// Nil means no template flow owns a destination; the empty string is the
    /// vault root. The name field remains relative to this destination.
    @Published private(set) var templateCreationDestinationOwner:
        TemplateCreationDestinationOwner?
    private var templateFlowGeneration: UInt64 = 0

    var templateCreationDestination: String? {
        templateCreationDestinationOwner?.path
    }

    static let templateAvailabilityLoadingReason =
        "Wait for Slate to finish loading templates."
    static let templateAvailabilityEmptyReason =
        "Add a Markdown file to this vault’s configured template folder to create from a template."
    static let templateAvailabilityFailedReason =
        "Slate couldn’t load templates. Check the configured template folder and try again."
    static let templateDestinationUnavailableReason =
        "The template destination is no longer available. Cancel and try again."
    static let templateFlowBusyReason =
        "Finish or cancel the current template note before starting another."
    static let templateDialogBusyReason =
        "Finish or cancel the current dialog before creating from a template."
    static let templateOtherWindowReason =
        "Return to the main Slate window before creating from a template."

    private var templateAvailabilityDisabledReason: String? {
        switch templateAvailability {
        case .available:
            return nil
        case .loading:
            return Self.templateAvailabilityLoadingReason
        case .empty:
            return Self.templateAvailabilityEmptyReason
        case .failed:
            return Self.templateAvailabilityFailedReason
        }
    }

    /// A new template sheet may start only from Slate's primary host window.
    /// An attached sheet is admitted solely when the existing template state
    /// owns it; that flow is then disabled by `templateFlowBusyReason` instead.
    private var templateShortcutModalDisabledReason: String? {
        // AppState is also used headlessly by tests and non-UI helpers. Window
        // admission begins only after RootView proves a real UI host exists.
        guard templateShortcutHostWindowWasRegistered else { return nil }
        guard let keyWindow = templateShortcutKeyWindowProvider() else {
            return Self.templateOtherWindowReason
        }
        if templateShortcutModalWindowProvider() === keyWindow {
            return Self.templateDialogBusyReason
        }
        guard let hostWindow = templateShortcutHostWindow else {
            return Self.templateOtherWindowReason
        }
        if keyWindow === hostWindow { return nil }
        if templateShortcutWindowOwnsActionLauncher(keyWindow) { return nil }
        if keyWindow.sheetParent === hostWindow,
            isTemplatePickerOpen || pendingTemplateFlow != .idle
        {
            return nil
        }
        if keyWindow.sheetParent === hostWindow {
            return Self.templateDialogBusyReason
        }
        return Self.templateOtherWindowReason
    }

    var templateCreationDestinationDescription: String {
        guard let destination = templateCreationDestination else {
            return "the selected folder"
        }
        return destination.isEmpty ? "the vault root" : destination
    }

    private func ownsTemplateCreationDestination(
        session: VaultSession,
        generation: UInt64? = nil
    ) -> Bool {
        guard let owner = templateCreationDestinationOwner,
            owner.sessionIdentity == ObjectIdentifier(session),
            owner.generation == templateFlowGeneration
        else { return false }
        return generation == nil || generation == owner.generation
    }

    /// Narrow test seam for synthetic flow-state tests that bypass the real
    /// picker. Production establishes ownership only through
    /// `openTemplatePicker(in:)`.
    func installTemplateDestinationForTesting(
        _ path: String,
        sessionIdentity: ObjectIdentifier? = nil
    ) {
        guard let session = currentSession else { return }
        templateFlowGeneration &+= 1
        templateCreationDestinationOwner = TemplateCreationDestinationOwner(
            sessionIdentity: sessionIdentity ?? ObjectIdentifier(session),
            generation: templateFlowGeneration,
            path: path)
    }

    /// One-shot channel for "park the editor cursor at byte offset N
    /// of the freshly-loaded note." Used by the create-from-template
    /// flow to honor a rendered template's `{{cursor}}` marker.
    /// Indexed in UTF-8 bytes — `NoteEditorView`'s coordinator
    /// converts to UTF-16 before talking to `NSTextView`.
    /// #421 (F-H1): a CurrentValueSubject, NOT a PassthroughSubject —
    /// the create-from-template flow sends the `{{cursor}}` offset
    /// right after the note load resolves, which can be a runloop
    /// tick BEFORE SwiftUI materializes the editor and subscribes.
    /// A passthrough drops that event silently and the caret lands
    /// at end-of-text (the VO test's finding); the current-value
    /// replay delivers it on subscribe. `nil` = no pending park;
    /// NoteContentView compactMaps it away and clears the value on
    /// delivery so re-attaching the editor later doesn't re-park.
    let cursorByteOffsetRequest = CurrentValueSubject<Int?, Never>(nil)
    // NOTE: delivery implies first-responder transfer to the editor
    // (placeCursorAtByteOffset) — a future sender inherits that
    // focus-stealing semantic; scope it deliberately.

    /// Clear any pending `{{cursor}}` park. Called on delivery (via
    /// NoteContentView's handleEvents) and on selection change so a
    /// stale offset can never park the caret in a different note.
    func clearPendingCursorByteOffset() {
        if cursorByteOffsetRequest.value != nil {
            cursorByteOffsetRequest.send(nil)
        }
    }

    /// One-shot channel for "scroll the content pane to this heading
    /// anchor." `OutlineSidebar` sends; `NoteContentView` subscribes
    /// via `.onReceive`. PassthroughSubject (not @Published) so
    /// repeated clicks on the same heading re-trigger the scroll
    /// without needing a counter.
    let scrollAnchorRequest = PassthroughSubject<String, Never>()

    /// #874 red-team: one-shot channel for "reveal the note find bar."
    /// `showFindInNote` sends this in editing mode; `NoteEditorView`'s
    /// `.onReceive` makes its `NSTextView` first responder AND opens the
    /// find bar — so ⌘F works regardless of which surface holds focus
    /// (opening a note from the tree leaves the TREE first responder, so
    /// a bare `performTextFinderAction:` up the current chain would miss
    /// the editor).
    let findInNoteRequest = PassthroughSubject<Void, Never>()

    /// One-shot channel for "scroll to line N." Search-result
    /// activation (#59) sends a 1-based line number; the content
    /// pane's `.onReceive` resolves to the `line-<N>` anchor.
    let lineScrollRequest = PassthroughSubject<Int, Never>()

    /// Live wire for the search-text debouncer. Every keystroke
    /// pushes the latest query string; the Combine pipeline waits
    /// 150 ms of inactivity before kicking off
    /// `runSearch(query:)`. Cancellation of any in-flight search
    /// happens at the head of each run so we don't pile up
    /// background queries.
    private let searchQuerySubject = PassthroughSubject<String, Never>()
    /// Handle on the in-flight search task. Exposed (internal) so
    /// tests can `await state.searchTask?.value` to deterministically
    /// observe the post-search state.
    private(set) var searchTask: Task<Void, Never>?
    private var searchCancelToken: CancelToken?

    /// Handle on the in-flight scan + list task kicked off by
    /// `openVault`. Exposed (internal, not Published) so tests can
    /// `await state.scanTask?.value` to deterministically observe the
    /// post-scan state.
    private(set) var scanTask: Task<Void, Never>?

    /// Handle on the in-flight note-load task. Same shape as
    /// `scanTask` so tests can await deterministically.
    private(set) var noteLoadTask: Task<Void, Never>?

    /// Handle on the in-flight links-fetch task. Held separately from
    /// `noteLoadTask` so the panels can stay responsive while the
    /// note content loads, and so tests can await each path
    /// independently.
    private(set) var linksLoadTask: Task<Void, Never>?

    /// Handle on the in-flight per-note tasks fetch. Same shape as
    /// `linksLoadTask`; held separately so the `TasksPanel` can
    /// render its loading state on a different timeline from the
    /// links/properties panels.
    private(set) var tasksLoadTask: Task<Void, Never>?

    /// Handle on the in-flight vault-wide tasks query. Driven by
    /// `loadVaultTasks()` (called from `openTasksReview` and
    /// `applyTaskReviewFilter`). Tests await this to deterministically
    /// observe filter-switch results.
    private(set) var vaultTasksLoadTask: Task<Void, Never>?

    /// Handle on the in-flight "Load more" page (#879 Codex red-team). The
    /// review is now a persistent leaf, so a fresh first-page load (⌘R, a
    /// reveal, a filter change, a vault switch) can race an in-flight
    /// "Load more" — an untracked page task would append its old cursor
    /// page AFTER the fresh page one. Storing the handle lets the fresh-
    /// load paths cancel it; `performLoadMoreVaultTasks`'s `Task.isCancelled`
    /// guard then drops the stale append.
    private(set) var vaultTasksLoadMoreTask: Task<Void, Never>?

    /// Monotonic epoch for the vault-tasks first-page query (#879 Codex
    /// red-team). A CANCELLED/superseded `loadVaultTasks` runs its
    /// unconditional `defer` clear late — without ownership it would wipe a
    /// NEWER load's `isLoadingVaultTasks` (and drop a stale publish onto the
    /// new vault). Each load captures the epoch it bumped; its defer +
    /// publish only fire while it's still the current one.
    private var vaultTasksLoadGeneration: Int = 0

    /// Handle on the most recent per-task toggle. Toggles serialise
    /// through the FFI's session mutex anyway, but holding the
    /// handle here lets tests await the result and surfaces the
    /// in-flight state if the UI ever wants to show a spinner on
    /// the toggled row.
    private(set) var taskToggleTask: Task<Void, Never>?

    /// Handle on the most recent `refreshTasksAfterSave` call.
    /// The refresh re-runs `tasksForFile` off the main actor to
    /// update `currentNoteTasks` after a toggle or save lands.
    /// Production code doesn't await this (the user sees the row
    /// flip when the refresh's @Published write fires); tests
    /// await it instead of using time-based settle waits (#161).
    private(set) var tasksRefreshTask: Task<Void, Never>?

    /// Handles on the most recent post-save content-pipeline
    /// refresh calls. Audit #258 wired three refresh-after-save
    /// helpers (math / code / diagram) so editing a fenced block
    /// updates the displayed cache. Red-team M1: stash the handles
    /// so `closeVault` and the selection-change clear path can
    /// cancel them — otherwise a save-then-immediately-close (or
    /// save-then-switch-files) window leaves orphan tasks running
    /// the off-actor FFI calls.
    private(set) var mathBlocksRefreshTask: Task<Void, Never>?
    private(set) var codeBlocksRefreshTask: Task<Void, Never>?
    private(set) var diagramBlocksRefreshTask: Task<Void, Never>?

    /// Handle on the most recent `reloadEditorBufferAfterToggle`
    /// call. The reload re-reads disk into `currentNoteText` +
    /// `savedBaselineText` so the editor's view of the file
    /// matches the toggled-on-disk state. Same lifecycle shape
    /// as `tasksRefreshTask` — production fire-and-forget,
    /// tests await deterministically (#161).
    private(set) var editorReloadTask: Task<Void, Never>?

    /// Handle on the inner Task spawned by `openTaskRowInEditor`
    /// when activating a row that points to a different file.
    /// The Task waits for the new file's load to settle, then
    /// emits `lineScrollRequest`. Held so tests can await the
    /// scroll emission (#161).
    private(set) var taskRowActivationTask: Task<Void, Never>?

    /// Handle on the most recent template-flow task — opens the
    /// picker (`openTemplatePicker`), reads source for prompt
    /// extraction (`selectTemplate`), or runs the render+save
    /// (`submitTemplateNoteName`). Exposed so tests can await
    /// deterministically on each step of the flow.
    private(set) var templatePickerTask: Task<Void, Never>?
    private(set) var templateAvailabilityTask: Task<Void, Never>?
    private(set) var templateSelectionTask: Task<Void, Never>?
    private(set) var templateCreateTask: Task<Void, Never>?
    private var templateAvailabilityGeneration: UInt64 = 0
    private var templateAvailabilityRefreshGeneration: UInt64 = 0
    private var templateAvailabilityRefreshPending = false
    private(set) var templateAvailabilityRefreshTaskForTesting: Task<Void, Never>?
    var templateListRunner: TemplateListRunner = { session, cancel in
        do {
            return .success(try session.listTemplates(cancel: cancel))
        } catch let error as VaultError {
            return .failure(error)
        } catch {
            return .failure(.Io(message: error.localizedDescription))
        }
    }
    /// Deterministic cancellation seam before detached template enumeration.
    /// Nil in production; tests suspend here to cancel a generation before it
    /// dispatches any filesystem work.
    var templateAvailabilityDispatchGateForTesting: ((UInt64) async -> Void)?
    var templateAvailabilityLandingGateForTesting: ((UInt64) async -> Void)?
    /// Deterministic C4 race seam after template source I/O and before the
    /// selection task is allowed to present its next sheet.
    var templateSelectionLandingGateForTesting: ((TemplateSummary) async -> Void)?
    /// Deterministic C4 race seam around the deferred template cursor landing.
    /// Nil in production; tests suspend after the intended note load settles.
    var templateCursorLandingGateForTesting: (() async -> Void)?
    private var deferredTemplateCursorLanding: DeferredTemplateCursorLanding?

    /// Total announcements fired since the most recent vault was
    /// opened. Internal so the test target can verify the rate-guard
    /// keeps things <= 3/s; the UI never reads it.
    private(set) var scanAnnouncementCount: Int = 0
    /// Most recent message passed to `postAccessibilityAnnouncement`.
    /// Same role as `scanAnnouncementCount` — for tests only.
    private(set) var scanAnnouncementLastMessage: String?

    /// Times `loadBibliographyEntries` has run its fetch since the current
    /// vault opened. Internal, for tests only (the UI never reads it): the
    /// U4-1 leaf-retention test asserts a Bibliography leaf kept mounted
    /// across leaf switches does NOT re-fetch — the load-fire spy that proves
    /// the mounted-ZStack retention actually holds. Same role/convention as
    /// `scanAnnouncementCount`.
    private(set) var bibliographyLoadCount: Int = 0

    /// Most recent message passed through the template-flow
    /// announcement helper (`announceTemplate`). Same role as
    /// `scanAnnouncementLastMessage` — exposed so tests can verify
    /// the polite live region fired without coupling to AppKit's
    /// `NSAccessibility.post` (which is a no-op under the XCTest
    /// runner anyway).
    private(set) var templateAnnouncementLastMessage: String?

    /// Time source for rate-limiting scan announcements. Injectable so
    /// tests can advance simulated time without sleeping.
    var scanClock: () -> Date = { Date() }
    /// Minimum gap between throttled scan announcements. The
    /// acceptance criteria say "no more than ~3 per second" so 350 ms
    /// gives us 2–3 announcements per real-world second with a little
    /// headroom for the synchronous overhead of posting through
    /// AppKit's accessibility bus.
    private let scanAnnouncementMinInterval: TimeInterval = 0.350
    private var scanAnnouncementLastFiredAt: Date = .distantPast

    private var subscriptions: Set<AnyCancellable> = []
    private let recentsStore: RecentVaultsStore
    /// Hand-off for external URLs (http/https/mailto links the user
    /// clicked in a note's outgoing-links panel). Production wires
    /// this to `NSWorkspace.shared.open`; tests inject a no-op so
    /// `XCTest` runs don't actually spawn the user's default browser
    /// every time the suite touches an external-link code path.
    let externalOpener: (URL) -> Bool
    /// Preferences persistence (math + code panels, #224). Injected
    /// at init so tests can substitute a non-standard `UserDefaults`.
    let preferencesStore: PreferencesStore

    /// Command palette registry (Milestone Q #314). Populated in
    /// `init` by `registerCoreCommands` so every menu item /
    /// keyboard shortcut surfaced in `MainSplitView`, `SlateMacApp`,
    /// and `PropertiesPanel` has a matching `Command` the palette
    /// can list and invoke. The id catalogue lives in
    /// `SlateCommands.swift` (`SlateCommandID.all`).
    let commandRegistry: CommandRegistry = CommandRegistry()

    /// Persistent store for the palette's Recent section (#316).
    /// File-backed JSON; in-memory mirror is `commandPaletteRecents`
    /// below. Failures during persistence are non-fatal — recents
    /// is convenience, not critical state.
    private let commandPaletteRecentsStore: CommandPaletteRecentsStore

    /// In-memory snapshot of the recents list, in most-recent-first
    /// order. Refreshed from `commandPaletteRecentsStore` on init
    /// and on every successful command invocation via
    /// `recordCommandInvocation(id:)`.
    @Published private(set) var commandPaletteRecents: [String] = []

    /// In-memory, most-recent-first list of vault-relative file paths
    /// the quick switcher (#495) orders its empty-query list by and
    /// tie-breaks fuzzy matches with. Loaded from the vault's
    /// `FileRecentsStore` on vault open, refreshed on every user-visible
    /// file open via `recordFileOpen(path:)`. Empty while no vault is
    /// open. Unlike `commandPaletteRecents` (a single global store), the
    /// backing store is per-vault, so this is repopulated from
    /// `fileRecentsStore` each time a vault opens.
    @Published private(set) var fileRecents: [String] = []

    /// The current vault's file-recents store, or nil with no vault
    /// open. A computed value rather than a stored field because the
    /// path is vault-relative (`<vault>/.slate/file-recents.json`) and
    /// changes with every vault switch.
    private var fileRecentsStore: FileRecentsStore? {
        currentVaultURL.map { FileRecentsStore(vaultRoot: $0) }
    }

    /// In-memory, most-recent-first list of vault search queries the
    /// overlay's idle state offers as re-runnable "Recent Searches"
    /// (#876; searching.md:37). Loaded from the vault's
    /// `SearchRecentsStore` on vault open, refreshed on every committed
    /// search via `recordSearchRecent(_:)`, wiped by `clearSearchRecents()`
    /// (the privacy affordance, searching.md:38). Empty while no vault is
    /// open — per-vault, like `fileRecents`, since queries are vault-
    /// content-specific.
    @Published private(set) var searchRecents: [String] = []

    /// The current vault's search-recents store, or nil with no vault
    /// open — the `fileRecentsStore` shape (vault-relative path, so a
    /// computed value, repopulated on every vault switch).
    private var searchRecentsStore: SearchRecentsStore? {
        currentVaultURL.map { SearchRecentsStore(vaultRoot: $0) }
    }

    /// Accessibility-announcement seam (M-3, #534; shared with O-5).
    /// The default wraps the global `postAccessibilityAnnouncement`;
    /// tests inject a recording fake to assert the announce gates.
    let announcer: AnnouncementPosting
    /// Clipboard seam for the Sidebar action dispatcher. The production value
    /// is AppKit-backed; tests inject a recorder so copy failures are observable
    /// without mutating the user's clipboard.
    private let sidebarPasteboard: SidebarPasteboardWriting

    init(
        recentsStore: RecentVaultsStore? = nil,
        externalOpener: @escaping (URL) -> Bool = { NSWorkspace.shared.open($0) },
        preferencesStore: PreferencesStore = PreferencesStore(),
        commandPaletteRecentsStore: CommandPaletteRecentsStore? = nil,
        announcer: AnnouncementPosting = AppKitAnnouncementPoster(),
        sidebarPasteboard: SidebarPasteboardWriting = AppKitSidebarPasteboard()
    ) {
        self.announcer = announcer
        self.sidebarPasteboard = sidebarPasteboard
        // Fall back to an in-memory-only store (writes go to a temp
        // path that's discarded on exit) if the standard Application
        // Support location can't be set up. Better degraded than crash
        // on launch.
        if let store = recentsStore {
            self.recentsStore = store
        } else if let store = try? RecentVaultsStore() {
            self.recentsStore = store
        } else {
            let fallback = FileManager.default.temporaryDirectory
                .appendingPathComponent("slate-recent-vaults-fallback.json")
            self.recentsStore = RecentVaultsStore(fileURL: fallback)
        }
        self.externalOpener = externalOpener
        self.preferencesStore = preferencesStore
        // History leaf (O-5): the since-open toggle is a host pref —
        // UI + mark writes only, no core behavior.
        self.historyShowChangesSinceOpen =
            preferencesStore.loadHistoryShowChangesSinceOpen()

        // Command palette recents store — same degraded-fallback
        // pattern as RecentVaultsStore above. Failures here never
        // crash the app; the palette just renders no Recent section.
        if let store = commandPaletteRecentsStore {
            self.commandPaletteRecentsStore = store
        } else if let store = try? CommandPaletteRecentsStore() {
            self.commandPaletteRecentsStore = store
        } else {
            let fallback = FileManager.default.temporaryDirectory
                .appendingPathComponent("slate-command-palette-recents-fallback.json")
            self.commandPaletteRecentsStore = CommandPaletteRecentsStore(fileURL: fallback)
        }
        self.commandPaletteRecents = self.commandPaletteRecentsStore.load()
        // Load persisted preferences AFTER the store is set, BEFORE
        // any other init work that might consume them. The didSet
        // observers haven't been installed yet (they only run on
        // assignment after init), so loading here doesn't recurse.
        self.mathPrefs = preferencesStore.loadMathPrefs()
        self.codePrefs = preferencesStore.loadCodePrefs()
        self.sidebarPreferences = preferencesStore.loadSidebarPreferences()
        // #848: persisted editor text zoom — applied on top of the
        // body-text-style base size in `monospacedBodyNSFont(scale:)`.
        self.editorTextScale = Self.nearestEditorTextRung(to: preferencesStore.loadEditorTextScale())
        // #855: persisted spell-check opt-in (default OFF).
        self.editorSpellCheckEnabled = preferencesStore.loadEditorSpellCheck()
        // #872: persisted "reopen last vault at launch" opt-out (default
        // ON). Read here so the Settings ▸ General toggle and the launch
        // decision both see the persisted value; the launch restore
        // itself is triggered by the root view's `.task`, never by init
        // (so constructing an AppState in tests never opens a vault).
        self.restoreVaultOnLaunch = preferencesStore.loadRestoreVaultOnLaunch()
        // #881: persisted "Don't Show Again" opt-out for the compaction-
        // failure alert (default OFF).
        self.compactionAlertSuppressed =
            preferencesStore.loadSuppressCompactionFailureAlert()
        self.baseQueries = BaseQueriesState(
            pinnedSavedQueryIDs: preferencesStore.loadBaseQueryPrefs().pinnedSavedQueryIDs)
        self.recentVaults = self.recentsStore.load()

        // #868: bridge the nested WorkspaceState's change signal into
        // this object's own. `workspace` is a `let` sub-ObservableObject,
        // and SwiftUI's `.commands` menu builder observes only `appState`
        // — so menu content that reads workspace state (the Duplicate
        // Tab / Close Tab `activeTab == nil` enablement, the #868
        // state-reflecting Reading Mode title) never re-evaluated when
        // ONLY the workspace published (the nested-ObservableObject
        // gap). Forwarding objectWillChange closes that seam for every
        // current and future workspace-reading menu item in one wire.
        //
        // #448 (publish-in-view-update) analysis: this forward is a
        // WILL-change relay — synchronous, same call stack — so it
        // publishes in exactly the transaction context of the source
        // publish and adds no hazard beyond those the workspace's own
        // publishes already carry. WorkspaceState's @Published
        // mutations run in action contexts (every mutation funnels
        // through WorkspaceState methods called from AppState command /
        // click handlers — the U1 funnel discipline) or in post-update
        // `.onChange` mirrors (the U4-4 passive region mirrors; the
        // properties-header expansion Binding setter fires on user
        // interaction) — none run inside a view-update transaction,
        // which is the #448 class. If a future workspace writer
        // violates that, the fix belongs at that call site (the
        // FileTreeSidebar local-@State + .onChange pattern), not here.
        workspace.objectWillChange
            .sink { [weak self] _ in self?.objectWillChange.send() }
            .store(in: &subscriptions)

        // #863: mirror the closed-tab stack's emptiness into the
        // published menu-enablement signal. Subscribing to the nested
        // WorkspaceState publisher (rather than updating at each call
        // site) covers every mutation path — close pushes, reopen
        // pops, and the vault close/switch reset — with one wire.
        workspace.$closedTabs
            .map { !$0.isEmpty }
            .removeDuplicates()
            .sink { [weak self] hasRecords in
                self?.canReopenClosedTab = hasRecords
            }
            .store(in: &subscriptions)

        // #867: menu-title observability for Undo/Redo. The state the
        // Edit ▸ Undo/Redo titles derive from lives OUTSIDE appState's
        // published surface — NSUndoManager instances down the
        // responder chain, and CanvasDocument's session stacks — so
        // nothing re-rendered the menu when an undo stack changed.
        // Observe the undo-manager lifecycle notifications with
        // object: nil (ANY manager: the note editor's, the YAML
        // source editor's, a sheet field editor's) plus a window-key
        // bump (key-window changes swap which manager the responder
        // path reads, without any undo notification), and merge the
        // canvas mutation funnel (`noteUndoStacksChanged`). Debounce-
        // lite: the notifications fire per undo GROUP — NSTextView
        // coalesces typing into per-burst groups, so the raw cadence
        // is human-scale already; 50 ms on the main queue folds a
        // group's open/close pair into one tick.
        //
        // #448: the notifications post from undo registration / undo
        // execution (event handling, never view updates), and the
        // debounce hop makes the eventual publish async on the main
        // queue — post-update by construction.
        let undoEventNames: [Notification.Name] = [
            .NSUndoManagerDidOpenUndoGroup,
            .NSUndoManagerDidCloseUndoGroup,
            .NSUndoManagerDidUndoChange,
            .NSUndoManagerDidRedoChange,
            NSWindow.didBecomeKeyNotification,
        ]
        var undoEventPublishers: [AnyPublisher<Void, Never>] = undoEventNames.map {
            NotificationCenter.default.publisher(for: $0, object: nil)
                .map { _ in () }
                .eraseToAnyPublisher()
        }
        undoEventPublishers.append(undoMenuSubject.eraseToAnyPublisher())
        Publishers.MergeMany(undoEventPublishers)
            .debounce(for: .milliseconds(50), scheduler: DispatchQueue.main)
            .sink { [weak self] in self?.undoMenuTick &+= 1 }
            .store(in: &subscriptions)

        // Watch `selectedFilePath` and (re)trigger note loading on
        // every change. Combine's removeDuplicates avoids reloading
        // when the same path is rebound (e.g. by SwiftUI list
        // diffing). The closure runs on the main actor since the
        // class is @MainActor.
        // The note-load cascade below (handleSelectionChange → ~15
        // `@Published` writes) must NOT run inside a SwiftUI update
        // transaction, or it trips a flood of "Publishing changes from
        // within view updates is not allowed, this will cause undefined
        // behavior" — and, per that warning, real UB: the note loaded
        // only intermittently (~50/50). Confirmed via lldb: frame #21
        // ObjectLocation.set(_:transaction:) → selectedFilePath.setter →
        // this sink → handleSelectionChange. Two transaction-context
        // writers are neutralised so the sink can stay synchronous:
        //
        // 1. The file list. It no longer binds `List(selection:)` to this
        //    property directly (which wrote it mid-transaction); it holds
        //    a local `@State` selection and assigns `selectedFilePath`
        //    from `.onChange` — a post-update, safe mutation point. See
        //    FileTreeSidebar.
        // 2. Init. `.dropFirst()` skips the value Combine replays to a new
        //    subscriber (the initial `nil`), which would otherwise fire
        //    handleSelectionChange(nil) inside the StateObject's creation
        //    pass — the same UB on already-empty state. Safe to drop:
        //    there's nothing to load or clear at init.
        //
        // The sink stays SYNCHRONOUS (no `.receive(on:)`): the direct,
        // programmatic writers — search-open, template-create, the
        // dirty-gate rollback, and the XCTest suite — depend on
        // `handleSelectionChange` (hence `noteLoadTask`) running
        // synchronously on assignment.
        $selectedFilePath
            .removeDuplicates(by: BaseExactIdentity.matches)
            .dropFirst()
            .sink { [weak self] path in
                self?.handleSelectionChange(to: path)
            }
            .store(in: &subscriptions)

        // Search query debouncer. 150 ms matches the acceptance
        // criteria and is short enough that typing feels live but
        // long enough that fast typists don't fire one query per
        // keystroke.
        // #422 red-team F1: NO removeDuplicates here. Its dedup
        // memory is pipeline-lifetime, so the overlay's
        // reopen-with-retained-query re-arm emitted the same string
        // and was silently swallowed — the re-arm was dead code.
        // Announcement dedup lives at the view (searchSummary
        // removeDuplicates); re-running an identical 150ms-debounced
        // query is cheap.
        searchQuerySubject
            .debounce(for: .milliseconds(150), scheduler: DispatchQueue.main)
            .sink { [weak self] query in
                self?.runSearch(query: query)
            }
            .store(in: &subscriptions)

        // Populate the command palette registry from the menu /
        // toolbar surfaces (Milestone Q #314). Closures weak-capture
        // `self` to break the appState → registry → action → appState
        // cycle.
        registerCoreCommands(into: commandRegistry, appState: self)
        wireWorkspacePersistence()
    }

    /// Entry point for the "Show Command Palette…" menu command and
    /// its `⌘⇧P` shortcut. Opens the palette when a vault is open;
    /// otherwise posts an accessibility announcement instead of doing
    /// nothing — pressing `⌘⇧P` on the welcome screen used to be a
    /// silent no-op (the menu item was `.disabled`), which is a dead
    /// end for keyboard / VoiceOver users. Found via live debugging.
    ///
    /// The palette is a vault-scoped surface: its sheet is only
    /// mounted by `MainSplitView` (when a vault is open). This method
    /// must NEVER set `isCommandPaletteOpen = true` while no vault is
    /// open — with no sheet mounted the flipped bool would do nothing
    /// now and then auto-present the palette the instant a vault
    /// opened (the #313 / #328 stuck-bool hazard). Branching here lets
    /// the View-menu command stay ENABLED on the welcome screen (so
    /// the keypress gives feedback) while preserving that invariant.
    func requestCommandPalette() {
        guard isVaultOpen else {
            postAccessibilityAnnouncement(
                "Open a vault to use the command palette.",
                priority: .high
            )
            return
        }
        isCommandPaletteOpen = true
    }

    /// Record that a command was invoked through the palette so the
    /// Recent section (#316) can surface it on next open.
    ///
    /// Updates the in-memory mirror unconditionally so the user
    /// sees the recent during this session even if persistence
    /// fails; THEN tries to persist. Disk failure → log + carry on
    /// (recents is convenience, not critical state). The in-memory
    /// session view stays internally consistent; the next session
    /// might silently "forget" the entry if the disk write didn't
    /// land, which is acceptable.
    ///
    /// Concurrency: `AppState` is `@MainActor`-isolated so this
    /// method (and the `@Published commandPaletteRecents` write
    /// inside it) is reachable only from the main actor. Background-
    /// thread callers must `await` or hop to main — the compiler
    /// enforces this at the call site.
    func recordCommandInvocation(id: String) {
        // LRU update on the in-memory mirror — same shape the
        // store's `add` produces, so session view matches what
        // disk would have if the write succeeds.
        var updated = commandPaletteRecents
        updated.removeAll { $0 == id }
        updated.insert(id, at: 0)
        if updated.count > CommandPaletteRecentsStore.maxEntries {
            updated = Array(updated.prefix(CommandPaletteRecentsStore.maxEntries))
        }
        commandPaletteRecents = updated

        // Persist. Atomic write; failure leaves the on-disk file
        // unchanged and the session view ahead of disk.
        do {
            try commandPaletteRecentsStore.save(updated)
        } catch {
            // Fixed-format NSLog: the id / error text can contain `%`, which a
            // dynamic format string would misread as an unsupplied specifier.
            let message = "Failed to persist command palette recent '\(id)': \(error)"
            NSLog("%@", message)
        }
    }

    /// Entry point for the ⌘O "Quick Open…" command (#495; chord moved
    /// ⌘T→⌘O by #863 — Obsidian's actual quick-switcher default, and
    /// the HIG-truer File ▸ Open). Opens the quick switcher when a
    /// vault is open. With NO vault it falls through to the vault
    /// picker (#863's welcome-screen nicety): the switcher sheet is
    /// only mounted by `MainSplitView`, so the bool must never flip
    /// here (the #313/#328 stuck-bool hazard, same reasoning as
    /// `requestCommandPalette()`) — but where the palette announces
    /// "open a vault first", ⌘O goes one better and OPENS the picker,
    /// so File ▸ Quick Open… is never a dead chord on the welcome
    /// screen. Cost, accepted in the decision record: the "Quick
    /// Open…" label is mildly inaccurate there.
    func openQuickSwitcher() {
        guard isVaultOpen else {
            pickAndOpenVault()
            return
        }
        isQuickSwitcherOpen = true
    }

    /// Record a user-visible file open into the vault's file-recents so
    /// the quick switcher (#495) surfaces it first next time. Called
    /// from ONE choke point — `openFile(_:target:)`, the U1-5 single
    /// navigation entry point every user open (sidebar, links, search,
    /// palette, quick switcher) routes through. Launch-time workspace
    /// restores use `activateTab` directly, NOT `openFile`, so they
    /// never land here — the restored layout doesn't churn recency.
    ///
    /// In-memory-first, persist-second, same as `recordCommandInvocation`:
    /// the session view stays consistent even if the per-vault write
    /// fails (recents is convenience, not critical state). No-op with no
    /// vault (the store is nil).
    func recordFileOpen(path: String) {
        guard let store = fileRecentsStore else { return }
        var updated = fileRecents
        updated.removeAll { $0 == path }
        updated.insert(path, at: 0)
        if updated.count > FileRecentsStore.maxEntries {
            updated = Array(updated.prefix(FileRecentsStore.maxEntries))
        }
        fileRecents = updated
        do {
            try store.save(updated)
        } catch {
            // Fixed-format NSLog: a file path / error text can contain `%`,
            // which a dynamic format string would misread as a specifier.
            let message = "Failed to persist file recent '\(path)': \(error)"
            NSLog("%@", message)
        }
    }

    /// Record a committed vault search into the recents so the overlay's
    /// idle state can offer it again (#876; searching.md:37). Called from
    /// ONE choke point — `openSearchResult(_:)`, i.e. when the user
    /// activates a result — the unambiguous "this query was useful"
    /// signal, NOT per-keystroke (recording every debounced prefix would
    /// bury the list in noise). Mirrors `recordFileOpen`'s open-choke-point
    /// discipline: in-memory-first, persist-second, non-fatal on write
    /// failure. Blank / whitespace-only queries are never recorded. No-op
    /// with no vault (the store is nil).
    func recordSearchRecent(_ query: String) {
        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty, let store = searchRecentsStore else { return }
        // Red-team: route the LRU through the store's tested `add`
        // (move-to-front + dedup + cap + atomic persist) rather than
        // re-implementing it here — a single source of truth.
        do {
            searchRecents = try store.add(trimmed)
        } catch {
            // Fixed-format NSLog: user search text / error can contain `%`,
            // which a dynamic format string would misread as a specifier.
            let message = "Failed to persist search recent '\(trimmed)': \(error)"
            NSLog("%@", message)
        }
    }

    /// Forget every remembered search (the idle-state "Clear" affordance,
    /// searching.md:38 privacy note). PERSIST-first, wipe-memory-on-success
    /// — mirroring `recordSearchRecent` so the in-memory list never
    /// diverges from disk. Red-team: clearing memory first and only
    /// NSLog-ing a `clear()` failure would show an empty list while disk
    /// still held the queries, and the very next `add()` (which rebuilds
    /// from `load()`) — or simply reopening the vault — resurrected them,
    /// silently defeating the privacy affordance. On a write failure the
    /// list stays visible (honest: it was NOT forgotten). No-op with no
    /// vault (the store is nil; the in-memory list is already empty).
    func clearSearchRecents() {
        guard let store = searchRecentsStore else {
            searchRecents = []
            return
        }
        do {
            try store.clear()
            searchRecents = []
        } catch {
            // Fixed-format NSLog: the error text can contain `%`, which a
            // dynamic format string would misread as an unsupplied specifier.
            let message = "Failed to clear search recents (list kept): \(error)"
            NSLog("%@", message)
        }
    }

    /// Re-run a remembered query from the overlay's idle state (#876):
    /// drop it into the field and push it through the debouncer, so the
    /// same `searchQuery` → results path a keystroke takes fires.
    func runRecentSearch(_ query: String) {
        searchQuery = query
        bumpSearchQuery()
    }

    /// Push the current `searchQuery` through the debouncer. Called
    /// from the SwiftUI TextField's `.onChange` so the UI doesn't
    /// have to know about the subject.
    func bumpSearchQuery() {
        searchQuerySubject.send(searchQuery)
    }

    /// Toggle the search overlay open / closed. When opening, the
    /// query is preserved so re-opening with a previous query lands
    /// the user back at the same results. When closing, we cancel
    /// the in-flight query so the worker doesn't keep churning
    /// after the user has moved on.
    /// Menu-driven entry point (#422): same behavior as the toolbar
    /// toggle, but guarded for the welcome screen — the menu item is
    /// reachable with no vault open, where the overlay has no host.
    /// Mirrors `requestCommandPalette()`'s guard + feedback pattern.
    func requestSearchOverlay() {
        guard isVaultOpen else {
            postAccessibilityAnnouncement(
                "Open a vault first. Search works inside a vault."
            )
            return
        }
        toggleSearchOverlay()
    }

    /// Menu-owned Find routing (Edit ▸ Find ▸ Find…, ⌘F). Editor-region
    /// Base/Canvas surfaces get their local filter fields; everything
    /// else routes to `showFindInNote()` — which reveals the note
    /// editor's find bar in editing mode (focusing the editor first, so
    /// it works from the tree / right pane too) and falls back to vault
    /// search in reading mode / with no note open (red-team: ⌘F must
    /// never be inert).
    ///
    /// #874 (Cory-confirmed 2026-07-12): ⌘F is now **find-in-note**, not
    /// vault search (which moved to ⇧⌘F). searching.md:29 — "macOS:
    /// support Find-in-window/page for locating content in open
    /// documents." This reverses the #422 vault-first ⌘F; the Base/Canvas
    /// filter routing is unchanged (their ⌘F already focused a local
    /// filter), only the fall-through — once vault search — now shows the
    /// editor find bar.
    func requestFindInFocusedSurface() {
        if activeBaseDocument != nil, workspace.focusRegion == .editor {
            basesFocusQuickFilter()
        } else if activeCanvasDocument != nil, workspace.focusRegion == .editor {
            canvasFocusFilter()
        } else {
            showFindInNote()
        }
    }

    /// #874: reveal the note editor's find bar (the HIG Find-in-window
    /// path, searching.md:29). ⌘F must NEVER be a dead keystroke
    /// (red-team):
    ///
    /// - **Editing mode, note open** — send `findInNoteRequest`;
    ///   `NoteEditorView` makes its `NSTextView` first responder and
    ///   opens the find bar. Going through the request (not a bare
    ///   `performTextFinderAction:` up the CURRENT chain) is what makes
    ///   ⌘F work when the tree / right pane holds focus — the common
    ///   case right after opening a note from the sidebar.
    /// - **Reading mode, non-note tab (Graph / Canvas / Base / dashboard),
    ///   or no tab open** — there is no mounted `NoteEditorView` subscribed
    ///   to `findInNoteRequest` (reading mode's `ReadingView` is pure
    ///   SwiftUI; the other surfaces mount their own container view). Fall
    ///   back through `requestSearchOverlay()` (the SAME vault-guarded
    ///   entry the ⇧⌘F menu item uses) so ⌘F still does something,
    ///   preserving the #422 never-inert guarantee: with a vault open it
    ///   reveals the search overlay; with none open it announces "Open a
    ///   vault first" rather than mounting a hostless overlay on the
    ///   welcome screen. (A reading-mode in-page find is a follow-up —
    ///   filed separately.)
    ///
    /// The mounted-editor test is `isNoteEditorMounted` — true ONLY when
    /// `NoteContentView.editorSurface` (which carries the
    /// find-bar-subscribing `NoteEditorView`) is actually on screen.
    /// Red-team: gating on `selectedFilePath` was wrong —
    /// `activateGraphTab`/`activateBaseTab`/`activateCanvasTab` leave it
    /// non-nil (a stale note path, or the base/canvas file's own path), so
    /// ⌘F would publish into zero subscribers and become a dead keystroke
    /// on those tabs. Codex round 1: gating on `activeTabPath` +
    /// `.editing` alone was ALSO insufficient — a `.markdown` tab whose
    /// note is still loading, or PERMANENTLY failed to load (deleted /
    /// unreadable / invalid-UTF-8 / oversized → `noteLoadError`), shows
    /// the loading/error state, NOT the editor, so `findInNoteRequest`
    /// again has zero subscribers. `isNoteEditorMounted` mirrors
    /// `NoteContentView.body`'s exact editor-mount conditions.
    func showFindInNote() {
        guard isNoteEditorMounted else {
            requestSearchOverlay()
            return
        }
        findInNoteRequest.send()
    }

    /// True exactly when `NoteContentView.editorSurface` — the only
    /// `findInNoteRequest` subscriber — is mounted and on screen, so a
    /// find request will actually reach an `NSTextView`. Mirrors
    /// `NoteContentView.body`: an active `.markdown` tab
    /// (`workspace.activeTabPath != nil`, so `NoteContentView` is the
    /// mounted container rather than Graph/Canvas/Base), in `.editing`
    /// mode (reading mode's `ReadingView` has no find bar), with the note
    /// LOADED — no `noteLoadError`, not `isLoadingNote`, and
    /// `currentNoteText` populated (the `contentState` arm). Any other
    /// combination routes ⌘F to the vault-search fallback so it is never
    /// inert (#422).
    var isNoteEditorMounted: Bool {
        workspace.activeTabPath != nil
            && activeViewMode == .editing
            && noteLoadError == nil
            && !isLoadingNote
            && currentNoteText != nil
    }

    func toggleSearchOverlay() {
        if isSearchOpen {
            closeSearchOverlay()
        } else {
            isSearchOpen = true
        }
    }

    /// Toggle the right pane's visibility (#882 — View ▸ Hide/Show Right Pane
    /// / ⌥⌘I / the palette). Announces the new state so the change is never
    /// silent for a VoiceOver user (the toggle-feedback policy shared with
    /// `toggleEditorSpellCheck` / `setEditorTextScale`).
    func toggleRightPane() {
        isRightPaneVisible.toggle()
        // #882 note (Codex red-team): hiding the pane while keyboard focus
        // is INSIDE it drops focus to the window (recover with Tab, or
        // ⌥⌘I to bring the pane back). A programmatic move of the real
        // first responder to the editor is intentionally NOT attempted
        // here: this app has no editor-focus request seam — even the
        // spec'd ⌘⌥← "return to editor" only updates region bookkeeping,
        // never `makeFirstResponder`, and the editor surface is an
        // NSTextView that owns first responder natively. A model-only
        // "rescue" would be a no-op that misrepresents where focus is;
        // adding a real editor-focus anchor risks fighting the NSTextView
        // and needs on-device VoiceOver verification — deferred to the
        // region-focus-containment work, tracked separately.
        postAccessibilityAnnouncement(
            isRightPaneVisible ? "Right pane shown." : "Right pane hidden.",
            priority: .medium)
    }

    /// Reveal the right pane and focus the leaf region — the single entry
    /// point every leaf-reveal command routes through (#882 red-team: a
    /// reveal command that only set `activeLeaf` was a dead no-op while the
    /// pane was hidden). Sets visibility BEFORE focusing so the leaf the
    /// caller just selected is actually on screen.
    func focusLeafRegionRevealingPane() {
        isRightPaneVisible = true
        workspace.focusLeafRegion()
    }

    /// Close the overlay and cancel any in-flight search. Keep
    /// `searchQuery` so a Cmd+F → Esc → Cmd+F round trip lands
    /// back where the user was — but RESET `searchScope` to `.vault`:
    /// a tag scope set by reading-view activation is a transient,
    /// invisible filter, and leaving it armed would silently scope the
    /// next ⌘F search to a tag the user can't see. `closeVault()`
    /// routes through here too, so this covers vault close as well.
    func closeSearchOverlay() {
        isSearchOpen = false
        cancelInFlightSearch()
        searchScope = .vault
        searchState = .idle
        searchSummary = ""
        // No rows are displayed once the panel is idle, so the
        // producing-query snapshot must go too (#876 Codex round 2) —
        // otherwise a stale `lastResultsQuery` could survive into the
        // next vault. This is the single teardown choke point (Esc,
        // closeVault, and the openVault direct-switch reset all route
        // here).
        lastResultsQuery = nil
    }

    /// Enter tag scope and re-arm the search. Called by the reading
    /// view's tag activation (#508): sets `.tag(name:)` and pushes the
    /// (typically empty) query through the debouncer, which under tag
    /// scope lists the tag's files rather than idling.
    func setSearchScope(_ scope: SearchScope) {
        searchScope = scope
        bumpSearchQuery()
    }

    /// Drop back to vault scope (the dismissible chip's clear button)
    /// and re-arm with the current query so the results refresh
    /// immediately under the wider scope.
    func clearSearchScope() {
        searchScope = .vault
        bumpSearchQuery()
    }

    /// Cancel any currently-running search task. Safe to call when
    /// nothing's in flight.
    private func cancelInFlightSearch() {
        searchCancelToken?.cancel()
        searchCancelToken = nil
        searchTask?.cancel()
        searchTask = nil
    }

    /// Kick off a fresh search. Called from the debouncer; callers
    /// shouldn't invoke directly.
    private func runSearch(query: String) {
        let trimmed = query.trimmingCharacters(in: .whitespaces)
        // Empty query → idle, EXCEPT under `.tag` scope: there an empty
        // query is meaningful (list every file with the tag), so it must
        // reach the FFI call instead of short-circuiting. `.vault` /
        // `.folder` keep their empty → idle behavior. Match on the scope
        // cases so a future scope can opt in explicitly.
        let scopeListsOnEmpty: Bool = {
            if case .tag = searchScope { return true }
            return false
        }()
        if trimmed.isEmpty && !scopeListsOnEmpty {
            cancelInFlightSearch()
            searchState = .idle
            searchSummary = ""
            lastResultsQuery = nil
            return
        }
        guard let session = currentSession else {
            // No vault open → surface a benign placeholder rather
            // than an error toast.
            searchState = .idle
            return
        }
        // Tear down the previous query before starting a new one.
        cancelInFlightSearch()
        searchState = .searching
        let cancel = CancelToken()
        searchCancelToken = cancel
        // Snapshot the scope for the detached task — reading it off
        // `self` across the actor hop would race a concurrent scope
        // change (e.g. the user clearing the chip mid-flight).
        let scope = searchScope
        // Explicit `@MainActor` on the Task body so the
        // post-await @Published writes are guaranteed to run on
        // the main thread (Codoki PR 86 callout). Without this the
        // awaiting Task could resume on whatever cooperative-pool
        // thread the inner detached task ran on, and SwiftUI
        // throws a runtime warning when @Published changes off-main.
        searchTask = Task { @MainActor [weak self] in
            let outcome: Result<QueryResultSet, VaultError> =
                await Task.detached(priority: .userInitiated) {
                    do {
                        let rs = try session.fullTextSearch(
                            query: trimmed,
                            scope: scope,
                            cancel: cancel
                        )
                        return .success(rs)
                    } catch let error as VaultError {
                        return .failure(error)
                    } catch {
                        return .failure(.Io(message: error.localizedDescription))
                    }
                }
                .value

            // Drop late results: another query may have taken over
            // while this one was in flight; tossing the result keeps
            // the overlay's panel coherent with the latest typed
            // query. The `currentSession !== session` arm is the
            // cross-vault guard (#876 Codex round 2): a direct vault
            // switch that resolves after this search was dispatched must
            // NOT publish vault A's rows into vault B's overlay (the same
            // identity guard the note-load and history paths use). Belt
            // and suspenders — the openVault teardown also cancels this
            // search — but robust if a switch races the await.
            guard let self else { return }
            if Task.isCancelled || self.searchCancelToken !== cancel
                || self.currentSession !== session
            {
                return
            }
            switch outcome {
            case .success(let rs):
                self.searchState = .results(rows: rs.rows, summary: rs.summary)
                self.searchSummary = rs.summary
                // #876 Codex round 1: remember WHICH query produced these
                // rows, so activating one records/anchors that query — not
                // a newer one the user may have typed during the debounce.
                self.lastResultsQuery = trimmed
            case .failure(let error):
                if case .Cancelled = error {
                    // Cancellation is a normal user action — keep
                    // whatever the panel was showing before.
                    return
                }
                let message = self.humanReadable(error)
                self.searchState = .error(message)
                self.searchSummary = "Search error: \(message)"
            }
        }
    }

    /// Internal hook from the selectedFilePath subscription. Cancels
    /// any in-flight note load and kicks off a fresh one — or clears
    /// content if `path` is nil.
    private func handleSelectionChange(to path: String?) {
        // A deferred template cursor belongs only to the dirty-gated target.
        // Preserve it during the gate's rollback (pendingNavigation is still
        // armed), but drop it if a later ordinary navigation chooses elsewhere.
        if pendingNavigation == nil,
            let deferred = deferredTemplateCursorLanding,
            !BaseExactIdentity.matches(path, deferred.path)
        {
            deferredTemplateCursorLanding = nil
        }
        // Same file re-selected → no-op. This guard matters
        // because the dirty-state rollback below writes
        // `selectedFilePath = loadedFilePath` to re-highlight the
        // unsaved file in the sidebar, which re-triggers this
        // subscription with `path == loadedFilePath`. Without the
        // guard, the rollback would clear and reload the file the
        // user is still editing, blowing away the dirty buffer
        // we're trying to preserve.
        if let loaded = loadedFilePath,
            BaseExactIdentity.matches(path, loaded)
        {
            return
        }
        // U1-2 (#454): re-entrancy guard — `activateTab` drives the funnel
        // itself and updates `selectedFilePath` as a mirror; the sink must
        // not run the funnel a second time on that assignment.
        if isActivatingTab { return }
        if let loaded = loadedFilePath,
            !BaseExactIdentity.matches(path, loaded),
            let reason = inFlightNavigationDisabledReason
        {
            postMutationAnnouncement(reason)
            DispatchQueue.main.async { [weak self] in
                guard let self,
                    !BaseExactIdentity.matches(self.selectedFilePath, loaded)
                else { return }
                self.selectedFilePath = loaded
            }
            return
        }
        // U1-2: a selection naming a path that is already open as ANOTHER
        // tab in the active group is a tab switch, not a navigation —
        // route through the tab funnel (snapshot/restore, no dirty gate:
        // each tab keeps its own dirty buffer; that is the point of tabs).
        if let path,
            let incomingTab = workspace.activeGroupTab(forPath: path),
            incomingTab.id != workspace.model.activeGroup.activeTabID {
            activateTab(incomingTab.id)
            return
        }
        let propertyRecoverySurvivesElsewhere: Bool = {
            guard let loaded = loadedFilePath,
                let activeID = workspace.model.activeGroup.activeTabID
            else { return false }
            return hasOtherMarkdownTab(for: loaded, excluding: activeID)
        }()
        if let loaded = loadedFilePath,
            !BaseExactIdentity.matches(path, loaded),
            hasAuthoredPropertyPublicationRecovery(for: loaded),
            !propertyRecoverySurvivesElsewhere
        {
            postMutationAnnouncement(
                "Resolve the saved property update awaiting verification in \(filename(of: loaded)) before replacing its final tab. Copy the retained update, reapply it, or use the current version.")
            DispatchQueue.main.async { [weak self] in
                guard let self,
                    !BaseExactIdentity.matches(self.selectedFilePath, loaded)
                else { return }
                self.selectedFilePath = loaded
            }
            return
        }
        // Milestone T/N: non-markdown selections reaching the sink (e.g.
        // a direct selectedFilePath write) reroute to their document arms —
        // never the note loader. This lives below the final-owner recovery
        // guard because these arms replace the current tab in place.
        if let path, path.lowercased().hasSuffix(".canvas") {
            openCanvasFile(
                path,
                target: .currentTab,
                advancesSidebarSelectionRevision: false)
            return
        }
        if let path, path.lowercased().hasSuffix(".base") {
            openBaseFile(
                path,
                target: .currentTab,
                advancesSidebarSelectionRevision: false)
            return
        }
        // Dirty-state gate (issue #63): switching files while the
        // editor has unsaved changes must not silently drop the
        // user's edits. Park the requested destination in
        // `pendingNavigation` and let the "Save changes?" alert
        // route the actual transition.
        //
        // U1-5 refinement: when the dirty buffer's file is ALSO open in
        // another tab, replacing THIS tab's item cannot lose the edits —
        // the sibling tab holds the same buffer (parked snapshots are
        // mirrored on every keystroke). No prompt in that case.
        let dirtyBufferSurvivesElsewhere =
            loadedFilePath.map { loaded in
                workspace.model.allTabs.filter { tab in
                    guard case .markdown(let candidate) = tab.item else {
                        return false
                    }
                    return BaseExactIdentity.matches(candidate, loaded)
                }.count > 1
            } ?? false
        if hasUnsavedChanges,
            !BaseExactIdentity.matches(path, loadedFilePath),
            !dirtyBufferSurvivesElsewhere
        {
            pendingNavigation = .selectFile(path)
            // Roll the selection back so the file list re-highlights
            // the dirty file while the alert is up. The async hop is
            // required because we're inside the `$selectedFilePath`
            // willSet/sink chain: a synchronous write here would be
            // overwritten by the outer assignment once the willSet
            // returns. Dispatching to the next main-loop tick lets
            // the outer write finish, then our rollback takes
            // effect; the same-file guard at the top of this method
            // short-circuits the re-entry triggered by the rollback.
            if let loaded = loadedFilePath {
                DispatchQueue.main.async { [weak self] in
                    guard let self else { return }
                    if !BaseExactIdentity.matches(self.selectedFilePath, loaded) {
                        self.selectedFilePath = loaded
                    }
                }
            }
            return
        }
        if let loaded = loadedFilePath,
            hasPropertyPublicationUncertainty(for: loaded),
            !hasAuthoredPropertyPublicationRecovery(for: loaded),
            !hasDirtyNoteRecovery(for: loaded),
            !dirtyBufferSurvivesElsewhere
        {
            // Replacing the final tab owner is equivalent to closing it: the
            // already-committed property version will be read normally on a
            // future open, and leaving a hidden marker would globally disable
            // structural commands with no Reload control on screen.
            clearCloseSafeBulkPropertyPublicationVerification(for: loaded)
        }
        // U1-2: park the outgoing tab's buffer BEFORE the teardown below
        // clears the fields. No-ops when nothing is loaded (guards inside).
        parkPropertiesSourceDraftForTransition()
        workspace.snapshotActiveTab(
            text: currentNoteText, baseline: savedBaselineText,
            contentHash: currentNoteContentHash,
            hasUnsavedChanges: hasUnsavedChanges,
            saveError: saveError, saveConflict: currentSaveConflict,
            loadedFilePath: loadedFilePath,
            fmSource: currentNoteFMSource,
            bodyByteOffset: bodyByteOffset, bodyLineOffset: bodyLineOffset)
        // Same save-then-close scope rule as activateTab (Codoki #492):
        // replacing the active tab's item in place also ends the scope —
        // the pending close would otherwise target a different document.
        pendingTabCloseAfterSave = nil
        cancelNoteScopedWork()
        clearActiveNoteFields()
        // Workspace model update (U1-4 mirror; tab switches took the
        // `activateTab` early-return above). Below the dirty gate on
        // purpose: a parked navigation rolled back by the alert must never
        // surface in the workspace. Replaces the active tab's item, or
        // closes it on deselect.
        let replacedItem = workspace.activeTab?.item
        workspace.mirrorSingleSelection(path)
        releaseCanvasDocumentIfUnreferenced(replacedItem)
        releaseBaseDocumentIfUnreferenced(replacedItem)
        releaseDashboardDocumentIfUnreferenced(replacedItem)
        guard let path else {
            // Full clear when nothing is selected. Safe here because
            // there's no destination note to attribute stale content
            // to — and `closeVault` / explicit deselect callers expect
            // the panels to drop their contents synchronously.
            currentBacklinks = []
            currentOutgoingLinks = []
            currentOutgoingLinksPath = nil
            currentNoteProperties = []
            currentNoteEmbedResolutions = [:]
            pendingEmbedPreview = nil
            currentNoteTasks = []
            currentNoteMathBlocks = []
            currentNoteCodeBlocks = []
            currentNoteDiagramBlocks = []
            currentNoteCitations = []
        currentNoteCitationRefs = []
            expandedCitation = nil
            isLoadingNote = false
            isLoadingLinks = false
            isLoadingEmbeds = false
            isLoadingTasks = false
            isLoadingMathBlocks = false
            isLoadingCodeBlocks = false
            isLoadingDiagramBlocks = false
            return
        }
        // Note-to-note transitions: leave `currentBacklinks`,
        // `currentOutgoingLinks`, and `currentNoteProperties` holding
        // the previous selection's values until the new load resolves.
        // The previous shape cleared them synchronously, which made
        // the PropertiesPanel render `EmptyView` for the duration of
        // the load — a visible flicker for sighted users and a
        // disappear/reappear of the "Properties, N items" rotor item
        // for VoiceOver on every selection change (#90). The
        // race-cancel guard in `loadCurrentLinks` (selectedFilePath ==
        // path) ensures the newer task's writes win, so the user only
        // sees stale content for the duration of the IO — typically
        // a few milliseconds.
        //
        // Embeds are the exception (audit #203). Each cached
        // resolution carries the embedded note's full body text;
        // holding the prior file's resolutions during a transition
        // would briefly render the prior file's *content* inside
        // panels labelled as belonging to the new file. The window
        // is sub-second but uniquely confusing for embeds because
        // the stale data is whole notes, not one-liners. Clear
        // synchronously so the panel falls back to "not yet
        // resolved" placeholders until the new resolutions land.
        clearTransitionSensitiveCollections()
        restoreParkedOrLoadFromDisk(path: path)
        fireCollectionLoads(path: path)
        scheduleBasesDockFollowActiveRefresh()
    }

    /// Cancel every note-scoped in-flight task (loads + after-save
    /// refreshes). Shared by the selection funnel and `activateTab`.
    /// Comment history: #421 cursor park; audit #257 M1 orphaned pipelines;
    /// red-team M1+M2 refresh-task cancellation.
    func cancelNoteScopedWork() {
        noteLoadTask?.cancel()
        noteLoadTask = nil
        // #421: a pending {{cursor}} park belongs to the note that
        // requested it — never let it ride into a different note.
        clearPendingCursorByteOffset()
        linksLoadTask?.cancel()
        linksLoadTask = nil
        // Codex round 6: the embeds + citations legs were missing from
        // this list. Active-note DELETION retains `selectedFilePath`
        // for the missing-file tab, so an uncancelled in-flight leg
        // still passes its `selectedFilePath == path` guard and could
        // publish resolutions/citations for the deleted note beside
        // the error tab. (The embeds entry guard's isCancelled check
        // is what this cancellation arms.)
        embedsLoadTask?.cancel()
        embedsLoadTask = nil
        citationsLoadTask?.cancel()
        citationsLoadTask = nil
        tasksLoadTask?.cancel()
        tasksLoadTask = nil
        // Audit #257 M1: orphaned content-pipeline tasks would otherwise
        // keep grabbing the session mutex after the user switched files.
        mathBlocksLoadTask?.cancel()
        mathBlocksLoadTask = nil
        codeBlocksLoadTask?.cancel()
        codeBlocksLoadTask = nil
        diagramBlocksLoadTask?.cancel()
        diagramBlocksLoadTask = nil
        // Red-team M1+M2: cancel pending refresh-after-save tasks too.
        mathBlocksRefreshTask?.cancel()
        mathBlocksRefreshTask = nil
        codeBlocksRefreshTask?.cancel()
        codeBlocksRefreshTask = nil
        diagramBlocksRefreshTask?.cancel()
        diagramBlocksRefreshTask = nil
    }

    /// Clear the active-note fields for a transition. Shared by the
    /// selection funnel and `activateTab`.
    func clearActiveNoteFields() {
        invalidateNoteAuthoringOwnership()
        // Preserve the view-owned source Binding synchronously before its
        // owner path disappears. SwiftUI's loaded-path onChange is a UI-state
        // synchronization belt, not the sole data-preservation boundary.
        parkPropertiesSourceDraftForTransition()
        clearMountedPropertiesSourceDraft()
        currentNoteText = nil
        savedBaselineText = nil
        currentNoteContentHash = nil
        currentNoteFMSource = ""
        bodyByteOffset = 0
        bodyLineOffset = 0
        propertiesSourceError = nil
        // #868: the menu-title mirror resets with the note — the widget
        // self-hides on `loadedFilePath == nil` WITHOUT firing its
        // `.onChange(of: isSourceMode)` (a removed view's onChange never
        // fires), so the transition funnel owns this edge.
        propertiesSourceShowing = false
        loadedFilePath = nil
        hasUnsavedChanges = false
        currentSaveConflict = nil
        saveError = nil
        currentNoteHeadings = []
        noteLoadError = nil
        linksLoadError = nil
        tasksLoadError = nil
    }

    /// Audit #203: resolved note embeds + content pipelines clear synchronously
    /// on transition (their cached payloads belong to the previous file).
    /// Rendered Base embeds use weak visibility leases because sibling panes
    /// can remain live; links/properties intentionally hold stale values until
    /// the new load lands (#90 anti-flicker discipline).
    func clearTransitionSensitiveCollections() {
        currentNoteEmbedResolutions = [:]
        releaseUnleasedBaseEmbedDocuments()
        // Drop any open embed-preview popover too — its target may
        // not exist in the new file's embed set.
        pendingEmbedPreview = nil
        currentNoteMathBlocks = []
        currentNoteCodeBlocks = []
        currentNoteDiagramBlocks = []
        currentNoteCitations = []
        currentNoteCitationRefs = []
        expandedCitation = nil
    }

    /// U1-2 restore path: a previously-activated tab restores its parked
    /// buffer instead of re-reading disk; headings refresh through the
    /// after-save path (index read, no file read). A parked stale
    /// `contentHash` is safe by construction — the next save's conflict
    /// detection compares it against disk, exactly as for a long-open note.
    private func restoreParkedOrLoadFromDisk(path: String) {
        if let activeTabID = workspace.model.activeGroup.activeTabID,
            let parked = workspace.document(for: activeTabID),
            parked.hasLoaded,
            BaseExactIdentity.matches(parked.path, path)
        {
            currentNoteText = parked.text
            savedBaselineText = parked.savedBaselineText
            currentNoteContentHash = parked.contentHash
            currentNoteFMSource = parked.fmSource
            bodyByteOffset = parked.bodyByteOffset
            bodyLineOffset = parked.bodyLineOffset
            _ = restoreParkedPropertiesSourceDraft(
                for: path,
                authoritativeFrontmatterSource: parked.fmSource)
            loadedFilePath = path
            hasUnsavedChanges = parked.hasUnsavedChanges
            saveError = parked.saveError
            currentSaveConflict = parked.saveConflict
            isLoadingNote = false
            if parked.isMissingFromDisk {
                let name = (path as NSString).lastPathComponent
                noteLoadError =
                    "\(name) was moved to Trash and is no longer available."
            } else {
                noteLoadError = nil
            }
            if !parked.isMissingFromDisk, let session = currentSession {
                refreshHeadingsAfterSave(session: session, path: path)
            }
        } else {
            noteLoadTask = Task { [weak self] in
                await self?.loadCurrentNote(path: path)
            }
        }
    }

    /// The per-note collection fan-out (links → embeds chain, tasks, math,
    /// code, diagrams, citations). Shared by the selection funnel and
    /// `activateTab`; every loader carries its own race guard.
    private func fireCollectionLoads(path: String) {
        // Codex round 5: cancel the previous fan-out before replacing
        // it. The per-loader race guards drop stale RESULTS, but a
        // dropped chain still had side effects — the old links leg
        // chained a fresh embeds task even when its own result was
        // rejected, and that late orphan could flip isLoadingEmbeds
        // AFTER the newer chain had already finished, stranding the
        // flag with no newer task left to clear it. Cancellation (plus
        // the chain gate and the embeds entry guard below) closes the
        // set-after-newer-finished window. `scheduleHistoryLoad`
        // serializes itself and is left alone.
        linksLoadTask?.cancel()
        embedsLoadTask?.cancel()
        tasksLoadTask?.cancel()
        mathBlocksLoadTask?.cancel()
        codeBlocksLoadTask?.cancel()
        diagramBlocksLoadTask?.cancel()
        citationsLoadTask?.cancel()
        linksLoadTask = Task { [weak self] in
            await self?.loadCurrentLinks(path: path)
            // Codex round 5: a cancelled links leg must not chain an
            // embeds leg — its result was dropped, and the chain it
            // would spawn is exactly the orphan described above.
            guard !Task.isCancelled else { return }
            // Chain the embed-resolution load on after links — we
            // need the outgoing-links query result (specifically
            // `is_embed = true` rows) before we know what to resolve.
            // Assign to `embedsLoadTask` so tests + future
            // cancellation paths have a handle on this leg
            // independently of the parent links load (audit #204
            // caught the missing assignment).
            let embedsTask: Task<Void, Never> = Task { [weak self] in
                await self?.loadCurrentNoteEmbedResolutions(path: path)
            }
            await MainActor.run { [weak self] in
                self?.embedsLoadTask = embedsTask
            }
            await embedsTask.value
        }
        tasksLoadTask = Task { [weak self] in
            await self?.loadCurrentNoteTasks(path: path)
        }
        // Content pipelines (#223): math + code + diagram fan out
        // in parallel after the selection lands. They don't depend
        // on links or each other; running concurrently keeps the
        // post-selection latency down. Each loader carries its own
        // race-guard (selectedFilePath == path) so a fast switch
        // can't write stale state.
        mathBlocksLoadTask = Task { [weak self] in
            await self?.loadCurrentNoteMathBlocks(path: path)
        }
        codeBlocksLoadTask = Task { [weak self] in
            await self?.loadCurrentNoteCodeBlocks(path: path)
        }
        diagramBlocksLoadTask = Task { [weak self] in
            await self?.loadCurrentNoteDiagramBlocks(path: path)
        }
        // History leaf (O-5, #543): version list + the pref-gated
        // since-open funnel (compute-then-mark), strictly serialized
        // behind any in-flight load (round 2 — see
        // scheduleHistoryLoad).
        scheduleHistoryLoad(path: path)
        // Milestone L (#279): citations for the current note. Same
        // fan-out shape — race-guarded by selectedFilePath == path
        // inside the loader.
        citationsLoadTask = Task { [weak self] in
            await self?.loadCurrentNoteCitations(path: path)
        }
    }

    /// Ask the content pane to scroll to the given heading anchor.
    /// Sent by `OutlineSidebar` rows; `NoteContentView` subscribes via
    /// `onReceive(scrollAnchorRequest)`.
    func requestScrollToHeading(anchor: String) {
        scrollAnchorRequest.send(anchor)
    }

    /// Activate a search result row from `SearchOverlay`.
    ///
    /// 1. Set `selectedFilePath` (which kicks off the regular note-
    ///    load observer).
    /// 2. Close the overlay so the content area gets focus.
    /// 3. Await the in-flight note-load so the per-line anchors are
    ///    in the rendered tree before we ask `ScrollViewReader` to
    ///    target one.
    /// 4. Send the line-scroll request.
    /// 5. Post a polite announcement with filename + line +
    ///    snippet — matches the acceptance criteria's
    ///    `"Opened <filename>, line N: <snippet>"`.
    ///
    /// If the path is the SAME file already open, we skip the
    /// selection assignment (the load observer wouldn't re-trigger
    /// the load anyway because of `.removeDuplicates()`) but still
    /// scroll and announce.
    func openSearchResult(_ hit: QueryHit) {
        let cleanSnippet = hit.snippet
            .replacingOccurrences(of: "\u{2}", with: "")
            .replacingOccurrences(of: "\u{3}", with: "")
        let filename = (hit.path as NSString).lastPathComponent
        // The query that PRODUCED the displayed rows, captured at result
        // time (`lastResultsQuery`) — NOT the live field. #876 Codex
        // round 1: the 150 ms debounce leaves the previous query's rows
        // visible while `searchQuery` already holds a newer string; the
        // row the user activated belongs to `lastResultsQuery`, so both
        // the line-scroll anchor AND the recorded recent must use it (the
        // `?? searchQuery` is a defensive fallback — row activation always
        // implies a `.results` panel, which sets `lastResultsQuery`).
        let queryForRow = lastResultsQuery ?? searchQuery
        let queryForLineLookup = queryForRow

        // #876: activating a result is the commit signal that a query
        // was useful — remember it before `closeSearchOverlay()` (which
        // preserves `searchQuery`, so order is not load-bearing) so the
        // idle overlay can offer it next time. Record the PRODUCING query
        // (`queryForRow`), not the live field (Codex round 1).
        recordSearchRecent(queryForRow)

        // Close the overlay first so focus moves cleanly back to
        // the content area before the file load completes.
        closeSearchOverlay()

        // U1-5: honor a live ⌘ modifier (row ⌘-click or ⌘Return through
        // the overlay's key monitor — both leave NSApp.currentEvent set).
        let target = openTargetFromCurrentEvent()
        let wasAlreadyOpen =
            BaseExactIdentity.matches(selectedFilePath, hit.path)
            && target == .currentTab
        if wasAlreadyOpen {
            recordExplicitSidebarNavigationIntent()
        } else {
            openFile(hit.path, target: target)
        }
        // Snapshot the in-flight load up front so the Task closure
        // doesn't have to reach back through `self?.` before its
        // strong-unwrap guard — that pre-guard `self?` access was
        // tripping Codoki's weak-self lint on PR 98 even though the
        // post-await `guard let self` correctly shadow-unwraps. The
        // Task reference outlives `self` cleanly if AppState
        // dealloc's during scheduling; we just await whatever load
        // was pending.
        let pendingLoad = noteLoadTask

        Task { @MainActor [weak self] in
            // Wait for any in-flight note load to finish so the
            // per-line anchors exist in the rendered tree before
            // we ask `ScrollViewReader.scrollTo` to target one.
            // For the same-file case the snapshot is nil and this
            // await is skipped.
            if let pendingLoad {
                await pendingLoad.value
            }
            guard let self else { return }
            // A subsequent selection change (the user moved to a
            // different file while we were waiting) cancels this
            // scroll — sending into the subject would land on the
            // wrong file's anchors.
            guard BaseExactIdentity.matches(self.selectedFilePath, hit.path)
            else { return }
            // Derive the line UI-side from the loaded body. Up
            // through PR 94 this came back on the QueryHit, but
            // computing it Rust-side meant pulling `body_text`
            // through SQLite for every hit (#92 item 1). The body
            // is loaded anyway by the time we get here, so we
            // tokenize the original query and scan for the first
            // match — same heuristic the Rust side used.
            let body = self.currentNoteText ?? ""
            let line = firstTokenLineNumber(in: body, query: queryForLineLookup)
            self.lineScrollRequest.send(line)
            // U3-3: the buffer (and thus `line`) is body-space; humans and
            // on-disk tooling count whole-file lines — announce THOSE.
            postAccessibilityAnnouncement(
                "Opened \(filename), line \(self.fileLine(fromBodyLine: line)): \(cleanSnippet)"
            )
            self.lastActivatedSearchResultLine = line
            self.lastActivatedSearchResultPath = hit.path
        }
    }

    /// Activate an outgoing-link row from the OutgoingLinksPanel.
    ///
    /// - Resolved internal: navigate to the target and announce the
    ///   filename. (The subsequent "Showing <filename>" announcement
    ///   from `NoteContentView.onAppear` rounds out the audio
    ///   feedback once the content has actually loaded.)
    /// - Unresolved internal: don't navigate; announce that we
    ///   couldn't open it so a screen-reader user doesn't think the
    ///   click was a no-op.
    /// - External: hand off to NSWorkspace; announce that the browser
    ///   was invoked.
    ///
    /// The branch chosen is also reflected in `lastActivatedLinkOutcome`
    /// so tests can verify behaviour without observing UIKit/AppKit
    /// side effects.
    func openLink(_ link: OutgoingLink) {
        if link.isExternal {
            // Allowlist the schemes we hand to LaunchServices. The
            // link parser flags `file:`, `javascript:`, and custom
            // schemes as external too, but blindly passing them to
            // NSWorkspace.open would let a typo in a markdown link
            // hand control of the user's machine to whatever app
            // happens to be registered for that scheme. http/https
            // (web pages) and mailto (compose new email) are the
            // schemes a notes app's "external link" feature is
            // expected to handle.
            guard let url = URL(string: link.targetRaw),
                let scheme = url.scheme?.lowercased(),
                ["http", "https", "mailto"].contains(scheme)
            else {
                postAccessibilityAnnouncement(
                    "Cannot open external link \(link.targetRaw). "
                        + "Only web and mail links are supported."
                )
                lastActivatedLinkOutcome = .externalOpenFailed(link.targetRaw)
                return
            }
            if externalOpener(url) {
                postAccessibilityAnnouncement(
                    "Opened external link in default browser."
                )
                lastActivatedLinkOutcome = .openedExternal(link.targetRaw)
            } else {
                postAccessibilityAnnouncement(
                    "Could not open external link \(link.targetRaw)."
                )
                lastActivatedLinkOutcome = .externalOpenFailed(link.targetRaw)
            }
            return
        }
        if link.isUnresolved {
            postAccessibilityAnnouncement(
                "\(link.targetRaw) is unresolved. Cannot open."
            )
            lastActivatedLinkOutcome = .unresolved(link.targetRaw)
            return
        }
        guard let path = link.targetPath else {
            // Defensive: a non-external, non-unresolved row should
            // always carry a target_path. Treat the impossible case
            // as unresolved so the user gets feedback instead of
            // silence.
            postAccessibilityAnnouncement(
                "\(link.targetRaw) is unresolved. Cannot open."
            )
            lastActivatedLinkOutcome = .unresolved(link.targetRaw)
            return
        }
        navigate(to: path, kind: "Opened", target: openTargetFromCurrentEvent())
    }

    /// The repository README URL the Help utility opens (gap G13). Small,
    /// honest, replaceable: Help has no dedicated in-app surface, so the
    /// utility bar's "Help" button hands this URL to the same external-open
    /// path (`externalOpener`, → `NSWorkspace` in production) that outgoing
    /// links use. `static` so a test can assert the exact URL a recording
    /// `externalOpener` received without reaching into a running view.
    static let helpURL = URL(string: "https://github.com/coryj627/slate#readme")!

    /// Open the repository README in the user's default browser (U4-3, #472;
    /// gap G13). Routed through `externalOpener` — the same injected hand-off
    /// the outgoing-links panel uses — so tests spy on it with a recording
    /// closure instead of spawning a browser, and the announcement mirrors the
    /// external-link path so a screen-reader user hears the hand-off. Surfaced
    /// both here (the `SidebarUtilityBar` "Help" button) and in the command
    /// registry as `slate.help.open` — one implementation, two entry points.
    func openHelp() {
        if externalOpener(Self.helpURL) {
            postAccessibilityAnnouncement(
                "Opened Help in your default browser."
            )
            lastActivatedLinkOutcome = .openedExternal(Self.helpURL.absoluteString)
        } else {
            postAccessibilityAnnouncement(
                "Could not open Help."
            )
            lastActivatedLinkOutcome = .externalOpenFailed(Self.helpURL.absoluteString)
        }
    }

    /// Activate a backlink row from the BacklinksPanel — navigates
    /// to the source file that linked here. Backlinks are always
    /// resolved (the query joins on resolved target_path), so this
    /// is the simple `navigate(to:)` path.
    func openBacklink(_ backlink: Backlink) {
        navigate(
            to: backlink.sourcePath, kind: "Opened backlink to",
            target: openTargetFromCurrentEvent())
    }

    /// Shared post-activation step: update `selectedFilePath` (which
    /// the file-list selection binding + the note-load observer both
    /// pick up) and post an immediate audio confirmation so the user
    /// hears that the click worked before the content load finishes.
    private func navigate(
        to path: String, kind: String, target: OpenTarget = .currentTab
    ) {
        openFile(path, target: target)
        let filename = (path as NSString).lastPathComponent
        // #424 (F-C1): .high — the selection change this just
        // triggered posts its own announcements ("Showing <file>.",
        // "Outline, N headings.") which superseded this medium one
        // before VO spoke it; the VO test heard ONLY the indirect
        // outline cue. High priority makes the activation
        // confirmation win; the outline count then follows with the
        // structure info.
        postAccessibilityAnnouncement("\(kind) \(filename).", priority: .high)
        lastActivatedLinkOutcome = .openedInternal(path)
    }

    var isVaultOpen: Bool { currentSession != nil }

    static let importNativeMoveVaultTransitionReason =
        "The vault stayed open. Wait for the in-vault move to finish, then try again."

    @discardableResult
    private func rejectVaultTransitionDuringNativeImport() -> Bool {
        guard currentImportBatchOwner != nil,
            importBatchProgress?.phase == .moving
        else { return false }
        pendingVaultSwitchTarget = nil
        announceNextOpenAfterClose = false
        sidebarActionBackgroundFailure =
            Self.importNativeMoveVaultTransitionReason
        postMutationAnnouncement(Self.importNativeMoveVaultTransitionReason)
        return true
    }

    func openVault(at url: URL) {
        guard !rejectVaultTransitionDuringNativeImport() else { return }
        if isVaultOpen, let reason = authoredPropertyPublicationRecoveryReason {
            postMutationAnnouncement(reason)
            return
        }
        if isVaultOpen, let reason = inFlightDraftDiscardDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        // `openVault(at:)` is also the lower-level open-document handoff used
        // by AppKit. When A is already open it must honor the same dirty close
        // transaction as Open Recent and the folder picker; replacing the
        // session directly would silently clear every authoring surface.
        if isVaultOpen, !dirtyVaultClosePaths().isEmpty {
            switchToRecent(RecentVault(url: url))
            return
        }
        cancelPendingNavigationSave()
        // MainSplitView posts the initial open announcement when the newly
        // mounted interface is ready. It stays mounted during a direct A→B
        // switch, so remember that case and announce it here after B is fully
        // installed instead of relying on a second onAppear that never occurs.
        let replacesOpenVault = isVaultOpen || announceNextOpenAfterClose
        announceNextOpenAfterClose = false
        resetSidebarMetadataRefresh()
        resetSidebarVaultPreferencesRetry()
        // A direct vault switch does not route through `closeVault`; clear the
        // old vault's store/notice up front so a failed open cannot leave stale
        // warnings or a writer targeting the previous root.
        sidebarVaultPrefsStore = nil
        sidebarVaultPrefsNotice = nil
        resetSidebarOrganizationState()
        // Commit the old operation lifecycle before attempting the new open.
        // Both success and either catch path replace/clear `currentSession`, so
        // provider progress, Task 3 work, and structural-token ownership must
        // be cancelled first in every case.
        cancelCurrentImportBatchForVaultTransition()
        cancelStructuralMutationOwnership()
        do {
            let session = try VaultSession.openFilesystem(rootPath: url.path)
            // Audit #259: push the persisted math prefs into the
            // fresh session so a user who set ClearSpeak → MathSpeak
            // in a prior run gets MathSpeak from the very first
            // `get_math_blocks` call. The Rust-side session opens
            // with defaults; without this the prefs would only take
            // effect after the first Picker interaction.
            do {
                try session.setMathPrefs(prefs: mathPrefs)
            } catch {
                fputs(
                    "Slate: initial session.setMathPrefs failed: \(error)\n",
                    stderr
                )
            }
            // History leaf (O-5, #543): register the compaction-error
            // channel before anything can compact. The adapter hops to
            // the main actor; the once-per-path gate lives there.
            registerVaultEventListener(on: session)
            // Drop document handles while `currentSession` still names the
            // previous vault. Calling close on the freshly-opened session
            // would pair old native handles with the wrong registry.
            resetBaseRefreshTasksForVaultTransition()
            releaseAllCanvasDocuments()
            releaseAllBaseDocuments()
            releaseAllBaseEmbedDocuments()
            releaseAllDashboardDocuments()
            // A directly reopened vault replaces the operation lifecycle too.
            // Cancel/reset before installing the new session so an old task
            // resuming later cannot own the new vault's saving/editing flags.
            cancelVaultCloseSaveAll()
            cancelSaveOwnership()
            cancelPropertyEditOwnership()
            cancelSidebarActionValidation()
            invalidateSidebarWikilinkCopy()
            dismissAddPropertySheet()
            currentPropertyEditConflict = nil
            propertyEditError = nil
            // A direct A→B open bypasses `closeVault`. Tear down A's active
            // note while its workspace still owns the buffer, before the
            // vault-scoped recovery registries and tabs are reset below.
            // Relying on `selectedFilePath = nil` is unsafe here: its normal
            // selection funnel is dirty-gated and can roll back to A's path,
            // allowing an equal relative path in B to inherit A's text.
            cancelNoteScopedWork()
            clearActiveNoteFields()
            resetVaultScopedPropertyRecovery()
            // #876 Codex round 2: Open Vault / Open Recent reach here
            // WITHOUT `closeVault`, so vault A's live search must be torn
            // down too — else the still-open overlay shows A's results
            // while `currentVaultURL`/`searchRecentsStore` now name B, and
            // activating a stale A row would persist A's query into B's
            // per-vault recents and try to open A's path inside B. Mirror
            // closeVault's teardown (closeSearchOverlay cancels the
            // in-flight search and resets searchState + lastResultsQuery;
            // clear the retained query), and do it while `currentSession`
            // still names A so the cancellation targets A's search. The
            // per-vault `searchRecents` load below then reflects B.
            closeSearchOverlay()
            searchQuery = ""
            resetTemplateLifecycleForVaultTransition()
            invalidateNoteAuthoringOwnership()
            currentSession = session
            currentVaultURL = url
            sidebarSelectionSnapshot = SidebarSelectionSnapshot(
                sessionIdentity: ObjectIdentifier(session),
                items: [],
                focusedPath: nil,
                creationParent: "")
            lastError = nil
            loadSidebarVaultPreferences(at: url)
            // Round-25, hardened round-27: the sidebar admission identity
            // (fstat on the store's own root descriptor) must match the
            // identity the SESSION itself observed inside its open, exposed
            // through the FFI. Comparing against the session's own anchor —
            // not another path resolution — closes the A→B→A replacement
            // race a path bracket cannot see. A session or admission that
            // observes no identity cannot prove the surfaces share one
            // root: abort those too.
            let sessionRootIdentity = session.rootIdentity().map {
                SidebarVaultRootIdentity(device: $0.device, inode: $0.inode)
            }
            if sessionRootIdentity == nil
                || sidebarVaultRootIdentity != sessionRootIdentity
            {
                tearDownVaultScopedStateForAbortedOpen()
                throw VaultOpenIdentityRaceError()
            }
            // Load this vault's file-recents (#495) now that the store's
            // vault path resolves. Per-vault, so it's repopulated on
            // every vault switch; a missing / malformed file loads empty.
            fileRecents = fileRecentsStore?.load() ?? []
            // #876: likewise this vault's recent search queries — per-
            // vault, so the overlay's idle "Recent Searches" reflects the
            // vault the user is actually in.
            searchRecents = searchRecentsStore?.load() ?? []
            // Reset file-list state so the previous vault's contents
            // don't briefly flash in the new vault's sidebar.
            files = []
            scanError = nil
            // M-3 (#534): likewise the previous vault's sync report —
            // nil puts the diagnostics panel back into its loading
            // state until this vault's post-scan load publishes.
            // #638: and the previous vault's marker watcher, so a late
            // debounced event can't fire a refresh under the new vault
            // (the load-side session guard would catch it anyway —
            // this just stops the noise at the source).
            stopSyncMarkerWatcher()
            syncReport = nil
            liveSyncConfig = nil
            syncDiagnosticsError = nil
            // Connections leaf (P1-1 #554): clear any prior vault's root
            // / back-stack / payload before the new vault populates
            // (review round 1 finding 3).
            resetConnectionsState()
            // Graph tab table (P1-2 #555): same cross-vault isolation.
            resetGraphTableState()
            // Graph tab diagram (P2-3 #559): tear down the layout session too.
            resetGraphDiagramState()
            // Graph config (P2-4 #560): EAGERLY load the new vault's
            // graph.json now — `currentVaultURL` already names it (set
            // above). Loading here (not lazily on first Graph-tab open)
            // means `graphConfig`/`connectionsDepth` always match the
            // current vault, so a Connections-depth edit BEFORE the Graph
            // tab is ever opened can't persist vault A's stale aggregate
            // into vault B (review finding 1). A pending debounced save
            // still targets the OLD vault via its captured root and is NOT
            // cancelled here, so no edit is lost (review finding 3).
            loadGraphConfig()
            // #871: the structural (file-op) undo/redo stacks are per-vault —
            // a direct Open Vault / Open Recent reaches here WITHOUT
            // `closeVault`, so an inverse move/rename staged against vault A
            // must not survive into vault B (it would move/rename the wrong
            // file). Same reasoning as the fileRecents/searchRecents/graph
            // resets in this block.
            clearStructuralUndoStacks()
            // #871 Codex round 2: INVALIDATE + release the structural-mutation
            // guard. A move/rename/import in flight when the vault switches
            // would otherwise leave `isMutatingStructure` stuck true (its
            // completion returns early on the `currentSession === session`
            // mismatch, before the release) — wedging every later structural op
            // in the new vault. Clearing the flag un-wedges; BUMPING the
            // ownership token (via `cancelStructuralMutationOwnership`) makes a
            // stale completion that already passed its session guard and then
            // suspended in `loadFiles` a no-op, so it can't clear a NEWER
            // vault's op flag on resume.
            // #879 Codex red-team: the vault-wide Tasks Review surface must
            // die with the previous vault too — direct Open Vault routes
            // here without `closeVault`, so a stale review would survive and
            // its reload guards would reject re-querying the new vault.
            resetVaultTasksReviewState()
            // U1-2: tabs belong to a vault; a fresh open starts clean (and
            // must reset BEFORE the selection clear so the funnel doesn't
            // park the previous vault's buffer).
            workspace.reset()
            pendingTabClose = nil
            pendingTabCloseAfterSave = nil
            selectedFilePath = nil
            // Codex review (corpus PR): the tree-selection mirror must
            // die with the vault — Reveal in Finder / Copy Path read it,
            // and a stale vault-A node would resolve against vault B's
            // root (cross-vault path leak).
            treeSelectedNode = nil
            // #873: vault A's expansion ids must not leak into vault B —
            // reset before restoreWorkspaceLayout refills from B's snapshot.
            treeExpandedDirPaths = []
            // #860: a staged folder-delete confirmation belongs to the old
            // vault's tree; drop it so the alert can't fire cross-vault.
            pendingFolderDelete = nil
            // #852: the batch move sheet / batch delete confirmation are tied
            // to the old vault's selection — drop them for the same reason.
            pendingMove = nil
            pendingBatchMove = nil
            pendingBatchDelete = nil
            renamingNode = nil
            structuralRenameError = nil
            resetBatchAlertPresentations()
            scanProgress = nil
            scanAnnouncementCount = 0
            scanAnnouncementLastMessage = nil
            scanAnnouncementLastFiredAt = .distantPast
            bibliographyLoadCount = 0
            recordOpened(url: url)
            // U1-6 (#458): restore the persisted workspace layout. Tabs
            // load lazily; a missing file surfaces the existing per-tab
            // load-error state rather than being dropped.
            restoreWorkspaceLayout()
            refreshBaseQueries()
            scanTask?.cancel()
            scanTask = Task { [weak self] in
                await self?.loadFiles()
                guard !Task.isCancelled else { return }
                self?.refreshBaseQueries()
                // M-3 (#534): sync diagnostics, once per vault open —
                // the post-scan continuation. The probes don't touch
                // the index, so this runs even when the scan itself
                // errored; a vault switch cancels this task and the
                // new vault's funnel runs its own load.
                guard !Task.isCancelled else { return }
                // #638: arm the live marker watch BEFORE the initial
                // probe and AWAIT readiness — `start()` returns only
                // once the fds are open. Arm-then-probe means a marker
                // that appears after arming emits an event (debounced
                // refresh) while anything already present is caught by
                // the probe itself, with no setup-race window
                // (adversarial re-review). A vault switch cancels this
                // task; the awaited arm suspends without blocking main.
                await self?.startSyncMarkerWatcher()
                guard !Task.isCancelled else { return }
                await self?.loadSyncDiagnostics()
            }
            refreshTemplateAvailability()
            // Milestone L #281: read `.slate/prefs.json` so the
            // Settings panel + style picker reflect the persisted
            // configuration. If the file has a configured
            // bibliography, push it through `setBibliographySources`
            // so the session's `bibliography_entries` matches what
            // the user last saved.
            loadBibliographyPrefsFromDisk()
            let persistedPrefs = bibliographyPrefs
            if !persistedPrefs.sources.isEmpty {
                Task { [weak self] in
                    await self?.applyBibliographyPrefs(persistedPrefs)
                }
            } else {
                // #411: no app-written sources. The session's
                // EFFECTIVE config may carry vault-shipped sources
                // from the root slate.json — the Rust side already
                // applied the precedence rules (an explicit-empty
                // prefs.json bibliography masks the vault config, a
                // silent one falls through to it). Adopt without
                // persisting: prefs.json stays untouched until the
                // user edits in Settings, so the vault file remains
                // the live source of truth.
                Task { [weak self] in
                    await self?.adoptSessionCitationsConfig()
                }
            }
            if replacesOpenVault {
                announceDirectVaultSwitch(to: url)
            }
        } catch let error as VaultError {
            sidebarVaultPrefsStore = nil
            sidebarVaultPrefsNotice = nil
            resetSidebarOrganizationState()
            currentSession = nil
            currentVaultURL = nil
            sidebarSelectionSnapshot = nil
            lastError = humanReadable(error)
        } catch {
            sidebarVaultPrefsStore = nil
            sidebarVaultPrefsNotice = nil
            resetSidebarOrganizationState()
            currentSession = nil
            currentVaultURL = nil
            sidebarSelectionSnapshot = nil
            lastError = error.localizedDescription
        }
    }

    /// Round-26: an aborted mid-open (identity race) has already torn the
    /// previous vault's session handles down but has not yet run the
    /// switch's old-state resets, which normally happen after admission.
    /// Clear every vault-scoped surface the interrupted switch would have
    /// cleared so no stale rows, selections, watchers, or scans survive
    /// into the Welcome screen.
    private func tearDownVaultScopedStateForAbortedOpen() {
        scanTask?.cancel()
        scanTask = nil
        files = []
        scanError = nil
        stopSyncMarkerWatcher()
        syncReport = nil
        liveSyncConfig = nil
        syncDiagnosticsError = nil
        resetConnectionsState()
        resetGraphTableState()
        resetGraphDiagramState()
        clearStructuralUndoStacks()
        resetVaultTasksReviewState()
        workspace.reset()
        pendingTabClose = nil
        pendingTabCloseAfterSave = nil
        selectedFilePath = nil
        treeSelectedNode = nil
        treeExpandedDirPaths = []
        pendingFolderDelete = nil
        pendingMove = nil
        pendingBatchMove = nil
        pendingBatchDelete = nil
        renamingNode = nil
        structuralRenameError = nil
        resetBatchAlertPresentations()
        scanProgress = nil
        scanAnnouncementCount = 0
        scanAnnouncementLastMessage = nil
        scanAnnouncementLastFiredAt = .distantPast
        bibliographyLoadCount = 0
    }

    /// Round-25: the root observed just before the session opened and the
    /// root the sidebar store admitted (descriptor-bound) disagree — the
    /// directory was swapped mid-open, so the open aborts as a whole.
    private struct VaultOpenIdentityRaceError: LocalizedError {
        var errorDescription: String? {
            "The folder changed while it was being opened. Try opening the "
                + "vault again."
        }
    }

    /// Install and inspect the per-vault store once per successful open. Reads
    /// are bounded by the store's 2 MiB cap. The typed notice is included in
    /// whichever single open announcement owns this transition and remains
    /// visible in the sidebar until the vault closes.
    private func loadSidebarVaultPreferences(at vaultRoot: URL) {
        let store = sidebarVaultPrefsStoreFactoryForTesting?(vaultRoot)
            ?? SidebarVaultPrefsStore(vaultRoot: vaultRoot)
        // Round-24: content and root identity come from ONE root-descriptor
        // resolution inside the store — a same-path swap during open can no
        // longer pair one vault's preferences with another vault's identity.
        let admission = store.readForAdmission()
        let result = admission.result
        sidebarVaultPrefsStore = store
        sidebarVaultRootIdentity = admission.rootIdentity
        // FL-06 (round-5 finding 3): a KNOWN section with an unrecognized
        // top-level shape enters the same read-only recovery flow as
        // malformed JSON — a later write must never silently replace it.
        if result.notice == nil,
            !SidebarOrganizationSchema.knownSectionShapesAreValid(root: result.root)
        {
            sidebarVaultPrefsNotice = .malformed
        } else {
            sidebarVaultPrefsNotice = result.notice
        }
        // Round-30 (review #2): writes parked by a previous same-vault
        // session settle through a CHAINED drain whose snapshot is taken
        // at run time — after any surviving writer has landed its failure
        // — and before the refresh below republishes. Installed whenever
        // a surviving chain OR parked entries exist, so a reopen that
        // races the failing writer still consumes its parked intent.
        if sidebarVaultPrefsNotice == nil,
            let identity = sidebarVaultRootIdentity,
            Self.sidebarStoreWriterChains[identity] != nil
                || Self.sidebarUnflushedWriteRetries[identity]?.isEmpty
                    == false
        {
            scheduleSidebarRetainedWriteDrain()
        }
        // Round-16: a writer detached before a close/reopen of the SAME
        // vault may still be completing. Queue a silent post-drain refresh
        // so published state converges on whatever that writer committed.
        // Round-23/24: the refresh republishes disk content after the prior
        // writer drains — bind its read to THIS open's admitted identity,
        // look the prior chain up by that PHYSICAL identity (any alias of
        // the same vault shares one chain), and skip entirely when identity
        // was never captured (fail closed).
        if let refreshIdentity = sidebarVaultRootIdentity,
            let priorWriter = Self.sidebarStoreWriterChains[refreshIdentity]
        {
            let generation = sidebarOrganizationWriteGeneration
            let session = currentSession
            // The refresh is installed as the per-file chain TAIL (round-17):
            // a command issued after reopen queues behind IT, so the refresh
            // can neither read past a newer writer nor republish stale state
            // over that writer's tail publish.
            let refreshToken = UUID()
            let refreshTask = Task { [weak self] in
                defer {
                    Task { @MainActor in
                        if AppState.sidebarStoreWriterChainTokens[refreshIdentity]
                            == refreshToken
                        {
                            AppState.sidebarStoreWriterChains[refreshIdentity] = nil
                            AppState.sidebarStoreWriterChainTokens[refreshIdentity] =
                                nil
                            AppState.sidebarCommittedTransformIDs[refreshIdentity] =
                                nil
                        }
                    }
                }
                await priorWriter.value
                guard let self,
                    self.sidebarOrganizationWriteGeneration == generation,
                    self.currentSession === session,
                    self.sidebarVaultPrefsStore?.fileURL == store.fileURL
                else { return }
                let refreshed = await Task.detached(priority: .utility) {
                    store.read(expectedRootIdentity: refreshIdentity)
                }.value
                guard self.sidebarOrganizationWriteGeneration == generation,
                    self.currentSession === session
                else { return }
                // A replaced root publishes nothing (round-23).
                guard let refreshed else { return }
                var notice = refreshed.notice
                if notice == nil,
                    !SidebarOrganizationSchema.knownSectionShapesAreValid(
                        root: refreshed.root)
                {
                    notice = .malformed
                }
                if self.sidebarVaultPrefsNotice != notice {
                    self.sidebarVaultPrefsNotice = notice
                }
                // Round-25: a writable refresh must not publish PAST the
                // session's pending structural journal — a rename journaled
                // while the file was read-only would be stranded (its Retry
                // surface removed with the notice) and a later close would
                // discard it. Route this publish through a backlog drain:
                // it replays the journal under the store lock with
                // committed-ID dedupe, and its tail publishes decoded
                // post-replay disk truth. A standing notice keeps defaults
                // published and the journal parked for Retry.
                if notice == nil,
                    !self.sidebarStructuralTransformJournal.isEmpty
                {
                    try? self.mutateSidebarOrganization(
                        announce: nil,
                        apply: { _ in },
                        reflect: { _ in },
                        isBacklogDrain: true)
                    return
                }
                let organization: SidebarOrganizationState
                if notice == nil {
                    let decoded = SidebarOrganizationSchema.decode(
                        root: refreshed.root)
                    organization = SidebarOrganizationState(
                        prefs: decoded.prefs, pins: decoded.pins)
                } else {
                    organization = SidebarOrganizationState()
                }
                if organization != self.sidebarOrganization {
                    self.sidebarOrganization = organization
                }
            }
            Self.sidebarStoreWriterChains[refreshIdentity] = refreshTask
            Self.sidebarStoreWriterChainTokens[refreshIdentity] = refreshToken
        }
        // Adopt the vault's authored organization in the same step. Unsafe
        // input already resolved to the default root, so this can't
        // interpret unreadable data.
        sidebarPinPruneLedger.reset()
        let organization: SidebarOrganizationState
        if sidebarVaultPrefsNotice == nil {
            let decoded = SidebarOrganizationSchema.decode(root: result.root)
            organization = SidebarOrganizationState(
                prefs: decoded.prefs, pins: decoded.pins)
        } else {
            organization = SidebarOrganizationState()
        }
        if organization != sidebarOrganization {
            sidebarOrganization = organization
        }
    }

    /// Re-read a repaired `.slate/sidebar.json` without making the user close
    /// the vault. Bounded file I/O and JSON decoding stay off the main actor;
    /// one owned task coalesces repeated activations, while its generation
    /// prevents a cancelled old-vault read from publishing or clearing the
    /// replacement vault's state. Unsafe input remains untouched and keeps its
    /// typed recovery notice. Round-25: the whole read/replay/publish
    /// transaction holds the vault's ONE identity-keyed writer slot — a
    /// queued writer surviving close/reopen commits first, and writes
    /// issued after Retry queue behind it.
    @discardableResult
    func retrySidebarVaultPreferences() -> Task<Void, Never>? {
        guard sidebarVaultPrefsRetryTask == nil else {
            return nil
        }
        guard let store = sidebarVaultPrefsStore, let session = currentSession,
            // Round-23: Retry reads, replays the journal, and republishes —
            // all of which require PROVING the root is still the admitted
            // vault. A never-captured identity is uncertainty: do nothing,
            // keep the notice, the journal, and the published state.
            let retryIdentity = sidebarVaultRootIdentity
        else {
            return nil
        }
        sidebarVaultPrefsRetryGeneration &+= 1
        let generation = sidebarVaultPrefsRetryGeneration
        isRetryingSidebarVaultPreferences = true
        let previousWriter = Self.sidebarStoreWriterChains[retryIdentity]
        let chainToken = UUID()
        let task = Task { [weak self] in
            await previousWriter?.value
            let result = await Task.detached(priority: .userInitiated) {
                store.read(expectedRootIdentity: retryIdentity)
            }.value
            // The chain slot belongs to this task regardless of retry
            // generation or session lifetime — release it (and the drained
            // ledger) exactly as the mutate funnel does, BEFORE the self
            // guard so a dead session still retires the entry (round-31).
            defer {
                if Self.sidebarStoreWriterChainTokens[retryIdentity]
                    == chainToken
                {
                    Self.sidebarStoreWriterChains[retryIdentity] = nil
                    Self.sidebarStoreWriterChainTokens[retryIdentity] = nil
                    Self.sidebarCommittedTransformIDs[retryIdentity] = nil
                }
            }
            guard let self else { return }
            guard generation == self.sidebarVaultPrefsRetryGeneration else { return }
            defer {
                if generation == self.sidebarVaultPrefsRetryGeneration {
                    self.sidebarVaultPrefsRetryTask = nil
                    self.isRetryingSidebarVaultPreferences = false
                }
            }
            guard !Task.isCancelled,
                self.currentSession === session,
                self.sidebarVaultPrefsStore?.fileURL == store.fileURL
            else { return }
            // Round-23: a same-path replacement vault's file is not ours —
            // keep the notice, the journal, and the published state.
            guard let result else { return }

            // FL-06 (round-4 finding 2): structural transforms that happened
            // while the file was read-only replay under the store lock BEFORE
            // the repaired content republishes, so the outage cannot orphan
            // the file's pins/overrides against their renamed folders.
            var adoptedRoot = result.root
            var adoptedNotice = result.notice
            var retryDurabilityWarning: String?
            // Round-5 finding 3: a repaired file whose known sections use an
            // unrecognized top-level shape stays in recovery — the replay
            // must not write into it either.
            if adoptedNotice == nil,
                !SidebarOrganizationSchema.knownSectionShapesAreValid(
                    root: adoptedRoot)
            {
                adoptedNotice = .malformed
            }
            // Round-5 finding 1: the main actor is reentrant across the
            // detached replay, and the read-only notice is still active, so
            // completed structural mutations may APPEND to the journal while
            // a pass is in flight. Acknowledge only each pass's captured
            // prefix and loop until no suffix remains.
            while adoptedNotice == nil,
                !self.sidebarStructuralTransformJournal.isEmpty
            {
                let pass = self.sidebarStructuralTransformJournal
                // Round-25: entries an earlier chained writer already
                // committed to this vault replay nowhere — acknowledge them
                // and continue (the mutate funnel's ledger filter, mirrored).
                let committed =
                    Self.sidebarCommittedTransformIDs[retryIdentity] ?? []
                let effectivePass = pass.filter { !committed.contains($0.id) }
                if effectivePass.isEmpty {
                    let passIDs = Set(pass.map(\.id))
                    self.sidebarStructuralTransformJournal.removeAll {
                        passIDs.contains($0.id)
                    }
                    continue
                }
                enum RetryReplayOutcome {
                    case success([String: Any])
                    case replacedButUnsynced([String: Any], reason: String)
                    case failure(Error)
                }
                let replayTask = Task.detached(priority: .userInitiated) {
                    () -> RetryReplayOutcome in
                    var finalRoot: [String: Any] = [:]
                    do {
                        try store.update(
                            expectedRootIdentity: retryIdentity
                        ) { root in
                            guard
                                SidebarOrganizationSchema
                                    .knownSectionShapesAreValid(root: root)
                            else {
                                throw SidebarOrganizationShapeError()
                            }
                            for transform in effectivePass {
                                transform.applyRaw(to: &root)
                            }
                            finalRoot = root
                        }
                        return .success(finalRoot)
                    } catch SidebarVaultPrefsStoreError.replacedButUnsynced(
                        let reason)
                    {
                        // The rename landed: the pass's content is committed
                        // (round-11 finding 1) — only durability is at risk.
                        return .replacedButUnsynced(finalRoot, reason: reason)
                    } catch {
                        return .failure(error)
                    }
                }
                // Test seam: deterministically interleave a structural append
                // between a pass's capture and its completion.
                self.sidebarStructuralJournalReplayInterleaveHookForTesting?()
                self.sidebarStructuralJournalReplayInterleaveHookForTesting = nil
                let replay = await replayTask.value
                guard generation == self.sidebarVaultPrefsRetryGeneration,
                    self.currentSession === session,
                    self.sidebarVaultPrefsStore?.fileURL == store.fileURL
                else { return }
                switch replay {
                case .success(let finalRoot):
                    adoptedRoot = finalRoot
                    Self.sidebarCommittedTransformIDs[retryIdentity, default: []]
                        .formUnion(effectivePass.map(\.id))
                    let passIDs = Set(pass.map(\.id))
                    self.sidebarStructuralTransformJournal.removeAll {
                        passIDs.contains($0.id)
                    }
                case .replacedButUnsynced(let finalRoot, let reason):
                    // Committed: adopt and acknowledge exactly this pass,
                    // continue any suffix, and surface only the durability
                    // warning after publish (round-11 finding 1).
                    adoptedRoot = finalRoot
                    Self.sidebarCommittedTransformIDs[retryIdentity, default: []]
                        .formUnion(effectivePass.map(\.id))
                    let passIDs = Set(pass.map(\.id))
                    self.sidebarStructuralTransformJournal.removeAll {
                        passIDs.contains($0.id)
                    }
                    retryDurabilityWarning =
                        "Sidebar settings were saved, but the change may not "
                        + "survive a sudden power loss: \(reason)"
                case .failure:
                    // The file regressed between the read and the replay;
                    // keep the whole journal for the next Retry and report
                    // the still-unsafe state honestly.
                    let reread = await Task.detached(priority: .userInitiated) {
                        store.read(expectedRootIdentity: retryIdentity)
                    }.value
                    guard generation == self.sidebarVaultPrefsRetryGeneration,
                        self.currentSession === session
                    else { return }
                    // A replaced root adopts nothing (round-23).
                    guard let reread else { return }
                    adoptedRoot = reread.root
                    if let notice = reread.notice {
                        adoptedNotice = notice
                    } else if !SidebarOrganizationSchema
                        .knownSectionShapesAreValid(root: reread.root)
                    {
                        adoptedNotice = .malformed
                    } else {
                        adoptedNotice = .unreadable
                    }
                }
            }

            self.sidebarVaultPrefsNotice = adoptedNotice
            self.sidebarOrganizationJournalRecoveryPending =
                adoptedNotice == nil
                && (!self.sidebarStructuralTransformJournal.isEmpty
                    || Self.sidebarUnflushedWriteRetries[retryIdentity]?
                        .isEmpty == false)
            self.sidebarOrganizationPendingAnnouncementVerifications = [:]
            // A successful repair re-adopts the file's authored organization
            // sections in the same publish; any standing notice publishes
            // defaults instead — partial salvage from an invalid file would
            // misrepresent it (round-8 finding 2).
            let organization: SidebarOrganizationState
            if adoptedNotice == nil {
                let decoded = SidebarOrganizationSchema.decode(root: adoptedRoot)
                organization = SidebarOrganizationState(
                    prefs: decoded.prefs, pins: decoded.pins)
            } else {
                organization = SidebarOrganizationState()
            }
            if organization != self.sidebarOrganization {
                self.sidebarOrganization = organization
            }
            if let notice = adoptedNotice {
                self.announcer.post(
                    "Sidebar settings still use defaults. \(notice.localizedDescription)",
                    priority: .medium)
            } else if self.sidebarStructuralTransformJournalOverflowed {
                self.sidebarStructuralTransformJournalOverflowed = false
                self.announcer.post(
                    "Sidebar settings reloaded. Some pinned notes or sort "
                        + "overrides may still reference old locations.",
                    priority: .medium)
            } else {
                self.announcer.post("Sidebar settings reloaded.", priority: .medium)
            }
            if adoptedNotice == nil, let retryDurabilityWarning {
                self.announcer.post(retryDurabilityWarning, priority: .medium)
            }
            // Round-30: retained writes parked behind the outage settle
            // once the file is healthy, in their own chained slot.
            if adoptedNotice == nil,
                Self.sidebarUnflushedWriteRetries[retryIdentity]?.isEmpty
                    == false
            {
                self.scheduleSidebarRetainedWriteDrain()
            }
        }
        sidebarVaultPrefsRetryTask = task
        Self.sidebarStoreWriterChains[retryIdentity] = task
        Self.sidebarStoreWriterChainTokens[retryIdentity] = chainToken
        return task
    }

    private func resetSidebarVaultPreferencesRetry() {
        sidebarVaultPrefsRetryGeneration &+= 1
        sidebarVaultPrefsRetryTask?.cancel()
        sidebarVaultPrefsRetryTask = nil
        isRetryingSidebarVaultPreferences = false
    }

    /// A direct vault switch keeps `MainSplitView` mounted, so its initial
    /// `.onAppear` announcement cannot fire again. Use the shared injectable
    /// poster here, after the replacement vault and its sidebar notice have
    /// both been installed. A clean recent-vault close/open may be coalesced
    /// without remounting too, so its narrowly scoped flag routes here. True
    /// initial mounts remain view-owned, avoiding duplicate speech.
    private func announceDirectVaultSwitch(to vaultRoot: URL) {
        let notice = sidebarVaultPrefsNotice
            .map { " \($0.localizedDescription)" } ?? ""
        announcer.post(
            "Vault \(vaultRoot.lastPathComponent) opened. Scanning files for the sidebar."
                + notice,
            priority: .medium
        )
    }

    /// The recent vault the user asked to switch to while the current vault
    /// was still open (U4-3, #472). Held from `switchToRecent(_:)` until the
    /// close committed (`closeVault()`'s tail opens it) or the dirty-gate
    /// prompt was cancelled (the cancel resolvers clear it → no switch).
    /// `private(set)` so tests can assert the gate parked / cleared it.
    private(set) var pendingVaultSwitchTarget: RecentVault?
    /// A clean recent-vault switch closes A before synchronously opening B.
    /// SwiftUI can coalesce that false→true transition without remounting
    /// `MainSplitView`, so the close tail marks B as state-announced just as a
    /// direct open-over-open switch is. The flag is scoped around `openRecent`
    /// and cannot leak from a missing target into a later unrelated open.
    private var announceNextOpenAfterClose = false

    /// Switch to a recent vault (U4-3 vault switcher): close the current vault
    /// **through the same dirty gate** `closeVaultFromUserAction` uses, then
    /// open the target. Cancelling the "Save changes?" prompt cancels the whole
    /// switch — nothing closes, the target is dropped, the current vault stays.
    ///
    /// The open is deferred to `closeVault()`'s tail (which fires once the close
    /// commits from any gate branch — clean, single-dirty save/discard, or
    /// multi-tab Save All / Discard All), so we never open over an unsaved
    /// buffer. We drive the same gate primitives as `closeVaultFromUserAction`
    /// (attemptCloseVault / pendingVaultClose) but WITHOUT its "returned to the
    /// welcome screen" announcement, which would be false for a switch — the
    /// subsequent `openVault` posts its own "Vault … opened" announcement.
    func switchToRecent(_ entry: RecentVault) {
        guard !rejectVaultTransitionDuringNativeImport() else { return }
        // Already the open vault → no-op (the menu also disables the current
        // vault's row; this guards the programmatic path).
        guard entry.path != currentVaultURL?.path else { return }
        if let reason = authoredPropertyPublicationRecoveryReason {
            postMutationAnnouncement(reason)
            return
        }
        if let reason = inFlightDraftDiscardDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        // Do not close the current vault for a stale recent. `openRecent` also
        // performs this check, but direct switch callers need the same
        // preservation guarantee before the close half of the transition.
        guard Self.vaultDirectoryExists(entry) else {
            missingRecentVault = entry
            return
        }
        supersedePendingTabCloseForVaultTransition()
        pendingVaultSwitchTarget = entry
        let parkedDirty = workspace.dirtyParkedDocuments()
        let recoveryPaths = uncommittedNoteDraftPaths()
        if parkedDirty.isEmpty, recoveryPaths.isEmpty {
            if hasUnsavedChanges {
                // Single dirty document → "Save changes?" (pendingNavigation
                // = .closeVault). On Save/Discard the resolver calls
                // closeVault(), whose tail opens the target; on Cancel the
                // resolver clears the target (no switch).
                attemptCloseVault()
            } else {
                // Clean → close now; the tail opens the target.
                closeVault()
            }
        } else {
            // Multiple dirty tabs → Save All / Discard All / Cancel prompt.
            pendingVaultClose = dirtyVaultClosePaths().count
        }
    }

    /// Open a recent-vaults entry. If the path no longer exists on
    /// disk, do *not* try to open it (which would either fail with
    /// InvalidPath or, on older bugs, silently materialize a vault) —
    /// instead surface the entry through `missingRecentVault` so the
    /// UI can offer removal.
    func openRecent(_ entry: RecentVault) {
        // #872 Codex red-team: opening a recent IS the user's launch
        // intent — claim the launch-restore attempt first. This matters
        // even for a MISSING entry (which only sets `missingRecentVault`
        // and opens nothing): without the claim, a WindowGroup launch
        // `.task` firing afterward would restore the leading VALID recent
        // and override the user's "I tried this stale one" intent. The
        // launch path already claimed before routing here; this covers a
        // manual recent-list click.
        hasAttemptedLaunchRestore = true
        guard Self.vaultDirectoryExists(entry) else {
            missingRecentVault = entry
            return
        }
        if isVaultOpen {
            switchToRecent(entry)
        } else {
            openVault(at: URL(fileURLWithPath: entry.path))
        }
    }

    /// Whether a directory exists at the entry's path — the existence
    /// rule `openRecent` enforces, factored out (#872) so the launch
    /// decision can consult the SAME rule without opening anything.
    /// Static + side-effect-free so tests drive the launch matrix
    /// deterministically by injecting a closure instead of the disk.
    static func vaultDirectoryExists(_ entry: RecentVault) -> Bool {
        var isDir: ObjCBool = false
        let exists = FileManager.default.fileExists(
            atPath: entry.path, isDirectory: &isDir)
        return exists && isDir.boolValue
    }

    /// Show the directory picker and, if the user chose a folder, open
    /// it as a vault. Centralizes the flow so the WelcomeView button
    /// and the App-level Shift-Command-O command share the same code path.
    ///
    /// `@MainActor` is redundant given the class-level annotation but
    /// is repeated here for self-documenting clarity: this method
    /// presents an `NSOpenPanel`, which AppKit requires on the main
    /// thread.
    @MainActor
    func pickAndOpenVault() {
        // #872 Codex red-team: a manual open IS the user's launch intent —
        // claim the launch-restore attempt BEFORE presenting the picker.
        // The production picker runs a nested `runModal()` event loop that
        // can execute the WindowGroup launch `.task` while the panel is
        // still up (and `isVaultOpen` is still false); without this claim,
        // that task would auto-restore a recent vault BEHIND the open
        // panel — cancelling then strands it open, choosing opens two.
        guard !rejectVaultTransitionDuringNativeImport() else { return }
        hasAttemptedLaunchRestore = true
        guard let url = vaultPicker() else { return }
        if isVaultOpen {
            switchToRecent(RecentVault(url: url))
        } else {
            openVault(at: url)
        }
    }

    /// Directory-picker seam. Production runs the real `NSOpenPanel`
    /// wrapper; tests substitute a canned URL (or nil = cancel) so
    /// flows that fall through to the picker — the welcome screen's
    /// ⌘O quick-open fallthrough (#863) — never present a modal panel
    /// under XCTest. Same injectable-var convention as `scanClock`.
    var vaultPicker: () -> URL? = { VaultPicker.pick() }

    /// Finder import-picker seam. Production uses one native open panel that
    /// accepts files and folders together; tests inject a deterministic URL
    /// array (nil means the user cancelled) without presenting AppKit UI.
    var importSourcePicker: () -> [URL]? = {
        let panel = NSOpenPanel()
        panel.canChooseFiles = true
        panel.canChooseDirectories = true
        panel.allowsMultipleSelection = true
        panel.resolvesAliases = false
        panel.prompt = "Import"
        panel.message = "Choose files and folders to import. Items already in this vault are moved to the selected location."
        guard panel.runModal() == .OK else { return nil }
        return panel.urls
    }

    // MARK: - Launch restore (#872)

    /// Where a cold launch should land. HIG launching.md: "Restore
    /// previous state on restart … avoid making people retrace steps";
    /// Obsidian / VS Code reopen the last workspace, the parity
    /// expectation for a vault app.
    enum LaunchDestination: Equatable {
        /// Auto-reopen this vault — it is present on disk.
        case restore(RecentVault)
        /// The most-recent vault is gone (folder moved / drive
        /// unplugged). Land on Welcome AND surface the EXISTING
        /// not-found flow so the user can prune the stale entry — the
        /// caller routes this through `openRecent`, which sets
        /// `missingRecentVault` and never opens a session.
        case notFound(RecentVault)
        /// Show the picker / Welcome with no auto-restore: the ⌥ escape
        /// hatch is held, the "Reopen last vault" setting is off, or
        /// there is no recent vault to restore.
        case welcome
    }

    /// Pure launch decision (#872) — no side effects, no I/O, so the
    /// whole matrix is unit-testable without an event queue or the
    /// filesystem. `optionHeld` is the ⌥-at-launch escape hatch;
    /// `restoreEnabled` is the Settings ▸ General toggle; `vaultExists`
    /// decides restore vs. the not-found flow for the most-recent entry.
    static func launchDestination(
        recents: [RecentVault],
        optionHeld: Bool,
        vaultExists: (RecentVault) -> Bool,
        restoreEnabled: Bool = true
    ) -> LaunchDestination {
        // ⌥ held, toggle off, or nothing to restore → a clean Welcome.
        guard restoreEnabled, !optionHeld, let mostRecent = recents.first else {
            return .welcome
        }
        return vaultExists(mostRecent) ? .restore(mostRecent) : .notFound(mostRecent)
    }

    /// True once `restoreMostRecentVaultOnLaunch()` has run, so the
    /// launch hook is idempotent no matter how many times the root
    /// view's `.task` re-fires across its lifetime.
    private(set) var hasAttemptedLaunchRestore = false

    /// Launch-time entry point (#872), called once from the root view's
    /// `.task`. Reopens the most-recent vault unless the ⌥ escape hatch
    /// is held or Settings ▸ General ▸ "Reopen last vault at launch" is
    /// off; a stale most-recent falls through the EXISTING not-found
    /// flow (`openRecent`). Idempotent, and a no-op once a vault is
    /// already open, so an early manual open can't be clobbered.
    ///
    /// `optionHeld` / `vaultExists` are injected — production reads the
    /// live modifier flags (evaluated at call time, so ⌥ held *during*
    /// launch is caught) and the filesystem — so the routing is
    /// unit-testable.
    func restoreMostRecentVaultOnLaunch(
        optionHeld: Bool = NSEvent.modifierFlags.contains(.option),
        vaultExists: (RecentVault) -> Bool = AppState.vaultDirectoryExists
    ) {
        guard !hasAttemptedLaunchRestore else { return }
        hasAttemptedLaunchRestore = true
        guard !isVaultOpen else { return }
        switch Self.launchDestination(
            recents: recentVaults,
            optionHeld: optionHeld,
            vaultExists: vaultExists,
            restoreEnabled: restoreVaultOnLaunch
        ) {
        case .restore(let entry), .notFound(let entry):
            // Both route through `openRecent`: it re-checks existence
            // (TOCTOU-safe) and either opens the vault or sets
            // `missingRecentVault` for the Welcome-screen not-found
            // alert — the "reuse the existing missing-vault handling"
            // requirement, no new error path.
            openRecent(entry)
        case .welcome:
            break
        }
    }

    /// True when a cold launch is *about* to auto-restore an existing
    /// vault (#872). WelcomeView reads this in `onAppear` to suppress
    /// its "Open Vault focused" announcement during the one-frame flash
    /// before the vault opens — the not-found and no-restore paths DO
    /// land on Welcome, so those keep the announcement. Mirrors the
    /// `restoreMostRecentVaultOnLaunch` decision (same inputs).
    var willRestoreVaultOnLaunch: Bool {
        guard !hasAttemptedLaunchRestore, !isVaultOpen else { return false }
        switch Self.launchDestination(
            recents: recentVaults,
            optionHeld: NSEvent.modifierFlags.contains(.option),
            vaultExists: AppState.vaultDirectoryExists,
            restoreEnabled: restoreVaultOnLaunch
        ) {
        case .restore: return true
        case .notFound, .welcome: return false
        }
    }

    /// User-action wrapper around `closeVault()` / `attemptCloseVault()`
    /// that mirrors what the MainSplitView "Close Vault" toolbar
    /// button does, including the post-close VoiceOver announcement.
    /// One source of truth for both the toolbar button (#296) and
    /// the command palette's `slate.vault.close` registration (#314).
    ///
    /// - Dirty editor → routes through `attemptCloseVault`; the
    ///   eventual close announces from `applyPendingNavigation`.
    /// - Clean editor → closes immediately and posts the
    ///   announcement inline here.
    func closeVaultFromUserAction() {
        guard !rejectVaultTransitionDuringNativeImport() else { return }
        if let reason = authoredPropertyPublicationRecoveryReason {
            postMutationAnnouncement(reason)
            return
        }
        if let reason = inFlightDraftDiscardDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        supersedePendingTabCloseForVaultTransition()
        // U1-2: the dirty check aggregates over every tab. With no parked
        // dirty documents the flow is exactly the pre-tabs behavior (the
        // active document routes through the existing single-file alert).
        let parkedDirty = workspace.dirtyParkedDocuments()
        let recoveryPaths = uncommittedNoteDraftPaths()
        if parkedDirty.isEmpty, recoveryPaths.isEmpty {
            if hasUnsavedChanges {
                attemptCloseVault()
            } else {
                if closeVault() {
                    announcer.post(
                        "Vault closed. Returned to the welcome screen.",
                        priority: .medium
                    )
                }
            }
        } else {
            pendingVaultClose = dirtyVaultClosePaths().count
        }
    }

    /// Multi-tab vault-close prompt (U1-2): the number of dirty tabs, nil
    /// when no prompt is up. Drives the Save All / Discard All / Cancel
    /// alert in `MainSplitView`.
    @Published var pendingVaultClose: Int?

    /// Test hook for the sequential Save All chain.
    private(set) var vaultCloseSaveAllTask: Task<Void, Never>?
    /// Owner generation for the outer sequential Save All continuation.
    /// Inner saves already capture a session; this closes the separate race
    /// where the outer loop resumes after a discard/switch and acts on the
    /// replacement vault's clean global fields.
    private var vaultCloseSaveAllGeneration = 0

    private func cancelVaultCloseSaveAll() {
        vaultCloseSaveAllGeneration &+= 1
        vaultCloseSaveAllTask?.cancel()
        vaultCloseSaveAllTask = nil
    }

    private func ownsVaultCloseSaveAll(
        generation: Int,
        session: VaultSession
    ) -> Bool {
        !Task.isCancelled
            && vaultCloseSaveAllGeneration == generation
            && currentSession === session
    }

    /// Save All is unavailable if any dirty note is covered by an
    /// outcome-unknown Trash root. Include parked tabs up front so the chain
    /// cannot save one note, activate a quarantined note, then spin on a nil
    /// save. The first exact capability reason drives both the alert and the
    /// defensive action.
    var pendingVaultCloseSaveAllDisabledReason: String? {
        guard pendingVaultClose != nil else { return nil }
        for path in dirtyVaultClosePaths() {
            if let reason = dirtyCloseSaveDisabledReason(for: path) { return reason }
        }
        return nil
    }

    var pendingVaultCloseDiscardAllDisabledReason: String? {
        guard pendingVaultClose != nil else { return nil }
        return inFlightDraftDiscardDisabledReason
    }

    /// "Save All": save every dirty tab through the STANDARD save path
    /// (activate → saveCurrentNote → await), sequentially. Aborts on the
    /// first conflict/error, leaving the user on that tab with the standard
    /// resolution dialog up; the vault stays open. Closes on full success.
    func resolveVaultCloseSaveAll() {
        guard pendingVaultClose != nil, let session = currentSession else { return }
        guard !rejectVaultTransitionDuringNativeImport() else { return }
        if let reason = authoredPropertyPublicationRecoveryReason {
            pendingVaultClose = nil
            postMutationAnnouncement(reason)
            return
        }
        if let reason = pendingVaultCloseSaveAllDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        cancelVaultCloseSaveAll()
        let generation = vaultCloseSaveAllGeneration
        let task = Task { [weak self] in
            guard let self else { return }
            defer {
                if self.vaultCloseSaveAllGeneration == generation {
                    self.vaultCloseSaveAllTask = nil
                }
            }
            guard self.ownsVaultCloseSaveAll(
                generation: generation, session: session)
            else { return }
            var startedSaving = false
            while true {
                if self.hasUnsavedChanges {
                    // A quarantine can arrive after the synchronous preflight
                    // but before this task runs, or between two sequential
                    // saves. Never await an optional/stale task: retain or
                    // re-present the prompt and stop on a nil admission.
                    guard let save = self.saveCurrentNote() else {
                        let dirtyCount = self.dirtyVaultClosePaths().count
                        self.pendingVaultClose = dirtyCount > 0 ? dirtyCount : nil
                        return
                    }
                    if !startedSaving {
                        self.pendingVaultClose = nil
                        startedSaving = true
                    }
                    await save.value
                    guard self.ownsVaultCloseSaveAll(
                        generation: generation, session: session)
                    else { return }
                    if self.currentSaveConflict != nil || self.saveError != nil {
                        // U4-3: an aborted Save All also aborts an in-flight
                        // vault switch — the vault stays open, so a stale
                        // parked target would make a LATER plain Close Vault
                        // surprise-open the other vault (the same leak class
                        // as the U1-2 save-then-close scope).
                        self.pendingVaultSwitchTarget = nil
                        return  // standard dialog owns recovery; vault stays open
                    }
                }
                guard let next = self.workspace.dirtyParkedDocuments().first else { break }
                self.activateTab(next.id)
                guard self.ownsVaultCloseSaveAll(
                    generation: generation, session: session)
                else { return }
            }
            // A property editor can become dirty while a sequential body Save
            // All is running. It has no body-save representation, so restore
            // the prompt instead of claiming all changes were saved.
            if !self.uncommittedNoteDraftPaths().isEmpty {
                self.pendingVaultClose = self.dirtyVaultClosePaths().count
                if let reason = self.pendingVaultCloseSaveAllDisabledReason {
                    self.postMutationAnnouncement(reason)
                }
                return
            }
            guard self.ownsVaultCloseSaveAll(
                generation: generation, session: session)
            else { return }
            self.pendingVaultClose = nil
            let completesVaultSwitch = self.pendingVaultSwitchTarget != nil
            if self.closeVault(), !completesVaultSwitch {
                self.announcer.post(
                    "All changes saved. Vault closed. Returned to the welcome screen.",
                    priority: .medium
                )
            }
        }
        vaultCloseSaveAllTask = task
    }

    /// "Discard All": close without saving any tab. The per-tab buffers are
    /// dropped by `closeVault`'s workspace reset.
    func resolveVaultCloseDiscardAll() {
        guard !rejectVaultTransitionDuringNativeImport() else { return }
        if let reason = authoredPropertyPublicationRecoveryReason {
            pendingVaultClose = nil
            postMutationAnnouncement(reason)
            return
        }
        if let reason = inFlightDraftDiscardDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        pendingVaultClose = nil
        hasUnsavedChanges = false
        let completesVaultSwitch = pendingVaultSwitchTarget != nil
        if closeVault(), !completesVaultSwitch {
            announcer.post(
                "Changes discarded. Vault closed. Returned to the welcome screen.",
                priority: .medium
            )
        }
    }

    func resolveVaultCloseCancel() {
        pendingVaultClose = nil
        // U4-3: same as the single-dirty cancel — a cancelled multi-tab close
        // cancels the switch and drops the parked target.
        pendingVaultSwitchTarget = nil
    }

    /// Property/source recovery identities are vault-owned even though their
    /// keys are relative paths. A direct A→B open does not pass through
    /// `closeVault`, so both transition funnels must clear these registries
    /// before B can restore an equal path such as `alpha.md`.
    private func resetVaultScopedPropertyRecovery() {
        missingNoteRecoveryDrafts = [:]
        preservedPropertyDrafts = [:]
        propertyPublicationUncertainties = [:]
        propertyDraftResetRequests = [:]
        parkedPropertiesSourceDrafts = [:]
        propertiesSourceDraft = ""
        propertiesSourceDraftPath = nil
        propertiesSourceCommitRequests = [:]
        propertiesSourceShowing = false
        propertiesSourceError = nil
    }

    @discardableResult
    func closeVault() -> Bool {
        guard !rejectVaultTransitionDuringNativeImport() else { return false }
        if let reason = authoredPropertyPublicationRecoveryReason {
            pendingVaultSwitchTarget = nil
            pendingVaultClose = nil
            if case .closeVault? = pendingNavigation {
                pendingNavigation = nil
            }
            postMutationAnnouncement(reason)
            return false
        }
        if let reason = inFlightDraftDiscardDisabledReason {
            pendingVaultSwitchTarget = nil
            pendingVaultClose = nil
            if case .closeVault? = pendingNavigation {
                pendingNavigation = nil
            }
            postMutationAnnouncement(reason)
            return false
        }
        // Round-26: a close with unsaved structural transforms makes one
        // final best-effort drain. The queued write survives teardown
        // (round-21) and lands against the captured, identity-verified
        // store; if the transient failure persists the transforms are lost
        // with the session — the recovery banner has been saying exactly
        // that since the failure.
        if sidebarVaultPrefsNotice == nil,
            !sidebarStructuralTransformJournal.isEmpty
        {
            try? mutateSidebarOrganization(
                announce: nil,
                apply: { _ in },
                reflect: { _ in },
                isBacklogDrain: true)
        }
        invalidateNoteAuthoringOwnership()
        cancelSaveOwnership()
        cancelPendingNavigationSave()
        // Cancel outer close continuations before clearing globals. Their
        // inner save tasks already carry session guards; their wrappers must
        // not resume and interpret a replacement vault as their completion.
        cancelVaultCloseSaveAll()
        // U1-6: persist the layout FIRST — the teardown below clears
        // `currentVaultURL`, and the save is a no-op once it's gone.
        saveWorkspaceLayout()
        resetSidebarMetadataRefresh()
        resetSidebarVaultPreferencesRetry()
        baseQueryBuilderPreviewGeneration += 1
        scanTask?.cancel()
        scanTask = nil
        noteLoadTask?.cancel()
        noteLoadTask = nil
        linksLoadTask?.cancel()
        linksLoadTask = nil
        tasksLoadTask?.cancel()
        tasksLoadTask = nil
        // #879: Tasks Review is a leaf now; its query teardown is the single
        // `closeTasksReview()` helper (cancels the in-flight page load).
        closeTasksReview()
        taskToggleTask?.cancel()
        taskToggleTask = nil
        // Audit #260: embed-resolution batch keeps grabbing the
        // session mutex post-closeVault if not cancelled. Race-guard
        // catches the stale write but the orphan task delays
        // session-deallocation.
        embedsLoadTask?.cancel()
        embedsLoadTask = nil
        isLoadingEmbeds = false
        baseQueryBuilderPreviewTask?.cancel()
        baseQueryBuilderPreviewTask = nil
        baseQueryBuilderPreviewCancelToken?.cancel()
        baseQueryBuilderPreviewCancelToken = nil
        closeSearchOverlay()
        searchQuery = ""
        // Reset transient sheet flags so a vault-close mid-palette
        // doesn't leave the bool stuck (next vault open would
        // auto-present the empty palette). #313 belt-and-suspenders
        // with the `requestCommandPalette()` open-guard.
        isCommandPaletteOpen = false
        activeBaseQueryBuilder = nil
        resetBaseRefreshTasksForVaultTransition()
        resetBaseQueriesForClosedVault()
        // Quick switcher (#495): same stuck-bool reset as the palette,
        // enforced by CloseVaultSheetParityTests. Also drop the in-memory
        // file-recents — it's per-vault, so the next vault reloads its own.
        isQuickSwitcherOpen = false
        fileRecents = []
        // #876: drop the in-memory recent searches — per-vault, so the
        // next vault reloads its own (mirrors `fileRecents` above).
        searchRecents = []
        // #871: the structural (file-op) undo/redo stacks are per-vault;
        // drop them so a stale inverse can't reverse against the next vault.
        clearStructuralUndoStacks()
        cancelCurrentImportBatchForVaultTransition()
        // #871 Codex round 2: invalidate + release the structural-mutation
        // guard on vault close too (see the openVault reset for the full
        // token rationale).
        cancelStructuralMutationOwnership()
        // #328 sheet-flag parity audit. Each `@Published var
        // is*Open` driving a `.sheet` binding must reset here for
        // the same reason as `isCommandPaletteOpen`: a vault close
        // while the sheet is presented would otherwise leave the
        // bool stuck `true`, and the next vault open would re-
        // present an empty / stale sheet against the new vault's
        // state. `isCitationSummaryOpen` is reset further down in
        // this method (search for `= false`); `isTasksReviewOpen` is
        // gone (#879 — Tasks Review is a leaf, not a sheet),
        // and `isSearchOpen` via the `closeSearchOverlay()` call
        // above. The full set is enforced by
        // `CloseVaultSheetParityTests` — a structural drift test
        // that scrapes every `@Published var is*Open` and asserts
        // each is reset here, so a newly-added sheet bool that
        // misses this method fails CI.
        dismissAddPropertySheet()
        // Bulk-rename: clear the sheet bool plus the in-flight
        // bookkeeping. A rename task in flight against the old
        // vault would race the close — the Rust call holds the
        // SQLite mutex and won't observe the Swift `Task.cancel`
        // signal until it next checks the `CancelToken`. We
        // cancel both: the token tells the Rust side to break
        // out of its row-by-row loop at the next check, and the
        // Task.cancel makes the Swift-side continuation observe
        // `Task.isCancelled` on resume (guarded by `performRename`
        // — #328 red-team P1).
        isBulkRenameSheetOpen = false
        renameCancelToken?.cancel()
        renameCancelToken = nil
        renameTask?.cancel()
        renameTask = nil
        renameApplySecondAdmissionGate = nil
        renamePostWritePublishGate = nil
        renameApplySecondAdmissionUnknownItemsForTesting = nil
        pendingRenameReport = nil
        isRenameInFlight = false
        renameError = nil
        // Property-edit state lives on the same lifecycle as the
        // Add-Property sheet. `performPropertyEdit` already self-
        // guards via `loadedFilePath == path` (closeVault zeroes
        // `selectedFilePath`/`loadedFilePath` below, so the late
        // write is suppressed), but the published flags + alert
        // binding would still leak across the close. The alert
        // matters most: `currentPropertyEditConflict` drives a
        // `.alert(...)` in MainSplitView; without the reset the
        // conflict dialog survives onto the welcome screen.
        cancelPropertyEditOwnership()
        cancelSidebarActionValidation()
        invalidateSidebarWikilinkCopy()
        propertyEditError = nil
        currentPropertyEditConflict = nil
        resetVaultScopedPropertyRecovery()
        // Template listing, presentation, destination, creation, and deferred
        // caret ownership are all vault-scoped and share one teardown path
        // with direct A→B replacement.
        resetTemplateLifecycleForVaultTransition()
        // Release native document handles before clearing `currentSession`;
        // the release helpers need the session that created those handles.
        releaseAllCanvasDocuments()
        releaseAllBaseDocuments()
        releaseAllBaseEmbedDocuments()
        releaseAllDashboardDocuments()
        // History leaf (O-5): the event-listener unregister also needs
        // the live session.
        unregisterVaultEventListener()
        currentSession = nil
        sidebarSelectionSnapshot = nil
        currentVaultURL = nil
        sidebarVaultPrefsStore = nil
        sidebarVaultPrefsNotice = nil
        resetSidebarOrganizationState()
        files = []
        scanError = nil
        stopSyncMarkerWatcher()  // #638: no vault, no watch
        syncReport = nil
        liveSyncConfig = nil
        syncDiagnosticsError = nil
        // History leaf (O-5): reset every history surface (the event
        // listener was unregistered above, while the session lived).
        compactionAlertedPaths = []
        compactionFailure = nil
        resetHistoryState()
        // Connections leaf (P1-1 #554): a root/back-stack path from the
        // closing vault must never load or open against the next one
        // (review round 1 finding 3).
        resetConnectionsState()
        // Graph tab table (P1-2 #555): same cross-vault isolation.
        resetGraphTableState()
        // Graph tab diagram (P2-3 #559): tear down the layout session too.
        resetGraphDiagramState()
        // Graph config (P2-4 #560): no vault now, so drop the in-memory
        // config to defaults and un-stamp the vault marker. A pending
        // debounced save still targets the CLOSING vault via its captured
        // root and completes normally (not cancelled), so its final edit
        // isn't lost (review finding 3).
        graphConfig = .default
        graphConfigVaultURL = nil
        graphConfigWritable = true
        // U1-2: drop every tab + parked document BEFORE clearing the
        // selection — the selection funnel's snapshot would otherwise park
        // the about-to-be-discarded buffer, and mirrorSingleSelection would
        // close only the ACTIVE tab, leaving siblings pointing into a
        // closed vault.
        workspace.reset()
        pendingTabClose = nil
        pendingTabCloseAfterSave = nil
        selectedFilePath = nil
        treeSelectedNode = nil
        treeExpandedDirPaths = []  // #873: expansion dies with the vault
        pendingFolderDelete = nil  // #860: staged confirmation dies with it
        pendingMove = nil  // U2-5: single Move capture dies with the vault
        pendingBatchMove = nil  // #852: batch sheet dies with the vault
        pendingBatchDelete = nil  // #852: batch confirmation dies with the vault
        renamingNode = nil  // inline rename belongs to the closed vault/session
        structuralRenameError = nil
        resetBatchAlertPresentations()  // FL-03: typed alerts belong to the closed session
        currentNoteText = nil
        currentNoteHeadings = []
        noteLoadError = nil
        currentBacklinks = []
        currentOutgoingLinks = []
        currentOutgoingLinksPath = nil
        currentNoteProperties = []
        currentNoteEmbedResolutions = [:]
        pendingEmbedPreview = nil
        currentNoteMathBlocks = []
        currentNoteCodeBlocks = []
        currentNoteDiagramBlocks = []
        mathBlocksLoadError = nil
        codeBlocksLoadError = nil
        diagramBlocksLoadError = nil
        isLoadingMathBlocks = false
        isLoadingCodeBlocks = false
        isLoadingDiagramBlocks = false
        mathBlocksLoadTask?.cancel()
        mathBlocksLoadTask = nil
        codeBlocksLoadTask?.cancel()
        codeBlocksLoadTask = nil
        diagramBlocksLoadTask?.cancel()
        diagramBlocksLoadTask = nil
        // Red-team M1: cancel any in-flight refresh-after-save
        // tasks so a save-then-immediately-close window doesn't
        // leave them grabbing the conn-mutex post-close.
        mathBlocksRefreshTask?.cancel()
        mathBlocksRefreshTask = nil
        codeBlocksRefreshTask?.cancel()
        codeBlocksRefreshTask = nil
        diagramBlocksRefreshTask?.cancel()
        diagramBlocksRefreshTask = nil
        // Milestone L #279/#280: drop citation + bibliography state
        // on vault close so a re-open starts fresh.
        citationsLoadTask?.cancel()
        citationsLoadTask = nil
        currentNoteCitations = []
        currentNoteCitationRefs = []
        citationsLoadError = nil
        isLoadingCitations = false
        expandedCitation = nil
        bibliographyEntries = []
        bibliographyLoadError = nil
        isLoadingBibliography = false
        unresolvedCitations = []
        bibliographySearchText = ""
        expandedBibEntry = nil
        filesCitingResult = nil
        bibliographyPrefs = .empty
        availableCslStyles = []
        bibliographySettingsError = nil
        isCitationSummaryOpen = false
        pendingBibliographyKeyFocus = nil
        activeStyleId = ""
        embedsLoadError = nil
        linksLoadError = nil
        currentNoteTasks = []
        tasksLoadError = nil
        // #160 / #879: clear the whole review surface (rows, error,
        // pagination cursor, total, filter) and cancel both query legs so
        // reopening on a different vault can't carry state forward. Shared
        // with `openVault` (Codex red-team — direct Open Vault bypasses
        // this close path).
        resetVaultTasksReviewState()
        isScanning = false
        isLoadingNote = false
        isLoadingLinks = false
        isLoadingTasks = false
        isLoadingVaultTasks = false
        scanProgress = nil
        // U4-3 vault switch: if this close was the front half of a switch,
        // open the parked target now that teardown is complete. Capture-then-
        // clear so the open (which resets state again) can't re-enter this
        // arm. `openRecent` re-checks the target exists on disk and posts its
        // own "Vault … opened" announcement. Cancelled switches never reach
        // here (the cancel resolvers cleared the target), so a plain Close
        // Vault after a cancelled switch can't accidentally reopen a vault.
        if let target = pendingVaultSwitchTarget {
            pendingVaultSwitchTarget = nil
            announceNextOpenAfterClose = true
            openRecent(target)
            announceNextOpenAfterClose = false
        }
        return true
    }

    /// Drop a recent-vaults entry by path. Used by the welcome screen
    /// when the user confirms removal of a missing vault.
    func removeRecent(path: String) {
        do {
            recentVaults = try recentsStore.remove(path: path)
        } catch {
            // Recents persistence isn't critical to app function — the
            // in-memory list is what the UI reads. Log so the failure
            // isn't completely silent during dev, but don't surface to
            // the user; they're already mid-flow on removing an entry.
            fputs(
                "Slate: failed to persist recent-vaults removal: \(error)\n",
                stderr
            )
        }
    }

    /// Empty the recent-vaults list. Backs the File ▸ Open Recent ▸
    /// Clear Menu item (the macOS-standard tail of an Open Recent
    /// submenu). Same fire-and-log persistence contract as
    /// `removeRecent(path:)` — the in-memory list is what the UI reads.
    func clearRecentVaults() {
        for entry in recentVaults {
            removeRecent(path: entry.path)
        }
    }

    /// Run the initial scan against the current session, then page
    /// through `listFiles` to build the sidebar's in-memory list.
    /// Called automatically after `openVault` succeeds; can be called
    /// again later (e.g. a refresh action) once we have one.
    ///
    /// Idempotent: the Rust scanner upserts on path so re-running on
    /// an already-indexed vault is fine.
    ///
    /// Honors `Task.isCancelled`: closing the vault or opening a
    /// different one cancels the wrapping task, which (a) signals the
    /// in-flight `scan_initial` via the `CancelToken` so the Rust side
    /// bails at the next per-entry cancel check, and (b) suppresses
    /// the post-scan publish so a late completion can't repopulate
    /// `files` after the user has already moved on.
    func loadFiles() async {
        guard let session = currentSession else { return }
        isScanning = true
        scanError = nil
        // #871 Codex round 3: clear the spinner only if THIS scan's vault is
        // still current (or the vault was closed) — a scan whose vault was
        // switched out from under it must not stomp the NEW vault's in-flight
        // `isScanning`. (closeVault also resets it, covering the closed case.)
        defer {
            if currentSession === session || currentSession == nil {
                isScanning = false
            }
        }

        let cancel = CancelToken()
        // Adapter bridges scanner-thread `onProgress` callbacks back
        // to the main actor where AppState can publish them. Holding a
        // strong reference here is enough to keep the FFI handle live
        // for the duration of the scan; uniffi releases it when the
        // last Swift reference goes away.
        // The Task closure needs its own explicit `[weak self]` so
        // strict-concurrency mode (Swift 6 / sendability checks) can
        // verify the capture is sendable across the @Sendable boundary
        // — without it, the implicit re-capture of `self?` from the
        // outer closure trips a "reference to captured var 'self' in
        // concurrently-executing code" diagnostic on the CI toolchain.
        let adapter = ScanProgressAdapter { [weak self] event in
            Task { @MainActor [weak self] in
                // #871 Codex round 3: drop a late progress event whose vault is
                // no longer current — it must not publish vault A's scan
                // progress into vault B after a switch.
                guard let self, self.currentSession === session else { return }
                self.handleScanProgress(event)
            }
        }

        do {
            let loaded: [FileSummary] = try await withTaskCancellationHandler {
                try Task.checkCancellation()
                // Scan + list both go through SQLite under a Mutex, so
                // dispatching off the main actor keeps the UI responsive
                // on multi-thousand-file vaults.
                return try await Task.detached(priority: .userInitiated) {
                    _ = try session.scanInitialWithProgress(
                        cancel: cancel,
                        listener: adapter
                    )
                    var all: [FileSummary] = []
                    var cursor: String? = nil
                    repeat {
                        let page = try session.listFiles(
                            // Milestone N (#702): quick open lists the
                            // openable-document set — notes, canvases, bases.
                            filter: .openableDocuments,
                            paging: Paging(cursor: cursor, limit: 1_000)
                        )
                        all.append(contentsOf: page.items)
                        cursor = page.nextCursor
                    } while cursor != nil
                    return all
                }.value
            } onCancel: {
                // Bridge structured-concurrency cancellation across to
                // the CancelToken the Rust scanner is polling.
                cancel.cancel()
            }

            // If we were cancelled mid-flight (e.g. closeVault fired
            // between the detached task starting and finishing), don't
            // overwrite the freshly-cleared state with stale results.
            // #871 Codex round 2: also re-check the SESSION is still current —
            // a direct vault switch (Open Vault / Open Recent) may not cancel
            // this task, and publishing vault A's file list after `currentSession`
            // has become vault B would show A's files under B.
            guard !Task.isCancelled, currentSession === session else { return }
            files = loaded.sorted { lhs, rhs in
                lhs.path.localizedCaseInsensitiveCompare(rhs.path) == .orderedAscending
            }
        } catch is CancellationError {
            // Cancellation isn't an error condition the user needs to
            // see; the new vault flow will start its own scan.
        } catch let error as VaultError {
            // Cancelled scans surface from Rust as VaultError.Cancelled
            // — also intentionally non-user-visible.
            if case .Cancelled = error { return }
            // #871 Codex round 3: a stale scan's error must not surface under
            // the new vault.
            guard !Task.isCancelled, currentSession === session else { return }
            scanError = humanReadable(error)
        } catch {
            guard !Task.isCancelled, currentSession === session else { return }
            scanError = error.localizedDescription
        }
    }

    /// Refresh only the indexed openable-file inventory. Structural native
    /// calls and exclusive creates update the index themselves, so a clean
    /// import/move landing must not pay for or expose a vault scan. Directory
    /// rows resolve through the aggregate tree invalidation that follows.
    private func reloadImportInventoryOnly(for session: VaultSession) async throws {
        let loaded = try await Task.detached(priority: .userInitiated) {
            var all: [FileSummary] = []
            var cursor: String? = nil
            repeat {
                let page = try session.listFiles(
                    filter: .openableDocuments,
                    paging: Paging(cursor: cursor, limit: 1_000))
                all.append(contentsOf: page.items)
                cursor = page.nextCursor
            } while cursor != nil
            return all
        }.value
        guard currentSession === session else { return }
        files = loaded.sorted {
            $0.path.localizedCaseInsensitiveCompare($1.path) == .orderedAscending
        }
    }

    /// Import-owned authoritative scan. Unlike `loadFiles`, errors and
    /// cancellation are not swallowed: Task 4 may promote unknown candidates
    /// only after this method returns successfully. The caller runs it as a
    /// separately cancellable phase so ordinary Cancel can stop remaining copy
    /// work without poisoning mandatory final reconciliation.
    private func reloadImportInventoryWithAuthoritativeScan(
        for session: VaultSession
    ) async throws {
        guard currentSession === session else { throw CancellationError() }
        importOwnedScanCounter &+= 1
        let importScanGeneration = importOwnedScanCounter
        lastImportOwnedScanGeneration = importScanGeneration
        importOwnedScanCompletionGeneration = importScanGeneration
        isScanning = true
        scanError = nil
        defer {
            if currentSession === session || currentSession == nil {
                isScanning = false
            }
        }
        let cancel = CancelToken()
        let loaded = try await withTaskCancellationHandler {
            try Task.checkCancellation()
            return try await Task.detached(priority: .userInitiated) {
                _ = try session.scanInitial(cancel: cancel)
                var all: [FileSummary] = []
                var cursor: String? = nil
                repeat {
                    let page = try session.listFiles(
                        filter: .openableDocuments,
                        paging: Paging(cursor: cursor, limit: 1_000))
                    all.append(contentsOf: page.items)
                    cursor = page.nextCursor
                } while cursor != nil
                return all
            }.value
        } onCancel: {
            cancel.cancel()
        }
        try Task.checkCancellation()
        guard currentSession === session else { throw CancellationError() }
        files = loaded.sorted {
            $0.path.localizedCaseInsensitiveCompare($1.path) == .orderedAscending
        }
    }

    // MARK: - History leaf (Milestone O-5, #543)

    /// Loaded version-history pages for the selected note, newest
    /// first ("Show older versions" appends). Reset on selection
    /// change and vault close.
    @Published var historyVersions: [VersionSummary] = []
    /// Opaque next-page cursor; `nil` = no more pages.
    @Published var historyNextCursor: String?
    /// Total non-marker versions (the section header count).
    @Published var historyTotalFiltered: UInt64 = 0
    @Published var historyLoadError: String?
    /// True from `scheduleHistoryLoad` until the NEWEST load publishes
    /// (or the panel resets on vault close). Gates the HistoryPanel's
    /// first-page spinner: the list starts EMPTY after a vault open
    /// and the load is async, so without this flag the panel shows the
    /// misleading "No versions yet" copy for the whole load window
    /// (the Tasks/Citations panels' loading idiom, applied here).
    /// Note-to-note switches LATCH the previous rows until the new
    /// publish (no flash — deliberate), so the spinner only fills
    /// genuinely-empty windows. Stale loads guard-return without
    /// touching the flag — the newest publish (first-page load OR
    /// `loadOlderVersions`, which also bumps the seq) or the reset
    /// clears it.
    @Published var isHistoryLoading = false
    /// Since-last-open verdict for the selected note. Populated ONLY
    /// when the pref is on — the compute-then-mark funnel order is
    /// pinned by o_spec §O-4/§O-5 (g3): compute first, then mark;
    /// mark-first would silently report Unchanged forever.
    @Published var sinceOpenChanges: ChangesSinceOpen?
    /// Deleted-file remnants (the "Deleted" segment).
    @Published var deletedFiles: [DeletedFileEntry] = []
    @Published var deletedLoadError: String?
    /// Pending "Restore As…" destination prompt (#795): raised when a
    /// deleted-file recovery hits an occupied destination, or from a
    /// version row's Restore As… action (materialize a copy).
    @Published var historyRestoreAsPrompt: RestoreAsPrompt?
    /// Pending restore confirmation (drives the alert).
    @Published var historyRestoreRequest: HistoryRestoreRequest?
    /// History-specific error alert (integrity failure, recover
    /// errors) — never routed through the generic save-error path.
    @Published var historyAlert: HistoryAlert?
    /// Compaction-failure alert payload (the O-2 VaultEventListener
    /// channel's Mac half).
    @Published var compactionFailure: CompactionFailure?
    /// Once-per-(path, session) gate for compaction-failure alerts —
    /// repeated failures on one file don't re-alert (the announcement-
    /// gate pattern). Reset with the session.
    var compactionAlertedPaths: Set<String> = []
    /// The alerts.md:36 "Don't Show Again" opt-out for the compaction-
    /// failure alert (#881). When true, `handleVaultEvent` routes the
    /// failure to a polite AX announcement instead of the app-modal alert
    /// — never silent (o_spec §O-2). Loaded from `PreferencesStore` in
    /// `init`; set only via `suppressCompactionFailureAlert()` (which
    /// lives in the AppState+History extension, so this can't be
    /// `private(set)` — the discipline is by convention).
    @Published var compactionAlertSuppressed: Bool = false
    /// uniffi listener registration token, unregistered on close.
    var vaultEventListenerToken: UInt64?
    /// The adapter's lifetime is ours: uniffi keeps a foreign handle,
    /// but the strong reference lives here.
    var vaultEventAdapter: VaultEventAdapter?
    /// Latest-wins sequencing for history loads (the sync-diagnostics
    /// seq pattern, #638).
    var historyLoadSeq: UInt64 = 0
    /// Bumps after a successful restore so the panel moves focus to
    /// the new head row (WCAG 2.4.3 — the old row's position shifted;
    /// "return focus" is defined as the new head).
    @Published var historyFocusHeadToken: UInt64 = 0
    /// Mirrors `PreferencesStore` key
    /// `slate.prefs.historyShowChangesSinceOpen`. Drives the UI
    /// section and the mark writes only — no core behavior.
    @Published var historyShowChangesSinceOpen: Bool = false
    /// Task handle for the per-note history load (cancelled with the
    /// other note-scoped work).
    var historyLoadTask: Task<Void, Never>?
    /// O-5 race-test seam — ALWAYS nil in production (the M-3
    /// `syncDiagnosticsPublishGate` pattern). Awaited between the
    /// detached compute and the main-actor guards so tests can park a
    /// load inside the window and prove a stale resume neither
    /// publishes NOR marks the baseline.
    var historyPublishGate: (() async -> Void)?

    // MARK: - Sync diagnostics (Milestone M-3, #534)

    /// Latest sync-detection report for the open vault. `nil` while
    /// the first load is in flight — the panel's loading state.
    @Published private(set) var syncReport: SyncDetectionReport?
    /// LiveSync plugin config status, loaded alongside the report.
    @Published private(set) var liveSyncConfig: LiveSyncConfigStatus?
    /// Specific failure message when either FFI call failed; the
    /// panel renders it with a Retry button.
    @Published private(set) var syncDiagnosticsError: String?

    /// Vault path the assertive sync announcement last fired for —
    /// the announce-once gate (the `announcedFilePath` pattern from
    /// CitationsPanel, vault-scoped). Reopening the same vault stays
    /// silent; a different vault re-arms. Deliberately NOT cleared on
    /// close: the risk story hasn't changed just because the vault
    /// was closed and reopened mid-session.
    private var syncAnnouncedVaultPath: String?

    /// M-3 (#534) race-test seam — ALWAYS nil in production. When set,
    /// `loadSyncDiagnostics` awaits it after the detached probe
    /// returns and BEFORE the publish guard, so the stale-refresh
    /// regression test can deterministically park a load inside the
    /// race window (a `Task.yield()`-based interleaving is scheduler
    /// behavior, not a guarantee — codex adversarial round 2). A nil
    /// hook is a single optional check on the load path.
    var syncDiagnosticsPublishGate: (() async -> Void)?

    /// Live marker re-detection (#638): a bounded directory watch on
    /// the detector's in-vault probe locations, debounced into
    /// `refreshSyncDiagnostics()`. Started from the post-scan
    /// continuation, torn down on vault close/switch. The
    /// announce-once gate above is what makes "newly risky
    /// mid-session" (git init, LiveSync install) announce exactly
    /// once without any watcher-side state.
    private var syncMarkerWatcher: SyncMarkerWatcher?

    /// Watcher debounce — injectable so tests don't wait
    /// production-scale quiet periods (`internal` for @testable).
    var syncMarkerWatcherDebounce: TimeInterval = 2.5

    /// Monotonic sequence for in-flight sync-diagnostics loads (#638
    /// adversarial re-review). The `currentSession === session` guard
    /// stops a stale load from publishing under a DIFFERENT vault, but
    /// within one session the initial post-scan load and a
    /// watcher-triggered refresh can overlap — and their detached
    /// probes can resume out of order. Each load captures the sequence
    /// value it bumped this to; only the load whose captured value is
    /// still the latest may publish, so an older clean probe can't
    /// clobber a newer marker-positive report. Reset on vault
    /// switch/close is unnecessary (monotonic + the session guard).
    private var syncDiagnosticsLoadSeq: Int = 0

    /// Arm the marker watcher for the current vault (#638). Called
    /// BEFORE the initial diagnostics probe in the post-scan funnel and
    /// awaited, so the watch is provably live before the probe reads —
    /// arm-then-probe closes the setup-race window (adversarial
    /// re-review). Idempotent per vault (re-arming stops the previous
    /// watcher).
    func startSyncMarkerWatcher() async {
        syncMarkerWatcher?.stop()
        syncMarkerWatcher = nil
        guard let vaultURL = currentVaultURL else { return }
        let watcher = SyncMarkerWatcher(
            root: vaultURL,
            debounceInterval: syncMarkerWatcherDebounce
        ) { [weak self] in
            // The watcher guarantees delivery on the MAIN queue, which
            // is the MainActor's executor — so assume isolation and run
            // the exact funnel the Refresh command uses directly. (Do
            // NOT wrap in an unstructured `Task { @MainActor … }`: that
            // spawns a stray task per callback whose task-local
            // allocations can outlive the caller's scope and corrupt
            // the concurrency allocator under rapid open/close churn.
            // `refreshSyncDiagnostics()` already owns its own Task.)
            // The session-identity guard in loadSyncDiagnostics makes a
            // late event after a vault switch harmless.
            MainActor.assumeIsolated {
                self?.refreshSyncDiagnostics()
            }
        }
        // Await arming: `start()` returns only once the fds are open, so
        // by the time the caller runs the initial probe the watch is
        // provably live (arm-then-probe, no setup-race window — #638
        // adversarial re-review). The await suspends without blocking
        // the main thread (no `queue.sync`).
        syncMarkerWatcher = watcher
        await watcher.start()
    }

    /// Tear down the marker watcher (vault close/switch).
    func stopSyncMarkerWatcher() {
        syncMarkerWatcher?.stop()
        syncMarkerWatcher = nil
    }

    /// Re-run detection + config read. Wired to the panel's Refresh
    /// button, the `slate.diagnostics.refreshSync` command, and its
    /// View-menu item.
    func refreshSyncDiagnostics() {
        Task { [weak self] in
            await self?.loadSyncDiagnostics()
        }
    }

    /// Load `detect_sync` + `livesync_config` off the main actor and
    /// publish (M-3, #534). Both are bounded filesystem probes — cheap,
    /// but they leave the main actor like every other FFI call. Errors
    /// land in `syncDiagnosticsError` for the panel's error state.
    func loadSyncDiagnostics() async {
        guard let session = currentSession else { return }
        // Claim the latest slot for this session (#638 adversarial
        // re-review). Bumped synchronously on the actor before the
        // detached probe; only the load still holding the top value may
        // publish, so an older overlapping same-vault load can't
        // clobber a newer one after resuming out of order.
        syncDiagnosticsLoadSeq += 1
        let seq = syncDiagnosticsLoadSeq
        let result: Result<(SyncDetectionReport, LiveSyncConfigStatus), VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    let report = try session.detectSync()
                    let config = try session.livesyncConfig()
                    return .success((report, config))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }.value
        // Race-test seam: parks the load inside the race window
        // (post-probe, pre-guard). Nil in production — see the
        // property doc.
        if let gate = syncDiagnosticsPublishGate { await gate() }
        // A vault switch mid-load: don't publish a stale report over
        // the new vault's freshly-reset state. `Task.isCancelled` only
        // covers the scanTask funnel — `refreshSyncDiagnostics()` runs
        // in its own Task that a vault switch never cancels, so a
        // refresh started under vault A resuming after a switch to B
        // would otherwise publish A's report AND fire A's assertive
        // announcement under B's gate (poisoning B's announce-once).
        // The session-identity recheck is the #328 red-team P1 pattern
        // every other post-await publish in this file uses. The seq
        // recheck adds same-session ordering: a newer load has since
        // bumped the counter, so this stale resume must not publish.
        guard !Task.isCancelled, currentSession === session,
            seq == syncDiagnosticsLoadSeq
        else { return }
        switch result {
        case .success(let (report, config)):
            syncReport = report
            liveSyncConfig = config
            syncDiagnosticsError = nil
            announceSyncFindingsIfNeeded(report)
        case .failure(let error):
            syncDiagnosticsError = humanReadable(error)
        }
    }

    /// Assertive announcement for risky sync states (m_spec §M-3):
    /// iff the report carries a multi-sync warning OR any High-risk
    /// provider, post the pre-rendered `audioSummary` at `.high`
    /// priority — at most once per vault. Low/Medium-only and empty
    /// reports stay silent: the leaf is discoverable, not shouty.
    private func announceSyncFindingsIfNeeded(_ report: SyncDetectionReport) {
        guard let vaultPath = currentVaultURL?.path else { return }
        guard syncAnnouncedVaultPath != vaultPath else { return }
        let hasHighRisk = report.providers.contains { $0.riskLevel == .high }
        guard report.multiSyncWarning != nil || hasHighRisk else { return }
        syncAnnouncedVaultPath = vaultPath
        announcer.post(report.audioSummary, priority: .high)
    }

    /// Read the selected note's bytes + indexed headings off the main
    /// actor and publish both. Surfaces InvalidUtf8 / FileTooLarge / IO
    /// via `noteLoadError`. Honors task cancellation so a fast click-
    /// through doesn't leave a stale string in `currentNoteText` or a
    /// stale outline.
    ///
    /// Both calls go in the same detached task: `read_text` and
    /// `get_file_metadata` each take the same SQLite mutex on the Rust
    /// side, so serializing them at the call site keeps the lock-
    /// contention picture predictable and ensures the text + outline
    /// we publish are from the same observation.
    func loadCurrentNote(path: String) async {
        guard let session = currentSession else { return }
        // Codex round 7: a task cancelled BEFORE its body ran must not
        // set the spinner it will never clear (this loader clears
        // explicitly at landing, not via defer — audit #201's race).
        guard !Task.isCancelled else { return }
        isLoadingNote = true

        // Capture (text, headings, contentHash) in one detached
        // task. The hash comes from `get_file_metadata.contentHash`
        // — that's the same hash the scanner cached, so it matches
        // what's on disk right now (modulo external writes between
        // the scan and this load, which `read_text` would have
        // surfaced as an error or stale-content situation). The
        // save-flow uses this hash as `expected_content_hash` so a
        // mid-edit external write is caught as `WriteConflict`.
        let result: Result<(NotePartsBundle, [Heading]), VaultError> = await Task.detached(priority: .userInitiated) {
            do {
                // U3-3 (#467/#469): the buffer is the BODY. One read, one
                // hash — `read_note_parts` splits at the canonical scanner
                // boundary and its hash covers the WHOLE file, so the
                // composed-save conflict chain stays intact.
                let parts = try session.readNoteParts(path: path)
                // get_file_metadata returns nil when the path isn't in
                // the index yet (race: file showed up between scan and
                // selection). Empty headings is the right fallback —
                // the outline pane shows its "no headings" empty state
                // and the user still sees the content.
                let metadata = try session.getFileMetadata(path: path)
                return .success((parts, metadata?.headings ?? []))
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }.value

        // Don't touch `isLoadingNote` if the user has already moved
        // on. Same reasoning as `loadCurrentLinks`: the newer task
        // already set the flag, and clearing it here would flicker
        // the loading state off briefly.
        guard !Task.isCancelled, currentSession === session,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }

        switch result {
        case .success(let (parts, headings)):
            currentNoteText = parts.body
            savedBaselineText = parts.body
            currentNoteContentHash = parts.contentHash
            currentNoteFMSource = parts.fmSource
            bodyByteOffset = Int(parts.bodyByteOffset)
            bodyLineOffset = Int(parts.bodyLineOffset)
            _ = restoreParkedPropertiesSourceDraft(
                for: path,
                authoritativeFrontmatterSource: parts.fmSource)
            loadedFilePath = path
            hasUnsavedChanges = false
            // The editor + reading view live in BODY space; backend
            // offsets are whole-file. Rebase once, here — every consumer
            // downstream (outline anchors, rotor, scroll routing) is then
            // body-relative for free.
            currentNoteHeadings = Self.rebasedToBody(
                headings, prefixBytes: Int(parts.bodyByteOffset))
            noteLoadError = nil
            deliverDeferredTemplateCursorIfReady(session: session, path: path)
        case .failure(let error):
            clearDeferredTemplateCursorIfMatching(session: session, path: path)
            currentNoteText = nil
            savedBaselineText = nil
            currentNoteContentHash = nil
            currentNoteFMSource = ""
            bodyByteOffset = 0
            bodyLineOffset = 0
            loadedFilePath = nil
            hasUnsavedChanges = false
            currentNoteHeadings = []
            // #868 red-team (Codex): a load FAILURE for the mounted path
            // (a same-path conflict reload whose file was externally
            // deleted/corrupted) tears the note down here without going
            // through `clearActiveNoteFields`, and NoteContentView
            // unmounts the properties widget before its `.onChange` can
            // reset the mirror — the same wrong-direction "Hide
            // Properties Source" latch the delete arm had. Reset both
            // mirror fields on the error mount.
            propertiesSourceShowing = false
            propertiesSourceError = nil
            noteLoadError = humanReadable(error)
        }
        isLoadingNote = false
    }

    /// Load the inbound (backlinks) and outgoing-links lists for the
    /// currently-selected note off the main actor. Both queries hit
    /// the same SQLite mutex so we run them in one detached task to
    /// keep the lock-contention picture predictable.
    ///
    /// The backlinks query is bounded with a generous page size
    /// (200) because the sidebar panel doesn't yet paginate — that
    /// lands when we wire link activation in #C5. Vaults with more
    /// than 200 inbound links to a single note are vanishingly rare
    /// in V1 territory and will get a "+ more" affordance later.
    func loadCurrentLinks(path: String, publishProperties: Bool = true) async {
        guard let session = currentSession else { return }
        // Codex round 7: same late-body guard as `loadCurrentNote` —
        // explicit-clear loaders must never set a flag under a
        // cancellation they'll drop at landing.
        guard !Task.isCancelled else { return }
        isLoadingLinks = true

        // Pull links + properties under a single mutex acquisition.
        // Previously this called `backlinks`, `outgoingLinks`, and
        // `getFileMetadata` in sequence — three independent lock
        // grabs that each raced the scanner's transaction-long lock
        // hold (#92 item 4). The new `noteLoadBundle` API holds the
        // mutex for one contiguous slice while it runs all three
        // queries.
        let result: Result<([Backlink], [OutgoingLink], [Property]), VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    let bundle = try session.noteLoadBundle(
                        path: path,
                        backlinksPaging: Paging(cursor: nil, limit: 200)
                    )
                    return .success((bundle.backlinks.items, bundle.outgoingLinks, bundle.properties))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value

        // Don't touch `isLoadingLinks` if the user has already moved
        // on: a newer task is in flight and has already re-set the
        // flag to `true`, so clearing it here would flicker the
        // spinner off mid-load. The newer task owns the flag's
        // lifecycle from this point on.
        guard !Task.isCancelled, currentSession === session,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }

        switch result {
        case .success(let (backlinks, outgoing, properties)):
            currentBacklinks = backlinks
            currentOutgoingLinks = outgoing
            currentOutgoingLinksPath = path
            if publishProperties {
                currentNoteProperties = properties
            }
            linksLoadError = nil
        case .failure(let error):
            currentBacklinks = []
            currentOutgoingLinks = []
            // Failure is still an ANSWER for this note (empty records
            // + error surface) — stamp ownership so reading classifies
            // against it rather than a previous note's records.
            currentOutgoingLinksPath = path
            if publishProperties {
                currentNoteProperties = []
            }
            linksLoadError = humanReadable(error)
        }
        isLoadingLinks = false
    }

    // MARK: - Embeds (#187)

    /// Resolve every `is_embed = true` outgoing link in
    /// `currentOutgoingLinks` against the backend and publish the
    /// result map as `currentNoteEmbedResolutions`. Called after
    /// `loadCurrentLinks` so the link list is already populated
    /// when we fan out per-embed.
    ///
    /// Each resolution is a separate FFI call; we batch them off
    /// the main actor to avoid pinning it while the SQLite mutex
    /// is held repeatedly.
    ///
    /// Failure handling (audit #202): per-embed failures don't
    /// discard the rest of the batch. An FFI throw on one embed
    /// becomes a synthesized `EmbedResolution.unresolved(reason:
    /// .readError(message:))` for that key and the loop keeps
    /// going. `embedsLoadError` is reserved for whole-batch
    /// problems (no session, etc.) — per-embed errors land in the
    /// resolution itself where the UI's `EmbedView` already
    /// renders them with the right shape.
    func loadCurrentNoteEmbedResolutions(path: String) async {
        guard let session = currentSession else { return }
        // Snapshot the embed targets from the just-loaded links.
        // We pass these into the detached task so a selection
        // change can't race the snapshot against a partial refresh.
        //
        // Each entry carries the composed cache key plus any alias
        // spellings the same embed can be looked up under. Block
        // anchors have two authored forms — the canonical Obsidian
        // `target#^id` and the legacy bare `target^id` (#413) — and
        // the editor's Cmd+E path looks up the AUTHORED text between
        // `![[` and `]]`, so the resolution must be reachable under
        // both. The composed key uses the bare form (the FFI
        // round-trip contract); the `#^` form is registered as an
        // alias of the same resolution.
        let embedTargets: [(key: String, aliases: [String], alt: String?)] =
            currentOutgoingLinks
            .filter { $0.isEmbed }
            .map { link in
                let key = embedTargetKey(link)
                // #433: the link's authored display text — for image
                // embeds, the alt — rides along so the resolver no
                // longer re-reads the host to recover it.
                if let anchor = link.targetAnchor, anchor.kind == "block" {
                    return (key, ["\(link.targetRaw)#^\(anchor.text)"], link.displayText)
                }
                return (key, [], link.displayText)
            }
        // Codex round 5, entry guard: an orphaned chain task (created
        // by a links leg whose result was already dropped) must not
        // clear the NEW note's resolutions through the empty-targets
        // path, nor set the loading flag after the newer chain has
        // finished. Mirrors the landing guard below.
        guard !Task.isCancelled,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }
        if embedTargets.isEmpty {
            currentNoteEmbedResolutions = [:]
            embedsLoadError = nil
            isLoadingEmbeds = false
            return
        }
        isLoadingEmbeds = true

        let resolutions: [String: EmbedResolution] =
            await Task.detached(priority: .userInitiated) {
                var out: [String: EmbedResolution] = [:]
                for target in embedTargets {
                    let resolution: EmbedResolution
                    do {
                        resolution = try session.resolveEmbed(
                            hostPath: path,
                            target: target.key,
                            alt: target.alt
                        )
                    } catch let error as VaultError {
                        // Per-embed failure: synthesize an
                        // Unresolved entry instead of bailing out
                        // of the whole batch (audit #202).
                        resolution = .unresolved(
                            reason: .readError(message: Self.humanReadableVaultError(error))
                        )
                    } catch {
                        resolution = .unresolved(
                            reason: .readError(message: error.localizedDescription)
                        )
                    }
                    // Same-src duplicates: the cache is keyed on
                    // target, so multiple occurrences overwrite in
                    // ordinal order and share the LAST one's
                    // resolution (incl. its alt). Per-occurrence alt
                    // exists at the resolution layer (#433) — nested
                    // embeds get it structurally; surfacing it at
                    // top level needs per-occurrence cache keys, a
                    // UI-contract change deferred with rationale on
                    // the issue.
                    out[target.key] = resolution
                    for alias in target.aliases {
                        out[alias] = resolution
                    }
                }
                return out
            }
            .value

        // Audit #201: clearing the spinner via `defer` made an old
        // cancelled task's late-firing deferred clear race the new
        // task's `isLoadingEmbeds = true`, briefly exposing the
        // panel to "not yet resolved" placeholders. Set explicitly
        // at the end, gated on the selection-change check below —
        // same pattern `loadCurrentLinks` uses.
        guard !Task.isCancelled,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }

        currentNoteEmbedResolutions = resolutions
        embedsLoadError = nil
        isLoadingEmbeds = false
    }

    /// Resolve ONE embed cache key against the current note and merge it into
    /// `currentNoteEmbedResolutions` (#511, block-level reading embeds).
    ///
    /// The batch resolver (`loadCurrentNoteEmbedResolutions`) only sees embeds
    /// in the SAVED-state `currentOutgoingLinks`; reading mode renders the
    /// LIVE buffer, so a just-typed `![[…]]` can be visible with no dict
    /// entry. The reading view's block-embed placeholder calls this once per
    /// missing key to fill that gap. The `target` string is already the
    /// cache-key form (`ReadingInlineMapper.blockEmbedTarget`, ==
    /// `embedTargetKey`), so it is BOTH the resolver input and the dict key —
    /// no re-derivation.
    ///
    /// Terminal by design: whatever the resolver returns (including a
    /// synthesized `.unresolved` on a broken target or FFI failure) is written
    /// under `target`, so the placeholder collapses to a real `EmbedView`
    /// render and can't spin forever. When there is no session — the one path
    /// that writes nothing — the reading view's own request-once guard keeps
    /// the key marked, and its state machine falls back to the inline link-run
    /// (deterministic, no re-request).
    func requestReadingEmbedResolution(target: String) async {
        guard let session = currentSession, let path = selectedFilePath else { return }
        // Already landed (a racing batch, or a duplicate request the view's
        // guard didn't cover across a re-init): don't re-resolve.
        if currentNoteEmbedResolutions[target] != nil { return }

        let resolution: EmbedResolution =
            await Task.detached(priority: .userInitiated) {
                do {
                    return try session.resolveEmbed(
                        hostPath: path, target: target, alt: nil)
                } catch let error as VaultError {
                    return .unresolved(
                        reason: .readError(message: Self.humanReadableVaultError(error)))
                } catch {
                    return .unresolved(
                        reason: .readError(message: error.localizedDescription))
                }
            }
            .value

        // Drop the write if the user navigated away mid-resolve — same
        // stale-guard the batch path uses.
        guard BaseExactIdentity.matches(selectedFilePath, path) else { return }
        // Merge (never replace): the batch may have populated other keys while
        // this single resolve was in flight.
        currentNoteEmbedResolutions[target] = resolution
    }

    // MARK: - Content pipelines (#223)

    /// Load math blocks for `path` via the math pipeline and publish
    /// to `currentNoteMathBlocks`. Cancellable, race-guarded, drops
    /// stale writes when the user has moved on. Same shape as
    /// `loadCurrentNoteEmbedResolutions`.
    func loadCurrentNoteMathBlocks(path: String) async {
        guard let session = currentSession else { return }
        isLoadingMathBlocks = true
        // Audit #257 M2: clear the spinner on EVERY exit path,
        // including cancellation / selection-moved-away. Without
        // `defer`, the late-arriving race-guard short-circuit
        // would leave `isLoadingMathBlocks = true` forever — a
        // WCAG 4.1.3 "stuck busy state" that VoiceOver would
        // announce and never withdraw.
        defer { isLoadingMathBlocks = false }
        let result: Result<[MathBlock], VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    return .success(try session.getMathBlocks(path: path))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }
        switch result {
        case .success(let blocks):
            currentNoteMathBlocks = blocks
            mathBlocksLoadError = nil
        case .failure(let err):
            currentNoteMathBlocks = []
            mathBlocksLoadError = humanReadable(err)
        }
    }

    /// Load code blocks (syntax-highlighted) for `path` and publish
    /// to `currentNoteCodeBlocks`. Same shape as
    /// `loadCurrentNoteMathBlocks`.
    func loadCurrentNoteCodeBlocks(path: String) async {
        guard let session = currentSession else { return }
        isLoadingCodeBlocks = true
        defer { isLoadingCodeBlocks = false }  // audit #257 M2
        let result: Result<[CodeBlock], VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    return .success(try session.getSyntaxTokens(path: path))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }
        switch result {
        case .success(let blocks):
            currentNoteCodeBlocks = blocks
            codeBlocksLoadError = nil
        case .failure(let err):
            currentNoteCodeBlocks = []
            codeBlocksLoadError = humanReadable(err)
        }
    }

    /// Load citation references for `path`, render each against the
    /// active CSL style, and publish to `currentNoteCitations`. Same
    /// shape as `loadCurrentNoteMathBlocks` — cancellable, race-
    /// guarded, drops stale writes when the user has moved on.
    ///
    /// When no bibliography is configured (`activeStyleId.isEmpty`)
    /// we publish an empty list rather than calling render with a
    /// missing style — the panel will then show the "no bibliography
    /// configured" empty state. Citations without a matching
    /// bibliography entry still render through the renderer's
    /// unresolved path ("Unresolved citation: <key>") so screen-
    /// reader users hear what's missing.
    func loadCurrentNoteCitations(path: String) async {
        guard let session = currentSession else { return }
        isLoadingCitations = true
        defer { isLoadingCitations = false }

        // Style id source: `activeStyleId` is empty until the Settings
        // panel (#281) wires `.slate/prefs.json`'s `default_style`
        // through. An empty id means "render not possible yet" — we
        // still pull the structural citation refs so the panel can
        // show keys + line numbers, but the visual + speech forms
        // come back empty from the renderer.
        let styleId = activeStyleId

        let result: Result<([CitationReference], [RenderedCitation]), VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    let refs = try session.listCitationsInFile(path: path)
                    guard !styleId.isEmpty else {
                        // No style yet — synthesize a placeholder
                        // RenderedCitation per ref using the key as
                        // the speech form. The panel announces these
                        // as "Citation: <key>" so AT users can still
                        // hear where citations are.
                        return .success(
                            (refs, refs.map { placeholderRendered(for: $0) })
                        )
                    }
                    var rendered: [RenderedCitation] = []
                    rendered.reserveCapacity(refs.count)
                    for ref in refs {
                        rendered.append(
                            try session.renderCitation(
                                reference: ref,
                                styleId: styleId
                            )
                        )
                    }
                    return .success((refs, rendered))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }
        switch result {
        case .success(let (refs, renders)):
            currentNoteCitationRefs = refs
            currentNoteCitations = renders
            citationsLoadError = nil
        case .failure(let err):
            currentNoteCitations = []
            currentNoteCitationRefs = []
            citationsLoadError = humanReadable(err)
        }
    }

    // MARK: - Bibliography prefs (#281)

    /// Read `<vault>/.slate/prefs.json` and publish its bibliography
    /// section. Called after a successful `openVault`. Parse failures
    /// surface as `bibliographyLoadError` so the user sees what went
    /// wrong rather than a silent no-bibliography state.
    func loadBibliographyPrefsFromDisk() {
        guard let vault = currentVaultURL else {
            bibliographyPrefs = .empty
            return
        }
        let store = PrefsJsonStore(vaultRoot: vault)
        do {
            let prefs = try store.readBibliographyPrefs()
            bibliographyPrefs = prefs
            bibliographySettingsError = nil
            // Seed activeStyleId from the persisted default (basename
            // without `.csl`). The didSet on activeStyleId triggers
            // a citation re-render for the current note.
            if let defaultPath = prefs.defaultStyle, !defaultPath.isEmpty {
                activeStyleId =
                    (defaultPath as NSString).lastPathComponent
                    .replacingOccurrences(of: ".csl", with: "")
            } else {
                activeStyleId = ""
            }
        } catch {
            bibliographyPrefs = .empty
            bibliographySettingsError = error.localizedDescription
        }
    }

    /// Adopt the session's effective citations config (#411): the
    /// merged `.slate/prefs.json` ⊕ vault-root `slate.json` view the
    /// Rust core resolved at open. Publishes it to the Settings
    /// surface and pushes sources into the bibliography index
    /// WITHOUT writing prefs.json — vault-shipped config must not be
    /// frozen into the app-written file by the mere act of opening
    /// the vault (red-team C1 on #411 found the previous gap: the
    /// merged config was passive and the demo vault still showed
    /// zero resolved citations).
    func adoptSessionCitationsConfig() async {
        guard let session = currentSession else { return }
        let effective = session.citationsPrefs()
        guard !effective.sources.isEmpty else {
            await refreshAvailableCslStyles()
            return
        }
        bibliographyPrefs = BibliographyPrefs(
            sources: effective.sources,
            defaultStyle: effective.defaultStyle,
            additionalStyles: effective.additionalStyles
        )
        if let defaultPath = effective.defaultStyle, !defaultPath.isEmpty {
            activeStyleId =
                (defaultPath as NSString).lastPathComponent
                .replacingOccurrences(of: ".csl", with: "")
        }
        await pushBibliographySources(effective.sources)
    }

    /// Persist `newPrefs` to disk AND push the new sources through
    /// the session (so the in-memory `bibliography_entries` table
    /// matches what the user just configured). Called by every
    /// Settings panel mutation — Add/Remove source, change default
    /// style, etc.
    func applyBibliographyPrefs(_ newPrefs: BibliographyPrefs) async {
        guard let vault = currentVaultURL else { return }
        let store = PrefsJsonStore(vaultRoot: vault)
        do {
            try store.writeBibliographyPrefs(newPrefs)
        } catch {
            bibliographySettingsError = error.localizedDescription
            return
        }
        bibliographyPrefs = newPrefs
        bibliographySettingsError = nil

        // Push sources to the session. Warnings (malformed entries,
        // missing files) flow back via `bibliographyLoadError` for
        // surfacing in the Settings UI.
        await pushBibliographySources(newPrefs.sources)
    }

    /// Push `sources` into the session's bibliography index and
    /// refresh every downstream surface (entries, styles, current
    /// note's citation renders). Shared by the Settings mutation
    /// path (`applyBibliographyPrefs`) and the vault-config adopt
    /// path (`adoptSessionCitationsConfig`) — the only difference
    /// between those is whether prefs.json gets written first.
    private func pushBibliographySources(_ sources: [BibliographySource]) async {
        guard let session = currentSession else { return }
        let result: Result<[BibLoadWarning], VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    return .success(try session.setBibliographySources(sources: sources))
                } catch let err as VaultError {
                    return .failure(err)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled else { return }
        switch result {
        case .success(let warnings):
            if !warnings.isEmpty {
                bibliographySettingsError = warnings
                    .map { "\($0.sourcePath): \($0.message)" }
                    .joined(separator: "\n")
            }
            await loadBibliographyEntries()
            await refreshAvailableCslStyles()
            // Re-render the current note's citations against the
            // (possibly new) default style.
            if let path = selectedFilePath {
                citationsLoadTask?.cancel()
                citationsLoadTask = Task { [weak self] in
                    await self?.loadCurrentNoteCitations(path: path)
                }
            }
        case .failure(let err):
            bibliographySettingsError = humanReadable(err)
        }
    }

    /// Jump-to-Bibliography (#282). Pull the first citation key out
    /// of the currently-expanded citation's `raw` text, set the
    /// search field + filter target, and close the popover so the
    /// sidebar surface is reachable. The BibliographyPanel observes
    /// `pendingBibliographyKeyFocus` and switches to its Entries
    /// segment with the key as the query.
    func jumpToBibliographyFromExpandedCitation() {
        guard let citation = expandedCitation else { return }
        let key = extractCitationKey(from: citation.raw)
        guard !key.isEmpty else { return }
        bibliographySearchText = key
        pendingBibliographyKeyFocus = key
        expandedCitation = nil
        let resolved = bibliographyEntries.contains(where: { $0.key == key })
        let message =
            resolved
            ? "Jumped to bibliography entry: \(key)."
            : "Searching bibliography for: \(key)."
        postAccessibilityAnnouncement(message, priority: .medium)
    }

    /// Update the active CSL style id (driven by Settings panel's
    /// style picker and by the View → Citation Style menu in #282).
    /// Announces the change via VoiceOver and re-renders the current
    /// note's citations. Idempotent — no announcement when `newId`
    /// equals the current `activeStyleId`.
    func switchActiveStyle(to newId: String) {
        guard newId != activeStyleId else { return }
        activeStyleId = newId  // didSet triggers re-render
        let title =
            availableCslStyles.first(where: { $0.id == newId })?.title ?? newId
        postAccessibilityAnnouncement(
            "Citation style: \(title).",
            priority: .medium
        )
    }

    /// Refresh `availableCslStyles` from the session — picks up
    /// changes the user just made to prefs.json (e.g. adding an
    /// additional style).
    func refreshAvailableCslStyles() async {
        guard let session = currentSession else {
            availableCslStyles = []
            return
        }
        let result: Result<[CslStyleInfo], VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    return .success(try session.listCslStyles())
                } catch let err as VaultError {
                    return .failure(err)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled else { return }
        switch result {
        case .success(let styles):
            availableCslStyles = styles
        case .failure:
            availableCslStyles = []
        }
    }

    // MARK: - Bibliography loaders (#280)

    /// Load the merged bibliography from the session's DB into
    /// `bibliographyEntries`. Cancel-safe; idempotent. Call after
    /// `setBibliographySources` or whenever the panel is opened to
    /// re-read the index. Auto-refreshes the `unresolvedCitations`
    /// list afterwards since the two views move together.
    func loadBibliographyEntries() async {
        guard let session = currentSession else {
            bibliographyEntries = []
            unresolvedCitations = []
            return
        }
        // Load-fire spy (tests only): counts real fetches so the U4-1
        // leaf-retention test can prove a mounted Bibliography leaf doesn't
        // re-fetch on leaf switch.
        bibliographyLoadCount += 1
        isLoadingBibliography = true
        defer { isLoadingBibliography = false }

        let result: Result<([BibEntry], [UnresolvedCitation]), VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    let entries = try session.getBibliographyEntries()
                    let unresolved = try session.listUnresolvedCitations()
                    return .success((entries, unresolved))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled else { return }
        switch result {
        case .success(let (entries, unresolved)):
            bibliographyEntries = entries
            unresolvedCitations = unresolved
            bibliographyLoadError = nil
        case .failure(let err):
            bibliographyEntries = []
            unresolvedCitations = []
            bibliographyLoadError = humanReadable(err)
        }
    }

    /// Request the set of vault files that cite `key`. Populates
    /// `filesCitingResult` for the BibliographyPanel's
    /// "Show files citing this entry" sheet.
    func requestFilesCiting(key: String) async {
        guard let session = currentSession else { return }
        let result: Result<[String], VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    return .success(try session.listFilesCiting(citationKey: key))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled else { return }
        switch result {
        case .success(let files):
            filesCitingResult = files
        case .failure:
            filesCitingResult = []
        }
    }

    /// Filtered view of `bibliographyEntries` against
    /// `bibliographySearchText`. Empty query returns everything.
    /// Substring match on title + author family + key (case-
    /// insensitive). Defined as a method (not computed property)
    /// because SwiftUI re-evaluates filtered lists every render
    /// pass and the closure form keeps the call-site explicit.
    func filteredBibliographyEntries() -> [BibEntry] {
        filterBibliographyEntries(
            bibliographyEntries,
            query: bibliographySearchText
        )
    }

    /// Load Mermaid diagram blocks (rendered SVG + structured
    /// description) for `path` and publish to
    /// `currentNoteDiagramBlocks`. Same shape as
    /// `loadCurrentNoteMathBlocks`.
    func loadCurrentNoteDiagramBlocks(path: String) async {
        guard let session = currentSession else { return }
        isLoadingDiagramBlocks = true
        defer { isLoadingDiagramBlocks = false }  // audit #257 M2
        let result: Result<[DiagramBlock], VaultError> =
            await Task.detached(priority: .userInitiated) {
                do {
                    return .success(try session.getDiagramBlocks(path: path))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }
            .value
        guard !Task.isCancelled,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }
        switch result {
        case .success(let blocks):
            currentNoteDiagramBlocks = blocks
            diagramBlocksLoadError = nil
        case .failure(let err):
            currentNoteDiagramBlocks = []
            diagramBlocksLoadError = humanReadable(err)
        }
    }

    /// Off-actor mirror of `humanReadable(_:)` — used inside the
    /// detached resolver loop where `self` isn't available. Keeps
    /// the per-embed `ReadError` message shape consistent with
    /// what the main-actor error surface produces.
    private nonisolated static func humanReadableVaultError(_ error: VaultError) -> String {
        switch error {
        case .Io(let m), .Db(let m), .Trash(let m), .InvalidQuery(let m),
            .InvalidArgument(let m):
            return m
        case .InvalidPath(let path, let reason):
            return "Invalid path \(path): \(reason)"
        case .Cancelled:
            return "Operation cancelled."
        case .InvalidUtf8(let path):
            return "File at \(path) is not valid UTF-8."
        case .FileTooLarge(let path, let size):
            return "File at \(path) is \(size) bytes — larger than this build's refuse threshold."
        case .Unsupported(let feature):
            return "\(feature) is not implemented yet."
        case .WriteConflict:
            return "File changed externally."
        case .MalformedFrontmatter(let path, let reason):
            return "Frontmatter at \(path) is malformed: \(reason)."
        case .BibSourceUnreadable(let path, let reason):
            return "Bibliography source \(path) couldn't be opened: \(reason)."
        case .CslStyleUnreadable(let path, let reason):
            return "Citation style \(path) couldn't be loaded: \(reason)."
        case .PrefsUnreadable(let path, let reason):
            return "Preferences file \(path) couldn't be loaded: \(reason)."
        case .DestinationExists(let path):
            return "Something named \(path) already exists there."
        case .HistoryUnavailable(let path, _):
            return "History for \(path) is unavailable: it failed an integrity check."
        }
    }

    /// Navigate to the target of an embed's "Jump to source" action.
    /// Wraps the private `navigate(to:kind:)` step so the embed
    /// panel + future inline editor activations share one entry
    /// point + announcement shape.
    func openEmbedTarget(_ path: String) {
        navigate(to: path, kind: "Opened embed source")
    }

    /// Pop the editor's Cmd+E embed-preview popover for `target`.
    /// `target` is the cache key form (target + optional `#heading`
    /// / `^block` suffix); we look up the already-resolved entry
    /// in `currentNoteEmbedResolutions` rather than re-resolving.
    /// No-op when the embed isn't in the cache (e.g. the user
    /// pressed Cmd+E before the resolutions finished loading).
    ///
    /// Audit #211: previously this also posted a "preview opened"
    /// AT announcement which competed with the popover's own
    /// `.accessibilityLabel` + the EmbedView's disclosure label,
    /// firing three near-identical sentences back to back. Dropped
    /// the action confirmation — the popover's label is the
    /// canonical "what you're looking at" message.
    ///
    /// Audit #212: rapid double Cmd+E with the same target used to
    /// re-fire side effects without state changes. Short-circuit
    /// when the same target is already pending so the popover
    /// behaves like an idempotent open.
    func requestEmbedPreview(target: String, sourceLine bodySourceLine: Int? = nil) {
        // U3-3: the editor reports body lines; the popover's spatial cue
        // ("source line N") should match what the user sees in the file.
        let sourceLine = bodySourceLine.map { fileLine(fromBodyLine: $0) }
        // Idempotency: re-firing Cmd+E on the exact same embed
        // occurrence (same target AND same source line) is a
        // no-op. A second Cmd+E on a different occurrence of
        // the same target — `![[foo]]` appearing twice on
        // different lines — still updates the popover so the
        // header's line number reflects where the user actually
        // is (Codoki PR #206).
        if let existing = pendingEmbedPreview,
            existing.target == target,
            existing.sourceLine == sourceLine
        {
            return
        }
        guard let resolution = currentNoteEmbedResolutions[target] else {
            postAccessibilityAnnouncement(
                "No resolved embed at cursor.",
                priority: .medium
            )
            return
        }
        pendingEmbedPreview = EmbedPreview(
            target: target,
            resolution: resolution,
            sourceLine: sourceLine
        )
    }

    /// Dismiss the embed-preview popover. Called by the popover's
    /// SwiftUI binding when the user clicks outside, presses Esc,
    /// or activates "Jump to source" (which closes the popover
    /// and navigates).
    func dismissEmbedPreview() {
        pendingEmbedPreview = nil
    }

    /// Compose the lookup key for an embed in `currentNoteEmbedResolutions`.
    /// Mirrors how the backend's `resolve_embed` parses the raw
    /// target (target_raw + optional anchor suffix); the map is
    /// keyed on this composite so the panel can look up "the
    /// resolution for this exact `![[…]]` reference."
    ///
    /// `LinkAnchor.kind` is one of `"heading"` / `"block"` — we map
    /// that back to the `#` / `^` marker so the reconstructed
    /// target matches what the user wrote between `![[` and `]]`.
    func embedTargetKey(_ link: OutgoingLink) -> String {
        if let anchor = link.targetAnchor {
            let marker = anchor.kind == "block" ? "^" : "#"
            return "\(link.targetRaw)\(marker)\(anchor.text)"
        }
        return link.targetRaw
    }

    // MARK: - Tasks (per-note + vault-wide)

    /// Load the per-note tasks for `path` off the main actor and
    /// publish them as `currentNoteTasks`. Same lifecycle shape as
    /// `loadCurrentLinks`: cancellable, dropped on the floor if the
    /// user has moved on by the time the query returns.
    ///
    /// `tasksForFile` returns an empty Vec when the path isn't
    /// indexed yet (race between selection and scan) — we surface
    /// that as an empty `currentNoteTasks` rather than an error,
    /// matching how the panels treat "no rows" elsewhere.
    func loadCurrentNoteTasks(path: String) async {
        guard let session = currentSession else { return }
        isLoadingTasks = true
        // #159: clear the spinner on EVERY exit path, including
        // cancellation and selection-moved-away. The previous
        // shape only cleared on success/failure, so a cancellation
        // without a replacement (e.g. selection cleared mid-load)
        // could leave the spinner stuck. `defer` runs on MainActor
        // when the function returns from any path, including the
        // early `guard` below.
        defer { isLoadingTasks = false }

        let result: Result<[TaskItem], VaultError> = await Task.detached(priority: .userInitiated) {
            do {
                let tasks = try session.tasksForFile(path: path)
                return .success(tasks)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }
        .value

        guard !Task.isCancelled,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return }

        switch result {
        case .success(let tasks):
            currentNoteTasks = tasks
            tasksLoadError = nil
        case .failure(let error):
            currentNoteTasks = []
            tasksLoadError = humanReadable(error)
        }
    }

    /// Refresh `currentNoteTasks` after a successful save so the
    /// panel reflects edits to task lines without waiting for the
    /// next selection change. Mirrors `refreshHeadingsAfterSave`'s
    /// shape: off-actor query, post-await re-grab of `self`, drop
    /// the result if the user has navigated away.
    ///
    /// Returns the in-flight Task so callers can stash it on
    /// `tasksRefreshTask` (and tests can await it deterministically
    /// instead of leaning on `Task.sleep` settle waits — #161).
    @discardableResult
    private func refreshTasksAfterSave(
        session: VaultSession,
        path: String
    ) -> Task<Void, Never> {
        Task { [weak self] in
            let tasks: [TaskItem]? = await Task.detached(priority: .userInitiated) {
                try? session.tasksForFile(path: path)
            }
            .value
            guard let self else { return }
            guard BaseExactIdentity.matches(self.loadedFilePath, path) else { return }
            self.currentNoteTasks = tasks ?? []
        }
    }

    // MARK: - Content pipeline refresh-after-save (audit #258)
    //
    // The math / code / diagram pipelines didn't refresh after a
    // `save_text`, so editing a fenced block would leave the
    // cached arrays stale until the user navigated away. Mirrors
    // `refreshTasksAfterSave`'s shape: off-actor FFI call,
    // post-await re-grab of `self`, drop the result if the user
    // has navigated away.

    @discardableResult
    private func refreshMathBlocksAfterSave(
        session: VaultSession,
        path: String
    ) -> Task<Void, Never> {
        Task { [weak self] in
            let blocks: [MathBlock]? = await Task.detached(priority: .userInitiated) {
                try? session.getMathBlocks(path: path)
            }
            .value
            guard let self else { return }
            guard BaseExactIdentity.matches(self.loadedFilePath, path) else { return }
            self.currentNoteMathBlocks = blocks ?? []
        }
    }

    @discardableResult
    private func refreshCodeBlocksAfterSave(
        session: VaultSession,
        path: String
    ) -> Task<Void, Never> {
        Task { [weak self] in
            let blocks: [CodeBlock]? = await Task.detached(priority: .userInitiated) {
                try? session.getSyntaxTokens(path: path)
            }
            .value
            guard let self else { return }
            guard BaseExactIdentity.matches(self.loadedFilePath, path) else { return }
            self.currentNoteCodeBlocks = blocks ?? []
        }
    }

    @discardableResult
    private func refreshDiagramBlocksAfterSave(
        session: VaultSession,
        path: String
    ) -> Task<Void, Never> {
        Task { [weak self] in
            let blocks: [DiagramBlock]? = await Task.detached(priority: .userInitiated) {
                try? session.getDiagramBlocks(path: path)
            }
            .value
            guard let self else { return }
            guard BaseExactIdentity.matches(self.loadedFilePath, path) else { return }
            self.currentNoteDiagramBlocks = blocks ?? []
        }
    }

    /// Flip the status character on a single task in the currently-
    /// loaded note. Calls `toggleTaskStatus` with the cached
    /// `currentNoteContentHash` so a mid-edit external write
    /// surfaces as a `WriteConflict` and routes through the same
    /// resolution UI the editor uses (#64). Refreshes
    /// `currentNoteTasks` on success so the panel mirrors the new
    /// state.
    ///
    /// The status toggle is `' '` ↔ `'x'`. Tasks already in a
    /// non-standard state (e.g. `[/]` in-progress, `[-]`
    /// cancelled) are normalised to one of those two by the
    /// completion check — the panel doesn't expose a way to
    /// author custom status chars (#113 scope).
    @discardableResult
    func toggleCurrentTask(_ task: TaskItem) -> Task<Void, Never>? {
        guard let session = currentSession else { return nil }
        guard let path = loadedFilePath else { return nil }
        guard admitBatchTrashWrite(to: [path]) else { return nil }
        // #158: The editor buffer is the user's authority. The
        // toggle's post-save reload (`reloadEditorBufferAfterToggle`)
        // unconditionally overwrites `currentNoteText` from disk —
        // and the FFI's WriteConflict check doesn't catch this case
        // because `currentNoteContentHash` tracks the *disk* hash,
        // not the buffer hash (the buffer can drift dirty while the
        // disk hash stays valid). So a toggle while the editor has
        // unsaved changes would silently drop those edits. Block
        // here, prompt the user to save first.
        guard !hasUnsavedChanges else {
            postAccessibilityAnnouncement(
                "Cannot toggle task. The editor has unsaved changes in \(filename(of: path)). Save the note first.",
                priority: .high
            )
            return nil
        }
        let newChar = task.completed ? " " : "x"
        let expected = currentNoteContentHash
        let toggle: Task<Void, Never> = Task { [weak self] in
            await self?.performToggleCurrentTask(
                session: session,
                path: path,
                ordinal: task.ordinal,
                newChar: newChar,
                expectedHash: expected
            )
            return
        }
        taskToggleTask = toggle
        return toggle
    }

    private func performToggleCurrentTask(
        session: VaultSession,
        path: String,
        ordinal: UInt32,
        newChar: String,
        expectedHash: String?
    ) async {
        guard admitBatchTrashWrite(to: [path]) else { return }
        let outcome: Result<SaveReport, VaultError> = await Task.detached(
            priority: .userInitiated
        ) {
            do {
                let report = try session.toggleTaskStatus(
                    path: path,
                    ordinal: ordinal,
                    newStatusChar: newChar,
                    expectedContentHash: expectedHash
                )
                return .success(report)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }
        .value

        // User could have switched files between toggle issue and
        // toggle completion. Drop the result rather than mutating
        // state attributed to a file that's no longer the active
        // selection.
        guard BaseExactIdentity.matches(loadedFilePath, path) else { return }

        switch outcome {
        case .success(let report):
            // The toggle path is a `save_text` under the hood, so
            // the on-disk file changed and the cached content
            // hash needs updating to match.
            currentNoteContentHash = report.newContentHash
            // The `toggleCurrentTask` guard (#158) blocks toggles
            // while `hasUnsavedChanges == true`, so we only reach
            // this branch with the buffer already matching disk
            // except for the toggled char. Re-reading from disk
            // back into `currentNoteText` + `savedBaselineText` is
            // therefore safe — no buffer edits to lose.
            //
            // Track the in-flight refresh + reload tasks and await
            // them before this toggle's `taskToggleTask` resolves
            // (#161). Production users never observe the difference
            // — `taskToggleTask` isn't subscribed by any UI — but
            // tests can `await state.taskToggleTask?.value` and
            // know the full settle has landed without sleeping.
            let refresh = refreshTasksAfterSave(session: session, path: path)
            tasksRefreshTask = refresh
            // Also refresh the editor's view of the file so the
            // toggled character appears in the rendered text.
            // Mirrors `loadCurrentNote`'s read-text shape but
            // doesn't redo the heading/property work.
            let reload = reloadEditorBufferAfterToggle(session: session, path: path)
            editorReloadTask = reload
            await refresh.value
            await reload.value
        case .failure(.WriteConflict(let currentHash, let expected, let currentMtimeMs)):
            // Same surface as the editor save's WriteConflict
            // path. The attemptedContents is the toggled file
            // contents — we don't actually have it here because
            // the FFI did the read + mutate internally, so re-
            // read from disk before stashing.
            // U3-3: SaveConflict.attemptedContents is BODY space now (the
            // keep-mine path composes it with the current fmSource).
            let attempted = ((try? session.readNoteParts(path: path))?.body) ?? ""
            currentSaveConflict = SaveConflict(
                path: path,
                attemptedContents: attempted,
                currentContentHash: currentHash,
                expectedContentHash: expected,
                currentMtimeMs: currentMtimeMs
            )
            postAccessibilityAnnouncement(
                "Toggle blocked. \(filename(of: path)) was modified externally. Resolve in the dialog.",
                priority: .medium
            )
        case .failure(let error):
            tasksLoadError = humanReadable(error)
        }
    }

    /// Re-read the on-disk file into the editor's buffer after a
    /// toggle. Toggle goes through `save_text` so the disk content
    /// changed; the editor buffer and `savedBaselineText` need to
    /// follow. Off-actor read so the SQLite-backed code path
    /// doesn't pin the main actor.
    ///
    /// Returns the in-flight Task so the caller can stash it on
    /// `editorReloadTask` (#161 — tests await this handle instead
    /// of using `Task.sleep` to wait for the buffer to settle).
    @discardableResult
    private func reloadEditorBufferAfterToggle(
        session: VaultSession,
        path: String
    ) -> Task<Void, Never> {
        Task { [weak self] in
            // U3-3: the buffer is the BODY — reload through the same split
            // the load path uses so fm + offsets stay coherent with it.
            let parts: NotePartsBundle? = await Task.detached(priority: .userInitiated) {
                try? session.readNoteParts(path: path)
            }
            .value
            guard let self, let parts else { return }
            guard BaseExactIdentity.matches(self.loadedFilePath, path) else { return }
            self.currentNoteText = parts.body
            self.savedBaselineText = parts.body
            self.currentNoteFMSource = parts.fmSource
            self.bodyByteOffset = Int(parts.bodyByteOffset)
            self.bodyLineOffset = Int(parts.bodyLineOffset)
            self.hasUnsavedChanges = false
        }
    }

    /// Reveal the vault-wide Tasks Review leaf (View ▸ Show Tasks Review / ⌘R
    /// / toolbar). #879: this used to present a modal sheet; it now selects the
    /// `Leaf.tasksReview` right-pane leaf, un-hides a hidden pane (the #882
    /// leaf-reveal invariant — routes through `focusLeafRegionRevealingPane()`
    /// like `showHistoryPanel` / `showConnectionsPanel`), kicks a fresh
    /// `loadVaultTasks` query, and posts a polite VoiceOver announcement. The
    /// no-session guard is preserved (the menu item + toolbar button also
    /// `.disabled` without a session).
    func openTasksReview() {
        guard currentSession != nil else { return }
        workspace.activeLeaf = .tasksReview
        // ⌘R / menu / toolbar forces a FRESH load. Cancel any in-flight
        // query first (#879 red-team: a rapid double ⌘R otherwise leaks
        // the prior task; an in-flight "Load more" would append a stale
        // page after the fresh first page).
        vaultTasksLoadTask?.cancel()
        vaultTasksLoadTask = Task { [weak self] in
            await self?.loadVaultTasks()
        }
        focusLeafRegionRevealingPane()  // #882: un-hide the pane on reveal
        postAccessibilityAnnouncement(
            "Tasks review. \(taskReviewFilter.displayName).",
            priority: .medium
        )
    }

    /// #879 red-team: Tasks Review is now a first-class rail leaf, so it's
    /// revealed WITHOUT `openTasksReview` — a rail click, a keyboard
    /// activate, or a layout restore that sets `activeLeaf = .tasksReview`.
    /// Those paths never kicked the vault query, so the panel showed a
    /// false "No tasks" empty state on a vault that has tasks. This
    /// idempotent kicker (called when the leaf becomes active) loads only
    /// when a load is both needed and possible.
    ///
    /// The review is a SNAPSHOT: it loads on its FIRST reveal per vault
    /// (rail / keyboard / restore / ⌘R) and re-queries on a filter change.
    /// A vault SWITCH resets it (`resetVaultTasksReviewState`) so the next
    /// reveal re-queries the new vault (Codex red-team: the empty/no-error
    /// guards would otherwise reject a reload and show the previous vault's
    /// rows). To refresh its rows against the CURRENT vault thereafter,
    /// press ⌘R (`openTasksReview` forces a fresh load) or switch the
    /// filter — re-revealing an already-loaded review keeps its loaded
    /// pages (this guard's `vaultTasks.isEmpty` makes it a no-op). It does
    /// NOT live-subscribe to editor edits: an auto-refresh-on-save was
    /// removed because it reset paging on every unrelated prose save and
    /// re-queried a hidden pane (Codex red-team).
    func ensureVaultTasksLoaded() {
        guard currentSession != nil,
            vaultTasks.isEmpty,
            !isLoadingVaultTasks,
            vaultTasksLoadError == nil
        else { return }
        vaultTasksLoadTask?.cancel()
        vaultTasksLoadMoreTask?.cancel()
        vaultTasksLoadTask = Task { [weak self] in
            await self?.loadVaultTasks()
        }
    }

    /// Clear the vault-wide Tasks Review surface. Called on vault CLOSE and
    /// on vault SWITCH (`openVault`) — Codex red-team: direct Open Vault
    /// bypasses `closeVault`, so without a reset here the review's
    /// empty/no-error guards reject a reload and the new vault shows the
    /// previous vault's rows (or its error) indefinitely. Cancels both
    /// query legs so a late page can't append across the switch.
    func resetVaultTasksReviewState() {
        // Supersede any in-flight load so its late defer/publish are inert.
        vaultTasksLoadGeneration += 1
        vaultTasksLoadTask?.cancel()
        vaultTasksLoadTask = nil
        vaultTasksLoadMoreTask?.cancel()
        vaultTasksLoadMoreTask = nil
        vaultTasks = []
        vaultTasksLoadError = nil
        vaultTasksNextCursor = nil
        vaultTasksTotalFiltered = 0
        isLoadingMoreVaultTasks = false
        isLoadingVaultTasks = false
        taskReviewFilter = .all
    }

    /// Tear down the vault-wide tasks query. #879: the review is now a non-modal
    /// leaf, so there's no sheet to "close" — activating a task row keeps the
    /// leaf beside the editor. This cancels the in-flight load (the
    /// `loadVaultTasks` `defer` then clears the spinner) and is the single
    /// teardown the vault-reset path routes through. Idempotent.
    func closeTasksReview() {
        vaultTasksLoadTask?.cancel()
        vaultTasksLoadTask = nil
    }

    /// Switch the active filter and re-query. Public setter so
    /// the UI's `Picker` / chips can call this rather than
    /// writing the `@Published` directly — pairs the state change
    /// with the load.
    func applyTaskReviewFilter(_ filter: TaskReviewFilter) {
        taskReviewFilter = filter
        vaultTasksLoadTask?.cancel()
        vaultTasksLoadTask = Task { [weak self] in
            await self?.loadVaultTasks()
        }
        postAccessibilityAnnouncement(
            "Filter set to \(filter.displayName).",
            priority: .medium
        )
    }

    /// Page size for the vault-wide tasks query. Matches the
    /// bench scenario `tasks_in_vault_first_page` so production
    /// behaviour is what perf is measured against. Lifted to a
    /// named constant (#160) so the inline `200` literal isn't
    /// duplicated between `loadVaultTasks` and
    /// `loadMoreVaultTasks`.
    static let vaultTasksPageSize: UInt32 = 200

    /// Run `tasksInVault` against the current filter and publish
    /// the first page as `vaultTasks`. Mirrors `loadFiles`' shape:
    /// off-actor query, cancellation-aware, no error surfaced
    /// when cancelled mid-flight. Also captures the cursor +
    /// total filtered count returned by the FFI so the review
    /// surface can show pagination affordances (#160).
    func loadVaultTasks() async {
        // #879 Codex red-team (round 3): bail BEFORE touching any shared
        // state if this task was already superseded. Cooperative
        // cancellation does NOT stop an unstarted task body from running,
        // and actor jobs aren't FIFO — so a cancelled predecessor could
        // otherwise bump the generation AFTER its replacement, fail its own
        // publish (cancelled) while superseding the replacement (stale
        // epoch), and strand the review empty.
        guard !Task.isCancelled else { return }
        guard let session = currentSession else { return }
        let filter = taskReviewFilter.toFFIFilter()
        let activeFilter = taskReviewFilter
        // #879 Codex red-team: a fresh first page invalidates any in-flight
        // "Load more" — cancel it HERE (the one funnel every first-page
        // caller reaches, incl. the review-row toggle's direct
        // `await loadVaultTasks()`) and clear its flag, so a stale page can
        // neither append after page one nor leak `isLoadingMoreVaultTasks`.
        vaultTasksLoadMoreTask?.cancel()
        isLoadingMoreVaultTasks = false
        // Generation ownership (#879 Codex red-team): only the LATEST load
        // owns `isLoadingVaultTasks` and the publish below.
        vaultTasksLoadGeneration += 1
        let generation = vaultTasksLoadGeneration
        isLoadingVaultTasks = true
        // #159: clear the spinner on EVERY exit path — but only while THIS
        // load is still current, so a superseded load's late `defer`
        // can't wipe a newer one's spinner (Codex red-team).
        defer {
            if generation == vaultTasksLoadGeneration { isLoadingVaultTasks = false }
        }

        let pageSize = Self.vaultTasksPageSize
        let result: Result<TaskWithLocationPage, VaultError> = await Task.detached(
            priority: .userInitiated
        ) {
            do {
                let page = try session.tasksInVault(
                    filter: filter,
                    paging: Paging(cursor: nil, limit: pageSize)
                )
                return .success(page)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }
        .value

        // If the user changed the filter while we were loading, a
        // newer task is already in flight; drop this result. Also
        // drop if the underlying VaultSession was swapped (close +
        // reopen on a different vault) — the captured `session`
        // would no longer match the live one, and applying its
        // rows to `vaultTasks` would pollute the new vault's
        // surface with the old vault's tasks (#164 Codoki).
        guard !Task.isCancelled,
              generation == vaultTasksLoadGeneration,
              taskReviewFilter == activeFilter,
              currentSession === session
        else { return }

        switch result {
        case .success(let page):
            vaultTasks = page.items
            vaultTasksNextCursor = page.nextCursor
            vaultTasksTotalFiltered = page.totalFiltered
            vaultTasksLoadError = nil
        case .failure(let error):
            vaultTasks = []
            vaultTasksNextCursor = nil
            vaultTasksTotalFiltered = 0
            vaultTasksLoadError = humanReadable(error)
        }
    }

    /// Append the next page of `vaultTasks` using the cursor
    /// returned by the previous `loadVaultTasks` /
    /// `loadMoreVaultTasks` call. No-op when there's no cursor
    /// (the result set has been fully loaded) or when a load is
    /// already in flight. Returns the in-flight Task so tests
    /// can await it deterministically.
    @discardableResult
    func loadMoreVaultTasks() -> Task<Void, Never>? {
        guard let session = currentSession else { return nil }
        guard let cursor = vaultTasksNextCursor else { return nil }
        // Don't stack concurrent "Load more" requests — the button
        // is disabled while one is in flight, but a programmatic
        // caller could still spam this. Re-entrancy here would
        // double-page and append duplicates.
        guard !isLoadingMoreVaultTasks else { return nil }
        let filter = taskReviewFilter.toFFIFilter()
        let activeFilter = taskReviewFilter
        isLoadingMoreVaultTasks = true
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performLoadMoreVaultTasks(
                session: session,
                filter: filter,
                cursor: cursor,
                activeFilter: activeFilter
            )
        }
        // #879 Codex red-team: track the handle so a fresh first-page load
        // can cancel this page — its `Task.isCancelled` guard then drops a
        // stale append that would otherwise land after the fresh page one.
        vaultTasksLoadMoreTask = task
        return task
    }

    private func performLoadMoreVaultTasks(
        session: VaultSession,
        filter: TaskFilter,
        cursor: String,
        activeFilter: TaskReviewFilter
    ) async {
        // #879 Codex red-team: a SUPERSEDED (cancelled) page must not clear
        // the flag a newer "Load more" owns — that would defeat the
        // reentrancy guard and permit a duplicate page request. A fresh
        // first-page load already cleared the flag when it cancelled us.
        defer { if !Task.isCancelled { isLoadingMoreVaultTasks = false } }
        let pageSize = Self.vaultTasksPageSize
        let result: Result<TaskWithLocationPage, VaultError> = await Task.detached(
            priority: .userInitiated
        ) {
            do {
                let page = try session.tasksInVault(
                    filter: filter,
                    paging: Paging(cursor: cursor, limit: pageSize)
                )
                return .success(page)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }
        .value

        // If the user changed the filter while the page was in
        // flight, the appended rows would not match the visible
        // filter — drop the result and let the new filter's
        // initial load take over. Same session-identity guard as
        // `loadVaultTasks` to defend against cross-vault races
        // (#164 Codoki).
        guard !Task.isCancelled,
              taskReviewFilter == activeFilter,
              currentSession === session
        else { return }

        switch result {
        case .success(let page):
            vaultTasks.append(contentsOf: page.items)
            vaultTasksNextCursor = page.nextCursor
            vaultTasksTotalFiltered = page.totalFiltered
            vaultTasksLoadError = nil
        case .failure(let error):
            // Don't clear `vaultTasks` on a failed "Load more" —
            // the user's already-visible rows are still valid; we
            // just surface the error so they know the next page
            // didn't land.
            vaultTasksLoadError = humanReadable(error)
        }
    }

    /// Toggle a task from the vault-wide review view. Routes
    /// through `toggleTaskStatus` with `expectedContentHash: nil`
    /// — the review surface doesn't track per-row hashes, and the
    /// user's explicit "I want to toggle this" intent overrides
    /// the conflict-detection that the editor save flow relies on.
    /// Re-loads vault tasks on completion so the row reflects its
    /// new state.
    ///
    /// If the toggled task belongs to the currently-loaded note,
    /// `refreshTasksAfterSave` also fires so the per-note panel
    /// stays in sync.
    @discardableResult
    func toggleVaultTask(_ row: TaskWithLocation) -> Task<Void, Never>? {
        guard let session = currentSession else { return nil }
        guard admitBatchTrashWrite(to: [row.path]) else { return nil }
        // #158: Toggling the currently-loaded file's task would
        // clobber any unsaved buffer edits on the post-save
        // reload — see the comment in `toggleCurrentTask` for the
        // full reasoning. Toggles against *other* files in the
        // review are safe because there's no live editor buffer
        // to lose, so we only block the loaded-file case.
        if BaseExactIdentity.matches(row.path, loadedFilePath), hasUnsavedChanges {
            postAccessibilityAnnouncement(
                "Cannot toggle task. The editor has unsaved changes in \(filename(of: row.path)). Save the note first.",
                priority: .high
            )
            return nil
        }
        let newChar = row.task.completed ? " " : "x"
        let path = row.path
        let ordinal = row.task.ordinal
        let toggle: Task<Void, Never> = Task { [weak self] in
            await self?.performToggleVaultTask(
                session: session,
                path: path,
                ordinal: ordinal,
                newChar: newChar
            )
            return
        }
        taskToggleTask = toggle
        return toggle
    }

    private func performToggleVaultTask(
        session: VaultSession,
        path: String,
        ordinal: UInt32,
        newChar: String
    ) async {
        guard admitBatchTrashWrite(to: [path]) else { return }
        let outcome: Result<SaveReport, VaultError> = await Task.detached(
            priority: .userInitiated
        ) {
            do {
                let report = try session.toggleTaskStatus(
                    path: path,
                    ordinal: ordinal,
                    newStatusChar: newChar,
                    expectedContentHash: nil
                )
                return .success(report)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }
        .value

        switch outcome {
        case .success:
            // Re-query the vault tasks so the row's `completed`
            // flips visually. Cheaper than mutating the array in
            // place: filter-window inclusion may have changed
            // (e.g. completing an overdue task removes it from
            // the `.overdue` filter result).
            await loadVaultTasks()
            // Per-note panel stays in sync if the toggle hit the
            // currently-loaded file. Track + await the refresh and
            // reload so this toggle's `taskToggleTask` resolves
            // only after the full settle lands (#161 — lets tests
            // skip the `Task.sleep(50ms)` pattern).
            if BaseExactIdentity.matches(loadedFilePath, path) {
                let refresh = refreshTasksAfterSave(session: session, path: path)
                tasksRefreshTask = refresh
                let reload = reloadEditorBufferAfterToggle(session: session, path: path)
                editorReloadTask = reload
                await refresh.value
                await reload.value
            }
        case .failure(let error):
            vaultTasksLoadError = humanReadable(error)
        }
    }

    /// Activate a `TasksReviewPanel` row: switch the file
    /// selection (if needed) and scroll the editor to the task's
    /// line. #879: the review is a non-modal leaf now, so this NO
    /// LONGER tears the review down — the leaf stays beside the
    /// editor so the user can click through several tasks in a row
    /// (the whole point of taking it out of the blocking sheet). The
    /// in-flight load is left running so the leaf keeps populating.
    /// Same selection+scroll pattern as the search-overlay
    /// activation flow.
    func openTaskRowInEditor(_ row: TaskWithLocation) {
        let target = row.path
        let line = Int(row.task.line)
        recordExplicitSidebarNavigationIntent()

        // If we're already on the file, just scroll.
        if BaseExactIdentity.matches(selectedFilePath, target) {
            // U3-3: task lines are whole-file; the editor buffer is body.
            lineScrollRequest.send(bodyLine(fromFileLine: line))
            postAccessibilityAnnouncement(
                "Scrolled to \(filename(of: target)), line \(line).",
                priority: .medium
            )
            return
        }

        // Otherwise switch selection + scroll once the new file's
        // load resolves so the per-line anchors exist in the
        // rendered tree before `ScrollViewReader.scrollTo` runs.
        selectedFilePath = target
        let pendingLoad = noteLoadTask
        // Track the inner Task so tests can await the deferred
        // scroll emission (#161). Production: nothing depends on
        // its completion, so this is purely a test-determinism
        // aid.
        taskRowActivationTask = Task { @MainActor [weak self] in
            if let pendingLoad {
                await pendingLoad.value
            }
            guard let self else { return }
            guard BaseExactIdentity.matches(self.selectedFilePath, target)
            else { return }
            // Offsets are current here — the awaited load set them.
            self.lineScrollRequest.send(self.bodyLine(fromFileLine: line))
            postAccessibilityAnnouncement(
                "Opened \(filename(of: target)), line \(line).",
                priority: .medium
            )
        }
    }

    // MARK: - Save flow

    /// Editor's two-way binding writes new buffer contents through
    /// this method. Keeps `currentNoteText` as the live buffer and
    /// recomputes `hasUnsavedChanges` against `savedBaselineText` so
    /// the dirty indicator and the dirty-gate stay in sync.
    ///
    /// Calling this with the same string the editor already holds
    /// is a no-op (the equality check below) — SwiftUI sometimes
    /// re-applies bindings during view updates, and we don't want
    /// that to spuriously flip the dirty flag.
    func updateEditorText(
        _ newText: String,
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        guard let path = loadedFilePath else { return }
        if let reason = markdownAuthoringDisabledReason(for: path) {
            postMutationAnnouncement(reason)
            return
        }
        if BaseExactIdentity.matches(currentNoteText, newText) { return }
        currentNoteText = newText
        hasUnsavedChanges = !BaseExactIdentity.matches(
            newText, savedBaselineText ?? "")
        // U1-2: a duplicated tab (same path in another tab) is the same
        // buffer — mirror the edit into same-path parked documents so an
        // unfocused pane never renders stale bytes. Copy-on-write assign.
        if let path = loadedFilePath {
            workspace.mirrorEdit(
                path: path, text: newText, hasUnsavedChanges: hasUnsavedChanges)
        }
    }

    /// SwiftUI `Binding<String>` for the editor view. Wraps the
    /// `currentNoteText` getter and routes writes through
    /// `updateEditorText` so the dirty-state bookkeeping happens
    /// exactly once per buffer change, regardless of how many
    /// times SwiftUI re-applies the binding during a render pass.
    func noteTextBinding() -> Binding<String> {
        let owner = noteAuthoringOwner()
        return Binding(
            get: { self.currentNoteText ?? "" },
            set: { newText in
                // The NSTextView delegate callback can already be queued when
                // quarantine or an absent reconciliation flips the live view.
                // Bind the callback to the note that created it and re-check
                // capability before accepting even one late character.
                guard let owner, self.ownsNoteAuthoring(owner)
                else { return }
                if let reason = self.markdownAuthoringDisabledReason(for: owner.path) {
                    self.postMutationAnnouncement(reason)
                    return
                }
                self.updateEditorText(newText, owner: owner)
            }
        )
    }

    /// Save the current editor buffer back to the file under
    /// `loadedFilePath`, refresh the cached hash + headings, and
    /// announce success or surface a conflict. Cmd+S calls this.
    ///
    /// Re-entrancy: a save already in flight is a no-op so the
    /// user can't queue overlapping `save_text` calls by spamming
    /// Cmd+S. The Rust side's session mutex would serialize them
    /// anyway, but this also keeps the UI flag (`isSaving`)
    /// coherent.
    ///
    /// Returns through `saveTask` so tests can `await` to
    /// deterministically observe the post-save state.
    @discardableResult
    func saveCurrentNote() -> Task<Void, Never>? {
        guard !isSaving else { return nil }
        guard let session = currentSession,
            let path = loadedFilePath,
            let contents = currentNoteText
        else { return nil }
        if let reason = noteSaveDisabledReason(for: path) {
            postMutationAnnouncement(reason)
            return nil
        }
        guard admitBatchTrashWrite(to: [path]) else { return nil }
        let generation = beginSaveOwnership()
        saveError = nil
        let expected = currentNoteContentHash
        let fmSource = currentNoteFMSource
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performSave(
                session: session,
                path: path,
                contents: contents,
                fmSource: fmSource,
                expectedHash: expected,
                saveGeneration: generation
            )
            return
        }
        saveTask = task
        return task
    }

    /// A queued save has a second admission immediately before native IO.
    /// Quarantine can land after the synchronous caller check, and a later
    /// absence reconciliation can replace quarantine with missing-draft
    /// ownership. Either state must reject the queued write without consuming
    /// the close workflow that still owns the dirty draft.
    private func rejectQueuedSave(
        generation: UInt64,
        session: VaultSession,
        path: String,
        reason: String?,
        rejectedConflict: SaveConflict? = nil
    ) {
        guard ownsSave(generation, session: session) else { return }
        if let reason { postMutationAnnouncement(reason) }
        // Keep Mine dismisses its alert while the retry owns the operation.
        // If a second admission rejects that queued retry, restore the exact
        // conflict instead of silently consuming the user's recovery choice.
        if let rejectedConflict,
            currentSaveConflict == nil,
            BaseExactIdentity.matches(loadedFilePath, path),
            (hasUnsavedChanges || hasDirtyNoteRecovery(for: path))
        {
            currentSaveConflict = rejectedConflict
        }
        // The close prompt's first admission can race an already-queued Trash
        // result. If this exact active dirty note still owns the close-after-
        // save continuation, restore its recovery prompt before consuming the
        // continuation. A tab switch, retarget, clean buffer, or newer tab /
        // vault / navigation recovery owner must never be displaced.
        if let pending = pendingTabCloseAfterSave,
            (pendingTabClose == nil || pendingTabClose == pending),
            pendingVaultClose == nil,
            pendingNavigation == nil,
            workspace.model.activeGroup.activeTabID == pending,
            let tab = workspace.model.tab(pending),
            case .markdown(let pendingPath) = tab.item,
            BaseExactIdentity.matches(pendingPath, path),
            BaseExactIdentity.matches(loadedFilePath, path),
            (hasUnsavedChanges || hasDirtyNoteRecovery(for: path))
        {
            pendingTabClose = pending
        }
        pendingTabCloseAfterSave = nil
        finishSaveOwnership(generation)
    }

    /// Inner save body. Split out so it can be reused by
    /// `resolveSaveConflictKeepMine` (which re-saves with the
    /// current on-disk hash so the user's bytes win).
    private func performSave(
        session: VaultSession,
        path: String,
        contents: String,
        fmSource: String,
        expectedHash: String?,
        saveGeneration: UInt64,
        structuralToken: Int? = nil,
        structuralRefresher: StructuralBatchRefreshRunner? = nil,
        rejectedConflict: SaveConflict? = nil
    ) async {
        guard ownsSave(saveGeneration, session: session) else { return }
        guard !Task.isCancelled else {
            finishSaveOwnership(saveGeneration)
            return
        }
        // Save does not commit property drafts. Prefer that exact actionable
        // reason to the structural destination diagnosis when a missing-path
        // Keep Mine targets its own recovery identity.
        if let reason = noteSaveDisabledReason(
            for: path,
            ignoringStructuralRecoveryReservationToken: structuralToken)
        {
            rejectQueuedSave(
                generation: saveGeneration,
                session: session,
                path: path,
                reason: reason,
                rejectedConflict: rejectedConflict)
            return
        }
        // Missing-path Keep Mine is a structural create. Repeat destination
        // admission immediately before native I/O so recovery that appeared
        // after the alert action cannot be overwritten.
        if let structuralToken {
            guard let reservation = admitStructuralRecoveryRecreation(path),
                installStructuralRecoveryReservation(
                    reservation, token: structuralToken)
            else {
                rejectQueuedSave(
                    generation: saveGeneration,
                    session: session,
                    path: path,
                    reason: nil,
                    rejectedConflict: rejectedConflict)
                return
            }
        }
        guard admitBatchTrashWrite(
            to: [path],
            ignoringStructuralRecoveryReservationToken: structuralToken)
        else {
            rejectQueuedSave(
                generation: saveGeneration,
                session: session,
                path: path,
                reason: nil,
                rejectedConflict: rejectedConflict)
            return
        }
        // Detached so the SQLite-mutex-holding save doesn't pin the main
        // actor while disk IO + tree rewrites run. U3-3 (#469): `contents`
        // is the BODY; `save_composed` reassembles fm ⊕ body through the
        // one Rust composer and then runs the existing save_text machinery
        // verbatim (conflict detection, atomic write, index, op-log).
        let outcome: Result<SaveReport, VaultError> = await Task.detached(priority: .userInitiated) {
            do {
                let report = try session.saveComposed(
                    path: path,
                    fmSource: fmSource,
                    body: contents,
                    expectedContentHash: expectedHash
                )
                return .success(report)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }.value

        if let gate = basesPostWritePublishGate { await gate() }

        // The user could have switched files (or closed the vault)
        // while we were saving. Drop the result in that case
        // rather than mutating state for a file the user has
        // already moved on from.
        guard ownsSave(saveGeneration, session: session) else { return }
        guard !Task.isCancelled else {
            finishSaveOwnership(saveGeneration)
            return
        }
        if let structuralToken {
            guard ownsStructuralMutation(structuralToken, session: session) else {
                finishSaveOwnership(saveGeneration)
                return
            }
        }
        if case .success = outcome {
            // Recreating an externally-deleted note is a structural create,
            // even though it enters through the save-conflict alert. Keep its
            // shared owner through the same authoritative tree refresh as the
            // other creation funnels, then revalidate after the suspension
            // before any undo barrier or editor state can land.
            if let structuralToken {
                guard let structuralRefresher else {
                    finishSaveOwnership(saveGeneration)
                    return
                }
                await structuralRefresher(self)
                guard ownsSave(saveGeneration, session: session) else { return }
                guard !Task.isCancelled,
                    ownsStructuralMutation(structuralToken, session: session)
                else {
                    finishSaveOwnership(saveGeneration)
                    return
                }
            }
            // Bases are session-global consumers. A same-session note switch
            // must not suppress their refresh after this write committed.
            _ = await refreshVisibleBasesAfterInAppWrite(
                session: session,
                changedPath: path)?.value
            guard ownsSave(saveGeneration, session: session) else { return }
            guard !Task.isCancelled else {
                finishSaveOwnership(saveGeneration)
                return
            }
            if let structuralToken {
                guard ownsStructuralMutation(structuralToken, session: session) else {
                    finishSaveOwnership(saveGeneration)
                    return
                }
            }
            // #871 post-merge audit: `expectedHash == ""` is the create-IF-ABSENT
            // idiom — the app observed this path as MISSING, so a successful save
            // just CREATED it (e.g. Keep Mine after the note's path was externally
            // deleted). That bypassing create is SESSION-GLOBAL (a file landing on
            // disk, not tied to the current note), so it barriers the structural
            // undo history REGARDLESS of whether the note is still loaded. It is
            // placed BEFORE the per-note `loadedFilePath` publication guard on
            // purpose: a same-vault note/tab switch mid-write trips that guard and
            // would otherwise skip the clear, leaving a stale inverse armed against
            // the recreated path. A NORMAL save of an existing file (non-empty
            // expected hash) leaves the history intact.
            if expectedHash?.isEmpty == true {
                barrierStructuralUndoForCreatedVaultPath(
                    relativePath: path, existedBefore: false)
            }
            if case .success(let report) = outcome {
                // File truth is path-owned, not active-tab-owned. Publish the
                // committed baseline/hash to every exact-path parked document
                // before the live-note guard so an unexpected programmatic
                // switch cannot restore a stale self-conflicting snapshot.
                workspace.mirrorSaveResult(
                    path: path,
                    baseline: contents,
                    contentHash: report.newContentHash)
            }
        }
        guard BaseExactIdentity.matches(loadedFilePath, path) else {
            finishSaveOwnership(saveGeneration)
            return
        }

        switch outcome {
        case .success(let report):
            currentNoteContentHash = report.newContentHash
            savedBaselineText = contents
            // Defensive newest-buffer check even though the visible editor is
            // read-only during Save. A queued/programmatic producer must never
            // let an older captured save claim a newer live buffer.
            hasUnsavedChanges = !BaseExactIdentity.matches(
                currentNoteText, Optional(contents))
            // U1-2: a close-tab request that chose "Save" completes its
            // close once the save lands cleanly.
            if let pending = pendingTabCloseAfterSave,
                workspace.model.activeGroup.activeTabID == pending {
                pendingTabCloseAfterSave = nil
                if hasUnsavedChanges {
                    pendingTabClose = pending
                } else if let tab = workspace.model.tab(pending),
                    case .markdown(let pendingPath) = tab.item,
                    hasDirtyNoteRecovery(for: pendingPath),
                    !hasOtherMarkdownTab(for: pendingPath, excluding: pending)
                {
                    pendingTabClose = pending
                    if let reason = dirtyCloseSaveDisabledReason(for: pendingPath) {
                        postMutationAnnouncement(reason)
                    }
                } else {
                    performCloseTab(pending)
                }
            }
            // Refresh headings so the outline matches the just-
            // saved buffer. Same shape as `loadCurrentNote` —
            // a metadata fetch, no need to re-read text. The
            // links/properties panels still get refreshed by the
            // existing `loadCurrentLinks` path when the user next
            // switches selection; refreshing them here would
            // double-spin the SQLite mutex for marginal benefit.
            refreshHeadingsAfterSave(session: session, path: path)
            tasksRefreshTask = refreshTasksAfterSave(session: session, path: path)
            // Audit #258: refresh the content-pipeline caches so an
            // edit that adds / removes / changes a math / code /
            // diagram block reflects in the panels without waiting
            // for the next selection-change. The race-guard inside
            // each refresher (loadedFilePath == path) drops the
            // result if the user has moved on, but red-team M1
            // flagged that orphan tasks still grab the conn-mutex
            // on close-during-save / switch-during-save — so we
            // stash the handles on the AppState and cancel them
            // from `closeVault` + the selection-change clear path.
            mathBlocksRefreshTask?.cancel()
            mathBlocksRefreshTask = refreshMathBlocksAfterSave(
                session: session, path: path
            )
            codeBlocksRefreshTask?.cancel()
            codeBlocksRefreshTask = refreshCodeBlocksAfterSave(
                session: session, path: path
            )
            diagramBlocksRefreshTask?.cancel()
            diagramBlocksRefreshTask = refreshDiagramBlocksAfterSave(
                session: session, path: path
            )
            postAccessibilityAnnouncement(
                "Saved \(filename(of: path)).",
                priority: .medium
            )
        case .failure(.WriteConflict(let currentHash, let expected, let currentMtimeMs)):
            // U1-2: a save-then-close chain aborts on conflict — the tab
            // must stay open while the user resolves the dialog.
            pendingTabCloseAfterSave = nil
            currentSaveConflict = SaveConflict(
                path: path,
                attemptedContents: contents,
                currentContentHash: currentHash,
                expectedContentHash: expected,
                currentMtimeMs: currentMtimeMs
            )
            // Polite announcement: surface the conflict state
            // without yanking focus away from whatever the user
            // is currently doing in the editor. The alert itself
            // is modal and will steal focus when SwiftUI presents
            // it.
            postAccessibilityAnnouncement(
                "Save blocked. \(filename(of: path)) was modified externally. Resolve in the dialog.",
                priority: .medium
            )
        case .failure(let error):
            pendingTabCloseAfterSave = nil
            saveError = humanReadable(error)
        }
        finishSaveOwnership(saveGeneration)
    }

    /// Re-run the save with `expected_content_hash` set to the
    /// hash we just observed on disk. The user explicitly chose to
    /// overwrite the external version; resetting `expected` to
    /// `current` removes the conflict guard so the second save
    /// goes through.
    @discardableResult
    func resolveSaveConflictKeepMine() -> Task<Void, Never>? {
        guard !isSaving else { return nil }
        guard let conflict = currentSaveConflict,
            let session = currentSession,
            BaseExactIdentity.matches(loadedFilePath, conflict.path)
        else {
            currentSaveConflict = nil
            return nil
        }
        // A body overwrite cannot commit a property editor's independent
        // draft. Leave the conflict alert in place until that draft is
        // explicitly applied or discarded.
        if let reason = noteSaveDisabledReason(for: conflict.path) {
            postMutationAnnouncement(reason)
            return nil
        }
        let recreatesMissingFile = conflict.currentContentHash.isEmpty
        let structuralToken: Int?
        let structuralRefresher: StructuralBatchRefreshRunner?
        if recreatesMissingFile {
            // A missing-path Keep Mine is create-if-absent. Admit it through
            // the shared structural gate before dismissing the alert so a busy
            // rejection leaves the user's recovery choice available to retry.
            guard admitStructuralMutationRequest() else { return nil }
            guard let recoveryReservation =
                admitStructuralRecoveryRecreation(conflict.path)
            else {
                return nil
            }
            guard admitBatchTrashWrite(to: [conflict.path]) else { return nil }
            structuralToken = beginStructuralMutation(
                recoveryReservation: recoveryReservation)
            structuralRefresher = structuralBatchRefreshRunner
        } else {
            // A regular conflict overwrite changes bytes but does not create a
            // tree entry, so it remains independent of structural operations.
            guard admitBatchTrashWrite(to: [conflict.path]) else { return nil }
            structuralToken = nil
            structuralRefresher = nil
        }
        let fmSource = currentNoteFMSource
        // The conflict/session/path snapshot identifies the incident, while
        // “Mine” means the latest visible buffer—not the superseded contents
        // captured by the first save attempt.
        let latestContents = currentNoteText ?? conflict.attemptedContents
        // Clear the conflict so the alert dismisses immediately
        // — the in-flight task takes over from here.
        currentSaveConflict = nil
        let generation = beginSaveOwnership()
        let task: Task<Void, Never> = Task { [weak self] in
            guard let self else { return }
            defer {
                if let structuralToken {
                    self.endStructuralMutation(structuralToken)
                }
            }
            // Keep-mine composes MY fm ⊕ MY body over the external write —
            // the same "my whole state wins" semantics the whole-file
            // keep-mine had before the body flip.
            await self.performSave(
                session: session,
                path: conflict.path,
                contents: latestContents,
                fmSource: fmSource,
                expectedHash: conflict.currentContentHash,
                saveGeneration: generation,
                structuralToken: structuralToken,
                structuralRefresher: structuralRefresher,
                rejectedConflict: conflict
            )
            return
        }
        saveTask = task
        if recreatesMissingFile {
            recordPendingStructuralTask(task)
        }
        return task
    }

    /// Keep Mine only participates in the structural gate when the conflicting
    /// path disappeared and the retry would recreate it. Existing-file
    /// overwrites remain available while an unrelated tree operation runs.
    var saveConflictKeepMineDisabledReason: String? {
        guard let conflict = currentSaveConflict else { return nil }
        if let reason = noteSaveDisabledReason(for: conflict.path) {
            return reason
        }
        guard conflict.currentContentHash.isEmpty else { return nil }
        return structuralMutationDisabledReason
    }

    /// Discard the in-editor buffer for the conflicted file and
    /// reload the current on-disk version. Equivalent to "let the
    /// external write win." Clears the conflict either way so the
    /// alert can dismiss.
    @discardableResult
    func resolveSaveConflictReloadFromDisk() -> Task<Void, Never>? {
        guard let conflict = currentSaveConflict else { return nil }
        currentSaveConflict = nil
        hasUnsavedChanges = false
        // Same path the conflict came from — kick `loadCurrentNote`
        // to refresh text + hash + headings together. If the user
        // has since navigated away, the load's `selectedFilePath
        // == path` guard will drop the result.
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.loadCurrentNote(path: conflict.path)
            return
        }
        noteLoadTask = task
        return task
    }

    /// Dismiss the conflict alert without writing or reloading.
    /// The buffer stays as the user left it; `hasUnsavedChanges`
    /// stays true so the indicator and dirty-gate remain active.
    func resolveSaveConflictCancel() {
        currentSaveConflict = nil
    }

    // MARK: - File management (U2-5, #463)

    /// A structural mutation the tree must react to. Carries the *primary*
    /// post-mutation path (the created/renamed/moved node's new path; nil for a
    /// delete) plus the parent path(s) whose levels changed, so
    /// `FileTreeViewModel` can invalidate exactly the touched levels and then
    /// compute the post-mutation focus target (U2-6). `token` makes the seam
    /// edge-trigger even when two mutations are otherwise equal.
    struct TreeMutation: Equatable {
        enum Kind: Equatable {
            /// A folder was created at `path` (parent = its parent level).
            case createFolder(path: String)
            /// A note was created at `path` (parent = its parent level).
            case createNote(path: String)
            /// `oldPath` → `newPath`, same parent level.
            case rename(oldPath: String, newPath: String)
            /// `oldPath` → `newPath`; source + destination parent levels both
            /// change (`newParent` is "" for the vault root).
            case move(oldPath: String, newPath: String, oldParent: String, newParent: String)
            /// `path` was deleted; `parent` is the level it left ("" = root).
            case delete(path: String, parent: String, wasDirectory: Bool)
            /// One native batch Move landing. `standing` is the only physical
            /// transform; `touched` additionally carries restored paths whose
            /// levels must be refreshed without remapping selection or tabs.
            case batchMove(standing: [BatchPathChange], touched: [BatchPathChange])
            /// One native batch Trash landing. Only these exact items left the
            /// vault; failed/untrashed report entries never appear here.
            case batchTrash(trashed: [StructuralBatchItem])
            /// One Finder import landing. Verified external destinations and
            /// authoritative native standing/touched changes publish together
            /// after the batch's sole refresh/reconcile decision.
            case importBatch(
                materialized: [SidebarImportMaterializedResult],
                standing: [BatchPathChange],
                touched: [BatchPathChange])
            /// Report/infrastructure state requires one authoritative root
            /// reconciliation but contains no truthful path transform.
            case batchReconcile
        }

        let token: Int
        let kind: Kind
        /// The op's rewritten-file count (distinct files whose links were
        /// updated) — U2-6's ", updated links in N notes." suffix reads this.
        let rewrittenCount: Int
        /// Core could not identify every touched level. The tree must perform
        /// one authoritative root invalidation instead of guessing paths.
        let requiresRescan: Bool
        /// Captured keyboard locus for one atomic post-batch focus decision.
        /// Nil leaves the tree's deterministic report-order fallback in charge.
        let preferredFocusPath: String?
        /// User selection/focus intent captured at atomic admission. Import
        /// landing may focus only if the tree model still owns this revision.
        let selectionRevision: UInt64?
        /// The admitted structural-owner generation, distinct from the
        /// presentation edge token. Deferred import selection must reject as
        /// soon as any newer structural operation begins, even before it lands.
        let structuralMutationToken: Int?
        /// Generation of the authoritative scan already performed by this
        /// import, used to acknowledge/suppress the generic scan-finish path.
        let importOwnedScanGeneration: Int?

        init(
            token: Int,
            kind: Kind,
            rewrittenCount: Int,
            requiresRescan: Bool = false,
            preferredFocusPath: String? = nil,
            selectionRevision: UInt64? = nil,
            structuralMutationToken: Int? = nil,
            importOwnedScanGeneration: Int? = nil
        ) {
            self.token = token
            self.kind = kind
            self.rewrittenCount = rewrittenCount
            self.requiresRescan = requiresRescan
            self.preferredFocusPath = preferredFocusPath
            self.selectionRevision = selectionRevision
            self.structuralMutationToken = structuralMutationToken
            self.importOwnedScanGeneration = importOwnedScanGeneration
        }

        /// The parent-level paths this mutation dirtied (nil = the vault root
        /// level). The tree invalidates each. A move dirties two; everything
        /// else dirties one.
        var affectedParents: [String?] {
            if requiresRescan { return [nil] }
            switch kind {
            case let .createFolder(path), let .createNote(path):
                return [Self.parentPath(of: path)]
            case let .rename(oldPath, _):
                return [Self.parentPath(of: oldPath)]
            case let .move(_, _, oldParent, newParent):
                return [Self.normalizedParent(oldParent), Self.normalizedParent(newParent)]
            case let .delete(path, _, _):
                return [Self.parentPath(of: path)]
            case let .batchMove(standing, touched):
                var seen = Set<String?>()
                var parents: [String?] = []
                for change in standing + touched {
                    for path in [change.oldPath, change.newPath] {
                        let parent = Self.parentPath(of: path)
                        if seen.insert(parent).inserted { parents.append(parent) }
                    }
                }
                return parents
            case let .batchTrash(trashed):
                var seen = Set<String?>()
                var parents: [String?] = []
                for item in trashed {
                    let parent = Self.parentPath(of: item.path)
                    if seen.insert(parent).inserted { parents.append(parent) }
                }
                return parents
            case let .importBatch(materialized, standing, touched):
                var seen = Set<String?>()
                var parents: [String?] = []
                for result in materialized {
                    let parent = Self.parentPath(of: result.path)
                    if seen.insert(parent).inserted { parents.append(parent) }
                }
                for change in standing + touched {
                    for path in [change.oldPath, change.newPath] {
                        let parent = Self.parentPath(of: path)
                        if seen.insert(parent).inserted { parents.append(parent) }
                    }
                }
                return parents.isEmpty ? [nil] : parents
            case .batchReconcile:
                return [nil]
            }
        }

        /// The parent path of a vault-relative path, or nil if it's a root-level
        /// entry (whose parent is the vault root).
        static func parentPath(of path: String) -> String? {
            guard let slash = path.lastIndex(of: "/") else { return nil }
            return String(path[path.startIndex..<slash])
        }

        /// "" (the root sentinel used by the mutation API) maps to nil (the
        /// tree's root level); any other parent stays as-is.
        static func normalizedParent(_ parent: String) -> String? {
            parent.isEmpty ? nil : parent
        }
    }

    struct SidebarFileSummaryUpdate: Equatable {
        let token: Int
        /// One atomic delivery prevents SwiftUI from coalescing a same-turn
        /// burst down to only its final file.
        let summaries: [FileSummary]
    }

    /// Main-actor entry point for rich-row metadata. The UniFFI worker callback
    /// hops to `@MainActor` before calling here, so pending paths, task ownership,
    /// generations, and delivery stay isolated. Only the immutable path snapshot
    /// and synchronous FFI lookups leave the actor in the detached utility task.
    /// This path handles only metadata-preserving modifications; sidebar
    /// structural commands have their own tree seam.
    func handleSidebarFileChange(_ event: FileChangeEvent, from session: VaultSession) {
        guard event.kind == .modified, currentSession === session else { return }
        sidebarMetadataPendingPaths.insert(event.path)
        guard sidebarMetadataRefreshTaskForTesting == nil else { return }
        let generation = sidebarMetadataRefreshGeneration
        sidebarMetadataRefreshTaskForTesting = Task { @MainActor [weak self, weak session] in
            guard let self, let session else { return }
            await self.runSidebarMetadataRefreshLoop(
                session: session,
                generation: generation)
        }
    }

    private func runSidebarMetadataRefreshLoop(
        session: VaultSession,
        generation: Int
    ) async {
        while true {
            do {
                try await Task.sleep(for: .milliseconds(75))
            } catch {
                return
            }
            guard !Task.isCancelled,
                generation == sidebarMetadataRefreshGeneration,
                currentSession === session
            else { return }

            let paths = sidebarMetadataPendingPaths.sorted()
            sidebarMetadataPendingPaths.removeAll(keepingCapacity: true)
            guard !paths.isEmpty else {
                sidebarMetadataRefreshTaskForTesting = nil
                return
            }
            let fetcher = sidebarFileSummaryFetcher
            let summaries = await Task.detached(priority: .utility) {
                paths.compactMap { fetcher(session, $0) }
            }.value
            guard !Task.isCancelled,
                generation == sidebarMetadataRefreshGeneration,
                currentSession === session
            else { return }

            if !summaries.isEmpty {
                publishSidebarFileSummaries(summaries)
            }
            if sidebarMetadataPendingPaths.isEmpty {
                sidebarMetadataRefreshTaskForTesting = nil
                return
            }
        }
    }

    private func publishSidebarFileSummaries(_ summaries: [FileSummary]) {
        let sorted = summaries.sorted(by: { $0.path < $1.path })
        // `files` is the flat openable-document inventory used for counts,
        // quick-open, and create-name collision checks. None of those consumers
        // reads rich row metadata, so rewriting its full 50k-element array after
        // every save would be pure main-actor work. The view-owned tree is the
        // sole rich metadata cache and applies this batch through its path index.
        sidebarFileSummaryUpdateCounter &+= 1
        sidebarFileSummaryUpdate = SidebarFileSummaryUpdate(
            token: sidebarFileSummaryUpdateCounter,
            summaries: sorted)
        sidebarFileSummaryUpdates.send(sorted)
    }

    private func resetSidebarMetadataRefresh() {
        sidebarMetadataRefreshGeneration &+= 1
        sidebarMetadataRefreshTaskForTesting?.cancel()
        sidebarMetadataRefreshTaskForTesting = nil
        sidebarMetadataPendingPaths.removeAll(keepingCapacity: false)
        sidebarFileSummaryUpdate = nil
    }

    /// A link-rewrite partial failure surfaced to the user (spec §U2-5). The
    /// mutation succeeded; `skipped` lists the notes whose links to it could not
    /// be updated. `verb`/`name` build the alert title.
    struct StructuralFailureReport: Identifiable, Equatable {
        let id = UUID()
        let verb: String
        let name: String
        let skipped: [String]
    }

    /// A tree node in inline-rename mode (U2-5).
    struct RenamingNode: Equatable, Identifiable {
        let id: UUID
        let sessionIdentity: ObjectIdentifier
        let path: String
        let isDirectory: Bool
        /// The current final component (the field's initial text).
        var name: String { (path as NSString).lastPathComponent }
    }

    /// Install rename state for a path that the captured session just created.
    /// Create flows call this only after their operation reports success; it
    /// intentionally bypasses the structural-busy presentation gate because
    /// the create still owns that gate until its task returns.
    @discardableResult
    func installRenameForCreatedEntry(
        path: String, isDirectory: Bool, session: VaultSession
    ) -> Bool {
        guard currentSession === session else { return false }
        structuralRenameError = nil
        renamingNode = RenamingNode(
            id: UUID(),
            sessionIdentity: ObjectIdentifier(session),
            path: path,
            isDirectory: isDirectory)
        return true
    }

    /// The one user-facing inline-rename staging resolver. F2, context menus,
    /// VoiceOver actions, and the selected-node command all route here.
    @discardableResult
    func requestRename(path: String, isDirectory: Bool) -> Bool {
        guard let session = currentSession else { return false }
        guard admitStructuralMutationRequest() else { return false }
        return installRenameForCreatedEntry(
            path: path, isDirectory: isDirectory, session: session)
    }

    /// Commit only the exact rendered rename owner. A busy rejection retains
    /// the field for retry; stale IDs and stale sessions are inert.
    @discardableResult
    func commitPendingRename(id: UUID, to newName: String) -> Bool {
        guard let pending = currentRename(id: id) else { return false }
        let trimmed = newName.trimmingCharacters(in: .whitespaces)
        guard !trimmed.isEmpty, trimmed != pending.name else {
            return cancelPendingRename(id: id)
        }
        guard admitStructuralMutationRequest() else { return false }
        guard
            let task = renameEntry(
                path: pending.path,
                isDirectory: pending.isDirectory,
                to: trimmed,
                renameOwnerID: id)
        else { return false }
        pendingStructuralTaskForTesting = task
        return true
    }

    /// Cancel only the exact rendered rename owner. This overload is distinct
    /// from Bulk Rename's no-argument cancellation method.
    @discardableResult
    func cancelPendingRename(id: UUID) -> Bool {
        guard currentRename(id: id) != nil else { return false }
        renamingNode = nil
        structuralRenameError = nil
        return true
    }

    private func currentRename(id: UUID) -> RenamingNode? {
        guard let pending = renamingNode, pending.id == id,
            let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else { return nil }
        return pending
    }

    private func clearPendingRename(id: UUID, session: VaultSession) {
        guard let pending = renamingNode, pending.id == id,
            pending.sessionIdentity == ObjectIdentifier(session),
            currentSession === session
        else { return }
        renamingNode = nil
        structuralRenameError = nil
    }

    /// A captured single-node Move awaiting a destination. Identity is unique
    /// per presentation (never path-derived), and the originating session rides
    /// with it so stale sheet callbacks cannot act after a vault switch.
    struct PendingMove: Equatable, Identifiable {
        let id: UUID
        let sessionIdentity: ObjectIdentifier
        let path: String
        let isDirectory: Bool
        var name: String { (path as NSString).lastPathComponent }
    }

    /// Stage a single Move sheet against the current vault. A structural
    /// operation already in flight rejects the presentation with the same
    /// reason the destination rows expose.
    @discardableResult
    func requestPendingMove(path: String, isDirectory: Bool) -> Bool {
        guard let session = currentSession else { return false }
        guard admitStructuralMutationRequest() else { return false }
        pendingMove = PendingMove(
            id: UUID(),
            sessionIdentity: ObjectIdentifier(session),
            path: path,
            isDirectory: isDirectory)
        return true
    }

    /// Commit only the exact single-Move presentation captured by the caller.
    /// The sheet clears after synchronous structural admission; a busy reject
    /// keeps the same request alive for retry or explicit cancellation.
    @discardableResult
    func commitPendingMove(id: UUID, to destination: String) -> Bool {
        guard let pending = pendingMove, pending.id == id,
            let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else { return false }
        guard admitStructuralMutationRequest() else { return false }
        guard let task = moveEntry(
            path: pending.path,
            isDirectory: pending.isDirectory,
            to: destination)
        else { return false }
        pendingMove = nil
        pendingStructuralTaskForTesting = task
        return true
    }

    /// The New Folder counterpart of `commitPendingMove`: creating the folder
    /// must itself be admitted synchronously before the presentation clears.
    @discardableResult
    func commitPendingMoveToNewFolder(
        id: UUID, newFolderName: String, in parent: String
    ) -> Bool {
        guard let pending = pendingMove, pending.id == id,
            let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else { return false }
        guard admitStructuralMutationRequest() else { return false }
        guard let task = createFolderThenMove(
            newFolderName: newFolderName,
            in: parent,
            movePath: pending.path,
            isDirectory: pending.isDirectory)
        else { return false }
        pendingMove = nil
        pendingStructuralTaskForTesting = task
        return true
    }

    /// Cancel only the captured presentation while it still belongs to the
    /// current vault session. A stale UUID/session pair is a no-op.
    @discardableResult
    func cancelPendingMove(id: UUID) -> Bool {
        guard let pending = pendingMove, pending.id == id,
            let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else { return false }
        pendingMove = nil
        return true
    }

    /// A captured batch action awaiting a Move-to-folder destination. Identity
    /// is operation-unique (never derived from content), and session/focus ride
    /// with the presentation so a same-URL reopen cannot commit stale work.
    struct BatchMove: Equatable, Identifiable {
        let id: UUID
        let sessionIdentity: ObjectIdentifier
        let items: [TreeSelection]
        let preferredFocusPath: String?
        /// The sheet's title/hint noun phrase — "3 items".
        var displayName: String {
            "\(items.count) \(items.count == 1 ? "item" : "items")"
        }
    }

    /// Stage a batch Move without changing the captured order or pruning
    /// descendants. Core owns projection/preflight and must receive the full
    /// user action even when it will project to one top-level item.
    @discardableResult
    func requestBatchMove(
        _ items: [TreeSelection], preferredFocusPath: String?
    ) -> Bool {
        guard !items.isEmpty, let session = currentSession else { return false }
        guard admitStructuralMutationRequest() else { return false }
        pendingBatchMove = BatchMove(
            id: UUID(),
            sessionIdentity: ObjectIdentifier(session),
            items: items,
            preferredFocusPath: preferredFocusPath)
        return true
    }

    /// Commit only the exact sheet instance that requested the destination.
    /// The presentation clears after synchronous batch admission succeeds; a
    /// busy race leaves it in place so the user can retry or cancel.
    @discardableResult
    func commitPendingBatchMove(id: UUID, to destination: String) -> Bool {
        guard let pending = pendingBatchMove, pending.id == id else { return false }
        guard let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else {
            pendingBatchMove = nil
            return false
        }
        guard admitStructuralMutationRequest() else { return false }
        guard batchMove(
            pending.items,
            to: destination,
            preferredFocusPath: pending.preferredFocusPath) != nil
        else { return false }
        pendingBatchMove = nil
        return true
    }

    @discardableResult
    func commitPendingBatchMoveToNewFolder(
        id: UUID, newFolderName: String, in parent: String
    ) -> Bool {
        guard let pending = pendingBatchMove, pending.id == id else { return false }
        guard let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else {
            pendingBatchMove = nil
            return false
        }
        guard admitStructuralMutationRequest() else { return false }
        guard createFolderThenBatchMove(
            newFolderName: newFolderName,
            in: parent,
            items: pending.items,
            preferredFocusPath: pending.preferredFocusPath) != nil
        else { return false }
        pendingBatchMove = nil
        return true
    }

    @discardableResult
    func cancelPendingBatchMove(id: UUID) -> Bool {
        guard let pending = pendingBatchMove, pending.id == id,
            let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else { return false }
        pendingBatchMove = nil
        return true
    }

    /// True while any structural mutation FFI call is in flight — serializes the
    /// commands (the session lock does too, but this stops the UI from firing a
    /// second mutation before the first's tree refresh lands).
    @Published private(set) var isMutatingStructure = false {
        // Round-32: mirrored into a static the termination fence can read
        // without an instance — every set/clear path (begin/end and the
        // open/close invalidation) flows through this property.
        didSet {
            Self.structuralMutationInFlightForTermination = isMutatingStructure
        }
    }

    /// Aggregate Finder import ownership is claimed synchronously before any
    /// public item-provider load. The reference identity is the lifecycle
    /// capability used by delayed callbacks and final landing.
    @Published private(set) var currentImportBatchOwner: SidebarImportBatchOwner?
    @Published private(set) var canRequestImportBatchCancellation = false

    /// Explicit handshake for the scan performed inside an aggregate import.
    /// The generic scan-finish observer consumes this generation and skips its
    /// own root invalidation; the aggregate TreeMutation owns the sole landing.
    @Published private(set) var importOwnedScanCompletionGeneration: Int?
    private var importOwnedScanCounter = 0
    private(set) var lastImportOwnedScanGeneration: Int?
    private var acknowledgedImportOwnedScanGeneration: Int?

    /// The visible strip observes the owner's immutable-denominator model. It
    /// exists from atomic admission through final refresh/reconciliation only.
    var importBatchProgress: SidebarImportProgressModel? {
        currentImportBatchOwner?.progress
    }

    /// One live reason shared by the File menu, command palette, and registry
    /// backstop. Nil means cancellation is currently actionable.
    var importCancellationDisabledReason: String? {
        guard !canRequestImportBatchCancellation else { return nil }
        guard let progress = importBatchProgress else {
            return SidebarImportProgressStrip.noImportInProgressHint
        }
        return SidebarImportProgressStrip.cancellationHint(
            phase: progress.phase,
            available: false)
    }

    func acknowledgeImportOwnedScanCompletion(_ generation: Int) {
        guard importOwnedScanCompletionGeneration == generation else { return }
        importOwnedScanCompletionGeneration = nil
        acknowledgedImportOwnedScanGeneration = generation
    }

    /// Consume exactly one generic scan-finish suppression regardless of
    /// whether the scan observer or aggregate mutation observer runs first.
    func consumeImportOwnedScanCompletion() -> Int? {
        if let generation = importOwnedScanCompletionGeneration {
            importOwnedScanCompletionGeneration = nil
            return generation
        }
        defer { acknowledgedImportOwnedScanGeneration = nil }
        return acknowledgedImportOwnedScanGeneration
    }

    /// Physical verification failed for these Trash roots. Keep the user's
    /// in-memory document state, but deny every path-bound write until a scan
    /// proves the item present or absent. The trie keeps the write check
    /// component-safe for folder selections without an O(batch) hot path.
    @Published private var batchTrashUnknownItems: [StructuralBatchItem] = []
    private var batchTrashUnknownPathIndex:
        VaultComponentPrefixIndex<StructuralBatchItem>?

    static let batchTrashQuarantineReason =
        "Slate couldn’t verify whether this item moved to Trash. "
        + "It remains read-only. Choose Check Again to retry."

    private static let invalidAbsoluteVaultPathReason =
        "Choose a vault-relative path. Absolute paths aren’t allowed."
    private static let invalidParentVaultPathReason =
        "Choose a vault-relative path without parent-directory references."

    var batchTrashQuarantineNotice: String? {
        guard !batchTrashUnknownItems.isEmpty else { return nil }
        let count = batchTrashUnknownItems.count
        let subject = count == 1 ? "1 item" : "\(count) items"
        let pronoun = count == 1 ? "It remains" : "They remain"
        return "Slate couldn’t verify whether \(subject) moved to Trash. "
            + "\(pronoun) read-only."
    }

    func batchTrashPathCapability(for path: String) -> BatchTrashPathCapability {
        let normalized: String
        switch Self.normalizeBatchTrashAdmissionPath(path) {
        case .normalized(let path): normalized = path
        case .invalid(let reason): return .invalid(reason)
        }
        return batchTrashUnknownPathIndex?.longestMatch(for: normalized) == nil
            ? .writable
            : .readOnly(Self.batchTrashQuarantineReason)
    }

    /// One capability for every note-authoring surface: Markdown body,
    /// frontmatter fields/source, Add Property, Save, and task toggles. Views
    /// use the exact reason for disabled/help/AX state; write funnels retain
    /// their own admission check as the race-proof backstop.
    private func noteAuthoringDisabledReason(
        for path: String,
        ignoringStructuralRecoveryReservationToken: Int?,
        ignoringPropertyPublicationUncertainty: Bool = false
    ) -> String? {
        if missingNoteRecoveryDraft(for: path) != nil {
            return Self.missingNoteDraftReason
        }
        if !ignoringPropertyPublicationUncertainty,
            hasPropertyPublicationUncertainty(for: path)
        {
            return propertyPublicationUncertaintyReason(for: path)
        }
        let ownsIgnoredReservation =
            ignoringStructuralRecoveryReservationToken.map {
                isMutatingStructure && structuralMutationToken == $0
            } ?? false
        if isMutatingStructure && !ownsIgnoredReservation {
            // A structural operation with a known recovery reservation owns
            // only its destination-only identities. Moving sources and
            // unrelated notes remain editable; their recovery is rekeyed after
            // native success. Operations without a bounded reservation retain
            // the conservative vault-wide authoring block.
            guard let reservation = activeStructuralRecoveryReservation else {
                return Self.structuralMutationBusyReason
            }
            if reservation.blocksAuthoring(at: path) {
                return Self.structuralMutationBusyReason
            }
        }
        switch batchTrashPathCapability(for: path) {
        case .writable:
            return ownsIgnoredReservation
                ? nil
                : structuralRecoveryReservationDisabledReason(for: path)
        case .readOnly(let reason), .invalid(let reason):
            return reason
        }
    }

    func noteAuthoringDisabledReason(for path: String) -> String? {
        noteAuthoringDisabledReason(
            for: path,
            ignoringStructuralRecoveryReservationToken: nil)
    }

    /// Defensive action admission for view callbacks that were queued before
    /// a disabled state reached AppKit. Returning false means the UI setter
    /// must leave its local value unchanged.
    @discardableResult
    func admitNoteAuthoring(
        for path: String,
        owner: NoteAuthoringOwner? = nil
    ) -> Bool {
        if let owner, !ownsNoteAuthoring(owner) { return false }
        guard let reason = propertyAuthoringDisabledReason(for: path) else {
            return true
        }
        postMutationAnnouncement(reason)
        return false
    }

    var activeNoteAuthoringDisabledReason: String? {
        guard let path = loadedFilePath else { return nil }
        return markdownAuthoringDisabledReason(for: path)
    }

    private func markdownAuthoringDisabledReason(for path: String) -> String? {
        if isSaving, BaseExactIdentity.matches(loadedFilePath, path) {
            return Self.saveInProgressReason
        }
        return noteAuthoringDisabledReason(for: path)
    }

    func propertyAuthoringDisabledReason(for path: String) -> String? {
        if isSaving, BaseExactIdentity.matches(loadedFilePath, path) {
            return Self.saveInProgressReason
        }
        if isEditingProperty, BaseExactIdentity.matches(loadedFilePath, path) {
            return Self.propertyEditInProgressReason
        }
        return noteAuthoringDisabledReason(for: path)
    }

    var activePropertyAuthoringDisabledReason: String? {
        guard let path = loadedFilePath else { return nil }
        return propertyAuthoringDisabledReason(for: path)
    }

    /// Local Revert/Discard never writes the vault and remains available in a
    /// persistent read-only/quarantine state. Only a bounded in-flight writer
    /// may temporarily own those draft bytes and delay their destruction.
    func draftDiscardDisabledReason(for path: String) -> String? {
        _ = path
        return inFlightDraftDiscardDisabledReason
    }

    var inFlightDraftDiscardDisabledReason: String? {
        if isSaving { return Self.saveInProgressReason }
        if isEditingProperty { return Self.propertyEditInProgressReason }
        return nil
    }

    /// Same-note navigation may resume after a property write commits while
    /// its path-owned verification is still running. Saving and the
    /// pre-commit property phase remain non-navigable.
    var inFlightNavigationDisabledReason: String? {
        if isSaving { return Self.saveInProgressReason }
        return propertyEditNavigationDisabledReason
    }

    var activeDraftDiscardDisabledReason: String? {
        guard let path = loadedFilePath else { return nil }
        return draftDiscardDisabledReason(for: path)
    }

    func propertiesSourceApplyDisabledReason(for path: String) -> String? {
        if let reason = propertyAuthoringDisabledReason(for: path) { return reason }
        if hasDirtyPreservedPropertyDrafts(for: path) {
            return Self.propertyRowsSourceApplyReason
        }
        return nil
    }

    private func hasDirtyPreservedPropertyDrafts(for path: String) -> Bool {
        preservedPropertyDrafts.values.contains {
            BaseExactIdentity.matches($0.path, path) && $0.isDirty
        }
    }

    var activePropertiesSourceApplyDisabledReason: String? {
        guard let path = loadedFilePath else { return nil }
        return propertiesSourceApplyDisabledReason(for: path)
    }

    /// Save commits the composed frontmatter baseline plus Markdown body; it
    /// does not commit a source editor or property row's local draft. Surface
    /// that capability difference everywhere Save is presented and retain the
    /// authoring reason's higher-priority missing/quarantine diagnosis.
    func noteSaveDisabledReason(for path: String) -> String? {
        noteSaveDisabledReason(
            for: path,
            ignoringStructuralRecoveryReservationToken: nil)
    }

    private func noteSaveDisabledReason(
        for path: String,
        ignoringStructuralRecoveryReservationToken: Int?
    ) -> String? {
        // The property writer and composed body writer both replace the same
        // whole file. Keep admission symmetric so Cmd-S cannot race a
        // no-draft Add/Delete property operation and pair stale FM/hash state.
        if isEditingProperty { return Self.propertyEditInProgressReason }
        if let reason = noteAuthoringDisabledReason(
            for: path,
            ignoringStructuralRecoveryReservationToken:
                ignoringStructuralRecoveryReservationToken)
        {
            return reason
        }
        if hasRecoverablePropertyDrafts(for: path) {
            return Self.propertyDraftSaveReason
        }
        return nil
    }

    var activeNoteSaveDisabledReason: String? {
        guard let path = loadedFilePath else { return nil }
        return noteSaveDisabledReason(for: path)
    }

    /// One truthful UI dirty signal for the active note. Body dirtiness stays
    /// separately observable for save mechanics and duplicate-tab mirroring.
    var activeNoteHasUnsavedChanges: Bool {
        _ = propertyRecoveryRevision
        guard let path = loadedFilePath else { return hasUnsavedChanges }
        return hasUnsavedChanges || hasDirtyNoteRecovery(for: path)
    }

    /// Path-owned recovery must project onto every Markdown tab that can keep
    /// it alive, including parked and duplicate tabs. Body dirtiness remains
    /// tab-owned, so only the globally active document reads the live buffer.
    func noteTabHasUnsavedChanges(_ id: TabID) -> Bool {
        _ = propertyRecoveryRevision
        guard let tab = workspace.model.tab(id),
            case .markdown(let path) = tab.item
        else { return false }
        let bodyDirty: Bool
        if id == workspace.model.activeGroup.activeTabID,
            BaseExactIdentity.matches(loadedFilePath, path)
        {
            bodyDirty = hasUnsavedChanges
        } else {
            bodyDirty = workspace.document(for: id)?.hasUnsavedChanges ?? false
        }
        return bodyDirty || hasDirtyNoteRecovery(for: path)
    }

    /// Admission-only canonicalization matching core's vault resolver on
    /// macOS: repeated separators and `.` disappear; absolute paths and every
    /// `..` component are rejected. Normal components remain byte-exact — no
    /// Unicode normalization or case folding is permitted at this boundary.
    private static func normalizeBatchTrashAdmissionPath(
        _ path: String
    ) -> BatchTrashAdmissionPath {
        guard !path.hasPrefix("/") else {
            return .invalid(invalidAbsoluteVaultPathReason)
        }
        var components: [Substring] = []
        for component in path.split(separator: "/", omittingEmptySubsequences: true) {
            if component == "." { continue }
            guard component != ".." else {
                return .invalid(invalidParentVaultPathReason)
            }
            components.append(component)
        }
        return .normalized(components.joined(separator: "/"))
    }

    /// The single admission gate for every path-bound writer. Callers pass
    /// every vault-relative path the operation can write; component-safe
    /// matching blocks an unknown folder's descendants without treating a
    /// prefix lookalike (or a file's textual suffix) as related.
    @discardableResult
    func admitBatchTrashWrite(
        to paths: [String],
        ignoringStructuralRecoveryReservationToken: Int? = nil
    ) -> Bool {
        guard let reason = batchTrashWriteFailureReason(
            to: paths,
            ignoringStructuralRecoveryReservationToken:
                ignoringStructuralRecoveryReservationToken)
        else { return true }
        postMutationAnnouncement(reason)
        return false
    }

    /// Non-presenting counterpart used by aggregate import after provider
    /// classification. Unsafe native move slots become provider-scoped failures
    /// while unrelated external copies continue under the same owner.
    private func batchTrashWriteFailureReason(
        to paths: [String],
        ignoringStructuralRecoveryReservationToken: Int? = nil
    ) -> String? {
        let ownsIgnoredReservation =
            ignoringStructuralRecoveryReservationToken.map {
                isMutatingStructure && structuralMutationToken == $0
            } ?? false
        for path in paths {
            if missingNoteRecoveryDraft(for: path) != nil {
                return Self.missingNoteDraftReason
            }
            switch batchTrashPathCapability(for: path) {
            case .writable:
                break
            case .readOnly(let reason), .invalid(let reason):
                return reason
            }
            if !ownsIgnoredReservation,
                let reason = structuralRecoveryReservationDisabledReason(for: path)
            {
                return reason
            }
        }
        return nil
    }

    /// Destructive path admission. A file checks its exact path; a directory
    /// also checks whether it contains an indexed unknown root so deleting an
    /// ancestor can never erase an item whose physical outcome is unresolved.
    @discardableResult
    func admitBatchTrashMutation(of items: [StructuralBatchItem]) -> Bool {
        for item in items {
            let normalized: String
            switch Self.normalizeBatchTrashAdmissionPath(item.path) {
            case .normalized(let path): normalized = path
            case .invalid(let reason):
                postMutationAnnouncement(reason)
                return false
            }
            if batchTrashUnknownPathIndex?.longestMatch(for: normalized) != nil
                || (item.isDirectory
                    && batchTrashUnknownPathIndex?.containsEntry(
                        atOrBelow: normalized) == true)
            {
                postMutationAnnouncement(Self.batchTrashQuarantineReason)
                return false
            }
        }
        return true
    }

    /// Finder-parity duplicate naming is case-insensitive. Snapshot the names
    /// of outcome-unknown siblings on the owning actor so the detached chooser
    /// can treat them exactly like occupied directory-listing entries.
    private func batchTrashUnknownSiblingNames(in parent: String) -> Set<String> {
        guard case .normalized(let normalizedParent) =
            Self.normalizeBatchTrashAdmissionPath(parent)
        else { return [] }
        return Set(batchTrashUnknownItems.compactMap { item in
            guard case .normalized(let path) =
                Self.normalizeBatchTrashAdmissionPath(item.path),
                (TreeMutation.parentPath(of: path) ?? "") == normalizedParent
            else { return nil }
            let name = (path as NSString).lastPathComponent
            return name.isEmpty ? nil : name.lowercased()
        })
    }

    /// Reserve the first child identity below an import destination for every
    /// outcome-unknown Trash descendant. Reserving only direct unknown leaves
    /// is insufficient: recreating an absent ancestor folder could later let
    /// Check Again attach stale recovery to new bytes below that ancestor.
    private func batchTrashUnknownImportReservationNames(
        in destination: String
    ) -> Set<String> {
        guard case .normalized(let normalizedDestination) =
            Self.normalizeBatchTrashAdmissionPath(destination)
        else { return [] }
        let destinationComponents = normalizedDestination.split(separator: "/")
        return Set(batchTrashUnknownItems.compactMap { item in
            guard case .normalized(let path) =
                Self.normalizeBatchTrashAdmissionPath(item.path)
            else { return nil }
            let components = path.split(separator: "/")
            guard components.count > destinationComponents.count,
                components.prefix(destinationComponents.count)
                    .elementsEqual(destinationComponents)
            else { return nil }
            return String(components[destinationComponents.count]).lowercased()
        })
    }

    /// Vault-wide writers cannot prove which files they will touch before the
    /// native call. Fail closed while any Trash outcome remains indeterminate;
    /// ordinary path-scoped writers continue to use `admitBatchTrashWrite` and
    /// remain available for unrelated files.
    @discardableResult
    func admitBatchTrashVaultWideWrite() -> Bool {
        guard batchTrashUnknownItems.isEmpty else {
            postMutationAnnouncement(Self.batchTrashQuarantineReason)
            return false
        }
        return true
    }

    static let structuralMutationBusyReason =
        "Wait for the current file operation to finish."

    /// A structural destination can be physically absent while still owning
    /// user-authored recovery bytes in Slate. Treat that identity as occupied:
    /// moving or creating into it would otherwise leave the filesystem at the
    /// destination while the only recoverable draft remains keyed elsewhere.
    static let structuralRecoveryDestinationReason =
        "Resolve or discard the uncommitted note or property draft at the destination before continuing."

    /// Body Save does not commit the independent properties-source or row
    /// editors. Never present it as a successful resolution for their drafts.
    static let propertyDraftSaveReason =
        "Apply or discard the uncommitted property changes before saving the note."

    static let propertyDraftDeleteReason =
        "Revert or save this property draft before deleting the property."

    static let propertyRowsSourceApplyReason =
        "Revert or save uncommitted property row drafts before applying properties source."

    static let propertyDraftBulkRenameReason =
        "Apply or discard uncommitted property changes before renaming properties."

    static let propertyPublicationUncertainReason =
        "Slate couldn’t verify the latest saved property version. Check the saved version before continuing."

    static let authoredPropertyPublicationUncertainReason =
        "Slate saved this property update, but a newer disk version may have replaced it before verification. Copy or resolve the retained update before leaving this note."

    static let bulkPropertyPublicationUncertainReason =
        "Slate couldn’t verify the bulk property rename in this note. Reload Properties before continuing."

    static let saveInProgressReason =
        "Wait for the current save to finish."

    static let propertyEditInProgressReason =
        "Wait for the current property update to finish."

    private var sidebarValidationIndependentStructuralMutationDisabledReason: String? {
        if isSaving { return Self.saveInProgressReason }
        if isEditingProperty { return Self.propertyEditInProgressReason }
        if !propertyPublicationUncertainties.isEmpty {
            return Self.propertyPublicationUncertainReason
        }
        return isMutatingStructure ? Self.structuralMutationBusyReason : nil
    }

    var structuralMutationDisabledReason: String? {
        if isValidatingSidebarAction {
            return Self.sidebarActionValidationPendingReason
        }
        return sidebarValidationIndependentStructuralMutationDisabledReason
    }

    /// Shared synchronous admission policy for every user-facing, non-drag
    /// structural request. Controls that cannot be disabled (keyboard and
    /// VoiceOver actions) still reject before staging UI or starting a runner,
    /// and announce the exact same reason the disableable controls display.
    @discardableResult
    func admitStructuralMutationRequest() -> Bool {
        guard let reason = structuralMutationDisabledReason else { return true }
        postMutationAnnouncement(reason)
        return false
    }

    /// Drop admission seam. The tree calls this only after it has classified a
    /// supported provider and before it settles the drag session or asks the
    /// provider to load anything.
    @discardableResult
    func admitStructuralDropRequest() -> Bool {
        admitStructuralMutationRequest()
    }

    /// Atomically claim one supported public Finder batch. All validation is
    /// complete before `beginStructuralMutation`, and the returned owner exists
    /// before any caller can invoke `SidebarImportProviderIntake.load()`.
    static var importProviderLimitReason: String {
        "Choose \(SidebarImportProviderIntake.maximumProviderCount) or fewer files and folders to import at once."
    }

    @discardableResult
    func beginImportBatch(
        providers: [NSItemProvider],
        destinationFolder: String,
        selectionRevision: UInt64 = 0
    ) -> SidebarImportBatchOwner? {
        let intake = SidebarImportProviderIntake(providers: providers)
        guard intake.supportedProviderCount > 0 else { return nil }
        guard intake.supportedProviderCount
            <= SidebarImportProviderIntake.maximumProviderCount
        else {
            sidebarActionBackgroundFailure = Self.importProviderLimitReason
            postMutationAnnouncement(Self.importProviderLimitReason)
            return nil
        }
        guard
            let session = currentSession,
            let vaultURL = currentVaultURL
        else {
            return nil
        }

        let canonicalDestination: String
        switch Self.normalizeBatchTrashAdmissionPath(destinationFolder) {
        case .normalized(let path):
            canonicalDestination = path
        case .invalid(let reason):
            postMutationAnnouncement(reason)
            return nil
        }

        guard admitStructuralMutationRequest(),
            admitBatchTrashWrite(to: [canonicalDestination]),
            let recoveryReservation = admitStructuralRecoveryDestination(
                canonicalDestination,
                includesDescendants: true)
        else { return nil }

        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let cancellationSignal = SidebarImportEngineSignal()
        let owner = SidebarImportBatchOwner(
            mutationToken: token,
            session: session,
            vaultURL: vaultURL,
            destinationFolder: canonicalDestination,
            selectionRevision: selectionRevision,
            supportedProviderCount: intake.supportedProviderCount,
            intake: intake,
            cancellationSignal: cancellationSignal,
            cancellationAvailabilityChanged: { [weak self] available in
                self?.canRequestImportBatchCancellation = available
            })
        currentImportBatchOwner = owner
        canRequestImportBatchCancellation = true
        return owner
    }

    /// Cancel a specific batch capability. Before its worker starts there is no
    /// physical work to drain, so ownership can be released immediately. Once
    /// a worker exists it remains the sole owner through final reconciliation.
    func cancelImportBatch(_ owner: SidebarImportBatchOwner) {
        guard currentImportBatchOwner === owner else { return }
        owner.requestCancellation()
        guard owner.workerTask == nil else { return }
        currentImportBatchOwner = nil
        canRequestImportBatchCancellation = false
        endStructuralMutation(owner.mutationToken)
    }

    /// Finalize only the exact owner that still belongs to this AppState.
    func finishImportBatch(_ owner: SidebarImportBatchOwner) {
        guard currentImportBatchOwner === owner else { return }
        owner.clearWorkerTask()
        currentImportBatchOwner = nil
        canRequestImportBatchCancellation = false
        if sidebarActionBackgroundFailure
            == Self.importNativeMoveVaultTransitionReason
        {
            sidebarActionBackgroundFailure = nil
        }
        endStructuralMutation(owner.mutationToken)
    }

    /// Vault replacement/close must signal provider and Task 3 cancellation
    /// before changing `currentSession`. Token invalidation remains centralized
    /// in `cancelStructuralMutationOwnership()` immediately afterward.
    private func cancelCurrentImportBatchForVaultTransition() {
        currentImportBatchOwner?.requestOwnershipLossCancellation()
        currentImportBatchOwner = nil
        canRequestImportBatchCancellation = false
        importOwnedScanCompletionGeneration = nil
        acknowledgedImportOwnedScanGeneration = nil
    }

    private struct ImportBatchPreparationFailure: Sendable {
        let providerIndex: Int
        let item: String
        let reason: String
    }

    private struct ImportBatchPreparation: @unchecked Sendable {
        let roots: [SidebarImportExternalRoot]
        let failures: [ImportBatchPreparationFailure]
    }

    private struct ImportMoveSlot: Sendable {
        let providerIndex: Int
        let item: TreeSelection
    }

    private struct ImportReconciledCandidateKey: Hashable {
        let providerIndex: Int
        let path: String
    }

    private func admittedImportMoveSlots(
        _ moveSlots: [ImportMoveSlot],
        owner: SidebarImportBatchOwner,
        failures: inout [ImportBatchFailureDetail]
    ) -> [ImportMoveSlot] {
        let vaultWideFailure = batchTrashUnknownItems.isEmpty
            ? nil
            : Self.batchTrashQuarantineReason
        var admitted: [ImportMoveSlot] = []
        admitted.reserveCapacity(moveSlots.count)
        for slot in moveSlots {
            let destination = Self.joinVaultPath(
                owner.destinationFolder,
                (slot.item.path as NSString).lastPathComponent)
            let reason = vaultWideFailure ?? batchTrashWriteFailureReason(
                to: [slot.item.path, destination],
                ignoringStructuralRecoveryReservationToken: owner.mutationToken)
            guard let reason else {
                admitted.append(slot)
                continue
            }
            owner.markProviderTerminal(slot.providerIndex)
            failures.append(ImportBatchFailureDetail(
                providerIndex: slot.providerIndex,
                treeOrder: 0,
                item: slot.item.path,
                reason: reason))
        }
        return admitted
    }

    /// Start exactly one worker after atomic admission and drag settlement.
    /// The owner itself is the capability: stale/replayed starts are no-ops.
    @discardableResult
    func startImportBatch(_ owner: SidebarImportBatchOwner) -> Task<Void, Never> {
        guard currentImportBatchOwner === owner, owner.workerTask == nil,
            ownsStructuralMutation(owner.mutationToken, session: owner.session)
        else { return Task {} }

        let task = Task { @MainActor [weak self, weak owner] in
            guard let self, let owner else { return }
            await self.performImportBatch(owner)
        }
        owner.installWorkerTask(task)
        pendingStructuralTaskForTesting = task
        return task
    }

    /// Shared visible-button / Escape / Command-period cancellation seam.
    /// Signalling is idempotent and nonblocking; the worker retains structural
    /// ownership until its final reconciliation, while a missing owner is a no-op.
    @discardableResult
    func requestImportBatchCancellation() -> Bool {
        guard let owner = currentImportBatchOwner else { return false }
        return owner.requestCancellation()
    }

    private func ownsImportBatch(_ owner: SidebarImportBatchOwner) -> Bool {
        currentImportBatchOwner === owner
            && ownsStructuralMutation(owner.mutationToken, session: owner.session)
    }

    private func runImportRefreshPhase(
        _ runner: @escaping ImportRefreshRunner,
        owner: SidebarImportBatchOwner
    ) async -> Result<Void, Error> {
        let task = Task { @MainActor in
            try await runner(self, owner.session)
        }
        owner.installActivePhaseCancellation(
            phase: .finishing,
            cancellableByUser: false
        ) {
            task.cancel()
        }
        let result = await task.result
        guard ownsImportBatch(owner) else { return result }
        owner.clearActivePhaseCancellation()
        return result
    }

    private func performImportBatch(_ owner: SidebarImportBatchOwner) async {
        let slots = await owner.intake.load(
            onTerminalFailure: { [weak self, weak owner] slot in
                Task { @MainActor [weak self, weak owner] in
                    guard let self, let owner,
                        self.ownsImportBatch(owner)
                    else { return }
                    owner.markProviderTerminal(slot.providerIndex)
                }
            })
        guard ownsImportBatch(owner) else { return }

        var externalSlots: [(providerIndex: Int, url: URL)] = []
        var moveSlots: [ImportMoveSlot] = []
        var failures: [ImportBatchFailureDetail] = []

        for slot in slots {
            switch slot.outcome {
            case .failure(let failure):
                owner.markProviderTerminal(slot.providerIndex)
                failures.append(ImportBatchFailureDetail(
                    providerIndex: slot.providerIndex,
                    treeOrder: 0,
                    item: "Provider \(slot.providerIndex + 1)",
                    reason: Self.importProviderFailureMessage(failure)))
            case .url(let url):
                let isDirectory = Self.urlIsDirectory(url)
                switch Self.fileURLDropAction(
                    url: url,
                    vaultURL: owner.vaultURL,
                    destinationFolder: owner.destinationFolder,
                    isDirectory: isDirectory)
                {
                case .importFile(let externalURL, _):
                    externalSlots.append((slot.providerIndex, externalURL))
                case .move(let path, let isDirectory, _):
                    moveSlots.append(ImportMoveSlot(
                        providerIndex: slot.providerIndex,
                        item: TreeSelection(path: path, isDirectory: isDirectory)))
                case .none(let reason):
                    owner.markProviderTerminal(slot.providerIndex)
                    failures.append(ImportBatchFailureDetail(
                        providerIndex: slot.providerIndex,
                        treeOrder: 0,
                        item: url.lastPathComponent,
                        reason: reason))
                }
            }
        }

        // Provider kind is known only after intake. Preserve standalone Move's
        // quarantine contract here while allowing unrelated external copies to
        // continue under the aggregate owner.
        moveSlots = admittedImportMoveSlots(
            moveSlots,
            owner: owner,
            failures: &failures)

        if owner.isCancellationRequested || Task.isCancelled {
            for slot in externalSlots {
                Self.appendImportCancellationFailure(
                    providerIndex: slot.providerIndex,
                    item: slot.url.lastPathComponent,
                    to: &failures)
            }
            for slot in moveSlots {
                Self.appendImportCancellationFailure(
                    providerIndex: slot.providerIndex,
                    item: slot.item.path,
                    to: &failures)
            }
            owner.markProvidersTerminal(slots.map(\.providerIndex))
            presentImportBatchOutcome(
                owner: owner,
                report: SidebarImportReport(failures: [], wasCancelled: true),
                moveCount: 0,
                failures: failures,
                wasCancelled: true)
            return
        }

        let signal = owner.cancellationSignal
        let vaultURL = owner.vaultURL
        let limits = SidebarImportSourceLimits(
            sessionRefuseBytes: owner.session.largeFileRefuseBytes())
        let preparationSlots = externalSlots
        let sourceWalkerHooks = importSourceWalkerHooks
        let aggregateEntryBudget = SidebarImportSourceEntryBudget(
            limit: SidebarImportSourceLimits.productionMaximumEntries)
        let preparationFailureDidBecomeTerminal: @Sendable (Int) -> Void = {
            [weak self, weak owner] providerIndex in
            Task { @MainActor [weak self, weak owner] in
                guard let self, let owner,
                    self.ownsImportBatch(owner)
                else { return }
                owner.markProviderTerminal(providerIndex)
            }
        }
        let preparation = await Task.detached(priority: .userInitiated) {
            var roots: [SidebarImportExternalRoot] = []
            var failures: [ImportBatchPreparationFailure] = []
            let walker = SidebarImportSourceWalker(
                limits: limits,
                scopeAccess: SidebarImportSecurityScopeAccess(
                    start: { $0.startAccessingSecurityScopedResource() },
                    stop: { $0.stopAccessingSecurityScopedResource() }),
                hooks: sourceWalkerHooks,
                cancellation: signal,
                aggregateEntryBudget: aggregateEntryBudget)
            for slot in preparationSlots {
                guard !signal.isCancelled else {
                    failures.append(ImportBatchPreparationFailure(
                        providerIndex: slot.providerIndex,
                        item: slot.url.lastPathComponent,
                        reason: "Cancelled"))
                    preparationFailureDidBecomeTerminal(slot.providerIndex)
                    continue
                }
                do {
                    roots.append(SidebarImportExternalRoot(
                        providerIndex: slot.providerIndex,
                        preparedSource: try walker.prepare(
                            rootURL: slot.url,
                            vaultURL: vaultURL)))
                } catch {
                    failures.append(ImportBatchPreparationFailure(
                        providerIndex: slot.providerIndex,
                        item: slot.url.lastPathComponent,
                        reason: Self.importPreparationFailureMessage(error)))
                    preparationFailureDidBecomeTerminal(slot.providerIndex)
                }
            }
            return ImportBatchPreparation(roots: roots, failures: failures)
        }.value
        guard ownsImportBatch(owner) else {
            preparation.roots.forEach { $0.preparedSource.close() }
            return
        }

        failures.append(contentsOf: preparation.failures.map {
            ImportBatchFailureDetail(
                providerIndex: $0.providerIndex,
                treeOrder: 0,
                item: $0.item,
                reason: $0.reason)
        })
        owner.markProvidersTerminal(preparation.failures.map(\.providerIndex))

        if owner.isCancellationRequested || Task.isCancelled || signal.isCancelled {
            for root in preparation.roots {
                Self.appendImportCancellationFailure(
                    providerIndex: root.providerIndex,
                    item: root.preparedSource.sourceRootName,
                    to: &failures)
            }
            for slot in moveSlots {
                Self.appendImportCancellationFailure(
                    providerIndex: slot.providerIndex,
                    item: slot.item.path,
                    to: &failures)
            }
            preparation.roots.forEach { $0.preparedSource.close() }
            owner.markProvidersTerminal(slots.map(\.providerIndex))
            presentImportBatchOutcome(
                owner: owner,
                report: SidebarImportReport(failures: [], wasCancelled: true),
                moveCount: 0,
                failures: failures,
                wasCancelled: true)
            return
        }

        let copyReport: SidebarImportReport
        if preparation.roots.isEmpty {
            copyReport = SidebarImportReport(
                failures: [], wasCancelled: signal.isCancelled)
        } else {
            let scheduler = SidebarImportByteScheduler(cancellation: signal)
            let progressProviderIndices = preparation.roots.map(\.providerIndex)
            let coordinator = SidebarImportCoordinator(
                signal: signal,
                scheduler: scheduler,
                creators: importDestinationCreators(owner.session),
                hooks: SidebarImportCoordinatorHooks(
                    didUpdateProgress: { [weak self, weak owner] snapshot in
                        let completedIndex = snapshot.completedTopLevel - 1
                        guard progressProviderIndices.indices.contains(completedIndex) else {
                            return
                        }
                        let providerIndex = progressProviderIndices[completedIndex]
                        Task { @MainActor [weak self, weak owner] in
                            guard let self, let owner,
                                self.ownsImportBatch(owner)
                            else { return }
                            owner.markProviderTerminal(providerIndex)
                        }
                    }))
            let reservedImportBasenames = moveSlots.map {
                ($0.item.path as NSString).lastPathComponent
            } + batchTrashUnknownImportReservationNames(
                in: owner.destinationFolder).sorted()
            let copyTask = Task {
                try await coordinator.copy(
                    roots: preparation.roots,
                    into: owner.destinationFolder,
                    reservingMoveBasenames: reservedImportBasenames)
            }
            owner.installActivePhaseCancellation {
                copyTask.cancel()
            }
            do {
                copyReport = try await copyTask.value
            } catch {
                copyReport = SidebarImportReport(
                    failures: [],
                    wasCancelled: signal.isCancelled)
                failures.append(ImportBatchFailureDetail(
                    providerIndex: preparation.roots.first?.providerIndex ?? 0,
                    treeOrder: 0,
                    item: preparation.roots.first?.preparedSource.sourceRootName
                        ?? "Import",
                    reason: error.localizedDescription))
            }
            guard ownsImportBatch(owner) else { return }
            owner.clearActivePhaseCancellation()
        }
        guard ownsImportBatch(owner) else { return }

        owner.markProvidersTerminal(externalSlots.map(\.providerIndex))
        failures.append(contentsOf: Self.importCoordinatorFailureDetails(copyReport))

        let hasVerifiedExternalEffect =
            copyReport.successfulFileCount > 0
            || copyReport.successfulFolderCount > 0
        var requiresScan = copyReport.requiresRescan
        if hasVerifiedExternalEffect || requiresScan {
            clearStructuralUndoStacks()
        }

        var nativeReduction: ForwardBatchMoveReduction?
        let cancelledBeforeNative = copyReport.wasCancelled
            || owner.isCancellationRequested
            || Task.isCancelled
            || signal.isCancelled
        if !cancelledBeforeNative {
            // Revalidate after the last external-copy suspension. Trash
            // reconciliation can tighten the vault capability while copying;
            // no await occurs between this live gate and native execution.
            moveSlots = admittedImportMoveSlots(
                moveSlots,
                owner: owner,
                failures: &failures)
        }
        if !cancelledBeforeNative, !moveSlots.isEmpty {
            let request = BatchMoveRequest(
                items: moveSlots.map {
                    StructuralBatchItem(
                        path: $0.item.path,
                        isDirectory: $0.item.isDirectory)
                },
                newParent: owner.destinationFolder)
            let runner = batchMoveRunner
            let nativeTask = Task { @MainActor [weak self] in
                guard let self else {
                    return Optional<Result<ForwardBatchMoveReduction, Error>>.none
                }
                return await self.executeForwardBatchMove(
                    session: owner.session,
                    request: request,
                    mutationToken: owner.mutationToken,
                    runner: runner)
            }
            owner.installActivePhaseCancellation(
                phase: .moving,
                cancellableByUser: false
            ) {
                nativeTask.cancel()
            }
            let nativeOutcome = await nativeTask.value
            guard ownsImportBatch(owner) else { return }
            if sidebarActionBackgroundFailure
                == Self.importNativeMoveVaultTransitionReason
            {
                sidebarActionBackgroundFailure = nil
            }
            owner.clearActivePhaseCancellation()
            guard let outcome = nativeOutcome else { return }
            owner.markProvidersTerminal(moveSlots.map(\.providerIndex))

            switch outcome {
            case .success(let reduction):
                nativeReduction = reduction
                failures.append(contentsOf: Self.importNativeFailureDetails(
                    reduction, moveSlots: moveSlots))
                requiresScan = requiresScan || reduction.requiresRescan
            case .failure(let error):
                requiresScan = true
                for slot in moveSlots {
                    failures.append(ImportBatchFailureDetail(
                        providerIndex: slot.providerIndex,
                        treeOrder: Int.max,
                        item: slot.item.path,
                        reason: error.localizedDescription))
                }
            }
        } else if cancelledBeforeNative {
            for slot in moveSlots {
                Self.appendImportCancellationFailure(
                    providerIndex: slot.providerIndex,
                    item: slot.item.path,
                    to: &failures)
            }
            owner.markProvidersTerminal(moveSlots.map(\.providerIndex))
        }

        let nativeReport = nativeReduction?.report
        let standing = nativeReduction?.standing ?? []
        let touched = nativeReduction?.touched ?? []
        var materialized = Self.importKnownMaterializedResults(
            copyReport: copyReport,
            moveSlots: moveSlots,
            standing: standing)
        let hasNativePhysicalWork = !standing.isEmpty || !touched.isEmpty
        let needsRefresh = hasVerifiedExternalEffect
            || hasNativePhysicalWork
            || requiresScan
        var authoritativeScanSucceeded = false
        var importOwnedScanGeneration: Int?

        if needsRefresh {
            if requiresScan {
                let previousScanGeneration = lastImportOwnedScanGeneration
                let scanResult = await runImportRefreshPhase(
                    importScanRefreshRunner, owner: owner)
                guard ownsImportBatch(owner) else { return }
                if lastImportOwnedScanGeneration != previousScanGeneration {
                    importOwnedScanGeneration = lastImportOwnedScanGeneration
                }
                switch scanResult {
                case .success:
                    authoritativeScanSucceeded = true
                case .failure(let error):
                    failures.append(ImportBatchFailureDetail(
                        batchStage: "Vault refresh",
                        treeOrder: 0,
                        item: "Vault refresh",
                        reason: error.localizedDescription))
                }
            } else {
                let listResult = await runImportRefreshPhase(
                    importInventoryRefreshRunner, owner: owner)
                guard ownsImportBatch(owner) else { return }
                if case .failure(let error) = listResult {
                    requiresScan = true
                    failures.append(ImportBatchFailureDetail(
                        batchStage: "Vault refresh",
                        treeOrder: 0,
                        item: "Vault refresh",
                        reason: error.localizedDescription))
                    let previousScanGeneration = lastImportOwnedScanGeneration
                    let scanResult = await runImportRefreshPhase(
                        importScanRefreshRunner, owner: owner)
                    guard ownsImportBatch(owner) else { return }
                    if lastImportOwnedScanGeneration != previousScanGeneration {
                        importOwnedScanGeneration = lastImportOwnedScanGeneration
                    }
                    switch scanResult {
                    case .success:
                        authoritativeScanSucceeded = true
                    case .failure(let scanError):
                        failures.append(ImportBatchFailureDetail(
                            batchStage: "Vault rescan",
                            treeOrder: 0,
                            item: "Vault rescan",
                            reason: scanError.localizedDescription))
                    }
                }
            }
        }

        var reconciledUnknownKeys = Set<ImportReconciledCandidateKey>()
        if requiresScan, authoritativeScanSucceeded {
            let unknown = copyReport.unknownCandidates.compactMap { candidate
                -> SidebarImportMaterializedResult? in
                let isDirectory: Bool
                switch candidate.identity.kind {
                case .directory: isDirectory = true
                case .regularFile: isDirectory = false
                case .rejected: return nil
                }
                return SidebarImportMaterializedResult(
                    providerIndex: candidate.identity.providerIndex,
                    path: candidate.candidatePath,
                    isDirectory: isDirectory)
            }
            var unknownByParent: [String: [SidebarImportMaterializedResult]] = [:]
            var parentOrder: [String] = []
            for candidate in unknown {
                let parent = TreeMutation.parentPath(of: candidate.path) ?? ""
                if unknownByParent[parent] == nil { parentOrder.append(parent) }
                unknownByParent[parent, default: []].append(candidate)
            }
            for (order, parent) in parentOrder.enumerated() {
                do {
                    let resolved = try await Self.resolveImportMaterialization(
                        unknownByParent[parent] ?? [],
                        session: owner.session)
                    materialized.append(contentsOf: resolved)
                    reconciledUnknownKeys.formUnion(resolved.map {
                        ImportReconciledCandidateKey(
                            providerIndex: $0.providerIndex,
                            path: $0.path)
                    })
                } catch {
                    failures.append(ImportBatchFailureDetail(
                        batchStage: "Result reconciliation",
                        treeOrder: order,
                        item: parent.isEmpty ? "Vault root" : parent,
                        reason: error.localizedDescription))
                }
            }
            guard ownsImportBatch(owner) else { return }
        }
        if !reconciledUnknownKeys.isEmpty {
            failures = failures.map { detail in
                guard case .provider(let providerIndex) = detail.scope,
                    detail.kind == .terminalFailure,
                    let candidatePath = detail.reconciliationCandidatePath,
                    reconciledUnknownKeys.contains(ImportReconciledCandidateKey(
                        providerIndex: providerIndex,
                        path: candidatePath))
                else { return detail }
                return ImportBatchFailureDetail(
                    providerIndex: providerIndex,
                    treeOrder: detail.treeOrder,
                    item: detail.item,
                    reason: "The destination was found during reconciliation after the copy outcome was initially uncertain.",
                    kind: .warning,
                    reconciliationCandidatePath: candidatePath)
            }
        }
        materialized = Self.providerOrderedImportResults(materialized)

        if !materialized.isEmpty || !standing.isEmpty || !touched.isEmpty || requiresScan {
            publishTreeMutation(
                .importBatch(
                    materialized: materialized,
                    standing: standing,
                    touched: touched),
                rewrittenCount: nativeReport.map {
                    Set($0.rewritten.map(\.path)).count
                } ?? 0,
                requiresRescan: requiresScan,
                preferredFocusPath: materialized.first?.path,
                selectionRevision: owner.selectionRevision,
                structuralMutationToken: owner.mutationToken,
                importOwnedScanGeneration: importOwnedScanGeneration)
        }

        owner.markProvidersTerminal(slots.map(\.providerIndex))
        presentImportBatchOutcome(
            owner: owner,
            report: copyReport,
            moveCount: standing.count,
            failures: failures,
            reconciledCandidateCount: reconciledUnknownKeys.count,
            wasCancelled: cancelledBeforeNative
                || owner.isCancellationRequested
                || Task.isCancelled
                || signal.isCancelled)
    }

    private static func appendImportCancellationFailure(
        providerIndex: Int,
        item: String,
        to failures: inout [ImportBatchFailureDetail]
    ) {
        let alreadyTerminal = failures.contains { detail in
            guard case .provider(let existingIndex) = detail.scope else { return false }
            return existingIndex == providerIndex
                && detail.kind == .terminalFailure
        }
        guard !alreadyTerminal else { return }
        failures.append(ImportBatchFailureDetail(
            providerIndex: providerIndex,
            treeOrder: Int.max,
            item: item,
            reason: "Cancelled"))
    }

    private func presentImportBatchOutcome(
        owner: SidebarImportBatchOwner,
        report: SidebarImportReport,
        moveCount: Int,
        failures: [ImportBatchFailureDetail],
        reconciledCandidateCount: Int = 0,
        wasCancelled: Bool
    ) {
        guard ownsImportBatch(owner) else { return }
        let failureReport = ImportBatchFailureReport(failures)
        if failureReport.totalDetailCount > 0 {
            let result = BatchStructuralResult(
                payload: .importBatch(failureReport),
                requiresAttention: true)
            setBatchStructuralResult(result)
            lastError = BatchStructuralCopy.attention(for: result).message
        }
        postMutationAnnouncement(Self.importBatchAnnouncement(
            report: report,
            moveCount: moveCount,
            destination: owner.destinationFolder,
            failureCount: failureReport.terminalFailureCount,
            warningCount: failureReport.warningCount,
            reconciledCandidateCount: reconciledCandidateCount,
            wasCancelled: wasCancelled))
        finishImportBatch(owner)
    }

    private static func importProviderFailureMessage(
        _ failure: SidebarImportProviderFailure
    ) -> String {
        switch failure {
        case .loadFailed(let message): return message
        case .missingData: return "The provider returned no file URL."
        case .invalidFileURL: return "The provider returned an invalid file URL."
        case .cancelled: return "Cancelled"
        }
    }

    private nonisolated static func importPreparationFailureMessage(
        _ error: Error
    ) -> String {
        guard let error = error as? SidebarImportSourceWalkerError else {
            return error.localizedDescription
        }
        switch error {
        case .invalidLimits:
            return "The configured import limits are invalid."
        case .securityScopeDenied:
            return "Slate does not have permission to read this item."
        case .rejectedRoot(_, let reason):
            return importSourceFailureMessage(reason)
        case .sourceContainsVault:
            return "A folder containing the open vault cannot be imported."
        case .openFailed(_, let reason), .inspectFailed(_, let reason),
            .readFailed(_, let reason):
            return reason
        case .unsupportedEntry:
            return "This item type is not supported."
        case .tooManyEntries(let limit):
            return "The folder contains more than \(limit) items."
        case .aggregateEntryLimitExceeded(let limit):
            return "The import batch contains more than \(limit.formatted()) items."
        case .tooDeep(_, let limit):
            return "The folder is deeper than the \(limit)-level import limit."
        case .fileTooLarge(_, let limitBytes):
            return "The file exceeds the \(limitBytes)-byte import limit."
        case .preparedSourceClosed:
            return "The item was no longer available to read."
        case .notARegularFile:
            return "The item changed before Slate could read it."
        case .cancelled:
            return "Cancelled"
        }
    }

    private nonisolated static func importSourceFailureMessage(
        _ reason: SidebarImportSourceFailureReason
    ) -> String {
        switch reason {
        case .hidden: return "Hidden items are not imported."
        case .symbolicLink: return "Symbolic links and aliases are not imported."
        case .fifo, .socket, .characterDevice, .blockDevice, .unsupported:
            return "This item type is not supported."
        case .unreadable: return "Slate does not have permission to read this item."
        case .entryKindChanged: return "The item changed while Slate was reading it."
        case .notDirectory: return "A folder path changed while Slate was reading it."
        case .invalidPath, .invalidFileName: return "The item has an invalid path or name."
        case .tooDeep: return "The item is deeper than the import limit."
        case .fileTooLarge(let limitBytes):
            return "The file exceeds the \(limitBytes)-byte import limit."
        }
    }

    private static func importCoordinatorFailureDetails(
        _ report: SidebarImportReport
    ) -> [ImportBatchFailureDetail] {
        report.failures.enumerated().map { order, failure in
            let relative = failure.identity.relativePath
            let item = relative.isEmpty
                ? failure.identity.sourceRootName
                : failure.identity.sourceRootName + "/" + relative
            let kindKey: String
            switch failure.identity.kind {
            case .directory: kindKey = "directory"
            case .regularFile: kindKey = "file"
            case .rejected: kindKey = "rejected"
            }
            let terminalItemKey = BaseExactIdentity.registryKey(
                prefix: "import-failed-entry",
                value: [
                    String(failure.identity.providerIndex),
                    failure.identity.sourceRootName,
                    failure.identity.relativePath,
                    kindKey,
                ].joined(separator: "\u{0}"))
            let reason: String
            let reconciliationCandidatePath: String?
            switch failure.reason {
            case .source(let source):
                reason = importSourceFailureMessage(source)
                reconciliationCandidatePath = nil
            case .readFailed(let message):
                reason = "Slate could not read the item: \(message)"
                reconciliationCandidatePath = nil
            case .capacityExceeded:
                reason = "The import byte limit was reached."
                reconciliationCandidatePath = nil
            case .physicalOutcomeUnknown(let candidatePath, let underlying):
                reason = "Slate could not verify whether the item was copied: \(underlying)"
                reconciliationCandidatePath = candidatePath
            case .blockedByUnknownAncestor:
                reason = "Slate could not verify its destination folder."
                reconciliationCandidatePath = nil
            case .cancelled:
                reason = "Cancelled"
                reconciliationCandidatePath = nil
            }
            return ImportBatchFailureDetail(
                providerIndex: failure.identity.providerIndex,
                treeOrder: order + 1,
                item: item,
                reason: reason,
                terminalItemKey: terminalItemKey,
                reconciliationCandidatePath: reconciliationCandidatePath)
        }
    }

    private static func importNativeFailureDetails(
        _ reduction: ForwardBatchMoveReduction,
        moveSlots: [ImportMoveSlot]
    ) -> [ImportBatchFailureDetail] {
        let report = reduction.report
        var providerQueues: [String: [Int]] = [:]
        for slot in moveSlots {
            providerQueues[slot.item.path, default: []].append(slot.providerIndex)
        }
        var providerQueueOffsets: [String: Int] = [:]
        func consumeProviderIndex(for path: String) -> Int? {
            let offset = providerQueueOffsets[path, default: 0]
            guard let queue = providerQueues[path], queue.indices.contains(offset) else {
                return nil
            }
            providerQueueOffsets[path] = offset + 1
            return queue[offset]
        }
        var plannedProvidersByPath: [String: [Int]] = [:]
        for item in report.envelope.planned {
            if let providerIndex = consumeProviderIndex(for: item.path) {
                plannedProvidersByPath[item.path, default: []].append(providerIndex)
            }
        }
        var fallbackPlannedProviderByPath: [String: Int] = [:]
        func plannedProviderIndex(for path: String) -> Int? {
            if let providerIndex = plannedProvidersByPath[path]?.first {
                return providerIndex
            }
            if let providerIndex = fallbackPlannedProviderByPath[path] {
                return providerIndex
            }
            guard let providerIndex = consumeProviderIndex(for: path) else {
                return nil
            }
            fallbackPlannedProviderByPath[path] = providerIndex
            return providerIndex
        }
        var standingProviderByPath: [String: Int] = [:]
        var standingProviderIndices = Set<Int>()
        for change in report.standing {
            guard let providerIndex = plannedProviderIndex(for: change.oldPath) else {
                continue
            }
            standingProviderIndices.insert(providerIndex)
            standingProviderByPath[change.oldPath] = providerIndex
            standingProviderByPath[change.newPath] = providerIndex
        }
        func kindForProvider(
            _ providerIndex: Int,
            proposed: ImportBatchFailureDetail.Kind
        ) -> ImportBatchFailureDetail.Kind {
            proposed == .terminalFailure
                && standingProviderIndices.contains(providerIndex)
                ? .warning
                : proposed
        }
        var result: [ImportBatchFailureDetail] = []
        var order = 0
        func appendProvider(
            providerIndex: Int,
            path: String?,
            reason: String,
            kind: ImportBatchFailureDetail.Kind = .terminalFailure
        ) {
            order += 1
            result.append(ImportBatchFailureDetail(
                providerIndex: providerIndex,
                treeOrder: order,
                item: path ?? "Move",
                reason: reason,
                kind: kind))
        }
        for diagnostic in reduction.diagnostics {
            order += 1
            let item = diagnostic.path ?? "Move"
            switch diagnostic.correlation {
            case .batch:
                result.append(ImportBatchFailureDetail(
                    batchStage: "Move reconciliation",
                    treeOrder: order,
                    item: item,
                    reason: diagnostic.reason,
                    kind: diagnostic.kind))
            case .standingPath:
                if let path = diagnostic.path,
                    let providerIndex = standingProviderByPath[path]
                {
                    result.append(ImportBatchFailureDetail(
                        providerIndex: providerIndex,
                        treeOrder: order,
                        item: item,
                        reason: diagnostic.reason,
                        kind: kindForProvider(
                            providerIndex, proposed: diagnostic.kind)))
                } else {
                    result.append(ImportBatchFailureDetail(
                        batchStage: "Move reconciliation",
                        treeOrder: order,
                        item: item,
                        reason: diagnostic.reason,
                        kind: diagnostic.kind))
                }
            case .plannedRequestPath:
                if let path = diagnostic.path,
                    let providerIndex = plannedProviderIndex(for: path)
                {
                    result.append(ImportBatchFailureDetail(
                        providerIndex: providerIndex,
                        treeOrder: order,
                        item: item,
                        reason: diagnostic.reason,
                        kind: kindForProvider(
                            providerIndex, proposed: diagnostic.kind)))
                } else {
                    result.append(ImportBatchFailureDetail(
                        batchStage: "Move",
                        treeOrder: order,
                        item: item,
                        reason: diagnostic.reason,
                        kind: diagnostic.kind))
                }
            case .skippedRequestPath:
                if let path = diagnostic.path,
                    let providerIndex = consumeProviderIndex(for: path)
                {
                    result.append(ImportBatchFailureDetail(
                        providerIndex: providerIndex,
                        treeOrder: order,
                        item: item,
                        reason: diagnostic.reason,
                        kind: diagnostic.kind))
                } else {
                    result.append(ImportBatchFailureDetail(
                        batchStage: "Move",
                        treeOrder: order,
                        item: item,
                        reason: diagnostic.reason,
                        kind: diagnostic.kind))
                }
            }
        }
        var terminalProviderIndices = Set(result.compactMap { detail -> Int? in
            guard detail.kind == .terminalFailure,
                case .provider(let providerIndex) = detail.scope
            else { return nil }
            return providerIndex
        })
        func appendMissingTerminalProvider(
            _ slot: ImportMoveSlot,
            reason: String
        ) {
            guard !standingProviderIndices.contains(slot.providerIndex),
                terminalProviderIndices.insert(slot.providerIndex).inserted
            else { return }
            appendProvider(
                providerIndex: slot.providerIndex,
                path: slot.item.path,
                reason: reason)
        }
        switch report.state {
        case .rejected:
            for slot in moveSlots {
                appendMissingTerminalProvider(slot, reason: "Move could not start.")
            }
        case .rolledBack:
            for slot in moveSlots {
                appendMissingTerminalProvider(
                    slot,
                    reason: "Move stopped and the item was restored.")
            }
        case .rollbackIncomplete:
            for slot in moveSlots {
                appendMissingTerminalProvider(
                    slot,
                    reason: "Move restoration needs attention.")
            }
        case .noOp, .succeeded:
            break
        }
        return result
    }

    private static func importStandingChanges(_ report: BatchMoveReport) -> [BatchPathChange] {
        switch report.state {
        case .succeeded, .rollbackIncomplete: return report.standing
        case .rejected, .noOp, .rolledBack: return []
        }
    }

    private static func importTouchedChanges(_ report: BatchMoveReport) -> [BatchPathChange] {
        switch report.state {
        case .rolledBack, .rollbackIncomplete: return report.rolledBack
        case .rejected, .noOp, .succeeded: return []
        }
    }

    private static func importKnownMaterializedResults(
        copyReport: SidebarImportReport,
        moveSlots: [ImportMoveSlot],
        standing: [BatchPathChange]
    ) -> [SidebarImportMaterializedResult] {
        var result = copyReport.verifiedTopLevelDestinations.map {
            SidebarImportMaterializedResult(
                providerIndex: $0.providerIndex,
                path: $0.path,
                isDirectory: $0.kind == .directory)
        }
        for slot in moveSlots {
            guard let change = standing.first(where: {
                $0.oldPath == slot.item.path
            }) else { continue }
            result.append(SidebarImportMaterializedResult(
                providerIndex: slot.providerIndex,
                path: change.newPath,
                isDirectory: change.isDirectory))
        }
        return providerOrderedImportResults(result)
    }

    private nonisolated static func providerOrderedImportResults(
        _ results: [SidebarImportMaterializedResult]
    ) -> [SidebarImportMaterializedResult] {
        let ordered = results.enumerated().sorted {
            if $0.element.providerIndex != $1.element.providerIndex {
                return $0.element.providerIndex < $1.element.providerIndex
            }
            return $0.offset < $1.offset
        }
        var seenProviders = Set<Int>()
        var seenPaths = Set<String>()
        return ordered.compactMap { _, result in
            guard seenProviders.insert(result.providerIndex).inserted,
                seenPaths.insert(result.path).inserted
            else { return nil }
            return result
        }
    }

    /// After an uncertainty scan, verify every candidate through the session's
    /// directory listing. This observes both `dirs` and `files`, so an empty
    /// folder can materialize even though openable-file inventory cannot prove
    /// its existence.
    nonisolated static func resolveImportMaterialization(
        _ candidates: [SidebarImportMaterializedResult],
        session: VaultSession
    ) async throws -> [SidebarImportMaterializedResult] {
        try await Task.detached(priority: .userInitiated) {
            let grouped = Dictionary(grouping: candidates) {
                guard let slash = $0.path.lastIndex(of: "/") else { return "" }
                return String($0.path[$0.path.startIndex..<slash])
            }
            var materialized: [SidebarImportMaterializedResult] = []
            for (parent, values) in grouped {
                var directoryPaths = Set<String>()
                var filePaths = Set<String>()
                var cursor: String? = nil
                repeat {
                    let listing = try session.listDirChildren(
                        parentPath: parent,
                        paging: Paging(cursor: cursor, limit: 1_000))
                    directoryPaths.formUnion(listing.dirs.map(\.path))
                    filePaths.formUnion(listing.files.items.map(\.path))
                    cursor = listing.files.nextCursor
                } while cursor != nil
                materialized.append(contentsOf: values.filter {
                    $0.isDirectory
                        ? directoryPaths.contains($0.path)
                        : filePaths.contains($0.path)
                })
            }
            return providerOrderedImportResults(materialized)
        }.value
    }

    private static func importBatchAnnouncement(
        report: SidebarImportReport,
        moveCount: Int,
        destination: String,
        failureCount: Int,
        warningCount: Int,
        reconciledCandidateCount: Int = 0,
        wasCancelled: Bool = false
    ) -> String {
        let location = destination.isEmpty
            ? "the vault root"
            : (destination as NSString).lastPathComponent
        let files = report.successfulFileCount
        let folders = report.successfulFolderCount
        var copiedParts: [String] = []
        if files > 0 { copiedParts.append("\(files) \(files == 1 ? "file" : "files")") }
        if folders > 0 {
            copiedParts.append("\(folders) \(folders == 1 ? "folder" : "folders")")
        }
        var clauses: [String] = []
        if !copiedParts.isEmpty {
            clauses.append("Copied \(copiedParts.joined(separator: " and "))")
        }
        if moveCount > 0 {
            let verb = clauses.isEmpty ? "Moved" : "moved"
            clauses.append("\(verb) \(moveCount) \(moveCount == 1 ? "item" : "items")")
        }
        if reconciledCandidateCount > 0 {
            let verb = clauses.isEmpty ? "Found" : "found"
            clauses.append(
                "\(verb) \(reconciledCandidateCount) destination "
                    + "\(reconciledCandidateCount == 1 ? "item" : "items") during reconciliation")
        }
        var message = clauses.isEmpty
            ? "No items were imported"
            : clauses.joined(separator: " and ")
        message += " to \(location)."
        if wasCancelled || report.wasCancelled {
            message += " Import cancelled; completed copies remain."
        } else if failureCount > 0 {
            message += " \(failureCount) \(failureCount == 1 ? "item was" : "items were") not imported."
        }
        if warningCount > 0 {
            message += " \(warningCount) import \(warningCount == 1 ? "warning needs" : "warnings need") attention."
        }
        return message
    }

    /// Ownership token for the in-flight structural mutation (#871 Codex
    /// round 2). Every structural op captures the token `beginStructuralMutation`
    /// hands it, and its completion only releases `isMutatingStructure` if the
    /// token still matches (`endStructuralMutation`). This closes a cross-vault
    /// race the plain flag couldn't: an op that passes its `currentSession ===
    /// session` guard and THEN suspends in `await loadFiles()` would, on resume,
    /// unconditionally clear the flag — even though the user switched vaults
    /// during the suspension and a NEW op already claimed it. A vault
    /// open/close bumps the token, so any such stale completion is a no-op.
    private var structuralMutationToken = 0

    /// Read-only generation seam for deferred UI landings. It advances at
    /// admission, not publication, so stale import focus cannot land while a
    /// newer operation is still in flight.
    var currentStructuralMutationGeneration: Int { structuralMutationToken }

    /// The destination identities owned by the current native structural
    /// operation. Admission and reservation are installed synchronously on the
    /// main actor before any asynchronous handoff, keeping property-authoring
    /// surfaces read-only until the operation publishes or fails. Moving source
    /// scopes are exempt because their recovery is intentionally rekeyed.
    @Published private var activeStructuralRecoveryReservation:
        StructuralRecoveryReservation?

    /// Claim the structural-mutation guard for a new op and return its
    /// ownership token. Callers have already checked `!isMutatingStructure`.
    func beginStructuralMutation(
        recoveryReservation: StructuralRecoveryReservation? = nil
    ) -> Int {
        structuralMutationToken &+= 1
        isMutatingStructure = true
        activeStructuralRecoveryReservation = recoveryReservation
        return structuralMutationToken
    }

    /// Dynamic-destination operations (Duplicate) determine their exact path
    /// only after asynchronous preparation. They still install the reservation
    /// on the main actor before launching the exclusive native create.
    @discardableResult
    func installStructuralRecoveryReservation(
        _ reservation: StructuralRecoveryReservation,
        token: Int
    ) -> Bool {
        guard isMutatingStructure, structuralMutationToken == token else {
            return false
        }
        activeStructuralRecoveryReservation = reservation
        return true
    }

    /// Release the structural-mutation guard IFF `token` still owns it — a
    /// stale task whose vault was switched out from under it (its token was
    /// bumped by open/close, or a newer op) must NOT clear a newer op's flag.
    func endStructuralMutation(_ token: Int) {
        guard structuralMutationToken == token else { return }
        activeStructuralRecoveryReservation = nil
        isMutatingStructure = false
    }

    /// Invalidate any in-flight structural mutation's ownership and release the
    /// guard — called from the vault open (direct-switch reset) and close
    /// paths. Bumping the token means a stale completion's `endStructuralMutation`
    /// no longer matches, so it can't clear a newer vault's op; clearing the
    /// flag itself un-wedges the new vault (the stale task's own session guard
    /// returns before its release, so nothing else clears it).
    private func cancelStructuralMutationOwnership() {
        structuralMutationToken &+= 1
        activeStructuralRecoveryReservation = nil
        isMutatingStructure = false
        batchTrashUnknownItems = []
        batchTrashUnknownPathIndex = nil
    }

    func ownsStructuralMutation(_ token: Int, session: VaultSession) -> Bool {
        isMutatingStructure
            && structuralMutationToken == token
            && currentSession === session
    }

    /// Monotone token backing `TreeMutation.token`.
    private var treeMutationCounter = 0

    /// The most recent structural-mutation task kicked off by a COMMAND entry
    /// point (`newNoteCommand`, `newFolderCommand`, `deleteSelectedCommand`, …).
    /// Command actions run through the registry and can't return their Task, so
    /// this handle lets tests `await` the mutation deterministically — the same
    /// role `scanTask`/`noteLoadTask` play for their flows.
    private(set) var pendingStructuralTaskForTesting: Task<Void, Never>?

    /// Record an admitted structural task from a feature extension. Keeping the
    /// setter here makes it impossible for a rejected extension funnel to
    /// accidentally replace the active task before admission succeeds.
    func recordPendingStructuralTask(_ task: Task<Void, Never>) {
        pendingStructuralTaskForTesting = task
    }

    /// Publish a tree mutation to the sidebar seam, bumping the edge-trigger
    /// token. Also fires the U2-6 announcement (`postMutationAnnouncement`,
    /// filled in that PR; a no-op stub until then).
    private func publishTreeMutation(
        _ kind: TreeMutation.Kind,
        rewrittenCount: Int,
        requiresRescan: Bool = false,
        preferredFocusPath: String? = nil,
        selectionRevision: UInt64? = nil,
        structuralMutationToken: Int? = nil,
        importOwnedScanGeneration: Int? = nil
    ) {
        // FL-06: pins follow every structural transform before the tree
        // refetches, so the re-fetched levels already see consistent pins.
        applySidebarPinsMutation(kind)
        treeMutationCounter += 1
        treeMutation = TreeMutation(
            token: treeMutationCounter,
            kind: kind,
            rewrittenCount: rewrittenCount,
            requiresRescan: requiresRescan,
            preferredFocusPath: preferredFocusPath,
            selectionRevision: selectionRevision,
            structuralMutationToken: structuralMutationToken,
            importOwnedScanGeneration: importOwnedScanGeneration)
        // #871 Codex round 1: every structural mutation that is NOT a recorded
        // move/rename is a structural-history BARRIER — it clears the undo/redo
        // stacks. A create / duplicate / import / delete can FREE or REFILL a
        // path an existing inverse names (e.g. move a.md→dest, delete
        // dest/a.md, import a different a.md→dest), so replaying that inverse
        // afterward would move/rename the WRONG replacement file. move/rename
        // are the only undoable ops; they push their own inverse immediately
        // after this call, so they must NOT clear. This is the single choke
        // point every structural op routes through on success.
        switch kind {
        case .move, .rename, .batchMove, .importBatch, .batchReconcile:
            break
        case .createFolder, .createNote, .delete, .batchTrash:
            clearStructuralUndoStacks()
        }
    }

    /// Turn a `StructuralReport.failed` list into the user-facing skipped-files
    /// alert, if non-empty. Never silent (spec §U2-5).
    private func surfaceStructuralFailures(
        _ report: StructuralReport, verb: String, name: String
    ) {
        guard !report.failed.isEmpty else { return }
        structuralFailureReport = StructuralFailureReport(
            verb: verb, name: name,
            skipped: report.failed.map(\.path).sorted())
    }

    /// The count of DISTINCT files whose links a report rewrote — the number
    /// U2-6's ", updated links in N notes." suffix announces.
    static func distinctRewrittenCount(_ report: StructuralReport) -> Int {
        Set(report.rewritten.map(\.path)).count
    }

    /// The last message routed through `postMutationAnnouncement`. Tests assert
    /// the VERBATIM string here (spec §U2-6); `postAccessibilityAnnouncement` is
    /// a no-op under the XCTest runner — there's no `NSApp` — so the string must
    /// be observable without a live announcement.
    @Published private(set) var lastMutationAnnouncement: String?

    /// Announce a completed (or failed) structural mutation to VoiceOver
    /// (spec §U2-6). The wrappers build the verbatim sentence; this seam routes
    /// it through the existing `postAccessibilityAnnouncement` helper at
    /// `.medium` priority (the politeness floor that survives — see the palette
    /// / search precedent) and records it for the verbatim-string tests.
    func postMutationAnnouncement(_ message: String) {
        lastMutationAnnouncement = message
        postAccessibilityAnnouncement(message, priority: .medium)
    }

    // MARK: Create

    /// Create a new folder named `name` inside `parent` ("" = vault root). On
    /// success: refreshes the affected tree level + selects the new row (U2-6),
    /// announces, and — never silently — surfaces any link-rewrite failures
    /// (a create has none, but the discipline is uniform). A collision /
    /// invalid name surfaces through `lastError` (the tree's create affordance
    /// has no inline field; the palette/menu path reports via the alert).
    ///
    /// `onResult` (#852, Codex finding 2): the create's ACTUAL outcome — `true`
    /// only on `.success`, `false` on failure OR a mid-flight vault switch. The
    /// "New Folder… then move" flows gate the dependent move SOLELY on this (plus
    /// session identity), never on folder existence — an empty pre-existing "New
    /// Folder" would make the create fail with DestinationExists yet still be on
    /// disk, so an existence check would wrongly move the selection into it.
    @discardableResult
    func createFolder(
        name: String, in parent: String, onResult: ((Bool) -> Void)? = nil
    ) -> Task<Void, Never>? {
        guard admitStructuralMutationRequest(), let session = currentSession else {
            onResult?(false)
            return nil
        }
        let path = Self.joinVaultPath(parent, name)
        guard let recoveryReservation = admitStructuralRecoveryDestination(
                path, includesDescendants: true),
            admitBatchTrashWrite(to: [path])
        else {
            onResult?(false)
            return nil
        }
        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let task = Task { [weak self] in
            let outcome: Result<StructuralReport, VaultError> = await Task.detached(
                priority: .userInitiated
            ) {
                do { return .success(try session.createFolder(path: path)) }
                catch let e as VaultError { return .failure(e) }
                catch { return .failure(.Io(message: error.localizedDescription)) }
            }.value
            guard let self, self.currentSession === session else {
                onResult?(false)
                return
            }
            switch outcome {
            case .success(let report):
                self.publishTreeMutation(
                    .createFolder(path: path),
                    rewrittenCount: Self.distinctRewrittenCount(report))
                self.postMutationAnnouncement(
                    "Created folder \((path as NSString).lastPathComponent).")
                onResult?(true)
            case .failure(let error):
                self.lastError = self.humanReadable(error)
                self.announceMutationFailure(
                    verb: "create folder",
                    name: (path as NSString).lastPathComponent, error: error)
                onResult?(false)
            }
            self.endStructuralMutation(token)
        }
        return task
    }

    /// Create a new untitled note inside `parent` ("" = vault root), open it in
    /// the current tab, and put the tree row into inline-rename mode with the
    /// title selected (spec §U2-5: "creates 'Untitled.md' … opens it, selects
    /// title for rename"). Collisions auto-suffix ("Untitled 2.md", …) so ⌘N is
    /// never a dead end.
    @discardableResult
    func createNote(in parent: String) -> Task<Void, Never>? {
        guard admitStructuralMutationRequest(), let session = currentSession else { return nil }
        // Compute a non-colliding name against the known file set. The backend
        // still guards the collision (DestinationExists) — this just spares the
        // user a failure on the common "several untitled notes" flow.
        let name = uniqueUntitledName(in: parent)
        let path = Self.joinVaultPath(parent, name)
        guard let recoveryReservation = admitStructuralRecoveryDestination(path),
            admitBatchTrashWrite(to: [path])
        else { return nil }
        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let refresher = structuralBatchRefreshRunner
        let task = Task { [weak self] in
            let outcome: Result<StructuralReport, VaultError> = await Task.detached(
                priority: .userInitiated
            ) {
                do {
                    // A new note is an empty file. create_exclusive (O-3) is
                    // the no-clobber primitive: a name race against a file
                    // the index hasn't seen yet (external create between
                    // scan and click) surfaces DestinationExists instead of
                    // truncating it — save_text would silently overwrite
                    // (#796).
                    _ = try session.createExclusive(path: path, content: "")
                    return .success(
                        StructuralReport(opId: 0, moved: [], rewritten: [], failed: []))
                } catch let e as VaultError { return .failure(e) }
                catch { return .failure(.Io(message: error.localizedDescription)) }
            }.value
            guard let self else { return }
            defer { self.endStructuralMutation(token) }
            guard !Task.isCancelled,
                self.ownsStructuralMutation(token, session: session)
            else { return }
            switch outcome {
            case .success:
                await refresher(self)
                guard !Task.isCancelled,
                    self.ownsStructuralMutation(token, session: session)
                else { return }
                self.publishTreeMutation(.createNote(path: path), rewrittenCount: 0)
                self.openFile(
                    path,
                    target: .currentTab,
                    advancesSidebarSelectionRevision: false)
                // Drop the user straight into renaming the fresh note's title.
                self.installRenameForCreatedEntry(
                    path: path, isDirectory: false, session: session)
                self.postMutationAnnouncement(
                    "Created note \((path as NSString).lastPathComponent).")
            case .failure(let error):
                self.lastError = self.humanReadable(error)
                self.announceMutationFailure(
                    verb: "create note",
                    name: (path as NSString).lastPathComponent, error: error)
            }
        }
        return task
    }

    /// User-facing New Note admission. Unlike the low-level runner above, a
    /// busy request is never a silent `nil`: it announces the shared reason
    /// synchronously, stages no rename UI, and starts no write.
    @discardableResult
    func requestCreateNote(in parent: String) -> Task<Void, Never>? {
        guard currentSession != nil else { return nil }
        guard admitStructuralMutationRequest() else { return nil }
        return createNote(in: parent)
    }

    // MARK: Duplicate (#853)

    /// Duplicate the FILE at `path` to a collision-safe sibling
    /// ("name copy.md", "name copy 2.md", …). Folders are out of scope
    /// (#853 notes the file-only cut).
    ///
    /// Backend-safe by construction: the copy is written with
    /// `create_exclusive` (the O-3 no-clobber primitive, #793/#796 context),
    /// so a name race against a file the index hasn't seen yet surfaces
    /// `DestinationExists` — the loop then advances to the next candidate
    /// instead of truncating anything. On success: refreshes the tree level +
    /// moves selection to the copy (the U2-6 funnel, via a `.createNote`
    /// mutation — a duplicate IS a created note), and announces
    /// "Duplicated <src> as <copy>.".
    @discardableResult
    func duplicateEntry(path: String) -> Task<Void, Never>? {
        guard admitStructuralMutationRequest(), let session = currentSession else { return nil }
        let sourceName = (path as NSString).lastPathComponent
        let parent = TreeMutation.parentPath(of: path) ?? ""
        guard admitBatchTrashWrite(to: [path, parent]) else { return nil }
        // Treat every quarantined sibling as occupied before entering detached
        // name selection. This preserves Duplicate's original behavior of
        // jumping past arbitrarily many listed collisions without spending its
        // 200 create-exclusive race attempts, while ensuring no concrete
        // unknown-outcome candidate can be selected.
        let quarantinedSiblingNames = batchTrashUnknownSiblingNames(in: parent)
        let token = beginStructuralMutation()
        let task = Task { @MainActor [weak self] in
            let preparation: Result<(String, Set<String>), VaultError> = await Task.detached(
                priority: .userInitiated
            ) {
                do {
                    let content = try session.readText(path: path)
                    // Seed the collision set from the live level listing
                    // (files AND folders — a folder named "a copy" blocks
                    // that name too). The index can lag disk; the exclusive-
                    // create below is the authoritative guard.
                    var existing = quarantinedSiblingNames
                    if let listing = try? session.listDirChildren(
                        parentPath: parent,
                        paging: Paging(cursor: nil, limit: FileTreeViewModel.levelPageLimit))
                    {
                        for dir in listing.dirs { existing.insert(dir.name.lowercased()) }
                        for file in listing.files.items { existing.insert(file.name.lowercased()) }
                    }
                    return .success((content, existing))
                } catch let e as VaultError { return .failure(e) }
                catch { return .failure(.Io(message: error.localizedDescription)) }
            }.value
            guard let self, self.ownsStructuralMutation(token, session: session) else {
                return
            }
            switch preparation {
            case .failure(let error):
                self.lastError = self.humanReadable(error)
                self.announceMutationFailure(
                    verb: "duplicate", name: sourceName, error: error)
                self.endStructuralMutation(token)
                return
            case .success(let prepared):
                var existing = prepared.1
                // Candidate selection must remain live-list/race aware, but the
                // recovery registry is main-actor state. Choose one candidate,
                // admit that exact identity, then perform only its exclusive
                // create. A user-owned recovery candidate rejects instead of
                // being silently treated as another suffix collision.
                for _ in 0..<200 {
                    let candidate = Self.duplicateName(
                        for: sourceName,
                        existingLowercasedNames: existing)
                    let candidatePath = Self.joinVaultPath(parent, candidate)
                    guard let recoveryReservation =
                            self.admitStructuralRecoveryDestination(candidatePath),
                        self.admitBatchTrashWrite(to: [candidatePath]),
                        self.installStructuralRecoveryReservation(
                            recoveryReservation, token: token)
                    else {
                        self.endStructuralMutation(token)
                        return
                    }
                    if let reservationGate =
                        self.duplicateCandidateReservationGateForTesting
                    {
                        await reservationGate(candidatePath)
                        guard self.ownsStructuralMutation(token, session: session)
                        else { return }
                    }
                    let create: Result<Void, VaultError> = await Task.detached(
                        priority: .userInitiated
                    ) {
                        do {
                            _ = try session.createExclusive(
                                path: candidatePath,
                                content: prepared.0)
                            return .success(())
                        } catch let error as VaultError {
                            return .failure(error)
                        } catch {
                            return .failure(.Io(message: error.localizedDescription))
                        }
                    }.value
                    guard self.ownsStructuralMutation(token, session: session) else {
                        return
                    }
                    switch create {
                    case .success:
                        self.publishTreeMutation(
                            .createNote(path: candidatePath),
                            rewrittenCount: 0)
                        self.postMutationAnnouncement(
                            "Duplicated \(sourceName) as \(candidate).")
                        await self.loadFiles()
                        guard self.ownsStructuralMutation(token, session: session) else {
                            return
                        }
                        self.endStructuralMutation(token)
                        return
                    case .failure(.DestinationExists):
                        existing.insert(candidate.lowercased())
                    case .failure(let error):
                        self.lastError = self.humanReadable(error)
                        self.announceMutationFailure(
                            verb: "duplicate", name: sourceName, error: error)
                        self.endStructuralMutation(token)
                        return
                    }
                }
                let error = VaultError.Io(
                    message: "could not find a free name after 200 attempts")
                self.lastError = self.humanReadable(error)
                self.announceMutationFailure(
                    verb: "duplicate", name: sourceName, error: error)
                self.endStructuralMutation(token)
            }
        }
        return task
    }

    /// User-facing Duplicate admission. Direct UI surfaces use this wrapper so
    /// keyboard and VoiceOver requests reject busy work with the same exact
    /// announcement as every other structural command.
    @discardableResult
    func requestDuplicateEntry(path: String) -> Task<Void, Never>? {
        guard currentSession != nil else { return nil }
        guard admitStructuralMutationRequest() else { return nil }
        return duplicateEntry(path: path)
    }

    /// Pure: the next collision-safe duplicate name for `name` given the
    /// (lowercased) sibling names already taken. Finder-parity naming:
    /// "a.md" → "a copy.md" → "a copy 2.md" → "a copy 3.md" — a source that
    /// already ends in " copy" / " copy N" re-uses its base rather than
    /// stacking ("a copy.md" duplicates to "a copy 2.md", not
    /// "a copy copy.md"). Static + nonisolated (pure string work) so the
    /// naming rule is regression-locked without a vault AND callable from
    /// the detached mutation task (the `humanReadableVaultError` pattern).
    nonisolated static func duplicateName(
        for name: String, existingLowercasedNames: Set<String>
    ) -> String {
        let ns = name as NSString
        let ext = ns.pathExtension
        var stem = ns.deletingPathExtension
        // Strip an existing " copy" / " copy N" suffix from the stem.
        if stem.hasSuffix(" copy") {
            stem = String(stem.dropLast(" copy".count))
        } else if let range = stem.range(of: #" copy \d+$"#, options: .regularExpression) {
            stem = String(stem[stem.startIndex..<range.lowerBound])
        }
        func candidate(_ n: Int?) -> String {
            let base = n.map { "\(stem) copy \($0)" } ?? "\(stem) copy"
            return ext.isEmpty ? base : "\(base).\(ext)"
        }
        if !existingLowercasedNames.contains(candidate(nil).lowercased()) {
            return candidate(nil)
        }
        var n = 2
        while existingLowercasedNames.contains(candidate(n).lowercased()) { n += 1 }
        return candidate(n)
    }

    // MARK: Rename

    /// Rename the file or folder at `path` to `newName` (a single path
    /// component). On success: retargets any open tab holding the file (or a
    /// descendant of the folder) so it follows the move, refreshes the tree
    /// level + keeps the renamed row selected (U2-6), announces (incl. the
    /// links-updated suffix), and surfaces any per-file rewrite failures. A
    /// collision / invalid name is returned via `structuralRenameError` so the
    /// inline field can show it and keep focus (spec §U2-5).
    ///
    /// `undoContext` (#871): `.record` (the default every user-facing caller
    /// takes — inline rename, the command, undo/redo of a MOVE never lands
    /// here) pushes the inverse rename onto the structural undo stack; the
    /// `.undoing`/`.redoing` contexts are how `structuralUndo/Redo` re-enter
    /// this same FFI path to reverse a rename while feeding the opposite stack.
    @discardableResult
    func renameEntry(
        path: String, isDirectory: Bool, to newName: String,
        undoContext: StructuralUndoContext = .record,
        renameOwnerID: UUID? = nil
    ) -> Task<Void, Never>? {
        guard admitStructuralMutationRequest(), let session = currentSession else { return nil }
        let newPath = Self.siblingPath(of: path, newName: newName)
        guard let recoveryReservation = admitStructuralRecoveryRetargets([
                NoteRecoveryPathRetarget(
                    oldPath: path,
                    newPath: newPath,
                    includesDescendants: isDirectory)
            ]),
            admitBatchTrashWrite(to: [path, newPath]),
            admitBatchTrashVaultWideWrite()
        else { return nil }
        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        if renameOwnerID == nil || renameOwnerID.flatMap({ currentRename(id: $0) }) != nil {
            structuralRenameError = nil
        }
        let runner = structuralRenameRunner
        let task = Task { [weak self] in
            let outcome: Result<StructuralReport, VaultError>
            do {
                outcome = .success(
                    try await runner(session, path, isDirectory, newName))
            } catch let error as VaultError {
                outcome = .failure(error)
            } catch {
                outcome = .failure(.Io(message: error.localizedDescription))
            }
            guard let self, self.currentSession === session else { return }
            switch outcome {
            case .success(let report):
                self.applyRetargets(report, movedFrom: path, movedTo: newPath, isDirectory: isDirectory)
                if let renameOwnerID {
                    self.clearPendingRename(id: renameOwnerID, session: session)
                }
                self.publishTreeMutation(
                    .rename(oldPath: path, newPath: newPath),
                    rewrittenCount: Self.distinctRewrittenCount(report))
                if undoContext == .record {
                    self.postMutationAnnouncement(
                        self.mutationSentence(
                            "Renamed \((path as NSString).lastPathComponent) to \(newName).",
                            report: report))
                } else {
                    // #871: an undo/redo of a rename announces "Undid/Redid
                    // rename to <target>." instead of the fresh-op sentence.
                    self.postMutationAnnouncement(
                        self.structuralUndoRedoAnnouncement(
                            executed: .rename(path: path, isDirectory: isDirectory, newName: newName),
                            context: undoContext))
                }
                // #871: record the inverse (rename `newPath` back to the OLD
                // name) on the correct stack for the given context.
                self.recordStructuralUndo(
                    inverse: .rename(
                        path: newPath, isDirectory: isDirectory,
                        newName: (path as NSString).lastPathComponent),
                    context: undoContext)
                self.surfaceStructuralFailures(
                    report, verb: "rename", name: (path as NSString).lastPathComponent)
                await self.loadFiles()
            case .failure(let error):
                if undoContext == .record {
                    // Inline rename: keep the field open + focused with a
                    // specific message it renders below itself.
                    if renameOwnerID == nil
                        || renameOwnerID.flatMap({ self.currentRename(id: $0) }) != nil
                    {
                        self.structuralRenameError = self.humanReadable(error)
                    }
                } else {
                    // #871 Codex round 1: an undo/redo rename has NO inline
                    // field (structural undo routes only when
                    // `renamingNode == nil`), so a failure — the target was
                    // externally deleted, or the restored name now collides —
                    // must surface through the general alert path a failed
                    // MOVE takes, not `structuralRenameError` (which no
                    // visible field would render → a silent failure).
                    self.structuralFailureReport = StructuralFailureReport(
                        verb: "rename", name: (path as NSString).lastPathComponent,
                        skipped: [])
                    self.lastError = self.humanReadable(error)
                }
                self.announceMutationFailure(
                    verb: "rename",
                    name: (path as NSString).lastPathComponent, error: error)
            }
            self.endStructuralMutation(token)
        }
        return task
    }

    /// Surfaced when `renameEntry` fails (collision / invalid name). The inline
    /// rename field renders this below itself and keeps focus (never silent).
    @Published var structuralRenameError: String?

    // MARK: Move

    /// Move the file or folder at `path` under `newParent` ("" = vault root).
    /// Same success handling as rename (retarget open tabs, refresh both
    /// affected levels, announce, surface failures). A collision / invalid
    /// destination (incl. moving a folder into its own subtree) surfaces via the
    /// skipped-files alert path's sibling — the move error alert.
    ///
    /// `undoContext` (#871): `.record` (the default — drag-drops, the Move
    /// sheet, the `createFolderThenMove` inner move) pushes the inverse move
    /// onto the structural undo stack; `.undoing`/`.redoing` are how
    /// `structuralUndo/Redo` re-enter this same FFI path to move an entry back
    /// while feeding the opposite stack.
    ///
    /// `announce` (#852): the per-item VoiceOver sentence. A BATCH move
    /// (`batchMove`) passes `false` so the individual "Moved <name> to <folder>."
    /// sentences don't chatter — the batch posts ONE summary ("Moved 3 items to
    /// Archive.") after every item's `moveEntry` (and its per-item link rewrite +
    /// structural-undo push) has completed. Single-surface callers leave it true.
    @discardableResult
    func moveEntry(
        path: String, isDirectory: Bool, to newParent: String,
        undoContext: StructuralUndoContext = .record,
        announce: Bool = true,
        onResult: ((Bool) -> Void)? = nil
    ) -> Task<Void, Never>? {
        guard admitStructuralMutationRequest(), let session = currentSession else { return nil }
        let newPath = Self.joinVaultPath(
            newParent, (path as NSString).lastPathComponent)
        guard let recoveryReservation = admitStructuralRecoveryRetargets([
                NoteRecoveryPathRetarget(
                    oldPath: path,
                    newPath: newPath,
                    includesDescendants: isDirectory)
            ]),
            admitBatchTrashWrite(to: [path, newPath]),
            admitBatchTrashVaultWideWrite()
        else { return nil }
        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let task = Task { [weak self] in
            let outcome: Result<StructuralReport, VaultError> = await Task.detached(
                priority: .userInitiated
            ) {
                do {
                    let report =
                        isDirectory
                        ? try session.moveFolder(path: path, newParent: newParent)
                        : try session.moveFile(path: path, newParent: newParent)
                    return .success(report)
                } catch let e as VaultError { return .failure(e) }
                catch { return .failure(.Io(message: error.localizedDescription)) }
            }.value
            guard let self, self.currentSession === session else { return }
            switch outcome {
            case .success(let report):
                let oldParent = TreeMutation.parentPath(of: path) ?? ""
                self.applyRetargets(report, movedFrom: path, movedTo: newPath, isDirectory: isDirectory)
                self.publishTreeMutation(
                    .move(
                        oldPath: path, newPath: newPath,
                        oldParent: oldParent, newParent: newParent),
                    rewrittenCount: Self.distinctRewrittenCount(report))
                if announce {
                    if undoContext == .record {
                        self.postMutationAnnouncement(
                            self.mutationSentence(
                                "Moved \((path as NSString).lastPathComponent) to "
                                    + "\(newParent.isEmpty ? "vault root" : (newParent as NSString).lastPathComponent).",
                                report: report))
                    } else {
                        // #871: an undo/redo of a move announces "Undid/Redid move
                        // of <name>." instead of the fresh-op sentence.
                        self.postMutationAnnouncement(
                            self.structuralUndoRedoAnnouncement(
                                executed: .move(
                                    path: path, isDirectory: isDirectory, targetParent: newParent),
                                context: undoContext))
                    }
                }
                // #871: record the inverse (move `newPath` back to `oldParent`)
                // on the correct stack for the given context.
                self.recordStructuralUndo(
                    inverse: .move(
                        path: newPath, isDirectory: isDirectory, targetParent: oldParent),
                    context: undoContext)
                self.surfaceStructuralFailures(
                    report, verb: "move", name: (path as NSString).lastPathComponent)
                await self.loadFiles()
                onResult?(true)
            case .failure(let error):
                // A move has no inline field — report through the alert path.
                self.structuralFailureReport = StructuralFailureReport(
                    verb: "move", name: (path as NSString).lastPathComponent,
                    skipped: [])
                self.lastError = self.humanReadable(error)
                // #852 red-team: the per-item VoiceOver failure is suppressed
                // under a batch (`announce == false`) so the batch owns ONE
                // summary; the alert (`lastError`) still surfaces the reason.
                if announce {
                    self.announceMutationFailure(
                        verb: "move",
                        name: (path as NSString).lastPathComponent, error: error)
                }
                onResult?(false)
            }
            self.endStructuralMutation(token)
        }
        return task
    }

    // MARK: - Batch move / delete (#852)

    /// Prune a multi-selection down to its TOP-LEVEL entries: drop any item that
    /// lives inside another SELECTED folder. Trashing/moving both a folder AND a
    /// file within it would leave the second op acting on a path the first
    /// already relocated (an error or a wrong-target op) — Finder likewise only
    /// operates on the outermost items. Pure + static so the dedup is regression-
    /// locked (the `moveOutcome` pattern); order-preserving so the batch acts in
    /// the caller's visible-row order.
    static func topLevelSelection(_ items: [TreeSelection]) -> [TreeSelection] {
        items.filter { item in
            !items.contains { other in
                other.path != item.path && other.isDirectory
                    && pathIsWithin(item.path, path: other.path, isDirectory: true)
            }
        }
    }

    /// Pure (#852): the ONE summary sentence a batch move announces once every
    /// item's `moveEntry` (announce:false) has landed. `count` is how many items
    /// actually moved (no-ops skipped). Static so the phrasing is regression-
    /// locked (the `withLinksSuffix` pattern).
    static func batchMoveAnnouncement(count: Int, destination newParent: String) -> String {
        let where_ = newParent.isEmpty ? "vault root" : (newParent as NSString).lastPathComponent
        return "Moved \(count) \(count == 1 ? "item" : "items") to \(where_)."
    }

    /// Pure (#852): the ONE summary sentence a batch delete announces.
    static func batchDeleteAnnouncement(count: Int) -> String {
        "Moved \(count) \(count == 1 ? "item" : "items") to Trash."
    }

    @discardableResult
    func moveTreeSelection(
        _ items: [TreeSelection],
        to newParent: String,
        preferredFocusPath: String? = nil
    ) -> Task<Void, Never>? {
        guard !items.isEmpty, currentSession != nil else { return nil }
        guard admitStructuralMutationRequest() else { return nil }
        if items.count == 1, let item = items.first {
            let currentParent = TreeMutation.parentPath(of: item.path) ?? ""
            guard currentParent != newParent else { return nil }
            guard !item.isDirectory
                || !Self.pathIsWithin(newParent, path: item.path, isDirectory: true)
            else { return nil }
            return moveEntry(
                path: item.path,
                isDirectory: item.isDirectory,
                to: newParent)
        }
        let validatedFocus = preferredFocusPath.flatMap { preferred in
            items.contains(where: { $0.path == preferred }) ? preferred : nil
        }
        return batchMove(
            items,
            to: newParent,
            preferredFocusPath: validatedFocus)
    }

    /// Compatibility entry used by older call sites that don't yet carry a
    /// preferred focus row. Admission-sensitive surfaces use the overload below
    /// so a busy second submission can observe `nil`.
    @discardableResult
    func batchMove(_ items: [TreeSelection], to newParent: String) -> Task<Void, Never> {
        batchMove(items, to: newParent, preferredFocusPath: nil) ?? Task {}
    }

    /// Submit the full captured selection to core exactly once. Swift does not
    /// prune descendants or no-ops: those are typed `envelope.skipped` facts in
    /// the native report and must survive for the result presentation.
    @discardableResult
    func batchMove(
        _ items: [TreeSelection],
        to newParent: String,
        preferredFocusPath: String?
    ) -> Task<Void, Never>? {
        guard !items.isEmpty, admitStructuralMutationRequest(),
            let session = currentSession
        else {
            return nil
        }
        let affectedPaths = items.flatMap { item in
            [
                item.path,
                Self.joinVaultPath(
                    newParent, (item.path as NSString).lastPathComponent),
            ]
        }
        guard let recoveryReservation = admitStructuralRecoveryRetargets(
                Self.topLevelSelection(items).map { item in
                    NoteRecoveryPathRetarget(
                        oldPath: item.path,
                        newPath: Self.joinVaultPath(
                            newParent,
                            (item.path as NSString).lastPathComponent),
                        includesDescendants: item.isDirectory)
                }),
            admitBatchTrashWrite(to: affectedPaths),
            admitBatchTrashVaultWideWrite()
        else { return nil }
        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let runner = batchMoveRunner
        let refresher = structuralBatchRefreshRunner
        let request = BatchMoveRequest(
            items: items.map {
                StructuralBatchItem(path: $0.path, isDirectory: $0.isDirectory)
            },
            newParent: newParent)
        let task = Task { @MainActor [weak self] in
            guard let self,
                let outcome = await self.executeForwardBatchMove(
                    session: session,
                    request: request,
                    mutationToken: token,
                runner: runner)
            else { return }

            guard self.ownsStructuralMutation(token, session: session) else {
                return
            }
            switch outcome {
            case .success(let reduction):
                if reduction.needsRefresh {
                    await refresher(self)
                    guard self.ownsStructuralMutation(token, session: session) else {
                        return
                    }
                }
                self.landForwardBatchMove(
                    reduction.report,
                    destination: newParent,
                    preferredFocusPath: preferredFocusPath,
                    historyWasReduced: true)
            case .failure(let error):
                await refresher(self)
                guard self.ownsStructuralMutation(token, session: session) else {
                    return
                }
                self.publishTreeMutation(
                    .batchReconcile,
                    rewrittenCount: 0,
                    requiresRescan: true,
                    preferredFocusPath: preferredFocusPath)
                let message = error.localizedDescription
                self.setBatchStructuralResult(BatchStructuralResult(
                    payload: .infrastructure(
                        operation: .move(.forward(destination: newParent)),
                        message: message),
                    requiresAttention: true))
                self.postMutationAnnouncement("Move failed: \(message)")
            }
            self.endStructuralMutation(token)
        }
        pendingStructuralTaskForTesting = task
        return task
    }

    private static func batchMoveNeedsRefresh(_ report: BatchMoveReport) -> Bool {
        switch report.state {
        case .rejected, .noOp:
            return report.requiresRescan
        case .succeeded, .rolledBack, .rollbackIncomplete:
            return true
        }
    }

    private enum ForwardBatchMoveHistoryAction {
        case preserve
        case record(StructuralUndoOp)
        case clear
    }

    private struct ForwardBatchMoveDiagnostic {
        enum Correlation {
            /// A fact about the planned request occurrence. Multiple facts for
            /// that item retain the same provider attribution.
            case plannedRequestPath
            /// A skipped ledger entry is its own request occurrence (notably a
            /// duplicate path), so it consumes the next provider occurrence.
            case skippedRequestPath
            case standingPath
            case batch
        }

        let path: String?
        let reason: String
        let kind: ImportBatchFailureDetail.Kind
        let correlation: Correlation
    }

    /// One canonical interpretation of a forward native batch report. Both
    /// standalone Move and aggregate Finder import consume this reducer, so
    /// physical paths, history, rescan requirements, and attention facts cannot
    /// drift between the two surfaces.
    private struct ForwardBatchMoveReduction {
        let report: BatchMoveReport
        let standing: [BatchPathChange]
        let touched: [BatchPathChange]
        let requiresRescan: Bool
        let needsRefresh: Bool
        let historyAction: ForwardBatchMoveHistoryAction
        let diagnostics: [ForwardBatchMoveDiagnostic]
    }

    private static func reduceForwardBatchMove(
        _ report: BatchMoveReport
    ) -> ForwardBatchMoveReduction {
        let standing = importStandingChanges(report)
        let touched = importTouchedChanges(report)
        let historyAction: ForwardBatchMoveHistoryAction
        var forceRescan = report.requiresRescan
        switch report.state {
        case .rejected, .noOp, .rolledBack:
            historyAction = .preserve
        case .succeeded:
            if !report.standing.isEmpty, let opID = report.opId {
                historyAction = .record(.batchMove(
                    opId: opID,
                    entries: report.standing))
            } else {
                historyAction = .clear
                forceRescan = true
            }
        case .rollbackIncomplete:
            historyAction = .clear
        }

        var diagnostics: [ForwardBatchMoveDiagnostic] = []
        func append(
            path: String?,
            reason: String,
            kind: ImportBatchFailureDetail.Kind = .terminalFailure,
            correlation: ForwardBatchMoveDiagnostic.Correlation = .plannedRequestPath
        ) {
            diagnostics.append(ForwardBatchMoveDiagnostic(
                path: path,
                reason: reason,
                kind: kind,
                correlation: correlation))
        }
        if let failure = report.failure {
            append(
                path: failure.item?.path,
                reason: BatchStructuralCopy.failureLine(failure))
        }
        for failure in report.rollbackFailures {
            append(
                path: failure.item?.path,
                reason: BatchStructuralCopy.failureLine(failure),
                correlation: .standingPath)
        }
        for failure in report.envelope.preflightFailures {
            append(
                path: failure.item?.path,
                reason: BatchStructuralCopy.failureLine(failure))
        }
        for skipped in report.envelope.skipped {
            append(
                path: skipped.item.path,
                reason: BatchStructuralCopy.skipReasonLabel(skipped.reason)
                    + (skipped.detail.isEmpty ? "" : ": \(skipped.detail)"),
                correlation: .skippedRequestPath)
        }
        for failure in report.rewriteFailures {
            append(
                path: failure.path,
                reason: "Link update failed: "
                    + BatchStructuralCopy.rewriteFailureReason(failure.kind),
                kind: .warning,
                correlation: .standingPath)
        }
        if forceRescan {
            append(
                path: nil,
                reason: "Slate needed an authoritative vault rescan to reconcile the move.",
                kind: .warning,
                correlation: .batch)
        }
        if report.state == .rollbackIncomplete {
            append(
                path: nil,
                reason: "Move restoration was incomplete; review the items that remain in their new locations.",
                kind: .warning,
                correlation: .batch)
        }
        if report.state == .succeeded,
            (report.standing.isEmpty || report.opId == nil)
        {
            append(
                path: nil,
                reason: "Slate could not reconcile the move safely.",
                kind: .warning,
                correlation: .batch)
        }

        return ForwardBatchMoveReduction(
            report: report,
            standing: standing,
            touched: touched,
            requiresRescan: forceRescan,
            needsRefresh: !standing.isEmpty || !touched.isEmpty || forceRescan,
            historyAction: historyAction,
            diagnostics: diagnostics)
    }

    /// Shared native executor and host reducer for every forward batch Move.
    /// The ownership guard is checked before any host mutation, so a report
    /// arriving after a vault replacement cannot retarget editors or history.
    private func executeForwardBatchMove(
        session: VaultSession,
        request: BatchMoveRequest,
        mutationToken: Int,
        runner: BatchMoveRunner
    ) async -> Result<ForwardBatchMoveReduction, Error>? {
        do {
            let report = try await runner(session, request)
            guard ownsStructuralMutation(mutationToken, session: session) else {
                return nil
            }
            let reduction = Self.reduceForwardBatchMove(report)
            quarantineBatchMovePathsBeforeRefresh(report)
            switch reduction.historyAction {
            case .preserve:
                break
            case .record(let inverse):
                recordStructuralUndo(inverse: inverse, context: .record)
            case .clear:
                clearStructuralUndoStacks()
            }
            return .success(reduction)
        } catch {
            guard ownsStructuralMutation(mutationToken, session: session) else {
                return nil
            }
            clearStructuralUndoStacks()
            return .failure(error)
        }
    }

    /// Synchronous host half of a native Move landing. The typed report is the
    /// sole path authority; history, tree mutation, result, and announcement
    /// still land once after the one inventory refresh.
    private func quarantineBatchMovePathsBeforeRefresh(_ report: BatchMoveReport) {
        switch report.state {
        case .succeeded, .rollbackIncomplete:
            applyBatchMoveRetargets(report.standing)
        case .rejected, .noOp, .rolledBack:
            break
        }
    }

    /// A no-op can still carry a native ledger that needs the user's attention.
    /// `planned` is only request context; every other vector describes work,
    /// rejection, recovery, or reconciliation that must not be hidden.
    private static func batchMoveHasActionableLedger(_ report: BatchMoveReport) -> Bool {
        report.failure != nil
            || !report.rollbackFailures.isEmpty
            || !report.envelope.preflightFailures.isEmpty
            || !report.rewriteFailures.isEmpty
            || !report.envelope.skipped.isEmpty
            || !report.standing.isEmpty
            || !report.rolledBack.isEmpty
            || !report.rewritten.isEmpty
            || report.requiresRescan
    }

    /// Execute one native batch-history edge. Core validates the journal id and
    /// returns the authoritative reverse/redo standing paths; Swift never
    /// synthesizes per-item destinations (which would be false for batches
    /// originating in multiple parent folders).
    @discardableResult
    private func executeBatchMoveInverse(
        _ inverse: StructuralUndoOp,
        opID: Int64,
        context: StructuralUndoContext
    ) -> Task<Void, Never>? {
        guard admitStructuralMutationRequest(), let session = currentSession else { return nil }
        guard case .batchMove(_, let entries) = inverse,
            let recoveryReservation = admitStructuralRecoveryRetargets(
                entries.map {
                    NoteRecoveryPathRetarget(
                        oldPath: $0.newPath,
                        newPath: $0.oldPath,
                        includesDescendants: $0.isDirectory)
                })
        else { return nil }
        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let runner = batchUndoMoveRunner
        let refresher = structuralBatchRefreshRunner
        let task = Task { @MainActor [weak self] in
            let outcome: Result<BatchMoveReport, Error>
            do {
                outcome = .success(try await runner(session, opID))
            } catch {
                outcome = .failure(error)
            }
            guard let self, self.ownsStructuralMutation(token, session: session) else {
                return
            }

            switch outcome {
            case .success(let report):
                self.quarantineBatchMovePathsBeforeRefresh(report)
                if Self.batchMoveNeedsRefresh(report) {
                    await refresher(self)
                    guard self.ownsStructuralMutation(token, session: session) else {
                        return
                    }
                }
                self.landBatchMoveInverse(report, source: inverse, context: context)
            case .failure(let error):
                await refresher(self)
                guard self.ownsStructuralMutation(token, session: session) else {
                    return
                }
                let mode: BatchStructuralResult.MoveMode =
                    context == .undoing ? .undo : .redo
                self.clearStructuralUndoStacks()
                self.publishTreeMutation(
                    .batchReconcile,
                    rewrittenCount: 0,
                    requiresRescan: true,
                    preferredFocusPath: nil)
                let message = error.localizedDescription
                self.setBatchStructuralResult(BatchStructuralResult(
                    payload: .infrastructure(
                        operation: .move(mode), message: message),
                    requiresAttention: true))
                let verb = context == .undoing ? "Undo" : "Redo"
                self.postMutationAnnouncement("\(verb) failed: \(message)")
            }
            self.endStructuralMutation(token)
        }
        return task
    }

    private enum BatchMoveHistoryPolicy {
        case recordForward
        case forwardAlreadyReduced
        case transition(source: StructuralUndoOp, context: StructuralUndoContext)
    }

    private func landBatchMoveInverse(
        _ report: BatchMoveReport,
        source: StructuralUndoOp,
        context: StructuralUndoContext
    ) {
        let mode: BatchStructuralResult.MoveMode =
            context == .undoing ? .undo : .redo
        landBatchMove(
            report,
            mode: mode,
            history: .transition(source: source, context: context),
            preferredFocusPath: nil)
    }

    private func landForwardBatchMove(
        _ report: BatchMoveReport,
        destination: String,
        preferredFocusPath: String?,
        historyWasReduced: Bool = false
    ) {
        let mode = BatchStructuralResult.MoveMode.forward(destination: destination)
        landBatchMove(
            report,
            mode: mode,
            history: historyWasReduced ? .forwardAlreadyReduced : .recordForward,
            preferredFocusPath: preferredFocusPath)
    }

    /// Shared physical Move matrix for forward, undo, and redo. The report is
    /// the sole authority for paths that stand or were restored; `history`
    /// changes only the stack edge and never changes physical interpretation.
    private func landBatchMove(
        _ report: BatchMoveReport,
        mode: BatchStructuralResult.MoveMode,
        history: BatchMoveHistoryPolicy,
        preferredFocusPath: String?
    ) {
        let attention: Bool
        let announcement: String
        let rewritten = Set(report.rewritten.map(\.path)).count
        switch report.state {
        case .rejected:
            attention = true
            announcement = "Move could not start. No items were moved."
            if report.requiresRescan {
                publishTreeMutation(
                    .batchReconcile,
                    rewrittenCount: 0,
                    requiresRescan: true,
                    preferredFocusPath: preferredFocusPath)
            }
        case .noOp:
            attention = Self.batchMoveHasActionableLedger(report)
            announcement = "Nothing moved."
            if report.requiresRescan {
                publishTreeMutation(
                    .batchReconcile,
                    rewrittenCount: 0,
                    requiresRescan: true,
                    preferredFocusPath: preferredFocusPath)
                }
        case .succeeded:
            guard !report.standing.isEmpty, let opID = report.opId else {
                clearStructuralUndoStacks()
                if report.standing.isEmpty {
                    publishTreeMutation(
                        .batchReconcile,
                        rewrittenCount: rewritten,
                        requiresRescan: true,
                        preferredFocusPath: preferredFocusPath)
                } else {
                    publishTreeMutation(
                        .batchMove(standing: report.standing, touched: []),
                        rewrittenCount: rewritten,
                        requiresRescan: true,
                        preferredFocusPath: preferredFocusPath)
                }
                setBatchStructuralResult(BatchStructuralResult(
                    payload: .move(report, mode: mode), requiresAttention: true))
                postMutationAnnouncement("Move could not be reconciled safely.")
                return
            }
            let landed = StructuralUndoOp.batchMove(
                opId: opID, entries: report.standing)
            let historyLanded: Bool
            switch history {
            case .recordForward:
                recordStructuralUndo(inverse: landed, context: .record)
                historyLanded = true
            case .forwardAlreadyReduced:
                historyLanded = structuralUndoStack.last == landed
            case .transition(let source, let context):
                let sourceStillTop: Bool
                switch context {
                case .undoing:
                    sourceStillTop = structuralUndoStack.last == source
                case .redoing:
                    sourceStillTop = structuralRedoStack.last == source
                case .record:
                    sourceStillTop = false
                }
                if sourceStillTop {
                    recordStructuralUndo(inverse: landed, context: context)
                }
                historyLanded = sourceStillTop
            }
            guard historyLanded else {
                clearStructuralUndoStacks()
                publishTreeMutation(
                    .batchMove(standing: report.standing, touched: []),
                    rewrittenCount: rewritten,
                    requiresRescan: true,
                    preferredFocusPath: preferredFocusPath)
                setBatchStructuralResult(BatchStructuralResult(
                    payload: .move(report, mode: mode), requiresAttention: true))
                postMutationAnnouncement("Move could not be reconciled safely.")
                return
            }
            publishTreeMutation(
                .batchMove(standing: report.standing, touched: []),
                rewrittenCount: rewritten,
                requiresRescan: report.requiresRescan,
                preferredFocusPath: preferredFocusPath)
            attention = !report.envelope.skipped.isEmpty
                || !report.envelope.preflightFailures.isEmpty
                || !report.rewriteFailures.isEmpty
                || report.requiresRescan
            let baseAnnouncement: String
            switch mode {
            case .forward(let destination):
                baseAnnouncement = Self.batchMoveAnnouncement(
                    count: report.standing.count, destination: destination)
            case .undo:
                baseAnnouncement = "Undid \(Self.structuralUndoActionName(landed))."
            case .redo:
                baseAnnouncement = "Redid \(Self.structuralUndoActionName(landed))."
            }
            announcement = Self.withLinksSuffix(
                baseAnnouncement, rewrittenCount: rewritten)
        case .rolledBack:
            attention = true
            publishTreeMutation(
                .batchMove(standing: [], touched: report.rolledBack),
                rewrittenCount: rewritten,
                requiresRescan: report.requiresRescan,
                preferredFocusPath: preferredFocusPath)
            announcement = "Move stopped. Slate restored every item to its original location."
        case .rollbackIncomplete:
            attention = true
            clearStructuralUndoStacks()
            publishTreeMutation(
                .batchMove(standing: report.standing, touched: report.rolledBack),
                rewrittenCount: rewritten,
                requiresRescan: report.requiresRescan,
                preferredFocusPath: preferredFocusPath)
            announcement = "Move stopped. Slate restored "
                + "\(Self.batchItemCountText(report.rolledBack.count)). "
                + "\(Self.batchItemCountText(report.standing.count)) "
                + "\(report.standing.count == 1 ? "remains in its" : "remain in their") "
                + "new location."
        }
        setBatchStructuralResult(BatchStructuralResult(
            payload: .move(report, mode: mode), requiresAttention: attention))
        postMutationAnnouncement(announcement)
    }

    private static func batchItemCountText(_ count: Int) -> String {
        "\(count) \(count == 1 ? "item" : "items")"
    }

    // MARK: - Structural undo/redo (#871)

    /// A reversible structural op — enough to invert a move or a rename via the
    /// SAME `moveEntry`/`renameEntry` FFI path the forward op used (constraint
    /// #871: reverse the op, don't invent a parallel primitive). `path` is the
    /// entry's CURRENT (post-forward-op) location; executing the case puts it
    /// back.
    enum StructuralUndoOp: Equatable {
        /// Reverse a move: move `path` under `targetParent` ("" = vault root).
        case move(path: String, isDirectory: Bool, targetParent: String)
        /// Reverse a rename: rename `path` to `newName` (a single component).
        case rename(path: String, isDirectory: Bool, newName: String)
        /// One native batch Move is one undo step. `opId` is the journal row
        /// core validates and reverses atomically; `entries` name the physical
        /// standing paths for truthful menu copy and later report comparison.
        case batchMove(opId: Int64, entries: [BatchPathChange])
    }

    /// Which structural-undo stack a completed move/rename feeds. Threaded
    /// through `moveEntry`/`renameEntry` so undo/redo re-use the exact forward
    /// path (constraint #871) without re-recording themselves onto the wrong
    /// stack. Equatable so the wrappers can branch the fresh-op announcement.
    enum StructuralUndoContext: Equatable {
        /// A fresh user op: push its inverse to the UNDO stack, clear REDO.
        case record
        /// This call IS an undo executing an inverse: retire the undone entry
        /// from the UNDO stack and stage its re-application on REDO.
        case undoing
        /// This call IS a redo: retire the redone entry from REDO and push its
        /// inverse back onto UNDO (REDO is NOT cleared).
        case redoing
    }

    /// Per-vault inverse-op stacks. Plain vars (not `@Published`): the Edit ▸
    /// Undo/Redo menu re-renders off the debounced `undoMenuTick` pulse
    /// (`noteUndoStacksChanged`), exactly like the canvas stacks that live on
    /// `CanvasDocument`. `private(set)` so tests can read depth/contents.
    ///
    /// Cross-vault safety (constraint #871.6): cleared on vault close AND on the
    /// direct-switch reset in `openVault` — an inverse resolved against the
    /// wrong vault would move/rename the wrong file.
    private(set) var structuralUndoStack: [StructuralUndoOp] = []
    private(set) var structuralRedoStack: [StructuralUndoOp] = []

    /// The menu action-name / announcement phrase for a structural op,
    /// describing it AS EXECUTED (direction-truthful): a move reads
    /// "move of <name>" (the item name is stable across the round-trip); a
    /// rename reads "rename to <target>" (the name the executed op produces).
    /// Reused by BOTH the "Undo/Redo …" menu title (the PENDING op, read from
    /// the stack top) and the "Undid/Redid …" announcement (the EXECUTED op) so
    /// the two phrasings can never drift. Static + pure → directly testable.
    static func structuralUndoActionName(_ op: StructuralUndoOp) -> String {
        switch op {
        case .move(let path, _, _):
            return "move of \((path as NSString).lastPathComponent)"
        case .rename(_, _, let newName):
            return "rename to \(newName)"
        case .batchMove(_, let entries):
            return "move of \(entries.count) \(entries.count == 1 ? "item" : "items")"
        }
    }

    /// The VoiceOver sentence for a completed undo/redo of a structural op
    /// (#871), e.g. "Undid move of Notes.md." / "Redid rename to Draft.md." —
    /// composed from the EXECUTED op so the announced name matches what landed
    /// on disk. `.record` never reaches here (the wrappers post the fresh-op
    /// sentence for it).
    private func structuralUndoRedoAnnouncement(
        executed: StructuralUndoOp, context: StructuralUndoContext
    ) -> String {
        let verb = (context == .undoing) ? "Undid" : "Redid"
        return "\(verb) \(Self.structuralUndoActionName(executed))."
    }

    /// Route a completed move/rename's inverse onto the correct stack for its
    /// `context` and pulse the undo menu. On the main actor and (for
    /// undo/redo) called from the SAME success handler that just executed the
    /// top-of-stack inverse under the `isMutatingStructure` guard, so the LIFO
    /// `removeLast()` retires exactly the entry we reversed — nothing can
    /// interleave between the peek in `structuralUndo/Redo` and this call.
    private func recordStructuralUndo(
        inverse: StructuralUndoOp, context: StructuralUndoContext
    ) {
        switch context {
        case .record:
            structuralUndoStack.append(inverse)
            structuralRedoStack.removeAll()
        case .undoing:
            if !structuralUndoStack.isEmpty { structuralUndoStack.removeLast() }
            structuralRedoStack.append(inverse)
        case .redoing:
            if !structuralRedoStack.isEmpty { structuralRedoStack.removeLast() }
            structuralUndoStack.append(inverse)
        }
        // #867/#871 debounced menu-title/enablement re-render pulse.
        noteUndoStacksChanged()
    }

    /// Whether a stack-top inverse is still SAFE to replay against the current
    /// filesystem (#871 Codex round 2). The `publishTreeMutation` barrier
    /// clears the stacks on every in-app non-move/rename mutation, but a
    /// file-creation FUNNEL that bypasses it (ghost note, new canvas, Restore
    /// As, template) — or an EXTERNAL change — can free the inverse's SOURCE or
    /// occupy its DESTINATION. Replaying then fails, or (worst case) touches a
    /// replacement file. This execution-time guard is the funnel-independent
    /// safety net: the source must still exist and the destination slot must be
    /// free, or the whole (now-suspect) history is dropped rather than replayed.
    private func structuralInverseIsExecutable(_ inverse: StructuralUndoOp) -> Bool {
        guard let vault = currentVaultURL else { return false }
        // lstat semantics (#871 Codex round 3): `attributesOfItem` does NOT
        // follow symlinks, so a DANGLING symlink at the destination — which
        // `fileExists` reports as absent — is correctly seen as an occupied
        // entry the replay must not clobber. Matches the backend no-clobber
        // check in `FilesystemProvider.rename`.
        func exists(_ rel: String) -> Bool {
            (try? FileManager.default.attributesOfItem(
                atPath: vault.appendingPathComponent(rel).path)) != nil
        }
        switch inverse {
        case .move(let path, _, let targetParent):
            let dest = Self.joinVaultPath(targetParent, (path as NSString).lastPathComponent)
            return exists(path) && !exists(dest)
        case .rename(let path, _, let newName):
            return exists(path) && !exists(Self.siblingPath(of: path, newName: newName))
        case .batchMove:
            // Core performs latest-journal validation and complete inverse
            // preflight under one lock. A Swift lstat loop would be a TOCTOU.
            return true
        }
    }

    /// ⌘Z routed to the structural domain (`undoTargetsStructural`): reverse
    /// the most recent move/rename via the SAME forward FFI wrapper, then stage
    /// its re-application on the redo stack. An empty stack ANNOUNCES rather
    /// than no-oping silently — the canvas-parity VoiceOver affordance
    /// (`undoMenuItemEnabled` keeps the item enabled to preserve it).
    func structuralUndo() {
        if let reason = structuralMutationDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        guard let inverse = structuralUndoStack.last else {
            postMutationAnnouncement("Nothing to undo.")
            return
        }
        guard structuralInverseIsExecutable(inverse) else {
            // The files changed under the inverse (a bypassing create funnel or
            // an external edit); drop the suspect history rather than replay it.
            clearStructuralUndoStacks()
            postMutationAnnouncement("Can't undo — the files have changed.")
            return
        }
        if let task = executeStructuralInverse(inverse, context: .undoing) {
            pendingStructuralTaskForTesting = task
        }
    }

    /// ⇧⌘Z twin of `structuralUndo`.
    func structuralRedo() {
        if let reason = structuralMutationDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        guard let inverse = structuralRedoStack.last else {
            postMutationAnnouncement("Nothing to redo.")
            return
        }
        guard structuralInverseIsExecutable(inverse) else {
            clearStructuralUndoStacks()
            postMutationAnnouncement("Can't redo — the files have changed.")
            return
        }
        if let task = executeStructuralInverse(inverse, context: .redoing) {
            pendingStructuralTaskForTesting = task
        }
    }

    /// Dispatch a stack-top inverse back through the forward wrappers with the
    /// given context (so the success handler feeds the OPPOSITE stack). Returns
    /// the wrapper's task so `structuralUndo/Redo` can park it in
    /// `pendingStructuralTaskForTesting` for deterministic test awaits (the
    /// same handle role the command funnels use).
    ///
    /// Constraint #871.5: the wrappers early-return under `isMutatingStructure`
    /// — a second ⌘Z while an op is still in flight is simply dropped (the
    /// entry stays put because the success handler that moves it never runs),
    /// never a deadlock and never a lost entry. Cross-vault (constraint
    /// #871.6): the wrappers' own `currentSession === session` guard after the
    /// FFI await bails without touching the stacks if the vault switched, and
    /// the stacks were already cleared by that switch.
    @discardableResult
    private func executeStructuralInverse(
        _ inverse: StructuralUndoOp, context: StructuralUndoContext
    ) -> Task<Void, Never>? {
        switch inverse {
        case .move(let path, let isDirectory, let targetParent):
            return moveEntry(
                path: path, isDirectory: isDirectory, to: targetParent, undoContext: context)
        case .rename(let path, let isDirectory, let newName):
            return renameEntry(
                path: path, isDirectory: isDirectory, to: newName, undoContext: context)
        case .batchMove(let opID, _):
            return executeBatchMoveInverse(
                inverse, opID: opID, context: context)
        }
    }

    /// Drop the per-vault structural undo/redo stacks (constraint #871.6),
    /// pulsing the menu only when something actually changed. Called from
    /// `closeVault` and the `openVault` direct-switch reset block.
    func clearStructuralUndoStacks() {
        guard !structuralUndoStack.isEmpty || !structuralRedoStack.isEmpty else { return }
        structuralUndoStack = []
        structuralRedoStack = []
        noteUndoStacksChanged()
    }

    /// On-disk presence of a VAULT-RELATIVE path right now — the snapshot a
    /// create-vs-overwrite barrier decision takes IMMEDIATELY BEFORE an
    /// unconditional (create-OR-overwrite) write, so it can tell a newly
    /// created path from an in-place overwrite of an already-present one.
    func vaultPathExists(_ relativePath: String) -> Bool {
        guard let vault = currentVaultURL else { return false }
        return FileManager.default.fileExists(
            atPath: vault.appendingPathComponent(relativePath).path)
    }

    /// The single place the #871 structural-undo barrier rule lives. The
    /// barrier (`clearStructuralUndoStacks`) must fire EXACTLY when a write
    /// makes a previously-ABSENT in-vault openable path become PRESENT, because
    /// a pending move/rename inverse could name that path as its destination
    /// and would then act on the wrong file. `relativePath` is the write target
    /// as a VAULT-RELATIVE path, or nil when the write lands OUTSIDE the vault
    /// (nothing to barrier). `existedBefore` is that path's on-disk presence
    /// snapshotted IMMEDIATELY BEFORE the write. Fires ONLY for a newly created
    /// in-vault path — never on an in-place OVERWRITE of an already-present path
    /// (that would drop an unrelated legit undo) and never off-vault. Exclusive
    /// funnels whose success already implies "created" (createExclusive /
    /// create-if-absent saveText / a delete-remnant restore) call
    /// `clearStructuralUndoStacks()` directly instead.
    func barrierStructuralUndoForCreatedVaultPath(
        relativePath: String?, existedBefore: Bool
    ) {
        guard relativePath != nil, !existedBefore else { return }
        clearStructuralUndoStacks()
    }

    /// Save-panel convenience over `barrierStructuralUndoForCreatedVaultPath`:
    /// resolve an arbitrary on-disk `url` (an NSSavePanel destination that may
    /// target ANYWHERE) to a vault-relative path — out-of-vault → nil → no
    /// barrier — and apply the create-vs-overwrite rule. `existedBefore` must be
    /// snapshotted before the write.
    func barrierStructuralUndoForExternalWrite(to url: URL, existedBefore: Bool) {
        barrierStructuralUndoForCreatedVaultPath(
            relativePath: Self.vaultRelativePath(of: url, vaultURL: currentVaultURL),
            existedBefore: existedBefore)
    }

    // MARK: - Import (#870)

    /// Import an EXTERNAL file (dropped from Finder / another app) into
    /// `destinationFolder` ("" = vault root) as a copy. Reuses the SAME
    /// no-clobber collision surface as `moveEntry` (constraint #870): the
    /// `create_exclusive` primitive throws `DestinationExists` on a name
    /// collision, which surfaces through the identical `lastError` +
    /// `announceMutationFailure` path a colliding move takes.
    ///
    /// Binary-aware (#910): the dropped file is read as raw `Data`, and the
    /// payload kind picks the FFI. A valid-UTF-8 file takes the text
    /// `createExclusive` path UNCHANGED (same link-rewrite scope — none — and
    /// announcement as before); a binary / non-UTF-8 file (image, PDF, …) takes
    /// the `createExclusiveBytes` FFI and lands as a byte-for-byte copy. Both
    /// share the SAME no-clobber collision surface — `create_exclusive`/
    /// `create_exclusive_bytes` throw `DestinationExists`, which flows through
    /// the identical `lastError` + `announceMutationFailure` a colliding
    /// `moveEntry` takes. An import is a CREATE (like `createNote`/
    /// `duplicateEntry` — not undoable; delete is the Trash-recoverable
    /// inverse), so its shared `publishTreeMutation(.createNote)` success path
    /// barriers the structural-undo stacks (#871) and records no undo entry.
    @discardableResult
    func importEntry(externalURL: URL, into destinationFolder: String) -> Task<Void, Never>? {
        guard let session = currentSession else { return nil }
        guard admitStructuralMutationRequest() else { return nil }
        let name = externalURL.lastPathComponent
        let destPath = Self.joinVaultPath(destinationFolder, name)
        guard let recoveryReservation = admitStructuralRecoveryDestination(destPath),
            admitBatchTrashWrite(to: [destPath])
        else { return nil }
        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let task = Task { [weak self] in
            let outcome: Result<Void, VaultError> = await Task.detached(
                priority: .userInitiated
            ) {
                // A dropped file URL may be security-scoped (sandboxed builds);
                // the accessor is a harmless no-op otherwise (returns false, we
                // still read). Balanced with a `defer`.
                let scoped = externalURL.startAccessingSecurityScopedResource()
                defer { if scoped { externalURL.stopAccessingSecurityScopedResource() } }
                do {
                    // Refuse an oversized import WITHOUT letting a >2 GiB buffer
                    // reach the FFI (#910 red-team Medium + Codex follow-up).
                    // Lowering a >2 GiB `Data`/`String` traps in the generated
                    // `Int32(value.count)` converter — a hard crash that beats
                    // the Rust `large_file_refuse_bytes` backstop. Two layers,
                    // both against the SAME engine threshold, both surfacing the
                    // identical `FileTooLarge` the Rust layer would (routed
                    // through the shared `announceMutationFailure` / `lastError`
                    // path below) and BOTH before the decode, so text and binary
                    // are covered alike.
                    // The EFFECTIVE ceiling is the engine threshold clamped to
                    // the FFI's single-buffer transport limit (`Int32.max - 4`,
                    // the 4 covering the RustBuffer length prefix), and it is
                    // used for EVERY byte-count decision below — the preflight,
                    // the read cap, AND the definitive gate — so nothing larger
                    // than the converter can carry ever reaches
                    // `createExclusive*` (#910 Codex rounds 2–3).
                    let ceiling = Self.importTransportCeiling(
                        refuseBytes: session.largeFileRefuseBytes())
                    // (1) Cheap preflight stat: fast-rejects the common large
                    //     file without a read. Metadata may be ABSENT (nil) for a
                    //     package/device/special source, or simply omitted by
                    //     Foundation — nil is NOT trusted as within-limit; step
                    //     (3) is the definitive gate.
                    let metadataSize = (try? externalURL.resourceValues(
                        forKeys: [.fileSizeKey]))?.fileSize
                    if let over = Self.importOverCeiling(
                        metadataSize: metadataSize, readByteCount: nil, refuseBytes: ceiling)
                    {
                        return .failure(.FileTooLarge(path: destPath, size: over))
                    }
                    // (2) BOUNDED read: never load more than `ceiling + 1`, so a
                    //     nil-/stale-metadata multi-GB (or unbounded) source is
                    //     never fully loaded, let alone lowered across the FFI.
                    let data = try Self.readImportBytes(from: externalURL, cap: ceiling)
                    // (3) DEFINITIVE gate on the bytes actually in hand — catches
                    //     the nil-preflight and grown-since-stat (TOCTOU) cases
                    //     the metadata check can miss, before either branch.
                    if let over = Self.importOverCeiling(
                        metadataSize: nil, readByteCount: data.count, refuseBytes: ceiling)
                    {
                        return .failure(.FileTooLarge(path: destPath, size: over))
                    }
                    // Branch on decodability: valid UTF-8 → the text create
                    // (byte-identical to the prior `String(contentsOf:…)`
                    // behavior); otherwise → the #910 bytes create, a verbatim
                    // copy.
                    if let text = String(data: data, encoding: .utf8) {
                        _ = try session.createExclusive(path: destPath, content: text)
                    } else {
                        _ = try session.createExclusiveBytes(path: destPath, bytes: data)
                    }
                    return .success(())
                } catch let e as VaultError { return .failure(e) }
                catch { return .failure(.Io(message: error.localizedDescription)) }
            }.value
            guard let self, self.currentSession === session else { return }
            switch outcome {
            case .success:
                // A fresh file at the destination — the same `.createNote`
                // mutation `duplicateEntry` publishes (a copy IS a created note).
                self.publishTreeMutation(.createNote(path: destPath), rewrittenCount: 0)
                self.postMutationAnnouncement("Imported \(name).")
                await self.loadFiles()
            case .failure(let error):
                self.lastError = self.humanReadable(error)
                self.announceMutationFailure(verb: "import", name: name, error: error)
            }
            self.endStructuralMutation(token)
        }
        return task
    }

    /// The effective transport ceiling for a single import buffer (#910 Codex
    /// rounds 2–3). Lowering a `Data`/`String` argument across the FFI wraps the
    /// payload in a RustBuffer whose length is converted with `Int32(...)`, and
    /// that conversion TRAPS above `Int32.max`. Two nested conversions matter,
    /// traced through the generated `slate_uniffi.swift`:
    ///   • `FfiConverterData.write` prefixes a 4-byte length, THEN
    ///     `RustBuffer.from` → `ForeignBytes.init` converts `Int32(payload.count
    ///     + 4)` — the OUTER conversion, stricter than the inner by the 4-byte
    ///     prefix.
    ///   • the `String` argument path lowers `Int32(utf8.count)` (no prefix),
    ///     and for an import `utf8.count == data.count`, so it is the looser of
    ///     the two.
    /// The binding constraint is therefore the Data path: `count + 4 <=
    /// Int32.max`, i.e. `count <= Int32.max - 4`. Clamping here — and using the
    /// result for the preflight, the bounded-read cap, AND the definitive gate —
    /// makes BOTH conversions (inner `value.count` and outer buffer length)
    /// unable to trap for ANY config, not just the ~50 MiB default, and keeps
    /// the reader's `cap + 1` sentinel `Int`-safe (the ceiling is ~2 GiB, far
    /// below `Int.max`). In the pathological >2 GiB-config case this makes Swift
    /// STRICTER than the Rust `large_file_refuse_bytes` backstop — it refuses a
    /// subset Rust would accept — which is the FFI transport bound, not an
    /// inconsistency (a larger single buffer would need a separate
    /// chunked-transfer feature). The Rust backstop is untouched.
    nonisolated static func importTransportCeiling(refuseBytes: UInt64) -> UInt64 {
        // `- 4` = the RustBuffer 4-byte length-prefix headroom, so the OUTER FFI
        // buffer conversion (`Int32(payload.count + 4)`), not just the inner
        // `Int32(value.count)`, cannot trap — for both Data and String lowering.
        min(refuseBytes, UInt64(Int32.max) - 4)
    }

    /// The #910 byte-ceiling decision, shared by `importEntry`'s two-layer
    /// size guard. `metadataSize` is the cheap pre-read stat (nil when the
    /// source's metadata is unavailable — a package/device/special file, or
    /// Foundation omitting `.fileSizeKey`); `readByteCount` is the count of
    /// bytes actually read. Returns the size to report in `FileTooLarge`, or
    /// nil to proceed.
    ///
    /// A nil `metadataSize` is deliberately NOT treated as within-limit: the
    /// post-read `readByteCount` is the definitive gate, so a nil/stale stat
    /// (and a file that grew between the stat and the read) is still refused
    /// before the bytes cross the FFI, where a >2 GiB buffer would trap.
    nonisolated static func importOverCeiling(
        metadataSize: Int?, readByteCount: Int?, refuseBytes: UInt64
    ) -> UInt64? {
        if let metadataSize, UInt64(metadataSize) > refuseBytes { return UInt64(metadataSize) }
        if let readByteCount, UInt64(readByteCount) > refuseBytes { return UInt64(readByteCount) }
        return nil
    }

    /// Read a to-be-imported file, BOUNDED to `cap + 1` bytes (#910). One byte
    /// past the refuse ceiling is enough for the caller to detect an over-limit
    /// file, so capping there means a nil-/stale-metadata multi-GB (or otherwise
    /// unbounded) source is never fully loaded into memory. Short-read-safe:
    /// accumulates until the cap is reached or EOF. `cap` is clamped so the
    /// `+ 1` cannot overflow `Int` (the threshold is realistically ~50 MB).
    nonisolated static func readImportBytes(from url: URL, cap: UInt64) throws -> Data {
        let readCap = cap < UInt64(Int.max) ? Int(cap) + 1 : Int.max
        let handle = try FileHandle(forReadingFrom: url)
        defer { try? handle.close() }
        var buffer = Data()
        while buffer.count < readCap {
            guard let chunk = try handle.read(upToCount: readCap - buffer.count),
                !chunk.isEmpty
            else { break }
            buffer.append(chunk)
        }
        return buffer
    }

    /// The action a file-URL drop (#870) resolves to. Pure decision so the
    /// import-vs-move branch is testable without a live drag.
    enum StructuralDropAction: Equatable {
        /// The dropped URL is INSIDE the current vault → move (existing
        /// behavior), routed through `moveEntry` (undoable).
        case move(path: String, isDirectory: Bool, to: String)
        /// The dropped URL is EXTERNAL → import a copy via `importEntry`.
        case importFile(url: URL, into: String)
        /// A reason-bearing no-op retained by aggregate imports and spoken by
        /// the legacy single-provider funnel.
        case none(reason: String)
    }

    static let sameParentImportNoOpReason =
        "Nothing moved. The item is already in this folder."
    static let ownSubtreeImportNoOpReason =
        "Nothing moved. A folder can’t be moved into itself."
    static let vaultRootImportNoOpReason =
        "Nothing imported. The open vault can’t be imported into itself."

    /// Pure (#870): classify a file-URL drop. A URL under the current vault is
    /// a MOVE (identical to an intra-tree drag — and thus undoable); an
    /// external URL is an IMPORT. Rejects the no-ops the private-type move path
    /// also rejects early (already in the destination; a folder onto its own
    /// subtree) so the two drop routes behave the same.
    /// Whether `url` points at a directory (#870, Codoki: extracted as a
    /// testable seam with UNAMBIGUOUS optional handling). `try?` wraps ONLY the
    /// throwing `resourceValues` call — yielding `URLResourceValues?` — then
    /// `?.isDirectory` reads the (itself-optional) key and `?? false` lands a
    /// plain `Bool`. The prior `(try? resourceValues(...).isDirectory) ?? false`
    /// nested the property access inside `try?`, relying on Swift's flattening
    /// and reading as a `Bool??` a reviewer (and a linter) can misjudge. An
    /// unreadable value falls back to false (treat as a file) — the safe
    /// default for the import path.
    static func urlIsDirectory(_ url: URL) -> Bool {
        (try? url.resourceValues(forKeys: [.isDirectoryKey]))?.isDirectory ?? false
    }

    static func fileURLDropAction(
        url: URL, vaultURL: URL?, destinationFolder: String, isDirectory: Bool
    ) -> StructuralDropAction {
        if let rel = vaultRelativePath(of: url, vaultURL: vaultURL) {
            let currentParent = TreeMutation.parentPath(of: rel) ?? ""
            if currentParent == destinationFolder {
                return .none(reason: sameParentImportNoOpReason)
            }
            if isDirectory, pathIsWithin(destinationFolder, path: rel, isDirectory: true) {
                return .none(reason: ownSubtreeImportNoOpReason)
            }
            return .move(path: rel, isDirectory: isDirectory, to: destinationFolder)
        }
        // #870 Codex round 3: dragging the CURRENT VAULT ROOT onto its own tree
        // is a no-op, NOT an external import. `vaultRelativePath` returns nil
        // for BOTH the root and a truly-external URL, so distinguish them here
        // before the import branch — otherwise Slate would try to text-import
        // the vault directory and surface a spurious failure.
        if isVaultRoot(url, vaultURL: vaultURL) {
            return .none(reason: vaultRootImportNoOpReason)
        }
        return .importFile(url: url, into: destinationFolder)
    }

    /// Dispatch one decoded public file-URL drop through the admission-aware
    /// move/import request funnels. Classification stays pure and preserves the
    /// existing same-parent, own-subtree, and vault-root no-op outcomes.
    @discardableResult
    func handleFileURLDrop(
        _ url: URL,
        into destinationFolder: String
    ) -> Task<Void, Never>? {
        let isDirectory = Self.urlIsDirectory(url)
        switch Self.fileURLDropAction(
            url: url,
            vaultURL: currentVaultURL,
            destinationFolder: destinationFolder,
            isDirectory: isDirectory)
        {
        case .move(let path, let isDirectory, let destination):
            return moveTreeSelection(
                [TreeSelection(path: path, isDirectory: isDirectory)],
                to: destination)
        case .importFile(let externalURL, let destination):
            return importEntry(externalURL: externalURL, into: destination)
        case .none(let reason):
            postMutationAnnouncement(reason)
            return nil
        }
    }

    /// Whether `url` IS the current vault root (#870 Codex round 3). Fully
    /// resolves symlinks on both sides (the root is a container, so — unlike a
    /// dropped item — its own final component is safe to resolve) and honors
    /// the volume's case sensitivity, so a vault opened through a symlinked
    /// spelling still matches.
    private static func isVaultRoot(_ url: URL, vaultURL: URL?) -> Bool {
        guard let vaultURL else { return false }
        guard !finalPathComponentIsSymbolicLink(url) else { return false }
        let vaultPath = vaultURL.resolvingSymlinksInPath().standardizedFileURL.path
        let droppedPath = url.resolvingSymlinksInPath().standardizedFileURL.path
        return pathComponentsEqual(
            droppedPath, vaultPath, caseInsensitive: volumeIsCaseInsensitive(vaultURL))
    }

    /// The vault-relative path of `url` if it lives inside `vaultURL`, else
    /// nil (external). The vault root itself maps to nil (it isn't a movable
    /// entry).
    ///
    /// #870 Codex round 1: containment is FILESYSTEM-AWARE, not a raw lexical
    /// compare. Both paths are resolved through symlinks and standardized
    /// (so a symlinked vault root, or a dropped URL that traverses a symlink
    /// or `..`, still matches), and the prefix match honors the volume's
    /// case sensitivity (defaulting to case-INSENSITIVE, the macOS APFS
    /// default). Without this, the same in-vault file reached via a symlink
    /// or a case-differing path was misclassified as external and IMPORTED
    /// as a duplicate instead of performing the required undoable move. The
    /// returned relative path keeps the resolved file's real component casing
    /// (what the backend expects).
    static func vaultRelativePath(of url: URL, vaultURL: URL?) -> String? {
        guard let vaultURL else { return nil }
        // The dropped final component is an object in its own right. Never
        // follow it into native Move classification: every final symlink stays
        // on the external path so Task 3's no-follow walker can reject it
        // truthfully without mutating its target.
        guard !finalPathComponentIsSymbolicLink(url) else { return nil }
        let vaultPath = vaultURL.resolvingSymlinksInPath().standardizedFileURL.path
        // #870 Codex round 2: resolve symlinks in the CONTAINER only, then
        // re-attach the dropped item's own final component UNRESOLVED. If the
        // whole URL were resolved, an EXTERNAL symlink file (e.g.
        // ~/Downloads/link.md → /vault/a.md) would dereference to its in-vault
        // target and be classified as a move of the real note — breaking the
        // external link — instead of importing the dropped entry. Resolving the
        // ancestor still canonicalizes a symlinked vault root / parent dir.
        let filePath =
            url.deletingLastPathComponent().resolvingSymlinksInPath()
            .appendingPathComponent(url.lastPathComponent).standardizedFileURL.path
        let caseInsensitive = volumeIsCaseInsensitive(vaultURL)
        if pathComponentsEqual(filePath, vaultPath, caseInsensitive: caseInsensitive) {
            return nil  // the vault root itself
        }
        let prefix = vaultPath.hasSuffix("/") ? vaultPath : vaultPath + "/"
        guard filePath.count > prefix.count else { return nil }
        let head = String(filePath.prefix(prefix.count))
        guard pathComponentsEqual(head, prefix, caseInsensitive: caseInsensitive) else {
            return nil
        }
        return String(filePath.dropFirst(prefix.count))
    }

    /// `lstat` observes the final directory entry without dereferencing it;
    /// intermediate components retain normal filesystem resolution.
    private static func finalPathComponentIsSymbolicLink(_ url: URL) -> Bool {
        var metadata = stat()
        return url.withUnsafeFileSystemRepresentation { path in
            guard let path, lstat(path, &metadata) == 0 else { return false }
            return metadata.st_mode & S_IFMT == S_IFLNK
        }
    }

    /// Whether `url`'s volume treats names case-INSENSITIVELY (the macOS APFS
    /// default). Defaults to `true` when the volume flag can't be read (#870).
    private static func volumeIsCaseInsensitive(_ url: URL) -> Bool {
        let values = try? url.resourceValues(forKeys: [.volumeSupportsCaseSensitiveNamesKey])
        if let sensitive = values?.volumeSupportsCaseSensitiveNames { return !sensitive }
        return true
    }

    private static func pathComponentsEqual(
        _ a: String, _ b: String, caseInsensitive: Bool
    ) -> Bool {
        caseInsensitive ? (a.compare(b, options: .caseInsensitive) == .orderedSame) : (a == b)
    }

    // MARK: Delete

    /// A non-empty folder delete awaiting user confirmation (#860). Set by
    /// `requestDeleteEntry` when the target is a folder with children; the
    /// MainSplitView alert consumes it (Move to Trash confirms, Cancel
    /// drops). Files and empty folders never stage — they keep the
    /// no-confirm Finder-parity path (a file trash is recoverable; a whole
    /// subtree moving on one chord is the heavier loss-of-context event).
    struct PendingFolderDelete: Equatable, Identifiable {
        let id: UUID
        let sessionIdentity: ObjectIdentifier
        let path: String
        /// Immediate (non-recursive) child count — the "its N items" the
        /// alert message speaks. Advisory: the delete itself takes the whole
        /// subtree regardless.
        let itemCount: Int
        var name: String { (path as NSString).lastPathComponent }
    }

    @Published private(set) var pendingFolderDelete: PendingFolderDelete?

    /// The single delete entry point every surface routes through (#860):
    /// tree ⌘⌫ / rotor / context menu, and the menu/palette command. A
    /// folder with children stages `pendingFolderDelete` (confirmation
    /// alert) instead of deleting; everything else falls straight through to
    /// `deleteEntry`. `knownChildCount` lets the tree pass its node's cached
    /// immediate count; callers without one (the selection-scoped command)
    /// leave it nil and a shallow FileManager enumerate fills in.
    @discardableResult
    func requestDeleteEntry(
        path: String, isDirectory: Bool, knownChildCount: Int? = nil
    ) -> Bool {
        guard let session = currentSession else { return false }
        guard admitStructuralMutationRequest() else { return false }
        guard admitBatchTrashMutation(
            of: [StructuralBatchItem(path: path, isDirectory: isDirectory)])
        else { return false }
        if isDirectory {
            // A cached count of ZERO is treated as unknown: the tree's
            // itemCount can be stale (folder filled externally since the
            // fetch), and a stale zero would BYPASS the confirmation —
            // trashing a non-empty folder unprompted. Only the zero case
            // re-probes; a stale positive merely over-confirms (harmless).
            let count = knownChildCount.flatMap { $0 > 0 ? $0 : nil }
                ?? shallowChildCount(ofFolder: path)
            if count > 0 {
                pendingFolderDelete = PendingFolderDelete(
                    id: UUID(),
                    sessionIdentity: ObjectIdentifier(session),
                    path: path,
                    itemCount: count)
                return true
            }
        }
        guard let task = deleteEntry(path: path, isDirectory: isDirectory) else {
            return false
        }
        pendingStructuralTaskForTesting = task
        return true
    }

    /// Alert "Move to Trash" — run the staged folder delete through the
    /// normal funnel (announcement + tree focus move ride along unchanged).
    @discardableResult
    func confirmPendingFolderDelete(id: UUID) -> Bool {
        guard let pending = pendingFolderDelete, pending.id == id else {
            return false
        }
        guard let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else {
            pendingFolderDelete = nil
            return false
        }
        guard admitStructuralMutationRequest() else { return false }
        guard let task = deleteEntry(path: pending.path, isDirectory: true) else {
            return false
        }
        pendingFolderDelete = nil
        pendingStructuralTaskForTesting = task
        return true
    }

    /// The live alert monitor consumes bare Return without admitting the
    /// destructive action or changing the staged request.
    @discardableResult
    func handlePendingFolderDeleteReturnKey(id: UUID) -> Bool {
        guard pendingFolderDelete?.id == id else { return false }
        return false
    }

    /// Alert "Cancel" — nothing is deleted.
    @discardableResult
    func cancelPendingFolderDelete(id: UUID) -> Bool {
        guard pendingFolderDelete?.id == id else { return false }
        pendingFolderDelete = nil
        return true
    }

    // MARK: - Batch delete (#852)

    /// A multi-selection awaiting delete confirmation (#852). Staged by
    /// `requestBatchDelete` only when the batch contains at least one non-empty
    /// folder (the #860 heavier-loss event); an all-files / empty-folder batch
    /// trashes straight through, Finder-parity. The MainSplitView alert consumes
    /// it.
    struct BatchDelete: Equatable, Identifiable {
        let id: UUID
        let sessionIdentity: ObjectIdentifier
        /// The complete captured selection. Core returns the projected ledger.
        let items: [TreeSelection]
        let preferredFocusPath: String?
        /// How many non-empty folders the batch includes — drives the alert
        /// message ("including N folders with contents").
        let nonEmptyFolderCount: Int
        var itemCount: Int { items.count }
    }

    @Published private(set) var pendingBatchDelete: BatchDelete?

    enum BatchDeleteConfirmationKey {
        case returnKey
        case cancel
    }

    /// Behavior seam for the destructive confirmation's keyboard contract:
    /// Return never admits Trash; Escape/Command-Period take the captured
    /// cancel path. SwiftUI's cancel-role button routes through this resolver.
    @discardableResult
    func handlePendingBatchDeleteKey(
        _ key: BatchDeleteConfirmationKey,
        id: UUID
    ) -> Bool {
        guard pendingBatchDelete?.id == id else { return false }
        switch key {
        case .returnKey:
            return false
        case .cancel:
            return cancelPendingBatchDelete(id: id)
        }
    }

    /// The batch delete entry point (#852): trashes a whole multi-selection with
    /// ONE summary announcement. Mirrors `requestDeleteEntry`'s #860 gate at the
    /// batch level — if ANY selected item is a non-empty folder, stage
    /// `pendingBatchDelete` (confirmation) rather than trashing unprompted; an
    /// all-files / empty-folder batch falls straight through to `batchDelete`.
    /// The selection is deduplicated to its top-level items first so a folder +
    /// something inside it don't double-delete.
    @discardableResult
    func requestBatchDelete(
        _ items: [TreeSelection], preferredFocusPath: String? = nil
    ) -> Bool {
        guard let session = currentSession, !items.isEmpty else { return false }
        guard admitStructuralMutationRequest() else { return false }
        guard admitBatchTrashMutation(
            of: items.map {
                StructuralBatchItem(path: $0.path, isDirectory: $0.isDirectory)
            })
        else { return false }
        // A single item routes through the single funnel so it gets the exact
        // #860 single-folder confirmation copy (and its own announcement).
        if items.count == 1, let only = items.first {
            return requestDeleteEntry(
                path: only.path, isDirectory: only.isDirectory)
        }
        guard let vaultURL = currentVaultURL else { return false }
        let capturedItems = items
        let capturedFocusPath = preferredFocusPath
        let sessionIdentity = ObjectIdentifier(session)
        let confirmationID = UUID()
        let folderPaths = items.compactMap { $0.isDirectory ? $0.path : nil }
        let probeRunner = batchDeleteConfirmationProbeRunner
        let trashRunner = batchTrashRunner
        let refresher = structuralBatchRefreshRunner
        let trashRequest = BatchTrashRequest(
            items: capturedItems.map {
                StructuralBatchItem(path: $0.path, isDirectory: $0.isDirectory)
            })
        let token = beginStructuralMutation()
        let task = Task { @MainActor [weak self] in
            let nonEmptyFolderCount = await probeRunner(vaultURL, folderPaths)
            guard let self, self.ownsStructuralMutation(token, session: session) else {
                return
            }
            guard nonEmptyFolderCount > 0 else {
                await self.performBatchTrash(
                    request: trashRequest,
                    preferredFocusPath: capturedFocusPath,
                    session: session,
                    token: token,
                    runner: trashRunner,
                    refresher: refresher)
                return
            }
            self.pendingBatchDelete = BatchDelete(
                id: confirmationID,
                sessionIdentity: sessionIdentity,
                items: capturedItems,
                preferredFocusPath: capturedFocusPath,
                nonEmptyFolderCount: nonEmptyFolderCount)
            self.endStructuralMutation(token)
        }
        pendingStructuralTaskForTesting = task
        return true
    }

    /// Alert "Move to Trash" — run the staged batch delete through the funnel.
    @discardableResult
    func confirmPendingBatchDelete(id: UUID) -> Bool {
        guard let pending = pendingBatchDelete, pending.id == id else { return false }
        guard let session = currentSession,
            pending.sessionIdentity == ObjectIdentifier(session)
        else {
            pendingBatchDelete = nil
            return false
        }
        guard admitStructuralMutationRequest() else { return false }
        guard batchDelete(
            pending.items, preferredFocusPath: pending.preferredFocusPath) != nil
        else { return false }
        pendingBatchDelete = nil
        return true
    }

    /// Alert "Cancel" — nothing is deleted.
    @discardableResult
    func cancelPendingBatchDelete(id: UUID) -> Bool {
        guard pendingBatchDelete?.id == id else { return false }
        pendingBatchDelete = nil
        return true
    }

    /// Compatibility entry for call sites without a captured focus path.
    @discardableResult
    func batchDelete(_ items: [TreeSelection]) -> Task<Void, Never> {
        batchDelete(items, preferredFocusPath: nil) ?? Task {}
    }

    /// Submit the captured Trash selection to core exactly once.
    @discardableResult
    func batchDelete(
        _ items: [TreeSelection],
        preferredFocusPath: String?
    ) -> Task<Void, Never>? {
        guard !items.isEmpty, admitStructuralMutationRequest(),
            let session = currentSession
        else {
            return nil
        }
        guard admitBatchTrashMutation(
            of: items.map {
                StructuralBatchItem(path: $0.path, isDirectory: $0.isDirectory)
            })
        else { return nil }
        let token = beginStructuralMutation()
        let runner = batchTrashRunner
        let refresher = structuralBatchRefreshRunner
        let request = BatchTrashRequest(
            items: items.map {
                StructuralBatchItem(path: $0.path, isDirectory: $0.isDirectory)
            })
        let task = Task { @MainActor [weak self] in
            guard let self else { return }
            await self.performBatchTrash(
                request: request,
                preferredFocusPath: preferredFocusPath,
                session: session,
                token: token,
                runner: runner,
                refresher: refresher)
        }
        pendingStructuralTaskForTesting = task
        return task
    }

    /// Execute and land one native batch Trash while retaining the caller's
    /// structural ownership. Both direct submission and the asynchronous
    /// confirmation probe use this helper so the all-empty transition never
    /// publishes a false idle state or duplicates the landing matrix.
    private func performBatchTrash(
        request: BatchTrashRequest,
        preferredFocusPath: String?,
        session: VaultSession,
        token: Int,
        runner: BatchTrashRunner,
        refresher: StructuralBatchRefreshRunner
    ) async {
        let outcome: Result<BatchTrashReport, Error>
        do {
            outcome = .success(try await runner(session, request))
        } catch {
            outcome = .failure(error)
        }
        guard ownsStructuralMutation(token, session: session) else { return }
        switch outcome {
        case .success(let report):
            // As with single-item Trash, invalidate the exact paths that core
            // says left the vault before any awaited refresh. The final tree,
            // result, and VoiceOver landing remains below the refresh.
            quarantineBatchTrashPathsBeforeRefresh(report)
            if Self.batchTrashNeedsRefresh(report) {
                await refresher(self)
                guard ownsStructuralMutation(token, session: session) else { return }
            }
            if !report.unknown.isEmpty {
                let probes = report.unknown.map {
                    BatchTrashPresenceProbe(
                        path: $0.item.path,
                        isDirectory: $0.item.isDirectory)
                }
                let vaultURL = currentVaultURL
                let presenceProbe = batchTrashPresenceProbeRunner
                let presence = await Task.detached(priority: .utility) {
                    probes.map { probe in
                        BatchTrashPresenceResult(
                            path: probe.path,
                            isDirectory: probe.isDirectory,
                            presence: vaultURL.map {
                                presenceProbe(
                                    $0.appendingPathComponent(probe.path),
                                    probe.isDirectory)
                            } ?? .indeterminate)
                    }
                }.value
                guard ownsStructuralMutation(token, session: session) else { return }
                reconcileBatchTrashUnknownPathsAfterRefresh(
                    presence,
                    session: session)
            }
            landBatchTrash(report, preferredFocusPath: preferredFocusPath)
        case .failure(let error):
            await refresher(self)
            guard ownsStructuralMutation(token, session: session) else { return }
            clearStructuralUndoStacks()
            publishTreeMutation(
                .batchReconcile,
                rewrittenCount: 0,
                requiresRescan: true,
                preferredFocusPath: preferredFocusPath)
            let message = error.localizedDescription
            setBatchStructuralResult(BatchStructuralResult(
                payload: .infrastructure(operation: .trash, message: message),
                requiresAttention: true))
            postMutationAnnouncement("Trash operation failed: \(message)")
        }
        endStructuralMutation(token)
    }

    private static func batchTrashNeedsRefresh(_ report: BatchTrashReport) -> Bool {
        if !report.unknown.isEmpty { return true }
        switch report.state {
        case .rejected, .noOp:
            return report.requiresRescan
        case .succeeded, .partial:
            return true
        case .failed:
            return report.requiresRescan || !report.trashed.isEmpty
        }
    }

    private func quarantineBatchTrashPathsBeforeRefresh(_ report: BatchTrashReport) {
        switch report.state {
        case .succeeded, .partial:
            invalidateTrashedBatchItems(report.trashed)
        case .failed where report.requiresRescan || !report.trashed.isEmpty:
            invalidateTrashedBatchItems(report.trashed)
        case .rejected, .noOp, .failed:
            break
        }
        quarantineUnknownBatchTrashItems(report.unknown.map(\.item))
    }

    /// Unknown is not a synonym for either moved or not moved. Keep open Swift
    /// documents and dirty Markdown bytes intact, but synchronously sever every
    /// native handle and install a component-safe write gate before refresh can
    /// suspend. Claiming each reservation without preparing it prevents tab
    /// activation from reopening the ambiguous path during that window.
    private func quarantineUnknownBatchTrashItems(_ items: [StructuralBatchItem]) {
        guard !items.isEmpty else { return }
        mergeBatchTrashUnknownItems(items)
        guard let session = currentSession else { return }
        quarantineUnknownBaseEmbedHandles(session: session)
        let index = Self.batchTrashPathIndex(items)
        var plans: [NativeDocumentRetargetPlan] = []

        for (path, document) in canvasDocuments
        where index.longestMatch(for: path) != nil {
            let reservation = document.beginBatchRetarget(to: path)
            _ = document.claimRetargetPreparation()
            plans.append(
                .canvas(
                    path: path,
                    generation: reservation.generation,
                    replacedHandle: reservation.replacedHandle,
                    prepare: false))
        }

        var reservedBases = Set<ObjectIdentifier>()
        for (key, document) in baseDocuments {
            guard let path = document.source.filePath,
                index.longestMatch(for: path) != nil,
                reservedBases.insert(ObjectIdentifier(document)).inserted
            else { continue }
            let source = BaseDocumentSource.file(path: path)
            let reservation = document.beginBatchRetarget(to: source)
            _ = document.claimRetargetPreparation()
            plans.append(
                .base(
                    owner: .registry(key: key),
                    source: source,
                    generation: reservation.generation,
                    replacedHandle: reservation.replacedHandle,
                    request: reservation.request,
                    prepare: false))
        }
        if let document = basesDockDocument,
            let path = document.source.filePath,
            index.longestMatch(for: path) != nil,
            reservedBases.insert(ObjectIdentifier(document)).inserted
        {
            let source = BaseDocumentSource.file(path: path)
            let reservation = document.beginBatchRetarget(
                to: source, thisPath: basesDock.thisPath)
            _ = document.claimRetargetPreparation()
            plans.append(
                .base(
                    owner: .basesDock,
                    source: source,
                    generation: reservation.generation,
                    replacedHandle: reservation.replacedHandle,
                    request: reservation.request,
                    prepare: false))
        }
        scheduleNativeDocumentRetargets(plans, session: session)
    }

    /// Re-enable only roots a post-refresh filesystem probe proves present;
    /// invalidate only roots whose absence is explicit. Permission failures and
    /// other ambiguous errors stay quarantined and preserve their live state.
    private func reconcileBatchTrashUnknownPathsAfterRefresh(
        _ results: [BatchTrashPresenceResult],
        session: VaultSession
    ) {
        let reportKeys = Set(results.map {
            Self.batchTrashUnknownKey(path: $0.path, isDirectory: $0.isDirectory)
        })
        var present: [StructuralBatchItem] = []
        var absent: [StructuralBatchItem] = []
        var indeterminate: [StructuralBatchItem] = []
        for result in results {
            let item = StructuralBatchItem(
                path: result.path, isDirectory: result.isDirectory)
            switch result.presence {
            case .present: present.append(item)
            case .absent: absent.append(item)
            case .indeterminate: indeterminate.append(item)
            }
        }

        let priorUnrelated = batchTrashUnknownItems.filter {
            !reportKeys.contains(
                Self.batchTrashUnknownKey(
                    path: $0.path, isDirectory: $0.isDirectory))
        }
        replaceBatchTrashUnknownItems(priorUnrelated + indeterminate)

        if !absent.isEmpty {
            invalidateTrashedBatchItems(absent)
            invalidateAbsentBaseEmbedHandles(absent, session: session)
        }
        resumePresentBatchTrashDocuments(present, session: session)
    }

    private func resumePresentBatchTrashDocuments(
        _ items: [StructuralBatchItem],
        session: VaultSession
    ) {
        guard !items.isEmpty else { return }
        let index = Self.batchTrashPathIndex(items)
        var plans: [NativeDocumentRetargetPlan] = []

        for (path, document) in canvasDocuments
        where index.longestMatch(for: path) != nil
            && !isBatchTrashPathQuarantined(path)
        {
            let reservation = document.beginBatchRetarget(to: path)
            let prepare =
                document.claimRetargetPreparation() == reservation.generation
            plans.append(
                .canvas(
                    path: path,
                    generation: reservation.generation,
                    replacedHandle: reservation.replacedHandle,
                    prepare: prepare))
        }

        var resumedBases = Set<ObjectIdentifier>()
        for (key, document) in baseDocuments {
            guard let path = document.source.filePath,
                index.longestMatch(for: path) != nil,
                !isBatchTrashPathQuarantined(path),
                resumedBases.insert(ObjectIdentifier(document)).inserted
            else { continue }
            let source = BaseDocumentSource.file(path: path)
            let reservation = document.beginBatchRetarget(to: source)
            let prepare =
                document.claimRetargetPreparation() == reservation.generation
            plans.append(
                .base(
                    owner: .registry(key: key),
                    source: source,
                    generation: reservation.generation,
                    replacedHandle: reservation.replacedHandle,
                    request: reservation.request,
                    prepare: prepare))
        }
        if let document = basesDockDocument,
            let path = document.source.filePath,
            index.longestMatch(for: path) != nil,
            !isBatchTrashPathQuarantined(path),
            resumedBases.insert(ObjectIdentifier(document)).inserted
        {
            let source = BaseDocumentSource.file(path: path)
            let reservation = document.beginBatchRetarget(
                to: source, thisPath: basesDock.thisPath)
            let prepare =
                document.claimRetargetPreparation() == reservation.generation
            plans.append(
                .base(
                    owner: .basesDock,
                    source: source,
                    generation: reservation.generation,
                    replacedHandle: reservation.replacedHandle,
                    request: reservation.request,
                    prepare: prepare))
        }
        resumePresentBaseEmbedHandles(items, session: session)
        scheduleNativeDocumentRetargets(plans, session: session)
    }

    func isBatchTrashPathQuarantined(_ path: String) -> Bool {
        if case .readOnly = batchTrashPathCapability(for: path) { return true }
        return false
    }

    private func mergeBatchTrashUnknownItems(_ items: [StructuralBatchItem]) {
        replaceBatchTrashUnknownItems(batchTrashUnknownItems + items)
    }

    private func replaceBatchTrashUnknownItems(_ items: [StructuralBatchItem]) {
        var seen = Set<String>()
        batchTrashUnknownItems = items.filter {
            seen.insert(
                Self.batchTrashUnknownKey(
                    path: $0.path, isDirectory: $0.isDirectory)).inserted
        }
        batchTrashUnknownPathIndex = batchTrashUnknownItems.isEmpty
            ? nil
            : Self.batchTrashPathIndex(batchTrashUnknownItems)
    }

    private static func batchTrashPathIndex(
        _ items: [StructuralBatchItem]
    ) -> VaultComponentPrefixIndex<StructuralBatchItem> {
        VaultComponentPrefixIndex(
            items.map {
                .init(
                    path: $0.path,
                    includesDescendants: $0.isDirectory,
                    value: $0)
            })
    }

    private static func batchTrashUnknownKey(
        path: String,
        isDirectory: Bool
    ) -> String {
        BaseExactIdentity.key(
            prefix: "batch-trash-unknown",
            components: [isDirectory ? "directory" : "file", path])
    }

    private nonisolated static func batchTrashPhysicalPresence(
        at url: URL,
        expectedIsDirectory: Bool
    ) -> BatchTrashPhysicalPresence {
        do {
            let values = try url.resourceValues(
                forKeys: [
                    .isDirectoryKey,
                    .isRegularFileKey,
                    .isSymbolicLinkKey,
                ])
            if values.isSymbolicLink == true { return .absent }
            if expectedIsDirectory {
                guard let isDirectory = values.isDirectory else {
                    return .indeterminate
                }
                return isDirectory ? .present : .absent
            }
            guard let isRegularFile = values.isRegularFile else {
                return .indeterminate
            }
            return isRegularFile ? .present : .absent
        } catch {
            let nsError = error as NSError
            if nsError.domain == NSCocoaErrorDomain,
                nsError.code == NSFileNoSuchFileError
                    || nsError.code == NSFileReadNoSuchFileError
            {
                return .absent
            }
            if nsError.domain == NSPOSIXErrorDomain, nsError.code == 2 {
                return .absent
            }
            return .indeterminate
        }
    }

    /// Re-run authoritative tree refresh and physical probes for every item
    /// that remains outcome-unknown. The quarantine is released only after
    /// both suspension points revalidate this exact vault/session owner.
    @discardableResult
    func retryBatchTrashUnknownReconciliation() -> Task<Void, Never>? {
        guard !batchTrashUnknownItems.isEmpty, let session = currentSession else {
            return nil
        }
        guard admitStructuralMutationRequest() else { return nil }
        let token = beginStructuralMutation()
        let items = batchTrashUnknownItems
        let refresher = structuralBatchRefreshRunner
        let presenceProbe = batchTrashPresenceProbeRunner
        let task = Task { @MainActor [weak self] in
            guard let self else { return }
            defer { self.endStructuralMutation(token) }

            await refresher(self)
            guard self.ownsStructuralMutation(token, session: session),
                let vaultURL = self.currentVaultURL
            else { return }

            let probes = items.map {
                BatchTrashPresenceProbe(path: $0.path, isDirectory: $0.isDirectory)
            }
            let results = await Task.detached(priority: .utility) {
                probes.map { probe in
                    BatchTrashPresenceResult(
                        path: probe.path,
                        isDirectory: probe.isDirectory,
                        presence: presenceProbe(
                            vaultURL.appendingPathComponent(probe.path),
                            probe.isDirectory))
                }
            }.value
            guard self.ownsStructuralMutation(token, session: session) else { return }

            self.reconcileBatchTrashUnknownPathsAfterRefresh(
                results,
                session: session)
            self.publishTreeMutation(
                .batchReconcile,
                rewrittenCount: 0,
                requiresRescan: !self.batchTrashUnknownItems.isEmpty)
            self.retireResolvedBatchTrashUnknownResult()
            self.postMutationAnnouncement(
                self.batchTrashRetryAnnouncement(for: results))
        }
        pendingStructuralTaskForTesting = task
        return task
    }

    private func batchTrashRetryAnnouncement(
        for results: [BatchTrashPresenceResult]
    ) -> String {
        let present = results.filter { $0.presence == .present }.count
        let absent = results.filter { $0.presence == .absent }.count
        let unresolved = results.count - present - absent
        if unresolved > 0 {
            let subject = unresolved == 1 ? "1 item" : "\(unresolved) items"
            let pronoun = unresolved == 1 ? "It remains" : "They remain"
            return "Slate still couldn’t verify whether \(subject) moved to Trash. "
                + "\(pronoun) read-only."
        }
        if absent == 0 {
            let subject = present == 1 ? "The item is" : "The items are"
            return "Checked again. \(subject) still in the vault and writable."
        }
        if present == 0 {
            let subject = absent == 1 ? "The item is" : "The items are"
            return "Checked again. \(subject) no longer in the vault."
        }
        return "Checked again. \(present) items are still in the vault and writable; "
            + "\(absent) are no longer in the vault."
    }

    private func retireResolvedBatchTrashUnknownResult() {
        guard batchTrashUnknownItems.isEmpty,
            let result = batchStructuralResult,
            case .trash(let report) = result.payload,
            !report.unknown.isEmpty
        else { return }
        batchStructuralResult = nil
        if case .result(let active)? = activeBatchAlertPresentation,
            active.id == result.id
        {
            activeBatchAlertPresentation = nil
            promoteDeferredBatchAlert()
        }
        if case .result(let deferred)? = deferredBatchAlertPresentation,
            deferred.id == result.id
        {
            deferredBatchAlertPresentation = nil
        }
    }

    private func landBatchTrash(
        _ report: BatchTrashReport,
        preferredFocusPath: String?
    ) {
        let attention: Bool
        switch report.state {
        case .rejected:
            attention = true
            if report.requiresRescan {
                publishTreeMutation(
                    .batchReconcile,
                    rewrittenCount: 0,
                    requiresRescan: true,
                    preferredFocusPath: preferredFocusPath)
            }
        case .noOp:
            attention = false
            if report.requiresRescan {
                publishTreeMutation(
                    .batchReconcile,
                    rewrittenCount: 0,
                    requiresRescan: true,
                    preferredFocusPath: preferredFocusPath)
            }
        case .succeeded:
            clearStructuralUndoStacks()
            if report.trashed.isEmpty {
                publishTreeMutation(
                    .batchReconcile,
                    rewrittenCount: 0,
                    requiresRescan: true,
                    preferredFocusPath: preferredFocusPath)
            } else {
                publishTreeMutation(
                    .batchTrash(trashed: report.trashed),
                    rewrittenCount: 0,
                    requiresRescan: report.requiresRescan,
                    preferredFocusPath: preferredFocusPath)
            }
            attention = !report.envelope.skipped.isEmpty
                || !report.envelope.preflightFailures.isEmpty
                || !report.bookkeepingFailures.isEmpty
                || report.requiresRescan
                || report.trashed.isEmpty
        case .partial:
            clearStructuralUndoStacks()
            publishTreeMutation(
                .batchTrash(trashed: report.trashed),
                rewrittenCount: 0,
                requiresRescan: report.requiresRescan,
                preferredFocusPath: preferredFocusPath)
            attention = true
        case .failed:
            attention = true
            if report.requiresRescan || !report.trashed.isEmpty {
                clearStructuralUndoStacks()
                if report.trashed.isEmpty {
                    publishTreeMutation(
                        .batchReconcile,
                        rewrittenCount: 0,
                        requiresRescan: true,
                        preferredFocusPath: preferredFocusPath)
                } else {
                    publishTreeMutation(
                        .batchTrash(trashed: report.trashed),
                        rewrittenCount: 0,
                        requiresRescan: true,
                        preferredFocusPath: preferredFocusPath)
                }
            }
        }
        setBatchStructuralResult(BatchStructuralResult(
            payload: .trash(report), requiresAttention: attention))
        postMutationAnnouncement(BatchTrashCopy.announcement(for: report))
    }

    /// Immediate child count of a vault folder via a shallow FileManager
    /// enumerate (hidden entries COUNT — a folder holding only `.env`
    /// must confirm; only Finder-noise `.DS_Store` is ignored — and
    /// Hidden entries count (only `.DS_Store` is ignored); an unreadable
    /// directory reads as NON-empty (fail-closed → the confirmation), so
    /// unknown never bypasses the prompt.
    private func shallowChildCount(ofFolder path: String) -> Int {
        guard let url = currentVaultURL?.appendingPathComponent(path) else { return 1 }
        // Hidden entries COUNT (Codex P1: a folder holding only `.env` or
        // `.git` must still confirm — those are exactly the deletions that
        // hurt); only the Finder-noise `.DS_Store` is ignored. Enumeration
        // failure fails CLOSED (treated as non-empty → confirmation), not
        // open — the alert is the safe side of "unknown".
        guard let contents = try? FileManager.default.contentsOfDirectory(
            at: url, includingPropertiesForKeys: nil)
        else { return 1 }
        return contents.filter { $0.lastPathComponent != ".DS_Store" }.count
    }

    /// Probe one folder for the batch confirmation threshold without allocating
    /// its complete child list. Hidden entries count; only Finder's `.DS_Store`
    /// noise is ignored. Every unknown/error path returns true so an unreadable
    /// folder can never bypass the destructive confirmation.
    nonisolated private static func batchDeleteFolderRequiresConfirmation(at url: URL) -> Bool {
        let fileManager = FileManager.default
        var isDirectory: ObjCBool = false
        guard fileManager.fileExists(atPath: url.path, isDirectory: &isDirectory),
            isDirectory.boolValue
        else { return true }

        var enumerationFailed = false
        guard
            let enumerator = fileManager.enumerator(
                at: url,
                includingPropertiesForKeys: nil,
                options: [.skipsSubdirectoryDescendants],
                errorHandler: { _, _ in
                    enumerationFailed = true
                    return false
                })
        else { return true }

        while let child = enumerator.nextObject() as? URL {
            if child.lastPathComponent != ".DS_Store" {
                return true
            }
        }
        return enumerationFailed
    }

    /// Send the file or folder at `path` to the system trash. Any open tab
    /// holding the file (or a descendant of the folder) flips to the missing-
    /// file error state (spec §U2-5). Refreshes the parent level + moves the
    /// selection to the next sibling / prev / parent (U2-6), and announces.
    ///
    /// `announce` (#852): mirrors `moveEntry` — a BATCH delete (`batchDelete`)
    /// passes `false` so the per-item "Moved <name> to Trash." doesn't chatter;
    /// the batch posts ONE summary after every item has been trashed.
    @discardableResult
    func deleteEntry(
        path: String, isDirectory: Bool, announce: Bool = true,
        onResult: ((Bool) -> Void)? = nil
    ) -> Task<Void, Never>? {
        guard admitStructuralMutationRequest(), let session = currentSession else { return nil }
        guard admitBatchTrashMutation(
            of: [StructuralBatchItem(path: path, isDirectory: isDirectory)])
        else { return nil }
        let token = beginStructuralMutation()
        let task = Task { [weak self] in
            let outcome: Result<Void, VaultError> = await Task.detached(
                priority: .userInitiated
            ) {
                do {
                    if isDirectory { try session.deleteFolder(path: path) }
                    else { try session.deleteFile(path: path) }
                    return .success(())
                } catch let e as VaultError { return .failure(e) }
                catch { return .failure(.Io(message: error.localizedDescription)) }
            }.value
            guard let self, self.currentSession === session else { return }
            switch outcome {
            case .success:
                // Moving an item to the system Trash is not undoable through
                // Slate. It is therefore a structural-history barrier: an
                // older inverse must not remain armed against paths the user
                // can now recreate with different content.
                self.clearStructuralUndoStacks()
                // Codex round 8: active-tab ownership is decided AT
                // COMPLETION, against the LIVE selection — the old
                // call-time `loadedFilePath` capture was stale in both
                // directions. Select-then-delete before the load
                // lands: captured false, the cleanup was skipped and
                // the doomed read published the deleted note.
                // Delete-then-switch-away: captured true, the
                // completion clobbered the NEW note's state with the
                // deleted-note error. Round 9: the compare is the
                // ACTIVE MARKDOWN TAB's own path — `selectedFilePath`
                // is a transient mirror during dirty navigation (it
                // briefly holds the requested destination while the
                // tab stays put and the rollback is async), so the
                // workspace tab identity is the durable truth.
                // Markdown-gated keeps the old semantics for
                // base/canvas actives (their documents are handled by
                // the invalidate loop below).
                let activeWasDeleted: Bool
                if case .markdown(let activePath) = self.workspace.activeTab?.item {
                    activeWasDeleted = Self.pathIsWithin(
                        activePath, path: path, isDirectory: isDirectory)
                } else {
                    activeWasDeleted = false
                }
                // Flip open tabs to the error state. The ACTIVE tab's document
                // lives in AppState's fields; parked tabs drop so re-activation
                // re-reads from disk and fails into `noteLoadError`.
                self.dropOpenTabsForDeletedPath(path, isDirectory: isDirectory, activeWasDeleted: activeWasDeleted)
                let parent = TreeMutation.parentPath(of: path) ?? ""
                self.publishTreeMutation(
                    .delete(path: path, parent: parent, wasDirectory: isDirectory),
                    rewrittenCount: 0)
                if announce {
                    self.postMutationAnnouncement(
                        "Moved \((path as NSString).lastPathComponent) to Trash.")
                }
                await self.loadFiles()
                onResult?(true)
            case .failure(let error):
                self.lastError = self.humanReadable(error)
                // #852 red-team: batch (`announce == false`) suppresses the
                // per-item VoiceOver failure; the batch announces one summary
                // and the alert (`lastError`) still surfaces the reason.
                if announce {
                    self.announceMutationFailure(
                        verb: "delete",
                        name: (path as NSString).lastPathComponent, error: error)
                }
                onResult?(false)
            }
            self.endStructuralMutation(token)
        }
        return task
    }

    /// Announce a failed mutation (spec §U2-6 failure form). "Could not <verb>
    /// <name>: <specific reason>." Routes through the same medium-priority seam
    /// as the success announcements.
    private func announceMutationFailure(verb: String, name: String, error: VaultError) {
        postMutationAnnouncement("Could not \(verb) \(name): \(humanReadable(error))")
    }

    /// Create a folder (auto-suffixed to avoid a collision) inside `parent`,
    /// then move `movePath` into it — the "New Folder…" row of the Move sheet.
    /// Chains the two mutations so the picker flow is atomic from the user's
    /// view. On a create failure the move is skipped and the error surfaces.
    @discardableResult
    func createFolderThenMove(
        newFolderName: String, in parent: String, movePath: String, isDirectory: Bool
    ) -> Task<Void, Never>? {
        guard let session = currentSession else { return nil }
        // Suffix the name against the known set so the create doesn't collide.
        let suffixed = uniqueName(
            base: newFolderName, ext: nil, siblingsIn: parent)
        let newFolderPath = Self.joinVaultPath(parent, suffixed)
        let movedPath = Self.joinVaultPath(
            newFolderPath,
            (movePath as NSString).lastPathComponent)
        guard admitStructuralRecoveryDestination(
                newFolderPath, includesDescendants: true) != nil,
            admitStructuralRecoveryRetargets([
                NoteRecoveryPathRetarget(
                    oldPath: movePath,
                    newPath: movedPath,
                    includesDescendants: isDirectory)
            ]) != nil,
            admitBatchTrashWrite(to: [parent, newFolderPath]),
            admitBatchTrashMutation(
                of: [
                    StructuralBatchItem(
                        path: movePath, isDirectory: isDirectory)
                ]),
            admitBatchTrashVaultWideWrite()
        else { return nil }
        // Admit the first structural edge synchronously. Returning an outer
        // Task before this check made a busy rejection look accepted to the
        // sheet, which dismissed even though no folder or move could run.
        var created = false
        guard let createTask = createFolder(
            name: suffixed, in: parent, onResult: { created = $0 })
        else { return nil }
        let task = Task { [weak self] in
            await createTask.value
            guard let self else { return }
            // Gate the dependent move SOLELY on the create's actual success
            // result + captured session, never folder existence.
            guard created, self.currentSession === session else { return }
            if let continuationGate = self.createFolderMoveContinuationGateForTesting {
                await continuationGate()
            }
            guard self.currentSession === session else { return }
            if let reason = self.structuralMutationDisabledReason {
                self.postMutationAnnouncement(
                    "\(reason) \((movePath as NSString).lastPathComponent) was not moved.")
                return
            }
            await self.moveEntry(path: movePath, isDirectory: isDirectory, to: newFolderPath)?.value
        }
        pendingStructuralTaskForTesting = task
        return task
    }

    /// #852: the batch analog of `createFolderThenMove` — create a fresh folder,
    /// then `batchMove` the whole selection into it (one summary announcement).
    /// The Move sheet's "New Folder…" row for a multi-selection.
    @discardableResult
    func createFolderThenBatchMove(
        newFolderName: String,
        in parent: String,
        items: [TreeSelection],
        preferredFocusPath: String? = nil
    ) -> Task<Void, Never>? {
        guard let session = currentSession else { return nil }
        let suffixed = uniqueName(base: newFolderName, ext: nil, siblingsIn: parent)
        let newFolderPath = Self.joinVaultPath(parent, suffixed)
        guard admitStructuralRecoveryDestination(
                newFolderPath, includesDescendants: true) != nil,
            admitStructuralRecoveryRetargets(
                Self.topLevelSelection(items).map { item in
                    NoteRecoveryPathRetarget(
                        oldPath: item.path,
                        newPath: Self.joinVaultPath(
                            newFolderPath,
                            (item.path as NSString).lastPathComponent),
                        includesDescendants: item.isDirectory)
                }) != nil,
            admitBatchTrashWrite(to: [parent, newFolderPath]),
            admitBatchTrashMutation(
                of: items.map {
                    StructuralBatchItem(
                        path: $0.path, isDirectory: $0.isDirectory)
                }),
            admitBatchTrashVaultWideWrite()
        else { return nil }
        // As above, the create itself is the synchronous admission boundary.
        // A busy caller receives nil before its sheet can clear.
        var created = false
        guard let createTask = createFolder(
            name: suffixed, in: parent, onResult: { created = $0 })
        else { return nil }
        let task = Task { [weak self] in
            await createTask.value
            guard let self else { return }
            // Gate the batch move on the create's actual success result + same
            // session, never folder existence.
            guard created, self.currentSession === session else { return }
            if let continuationGate = self.createFolderMoveContinuationGateForTesting {
                await continuationGate()
            }
            guard self.currentSession === session else { return }
            if let reason = self.structuralMutationDisabledReason {
                let subject = items.count == 1 ? "1 item was" : "\(items.count) items were"
                self.postMutationAnnouncement(
                    "\(reason) \(subject) not moved.")
                return
            }
            await self.batchMove(
                items,
                to: newFolderPath,
                preferredFocusPath: preferredFocusPath)?.value
        }
        pendingStructuralTaskForTesting = task
        return task
    }

    /// Generic non-colliding-name helper: `base`(+`.ext`), then `base N`(+ext).
    /// `siblingsIn` scopes the collision check to one parent level. Used by
    /// note/folder creation + the move-new-folder flow so the auto-naming rule
    /// is single-source.
    ///
    /// #852 (Codex finding 2): the sibling set is drawn from an AUTHORITATIVE
    /// on-disk directory listing (files AND folders, including EMPTY folders),
    /// not just `files` — which holds only openable DOCUMENTS. An existing empty
    /// "New Folder" is invisible to `files`, so the old heuristic would pick
    /// "New Folder" again and the create would FAIL with DestinationExists. The
    /// known-file set is unioned in as a fallback (a not-yet-flushed index / the
    /// no-vault path).
    private func uniqueName(base: String, ext: String?, siblingsIn parent: String) -> String {
        var siblings: Set<String> = []
        if let vault = currentVaultURL {
            let dir = parent.isEmpty ? vault : vault.appendingPathComponent(parent)
            if let entries = try? FileManager.default.contentsOfDirectory(
                at: dir, includingPropertiesForKeys: nil) {
                for entry in entries { siblings.insert(entry.lastPathComponent.lowercased()) }
            }
        }
        let prefix = parent.isEmpty ? "" : parent + "/"
        for file in files where file.path.hasPrefix(prefix) {
            let rest = String(file.path.dropFirst(prefix.count))
            if let slash = rest.firstIndex(of: "/") {
                siblings.insert(String(rest[rest.startIndex..<slash]).lowercased())
            } else {
                siblings.insert(rest.lowercased())
            }
        }
        func candidate(_ n: Int?) -> String {
            let stem = n.map { "\(base) \($0)" } ?? base
            return ext.map { "\(stem).\($0)" } ?? stem
        }
        if !siblings.contains(candidate(nil).lowercased()) { return candidate(nil) }
        var n = 2
        while siblings.contains(candidate(n).lowercased()) { n += 1 }
        return candidate(n)
    }

    // MARK: Retarget / error-flip helpers

    /// Run detached-handle cleanup first, then prepare at most two visible
    /// native documents concurrently. Batch result/history/announcement
    /// landing never awaits this task.
    func scheduleNativeDocumentRetargets(
        _ plans: [NativeDocumentRetargetPlan],
        session explicitSession: VaultSession? = nil
    ) {
        guard !plans.isEmpty,
            let originSession = explicitSession ?? currentSession
        else { return }
        let canvasObserver = canvasNewFileNativeExecutionObserverForTesting
        let canvasRunner = canvasNewFilePreloadRunner
        let baseObserver = baseRetargetNativeExecutionObserverForTesting
        let baseRunner = baseRetargetPreloadRunner
        let preparationLimiter = nativeDocumentPreparationLimiter

        let workTask = Task { @MainActor [weak self] in
            await Task.detached(priority: .userInitiated) {
                for plan in plans {
                    Self.closeReplacedNativeHandle(
                        for: plan,
                        session: originSession,
                        canvasObserver: canvasObserver,
                        baseObserver: baseObserver)
                }
            }.value

            let preparations = plans.filter(\.shouldPrepare)
            var offset = 0
            while offset < preparations.count {
                let end = min(offset + 2, preparations.count)
                let chunk = Array(preparations[offset..<end])
                let results = await withTaskGroup(
                    of: NativeDocumentRetargetResult?.self,
                    returning: [NativeDocumentRetargetResult].self
                ) { group in
                    for plan in chunk {
                        group.addTask {
                            await preparationLimiter.acquire()
                            let result = await Task.detached(priority: .userInitiated) {
                                Self.prepareNativeDocumentRetarget(
                                    plan,
                                    session: originSession,
                                    canvasRunner: canvasRunner,
                                    canvasObserver: canvasObserver,
                                    baseRunner: baseRunner,
                                    baseObserver: baseObserver)
                            }.value
                            await preparationLimiter.release()
                            return result
                        }
                    }
                    var prepared: [NativeDocumentRetargetResult] = []
                    for await result in group {
                        if let result { prepared.append(result) }
                    }
                    return prepared
                }

                guard let self else {
                    for result in results {
                        Self.releaseStaleNativeRetargetResult(
                            result,
                            session: originSession,
                            canvasObserver: canvasObserver,
                            baseObserver: baseObserver)
                    }
                    return
                }
                for result in results {
                    self.applyNativeDocumentRetargetResult(
                        result,
                        session: originSession,
                        canvasObserver: canvasObserver,
                        baseObserver: baseObserver)
                }
                offset = end
            }
        }
        let predecessor = nativeDocumentRetargetTask
        let aggregateTask = Task { @MainActor in
            await predecessor?.value
            await workTask.value
        }
        nativeDocumentRetargetTask = aggregateTask
    }

    private nonisolated static func closeReplacedNativeHandle(
        for plan: NativeDocumentRetargetPlan,
        session: VaultSession,
        canvasObserver: CanvasNewFileNativeExecutionObserver?,
        baseObserver: BaseRetargetNativeExecutionObserver?
    ) {
        switch plan {
        case .canvas(_, _, let replacedHandle, _):
            if let replacedHandle {
                CanvasPreparedLoader.closeReplaced(
                    handle: replacedHandle,
                    session: session,
                    observer: canvasObserver)
            }
        case .base(_, _, _, let replacedHandle, _, _):
            if let replacedHandle {
                BasePreparedLoader.closeReplaced(
                    handle: replacedHandle,
                    session: session,
                    observer: baseObserver)
            }
        }
    }

    private nonisolated static func prepareNativeDocumentRetarget(
        _ plan: NativeDocumentRetargetPlan,
        session: VaultSession,
        canvasRunner: CanvasNewFilePreloadRunner,
        canvasObserver: CanvasNewFileNativeExecutionObserver?,
        baseRunner: BaseRetargetPreloadRunner,
        baseObserver: BaseRetargetNativeExecutionObserver?
    ) -> NativeDocumentRetargetResult? {
        switch plan {
        case .canvas(let path, let generation, _, let prepare):
            guard prepare else { return nil }
            return .canvas(
                path: path,
                generation: generation,
                prepared: canvasRunner(session, path, canvasObserver))
        case .base(let owner, let source, let generation, _, let request, let prepare):
            guard prepare else { return nil }
            return .base(
                owner: owner,
                source: source,
                generation: generation,
                prepared: baseRunner(session, request, baseObserver))
        }
    }

    private func applyNativeDocumentRetargetResult(
        _ result: NativeDocumentRetargetResult,
        session: VaultSession,
        canvasObserver: CanvasNewFileNativeExecutionObserver?,
        baseObserver: BaseRetargetNativeExecutionObserver?
    ) {
        let applied: Bool
        switch result {
        case .canvas(let path, let generation, let prepared):
            applied = currentSession === session
                && canvasDocuments[path]?.applyRetargetPreparation(
                    prepared, generation: generation, path: path) == true
        case .base(let owner, let source, let generation, let prepared):
            let document: BaseDocument?
            switch owner {
            case .registry(let key):
                document = baseDocuments[key]
            case .basesDock:
                document = basesDockDocument
            }
            applied = currentSession === session
                && document?.applyRetargetPreparation(
                    prepared, generation: generation, source: source) == true
            if applied, owner == .basesDock, let document {
                basesDock.rebaseMembership(
                    BaseRowMembership(rows: document.result?.rows ?? []))
            }
        }
        guard !applied else { return }
        Task.detached(priority: .utility) {
            Self.releaseStaleNativeRetargetResult(
                result,
                session: session,
                canvasObserver: canvasObserver,
                baseObserver: baseObserver)
        }
    }

    private nonisolated static func releaseStaleNativeRetargetResult(
        _ result: NativeDocumentRetargetResult,
        session: VaultSession,
        canvasObserver: CanvasNewFileNativeExecutionObserver?,
        baseObserver: BaseRetargetNativeExecutionObserver?
    ) {
        switch result {
        case .canvas(_, _, let prepared):
            CanvasPreparedLoader.release(
                prepared, session: session, observer: canvasObserver)
        case .base(_, _, _, let prepared):
            BasePreparedLoader.release(
                prepared, session: session, observer: baseObserver)
        }
    }

    /// Apply only core's physically-standing batch paths. The prefix trie is
    /// built once, then every file-backed tab is visited once; folder suffixes
    /// follow the longest component-safe selected root.
    private func applyBatchMoveRetargets(_ standing: [BatchPathChange]) {
        guard !standing.isEmpty else { return }
        // Draft/recovery ownership must move before WorkspaceState publishes
        // retargeted tabs. Otherwise the mounted properties header observes a
        // new loaded path while its draft still claims the old path and parks
        // the only copy under an identity that can no longer be reached.
        rekeyNoteRecoveryPaths(
            standing.map {
                NoteRecoveryPathRetarget(
                    oldPath: $0.oldPath,
                    newPath: $0.newPath,
                    includesDescendants: $0.isDirectory)
            })
        let index = VaultComponentPrefixIndex<BatchPathChange>(
            standing.map {
                .init(
                    path: $0.oldPath,
                    includesDescendants: $0.isDirectory,
                    value: $0)
            })
        let activeID = workspace.model.activeGroup.activeTabID
        let changes = workspace.retargetFileBackedTabs { item in
            guard let match = index.longestMatch(for: item.path) else { return nil }
            let root = match.entry.value.newPath
            let newPath = match.relativeSuffix.isEmpty
                ? root
                : Self.joinVaultPath(root, match.relativeSuffix)
            switch item {
            case .markdown:
                return .markdown(path: newPath)
            case .canvas:
                return .canvas(path: newPath)
            case .base:
                return .base(path: newPath)
            case .savedQuery, .dashboard, .graph:
                return nil
            }
        }
        var nativeRetargetPlans: [NativeDocumentRetargetPlan] = []
        for change in changes {
            if case .base = change.oldItem {
                nativeRetargetPlans.append(
                    contentsOf: detachBaseDocumentsForRetarget(
                        [change.tabID], oldPath: change.oldPath, newPath: change.newPath))
            } else if case .canvas = change.oldItem {
                let prepare = workspace.model.groupsInOrder.contains { group in
                    guard case .canvas(let path)? = group.activeTab?.item else { return false }
                    return BaseExactIdentity.matches(path, change.newPath)
                }
                if let plan = detachCanvasDocumentForRetarget(
                    oldPath: change.oldPath,
                    newPath: change.newPath,
                    prepare: prepare)
                {
                    nativeRetargetPlans.append(plan)
                }
            }
        }
        // A docked Base can exist without an open tab. Retarget it through the
        // same index rather than requiring a synthetic tab change.
        if case .base(let dockPath, _) = basesDock.target,
            let match = index.longestMatch(for: dockPath)
        {
            let newPath = match.relativeSuffix.isEmpty
                ? match.entry.value.newPath
                : Self.joinVaultPath(match.entry.value.newPath, match.relativeSuffix)
            nativeRetargetPlans.append(
                contentsOf: detachBaseDocumentsForRetarget(
                    [], oldPath: dockPath, newPath: newPath))
        }
        scheduleNativeDocumentRetargets(nativeRetargetPlans)
        if let activeID,
            let activeChange = changes.first(where: { $0.tabID == activeID })
        {
            rebindActiveIfRetargeted([activeID], to: activeChange.newPath)
        }
    }

    /// Retarget open tabs after a rename/move: the moved node itself, and — for
    /// a folder — every open descendant path (they moved with the folder). Uses
    /// the report's `moved` list (authoritative: it's exactly the files whose
    /// path changed) so multi-file folder moves retarget precisely.
    private func applyRetargets(
        _ report: StructuralReport, movedFrom: String, movedTo: String, isDirectory: Bool
    ) {
        // A successful directory move/rename retargets the requested root,
        // including registry-only or missing descendants that cannot appear in
        // core's physical-file report. File operations retain the report's
        // exact mappings. Rekey the complete set before Workspace publishes.
        let recoveryRetargets: [NoteRecoveryPathRetarget]
        if isDirectory {
            recoveryRetargets = [
                NoteRecoveryPathRetarget(
                    oldPath: movedFrom,
                    newPath: movedTo,
                    includesDescendants: true)
            ]
        } else {
            recoveryRetargets = report.moved.map {
                NoteRecoveryPathRetarget(
                    oldPath: $0.oldPath,
                    newPath: $0.newPath,
                    includesDescendants: false)
            }
        }
        rekeyNoteRecoveryPaths(recoveryRetargets)
        if isDirectory {
            // Folder: retarget each moved file by its own old→new mapping.
            for m in report.moved {
                let changed = workspace.retarget(old: m.oldPath, new: m.newPath)
                rekeyBaseDocumentIfRetargeted(changed, oldPath: m.oldPath, newPath: m.newPath)
                rebindActiveIfRetargeted(changed, to: m.newPath)
            }
            // The report's `moved` only lists FILES; if the active buffer is a
            // file under the folder it's covered above. Nothing else to do —
            // folders don't have buffers.
        } else {
            let changed = workspace.retarget(old: movedFrom, new: movedTo)
            rekeyBaseDocumentIfRetargeted(changed, oldPath: movedFrom, newPath: movedTo)
            rebindActiveIfRetargeted(changed, to: movedTo)
        }
    }

    /// If the ACTIVE tab was among the retargeted set, rebind AppState's live
    /// fields to the new path (the active document lives here, not in
    /// `workspace.documents`, so `WorkspaceState.retarget` couldn't touch it).
    private func rebindActiveIfRetargeted(_ changed: [TabID], to newPath: String) {
        guard let activeID = workspace.model.activeGroup.activeTabID,
            changed.contains(activeID)
        else { return }
        // Codex round 3: the link-record OWNERSHIP marker follows the
        // rename with the live fields. `loadedFilePath` is updated
        // first, so the selection sink takes its same-file early
        // return and NO new link query restamps the marker — left
        // behind, every reading link classifies unresolved and
        // refuses activation until an unrelated reload.
        let ownershipLanded = BaseExactIdentity.matches(
            currentOutgoingLinksPath, selectedFilePath)
        if ownershipLanded {
            currentOutgoingLinksPath = newPath
        }
        if case .markdown = workspace.activeTab?.item {
            loadedFilePath = newPath
        } else {
            loadedFilePath = nil
        }
        let selectionMatches: Bool
        if case .base = workspace.activeTab?.item {
            selectionMatches = BaseExactIdentity.matches(selectedFilePath, newPath)
        } else {
            selectionMatches = BaseExactIdentity.matches(
                selectedFilePath, newPath)
        }
        if !selectionMatches {
            selectedFilePath = newPath
        }
        // Codex rounds 4+5: the fan-out legs race the rename
        // INDEPENDENTLY — the links marker landing says nothing about
        // math/tasks/code/diagrams/citations, and any leg that lands
        // late is dropped by its guard with its isLoading flag left
        // for a "newer task" that otherwise never comes. Re-fire the
        // whole fan-out for the new path unconditionally:
        // fireCollectionLoads cancels the previous legs, every loader
        // carries its own race guard, and a rename is rare enough
        // that the extra query burst is irrelevant. (The marker
        // retarget above still matters: it keeps reading
        // classification correct in the window before the refired
        // links leg lands.)
        if case .markdown = workspace.activeTab?.item {
            fireCollectionLoads(path: newPath)
        }
    }

    /// After a successful delete, flip open tabs pointing at the removed path
    /// to the missing-file error state. The active tab: clear its buffer + set
    /// `noteLoadError` (NoteContentView then renders its error pane). Parked
    /// tabs: drop their document so re-activation re-reads and fails into the
    /// same error state.
    private func dropOpenTabsForDeletedPath(
        _ path: String, isDirectory: Bool, activeWasDeleted: Bool
    ) {
        // Parked tabs whose path is within the deleted subtree.
        for tab in workspace.model.allTabs {
            let tabPath = tab.item.path
            guard Self.pathIsWithin(tabPath, path: path, isDirectory: isDirectory) else {
                continue
            }
            switch tab.item {
            case .markdown:
                preserveParkedMissingNoteRecovery(tabID: tab.id)
                _ = workspace.invalidateParkedDocuments(forPath: tabPath)
            case .canvas:
                invalidateCanvasDocument(path: tabPath)
            case .base:
                invalidateBaseDocument(path: tabPath)
            case .savedQuery:
                continue
            case .dashboard:
                continue
            case .graph:
                // Synthetic path; never within a deleted real subtree.
                continue
            }
        }
        if activeWasDeleted { flipActiveMarkdownToTrashError() }
    }

    /// One-pass batch invalidation driven only by the report's `trashed`
    /// vector. File-backed tabs remain open; parked/live documents become the
    /// existing missing-file state without touching any `untrashed` item.
    private func invalidateTrashedBatchItems(_ trashed: [StructuralBatchItem]) {
        guard !trashed.isEmpty else { return }
        let index = VaultComponentPrefixIndex<StructuralBatchItem>(
            trashed.map {
                .init(path: $0.path, includesDescendants: $0.isDirectory, value: $0)
            })
        let activeID = workspace.model.activeGroup.activeTabID
        var markdownTabs: [TabID] = []
        var canvasPaths: [String: String] = [:]
        var basePaths: [String: String] = [:]
        var activeMarkdownWasTrashed = false

        for tab in workspace.model.allTabs {
            guard index.longestMatch(for: tab.item.path) != nil else { continue }
            switch tab.item {
            case .markdown(let path):
                if tab.id == activeID {
                    activeMarkdownWasTrashed = true
                } else {
                    preserveParkedMissingNoteRecovery(tabID: tab.id)
                    markdownTabs.append(tab.id)
                }
                _ = path
            case .canvas(let path):
                canvasPaths[
                    BaseExactIdentity.registryKey(prefix: "canvas-trash", value: path)] = path
            case .base(let path):
                basePaths[
                    BaseExactIdentity.registryKey(prefix: "base-trash", value: path)] = path
            case .savedQuery, .dashboard, .graph:
                continue
            }
        }
        workspace.invalidateParkedDocuments(tabIDs: markdownTabs)
        for path in canvasPaths.values { invalidateCanvasDocument(path: path) }
        for path in basePaths.values { invalidateBaseDocument(path: path) }
        if activeMarkdownWasTrashed { flipActiveMarkdownToTrashError() }
    }

    private func preserveParkedMissingNoteRecovery(tabID: TabID) {
        guard let document = workspace.document(for: tabID) else { return }
        let hasPropertyDrafts = hasRecoverablePropertyDrafts(
            for: document.path,
            frontmatterSource: document.fmSource)
        guard document.hasUnsavedChanges || hasPropertyDrafts else { return }
        preserveMissingNoteRecovery(
            path: document.path,
            body: document.text,
            frontmatterSource: document.fmSource)
        // Property-only edits do not make the Markdown body dirty, but they
        // still own user input and must participate in tab/vault close gates.
        workspace.markDocumentMissing(tabID, retainAsDirty: true)
    }

    private func flipActiveMarkdownToTrashError() {
        // `loadedFilePath` may be nil when the doomed load never landed — fall
        // back to the selection used for live active-tab ownership.
        let deletedPath = loadedFilePath ?? selectedFilePath
        let deletedName = deletedPath
            .map { ($0 as NSString).lastPathComponent }
        cancelNoteScopedWork()
        isLoadingNote = false
        isLoadingLinks = false
        isLoadingEmbeds = false
        currentNoteHeadings = []
        propertiesSourceShowing = false
        propertiesSourceError = nil
        noteLoadError =
            "\(deletedName ?? "This note") was moved to Trash and is no longer available."

        guard let path = deletedPath,
            let body = currentNoteText,
            hasUnsavedChanges
                || hasRecoverablePropertyDrafts(
                    for: path,
                    frontmatterSource: currentNoteFMSource)
        else {
            currentNoteText = nil
            savedBaselineText = nil
            currentNoteContentHash = nil
            currentNoteFMSource = ""
            bodyByteOffset = 0
            bodyLineOffset = 0
            hasUnsavedChanges = false
            loadedFilePath = nil
            return
        }

        // A proven-absent file must not turn a dirty note into a clean empty
        // error. Snapshot first so a background tab activation can restore
        // the same draft, then mark that parked copy missing and retain the
        // live fields for the recovery surface.
        let baseline = savedBaselineText ?? ""
        savedBaselineText = baseline
        preserveMissingNoteRecovery(
            path: path,
            body: body,
            frontmatterSource: currentNoteFMSource)
        workspace.snapshotActiveTab(
            text: body,
            baseline: baseline,
            contentHash: currentNoteContentHash,
            hasUnsavedChanges: true,
            saveError: saveError,
            saveConflict: currentSaveConflict,
            loadedFilePath: path,
            fmSource: currentNoteFMSource,
            bodyByteOffset: bodyByteOffset,
            bodyLineOffset: bodyLineOffset)
        if let activeID = workspace.model.activeGroup.activeTabID {
            workspace.markDocumentMissing(activeID)
        }
        currentNoteContentHash = nil
        loadedFilePath = path
        hasUnsavedChanges = true
    }

    // MARK: Path helpers

    /// Join a parent path ("" = root) and a final component into a vault path.
    /// `nonisolated`: pure string work, used from the detached duplicate task.
    nonisolated static func joinVaultPath(_ parent: String, _ name: String) -> String {
        parent.isEmpty ? name : "\(parent)/\(name)"
    }

    /// The sibling path of `path` with its final component replaced by `newName`.
    static func siblingPath(of path: String, newName: String) -> String {
        let parent = TreeMutation.parentPath(of: path) ?? ""
        return joinVaultPath(parent, newName)
    }

    /// Whether `candidate` is `path` itself, or (when `path` is a folder) a
    /// descendant of it. Used to decide which open tabs a delete/rename affects.
    static func pathIsWithin(_ candidate: String, path: String, isDirectory: Bool) -> Bool {
        if candidate == path { return true }
        guard isDirectory else { return false }
        return candidate.hasPrefix(path + "/")
    }

    /// Build a non-colliding "Untitled.md" / "Untitled N.md" for a fresh note in
    /// `parent`, checking the known file set (case-insensitively). The backend
    /// re-checks; this just avoids the common repeat-⌘N collision.
    private func uniqueUntitledName(in parent: String) -> String {
        let existing = Set(
            files.map { ($0.path as NSString).lastPathComponent.lowercased() })
        if !existing.contains("untitled.md") { return "Untitled.md" }
        var n = 2
        while existing.contains("untitled \(n).md") { n += 1 }
        return "Untitled \(n).md"
    }

    /// Append U2-6's ", updated links in N notes." suffix to a mutation
    /// sentence when the report rewrote links; otherwise return the base.
    /// (U2-6 fills the announcement *routing*; the suffix logic is shared here
    /// so rename/move build one sentence.)
    private func mutationSentence(_ base: String, report: StructuralReport) -> String {
        Self.withLinksSuffix(base, rewrittenCount: Self.distinctRewrittenCount(report))
    }

    /// Pure: append ", updated links in N notes." to `base` when `rewrittenCount
    /// > 0` (spec §U2-6 verbatim suffix), else return `base` unchanged. Static so
    /// the exact phrasing is regression-locked without a live rewrite — which the
    /// current base branch never produces (U2-3 part 2, the rewriter's session
    /// integration, isn't wired here; `StructuralReport.rewritten` is always
    /// empty until it lands, so this suffix is dormant end-to-end).
    static func withLinksSuffix(_ base: String, rewrittenCount: Int) -> String {
        guard rewrittenCount > 0 else { return base }
        // "Renamed a.md to b.md" (drop trailing period) + suffix.
        let trimmed = base.hasSuffix(".") ? String(base.dropLast()) : base
        return "\(trimmed), updated links in \(rewrittenCount) "
            + "\(rewrittenCount == 1 ? "note" : "notes")."
    }

    // MARK: Command entry points (palette + menu → tree selection)

    /// ⌘N — create a new note in the selection's folder (or root) and open it
    /// for renaming. The command-surface funnel for `createNote(in:)`.
    func newNoteCommand() {
        guard isVaultOpen else { return }
        pendingStructuralTaskForTesting = requestCreateNote(in: creationParentPath)
    }

    /// Context-menu / palette "New Folder…". Opens an inline-named folder in the
    /// selection's parent. Uses a placeholder name the user then renames — the
    /// tree has no create-time field, so we create "Untitled Folder" and drop
    /// straight into rename, mirroring the new-note flow.
    func newFolderCommand() {
        guard isVaultOpen else { return }
        newFolderInContext(parent: creationParentPath)
    }

    /// Create a new folder in an EXPLICIT parent (the context-menu path, which
    /// targets the right-clicked folder rather than the current selection), then
    /// drop into inline rename of the new folder.
    @discardableResult
    func newFolderInContext(parent: String) -> Bool {
        guard let session = currentSession else { return false }
        guard admitStructuralMutationRequest() else { return false }
        let name = uniqueUntitledFolderName(in: parent)
        let path = Self.joinVaultPath(parent, name)
        guard
            let task = createFolder(
                name: name,
                in: parent,
                onResult: { [weak self] created in
                    guard created, let self else { return }
                    self.installRenameForCreatedEntry(
                        path: path, isDirectory: true, session: session)
                })
        else { return false }
        // Retain the admitted CREATE itself. Its explicit result callback owns
        // the dependent rename stage; no outer Task can make a busy reject or
        // failed create look accepted.
        pendingStructuralTaskForTesting = task
        return true
    }

    /// Dispatcher-facing New Folder admission. The existing contextual funnel
    /// remains the one implementation so placeholder naming, task retention,
    /// and exact-session rename staging cannot drift between surfaces.
    @discardableResult
    func requestCreateFolder(in parent: String) -> Bool {
        newFolderInContext(parent: parent)
    }

    /// ⌘⌥R — rename the selected node. Enters inline-rename mode (the tree row
    /// swaps to a field); the actual FFI call fires on commit via `renameEntry`.
    func renameSelectedCommand() {
        guard isVaultOpen, let node = treeSelectedNode else { return }
        requestRename(path: node.path, isDirectory: node.isDirectory)
    }

    /// ⌘⇧M — open the Move-to-folder sheet for the selected node.
    func moveSelectedCommand() {
        guard isVaultOpen, let node = treeSelectedNode else { return }
        requestPendingMove(path: node.path, isDirectory: node.isDirectory)
    }

    /// File ▸ Reveal in Finder / palette — jump to the selected node on
    /// disk. Context menus keep their own per-clicked-node variant; this
    /// one follows the tree SELECTION like every other file command
    /// (context-menus.md redundancy rule: every context action needs a
    /// primary-UI home).
    func revealSelectedInFinderCommand() {
        guard isVaultOpen, let node = treeSelectedNode,
            let url = currentVaultURL?.appendingPathComponent(node.path)
        else { return }
        NSWorkspace.shared.activateFileViewerSelecting([url])
    }

    /// ⌘⌫ (tree-focused) / context-menu "Move to Trash" — delete the selected
    /// node. Routes through `requestDeleteEntry` so a non-empty folder
    /// stages the #860 confirmation; files and empty folders delete
    /// immediately as before. No cached child count here (the selection
    /// mirror carries only path + kind) — the FileManager fallback counts.
    func deleteSelectedCommand() {
        guard isVaultOpen, let node = treeSelectedNode else { return }
        requestDeleteEntry(path: node.path, isDirectory: node.isDirectory)
    }

    /// File ▸ Duplicate / palette / context menu — duplicate the selected
    /// FILE next to itself (#853). Folder selections no-op (folders are out
    /// of #853's scope); the menu items are disabled for them, and the
    /// palette row falls through here harmlessly.
    func duplicateSelectedCommand() {
        guard isVaultOpen, let node = treeSelectedNode else { return }
        guard !node.isDirectory else {
            // The palette row can't gray out per-selection like the menu
            // items do — a silent no-op there reads as breakage, so the
            // folder case announces its scope (red-team).
            postAccessibilityAnnouncement(
                "Duplicate applies to files only.", priority: .medium)
            return
        }
        pendingStructuralTaskForTesting = requestDuplicateEntry(path: node.path)
    }

    /// Every folder path in the vault (vault-relative, sorted case-insensitive,
    /// dirs-first order from the API), for the Move-to-folder picker. Walks
    /// `list_dir_children` recursively off the main actor. The vault root is NOT
    /// included as a path here — the picker adds a "Vault root" row (path "")
    /// explicitly. Empty folders ARE included (they're real move targets).
    func loadAllFolders() async -> [String] {
        guard let session = currentSession else { return [] }
        return await Task.detached(priority: .userInitiated) {
            var out: [String] = []
            var queue: [String] = [""]
            // Bound the walk defensively against a pathological vault so the
            // picker can't hang; realistic vaults are far under this.
            var visited = 0
            let cap = 50_000
            while !queue.isEmpty, visited < cap {
                let parent = queue.removeFirst()
                visited += 1
                guard
                    let listing = try? session.listDirChildren(
                        parentPath: parent,
                        paging: Paging(cursor: nil, limit: 5000))
                else { continue }
                for dir in listing.dirs {
                    out.append(dir.path)
                    queue.append(dir.path)
                }
            }
            return out
        }.value
    }

    /// A non-colliding "Untitled Folder" / "Untitled Folder N" for `parent`.
    private func uniqueUntitledFolderName(in parent: String) -> String {
        // Folders aren't in `files`; derive existing sibling folder names from
        // the file set's path prefixes under `parent`.
        let prefix = parent.isEmpty ? "" : parent + "/"
        let siblingDirs: Set<String> = Set(
            files.compactMap { file -> String? in
                guard file.path.hasPrefix(prefix) else { return nil }
                let rest = String(file.path.dropFirst(prefix.count))
                guard let slash = rest.firstIndex(of: "/") else { return nil }
                return String(rest[rest.startIndex..<slash]).lowercased()
            })
        if !siblingDirs.contains("untitled folder") { return "Untitled Folder" }
        var n = 2
        while siblingDirs.contains("untitled folder \(n)") { n += 1 }
        return "Untitled Folder \(n)"
    }

    // MARK: - Property edits (Milestone I)

    @discardableResult
    func requestAddPropertySheet() -> Bool {
        guard let path = loadedFilePath else { return false }
        if let reason = noteAuthoringDisabledReason(for: path) {
            postMutationAnnouncement(reason)
            return false
        }
        addPropertySheetOwnerPath = path
        addPropertySheetOwner = noteAuthoringOwner(for: path)
        isAddPropertySheetOpen = true
        return true
    }

    func ensureAddPropertySheetOwner() {
        if addPropertySheetOwnerPath == nil {
            addPropertySheetOwnerPath = loadedFilePath
            addPropertySheetOwner = noteAuthoringOwner()
        }
    }

    func dismissAddPropertySheet() {
        isAddPropertySheetOpen = false
        addPropertySheetOwnerPath = nil
        addPropertySheetOwner = nil
    }

    static let missingNoteDraftReason =
        "This note is no longer available. Copy your draft before closing."

    var addPropertySheetDisabledReason: String? {
        guard let path = addPropertySheetOwnerPath,
            let owner = addPropertySheetOwner,
            ownsNoteAuthoring(owner),
            BaseExactIdentity.matches(owner.path, path)
        else {
            return Self.missingNoteDraftReason
        }
        if let reason = noteAuthoringDisabledReason(for: path) {
            return reason
        }
        guard BaseExactIdentity.matches(loadedFilePath, path),
            noteLoadError == nil
        else {
            return Self.missingNoteDraftReason
        }
        return nil
    }

    /// Insert or replace a frontmatter property on `path`. Routes
    /// through the same `save_text` pipeline as the editor save, so
    /// `WriteConflict` is detected the same way and the F-precedent
    /// conflict dialog is reused (scoped to the property edit via
    /// `currentPropertyEditConflict`).
    ///
    /// On success: refreshes `currentNoteProperties` +
    /// `currentNoteContentHash` so the panel reflects the new state
    /// and a subsequent edit doesn't carry a stale hash.
    @discardableResult
    func setProperty(
        path: String,
        key: String,
        value: PropertyValue,
        submittedDraft: PropertyEditDraft? = nil,
        owner: NoteAuthoringOwner? = nil
    ) -> Task<Void, Never>? {
        if let owner, !ownsNoteAuthoring(owner) { return nil }
        guard !isEditingProperty else { return nil }
        guard !isMutatingStructure else {
            postMutationAnnouncement(Self.structuralMutationBusyReason)
            return nil
        }
        guard let session = currentSession else { return nil }
        guard admitNoteAuthoring(for: path, owner: owner) else { return nil }
        guard admitBatchTrashWrite(to: [path]) else { return nil }
        let generation = beginPropertyEditOwnership(path: path)
        propertyEditError = nil
        let expected = currentNoteContentHash
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performPropertyEdit(
                session: session,
                path: path,
                key: key,
                action: .set(value),
                expectedHash: expected,
                generation: generation,
                submittedRowDraft: submittedDraft
            )
            return
        }
        propertyEditTask = task
        return task
    }

    /// U3-4 (#468): commit the show-source editor's YAML draft — the
    /// whole frontmatter block replaced through `set_frontmatter_source`
    /// (YAML validated Rust-side FIRST; malformed input writes nothing).
    /// Rides the property-edit machinery (`.setSource` action): same
    /// in-flight guard, same WriteConflict alert + resolutions, and the
    /// stage-A success refresh (fmSource + offsets + hash + rows).
    @discardableResult
    func applyPropertiesSource(
        _ draft: String,
        owner: NoteAuthoringOwner? = nil
    ) -> Task<Void, Never>? {
        if let owner, !ownsNoteAuthoring(owner) { return nil }
        guard !isEditingProperty else { return nil }
        guard !isMutatingStructure else {
            postMutationAnnouncement(Self.structuralMutationBusyReason)
            return nil
        }
        guard let session = currentSession, let path = loadedFilePath else { return nil }
        if let reason = propertiesSourceApplyDisabledReason(for: path) {
            postMutationAnnouncement(reason)
            return nil
        }
        guard admitBatchTrashWrite(to: [path]) else { return nil }
        let generation = beginPropertyEditOwnership(path: path)
        propertyEditError = nil
        propertiesSourceError = nil
        let expected = currentNoteContentHash
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performPropertyEdit(
                session: session,
                path: path,
                key: "",
                action: .setSource(draft),
                expectedHash: expected,
                generation: generation
            )
            return
        }
        propertyEditTask = task
        return task
    }

    /// ⌘⇧D / palette: ask the widget to flip fields ⇄ source. View state
    /// (draft, mode) lives in the widget; AppState can only signal — the
    /// U4-4 request-token pattern. No-ops without a renderable note.
    @Published private(set) var propertiesSourceToggleRequest: Int = 0

    func togglePropertiesSourceCommand() {
        guard loadedFilePath != nil, noteLoadError == nil else { return }
        propertiesSourceToggleRequest &+= 1
    }

    /// #868: published mirror of the properties widget's view-local
    /// source-mode `@State`. The DRAFT must stay in the view (#448:
    /// uncommitted user input never rides a `@Published`), but the
    /// View ▸ Show/Hide Properties Source title needs the direction —
    /// so the widget mirrors JUST the bool through
    /// `notePropertiesSourceModeChanged` from a post-update
    /// `.onChange(of: isSourceMode)` (plus an `.onAppear` resync for
    /// mount gaps). `clearActiveNoteFields` also resets it on note
    /// transitions: the widget self-hides without firing its onChange
    /// when the note vanishes (same belt as `propertiesSourceError`).
    @Published private(set) var propertiesSourceShowing = false
    /// Source-editor draft ownership survives quarantine-driven remounts. It
    /// is still uncommitted user input; publishing here is intentional so a
    /// missing-file transition cannot erase the only copy held by view-local
    /// state.
    @Published var propertiesSourceDraft = "" {
        didSet { publishPropertyRecoveryTransitionIfNeeded() }
    }
    @Published var propertiesSourceDraftPath: String? {
        didSet { publishPropertyRecoveryTransitionIfNeeded() }
    }

    /// Low-churn observation edge for row/source recovery ownership. The
    /// revision changes only when the set of dirty recovery paths changes,
    /// never for each character typed within an already-dirty note.
    @Published private(set) var propertyRecoveryRevision: UInt64 = 0
    private var propertyRecoveryPathFingerprint: Set<String> = []

    /// Guarded production setter for the properties-source editor binding.
    /// SwiftUI disables the editor as soon as a structural destination is
    /// reserved; this is the race-proof backstop for an already-queued AppKit
    /// text callback that arrives after that state change.
    func updatePropertiesSourceDraft(
        _ draft: String,
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        if let path = propertiesSourceDraftPath,
            let reason = propertyAuthoringDisabledReason(for: path)
        {
            let parkedBaseline = parkedPropertiesSourceDrafts[
                propertiesSourceDraftKey(path)]?.baseline
            let baseline = BaseExactIdentity.matches(path, loadedFilePath)
                ? currentNoteFMSource
                : parkedBaseline
            if !BaseExactIdentity.matches(baseline, draft) {
                postMutationAnnouncement(reason)
                return
            }
        }
        propertiesSourceDraft = draft
    }
    /// Source drafts park by exact path across tab switches. The mounted
    /// header still exposes one active Binding, while this registry prevents
    /// its cross-tab leak guard from erasing another tab's uncommitted YAML.
    private struct ParkedPropertiesSourceDraftRecord {
        let path: String
        let draft: String
        let baseline: String?

        var isDirty: Bool {
            baseline.map { !BaseExactIdentity.matches(draft, $0) } ?? true
        }
    }
    private var parkedPropertiesSourceDrafts:
        [String: ParkedPropertiesSourceDraftRecord] = [:] {
            didSet { publishPropertyRecoveryTransitionIfNeeded() }
        }

    private func propertiesSourceDraftKey(_ path: String) -> String {
        BaseExactIdentity.key(
            prefix: "note-properties-source-draft", components: [path])
    }

    func parkPropertiesSourceDraftForTransition(
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        guard let path = propertiesSourceDraftPath else { return }
        let existing = parkedPropertiesSourceDrafts[
            propertiesSourceDraftKey(path)]
        let baseline = BaseExactIdentity.matches(path, loadedFilePath)
            ? currentNoteFMSource
            : existing?.baseline
        let cacheKey = propertiesSourceDraftKey(path)
        if let baseline,
            BaseExactIdentity.matches(propertiesSourceDraft, baseline)
        {
            // Clean source-mode state is presentation state, not recovery.
            // Retaining it across a close/rewrite can turn old FM bytes into a
            // false draft that later undoes a property or bulk-rename write.
            parkedPropertiesSourceDrafts[cacheKey] = nil
            return
        }
        parkedPropertiesSourceDrafts[cacheKey] =
            ParkedPropertiesSourceDraftRecord(
                path: path,
                draft: propertiesSourceDraft,
                baseline: baseline)
    }

    /// Clear only the mounted Binding after parking; the exact-path recovery
    /// registry remains available to a later activation or absence proof.
    func clearMountedPropertiesSourceDraft(
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        propertiesSourceDraft = ""
        propertiesSourceDraftPath = nil
    }

    @discardableResult
    func restoreParkedPropertiesSourceDraft(
        for path: String,
        authoritativeFrontmatterSource: String? = nil,
        owner: NoteAuthoringOwner? = nil
    ) -> Bool {
        if let owner, !ownsNoteAuthoring(owner) { return false }
        guard let record = parkedPropertiesSourceDrafts[propertiesSourceDraftKey(path)]
        else { return false }
        propertiesSourceDraft = record.isDirty
            ? record.draft
            : (authoritativeFrontmatterSource ?? record.draft)
        propertiesSourceDraftPath = path
        // Transfer ownership to the mounted editor. Leaving a copy parked
        // would preserve stale V0 after the mounted draft advances to V1 and
        // can resurrect it on the next tab round-trip.
        parkedPropertiesSourceDrafts[propertiesSourceDraftKey(path)] = nil
        return true
    }

    func discardPropertiesSourceDraft(
        for path: String?,
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        guard let path else {
            clearMountedPropertiesSourceDraft()
            return
        }
        parkedPropertiesSourceDrafts[propertiesSourceDraftKey(path)] = nil
        if BaseExactIdentity.matches(propertiesSourceDraftPath, path) {
            clearMountedPropertiesSourceDraft()
        }
    }

    /// A completed source write may clear only the exact bytes it submitted.
    /// If a newer draft somehow arrived before publication, it remains
    /// recoverable and no fields-switch edge is emitted for it.
    @discardableResult
    private func clearPropertiesSourceDraftIfCommitted(
        path: String,
        submitted: String
    ) -> Bool {
        var cleared = false
        let cacheKey = propertiesSourceDraftKey(path)
        if let parked = parkedPropertiesSourceDrafts[cacheKey],
            BaseExactIdentity.matches(parked.draft, submitted)
        {
            parkedPropertiesSourceDrafts[cacheKey] = nil
            cleared = true
        }
        if BaseExactIdentity.matches(propertiesSourceDraftPath, path),
            BaseExactIdentity.matches(propertiesSourceDraft, submitted)
        {
            clearMountedPropertiesSourceDraft()
            cleared = true
        }
        return cleared
    }

    /// Property rows keep local SwiftUI state for low-churn editing, mirrored
    /// here only as a recovery cache so an absent reconciliation/unmount can
    /// restore the exact draft if the note returns.
    private struct PreservedPropertyDraftRecord {
        let path: String
        let key: String
        var draft: PropertyEditDraft
        let baseline: PropertyEditDraft?

        var isDirty: Bool {
            baseline.map { draft != $0 } ?? true
        }
    }
    private var preservedPropertyDrafts: [String: PreservedPropertyDraftRecord] = [:] {
        didSet { publishPropertyRecoveryTransitionIfNeeded() }
    }
    private struct PropertyPublicationUncertainty {
        let path: String
        let key: String
        /// Whole-file hash returned by the native write that succeeded. Retry
        /// may clear recovery only after reading this exact version.
        let expectedContentHash: String
        let action: PropertyEditAction?
        let submittedRowDraft: PropertyEditDraft?
    }
    private var propertyPublicationUncertainties:
        [String: PropertyPublicationUncertainty] = [:] {
            didSet { publishPropertyRecoveryTransitionIfNeeded() }
        }
    /// Observable, per-row reset epochs for an explicit identity-scoped
    /// Reload. A row listens independently of `Property` equality, because an
    /// external body/other-key edit can conflict while this key is unchanged.
    @Published private(set) var propertyDraftResetRevision: UInt64 = 0
    private var propertyDraftResetRequests: [String: UInt64] = [:]

    private func publishPropertyRecoveryTransitionIfNeeded() {
        let next = Set(
            recoverablePropertyDraftPaths().map {
                BaseExactIdentity.registryKey(
                    prefix: "property-recovery-observation", value: $0)
            })
        guard next != propertyRecoveryPathFingerprint else { return }
        propertyRecoveryPathFingerprint = next
        propertyRecoveryRevision &+= 1
    }

    /// Missing-note recovery is vault-scoped and intentionally survives the
    /// transition into the error UI. The dictionary is published so that a
    /// recovery payload captured during reconciliation remounts the error pane
    /// with selectable/copyable content immediately.
    @Published private var missingNoteRecoveryDrafts: [String: MissingNoteRecoveryDraft] = [:]

    private func propertyDraftKey(path: String, key: String) -> String {
        BaseExactIdentity.key(
            prefix: "note-property-draft",
            components: [path, key])
    }

    private func propertyPublicationUncertaintyKey(
        path: String, key: String
    ) -> String {
        BaseExactIdentity.key(
            prefix: "property-publication-uncertainty",
            components: [path, key])
    }

    private func hasPropertyPublicationUncertainty(for path: String) -> Bool {
        propertyPublicationUncertainties.values.contains {
            BaseExactIdentity.matches($0.path, path)
        }
    }

    func hasAuthoredPropertyPublicationRecovery(for path: String) -> Bool {
        propertyPublicationUncertainties.values.contains {
            BaseExactIdentity.matches($0.path, path) && $0.action != nil
        }
    }

    private func authoredPropertyPublicationRecoveries(
        for path: String? = nil
    ) -> [PropertyPublicationUncertainty] {
        propertyPublicationUncertainties.values
            .filter { record in
                record.action != nil
                    && (path.map {
                        BaseExactIdentity.matches(record.path, $0)
                    } ?? true)
            }
            .sorted { lhs, rhs in
                if BaseExactIdentity.matches(lhs.path, rhs.path) {
                    return BaseExactIdentity.lessThan(lhs.key, rhs.key)
                }
                return BaseExactIdentity.lessThan(lhs.path, rhs.path)
            }
    }

    private func activeAuthoredPropertyPublicationRecovery()
        -> PropertyPublicationUncertainty?
    {
        guard let path = loadedFilePath else { return nil }
        return authoredPropertyPublicationRecoveries(for: path).first
    }

    private func propertyPublicationUncertaintyReason(for path: String) -> String {
        hasAuthoredPropertyPublicationRecovery(for: path)
            ? Self.authoredPropertyPublicationUncertainReason
            : Self.bulkPropertyPublicationUncertainReason
    }

    var authoredPropertyPublicationRecoveryPaths: [String] {
        var paths: [String: String] = [:]
        for record in authoredPropertyPublicationRecoveries() {
            paths[BaseExactIdentity.registryKey(
                prefix: "authored-property-publication-recovery",
                value: record.path)] = record.path
        }
        return paths.values.sorted(by: BaseExactIdentity.lessThan)
    }

    var authoredPropertyPublicationRecoveryReason: String? {
        let paths = authoredPropertyPublicationRecoveryPaths
        guard !paths.isEmpty else { return nil }
        let names = paths.prefix(3).map {
            authoredPropertyRecoveryDisplayName(for: $0, among: paths)
        }
        let listed = names.joined(separator: ", ")
        let remainder = paths.count - names.count
        let subject = remainder > 0
            ? "\(listed), and \(remainder) more"
            : listed
        return "Resolve the saved property update awaiting verification in \(subject) before closing or switching vaults. Open the note to copy the retained update, reapply it, or use the current version."
    }

    private func announceInactivePropertyPublicationRecovery(for path: String) {
        guard !BaseExactIdentity.matches(loadedFilePath, path) else { return }
        let displayName = authoredPropertyRecoveryDisplayName(
            for: path,
            among: authoredPropertyPublicationRecoveryPaths)
        postAccessibilityAnnouncement(
            "The saved property update in \(displayName) could not be verified. Reopen the note to copy or resolve the retained update.",
            priority: .high)
    }

    private func authoredPropertyRecoveryDisplayName(
        for path: String,
        among paths: [String]
    ) -> String {
        let basename = filename(of: path)
        let duplicateCount = paths.lazy.filter {
            self.filename(of: $0) == basename
        }.count
        return duplicateCount > 1 ? path : basename
    }

    func propertyDraftIsCommittedPendingVerification(
        path: String,
        key: String,
        draft: PropertyEditDraft
    ) -> Bool {
        propertyPublicationUncertainties.values.contains { record in
            guard BaseExactIdentity.matches(record.path, path),
                BaseExactIdentity.matches(record.key, key),
                case .set? = record.action,
                let submitted = record.submittedRowDraft
            else { return false }
            return submitted == draft
        }
    }

    func propertyDraftRevertTarget(
        path: String,
        key: String,
        fallback: PropertyEditDraft
    ) -> PropertyEditDraft {
        propertyPublicationUncertainties.values.first { record in
            BaseExactIdentity.matches(record.path, path)
                && BaseExactIdentity.matches(record.key, key)
                && record.submittedRowDraft != nil
        }?.submittedRowDraft ?? fallback
    }

    func propertiesSourceDraftIsCommittedPendingVerification(
        path: String,
        draft: String
    ) -> Bool {
        propertyPublicationUncertainties.values.contains { record in
            guard BaseExactIdentity.matches(record.path, path),
                case .setSource(let submitted)? = record.action
            else { return false }
            return BaseExactIdentity.matches(submitted, draft)
        }
    }

    func propertyRowDraftDiscardDisabledReason(
        path: String,
        key: String,
        draft: PropertyEditDraft
    ) -> String? {
        if let reason = inFlightDraftDiscardDisabledReason { return reason }
        return propertyDraftIsCommittedPendingVerification(
            path: path, key: key, draft: draft)
            ? Self.propertyPublicationUncertainReason
            : nil
    }

    func propertiesSourceDraftDiscardDisabledReason(
        path: String,
        draft: String
    ) -> String? {
        if let reason = inFlightDraftDiscardDisabledReason { return reason }
        return propertiesSourceDraftIsCommittedPendingVerification(
            path: path, draft: draft)
            ? Self.propertyPublicationUncertainReason
            : nil
    }

    var activePropertyPublicationUncertaintyReason: String? {
        guard let path = loadedFilePath,
            hasPropertyPublicationUncertainty(for: path)
        else { return nil }
        return propertyPublicationUncertaintyReason(for: path)
    }

    var activePropertyPublicationRecoveryTitle: String? {
        guard let record = activeAuthoredPropertyPublicationRecovery(),
            let action = record.action
        else { return nil }
        switch action {
        case .set:
            return "Saved update awaiting verification: \(record.key)"
        case .delete:
            return "Saved deletion awaiting verification: \(record.key)"
        case .setSource:
            return "Saved properties source awaiting verification"
        }
    }

    var activePropertyPublicationRecoveryText: String? {
        guard let record = activeAuthoredPropertyPublicationRecovery() else {
            return nil
        }
        return propertyPublicationRecoveryText(for: record)
    }

    /// Full-source recovery replaces the complete current frontmatter block;
    /// the confirmation surface uses this to avoid making the per-key
    /// "other properties remain unchanged" promise for that action.
    var activePropertyPublicationRecoveryReplacesAllProperties: Bool {
        guard let action = activeAuthoredPropertyPublicationRecovery()?.action
        else { return false }
        if case .setSource = action { return true }
        return false
    }

    private func propertyPublicationRecoveryText(
        for record: PropertyPublicationUncertainty
    ) -> String? {
        guard let action = record.action else { return nil }
        switch action {
        case .set(let value):
            let valueText = record.submittedRowDraft?.recoveryText
                ?? Self.propertyValueRecoveryText(value)
            return "Property: \(record.key)\nAction: Set\nValue:\n\(valueText)"
        case .delete:
            return "Property: \(record.key)\nAction: Delete"
        case .setSource(let source):
            return "Action: Replace properties source\nSource:\n\(source)"
        }
    }

    private static func propertyValueRecoveryText(_ value: PropertyValue) -> String {
        switch value {
        case .text(let value), .date(let value), .datetime(let value):
            return value
        case .integer(let value):
            return String(value)
        case .float(let value):
            return String(value)
        case .boolean(let value):
            return value ? "true" : "false"
        case .wikilink(let target):
            return "[[\(target)]]"
        case .list(let items):
            return items.map(propertyValueRecoveryText).joined(separator: "\n")
        case .tagList(let tags):
            return tags.joined(separator: "\n")
        }
    }

    func copyActivePropertyPublicationRecovery() {
        guard let text = activePropertyPublicationRecoveryText else { return }
        NSPasteboard.general.clearContents()
        NSPasteboard.general.setString(text, forType: .string)
        postAccessibilityAnnouncement("Retained property update copied.")
    }

    private func clearPropertyPublicationUncertainty(
        path: String, key: String
    ) {
        propertyPublicationUncertainties[
            propertyPublicationUncertaintyKey(path: path, key: key)] = nil
    }

    private func authoredPropertyPublicationRecovery(
        path: String, key: String
    ) -> PropertyPublicationUncertainty? {
        let record = propertyPublicationUncertainties[
            propertyPublicationUncertaintyKey(path: path, key: key)]
        return record?.action == nil ? nil : record
    }

    /// Release only the submitted H1 copy after an explicit disk-wins choice.
    /// A distinct V2 typed before publication finished remains an ordinary
    /// uncommitted draft over the newly loaded disk baseline.
    private func acceptDiskVersion(
        for record: PropertyPublicationUncertainty
    ) {
        clearPropertyPublicationUncertainty(path: record.path, key: record.key)
        guard let action = record.action else { return }
        switch action {
        case .set:
            let latest = preservedPropertyDraft(
                path: record.path, key: record.key)
            if record.submittedRowDraft == nil
                || latest == nil
                || latest == record.submittedRowDraft
            {
                clearPreservedPropertyDraft(
                    path: record.path, key: record.key)
                requestPropertyDraftReset(path: record.path, key: record.key)
            }
        case .delete:
            clearPreservedPropertyDraft(path: record.path, key: record.key)
            requestPropertyDraftReset(path: record.path, key: record.key)
        case .setSource(let submitted):
            let latest: String?
            if BaseExactIdentity.matches(propertiesSourceDraftPath, record.path) {
                latest = propertiesSourceDraft
            } else {
                latest = parkedPropertiesSourceDrafts[
                    propertiesSourceDraftKey(record.path)]?.draft
            }
            if latest == nil || BaseExactIdentity.matches(latest, submitted) {
                discardPropertiesSourceDraft(for: record.path)
                propertiesSourceError = nil
                propertiesSourceCommitted &+= 1
                requestPropertiesSourceCommit(path: record.path)
            }
        }
    }

    /// Bulk rename carries no user-authored action to recover. Its verification
    /// marker may be dropped when the final tab owner closes because a future
    /// open performs a normal authoritative load. Authored actions are never
    /// eligible for this cleanup; they require an explicit recovery decision.
    private func clearCloseSafeBulkPropertyPublicationVerification(for path: String) {
        propertyPublicationUncertainties =
            propertyPublicationUncertainties.filter {
                !BaseExactIdentity.matches($0.value.path, path)
                    || $0.value.action != nil
            }
    }

    func preservePropertyDraft(
        _ draft: PropertyEditDraft,
        path: String,
        key: String,
        owner: NoteAuthoringOwner? = nil
    ) {
        preservePropertyDraft(
            draft, baseline: nil, path: path, key: key, owner: owner)
    }

    func preservePropertyDraft(
        _ draft: PropertyEditDraft,
        baseline: PropertyEditDraft?,
        path: String,
        key: String,
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        let cacheKey = propertyDraftKey(path: path, key: key)
        if let baseline, draft == baseline {
            preservedPropertyDrafts[cacheKey] = nil
            return
        }
        // Defensive backstop for a view callback already queued when a
        // structural destination became reserved. Normal UI authoring is
        // disabled through `noteAuthoringDisabledReason`; this guard ensures a
        // stale/programmatic callback cannot create a new colliding recovery
        // identity after admission and before native I/O.
        if let reason = propertyAuthoringDisabledReason(for: path) {
            postMutationAnnouncement(reason)
            return
        }
        preservedPropertyDrafts[cacheKey] =
            PreservedPropertyDraftRecord(
                path: path,
                key: key,
                draft: draft,
                baseline: baseline)
    }

    func preservedPropertyDraft(path: String, key: String) -> PropertyEditDraft? {
        preservedPropertyDrafts[propertyDraftKey(path: path, key: key)]?.draft
    }

    func clearPreservedPropertyDraft(
        path: String,
        key: String,
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        preservedPropertyDrafts[propertyDraftKey(path: path, key: key)] = nil
    }

    /// Resolve an inactive row's recovery cache after its exact submitted
    /// value commits. A later V2 remains dirty and must never be consumed by
    /// the V1 completion.
    @discardableResult
    private func clearPreservedPropertyDraftIfCommitted(
        path: String,
        key: String,
        submittedDraft: PropertyEditDraft
    ) -> Bool {
        let cacheKey = propertyDraftKey(path: path, key: key)
        guard let record = preservedPropertyDrafts[cacheKey],
            record.draft == submittedDraft
        else { return false }
        preservedPropertyDrafts[cacheKey] = nil
        return true
    }

    private func requestPropertyDraftReset(path: String, key: String) {
        propertyDraftResetRevision &+= 1
        propertyDraftResetRequests[propertyDraftKey(path: path, key: key)] =
            propertyDraftResetRevision
    }

    func propertyDraftResetRevision(path: String, key: String) -> UInt64 {
        propertyDraftResetRequests[propertyDraftKey(path: path, key: key)] ?? 0
    }

    private func missingNoteRecoveryKey(_ path: String) -> String {
        BaseExactIdentity.key(
            prefix: "missing-note-recovery", components: [path])
    }

    /// One authoritative physical path transform. `includesDescendants` is
    /// used by batch Move's standing directory roots; single rename/move
    /// reports provide exact per-file mappings and therefore pass `false`.
    private struct NoteRecoveryPathRetarget {
        let oldPath: String
        let newPath: String
        let includesDescendants: Bool
    }

    fileprivate struct NoteRecoveryPathScope {
        let path: String
        let includesDescendants: Bool
    }

    /// O(path-components) reservation lookup used by every property-authoring
    /// surface while a structural operation is in flight. The indices retain
    /// byte-exact component identity and folder-descendant semantics identical
    /// to the recovery collision census.
    struct StructuralRecoveryReservation {
        private let sourceIndex: VaultComponentPrefixIndex<Bool>
        private let destinationIndex: VaultComponentPrefixIndex<Bool>

        fileprivate init(
            sources: [NoteRecoveryPathScope],
            destinations: [NoteRecoveryPathScope]
        ) {
            sourceIndex = VaultComponentPrefixIndex(
                sources.map {
                    .init(
                        path: $0.path,
                        includesDescendants: $0.includesDescendants,
                        value: true)
                })
            destinationIndex = VaultComponentPrefixIndex(
                destinations.map {
                    .init(
                        path: $0.path,
                        includesDescendants: $0.includesDescendants,
                        value: true)
                })
        }

        fileprivate func blocksAuthoring(at path: String) -> Bool {
            destinationIndex.longestMatch(for: path) != nil
                && sourceIndex.longestMatch(for: path) == nil
        }
    }

    /// Every recovery or verification identity that must block a structural
    /// destination. This includes publication uncertainty even though those
    /// bytes already reached disk; structural writes stay fail-closed until
    /// the exact committed version is verified.
    private func recoverableNoteDraftPaths() -> [String] {
        var paths: [String: String] = [:]
        func include(_ path: String) {
            paths[BaseExactIdentity.registryKey(
                prefix: "recoverable-note-draft-path",
                value: path)] = path
        }
        for path in recoverablePropertyDraftPaths() { include(path) }
        if hasUnsavedChanges, let path = loadedFilePath { include(path) }
        for document in workspace.dirtyParkedDocuments() {
            include(document.path)
        }
        for recovery in missingNoteRecoveryDrafts.values { include(recovery.path) }
        return paths.values.sorted(by: BaseExactIdentity.lessThan)
    }

    /// Only user-authored bytes that closing could actually discard. A
    /// publication uncertainty is verification state for an already-committed
    /// write, so it must never create a Save/Discard close prompt.
    private func uncommittedNoteDraftPaths() -> [String] {
        var paths: [String: String] = [:]
        func include(_ path: String) {
            paths[BaseExactIdentity.registryKey(
                prefix: "uncommitted-note-draft-path",
                value: path)] = path
        }
        for path in uncommittedPropertyDraftPaths() { include(path) }
        for recovery in missingNoteRecoveryDrafts.values {
            include(recovery.path)
        }
        return paths.values.sorted(by: BaseExactIdentity.lessThan)
    }

    private func hasRecoveryDestinationCollision(
        sources: [NoteRecoveryPathScope],
        destinations: [NoteRecoveryPathScope],
        allowingExactRecoveryPaths: [String] = []
    ) -> Bool {
        guard !destinations.isEmpty else { return false }
        let allowedExactRecoveryKeys = Set(
            allowingExactRecoveryPaths.map {
                BaseExactIdentity.registryKey(
                    prefix: "allowed-structural-recovery-path",
                    value: $0)
            })
        let sourceIndex = VaultComponentPrefixIndex<Bool>(
            sources.map {
                .init(
                    path: $0.path,
                    includesDescendants: $0.includesDescendants,
                    value: true)
            })
        let destinationIndex = VaultComponentPrefixIndex<Bool>(
            destinations.map {
                .init(
                    path: $0.path,
                    includesDescendants: $0.includesDescendants,
                    value: true)
            })
        return recoverableNoteDraftPaths().contains { path in
            let exactKey = BaseExactIdentity.registryKey(
                prefix: "allowed-structural-recovery-path",
                value: path)
            return !allowedExactRecoveryKeys.contains(exactKey)
                && destinationIndex.longestMatch(for: path) != nil
                && sourceIndex.longestMatch(for: path) == nil
        }
    }

    /// Test-visible through the public authoring capability projection. A
    /// reservation is deliberately reported as the ordinary structural busy
    /// reason: the user can safely retry when the current operation finishes.
    private func structuralRecoveryReservationDisabledReason(
        for path: String
    ) -> String? {
        activeStructuralRecoveryReservation?.blocksAuthoring(at: path) == true
            ? Self.structuralMutationBusyReason
            : nil
    }

    /// Central pre-write admission for an exact create destination. Extension
    /// funnels (Canvas, Graph, History) use this same seam rather than
    /// reimplementing registry inspection.
    @discardableResult
    func admitStructuralRecoveryDestination(
        _ path: String,
        includesDescendants: Bool = false
    ) -> StructuralRecoveryReservation? {
        let sources: [NoteRecoveryPathScope] = []
        let destinations = [
            NoteRecoveryPathScope(
                path: path,
                includesDescendants: includesDescendants)
        ]
        let collision = hasRecoveryDestinationCollision(
            sources: [],
            destinations: destinations)
        guard !collision else {
            postMutationAnnouncement(Self.structuralRecoveryDestinationReason)
            return nil
        }
        return StructuralRecoveryReservation(
            sources: sources,
            destinations: destinations)
    }

    /// A missing-file Keep Mine recreates the path already owned by its dirty
    /// body. That exact byte identity is the recovery source, not a distinct
    /// destination draft, so it must not collide with itself. Canonically
    /// equivalent aliases and every other destination recovery remain blocked.
    /// The returned reservation marks that same exact path as the operation's
    /// source so the recovery save itself can pass the authoring gate. Save
    /// ownership still rejects concurrent edits, while aliases and unrelated
    /// destination drafts remain blocked.
    private func admitStructuralRecoveryRecreation(
        _ path: String
    ) -> StructuralRecoveryReservation? {
        let destinations = [
            NoteRecoveryPathScope(path: path, includesDescendants: false)
        ]
        let collision = hasRecoveryDestinationCollision(
            sources: [],
            destinations: destinations,
            allowingExactRecoveryPaths: [path])
        guard !collision else {
            postMutationAnnouncement(Self.structuralRecoveryDestinationReason)
            return nil
        }
        return StructuralRecoveryReservation(
            sources: [
                NoteRecoveryPathScope(path: path, includesDescendants: false)
            ],
            destinations: destinations)
    }

    /// Central pre-write admission for path transforms. Recovery already owned
    /// by a moving source is allowed and will be rekeyed transactionally;
    /// destination-only recovery is a separate user identity and blocks.
    @discardableResult
    private func admitStructuralRecoveryRetargets(
        _ retargets: [NoteRecoveryPathRetarget]
    ) -> StructuralRecoveryReservation? {
        let sources = retargets.map {
                NoteRecoveryPathScope(
                    path: $0.oldPath,
                    includesDescendants: $0.includesDescendants)
            }
        let destinations = retargets.map {
                NoteRecoveryPathScope(
                    path: $0.newPath,
                    includesDescendants: $0.includesDescendants)
            }
        let collision = hasRecoveryDestinationCollision(
            sources: sources,
            destinations: destinations)
        guard !collision else {
            postMutationAnnouncement(Self.structuralRecoveryDestinationReason)
            return nil
        }
        return StructuralRecoveryReservation(
            sources: sources,
            destinations: destinations)
    }

    /// Retarget every Markdown recovery owner as one two-phase transaction:
    /// snapshot from the old identities first, then clear/install. This keeps
    /// folder mappings component-safe and prevents a mapping whose destination
    /// is another mapping's source from cascading in dictionary iteration
    /// order. It runs before WorkspaceState publishes its corresponding tab
    /// changes, so a mounted source editor never observes split ownership.
    ///
    /// Destination-cache collisions are deliberately left untouched here.
    /// Those bytes may be user-authored recovery state despite the physical
    /// destination being free; until admission/surfacing policy resolves the
    /// two identities, preserving both old and destination entries is safer
    /// than silently deleting either one.
    private func rekeyNoteRecoveryPaths(
        _ retargets: [NoteRecoveryPathRetarget]
    ) {
        guard !retargets.isEmpty else { return }
        let sourceIndex = VaultComponentPrefixIndex<NoteRecoveryPathRetarget>(
            retargets.map {
                .init(
                    path: $0.oldPath,
                    includesDescendants: $0.includesDescendants,
                    value: $0)
            })
        let destinationIndex = VaultComponentPrefixIndex<NoteRecoveryPathRetarget>(
            retargets.map {
                .init(
                    path: $0.newPath,
                    includesDescendants: $0.includesDescendants,
                    value: $0)
            })

        func destination(for path: String) -> String? {
            guard let match = sourceIndex.longestMatch(for: path) else {
                return nil
            }
            return match.relativeSuffix.isEmpty
                ? match.entry.value.newPath
                : Self.joinVaultPath(
                    match.entry.value.newPath,
                    match.relativeSuffix)
        }

        func isDestinationOnly(_ path: String) -> Bool {
            destinationIndex.longestMatch(for: path) != nil
                && sourceIndex.longestMatch(for: path) == nil
        }

        // Every native structural funnel preflights this same recoverable set.
        // Keep a defensive fail-closed guard for future callers, but do not let
        // clean editor caches abort a post-success rekey: they are presentation
        // state, not a second user-authored identity, and the filter/install
        // transaction below may safely replace them.
        let hasDestinationCollision = recoverableNoteDraftPaths().contains(
            where: isDestinationOnly)
        guard !hasDestinationCollision else { return }

        let parkedSnapshots = parkedPropertiesSourceDrafts.values.compactMap {
            record -> (source: String, moved: ParkedPropertiesSourceDraftRecord)? in
            guard let newPath = destination(for: record.path) else { return nil }
            return (
                record.path,
                ParkedPropertiesSourceDraftRecord(
                    path: newPath,
                    draft: record.draft,
                    baseline: record.baseline))
        }.sorted { BaseExactIdentity.lessThan($0.source, $1.source) }

        let propertySnapshots = preservedPropertyDrafts.values.compactMap {
            record -> (source: String, moved: PreservedPropertyDraftRecord)? in
            guard let newPath = destination(for: record.path) else { return nil }
            return (
                record.path,
                PreservedPropertyDraftRecord(
                    path: newPath,
                    key: record.key,
                    draft: record.draft,
                    baseline: record.baseline))
        }.sorted {
            if BaseExactIdentity.matches($0.source, $1.source) {
                return BaseExactIdentity.lessThan($0.moved.key, $1.moved.key)
            }
            return BaseExactIdentity.lessThan($0.source, $1.source)
        }

        let recoverySnapshots = missingNoteRecoveryDrafts.values.compactMap {
            recovery -> (source: String, moved: MissingNoteRecoveryDraft)? in
            guard let newPath = destination(for: recovery.path) else { return nil }
            return (
                recovery.path,
                MissingNoteRecoveryDraft(
                    path: newPath,
                    body: recovery.body,
                    frontmatterSource: recovery.frontmatterSource,
                    propertiesSourceDraft: recovery.propertiesSourceDraft,
                    propertyDrafts: recovery.propertyDrafts,
                    retainedPropertyUpdates: recovery.retainedPropertyUpdates))
        }.sorted { BaseExactIdentity.lessThan($0.source, $1.source) }

        let uncertaintySnapshots = propertyPublicationUncertainties.values
            .compactMap {
                record
                    -> (source: String, moved: PropertyPublicationUncertainty)? in
                guard let newPath = destination(for: record.path) else {
                    return nil
                }
                return (
                    record.path,
                    PropertyPublicationUncertainty(
                        path: newPath,
                        key: record.key,
                        expectedContentHash: record.expectedContentHash,
                        action: record.action,
                        submittedRowDraft: record.submittedRowDraft))
            }
            .sorted {
                if BaseExactIdentity.matches($0.source, $1.source) {
                    return BaseExactIdentity.lessThan(
                        $0.moved.key, $1.moved.key)
                }
                return BaseExactIdentity.lessThan($0.source, $1.source)
            }

        let conflictSnapshot = currentPropertyEditConflict.flatMap { conflict in
            destination(for: conflict.path).map { newPath in
                PropertyEditConflict(
                    path: newPath,
                    key: conflict.key,
                    action: conflict.action,
                    currentContentHash: conflict.currentContentHash,
                    expectedContentHash: conflict.expectedContentHash,
                    currentMtimeMs: conflict.currentMtimeMs)
            }
        }

        let mountedSnapshot: (path: String, draft: String, baseline: String?)? =
            propertiesSourceDraftPath.flatMap { path in
                destination(for: path).map {
                    (
                        path: $0,
                        draft: propertiesSourceDraft,
                        baseline: BaseExactIdentity.matches(path, loadedFilePath)
                            ? currentNoteFMSource
                            : parkedPropertiesSourceDrafts[
                                propertiesSourceDraftKey(path)]?.baseline)
                }
            }

        parkedPropertiesSourceDrafts = parkedPropertiesSourceDrafts.filter {
            sourceIndex.longestMatch(for: $0.value.path) == nil
                && destinationIndex.longestMatch(for: $0.value.path) == nil
        }
        preservedPropertyDrafts = preservedPropertyDrafts.filter {
            sourceIndex.longestMatch(for: $0.value.path) == nil
                && destinationIndex.longestMatch(for: $0.value.path) == nil
        }
        missingNoteRecoveryDrafts = missingNoteRecoveryDrafts.filter {
            sourceIndex.longestMatch(for: $0.value.path) == nil
                && destinationIndex.longestMatch(for: $0.value.path) == nil
        }
        propertyPublicationUncertainties =
            propertyPublicationUncertainties.filter {
                sourceIndex.longestMatch(for: $0.value.path) == nil
                    && destinationIndex.longestMatch(for: $0.value.path) == nil
            }

        for snapshot in parkedSnapshots {
            parkedPropertiesSourceDrafts[
                propertiesSourceDraftKey(snapshot.moved.path)] = snapshot.moved
        }
        for snapshot in propertySnapshots {
            preservedPropertyDrafts[
                propertyDraftKey(
                    path: snapshot.moved.path,
                    key: snapshot.moved.key)] = snapshot.moved
        }
        for snapshot in recoverySnapshots {
            missingNoteRecoveryDrafts[
                missingNoteRecoveryKey(snapshot.moved.path)] = snapshot.moved
        }
        for snapshot in uncertaintySnapshots {
            propertyPublicationUncertainties[
                propertyPublicationUncertaintyKey(
                    path: snapshot.moved.path,
                    key: snapshot.moved.key)] = snapshot.moved
        }
        if let conflictSnapshot {
            currentPropertyEditConflict = conflictSnapshot
        }
        if let ownerPath = propertyEditOwnerPath,
            let movedOwnerPath = destination(for: ownerPath)
        {
            propertyEditOwnerPath = movedOwnerPath
        }
        if let mountedSnapshot {
            propertiesSourceDraftPath = mountedSnapshot.path
            propertiesSourceDraft = mountedSnapshot.draft
            // Ownership transfers to the mounted editor. Keeping an identical
            // parked copy would leave V0 behind after the mounted draft grows
            // to V1, letting V0 resurrect on the next tab round-trip. Every
            // unmount funnel parks the current mounted bytes synchronously.
            parkedPropertiesSourceDrafts[
                propertiesSourceDraftKey(mountedSnapshot.path)] = nil
        }
    }

    func missingNoteRecoveryDraft(for path: String) -> MissingNoteRecoveryDraft? {
        missingNoteRecoveryDrafts[missingNoteRecoveryKey(path)]
    }

    private func propertyRecoveryDrafts(for path: String)
        -> [MissingPropertyRecoveryDraft]
    {
        preservedPropertyDrafts.values
            .filter {
                BaseExactIdentity.matches($0.path, path) && $0.isDirty
            }
            .map {
                MissingPropertyRecoveryDraft(
                    key: $0.key,
                    value: Self.recoveryText(for: $0.draft))
            }
            .sorted { $0.key < $1.key }
    }

    private func propertyPublicationRecoveryDrafts(for path: String)
        -> [MissingPropertyRecoveryDraft]
    {
        authoredPropertyPublicationRecoveries(for: path).compactMap { record in
            guard let action = record.action,
                let value = propertyPublicationRecoveryText(for: record)
            else { return nil }
            let key: String
            if case .setSource = action {
                key = "properties source"
            } else {
                key = record.key
            }
            return MissingPropertyRecoveryDraft(key: key, value: value)
        }
    }

    private static func recoveryText(for draft: PropertyEditDraft) -> String {
        switch draft {
        case .scalarText(let kind): return kind.value
        case .integer(let value), .float(let value), .wikilink(let value):
            return value
        case .boolean(let value): return value ? "true" : "false"
        case .list(let values), .tagList(let values):
            return values.joined(separator: "\n")
        }
    }

    private func preserveMissingNoteRecovery(
        path: String, body: String, frontmatterSource: String
    ) {
        let sourceDraft = propertiesSourceRecoveryDraft(
            for: path,
            frontmatterSource: frontmatterSource)
        missingNoteRecoveryDrafts[missingNoteRecoveryKey(path)] =
            MissingNoteRecoveryDraft(
                path: path,
                body: body,
                frontmatterSource: frontmatterSource,
                propertiesSourceDraft: sourceDraft,
                propertyDrafts: propertyRecoveryDrafts(for: path),
                retainedPropertyUpdates:
                    propertyPublicationRecoveryDrafts(for: path))
    }

    func hasRecoverablePropertyDrafts(
        for path: String,
        frontmatterSource: String
    ) -> Bool {
        if propertiesSourceRecoveryDraft(
            for: path,
            frontmatterSource: frontmatterSource) != nil
        {
            return true
        }
        return preservedPropertyDrafts.values.contains {
            BaseExactIdentity.matches($0.path, path) && $0.isDirty
        }
    }

    /// Exact paths that still own user-authored properties-source or row
    /// drafts. Includes registry-only paths so tab/vault close cannot miss a
    /// draft merely because its tab was already closed or unmounted.
    func recoverablePropertyDraftPaths() -> [String] {
        propertyRecoveryPaths(includePublicationUncertainty: true)
    }

    /// Paths with actual user-authored bytes that a destructive close could
    /// discard. A publication uncertainty is deliberately excluded: native
    /// I/O already succeeded, so closing cannot and must not claim to undo it.
    private func uncommittedPropertyDraftPaths() -> [String] {
        propertyRecoveryPaths(includePublicationUncertainty: false)
    }

    private func propertyRecoveryPaths(
        includePublicationUncertainty: Bool
    ) -> [String] {
        var paths: [String: String] = [:]
        func include(_ path: String) {
            paths[BaseExactIdentity.registryKey(
                prefix: "recoverable-property-draft-path",
                value: path)] = path
        }
        for record in parkedPropertiesSourceDrafts.values where record.isDirty {
            if !includePublicationUncertainty,
                propertiesSourceDraftIsCommittedPendingVerification(
                    path: record.path, draft: record.draft)
            {
                continue
            }
            include(record.path)
        }
        for record in preservedPropertyDrafts.values where record.isDirty {
            if !includePublicationUncertainty,
                propertyDraftIsCommittedPendingVerification(
                    path: record.path, key: record.key, draft: record.draft)
            {
                continue
            }
            include(record.path)
        }
        if includePublicationUncertainty {
            for record in propertyPublicationUncertainties.values {
                include(record.path)
            }
        }
        if let conflict = currentPropertyEditConflict {
            include(conflict.path)
        }
        if let path = propertiesSourceDraftPath {
            let baseline: String?
            if BaseExactIdentity.matches(path, loadedFilePath) {
                baseline = currentNoteFMSource
            } else {
                baseline = parkedPropertiesSourceDrafts[
                    propertiesSourceDraftKey(path)]?.baseline
            }
            if baseline.map({
                !BaseExactIdentity.matches(propertiesSourceDraft, $0)
            }) ?? true,
                includePublicationUncertainty
                    || !propertiesSourceDraftIsCommittedPendingVerification(
                        path: path, draft: propertiesSourceDraft)
            {
                include(path)
            }
        }
        return paths.values.sorted(by: BaseExactIdentity.lessThan)
    }

    func hasRecoverablePropertyDrafts(for path: String) -> Bool {
        recoverablePropertyDraftPaths().contains {
            BaseExactIdentity.matches($0, path)
        }
    }

    private func hasDirtyNoteRecovery(for path: String) -> Bool {
        uncommittedPropertyDraftPaths().contains {
            BaseExactIdentity.matches($0, path)
        }
            || missingNoteRecoveryDraft(for: path) != nil
    }

    private func hasOtherMarkdownTab(for path: String, excluding id: TabID) -> Bool {
        workspace.model.allTabs.contains { tab in
            guard tab.id != id, case .markdown(let candidate) = tab.item else {
                return false
            }
            return BaseExactIdentity.matches(candidate, path)
        }
    }

    /// Non-Markdown current-tab routers (Canvas, Bases, saved queries, and
    /// dashboards) replace the active item directly instead of passing through
    /// `selectedFilePath`. Keep their shared admission at AppState so none can
    /// consume the final tab that owns an authored publication recovery.
    func admitCurrentTabReplacementForPropertyRecovery() -> Bool {
        if let reason = propertyEditNavigationDisabledReason {
            postMutationAnnouncement(reason)
            return false
        }
        guard let activeID = workspace.model.activeGroup.activeTabID,
            let tab = workspace.model.tab(activeID),
            case .markdown(let path) = tab.item,
            hasAuthoredPropertyPublicationRecovery(for: path),
            !hasOtherMarkdownTab(for: path, excluding: activeID)
        else { return true }
        postMutationAnnouncement(
            "Resolve the saved property update awaiting verification in \(filename(of: path)) before replacing its final tab. Copy the retained update, reapply it, or use the current version.")
        return false
    }

    /// Unique note identities at risk during vault close. Duplicate tabs do not
    /// inflate the count, and registry-only recovery remains visible even when
    /// its last tab has already unmounted.
    private func dirtyVaultClosePaths() -> [String] {
        var paths: [String: String] = [:]
        func include(_ path: String) {
            paths[BaseExactIdentity.registryKey(
                prefix: "dirty-vault-close-path",
                value: path)] = path
        }
        if hasUnsavedChanges, let path = loadedFilePath { include(path) }
        for document in workspace.dirtyParkedDocuments() { include(document.path) }
        for path in uncommittedPropertyDraftPaths() { include(path) }
        for recovery in missingNoteRecoveryDrafts.values {
            include(recovery.path)
        }
        return paths.values.sorted(by: BaseExactIdentity.lessThan)
    }

    /// Explicit destructive resolution for the close/discard workflows. The
    /// caller owns confirmation and announcements. A later V2 draft may be
    /// discarded here, but an authored update whose native write has not been
    /// verified remains retained as H1 until the user resolves that separate
    /// recovery state explicitly.
    func discardRecoverablePropertyDrafts(for path: String) {
        let retainedAuthored = authoredPropertyPublicationRecoveries(for: path)
        let priorRows = preservedPropertyDrafts
        preservedPropertyDrafts = preservedPropertyDrafts.filter {
            !BaseExactIdentity.matches($0.value.path, path)
        }
        if BaseExactIdentity.matches(currentPropertyEditConflict?.path, path) {
            currentPropertyEditConflict = nil
        }
        discardPropertiesSourceDraft(for: path)
        for record in retainedAuthored {
            guard let action = record.action else { continue }
            switch action {
            case .set:
                guard let submitted = record.submittedRowDraft else { continue }
                let cacheKey = propertyDraftKey(path: path, key: record.key)
                preservedPropertyDrafts[cacheKey] = PreservedPropertyDraftRecord(
                    path: path,
                    key: record.key,
                    draft: submitted,
                    baseline: priorRows[cacheKey]?.baseline)
            case .setSource(let submitted):
                if BaseExactIdentity.matches(loadedFilePath, path) {
                    propertiesSourceDraft = submitted
                    propertiesSourceDraftPath = path
                } else {
                    parkedPropertiesSourceDrafts[propertiesSourceDraftKey(path)] =
                        ParkedPropertiesSourceDraftRecord(
                            path: path,
                            draft: submitted,
                            baseline: nil)
                }
            case .delete:
                break
            }
        }
    }

    private func propertiesSourceRecoveryDraft(
        for path: String,
        frontmatterSource: String
    ) -> String? {
        let candidate: String?
        if BaseExactIdentity.matches(propertiesSourceDraftPath, path) {
            candidate = propertiesSourceDraft
        } else {
            candidate = parkedPropertiesSourceDrafts[
                propertiesSourceDraftKey(path)]?.draft
        }
        guard let candidate,
            !BaseExactIdentity.matches(candidate, frontmatterSource)
        else { return nil }
        return candidate
    }

    /// Copies every recoverable editing surface in one plain-text payload so
    /// users do not have to discover the body/source/row sections separately.
    func copyMissingNoteRecoveryDraft(for path: String) {
        guard let recovery = missingNoteRecoveryDraft(for: path) else { return }
        NSPasteboard.general.clearContents()
        NSPasteboard.general.setString(recovery.copyText, forType: .string)
        postMutationAnnouncement("Recovered drafts copied.")
    }

    /// Explicit destructive recovery action used by the error pane after its
    /// confirmation dialog. Normal reconciliation never calls this method.
    func discardMissingNoteRecoveryDraft(for path: String) {
        discardMissingNoteRecoveryDraft(path: path, announce: true)
    }

    private func discardMissingNoteRecoveryDraft(path: String, announce: Bool) {
        missingNoteRecoveryDrafts[missingNoteRecoveryKey(path)] = nil
        preservedPropertyDrafts = preservedPropertyDrafts.filter {
            !BaseExactIdentity.matches($0.value.path, path)
        }
        propertyPublicationUncertainties =
            propertyPublicationUncertainties.filter {
                !BaseExactIdentity.matches($0.value.path, path)
            }
        discardPropertiesSourceDraft(for: path)
        workspace.discardMissingDocuments(forPath: path)
        if BaseExactIdentity.matches(loadedFilePath, path), noteLoadError != nil {
            currentNoteText = nil
            savedBaselineText = nil
            currentNoteContentHash = nil
            currentNoteFMSource = ""
            bodyByteOffset = 0
            bodyLineOffset = 0
            loadedFilePath = nil
            hasUnsavedChanges = false
        }
        if announce {
            postMutationAnnouncement("Recovered drafts discarded.")
        }
    }

    /// The widget's single-writer seam for the mirror above — the view
    /// remains the owner of the real state; AppState only reflects it.
    /// The equality guard makes the `.onAppear` resync publish-free on
    /// the common (already-in-sync) mount path.
    func notePropertiesSourceModeChanged(
        _ showing: Bool,
        owner: NoteAuthoringOwner? = nil
    ) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        guard propertiesSourceShowing != showing else { return }
        propertiesSourceShowing = showing
    }

    /// Inline error for the show-source editor (U3-4): the Rust
    /// MalformedFrontmatter line/column message, or nil. Cleared on every
    /// apply attempt, on success, on source-mode exit (the widget's
    /// Cancel/Discard call `clearPropertiesSourceError`), and on note
    /// transitions (`clearActiveNoteFields`) — a stale message must never
    /// greet the next source session (Codoki #530). The draft is NEVER
    /// touched by the error path (non-destructive, DoD §F).
    @Published private(set) var propertiesSourceError: String?

    /// The widget's exit paths reset the inline error without widening
    /// the setter (state mutations stay funneled through AppState).
    func clearPropertiesSourceError(owner: NoteAuthoringOwner? = nil) {
        if let owner, !ownsNoteAuthoring(owner) { return }
        propertiesSourceError = nil
    }

    /// Bumped on every successful `.setSource` commit — the widget flips
    /// back to the fields view through the path-scoped edge below. Retained as
    /// a coarse diagnostic/test counter; UI must not consume it because a
    /// commit for an inactive note cannot dismiss the active note's draft.
    @Published private(set) var propertiesSourceCommitted: Int = 0
    @Published private(set) var propertiesSourceCommitRevision: UInt64 = 0
    private var propertiesSourceCommitRequests: [String: UInt64] = [:]

    private func requestPropertiesSourceCommit(path: String) {
        propertiesSourceCommitRevision &+= 1
        propertiesSourceCommitRequests[propertiesSourceDraftKey(path)] =
            propertiesSourceCommitRevision
    }

    func propertiesSourceCommitRevision(for path: String) -> UInt64 {
        propertiesSourceCommitRequests[propertiesSourceDraftKey(path)] ?? 0
    }

    /// Remove a frontmatter property. Symmetric to `setProperty`:
    /// same conflict path, same refresh on success.
    @discardableResult
    func deleteProperty(
        path: String,
        key: String,
        owner: NoteAuthoringOwner? = nil
    ) -> Task<Void, Never>? {
        if let owner, !ownsNoteAuthoring(owner) { return nil }
        guard !isEditingProperty else { return nil }
        guard !isMutatingStructure else {
            postMutationAnnouncement(Self.structuralMutationBusyReason)
            return nil
        }
        guard let session = currentSession else { return nil }
        guard admitNoteAuthoring(for: path, owner: owner) else { return nil }
        if preservedPropertyDrafts[propertyDraftKey(path: path, key: key)]?.isDirty == true {
            postMutationAnnouncement(Self.propertyDraftDeleteReason)
            return nil
        }
        guard admitBatchTrashWrite(to: [path]) else { return nil }
        let generation = beginPropertyEditOwnership(path: path)
        propertyEditError = nil
        let expected = currentNoteContentHash
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performPropertyEdit(
                session: session,
                path: path,
                key: key,
                action: .delete,
                expectedHash: expected,
                generation: generation
            )
            return
        }
        propertyEditTask = task
        return task
    }

    /// Shared body for `setProperty` / `deleteProperty`. Detaches
    /// the SQLite-mutex-holding FFI call off the main actor, then
    /// routes the outcome to one of three paths (success / conflict
    /// / error) on the main actor.
    private func rejectQueuedPropertyEdit(
        generation: UInt64,
        session: VaultSession,
        path: String,
        reason: String?,
        rejectedConflict: PropertyEditConflict?
    ) {
        guard ownsPropertyEdit(generation, session: session) else { return }
        if let reason { postMutationAnnouncement(reason) }
        if let rejectedConflict,
            currentPropertyEditConflict == nil,
            BaseExactIdentity.matches(loadedFilePath, path)
        {
            currentPropertyEditConflict = rejectedConflict
        }
        finishPropertyEditOwnership(generation)
    }

    private func queuedPropertyEditDisabledReason(
        path: String,
        action: PropertyEditAction,
        ignoringPropertyPublicationUncertainty: Bool
    ) -> String? {
        if isSaving { return Self.saveInProgressReason }
        if let reason = noteAuthoringDisabledReason(
            for: path,
            ignoringStructuralRecoveryReservationToken: nil,
            ignoringPropertyPublicationUncertainty:
                ignoringPropertyPublicationUncertainty)
        {
            return reason
        }
        if case .setSource = action,
            hasDirtyPreservedPropertyDrafts(for: path)
        {
            return Self.propertyRowsSourceApplyReason
        }
        return nil
    }

    private func performPropertyEdit(
        session: VaultSession,
        path: String,
        key: String,
        action: PropertyEditAction,
        expectedHash: String?,
        generation: UInt64,
        rejectedConflict: PropertyEditConflict? = nil,
        submittedRowDraft: PropertyEditDraft? = nil,
        isPublicationRecovery: Bool = false
    ) async {
        guard ownsPropertyEdit(generation, session: session) else { return }
        guard !Task.isCancelled else {
            finishPropertyEditOwnership(generation)
            return
        }
        if let reason = queuedPropertyEditDisabledReason(
            path: path,
            action: action,
            ignoringPropertyPublicationUncertainty: isPublicationRecovery)
        {
            rejectQueuedPropertyEdit(
                generation: generation,
                session: session,
                path: path,
                reason: reason,
                rejectedConflict: rejectedConflict)
            return
        }
        guard admitBatchTrashWrite(to: [path]) else {
            rejectQueuedPropertyEdit(
                generation: generation,
                session: session,
                path: path,
                reason: nil,
                rejectedConflict: rejectedConflict)
            return
        }
        let outcome: Result<SaveReport, VaultError> = await Task.detached(priority: .userInitiated) {
            do {
                switch action {
                case .set(let value):
                    let report = try session.setProperty(
                        path: path,
                        key: key,
                        value: value,
                        expectedContentHash: expectedHash
                    )
                    return .success(report)
                case .delete:
                    let report = try session.deleteProperty(
                        path: path,
                        key: key,
                        expectedContentHash: expectedHash
                    )
                    return .success(report)
                case .setSource(let fmSource):
                    // Validates YAML first (MalformedFrontmatter, nothing
                    // written), then read-current-body + compose + save —
                    // all Rust-side (set_frontmatter_source, #469).
                    let report = try session.setFrontmatterSource(
                        path: path,
                        fmSource: fmSource,
                        expectedContentHash: expectedHash
                    )
                    return .success(report)
                }
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }.value

        if case .success = outcome,
            ownsPropertyEdit(generation, session: session),
            !Task.isCancelled
        {
            propertyEditNativeWriteSucceededGeneration = generation
        }

        if let gate = basesPostWritePublishGate { await gate() }

        // If the user navigated away mid-edit, drop the result
        // rather than mutating state for a file the user has
        // already moved on from. Same shape as `performSave`.
        guard ownsPropertyEdit(generation, session: session) else { return }
        guard !Task.isCancelled else {
            finishPropertyEditOwnership(generation)
            return
        }
        if case .success = outcome {
            // The native property write is already indexed. Refresh global
            // Bases consumers before guarding active-note-only publication.
            _ = await refreshVisibleBasesAfterInAppWrite(
                session: session,
                changedPath: path)?.value
            guard ownsPropertyEdit(generation, session: session) else { return }
            guard !Task.isCancelled else {
                finishPropertyEditOwnership(generation)
                return
            }
        }
        switch outcome {
        case .success(let report):
            // U3-3 (#469 handoff): the edit rewrote the file's frontmatter —
            // publish fmSource + offsets + hash atomically from ONE read. The
            // read must still describe this exact native write and its body
            // must equal every open document's saved baseline; otherwise keep
            // the old expected hash so a later body save fails closed.
            let refresh = await refreshNoteParts(
                session: session,
                path: path,
                expectedContentHash: report.newContentHash)
            guard ownsPropertyEdit(generation, session: session) else { return }
            switch refresh {
            case .published:
                break
            case .changedAgain(let currentContentHash):
                propertyPublicationUncertainties[
                    propertyPublicationUncertaintyKey(path: path, key: key)] =
                    PropertyPublicationUncertainty(
                        path: path, key: key,
                        expectedContentHash: report.newContentHash,
                        action: action,
                        submittedRowDraft: submittedRowDraft)
                announceInactivePropertyPublicationRecovery(for: path)
                if BaseExactIdentity.matches(loadedFilePath, path) {
                    currentPropertyEditConflict = PropertyEditConflict(
                        path: path,
                        key: key,
                        action: action,
                        currentContentHash: currentContentHash,
                        expectedContentHash: report.newContentHash,
                        currentMtimeMs: 0)
                    propertyEditError =
                        "The property update was saved, but the note changed again before Slate could verify it. Choose Keep Mine or Reload from Disk."
                    postAccessibilityAnnouncement(
                        propertyEditError ?? "The note changed again.",
                        priority: .high)
                }
                finishPropertyEditOwnership(generation)
                return
            case .stale:
                return
            case .propertiesOnly:
                // This outcome is reserved for explicit conflict Reload.
                let reason = "Slate could not safely publish the property update."
                propertyPublicationUncertainties[
                    propertyPublicationUncertaintyKey(path: path, key: key)] =
                    PropertyPublicationUncertainty(
                        path: path, key: key,
                        expectedContentHash: report.newContentHash,
                        action: action,
                        submittedRowDraft: submittedRowDraft)
                announceInactivePropertyPublicationRecovery(for: path)
                propertyEditError =
                    "The property was saved, but Slate could not safely reload it. Choose Reload Properties to try again. \(reason)"
                finishPropertyEditOwnership(generation)
                return
            case .failed(let reason):
                propertyPublicationUncertainties[
                    propertyPublicationUncertaintyKey(path: path, key: key)] =
                    PropertyPublicationUncertainty(
                        path: path, key: key,
                        expectedContentHash: report.newContentHash,
                        action: action,
                        submittedRowDraft: submittedRowDraft)
                announceInactivePropertyPublicationRecovery(for: path)
                if BaseExactIdentity.matches(loadedFilePath, path) {
                    propertyEditError =
                        "The property was saved, but Slate could not safely reload it. Choose Reload Properties to try again. \(reason)"
                    postAccessibilityAnnouncement(
                        propertyEditError ?? reason,
                        priority: .high)
                }
                finishPropertyEditOwnership(generation)
                return
            }
            clearPropertyPublicationUncertainty(path: path, key: key)
            if BaseExactIdentity.matches(loadedFilePath, path) {
                // Frontmatter can contain link-valued properties, so refresh
                // the active note's link collections after the authoritative
                // property publication. The index belongs to this same report.
                await loadCurrentLinks(path: path, publishProperties: false)
                guard ownsPropertyEdit(generation, session: session) else { return }
            }

            switch action {
            case .set:
                if let submittedRowDraft {
                    let cleared = clearPreservedPropertyDraftIfCommitted(
                        path: path, key: key,
                        submittedDraft: submittedRowDraft)
                    if cleared {
                        requestPropertyDraftReset(path: path, key: key)
                    }
                }
            case .delete:
                clearPreservedPropertyDraft(path: path, key: key)
            case .setSource(let submitted):
                propertiesSourceError = nil
                propertiesSourceCommitted &+= 1
                if clearPropertiesSourceDraftIfCommitted(
                    path: path, submitted: submitted)
                {
                    requestPropertiesSourceCommit(path: path)
                }
            }

            if BaseExactIdentity.matches(loadedFilePath, path) {
                if case .setSource = action {
                    postAccessibilityAnnouncement(
                        "Properties updated.", priority: .medium)
                } else {
                    postAccessibilityAnnouncement(
                        "Property \(key) \(action == .delete ? "deleted" : "updated").",
                        priority: .medium
                    )
                }
            }
        case .failure(.WriteConflict(let currentHash, let expected, let currentMtimeMs)):
            guard BaseExactIdentity.matches(loadedFilePath, path) else {
                finishPropertyEditOwnership(generation)
                return
            }
            currentPropertyEditConflict = PropertyEditConflict(
                path: path,
                key: key,
                action: action,
                currentContentHash: currentHash,
                expectedContentHash: expected,
                currentMtimeMs: currentMtimeMs
            )
            postAccessibilityAnnouncement(
                "Property edit blocked. \(filename(of: path)) was modified externally. Resolve in the dialog.",
                priority: .medium
            )
        case .failure(let error):
            guard BaseExactIdentity.matches(loadedFilePath, path) else {
                finishPropertyEditOwnership(generation)
                return
            }
            if case .setSource = action,
                case .MalformedFrontmatter(_, let reason) = error
            {
                // U3-4: inline, specific, non-destructive — the draft stays
                // in the editor, focus stays put, nothing was written.
                propertiesSourceError = reason
                postAccessibilityAnnouncement(
                    "Properties source not applied: \(reason)",
                    priority: .high
                )
            } else {
                propertyEditError = humanReadable(error)
                postAccessibilityAnnouncement(
                    "Property edit failed: \(propertyEditError ?? "")",
                    priority: .high
                )
            }
        }
        finishPropertyEditOwnership(generation)
    }

    /// Re-issue the property edit with the new on-disk hash as
    /// `expectedHash` — the user explicitly chose to overwrite the
    /// external change.
    var propertyEditConflictKeepMineDisabledReason: String? {
        guard let conflict = currentPropertyEditConflict else { return nil }
        if isMutatingStructure { return Self.structuralMutationBusyReason }
        if hasAuthoredPropertyPublicationRecovery(for: conflict.path) {
            if isSaving { return Self.saveInProgressReason }
            if let reason = noteAuthoringDisabledReason(
                for: conflict.path,
                ignoringStructuralRecoveryReservationToken: nil,
                ignoringPropertyPublicationUncertainty: true)
            {
                return reason
            }
            if case .setSource = conflict.action,
                hasDirtyPreservedPropertyDrafts(for: conflict.path)
            {
                return Self.propertyRowsSourceApplyReason
            }
            return nil
        }
        if case .setSource = conflict.action {
            return propertiesSourceApplyDisabledReason(for: conflict.path)
        }
        return propertyAuthoringDisabledReason(for: conflict.path)
    }

    @discardableResult
    func resolvePropertyEditConflictKeepMine() -> Task<Void, Never>? {
        guard let conflict = currentPropertyEditConflict,
            let session = currentSession,
            BaseExactIdentity.matches(loadedFilePath, conflict.path)
        else {
            currentPropertyEditConflict = nil
            return nil
        }
        guard !isEditingProperty else { return nil }
        guard !isMutatingStructure else {
            postMutationAnnouncement(Self.structuralMutationBusyReason)
            return nil
        }
        if let reason = propertyEditConflictKeepMineDisabledReason {
            postMutationAnnouncement(reason)
            return nil
        }
        guard admitBatchTrashWrite(to: [conflict.path]) else { return nil }
        let retryConflict = propertyConflictUsingLatestDraft(conflict)
        let submittedRowDraft: PropertyEditDraft?
        if case .set = retryConflict.action {
            submittedRowDraft = preservedPropertyDraft(
                path: retryConflict.path, key: retryConflict.key)
        } else {
            submittedRowDraft = nil
        }
        currentPropertyEditConflict = nil
        let generation = beginPropertyEditOwnership(path: retryConflict.path)
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performPropertyEdit(
                session: session,
                path: retryConflict.path,
                key: retryConflict.key,
                action: retryConflict.action,
                expectedHash: retryConflict.currentContentHash,
                generation: generation,
                rejectedConflict: retryConflict,
                submittedRowDraft: submittedRowDraft,
                isPublicationRecovery: true
            )
            return
        }
        propertyEditTask = task
        return task
    }

    private func propertyConflictUsingLatestDraft(
        _ conflict: PropertyEditConflict
    ) -> PropertyEditConflict {
        let action: PropertyEditAction
        switch conflict.action {
        case .set:
            if let draft = preservedPropertyDraft(
                path: conflict.path, key: conflict.key),
                case .success(let value) = draft.toPropertyValue()
            {
                action = .set(value)
            } else {
                action = conflict.action
            }
        case .delete:
            action = .delete
        case .setSource(let submitted):
            let latest: String?
            if BaseExactIdentity.matches(propertiesSourceDraftPath, conflict.path) {
                latest = propertiesSourceDraft
            } else {
                latest = parkedPropertiesSourceDrafts[
                    propertiesSourceDraftKey(conflict.path)]?.draft
            }
            action = .setSource(latest ?? submitted)
        }
        return PropertyEditConflict(
            path: conflict.path,
            key: conflict.key,
            action: action,
            currentContentHash: conflict.currentContentHash,
            expectedContentHash: conflict.expectedContentHash,
            currentMtimeMs: conflict.currentMtimeMs)
    }

    /// Drop the property edit attempt and reload the file from
    /// disk. The user explicitly chose to let the external write
    /// win for this property.
    @discardableResult
    func resolvePropertyEditConflictReloadFromDisk() -> Task<Void, Never>? {
        guard let conflict = currentPropertyEditConflict,
            let session = currentSession,
            BaseExactIdentity.matches(loadedFilePath, conflict.path)
        else { return nil }
        guard !isEditingProperty else { return nil }
        let publicationRecovery = authoredPropertyPublicationRecovery(
            path: conflict.path, key: conflict.key)
        let generation = beginPropertyEditOwnership(path: conflict.path)
        currentPropertyEditConflict = nil
        // Reload only the property-owned file state. A property conflict must
        // never replace the independent Markdown body buffer/baseline or clear
        // its dirty flag.
        let task: Task<Void, Never> = Task { [weak self] in
            guard let self else { return }
            let refresh = await self.refreshNoteParts(
                session: session,
                path: conflict.path,
                allowPropertiesOnlyOnBodyMismatch: true)
            guard self.ownsPropertyEdit(generation, session: session),
                !Task.isCancelled,
                BaseExactIdentity.matches(self.loadedFilePath, conflict.path)
            else { return }
            switch refresh {
            case .published, .propertiesOnly:
                await self.loadCurrentLinks(
                    path: conflict.path, publishProperties: false)
                guard self.ownsPropertyEdit(generation, session: session),
                    !Task.isCancelled,
                    BaseExactIdentity.matches(
                        self.loadedFilePath, conflict.path)
                else { return }
                if let publicationRecovery {
                    self.acceptDiskVersion(for: publicationRecovery)
                } else {
                    self.clearPropertyPublicationUncertainty(
                        path: conflict.path, key: conflict.key)
                    switch conflict.action {
                    case .setSource:
                        self.discardPropertiesSourceDraft(for: conflict.path)
                        self.propertiesSourceError = nil
                        self.propertiesSourceCommitted &+= 1
                        self.requestPropertiesSourceCommit(path: conflict.path)
                    case .set, .delete:
                        self.requestPropertyDraftReset(
                            path: conflict.path, key: conflict.key)
                        self.clearPreservedPropertyDraft(
                            path: conflict.path, key: conflict.key)
                    }
                }
                if case .propertiesOnly = refresh {
                    postAccessibilityAnnouncement(
                        "Properties reloaded. The note body also changed externally; saving it will require conflict resolution.",
                        priority: .high)
                }
            case .changedAgain:
                self.currentPropertyEditConflict = conflict
                self.propertyEditError =
                    "The note changed again while Slate was reloading its properties."
                postAccessibilityAnnouncement(
                    self.propertyEditError ?? "The note changed again.",
                    priority: .high)
            case .failed(let reason):
                self.currentPropertyEditConflict = conflict
                self.propertyEditError = reason
                postAccessibilityAnnouncement(
                    "Properties could not be reloaded: \(reason)", priority: .high)
            case .stale:
                break
            }
            self.finishPropertyEditOwnership(generation)
            return
        }
        propertyEditTask = task
        return task
    }

    /// Retry the authoritative NoteParts publication after native property or
    /// bulk-rename I/O succeeded but the post-write read could not be safely
    /// adopted. The visible Properties header keeps this non-destructive retry
    /// available even after an error alert is dismissed.
    @discardableResult
    func retryActivePropertyPublication() -> Task<Void, Never>? {
        guard !isEditingProperty,
            let session = currentSession,
            let path = loadedFilePath,
            let record = propertyPublicationUncertainties.values.first(where: {
                BaseExactIdentity.matches($0.path, path)
            })
        else { return nil }
        let generation = beginPropertyEditOwnership(path: path)
        propertyEditError = nil
        let task: Task<Void, Never> = Task { [weak self] in
            guard let self else { return }
            let refresh = await self.refreshNoteParts(
                session: session,
                path: path,
                // Authored single-property recovery retains an action whose
                // H1 identity must still be verified before offering conflict
                // resolution. Bulk rename retains no replayable action: Retry
                // therefore means "adopt the current saved properties" and
                // must not wedge an unrelated dirty body behind a stale H1.
                expectedContentHash:
                    record.action == nil ? nil : record.expectedContentHash,
                allowPropertiesOnlyOnBodyMismatch: true)
            guard self.ownsPropertyEdit(generation, session: session),
                !Task.isCancelled,
                BaseExactIdentity.matches(self.loadedFilePath, path)
            else { return }
            switch refresh {
            case .published, .propertiesOnly:
                await self.loadCurrentLinks(
                    path: path, publishProperties: false)
                guard self.ownsPropertyEdit(generation, session: session),
                    !Task.isCancelled,
                    BaseExactIdentity.matches(self.loadedFilePath, path)
                else { return }
                self.clearPropertyPublicationUncertainty(
                    path: path, key: record.key)
                if let action = record.action {
                    switch action {
                    case .set:
                        if let submitted = record.submittedRowDraft,
                            self.clearPreservedPropertyDraftIfCommitted(
                                path: path,
                                key: record.key,
                                submittedDraft: submitted)
                        {
                            self.requestPropertyDraftReset(
                                path: path, key: record.key)
                        }
                    case .delete:
                        self.clearPreservedPropertyDraft(
                            path: path, key: record.key)
                    case .setSource(let submitted):
                        self.propertiesSourceError = nil
                        self.propertiesSourceCommitted &+= 1
                        if self.clearPropertiesSourceDraftIfCommitted(
                            path: path, submitted: submitted)
                        {
                            self.requestPropertiesSourceCommit(path: path)
                        }
                    }
                }
                postAccessibilityAnnouncement(
                    "Properties reloaded.", priority: .medium)
            case .changedAgain(let currentContentHash):
                if let action = record.action {
                    self.currentPropertyEditConflict = PropertyEditConflict(
                        path: path,
                        key: record.key,
                        action: action,
                        currentContentHash: currentContentHash,
                        expectedContentHash: record.expectedContentHash,
                        currentMtimeMs: 0)
                    self.propertyEditError =
                        "The note changed again after the property update. Choose Keep Mine or Reload from Disk."
                } else {
                    self.propertyEditError =
                        "The note changed again after the bulk rename. Reload the note to use its current properties."
                }
                postAccessibilityAnnouncement(
                    self.propertyEditError ?? "The note changed again.",
                    priority: .high)
            case .failed(let reason):
                self.propertyEditError =
                    "Slate still could not reload the saved property update. \(reason)"
                postAccessibilityAnnouncement(
                    self.propertyEditError ?? reason, priority: .high)
            case .stale:
                break
            }
            self.finishPropertyEditOwnership(generation)
        }
        propertyEditTask = task
        return task
    }

    /// Reapply the exact retained authored action to the newest readable disk
    /// version. The read supplies a fresh compare-and-swap hash; if the file
    /// changes again before native I/O, the ordinary conflict alert preserves
    /// both versions instead of overwriting blindly.
    @discardableResult
    func reapplyActivePropertyPublication() -> Task<Void, Never>? {
        guard !isEditingProperty,
            let session = currentSession,
            let record = activeAuthoredPropertyPublicationRecovery(),
            let action = record.action,
            BaseExactIdentity.matches(loadedFilePath, record.path)
        else { return nil }
        let generation = beginPropertyEditOwnership(path: record.path)
        currentPropertyEditConflict = nil
        propertyEditError = nil
        let task: Task<Void, Never> = Task { [weak self] in
            guard let self else { return }
            let outcome: Result<NotePartsBundle, VaultError> = await Task.detached(
                priority: .userInitiated
            ) {
                do {
                    return .success(try session.readNoteParts(path: record.path))
                } catch let error as VaultError {
                    return .failure(error)
                } catch {
                    return .failure(.Io(message: error.localizedDescription))
                }
            }.value
            guard self.ownsPropertyEdit(generation, session: session),
                !Task.isCancelled,
                BaseExactIdentity.matches(self.loadedFilePath, record.path)
            else { return }
            switch outcome {
            case .success(let parts):
                await self.performPropertyEdit(
                    session: session,
                    path: record.path,
                    key: record.key,
                    action: action,
                    expectedHash: parts.contentHash,
                    generation: generation,
                    submittedRowDraft: record.submittedRowDraft,
                    isPublicationRecovery: true)
            case .failure(let error):
                self.propertyEditError =
                    "Slate couldn’t read the current note before reapplying the retained property update. \(self.humanReadable(error))"
                postAccessibilityAnnouncement(
                    self.propertyEditError ?? "The retained property update could not be reapplied.",
                    priority: .high)
                self.finishPropertyEditOwnership(generation)
            }
        }
        propertyEditTask = task
        return task
    }

    /// Explicit disk-wins resolution for an authored publication uncertainty.
    /// Unlike ordinary Discard/Revert, this action first loads a current,
    /// authoritative frontmatter snapshot and only then releases the retained
    /// H1 intent.
    @discardableResult
    func useCurrentVersionForActivePropertyPublication() -> Task<Void, Never>? {
        guard !isEditingProperty,
            let session = currentSession,
            let record = activeAuthoredPropertyPublicationRecovery(),
            BaseExactIdentity.matches(loadedFilePath, record.path)
        else { return nil }
        let generation = beginPropertyEditOwnership(path: record.path)
        currentPropertyEditConflict = nil
        propertyEditError = nil
        let task: Task<Void, Never> = Task { [weak self] in
            guard let self else { return }
            let refresh = await self.refreshNoteParts(
                session: session,
                path: record.path,
                allowPropertiesOnlyOnBodyMismatch: true)
            guard self.ownsPropertyEdit(generation, session: session),
                !Task.isCancelled,
                BaseExactIdentity.matches(self.loadedFilePath, record.path)
            else { return }
            switch refresh {
            case .published, .propertiesOnly:
                await self.loadCurrentLinks(
                    path: record.path, publishProperties: false)
                guard self.ownsPropertyEdit(generation, session: session),
                    !Task.isCancelled,
                    BaseExactIdentity.matches(self.loadedFilePath, record.path)
                else { return }
                self.acceptDiskVersion(for: record)
                postAccessibilityAnnouncement(
                    "Using the current saved properties. The retained update was discarded.",
                    priority: .medium)
            case .changedAgain:
                // No expected hash was supplied, so this outcome is defensive.
                self.propertyEditError =
                    "The note changed again while Slate was loading its current properties."
                postAccessibilityAnnouncement(
                    self.propertyEditError ?? "The note changed again.",
                    priority: .high)
            case .failed(let reason):
                self.propertyEditError =
                    "Slate couldn’t load the current properties. The retained update is still available. \(reason)"
                postAccessibilityAnnouncement(
                    self.propertyEditError ?? reason, priority: .high)
            case .stale:
                break
            }
            self.finishPropertyEditOwnership(generation)
        }
        propertyEditTask = task
        return task
    }

    /// Dismiss the property-edit conflict alert without acting on
    /// it. The panel stays as-is; the row's local "in-flight edit"
    /// state is cleared by the resolver (the row reads
    /// `currentPropertyEditConflict` going to `nil` as the cue to
    /// reset its commit state).
    func resolvePropertyEditConflictCancel() {
        currentPropertyEditConflict = nil
    }

    // MARK: - Bulk rename (#170)

    /// Dry-run a vault-wide property rename, populating
    /// `pendingRenameReport` with the per-file diff for the
    /// bulk-rename sheet's preview grid. No writes.
    @discardableResult
    func previewPropertyRename(oldKey: String, newKey: String) -> Task<Void, Never>? {
        runRename(oldKey: oldKey, newKey: newKey, dryRun: true)
    }

    /// Apply a vault-wide property rename. Each affected file is
    /// saved with its fresh on-disk hash as `expected_content_hash`
    /// so an external mid-rename modification surfaces as a per-file
    /// `RenameFailed` rather than aborting the whole run.
    @discardableResult
    func applyPropertyRename(oldKey: String, newKey: String) -> Task<Void, Never>? {
        runRename(oldKey: oldKey, newKey: newKey, dryRun: false)
    }

    /// Cancel an in-flight preview or apply via the existing
    /// cancellation token. The sheet's Esc handler calls this.
    func cancelPendingRename() {
        renameCancelToken?.cancel()
    }

    /// Preview is read-only and remains available while Trash reconciliation
    /// is unresolved. Apply is vault-wide, so it must fail closed until every
    /// outcome is known.
    var bulkRenameApplyDisabledReason: String? {
        if !batchTrashUnknownItems.isEmpty {
            return Self.batchTrashQuarantineReason
        }
        if !recoverablePropertyDraftPaths().isEmpty {
            return Self.propertyDraftBulkRenameReason
        }
        return structuralMutationDisabledReason
    }

    private func runRename(oldKey: String, newKey: String, dryRun: Bool) -> Task<Void, Never>? {
        guard !isRenameInFlight else { return nil }
        guard let session = currentSession else { return nil }
        var structuralToken: Int?
        if !dryRun {
            if let reason = bulkRenameApplyDisabledReason {
                postMutationAnnouncement(reason)
                return nil
            }
            // First synchronous vault-wide admission. `performRename` repeats
            // this after its suspension seam so a quarantine arriving between
            // preview confirmation and native I/O still fails closed.
            guard admitBatchTrashVaultWideWrite() else { return nil }
            guard admitStructuralMutationRequest() else { return nil }
            structuralToken = beginStructuralMutation()
        }
        renameError = nil
        isRenameInFlight = true
        let cancel = CancelToken()
        renameCancelToken = cancel
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performRename(
                session: session,
                oldKey: oldKey,
                newKey: newKey,
                dryRun: dryRun,
                cancel: cancel,
                structuralToken: structuralToken
            )
            return
        }
        renameTask = task
        return task
    }

    private func performRename(
        session: VaultSession,
        oldKey: String,
        newKey: String,
        dryRun: Bool,
        cancel: CancelToken,
        structuralToken: Int?
    ) async {
        if let structuralToken {
            await renameApplySecondAdmissionGate?()
            if let injected = renameApplySecondAdmissionUnknownItemsForTesting?(),
                !injected.isEmpty
            {
                mergeBatchTrashUnknownItems(injected)
            }
            guard !Task.isCancelled,
                ownsStructuralMutation(structuralToken, session: session)
            else {
                finishRenameAttempt(structuralToken: structuralToken, cancel: cancel)
                return
            }
            guard admitBatchTrashVaultWideWrite() else {
                // Keep the preview and both sheet text-field drafts intact.
                // The exact quarantine announcement comes from admission.
                finishRenameAttempt(structuralToken: structuralToken, cancel: cancel)
                return
            }
            guard recoverablePropertyDraftPaths().isEmpty else {
                postMutationAnnouncement(Self.propertyDraftBulkRenameReason)
                finishRenameAttempt(structuralToken: structuralToken, cancel: cancel)
                return
            }
        }
        let outcome: Result<RenameReport, VaultError> = await Task.detached(priority: .userInitiated) {
            do {
                let report = try session.renamePropertyAcrossVault(
                    oldKey: oldKey,
                    newKey: newKey,
                    dryRun: dryRun,
                    cancel: cancel
                )
                return .success(report)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }.value

        // #328 red-team P1: closeVault zeros out the rename-related
        // state and cancels the token, but the Rust call may have
        // resolved between the cancel signal arriving and this
        // continuation resuming on the main actor. Without the
        // guard, we'd write `pendingRenameReport`/`renameError`
        // back over the just-zeroed values and post an a11y
        // announcement against the welcome screen. Mirrors the
        // `loadedFilePath == path` guard in `performPropertyEdit`.
        guard !Task.isCancelled, currentSession === session else {
            finishRenameAttempt(structuralToken: structuralToken, cancel: cancel)
            return
        }
        if !dryRun, case .success = outcome {
            await renamePostWritePublishGate?()
            guard !Task.isCancelled, currentSession === session else {
                finishRenameAttempt(
                    structuralToken: structuralToken, cancel: cancel)
                return
            }
        }

        switch outcome {
        case .success(let report):
            pendingRenameReport = report
            if !dryRun {
                // Refresh only affected OPEN Markdown notes. The report is the
                // bounded changed-path ledger; scanning the vault again would
                // turn this publication step into unnecessary O(N) work.
                var openPaths: [String: String] = [:]
                for tab in workspace.model.allTabs {
                    guard case .markdown(let path) = tab.item else { continue }
                    openPaths[BaseExactIdentity.registryKey(
                        prefix: "bulk-rename-open-note", value: path)] = path
                }
                let affectedOpenPaths = report.affected.compactMap {
                    row -> (path: String, expectedContentHash: String)? in
                    guard row.applied, let expectedContentHash = row.newContentHash,
                        let path = openPaths[BaseExactIdentity.registryKey(
                            prefix: "bulk-rename-open-note", value: row.path)]
                    else { return nil }
                    return (path, expectedContentHash)
                }.sorted { BaseExactIdentity.lessThan($0.path, $1.path) }
                var refreshFailures: [String] = []
                var refreshedActivePath = false
                let renamePublicationKey = "__bulk_property_rename__"
                for affected in affectedOpenPaths {
                    let path = affected.path
                    let refresh = await refreshNoteParts(
                        session: session,
                        path: path,
                        expectedContentHash: affected.expectedContentHash)
                    guard !Task.isCancelled, currentSession === session,
                        structuralToken.map({
                            ownsStructuralMutation($0, session: session)
                        }) ?? true
                    else {
                        finishRenameAttempt(
                            structuralToken: structuralToken, cancel: cancel)
                        return
                    }
                    switch refresh {
                    case .published:
                        refreshedActivePath = refreshedActivePath
                            || BaseExactIdentity.matches(loadedFilePath, path)
                    case .changedAgain:
                        propertyPublicationUncertainties[
                            propertyPublicationUncertaintyKey(
                                path: path, key: renamePublicationKey)] =
                            PropertyPublicationUncertainty(
                                path: path,
                                key: renamePublicationKey,
                                expectedContentHash:
                                    affected.expectedContentHash,
                                action: nil,
                                submittedRowDraft: nil)
                        refreshFailures.append(
                            "\(filename(of: path)): The note changed again before Slate could verify the rename.")
                    case .failed(let reason):
                        propertyPublicationUncertainties[
                            propertyPublicationUncertaintyKey(
                                path: path, key: renamePublicationKey)] =
                            PropertyPublicationUncertainty(
                                path: path,
                                key: renamePublicationKey,
                                expectedContentHash:
                                    affected.expectedContentHash,
                                action: nil,
                                submittedRowDraft: nil)
                        refreshFailures.append("\(filename(of: path)): \(reason)")
                    case .propertiesOnly, .stale:
                        propertyPublicationUncertainties[
                            propertyPublicationUncertaintyKey(
                                path: path, key: renamePublicationKey)] =
                            PropertyPublicationUncertainty(
                                path: path,
                                key: renamePublicationKey,
                                expectedContentHash:
                                    affected.expectedContentHash,
                                action: nil,
                                submittedRowDraft: nil)
                        refreshFailures.append(
                            "\(filename(of: path)): Slate could not safely publish the renamed frontmatter.")
                    }
                }
                if refreshedActivePath, let path = loadedFilePath {
                    await loadCurrentLinks(path: path, publishProperties: false)
                }
                if !refreshFailures.isEmpty {
                    renameError =
                        "Rename applied, but some open notes could not be safely reloaded. "
                        + refreshFailures.joined(separator: " ")
                    postAccessibilityAnnouncement(
                        renameError ?? "Some open notes could not be reloaded.",
                        priority: .high)
                }
            }
            let summary = renameSummary(report: report, applied: !dryRun)
            postAccessibilityAnnouncement(summary, priority: .medium)
        case .failure(let error):
            renameError = humanReadable(error)
            postAccessibilityAnnouncement(
                "Rename failed: \(renameError ?? "")",
                priority: .high
            )
        }
        finishRenameAttempt(structuralToken: structuralToken, cancel: cancel)
    }

    private func finishRenameAttempt(
        structuralToken: Int?,
        cancel: CancelToken
    ) {
        if let structuralToken {
            endStructuralMutation(structuralToken)
        }
        // A late cancelled attempt from a closed/replaced vault must not clear
        // the in-flight flag, cancellation target, or task owned by a newer
        // request. CancelToken is a reference type and is unique per request.
        guard renameCancelToken === cancel else { return }
        isRenameInFlight = false
        renameCancelToken = nil
        renameTask = nil
    }

    /// Render a one-line summary of a `RenameReport` for the
    /// accessibility announcement + the sheet's footer.
    private func renameSummary(report: RenameReport, applied: Bool) -> String {
        if applied {
            let renamed = report.affected.filter { $0.applied }.count
            let skipped = report.skipped.count
            let failed = report.failed.count
            return "\(renamed) renamed, \(skipped) skipped, \(failed) failed."
        } else {
            let will = report.affected.count
            let skipped = report.skipped.count
            return "\(will) \(will == 1 ? "file" : "files") will be renamed, \(skipped) skipped, 0 errors."
        }
    }

    /// "Save changes?" prompt: Save → run the save, then continue
    /// with the pending navigation if the save succeeds. A
    /// `WriteConflict` short-circuits the navigation so the user
    /// gets the conflict alert in place of the navigation step.
    var pendingNavigationSaveDisabledReason: String? {
        guard pendingNavigation != nil, let path = loadedFilePath else { return nil }
        return noteSaveDisabledReason(for: path)
    }

    var pendingNavigationDiscardDisabledReason: String? {
        guard pendingNavigation != nil else { return nil }
        return inFlightDraftDiscardDisabledReason
    }

    @discardableResult
    func resolvePendingNavigationSave() -> Task<Void, Never>? {
        guard let pending = pendingNavigation,
            let session = currentSession,
            let noteOwner = noteAuthoringOwner()
        else { return nil }
        if case .closeVault = pending,
            rejectVaultTransitionDuringNativeImport()
        {
            return nil
        }
        if let reason = pendingNavigationSaveDisabledReason {
            postMutationAnnouncement(reason)
            return nil
        }
        cancelPendingNavigationSave()
        let generation = pendingNavigationSaveGeneration
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.saveAndPerformNavigation(
                pending,
                session: session,
                noteOwner: noteOwner,
                generation: generation)
            return
        }
        pendingNavigationSaveTask = task
        return task
    }

    private func saveAndPerformNavigation(
        _ pending: PendingNavigation,
        session: VaultSession,
        noteOwner: NoteAuthoringOwner,
        generation: UInt64
    ) async {
        guard ownsPendingNavigationSave(
            generation,
            session: session,
            pending: pending,
            noteOwner: noteOwner)
        else { return }
        guard let save = saveCurrentNote() else { return }
        await save.value
        // Save can complete in one of three states; only proceed
        // with the navigation when the save genuinely succeeded
        // (hasUnsavedChanges cleared, no conflict, no error).
        guard ownsPendingNavigationSave(
            generation,
            session: session,
            pending: pending,
            noteOwner: noteOwner),
            !hasUnsavedChanges,
            currentSaveConflict == nil,
            saveError == nil,
            loadedFilePath.map({ !hasDirtyNoteRecovery(for: $0) }) ?? true
        else {
            return
        }
        applyPendingNavigation(pending)
    }

    /// "Save changes?" prompt: Discard → drop the dirty flag and
    /// continue with the pending navigation.
    func resolvePendingNavigationDiscard() {
        guard let pending = pendingNavigation else { return }
        if case .closeVault = pending,
            rejectVaultTransitionDuringNativeImport()
        {
            return
        }
        if case .closeVault = pending,
            let reason = authoredPropertyPublicationRecoveryReason
        {
            pendingNavigation = nil
            pendingVaultSwitchTarget = nil
            postMutationAnnouncement(reason)
            return
        }
        if let path = loadedFilePath,
            let reason = draftDiscardDisabledReason(for: path)
        {
            postMutationAnnouncement(reason)
            return
        }
        cancelPendingNavigationSave()
        if let path = loadedFilePath,
            missingNoteRecoveryDraft(for: path) != nil
        {
            discardMissingNoteRecoveryDraft(path: path, announce: false)
        } else {
            if let path = loadedFilePath {
                discardRecoverablePropertyDrafts(for: path)
            }
            hasUnsavedChanges = false
            // Restore the editor buffer to the baseline so a subsequent
            // load doesn't have a stale dirty buffer hanging around in
            // memory (the load will overwrite anyway, but matching
            // baseline keeps the dirty flag honest in the interim).
            currentNoteText = savedBaselineText
        }
        applyPendingNavigation(pending)
    }

    /// "Save changes?" prompt: Cancel → clear the pending
    /// navigation without saving. The dirty buffer stays.
    func resolvePendingNavigationCancel() {
        cancelPendingNavigationSave()
        if case .selectFile(let path) = pendingNavigation,
            deferredTemplateCursorLanding?.path == path
        {
            deferredTemplateCursorLanding = nil
        }
        pendingNavigation = nil
        // U4-3: cancelling the gate cancels an in-flight vault switch — drop
        // the parked target so no close/open follows and a later plain Close
        // Vault can't inherit it.
        pendingVaultSwitchTarget = nil
    }

    /// Common tail for the Save / Discard branches: clear the
    /// pending state and actually perform the requested
    /// navigation.
    private func applyPendingNavigation(_ pending: PendingNavigation) {
        cancelPendingNavigationSave()
        pendingNavigation = nil
        switch pending {
        case .closeVault:
            closeVault()
        case .selectFile(let path):
            // Setting selectedFilePath re-triggers the
            // handleSelectionChange subscription. At this point
            // `hasUnsavedChanges` is false (Save cleared it; Discard
            // cleared it), so the dirty gate falls through and the
            // load proceeds normally.
            selectedFilePath = path
            // A template-created target can already have a parked workspace
            // document for the same path (including a prior failed load). Its
            // deferred {{cursor}} offset is authoritative only for the bytes
            // just written, so bypass that cache and require a fresh disk load
            // before the caret may land.
            if let path,
                let session = currentSession,
                deferredTemplateCursorLanding?.sessionID == ObjectIdentifier(session),
                deferredTemplateCursorLanding?.path == path
            {
                _ = startAuthoritativeTemplateTargetLoad(
                    session: session, path: path)
            }
        }
    }

    /// Refresh headings for the just-saved note without
    /// re-reading its text. `save_text` already updates the
    /// `headings` table inside its transaction, so a single
    /// metadata fetch is enough. Failures are non-fatal: the
    /// outline shows the old list until the next reload.
    private func refreshHeadingsAfterSave(session: VaultSession, path: String) {
        Task { [weak self] in
            // Off-actor metadata fetch — getFileMetadata grabs the
            // SQLite mutex, so we don't want to pin the main actor
            // for its duration. The post-await re-grab of `self`
            // keeps the Sendable check happy under the Swift 6
            // language mode.
            let headings: [Heading]? = await Task.detached(priority: .userInitiated) {
                (try? session.getFileMetadata(path: path))?.headings
            }.value
            guard let self else { return }
            guard BaseExactIdentity.matches(self.loadedFilePath, path) else { return }
            // U3-3: metadata offsets are whole-file; the buffer is body.
            self.currentNoteHeadings = Self.rebasedToBody(
                headings ?? [], prefixBytes: self.bodyByteOffset)
        }
    }

    /// Closes the vault when the editor is clean; routes through
    /// the "Save changes?" alert when it's dirty. The toolbar
    /// "Close Vault" button calls this instead of `closeVault()`
    /// directly so the dirty path can't be bypassed.
    func attemptCloseVault() {
        if let reason = authoredPropertyPublicationRecoveryReason {
            postMutationAnnouncement(reason)
            return
        }
        if let reason = inFlightDraftDiscardDisabledReason {
            postMutationAnnouncement(reason)
            return
        }
        supersedePendingTabCloseForVaultTransition()
        let recoveryPaths = uncommittedNoteDraftPaths()
        if !recoveryPaths.isEmpty {
            pendingVaultClose = dirtyVaultClosePaths().count
        } else if hasUnsavedChanges {
            pendingNavigation = .closeVault
        } else {
            closeVault()
        }
    }

    func filename(of path: String) -> String {
        (path as NSString).lastPathComponent
    }

    // MARK: - Scan progress

    /// Main-actor entry point for scanner events. Called by
    /// `ScanProgressAdapter` after marshaling from the scanner thread.
    /// `internal` so XCTest can drive synthetic event streams against
    /// it without spinning up a real scan.
    func handleScanProgress(_ event: ScanProgress) {
        scanProgress = event
        switch event {
        case .started(let totalFiles):
            // Forced announcement: the user wants to know a scan
            // started even if they just opened the vault and we
            // haven't accumulated 350 ms of cooldown yet.
            announceScan(
                message: "Scanning vault. "
                    + "\(totalFiles) \(totalFiles == 1 ? "file" : "files") to index.",
                force: true
            )
        case .fileIndexed(_, let indexed, let total):
            // Rate-limited: at most ~3 per second per the acceptance
            // criteria, so VoiceOver flow stays polite even on a
            // 50k-file vault.
            announceScan(
                message: "Indexed \(indexed) of \(total) files.",
                force: false
            )
        case .finished(let report):
            announceScan(
                message: "Scan complete. "
                    + "\(report.filesIndexed) "
                    + (report.filesIndexed == 1 ? "file" : "files")
                    + " indexed.",
                force: true
            )
            // Clear so the progress bar hides; loadFiles' post-scan
            // populate runs next and updates `files`.
            scanProgress = nil
        case .cancelled, .failed:
            // No "finished" announcement. Failed is surfaced via
            // `scanError` (the existing path); cancelled is silent
            // because closeVault / next-vault flow is already
            // visible.
            scanProgress = nil
        }
    }

    /// Post a VoiceOver announcement subject to the rate guard. When
    /// `force` is true the announcement always fires (used for
    /// Started/Finished). Otherwise it only fires if the clock has
    /// advanced past the configured min-interval since the last fire.
    private func announceScan(message: String, force: Bool) {
        let now = scanClock()
        if !force,
            now.timeIntervalSince(scanAnnouncementLastFiredAt) < scanAnnouncementMinInterval
        {
            return
        }
        scanAnnouncementLastFiredAt = now
        scanAnnouncementCount += 1
        scanAnnouncementLastMessage = message
        postAccessibilityAnnouncement(message)
    }

    // MARK: - Templates (Milestone H)

    /// Re-fetch templates and open the picker only when the result is
    /// available. Empty and failed results remain distinct disabled states;
    /// neither presents an empty picker or collapses an I/O error to empty.
    @discardableResult
    func openTemplatePicker() -> Task<Void, Never>? {
        openTemplatePicker(in: "")
    }

    /// Open the existing picker while retaining the canonical parent captured
    /// by the action evaluation. The destination is established only after the
    /// structural admission succeeds, so a rejected invocation has no state
    /// or presentation side effects.
    @discardableResult
    func openTemplatePicker(in destination: String) -> Task<Void, Never>? {
        guard let session = currentSession,
            admitStructuralMutationRequest()
        else { return nil }
        templateSelectionTask?.cancel()
        templateSelectionTask = nil
        templateFlowGeneration &+= 1
        templateCreationDestinationOwner = TemplateCreationDestinationOwner(
            sessionIdentity: ObjectIdentifier(session),
            generation: templateFlowGeneration,
            path: destination)
        return startTemplateAvailabilityLoad(presentPicker: true)
    }

    /// Refresh the AppState-owned availability snapshot without presenting UI.
    /// Projection reads only the published result and therefore performs no
    /// filesystem or FFI I/O.
    @discardableResult
    func refreshTemplateAvailability() -> Task<Void, Never>? {
        guard templateCreationDestinationOwner == nil,
            pendingTemplateFlow == .idle,
            !isTemplatePickerOpen
        else { return templateAvailabilityTask }
        return startTemplateAvailabilityLoad(presentPicker: false)
    }

    /// Narrow recovery helper retained for callers that only need to retry an
    /// unavailable projection. Foreground and file-event recovery use the
    /// debounced scheduler below so cached `.available` state is revalidated.
    @discardableResult
    func refreshUnavailableTemplateAvailability() -> Task<Void, Never>? {
        guard templateAvailability == .empty || templateAvailability == .failed
        else { return nil }
        return refreshTemplateAvailability()
    }

    /// Retry a visible empty/failed picker without changing its frozen
    /// destination. The same sheet returns to loading immediately, keeping
    /// Cancel and Escape reachable throughout the new enumeration.
    @discardableResult
    func retryTemplatePickerLoad() -> Task<Void, Never>? {
        guard let session = currentSession,
            isTemplatePickerOpen,
            ownsTemplateCreationDestination(session: session),
            templateAvailability == .empty || templateAvailability == .failed
        else { return nil }
        return startTemplateAvailabilityLoad(presentPicker: true)
    }

    /// Debounced passive refresh used by vault events, scan completion, and
    /// foreground activation. It intentionally refreshes cached `.available`
    /// state too: templates can be created, deleted, or renamed while the
    /// vault remains open. Projection remains a pure read of published state.
    func scheduleTemplateAvailabilityRefresh() {
        guard let session = currentSession else { return }
        scheduleTemplateAvailabilityRefresh(for: session)
    }

    /// Structural file events do not expose the configured templates folder,
    /// so conservatively refresh for Markdown create/delete/rename events.
    /// The 75 ms coalescer turns mutation bursts into one enumeration.
    func handleTemplateAvailabilityFileChange(
        _ event: FileChangeEvent,
        from session: VaultSession
    ) {
        guard currentSession === session else { return }
        let paths: [String]
        switch event.kind {
        case .created, .deleted:
            paths = [event.path]
        case .renamed:
            paths = [event.path, event.previousPath].compactMap { $0 }
        case .modified:
            return
        }
        guard paths.contains(where: { ($0 as NSString).pathExtension.lowercased() == "md" })
        else { return }
        scheduleTemplateAvailabilityRefresh(for: session)
    }

    private func scheduleTemplateAvailabilityRefresh(for session: VaultSession) {
        guard currentSession === session else { return }
        templateAvailabilityRefreshPending = true
        guard templateAvailabilityRefreshTaskForTesting == nil else { return }
        let generation = templateAvailabilityRefreshGeneration
        templateAvailabilityRefreshTaskForTesting = Task { @MainActor [weak self, weak session] in
            do {
                try await Task.sleep(for: .milliseconds(75))
            } catch {
                return
            }
            guard let self, let session, !Task.isCancelled,
                self.currentSession === session,
                self.templateAvailabilityRefreshGeneration == generation
            else { return }
            self.templateAvailabilityRefreshTaskForTesting = nil
            self.drainPendingTemplateAvailabilityRefreshIfIdle()
        }
    }

    private func drainPendingTemplateAvailabilityRefreshIfIdle() {
        guard templateAvailabilityRefreshPending,
            templateCreationDestinationOwner == nil,
            pendingTemplateFlow == .idle,
            !isTemplatePickerOpen
        else { return }
        templateAvailabilityRefreshPending = false
        _ = refreshTemplateAvailability()
    }

    private func startTemplateAvailabilityLoad(
        presentPicker: Bool
    ) -> Task<Void, Never>? {
        guard let session = currentSession else {
            templateAvailability = .empty
            availableTemplates = []
            return nil
        }
        templateAvailabilityTask?.cancel()
        templateAvailabilityGeneration &+= 1
        let generation = templateAvailabilityGeneration
        let runner = templateListRunner
        let dispatchGate = templateAvailabilityDispatchGateForTesting
        let landingGate = templateAvailabilityLandingGateForTesting
        let cancel = CancelToken()
        templateAvailability = .loading
        isTemplatePickerOpen = presentPicker

        let task: Task<Void, Never> = Task { [weak self] in
            await withTaskCancellationHandler {
                if let dispatchGate {
                    await dispatchGate(generation)
                }
                guard !Task.isCancelled, !cancel.isCancelled() else { return }
                let result = await Task.detached(priority: .userInitiated) {
                    guard !cancel.isCancelled() else {
                        return Result<[TemplateSummary], VaultError>.failure(.Cancelled)
                    }
                    return runner(session, cancel)
                }.value
                if let landingGate {
                    await landingGate(generation)
                }
                guard let self, !Task.isCancelled, !cancel.isCancelled(),
                    self.currentSession === session,
                    self.templateAvailabilityGeneration == generation
                else { return }

                self.templateAvailabilityTask = nil
                if presentPicker {
                    self.templatePickerTask = nil
                }
                switch result {
                case .success(let summaries):
                    self.availableTemplates = summaries
                    if summaries.isEmpty {
                        self.templateAvailability = .empty
                        if presentPicker {
                            self.announceTemplate(Self.templateAvailabilityEmptyReason)
                        }
                    } else {
                        self.templateAvailability = .available
                        if presentPicker {
                            self.announceTemplate(
                                self.templatePickerOpenAnnouncement(summaries.count))
                        }
                    }
                case .failure(let error):
                    guard case .Cancelled = error else {
                        self.availableTemplates = []
                        self.templateAvailability = .failed
                        if presentPicker {
                            self.announceTemplate(Self.templateAvailabilityFailedReason)
                        }
                        return
                    }
                }
            } onCancel: {
                cancel.cancel()
            }
        }
        templateAvailabilityTask = task
        if presentPicker {
            templatePickerTask = task
        }
        return task
    }

    /// Compose the open-picker announcement. Pulled out so the
    /// empty-state copy stays in sync with the non-empty case and
    /// so unit tests can hit it without standing up a real vault.
    private func templatePickerOpenAnnouncement(_ count: Int) -> String {
        switch count {
        case 0:
            return "Template picker opened. No templates found. "
                + "Add a Markdown file to the configured template folder."
        case 1:
            return "Template picker opened. 1 template available."
        default:
            return "Template picker opened. \(count) templates available."
        }
    }

    /// User chose a template row in the picker. Pulls the source off
    /// disk to extract prompt metadata; routes to the prompt sheet
    /// if there are prompts, otherwise straight to the name sheet.
    /// On read failure (template deleted between list and select)
    /// cancels the flow rather than blocking on an error sheet.
    @discardableResult
    func selectTemplate(_ summary: TemplateSummary) -> Task<Void, Never>? {
        guard let session = currentSession,
            ownsTemplateCreationDestination(session: session)
        else {
            resetTemplateFlowPresentation()
            return nil
        }
        guard admitStructuralMutationRequest() else { return nil }
        let flowGeneration = templateFlowGeneration
        // The picker remains visible while source metadata is read, so a user
        // can activate another row before the first read lands. Supersede the
        // prior owner synchronously: only the most recent row may present the
        // next sheet, and Cancel can then invalidate the whole visible choice.
        templateSelectionTask?.cancel()
        templateRetryNoteName = nil
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performSelectTemplate(
                summary, flowGeneration: flowGeneration)
        }
        templateSelectionTask = task
        return task
    }

    private func performSelectTemplate(
        _ summary: TemplateSummary,
        flowGeneration: UInt64
    ) async {
        guard let session = currentSession else {
            resetTemplateFlowPresentation()
            return
        }
        let sourceResult: String? = await Task.detached(
            priority: .userInitiated
        ) {
            try? session.readText(path: summary.path)
        }.value
        if let landingGate = templateSelectionLandingGateForTesting {
            await landingGate(summary)
        }
        // #328 red-team P1: vault close mid-read would otherwise
        // resume here, run `cancelTemplateFlow()`/`pendingTemplateFlow
        // = .needsName(...)` against the dead session, and re-present
        // the template flow sheet on the welcome screen.
        guard !Task.isCancelled, currentSession === session,
            ownsTemplateCreationDestination(
                session: session, generation: flowGeneration)
        else { return }
        guard let source = sourceResult else {
            // This is the selection task's own terminal failure. Reset the
            // presentation without asking it to cancel its own task handle.
            resetTemplateFlowPresentation()
            return
        }
        let metadata = extractTemplateMetadata(source: source)
        isTemplatePickerOpen = false
        if metadata.prompts.isEmpty {
            pendingTemplateFlow = .needsName(summary, [:])
        } else {
            pendingTemplateFlow = .needsPrompts(summary, metadata.prompts)
        }
    }

    /// Hand-off from the prompt sheet's Submit button. Stuffs the
    /// user's responses into the flow and advances to the name
    /// sheet. No-op when the flow isn't currently waiting on prompts
    /// (e.g. a late callback from a sheet that already dismissed).
    func submitTemplatePrompts(_ values: [String: String]) {
        guard case .needsPrompts(let template, _) = pendingTemplateFlow else {
            return
        }
        guard let session = currentSession,
            ownsTemplateCreationDestination(session: session)
        else {
            resetTemplateFlowPresentation()
            return
        }
        guard admitStructuralMutationRequest() else { return }
        templateRetryNoteName = nil
        pendingTemplateFlow = .needsName(template, values)
    }

    /// Final step. Renders the template, atomically writes the new
    /// note, selects it in the editor, and parks the cursor at the
    /// template's `{{cursor}}` byte offset (if any).
    ///
    /// Path validation rejects empty / `.` / `..` / absolute paths
    /// up front so the user sees the error inline instead of as a
    /// late `save_text` failure. Cancel from any earlier sheet
    /// leaves no file on disk; this method only fires on the user's
    /// explicit Submit.
    @discardableResult
    func submitTemplateNoteName(_ relativePath: String) -> Task<Void, Never>? {
        guard case .needsName(let template, let promptValues) = pendingTemplateFlow
        else { return nil }
        guard let session = currentSession,
            let vaultURL = currentVaultURL
        else {
            cancelTemplateFlow()
            return nil
        }
        // The name field's Return handler remains invokable while another
        // structural operation owns the gate. Reject before validation can
        // replace the retained sheet's error state, so every busy submission
        // announces the same exact reason and leaves the presentation intact.
        guard admitStructuralMutationRequest() else { return nil }
        guard ownsTemplateCreationDestination(session: session),
            let destination = templateCreationDestination
        else {
            templateNoteNameError = Self.templateDestinationUnavailableReason
            return nil
        }

        let trimmed = relativePath.trimmingCharacters(in: .whitespacesAndNewlines)
        if let problem = validateTemplateNoteName(trimmed) {
            templateNoteNameError = problem
            return nil
        }

        // Append `.md` if the user omitted it. The picker's "default
        // name" already includes it, but a paste from elsewhere
        // might not — adding it here keeps every created template
        // note Markdown-shaped. `pathExtension` is more robust than
        // a bare `hasSuffix(".md")`: it correctly handles multi-dot
        // names like `archive.tar.MD` (extension is `MD`, lowercased
        // matches `md`, so we leave it alone instead of producing
        // `archive.tar.MD.md` — Codoki PR #154 suggestion). Case-
        // insensitive comparison also preserves the user's casing
        // for any-case `.md` / `.MD` / `.Md` (#133).
        let normalized = (trimmed as NSString).pathExtension.lowercased() == "md"
            ? trimmed : "\(trimmed).md"
        let creationPath = destination.isEmpty
            ? normalized
            : "\(destination)/\(normalized)"
        guard let recoveryReservation =
                admitStructuralRecoveryDestination(creationPath),
            admitBatchTrashWrite(to: [creationPath])
        else { return nil }
        // `title` for the rendered template is the file stem of the
        // new note, not the template's own name. Matches how
        // `{{title}}` is documented to behave in §8.2.
        let titleStem = ((normalized as NSString).lastPathComponent as NSString)
            .deletingPathExtension
        let context = TemplateContext(
            nowMs: Int64(Date().timeIntervalSince1970 * 1000),
            title: titleStem,
            vaultName: vaultURL.lastPathComponent,
            promptValues: promptValues
        )

        let token = beginStructuralMutation(
            recoveryReservation: recoveryReservation)
        let refresher = structuralBatchRefreshRunner
        let retryFlow = PendingTemplateFlow.needsName(template, promptValues)
        // The name sheet's Cancel copy promises that no file is written. Once
        // admission succeeds, remove that control synchronously before the
        // render/write task can begin. A real write failure restores this exact
        // captured flow below so the user can correct the destination and retry.
        pendingTemplateFlow = .idle
        templateNoteNameError = nil
        templateRetryNoteName = nil
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.performCreateNoteFromTemplate(
                session: session,
                template: template,
                context: context,
                relativePath: creationPath,
                token: token,
                refresher: refresher,
                retryFlow: retryFlow,
                retryNoteName: trimmed
            )
        }
        templateCreateTask = task
        pendingStructuralTaskForTesting = task
        return task
    }

    private func performCreateNoteFromTemplate(
        session: VaultSession,
        template: TemplateSummary,
        context: TemplateContext,
        relativePath: String,
        token: Int,
        refresher: @escaping StructuralBatchRefreshRunner,
        retryFlow: PendingTemplateFlow,
        retryNoteName: String
    ) async {
        // Render + save off the main actor so the SQLite mutex and
        // file write don't pin the UI thread. Match the
        // `performSave` shape so the threading story stays uniform
        // across editor-save and template-create paths.
        let outcome: Result<RenderedTemplate, VaultError> = await Task.detached(
            priority: .userInitiated
        ) {
            do {
                let rendered = try session.renderTemplate(
                    templatePath: template.path,
                    context: context
                )
                // Same no-clobber discipline as createNote (#796): the
                // template flow races external creates identically.
                _ = try session.createExclusive(
                    path: relativePath,
                    content: rendered.body
                )
                return .success(rendered)
            } catch let error as VaultError {
                return .failure(error)
            } catch {
                return .failure(.Io(message: error.localizedDescription))
            }
        }.value

        guard ownsStructuralMutation(token, session: session) else { return }
        defer { endStructuralMutation(token) }
        guard !Task.isCancelled else { return }

        switch outcome {
        case .success(let rendered):
            await refresher(self)
            // A vault switch invalidates this token before the refresh can
            // resume. Do not dismiss, select, announce, or release a newer
            // vault's structural owner from this stale completion.
            guard !Task.isCancelled,
                ownsStructuralMutation(token, session: session)
            else { return }
            // #871 Codex round 2: template creation writes a file outside the
            // `publishTreeMutation` barrier — clear the structural undo history
            // so a stale inverse can't target the created path.
            clearStructuralUndoStacks()
            pendingTemplateFlow = .idle
            templateNoteNameError = nil
            templateRetryNoteName = nil
            // The authoritative write has succeeded and `relativePath` now
            // carries the destination through selection/caret work. Release
            // the presentation-only destination before any cursor-path early
            // return so dirty navigation or a failed target load cannot retain
            // stale ownership.
            templateCreationDestinationOwner = nil
            drainPendingTemplateAvailabilityRefreshIfIdle()
            // #421 (F-H1): .high, not .medium — the create
            // announcement is immediately followed by
            // selectedFilePath changing, whose "Showing <file>."
            // announcement supersedes an in-flight medium one before
            // VO finishes it. High makes the completed user action
            // win; the picker-open/cancel messages stay .medium
            // (red-team scoping note).
            announceTemplate(
                "Created \(filename(of: relativePath)) from \(template.name).",
                priority: .high
            )
            // Open the new file. SwiftUI propagates the binding
            // change → `handleSelectionChange` kicks off a fresh
            // note load. After the load resolves, we send the
            // cursor request so `NoteEditorView`'s coordinator can
            // park the caret at `{{cursor}}`.
            deferredTemplateCursorLanding = nil
            selectedFilePath = relativePath
            if let offset = rendered.cursorByteOffset {
                // The selection sink can synchronously refuse navigation when
                // the current editor is dirty. In that case `noteLoadTask`
                // still belongs to the old note: retain the park separately
                // and let the created note's eventual successful load deliver
                // it after Save/Discard resolves the prompt.
                if pendingNavigation == .selectFile(relativePath) {
                    deferredTemplateCursorLanding = DeferredTemplateCursorLanding(
                        sessionID: ObjectIdentifier(session),
                        path: relativePath,
                        fileByteOffset: Int(offset))
                    return
                }
                // Require a fresh read of the bytes just created. A same-path
                // workspace tab may otherwise restore a parked (or failed)
                // document and make an old body offset look current.
                guard let pendingLoad = startAuthoritativeTemplateTargetLoad(
                    session: session, path: relativePath
                ) else { return }
                let landingGate = templateCursorLandingGateForTesting
                await pendingLoad.value
                if let landingGate {
                    await landingGate()
                }
                // Keep this landing inside the structural owner rather than
                // spawning an untracked task. A direct vault switch invalidates
                // the token; a same-session selection change cancels the exact
                // load captured above. Neither may deliver a stale cursor park.
                guard !Task.isCancelled,
                    ownsStructuralMutation(token, session: session),
                    !pendingLoad.isCancelled,
                    BaseExactIdentity.matches(selectedFilePath, relativePath),
                    BaseExactIdentity.matches(loadedFilePath, relativePath)
                else { return }
                // U3-3: {{cursor}} offsets are whole-rendered-file;
                // the load above set the body offsets for this note.
                cursorByteOffsetRequest.send(bodyByte(fromFileByte: Int(offset)))
                // Focus follows content (F-H1): the caret park
                // alone leaves keyboard focus on the window; the
                // coordinator makes the editor first responder
                // when it handles this request.
            }
        case .failure(let error):
            templateRetryNoteName = retryNoteName
            pendingTemplateFlow = retryFlow
            templateNoteNameError = humanReadable(error)
        }
    }

    /// Deliver a cursor park retained across the dirty-navigation prompt only
    /// after the created note's own successful load establishes body offsets.
    private func deliverDeferredTemplateCursorIfReady(
        session: VaultSession, path: String
    ) {
        guard let deferred = deferredTemplateCursorLanding,
            deferred.sessionID == ObjectIdentifier(session),
            currentSession === session,
            deferred.path == path,
            BaseExactIdentity.matches(selectedFilePath, path),
            BaseExactIdentity.matches(loadedFilePath, path)
        else { return }
        deferredTemplateCursorLanding = nil
        cursorByteOffsetRequest.send(bodyByte(fromFileByte: deferred.fileByteOffset))
    }

    /// Start the template target's disk read even when the workspace has a
    /// same-path parked document. The returned task is the exact authority the
    /// cursor landing awaits and is still cancellable by ordinary navigation.
    @discardableResult
    private func startAuthoritativeTemplateTargetLoad(
        session: VaultSession, path: String
    ) -> Task<Void, Never>? {
        guard currentSession === session,
            BaseExactIdentity.matches(selectedFilePath, path)
        else { return nil }
        noteLoadTask?.cancel()
        let task: Task<Void, Never> = Task { [weak self] in
            await self?.loadCurrentNote(path: path)
        }
        noteLoadTask = task
        return task
    }

    /// A failed target read is terminal for its retained cursor request. If a
    /// file later appears at the same path it is a new navigation, not proof
    /// that the original rendered byte offset is still valid.
    private func clearDeferredTemplateCursorIfMatching(
        session: VaultSession, path: String
    ) {
        guard deferredTemplateCursorLanding?.sessionID == ObjectIdentifier(session),
            deferredTemplateCursorLanding?.path == path
        else { return }
        deferredTemplateCursorLanding = nil
    }

    /// Reset the create-from-template flow back to idle. Called by
    /// every sheet's Cancel button and by the failure paths above.
    /// Idempotent — safe to call from any state.
    func cancelTemplateFlow() {
        templateFlowGeneration &+= 1
        if templatePickerTask != nil {
            templateAvailabilityGeneration &+= 1
            templatePickerTask?.cancel()
            templatePickerTask = nil
            templateAvailabilityTask?.cancel()
            templateAvailabilityTask = nil
            templateAvailability = availableTemplates.isEmpty ? .empty : .available
        }
        // Cancel/Escape is authoritative over a row selection whose source
        // read has not landed yet. Nil the public handle too so callers cannot
        // mistake the cancelled selection for an active transition.
        templateSelectionTask?.cancel()
        templateSelectionTask = nil
        resetTemplateFlowPresentation()
    }

    /// Tear down every vault-owned piece of the template lifecycle. Bumping
    /// the generation is the publication barrier for detached list work;
    /// session identity remains the independent cross-vault barrier.
    private func resetTemplateLifecycleForVaultTransition() {
        templateAvailabilityGeneration &+= 1
        templateAvailabilityRefreshGeneration &+= 1
        templateFlowGeneration &+= 1
        clearTemplateShortcutDialogNotice()
        templateAvailabilityRefreshTaskForTesting?.cancel()
        templateAvailabilityRefreshTaskForTesting = nil
        templateAvailabilityRefreshPending = false
        templateAvailabilityTask?.cancel()
        templateAvailabilityTask = nil
        templatePickerTask?.cancel()
        templatePickerTask = nil
        templateSelectionTask?.cancel()
        templateSelectionTask = nil
        templateCreateTask?.cancel()
        templateCreateTask = nil
        deferredTemplateCursorLanding = nil
        pendingTemplateFlow = .idle
        isTemplatePickerOpen = false
        templateNoteNameError = nil
        templateRetryNoteName = nil
        templateCreationDestinationOwner = nil
        availableTemplates = []
        templateAvailability = .empty
    }

    /// Presentation-only reset for terminal paths already running inside the
    /// selection task. Keeping this separate avoids self-cancellation while
    /// preserving the exact same visible resting state.
    private func resetTemplateFlowPresentation() {
        pendingTemplateFlow = .idle
        isTemplatePickerOpen = false
        templateNoteNameError = nil
        templateRetryNoteName = nil
        templateCreationDestinationOwner = nil
        drainPendingTemplateAvailabilityRefreshIfIdle()
    }

    /// Reject the new-note name early so the user sees a useful
    /// inline error rather than a `save_text` `InvalidPath` failure
    /// that arrives after the render finishes. Mirrors the rules in
    /// `validate_save_path` in `slate-core`.
    private func validateTemplateNoteName(_ candidate: String) -> String? {
        if candidate.isEmpty {
            return "Note name cannot be empty."
        }
        if candidate == "." || candidate == ".." {
            return "Note name cannot be `.` or `..`."
        }
        if candidate.hasPrefix("/") {
            return "Note name must be vault-relative, not absolute."
        }
        // Any segment equal to `..` is a path traversal. Block both
        // `../foo.md` and `foo/../bar.md`.
        for segment in candidate.split(separator: "/", omittingEmptySubsequences: false) {
            if segment == ".." {
                return "Note name cannot contain `..` segments."
            }
        }
        return nil
    }

    /// Convenience: the new-note name field's default value for a
    /// freshly-selected template. Templates whose name starts with
    /// the **word** `Daily` get a date suffix so the user can
    /// confirm-Enter on the daily-note flow without typing;
    /// everything else pre-fills with the template's own name.
    ///
    /// The date is joined with a **space** rather than a dash so
    /// multi-word names read naturally: `Daily Standup` becomes
    /// `Daily Standup 2026-05-23.md`, not the awkward
    /// `Daily Standup-2026-05-23.md` (#133). A bare `Daily` template
    /// becomes `Daily 2026-05-23.md`, which matches the spacing most
    /// users would type by hand.
    ///
    /// "Word" prefix means `daily` is either the whole name or is
    /// followed by a non-alphanumeric character — so `Daily`,
    /// `Daily Standup`, `Daily-notes`, and `Daily.md` all qualify,
    /// but `Dailyness` and `Daily123` don't (Codoki PR #154
    /// suggestion).
    func defaultNewNoteName(for template: TemplateSummary) -> String {
        if Self.isDailyTemplateName(template.name) {
            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.timeZone = TimeZone(secondsFromGMT: 0)
            formatter.dateFormat = "yyyy-MM-dd"
            return "\(template.name) \(formatter.string(from: Date())).md"
        }
        return "\(template.name).md"
    }

    /// `true` iff `name` begins with the standalone word `daily`
    /// (case-insensitive). Catches `Daily`, `Daily Standup`,
    /// `Daily-notes`; rejects `Dailyness`, `Daily123`. Pulled out
    /// + made static so tests can drive it directly without
    /// constructing a `TemplateSummary`.
    static func isDailyTemplateName(_ name: String) -> Bool {
        let lower = name.lowercased()
        guard lower.hasPrefix("daily") else { return false }
        let afterIdx = lower.index(lower.startIndex, offsetBy: "daily".count)
        if afterIdx == lower.endIndex { return true }
        let next = lower[afterIdx]
        // Anything that isn't a continuation of the word `daily` is
        // a word boundary: whitespace, dashes, periods, slashes are
        // all valid daily-template separators.
        return !next.isLetter && !next.isNumber
    }

    /// Post a polite announcement through AppKit's accessibility
    /// bus and capture it for the test target. Same shape as
    /// `announceScan` but without the per-second rate guard —
    /// template events are user-driven and never rapid-fire.
    private func announceTemplate(
        _ message: String,
        priority: AnnouncementPriority = .medium
    ) {
        templateAnnouncementLastMessage = message
        announcer.post(message, priority: priority)
    }

    // MARK: - Private

    private func recordOpened(url: URL) {
        let entry = RecentVault(url: url)
        do {
            recentVaults = try recentsStore.add(entry)
        } catch {
            // Same rationale as removeRecent: don't block the open flow
            // on a recents-list write failure.
            fputs(
                "Slate: failed to persist recent-vaults add: \(error)\n",
                stderr
            )
        }
    }

    func humanReadable(_ error: VaultError) -> String {
        switch error {
        case .Io(let message), .Db(let message), .Trash(let message):
            return message
        case .InvalidPath(let path, let reason):
            return "Invalid path \(path): \(reason)"
        case .Cancelled:
            return "Operation cancelled."
        case .InvalidUtf8(let path):
            return "File at \(path) is not valid UTF-8."
        case .FileTooLarge(let path, let size):
            return "File at \(path) is \(size) bytes — larger than this build's refuse threshold."
        case .InvalidQuery(let message):
            return "Search query is invalid: \(message)"
        case .Unsupported(let feature):
            return "\(feature) is not implemented yet."
        case .InvalidArgument(let message):
            return "Invalid argument: \(message)"
        case .WriteConflict:
            // The editor's save-flow handles this case directly with
            // a "Keep mine / Reload from disk" affordance (issue #64);
            // surfacing it through the generic humanReadable path is
            // a last-resort fallback for non-editor callers.
            return "This file was modified by another writer since you opened it. Reload to see the latest version."
        case .MalformedFrontmatter(let path, let reason):
            return
                "Frontmatter at \(path) is malformed: \(reason). Fix the YAML in this note before editing properties."
        case .BibSourceUnreadable(let path, let reason):
            return "Bibliography source \(path) couldn't be opened: \(reason)."
        case .CslStyleUnreadable(let path, let reason):
            return "Citation style \(path) couldn't be loaded: \(reason)."
        case .PrefsUnreadable(let path, let reason):
            return "Preferences file \(path) couldn't be loaded: \(reason)."
        case .DestinationExists(let path):
            return "Something named \(path) already exists there. Choose a different name."
        case .HistoryUnavailable(let path, _):
            // O-3 (#541): a version operation failed integrity
            // verification and refused rather than serving wrong
            // bytes. The reason string is diagnostic detail; the
            // user-facing message keeps the O-5 alert's framing.
            return "History for \(path) is unavailable: it failed an integrity check."
        }
    }
}

/// 1-based line number of the first occurrence (in `body`) of any
/// alphanumeric token from `query`. Falls back to 1 when no token
/// can be found — FTS5 may have matched through stemming, so the
/// raw tokens needn't appear literally in the note.
///
/// Lives at file scope (not on AppState) so it has no implicit
/// MainActor isolation — pure string crunching, the caller can
/// invoke it from any actor context.
///
/// Mirrors the Rust-side heuristic that lived in
/// `search_db::find_first_token_line` before #92 item 1 moved
/// line derivation out of `full_text_search`. Lowercases the body
/// Pull the first citation key from a raw source-form string. Handles
/// `[@key]`, `[@key, p. 23]`, `[-@key]`, `@key`, etc. Returns `""` when
/// no `@`-anchored key is found. Mirrors the helper in
/// `CitationPopover.extractKey` — pulled out here so the AppState
/// Jump-to-Bibliography action can call it without coupling to the
/// view layer.
func extractCitationKey(from raw: String) -> String {
    guard let atIdx = raw.firstIndex(of: "@") else { return "" }
    let after = raw.index(after: atIdx)
    let tail = raw[after...]
    let key = tail.prefix { ch in
        ch.isLetter || ch.isNumber || ch == "_" || ch == "-" || ch == ":"
            || ch == "." || ch == "+"
    }
    return String(key).trimmingCharacters(in: CharacterSet(charactersIn: "."))
}

/// Pure filter used by `BibliographyPanel`. Empty query returns
/// `entries` unchanged. Otherwise case-insensitive substring match
/// against title, key, author family, and author given names. Split
/// out as a free function so tests can exercise the logic without
/// AppState's `private(set)` constraints.
func filterBibliographyEntries(_ entries: [BibEntry], query: String) -> [BibEntry] {
    let q = query
        .trimmingCharacters(in: .whitespacesAndNewlines)
        .lowercased()
    guard !q.isEmpty else { return entries }
    return entries.filter { entry in
        if entry.title.lowercased().contains(q) { return true }
        if entry.key.lowercased().contains(q) { return true }
        for author in entry.authors {
            if author.family.lowercased().contains(q) { return true }
            if let given = author.given,
                given.lowercased().contains(q)
            {
                return true
            }
        }
        return false
    }
}

/// Synthesize a `RenderedCitation` for a `CitationReference` when no
/// CSL style is configured yet. The panel will announce these via
/// the citation key — better than rendering nothing, since AT users
/// at least learn where citations live in the document. Once #281
/// wires a default style, the real renderer takes over.
func placeholderRendered(for ref: CitationReference) -> RenderedCitation {
    let speech: String
    if ref.citations.count == 1 {
        let item = ref.citations[0]
        switch item.mode {
        case .inText:
            speech = item.key
        default:
            speech = "Citation: \(item.key)"
        }
    } else {
        let keys = ref.citations.map { $0.key }.joined(separator: ", ")
        speech = "Citation: \(keys)"
    }
    return RenderedCitation(
        raw: ref.raw,
        visualText: ref.raw,
        speechText: speech,
        bibEntry: nil,
        styleId: ""
    )
}

/// once and counts newlines in the lowercased prefix — avoids a
/// cross-string slice that would panic on non-boundary indices
/// when Unicode lowercasing changes byte length (`İ` → `i` + U+0307
/// is 2→3 bytes).
func firstTokenLineNumber(in body: String, query: String) -> Int {
    let bodyLower = body.lowercased()
    // Strip FTS5 column-filter prefixes before tokenizing. Today the
    // only indexed column is `body_text`; a user typing
    // `body_text:foo` means "find `foo` inside body_text", so the
    // `body_text:` part shouldn't seed tokens for the line scan. If
    // more columns ever land in the FTS5 schema, add their names
    // here.
    let preprocessed = query.lowercased()
        .replacingOccurrences(of: "body_text:", with: " ")
    // FTS5 keywords that would otherwise sneak through the split and
    // pollute the line lookup if they happen to appear as bare words
    // in prose (#93 item 5). Pure-numeric tokens are also dropped:
    // numbers appearing inside composite FTS5 constructs
    // (`NEAR(a b, 5)`, `LIMIT 10`) aren't semantically meaningful to
    // a body-line scan.
    let fts5Keywords: Set<String> = ["and", "or", "not", "near"]
    let tokens = preprocessed
        .split { !$0.isLetter && !$0.isNumber }
        .map(String.init)
        .filter { tok in
            !tok.isEmpty
                && !fts5Keywords.contains(tok)
                && !tok.allSatisfy(\.isNumber)
        }
    var earliest: String.Index? = nil
    for tok in tokens {
        if let range = bodyLower.range(of: tok) {
            switch earliest {
            case .none:
                earliest = range.lowerBound
            case .some(let prev):
                earliest = min(prev, range.lowerBound)
            }
        }
    }
    guard let earliest else { return 1 }
    // Count newlines in the prefix using UTF-8 view so we don't
    // pay for an O(n) String.distance over the prefix.
    let prefix = bodyLower[..<earliest]
    return prefix.utf8.reduce(1) { acc, byte in
        byte == 0x0A ? acc + 1 : acc
    }
}
